  ($lum$458418e5-8af2-5640-ad4e-0439bfa1c1f8$lum$::uuid, $lum$workflows$lum$, $lum$Workflows$lum$, $lum$topic$lum$)
insert into lessons (id, slug, module_id, title, hook, key_takeaway, level, estimated_minutes, order_index, status) values
  ($lum$fa87a7e0-7889-5673-981c-da2cf84fb515$lum$::uuid, $lum$ai-templates-for-teams$lum$, $lum$a2671a81-7114-5587-8321-da5fa352bbc5$lum$::uuid, $lum$Creating AI Templates Your Team Will Actually Use$lum$, $lum$A shared prompt only helps if people actually use it. Here is how to build ones that stick.$lum$, $lum$Team templates succeed when they are specific, easy to fill in, and solve a real shared pain, so build them around frequent tasks and make using them easier than not.$lum$, $lum$confident$lum$, 7, 7, $lum$published$lum$),
  ($lum$6176690d-cee6-529a-ab80-6064ee4e0185$lum$::uuid, $lum$building-your-ai-toolkit$lum$, $lum$a2671a81-7114-5587-8321-da5fa352bbc5$lum$::uuid, $lum$Building Your Personal AI Toolkit$lum$, $lum$Stop solving the same problems from scratch. Build a personal kit of prompts and setups that does the work for you.$lum$, $lum$A personal AI toolkit is your saved collection of go-to prompts, custom instructions, and routines, so your best discoveries become reusable assets instead of one-off wins.$lum$, $lum$confident$lum$, 7, 6, $lum$published$lum$),
  ($lum$bd003094-cdd4-5fce-92db-48604e48f2cd$lum$::uuid, $lum$chain-ai-steps-to-finish-a-whole-task$lum$, $lum$a2671a81-7114-5587-8321-da5fa352bbc5$lum$::uuid, $lum$Chain AI steps to finish a whole task$lum$, $lum$The most powerful AI workflows don't involve one model doing one thing: they involve models checking each other's work.$lum$, $lum$Specialist agents checking each other's work consistently outperform one generalist agent doing everything. The critique loop is the most powerful pattern in practical AI.$lum$, $lum$confident$lum$, 15, 1, $lum$published$lum$),
  ($lum$f5ae420a-124f-5923-83cd-dc8ef5714c76$lum$::uuid, $lum$connect-ai-to-your-other-tools-no-code$lum$, $lum$a2671a81-7114-5587-8321-da5fa352bbc5$lum$::uuid, $lum$Connect AI to your other tools (no code)$lum$, $lum$You don't need to be a developer to call an API: you just need to understand what an API call actually is.$lum$, $lum$An API call is just a structured message to a model. Once you understand that, the whole world of automation opens up without requiring coding skills.$lum$, $lum$confident$lum$, 12, 0, $lum$published$lum$),
  ($lum$ac0470cf-2bca-594d-b34e-b4218d902d4a$lum$::uuid, $lum$find-anything-youve-ever-saved-instantly$lum$, $lum$a2671a81-7114-5587-8321-da5fa352bbc5$lum$::uuid, $lum$Find anything you've ever saved, instantly$lum$, $lum$You've written thousands of documents, taken thousands of notes, and read thousands of articles. Almost none of it is retrievable when you need it.$lum$, $lum$Centralize → enrich with AI retrieval → capture consistently. A searchable body of your own knowledge is the most underrated productivity investment.$lum$, $lum$confident$lum$, 14, 3, $lum$published$lum$),
  ($lum$dde8fe13-0872-5089-81d5-8319ce926ada$lum$::uuid, $lum$measuring-the-time-you-actually-saved$lum$, $lum$a2671a81-7114-5587-8321-da5fa352bbc5$lum$::uuid, $lum$Measuring the Time You Actually Saved$lum$, $lum$Everyone says AI saves them time, but almost no one can prove it. A simple before-and-after measurement turns a vague feeling into a number you can stand behind.$lum$, $lum$Pick a few recurring tasks, time them honestly before and after AI including the editing and checking, and track the real net saving over a couple of weeks so your claims rest on evidence instead of enthusiasm.$lum$, $lum$confident$lum$, 7, 8, $lum$published$lum$),
  ($lum$4fadbee5-5a11-5314-a23a-5aac50a4071b$lum$::uuid, $lum$prompt-chaining$lum$, $lum$a2671a81-7114-5587-8321-da5fa352bbc5$lum$::uuid, $lum$Prompt Chaining: Connecting AI Steps$lum$, $lum$Stop cramming everything into one giant prompt. Break the job into a chain and the quality jumps.$lum$, $lum$Splitting a complex task into a sequence of focused prompts, where each step feeds the next, produces far better results than one overloaded prompt trying to do everything at once.$lum$, $lum$confident$lum$, 7, 5, $lum$published$lum$),
  ($lum$a5667a30-ab8a-5786-a0fe-bd4f76c747ea$lum$::uuid, $lum$pull-data-from-any-website-without-code$lum$, $lum$a2671a81-7114-5587-8321-da5fa352bbc5$lum$::uuid, $lum$Pull data from any website without code$lum$, $lum$The data you need is publicly available on the web. And you don't need Python to get it.$lum$, $lum$No-code scrapers + AI synthesis = competitive intelligence that used to require a data team, now available to any analyst with 30 minutes.$lum$, $lum$confident$lum$, 11, 2, $lum$published$lum$),
  ($lum$28aa7ce9-cf8f-5704-815c-014672c045f5$lum$::uuid, $lum$the-autonomous-workday-whats-next$lum$, $lum$a2671a81-7114-5587-8321-da5fa352bbc5$lum$::uuid, $lum$The autonomous workday: what's next?$lum$, $lum$Everything in this course has been about augmenting what you do. What comes next is about what you no longer need to do at all.$lum$, $lum$Document your decision rules now. The processes you've made explicit are the ones that become autonomous, and the ones still in your head will remain manual.$lum$, $lum$confident$lum$, 12, 4, $lum$published$lum$),
  ($lum$b7ef57b8-a94f-5219-903f-9ba6b94811eb$lum$::uuid, $lum$ai-as-a-decision-sounding-board$lum$, $lum$4fff1d1f-a4e8-5b0d-8b5a-9aee6a95e4fa$lum$::uuid, $lum$AI as a Decision Sounding Board$lum$, $lum$Sometimes you need to think a decision through out loud but there is no one around to think with. AI is an always-available thinking partner, if you use it right.$lum$, $lum$Use AI to pressure-test a decision by having it lay out options, challenge your reasoning, and ask the questions a sharp colleague would, while you keep the final call grounded in context only you have.$lum$, $lum$growing$lum$, 7, 10, $lum$published$lum$),
  ($lum$7d5bf106-8b58-59ab-bcd4-de5ebfbc3019$lum$::uuid, $lum$ai-for-team-communication$lum$, $lum$4fff1d1f-a4e8-5b0d-8b5a-9aee6a95e4fa$lum$::uuid, $lum$AI-Powered Team Communication Templates$lum$, $lum$Build a small library of message templates once, and never agonize over routine updates again.$lum$, $lum$Use AI to create reusable templates for the messages your team sends constantly, so routine communication becomes fill-in-the-blank instead of a blank page every time.$lum$, $lum$growing$lum$, 7, 6, $lum$published$lum$),
  ($lum$9e75bbdf-e265-5937-8ac3-8597413d6e6d$lum$::uuid, $lum$automating-lead-research$lum$, $lum$4fff1d1f-a4e8-5b0d-8b5a-9aee6a95e4fa$lum$::uuid, $lum$Automating lead research$lum$, $lum$Your sales team is spending 40% of their time on research that could be done in 10 minutes per lead.$lum$, $lum$Context dump + research prompt + personalization brief: 10 minutes of structured AI research outperforms 30 minutes of manual tab-switching.$lum$, $lum$growing$lum$, 9, 0, $lum$published$lum$),
  ($lum$3019a899-ab5e-51b6-9fea-351fd5741163$lum$::uuid, $lum$automating-repetitive-tasks$lum$, $lum$4fff1d1f-a4e8-5b0d-8b5a-9aee6a95e4fa$lum$::uuid, $lum$Spotting Which Tasks AI Can Handle$lum$, $lum$The biggest wins come from knowing which of your weekly tasks AI should touch, and which it should not.$lum$, $lum$AI is best at repetitive, text-heavy tasks that follow a pattern and where a human still checks the result, so learn to spot those and hand them over first.$lum$, $lum$growing$lum$, 6, 9, $lum$published$lum$),
  ($lum$f09a279f-4fba-5fce-914c-afbd586ae263$lum$::uuid, $lum$build-your-own-ai-helper-that-knows-your-company$lum$, $lum$4fff1d1f-a4e8-5b0d-8b5a-9aee6a95e4fa$lum$::uuid, $lum$Build your own AI helper that knows your company$lum$, $lum$Your company has context that no public AI knows. Here's how to build a version that does.$lum$, $lum$A custom GPT with your company context in the system prompt turns generic outputs into answers that actually fit your specific situation.$lum$, $lum$growing$lum$, 12, 3, $lum$published$lum$),
  ($lum$ebc313c3-7d32-5f03-933b-151179686c92$lum$::uuid, $lum$building-simple-workflows$lum$, $lum$4fff1d1f-a4e8-5b0d-8b5a-9aee6a95e4fa$lum$::uuid, $lum$Building a Simple AI Workflow$lum$, $lum$Stop reinventing the same task every week. Turn it into a repeatable AI routine.$lum$, $lum$A workflow is just a repeatable task broken into clear steps with a reusable prompt for each, so you set it up once and run it on autopilot every time.$lum$, $lum$growing$lum$, 7, 5, $lum$published$lum$),
  ($lum$b7df9934-e2fd-594b-aee9-272078b3ac75$lum$::uuid, $lum$competitive-research$lum$, $lum$4fff1d1f-a4e8-5b0d-8b5a-9aee6a95e4fa$lum$::uuid, $lum$AI-Assisted Research and Competitive Analysis$lum$, $lum$Turn scattered facts about a competitor into a clear, structured picture you can actually act on.$lum$, $lum$Give the AI the raw information you have gathered and a clear framework, and it organizes it into a comparison you can use, as long as you verify the facts yourself.$lum$, $lum$growing$lum$, 7, 7, $lum$published$lum$),
  ($lum$60792d9c-de45-5fcb-a425-4e6d113f382e$lum$::uuid, $lum$competitor-tracking-on-autopilot$lum$, $lum$4fff1d1f-a4e8-5b0d-8b5a-9aee6a95e4fa$lum$::uuid, $lum$Competitor tracking on autopilot$lum$, $lum$Your competitors are moving and you're finding out two months late. Here's the monitoring stack that costs nothing.$lum$, $lum$Automate collection, synthesize weekly, deep-dive quarterly. Competitive intelligence doesn't need to be expensive, just consistent.$lum$, $lum$growing$lum$, 11, 4, $lum$published$lum$),
  ($lum$8672ffe6-572f-5736-8f76-b31f71352a5b$lum$::uuid, $lum$data-cleaning-for-the-spreadsheet-phobic$lum$, $lum$4fff1d1f-a4e8-5b0d-8b5a-9aee6a95e4fa$lum$::uuid, $lum$Data cleaning for the spreadsheet-phobic$lum$, $lum$You don't need to know Excel formulas if you can describe what you want in plain English.$lum$, $lum$Describe the data problem in plain English with a sample. You don't need formulas when you can tell the model exactly what the data should look like.$lum$, $lum$growing$lum$, 10, 2, $lum$published$lum$),
  ($lum$eb703d41-6063-5568-84e3-8a03b9c64f78$lum$::uuid, $lum$find-the-themes-hiding-in-your-feedback$lum$, $lum$4fff1d1f-a4e8-5b0d-8b5a-9aee6a95e4fa$lum$::uuid, $lum$Finding the Themes Hiding in Your Feedback$lum$, $lum$A hundred survey comments or support tickets are impossible to read for patterns by hand. AI finds the themes and counts them in seconds.$lum$, $lum$Paste a pile of open-ended feedback and ask AI to group it into themes with counts and example quotes, turning a wall of comments into a clear, prioritized picture of what people are actually saying.$lum$, $lum$growing$lum$, 7, 8, $lum$published$lum$),
  ($lum$5ff60ffb-4eff-59d5-9497-fd5664b7b74d$lum$::uuid, $lum$turn-a-screen-recording-into-a-step-by-step-guide$lum$, $lum$4fff1d1f-a4e8-5b0d-8b5a-9aee6a95e4fa$lum$::uuid, $lum$Turn a screen recording into a step-by-step guide$lum$, $lum$The knowledge that lives in people's heads is the most expensive operational risk your company has. Here's how to extract it.$lum$, $lum$Record → transcribe → prompt: converts a spoken walkthrough into a structured SOP in 30 minutes, replacing what used to take a full day.$lum$, $lum$growing$lum$, 8, 1, $lum$published$lum$),
  ($lum$30724c39-9997-516e-91ae-2656cf35efe0$lum$::uuid, $lum$creating-presentations$lum$, $lum$811fb775-9241-5709-87bb-bfc2cf64c2db$lum$::uuid, $lum$AI-Assisted Presentations That Don't Look AI-Made$lum$, $lum$Use AI for the structure and the words, not the autopilot, and your deck will actually land.$lum$, $lum$Let AI build your narrative arc and tighten each slide's message, but keep your real examples and your judgment, so the deck persuades instead of reading like filler.$lum$, $lum$growing$lum$, 7, 8, $lum$published$lum$),
  ($lum$5f4b4f39-02bc-57bd-8555-a15126e5f43c$lum$::uuid, $lum$cut-the-padding-fixing-bloat-and-format-drift$lum$, $lum$811fb775-9241-5709-87bb-bfc2cf64c2db$lum$::uuid, $lum$Cut the Padding: Fixing Bloat and Format Drift$lum$, $lum$AI writes long, hedges everything, and slowly forgets the format you asked for. A few sharp instructions fix all three.$lum$, $lum$Counter AI's tendency to bloat and drift by setting hard limits on length, banning filler and hedging up front, and restating your format when a long output starts wandering.$lum$, $lum$growing$lum$, 6, 9, $lum$published$lum$),
  ($lum$610ed6f0-0e97-5367-b4fe-82e52c68da3e$lum$::uuid, $lum$make-a-great-image-from-a-sentence$lum$, $lum$811fb775-9241-5709-87bb-bfc2cf64c2db$lum$::uuid, $lum$Make a great image from a sentence$lum$, $lum$The difference between a mediocre AI image and a stunning one is entirely in the prompt. Here's the structure that works.$lum$, $lum$Subject + setting + lighting + style anchor + technical parameters: stack these five and you'll get a usable image in 2–3 iterations instead of 15.$lum$, $lum$growing$lum$, 9, 2, $lum$published$lum$),
  ($lum$df21dae9-377b-51cf-9099-5f078d85caa9$lum$::uuid, $lum$matching-your-voice$lum$, $lum$811fb775-9241-5709-87bb-bfc2cf64c2db$lum$::uuid, $lum$Getting AI to Write in Your Voice$lum$, $lum$Stop sounding like a robot. Teach the AI how you actually write, and it will follow your lead.$lum$, $lum$Show the AI samples of your real writing and name the traits of your style, and it stops producing generic text and starts sounding like you.$lum$, $lum$growing$lum$, 7, 6, $lum$published$lum$),
  ($lum$383cf262-4694-5db7-a82a-52d56a8cfbc1$lum$::uuid, $lum$repurposing-content$lum$, $lum$811fb775-9241-5709-87bb-bfc2cf64c2db$lum$::uuid, $lum$One Piece of Content, Many Formats$lum$, $lum$Write something once, then let AI reshape it into five formats for five places.$lum$, $lum$One solid source piece can become an email, a post, a summary, and more, because AI is excellent at reshaping the same ideas for different audiences and formats.$lum$, $lum$growing$lum$, 7, 7, $lum$published$lum$),
  ($lum$bf5913d3-d1c9-5723-910d-2f1edf820e2b$lum$::uuid, $lum$structural-editing-rewrite-without-losing-voice$lum$, $lum$811fb775-9241-5709-87bb-bfc2cf64c2db$lum$::uuid, $lum$Structural editing: rewrite without losing voice$lum$, $lum$The reason AI-edited text sounds generic isn't the AI: it's that you're asking it to rewrite instead of restructure.$lum$, $lum$Ask for structural feedback, not a rewrite. The model can tell you what's wrong without replacing your voice with its own.$lum$, $lum$growing$lum$, 8, 0, $lum$published$lum$),
  ($lum$adcfe362-f983-574c-b70d-6c5a10c9fce4$lum$::uuid, $lum$synthesizing-research-30-pdfs-into-1-page$lum$, $lum$811fb775-9241-5709-87bb-bfc2cf64c2db$lum$::uuid, $lum$Synthesizing research: 30 PDFs into 1 page$lum$, $lum$The report that used to take two weeks of reading now takes two hours, if you know how to feed documents to a model.$lum$, $lum$Extract first, synthesize second. The model finds cross-document patterns you'd miss reading them one at a time.$lum$, $lum$growing$lum$, 10, 3, $lum$published$lum$),
  ($lum$a716986f-7c00-5153-a743-95ce7a1cfa3d$lum$::uuid, $lum$the-brainstorming-loop-getting-past-version-1$lum$, $lum$811fb775-9241-5709-87bb-bfc2cf64c2db$lum$::uuid, $lum$The brainstorming loop: getting past version 1$lum$, $lum$Version 1 of anything is almost never good. And AI can get you to version 5 in the time it used to take to get to version 2.$lum$, $lum$Run 4 rounds: diverge → interrogate → constrain → combine; the best idea is almost never in the first output.$lum$, $lum$growing$lum$, 7, 1, $lum$published$lum$),
  ($lum$c8ad5de6-5654-5ad1-8d52-6276f4eaa213$lum$::uuid, $lum$the-outline-method-for-long-form-content$lum$, $lum$811fb775-9241-5709-87bb-bfc2cf64c2db$lum$::uuid, $lum$The outline method for long-form content$lum$, $lum$The blank page problem disappears the moment you separate structure from writing. Here's how.$lum$, $lum$Separate structure from writing. Let AI give you 5 structural options, pick one, then write section-by-section instead of into the void.$lum$, $lum$growing$lum$, 8, 4, $lum$published$lum$),
  ($lum$d60b3cae-8932-51e5-83b0-ad4fc1129abd$lum$::uuid, $lum$writing-first-drafts$lum$, $lum$811fb775-9241-5709-87bb-bfc2cf64c2db$lum$::uuid, $lum$Writing First Drafts You're Not Embarrassed By$lum$, $lum$The blank page is the enemy. AI gets you to a real first draft you can actually improve.$lum$, $lum$Give the AI your angle, audience, and key points to generate a rough draft, then your real work is shaping it, which is far easier than starting from nothing.$lum$, $lum$growing$lum$, 7, 5, $lum$published$lum$),
  ($lum$a41df8a9-a2bb-5f3d-bab6-e68d44b81877$lum$::uuid, $lum$ai-for-research$lum$, $lum$a529e901-a3fd-5ab8-890d-11e289b52db2$lum$::uuid, $lum$Using AI to Research Anything Faster$lum$, $lum$Get oriented on any new topic in minutes, then know exactly what to verify.$lum$, $lum$Use AI to map a topic and explain it in plain terms fast, but treat its specifics as leads to confirm, never as the final source.$lum$, $lum$beginner$lum$, 6, 8, $lum$published$lum$),
  ($lum$d7ed7045-1f7c-54da-9b42-06f024dabc70$lum$::uuid, $lum$break-a-big-task-into-a-timeline$lum$, $lum$a529e901-a3fd-5ab8-890d-11e289b52db2$lum$::uuid, $lum$Breaking a Big Task Into a Timeline$lum$, $lum$A huge project with a far-off deadline is paralyzing because your brain cannot hold all the pieces. AI breaks it into steps and dates you can actually start on.$lum$, $lum$Describe the project, the deadline, and your constraints, and AI turns an overwhelming goal into an ordered set of steps with realistic timing, which you adjust with your real-world knowledge.$lum$, $lum$growing$lum$, 6, 13, $lum$published$lum$),
  ($lum$48448dca-5fe6-52df-8bb1-004ae444b592$lum$::uuid, $lum$compare-two-documents-side-by-side$lum$, $lum$a529e901-a3fd-5ab8-890d-11e289b52db2$lum$::uuid, $lum$Comparing Two Documents Side by Side$lum$, $lum$Spotting what changed between two versions of a contract or policy by eye is slow and error-prone. AI does it in seconds and tells you what matters.$lum$, $lum$Paste two versions of a document and tell AI what you care about, and it pulls out exactly what changed, what was added or removed, and which differences actually matter to you.$lum$, $lum$beginner$lum$, 6, 11, $lum$published$lum$),
  ($lum$dcef9dfc-dd6d-53ec-8244-881e82cff2f7$lum$::uuid, $lum$decode-the-jargon-in-any-document$lum$, $lum$a529e901-a3fd-5ab8-890d-11e289b52db2$lum$::uuid, $lum$Decoding the Jargon in Any Document$lum$, $lum$Legal contracts, insurance forms, technical specs, medical letters: documents written to sound official and leave you guessing. AI translates them into plain English.$lum$, $lum$Paste a confusing document and ask AI to explain it in plain language at the level you need, and it turns dense jargon into something you can actually understand and act on.$lum$, $lum$beginner$lum$, 5, 12, $lum$published$lum$),
  ($lum$41d7b1af-4664-5fc0-b4b7-e65e289112ab$lum$::uuid, $lum$drafting-professional-emails$lum$, $lum$a529e901-a3fd-5ab8-890d-11e289b52db2$lum$::uuid, $lum$Drafting Professional Emails with AI$lum$, $lum$Stop staring at the blank reply box. Brief the AI on the situation, the tone, and the limits, then own the final send.$lum$, $lum$A strong email draft comes from briefing the AI on the situation, the key points, the tone, and the constraints. The AI drafts, but you read it, fix what does not sound like you, and own the send.$lum$, $lum$beginner$lum$, 15, 5, $lum$published$lum$),
  ($lum$c39f644b-abab-5e67-a543-71193829437b$lum$::uuid, $lum$inbox-triage-auto-drafting-responses$lum$, $lum$a529e901-a3fd-5ab8-890d-11e289b52db2$lum$::uuid, $lum$Inbox triage: auto-drafting responses$lum$, $lum$The emails that take you 20 minutes to draft take ChatGPT 30 seconds. And the difference in quality is smaller than you think.$lum$, $lum$Classify every email before you write it. 80% are Tier 1 and can be drafted in 30 seconds, saving your cognitive load for the 20% that actually need it.$lum$, $lum$beginner$lum$, 6, 1, $lum$published$lum$),
  ($lum$c69000a0-7a79-598c-b2b0-9e98f9493c6f$lum$::uuid, $lum$learn-new-software-or-a-new-concept-fast$lum$, $lum$a529e901-a3fd-5ab8-890d-11e289b52db2$lum$::uuid, $lum$Learning New Software or a New Concept Fast$lum$, $lum$Stop hunting through help docs and unwatchable tutorial videos. Ask AI your exact question and get the answer at your exact level.$lum$, $lum$Treat AI as a patient on-demand tutor: tell it what you are trying to do and what you already know, ask follow-ups until it clicks, and verify any step-by-step instructions against the real tool.$lum$, $lum$beginner$lum$, 6, 14, $lum$published$lum$),
  ($lum$d5a233df-02f7-532c-bc58-6266a397975e$lum$::uuid, $lum$preparing-for-meetings$lum$, $lum$a529e901-a3fd-5ab8-890d-11e289b52db2$lum$::uuid, $lum$Using AI to Prepare for Any Meeting$lum$, $lum$Walk into your next meeting as the most prepared person in the room, in ten minutes flat.$lum$, $lum$Use AI to turn what you know into an agenda, smart questions, and likely objections, so you arrive clear on your goal and ready for what comes up.$lum$, $lum$beginner$lum$, 7, 6, $lum$published$lum$),
  ($lum$685dced9-5a32-50b3-a8a2-e15bcfefd143$lum$::uuid, $lum$replying-to-an-angry-customer$lum$, $lum$a529e901-a3fd-5ab8-890d-11e289b52db2$lum$::uuid, $lum$Replying to an Angry Customer$lum$, $lum$An angry message makes your own heart rate spike, which is the worst state to write a reply in. Let AI draft the calm version while you stay the judgment.$lum$, $lum$Feed AI the complaint and the facts of what you can actually do, and it produces a calm, empathetic reply that de-escalates, which you then check for accuracy and tone before sending.$lum$, $lum$growing$lum$, 6, 10, $lum$published$lum$),
  ($lum$2619ae8e-1c6c-5f35-be89-86ec671c690f$lum$::uuid, $lum$rough-notes-to-polished-writing$lum$, $lum$a529e901-a3fd-5ab8-890d-11e289b52db2$lum$::uuid, $lum$From Rough Notes to Polished Writing$lum$, $lum$Brain-dump the mess, then let AI shape it into something you would be happy to send.$lum$, $lum$Capture your raw thoughts first, then hand them to AI to organize and tighten, so the thinking stays yours and the polishing gets easy.$lum$, $lum$beginner$lum$, 6, 7, $lum$published$lum$),
  ($lum$aeaba649-bfe8-5541-9e0c-ed1f2b45ec04$lum$::uuid, $lum$summarizing-long-documents$lum$, $lum$a529e901-a3fd-5ab8-890d-11e289b52db2$lum$::uuid, $lum$Summarizing Long Documents in Seconds$lum$, $lum$The 40-page report you have been avoiding can become a clear one-page brief before your coffee gets cold, if you ask for the right kind of summary.$lum$, $lum$A useful summary is shaped by your purpose. Tell the AI who you are, what you need to decide, and how to shape the answer, then spot-check the result against the source before you rely on it.$lum$, $lum$beginner$lum$, 15, 4, $lum$published$lum$),
  ($lum$f3c48a5e-7040-5855-98f2-61b1c8514c55$lum$::uuid, $lum$the-5-minute-meeting-debrief-protocol$lum$, $lum$a529e901-a3fd-5ab8-890d-11e289b52db2$lum$::uuid, $lum$The 5-minute meeting debrief protocol$lum$, $lum$Most action items from meetings disappear within 48 hours. Here's a protocol that takes 5 minutes and captures everything.$lum$, $lum$Rough notes + a structured prompt immediately after the meeting captures everything and drafts the follow-up before you've even walked back to your desk.$lum$, $lum$beginner$lum$, 5, 0, $lum$published$lum$),
  ($lum$f78c5f60-14ea-54cc-a7b7-a9c5eb3bed5c$lum$::uuid, $lum$the-slack-summary-rule$lum$, $lum$a529e901-a3fd-5ab8-890d-11e289b52db2$lum$::uuid, $lum$The Slack summary rule$lum$, $lum$You're spending 45 minutes a day reading Slack threads that could be summarized in 90 seconds.$lum$, $lum$Paste, summarize, act. Never read a long thread linearly again; the model extracts signal from noise faster than you can scroll.$lum$, $lum$beginner$lum$, 5, 3, $lum$published$lum$),
  ($lum$cca9dfe2-ad9f-54a3-83a0-835db3624cfc$lum$::uuid, $lum$writing-better-briefs-for-external-teams$lum$, $lum$a529e901-a3fd-5ab8-890d-11e289b52db2$lum$::uuid, $lum$Writing better briefs for external teams$lum$, $lum$The reason external agencies and freelancers deliver the wrong thing isn't their fault: it's yours.$lum$, $lum$A brief that explains the why and defines what bad looks like cuts revision rounds in half. AI drafts it in 60 seconds, you just need to fill in what you know.$lum$, $lum$beginner$lum$, 7, 2, $lum$published$lum$),
  ($lum$3ab28d12-c367-55f2-8b6e-8c93dfc40d77$lum$::uuid, $lum$writing-hard-messages-saying-no-gracefully$lum$, $lum$a529e901-a3fd-5ab8-890d-11e289b52db2$lum$::uuid, $lum$Writing Hard Messages: Saying No Gracefully$lum$, $lum$The messages that drain you are the hard ones: turning someone down, pushing back, delivering bad news. AI helps you find the words that are kind and clear.$lum$, $lum$Give AI the situation, your real position, and the relationship you want to protect, and it drafts a message that says no clearly without burning the bridge.$lum$, $lum$growing$lum$, 6, 9, $lum$published$lum$),
  ($lum$01bbfdc0-3784-5623-ac50-69d0e853b466$lum$::uuid, $lum$ask-for-less-beating-the-wall-of-text$lum$, $lum$29b588fb-3344-5efd-97f4-813d16bc9ea3$lum$::uuid, $lum$Ask for Less: Beating the Wall of Text$lum$, $lum$You asked one question and got back six paragraphs you'll never read. The fix isn't a better question. It's a smaller one.$lum$, $lum$AI defaults to long and exhaustive. Tell it how short you want the answer and in what shape, and you go from skimming a wall of text to getting exactly what you needed.$lum$, $lum$beginner$lum$, 5, 9, $lum$published$lum$),
  ($lum$88ae3149-d332-5be1-a850-8e342251cdc3$lum$::uuid, $lum$free-vs-paid-what-you-need$lum$, $lum$29b588fb-3344-5efd-97f4-813d16bc9ea3$lum$::uuid, $lum$Free vs Paid: What You Actually Need$lum$, $lum$Every AI tool dangles a paid tier at you within about thirty seconds. Here's how to know whether you actually need it yet.$lum$, $lum$Start free. Upgrade only when you hit a specific wall you can name, because for most beginners the free tier is more than enough to build the habit.$lum$, $lum$beginner$lum$, 5, 1, $lum$published$lum$),
  ($lum$f1b7ebba-a8a7-5762-b108-b4317e2c6dba$lum$::uuid, $lum$is-this-safe-to-paste$lum$, $lum$29b588fb-3344-5efd-97f4-813d16bc9ea3$lum$::uuid, $lum$Is This Safe to Paste?$lum$, $lum$AI gets dramatically more useful the second you paste in real material. That is also the exact second you can hand over something you were never supposed to share.$lum$, $lum$Before you paste, ask one question: would I be comfortable posting this on a public bulletin board? If the answer is no, strip the names and specifics, or use your work-approved tool, or do that part yourself.$lum$, $lum$beginner$lum$, 15, 10, $lum$published$lum$),
  ($lum$6dd48206-2fd2-5f79-873a-be46f4172f6e$lum$::uuid, $lum$paste-a-document-give-it-a-role-save-the-output$lum$, $lum$29b588fb-3344-5efd-97f4-813d16bc9ea3$lum$::uuid, $lum$Paste a Document, Give It a Role, Save the Output$lum$, $lum$Three small habits separate people who get real work done with AI from people who just chat with it. None of them take more than a few seconds.$lum$, $lum$Paste the actual material instead of describing it, tell the AI who to be, and keep the good outputs. These three moves turn AI from a toy into a workhorse.$lum$, $lum$beginner$lum$, 7, 7, $lum$published$lum$),
  ($lum$db25e28a-6ea6-5eb2-8e40-e082b37b153f$lum$::uuid, $lum$set-up-ai-once-so-it-remembers-how-you-work$lum$, $lum$29b588fb-3344-5efd-97f4-813d16bc9ea3$lum$::uuid, $lum$Set up AI once so it remembers how you work$lum$, $lum$You have been re-introducing yourself to the AI in every single chat. There is a settings box that ends that forever.$lum$, $lum$Spend fifteen minutes filling in custom instructions or saved memory with your role, your audience, and how you want answers written. After that, every chat starts already knowing you.$lum$, $lum$beginner$lum$, 15, 6, $lum$published$lum$),
  ($lum$6343674a-601c-5d2d-92c6-60fe3784cb36$lum$::uuid, $lum$stop-writing-prompts-start-writing-briefs$lum$, $lum$29b588fb-3344-5efd-97f4-813d16bc9ea3$lum$::uuid, $lum$Stop writing prompts (start writing briefs)$lum$, $lum$Every disappointing AI answer has the same root cause: you gave it a question when it needed a brief.$lum$, $lum$A brief costs you 60 extra seconds and saves 20 minutes of revisions, because it tells the AI everything a capable assistant would need to know before starting.$lum$, $lum$beginner$lum$, 15, 3, $lum$published$lum$),
  ($lum$3ac195ba-ec6e-5dab-80bd-1a0aae116991$lum$::uuid, $lum$the-3-step-framing-technique$lum$, $lum$29b588fb-3344-5efd-97f4-813d16bc9ea3$lum$::uuid, $lum$The 3-step framing technique$lum$, $lum$One extra sentence before your request doubles the quality of every answer you get back.$lum$, $lum$Role, then task, then format. Ten seconds of framing turns a generic answer into something you can actually use at work.$lum$, $lum$beginner$lum$, 15, 2, $lum$published$lum$),
  ($lum$353c8369-6493-519c-b0c8-0f86684a58ed$lum$::uuid, $lum$the-iteration-loop$lum$, $lum$29b588fb-3344-5efd-97f4-813d16bc9ea3$lum$::uuid, $lum$Getting Better Answers: The Iteration Loop$lum$, $lum$The first answer is almost never the best one. The people who get the most out of AI know that and keep talking.$lum$, $lum$A great result is a short back-and-forth, not one perfect prompt. Ask, read the answer critically, name exactly what is wrong, and ask for one specific change. Repeat two or three times and it lands.$lum$, $lum$beginner$lum$, 15, 8, $lum$published$lum$),
  ($lum$9f9624a6-e38e-567c-aea8-e7d197129d33$lum$::uuid, $lum$the-jargon-glossary$lum$, $lum$29b588fb-3344-5efd-97f4-813d16bc9ea3$lum$::uuid, $lum$The Jargon Glossary$lum$, $lum$Half of feeling behind on AI is just not knowing the words. Here are the ten that actually come up, in plain English.$lum$, $lum$The vocabulary is smaller than it looks. Learn ten terms and most articles, settings menus, and colleagues suddenly make sense.$lum$, $lum$beginner$lum$, 6, 5, $lum$published$lum$),
  ($lum$7783e9f8-daf8-56d1-9340-d52994020e14$lum$::uuid, $lum$whats-a-good-job-for-ai$lum$, $lum$29b588fb-3344-5efd-97f4-813d16bc9ea3$lum$::uuid, $lum$What's a Good Job for AI?$lum$, $lum$The difference between people who love AI and people who give up is almost never skill. It's that one group points it at the right tasks.$lum$, $lum$AI is strongest on first drafts, reshaping text, and explaining things, and weakest on facts, math, and anything where being wrong is expensive. Match the task to the tool.$lum$, $lum$beginner$lum$, 6, 4, $lum$published$lum$),
  ($lum$a6462f1d-5f41-553a-870a-e490cb965021$lum$::uuid, $lum$your-first-five-minutes$lum$, $lum$29b588fb-3344-5efd-97f4-813d16bc9ea3$lum$::uuid, $lum$Your First Five Minutes (and Your First Win)$lum$, $lum$The blank chat box is where most people freeze. Here's a five-minute path from "now what?" to your first genuinely useful answer.$lum$, $lum$Start with a real task you already have, not a test question. One small win on actual work is worth more than an hour of poking around.$lum$, $lum$beginner$lum$, 5, 0, $lum$published$lum$),
  ($lum$3c690267-cbaf-5596-b072-115de24e0cc3$lum$::uuid, $lum$spot-when-ai-is-making-things-up$lum$, $lum$0c46c9ff-099c-5f97-82bd-26f6977da2cb$lum$::uuid, $lum$Spot when AI is making things up$lum$, $lum$ChatGPT lies with complete confidence. And there are clear tells that give it away every time.$lum$, $lum$Hallucinations are built into how AI works, not a bug. Learn the tells and build a verify-before-you-trust habit for anything with your name on it.$lum$, $lum$beginner$lum$, 15, 4, $lum$published$lum$),
  ($lum$849b2638-cf39-5842-a9cc-96d99fa1d407$lum$::uuid, $lum$what-ai-actually-is-and-isnt$lum$, $lum$0c46c9ff-099c-5f97-82bd-26f6977da2cb$lum$::uuid, $lum$What AI Actually Is (and Isn't)$lum$, $lum$You don't need to know how an engine works to drive a car. But knowing one thing about how AI works will change every answer you ever get from it.$lum$, $lum$A chatbot predicts likely text, it does not look up facts. That single mental model explains why it's brilliant at drafting and unreliable at recall.$lum$, $lum$beginner$lum$, 6, 1, $lum$published$lum$),
  ($lum$fecbad02-d871-5221-95d0-9e2a34de1eeb$lum$::uuid, $lum$what-ai-cannot-do$lum$, $lum$0c46c9ff-099c-5f97-82bd-26f6977da2cb$lum$::uuid, $lum$What AI Cannot Do: Understanding the Limits$lum$, $lum$Knowing exactly where AI breaks down is what keeps you safe, in control, and out of trouble at work.$lum$, $lum$AI predicts likely words; it has no live knowledge, no access to your private systems, no real judgment, and no accountability. Treat it as a fast first draft you always check, never a source of truth.$lum$, $lum$beginner$lum$, 15, 5, $lum$published$lum$),
  ($lum$4c0a103f-20e6-5158-ace5-64db3fb780da$lum$::uuid, $lum$when-to-use-chatgpt-vs-google$lum$, $lum$0c46c9ff-099c-5f97-82bd-26f6977da2cb$lum$::uuid, $lum$When to use ChatGPT vs. Google$lum$, $lum$You've been using the wrong tool for half your questions. Here's the 10-second test that fixes that.$lum$, $lum$Google retrieves verifiable facts that already exist; ChatGPT reasons and creates. Match the tool to the job and use both together for research.$lum$, $lum$beginner$lum$, 15, 3, $lum$published$lum$),
  ($lum$cf17c072-349e-5c46-8281-d17d4183041a$lum$::uuid, $lum$which-ai-tool-and-is-it-online$lum$, $lum$0c46c9ff-099c-5f97-82bd-26f6977da2cb$lum$::uuid, $lum$Which AI Tool, and Is It Online?$lum$, $lum$There are a dozen AI tools and they all look the same in the box. Two questions tell you which one you actually need today.$lum$, $lum$For most knowledge work, one mainstream chat assistant is plenty, and the single setting that matters most is whether it can browse the live web.$lum$, $lum$beginner$lum$, 6, 2, $lum$published$lum$),
  ($lum$1bf42333-a27b-5898-8458-43b8d8a35ca7$lum$::uuid, $lum$youre-not-behind-and-its-not-cheating$lum$, $lum$0c46c9ff-099c-5f97-82bd-26f6977da2cb$lum$::uuid, $lum$You're Not Behind (and It's Not Cheating)$lum$, $lum$Two quiet fears keep smart people away from AI: that everyone else already gets it, and that using it is a kind of cheating. Both are wrong.$lum$, $lum$Nobody is more than a year ahead of you, and using AI is no more cheating than using a calculator. The only real mistake is not starting.$lum$, $lum$beginner$lum$, 5, 0, $lum$published$lum$),
  ($lum$d14e9d54-e16a-50d2-b2e3-2436208ccd1e$lum$::uuid, $lum$ai-assisted-patient-handoffs-the-sbar-method$lum$, $lum$52bf84a8-edd6-5b0b-93f3-fcd138f3658d$lum$::uuid, $lum$AI-assisted patient handoffs: the SBAR method$lum$, $lum$A rushed handoff is where details fall through the cracks. AI can turn your scattered notes into a clean SBAR in under a minute, so nothing gets lost between you and the next clinician.$lum$, $lum$Paste your rough notes, ask for SBAR format, and you get a structured handoff that the next nurse can act on immediately. You stay in charge of the clinical judgment; the tool handles the structure.$lum$, $lum$beginner$lum$, 15, 5, $lum$published$lum$),
  ($lum$718e3671-24db-5972-be29-4525de9c9e27$lum$::uuid, $lum$ai-assisted-screening-without-baking-in-bias$lum$, $lum$52bf84a8-edd6-5b0b-93f3-fcd138f3658d$lum$::uuid, $lum$AI-Assisted Screening Without Baking In Bias$lum$, $lum$An AI that screens resumes does not remove human bias. It can scale it silently across every applicant at once, and then hand you the result wearing the costume of objectivity.$lum$, $lum$AI may organize and summarize applications against written, job-related requirements, but ranking, scoring, or rejecting candidates is a regulated, high-stakes decision that stays with a person.$lum$, $lum$growing$lum$, 15, 31, $lum$published$lum$),
  ($lum$5243155b-34ae-5912-b919-d188baa6b766$lum$::uuid, $lum$ai-for-lesson-planning-build-a-week-in-minutes$lum$, $lum$52bf84a8-edd6-5b0b-93f3-fcd138f3658d$lum$::uuid, $lum$AI for Lesson Planning: Build a Week in Minutes$lum$, $lum$The Sunday-night planning marathon can become a fifteen-minute draft-and-refine session, with you still making every real teaching decision.$lum$, $lum$Give AI your grade, your standard, and your constraints, and it drafts a coherent week you can shape, so your evening goes to refining instruction instead of building scaffolding from scratch.$lum$, $lum$growing$lum$, 15, 19, $lum$published$lum$),
  ($lum$e23574ab-93e9-5d78-b3ca-774ad04fab25$lum$::uuid, $lum$ai-in-design-copy-fitting-and-ux-writing$lum$, $lum$52bf84a8-edd6-5b0b-93f3-fcd138f3658d$lum$::uuid, $lum$AI in Design: copy-fitting and UX writing$lum$, $lum$UI copy is often treated as an afterthought, which is why most products sound like error message generators.$lum$, $lum$Set the tone system prompt once, then use AI to generate, fit, and audit UX copy. The model is faster at 32-character constraints than any human.$lum$, $lum$confident$lum$, 9, 2, $lum$published$lum$),
  ($lum$7b107772-ee1a-5040-a84c-68ac406b48df$lum$::uuid, $lum$ai-in-finance-quick-p-l-analysis$lum$, $lum$52bf84a8-edd6-5b0b-93f3-fcd138f3658d$lum$::uuid, $lum$AI in Finance: quick P&L analysis$lum$, $lum$A P&L that gets filed and forgotten teaches nobody. Here is how to turn one into a fast, decision-driving analysis without handing your judgment to a model.$lum$, $lum$Use AI to translate a P&L into a health signal, honest variance explanations, and sharp questions. The model surfaces patterns and frames questions well, but it has no company context, so every interpretation and every figure stays with you.$lum$, $lum$confident$lum$, 15, 4, $lum$published$lum$),
  ($lum$b5aecf38-58f5-5cbf-82e8-b772e2f132dc$lum$::uuid, $lum$ai-in-legal-work-limits$lum$, $lum$52bf84a8-edd6-5b0b-93f3-fcd138f3658d$lum$::uuid, $lum$AI in Legal Work: What's Permitted and What's Not$lum$, $lum$AI can save legal professionals real time, but only if you respect the one line you must never cross.$lum$, $lum$AI is a capable assistant for drafting and organizing, never a source of legal authority, so you must verify every citation in a real legal source and keep a qualified human responsible for the work.$lum$, $lum$beginner$lum$, 15, 10, $lum$published$lum$),
  ($lum$e8029024-e784-57fb-a991-3e398563877a$lum$::uuid, $lum$ai-in-marketing-campaign-drafting$lum$, $lum$52bf84a8-edd6-5b0b-93f3-fcd138f3658d$lum$::uuid, $lum$AI in Marketing: campaign drafting$lum$, $lum$Marketing teams that still write every asset from scratch are losing to competitors running 10x the copy variations.$lum$, $lum$Positioning brief first, then copy at volume. Your job shifts from writing every word to making the curatorial decisions machines can't.$lum$, $lum$confident$lum$, 8, 1, $lum$published$lum$),
  ($lum$8af01945-b2ba-5d93-a1ee-e8e12655f57f$lum$::uuid, $lum$ai-in-operations-process-mapping$lum$, $lum$52bf84a8-edd6-5b0b-93f3-fcd138f3658d$lum$::uuid, $lum$AI in Operations: process mapping$lum$, $lum$Every operations problem is really a documentation problem. And documentation is exactly what AI is built for.$lum$, $lum$Capture the process in conversation, map it with AI, then ask where it breaks. You can't fix what isn't visible.$lum$, $lum$confident$lum$, 10, 3, $lum$published$lum$),
  ($lum$3cc781f0-49a5-5b87-b4c9-1349311f1976$lum$::uuid, $lum$ai-in-product-management-spec-writing$lum$, $lum$52bf84a8-edd6-5b0b-93f3-fcd138f3658d$lum$::uuid, $lum$AI in Product Management: spec writing$lum$, $lum$The PRD that used to take a PM two days to write now takes two hours: if you know which parts to delegate.$lum$, $lum$Write the problem statement yourself, delegate the scaffolding. AI is excellent at structure and edge-case generation, terrible at identifying the actual problem.$lum$, $lum$confident$lum$, 8, 0, $lum$published$lum$),
  ($lum$150c8973-03f5-5e8e-bc31-fb560101630d$lum$::uuid, $lum$ai-in-your-classroom-setting-honest-expectations$lum$, $lum$52bf84a8-edd6-5b0b-93f3-fcd138f3658d$lum$::uuid, $lum$AI in Your Classroom: Setting Honest Expectations$lum$, $lum$Your students are already using AI. The real question is whether you have told them clearly when it helps their learning and when it quietly does the learning for them.$lum$, $lum$A clear, honest classroom AI policy names where the tool supports thinking and where it replaces the specific skill an assignment was built to develop, stated in plain language students and families can actually follow.$lum$, $lum$growing$lum$, 15, 28, $lum$published$lum$),
  ($lum$002434d9-17a1-51ca-89c2-b55857bb9fa8$lum$::uuid, $lum$build-a-shift-change-briefing-in-five-minutes$lum$, $lum$52bf84a8-edd6-5b0b-93f3-fcd138f3658d$lum$::uuid, $lum$Build a shift-change briefing in five minutes$lum$, $lum$At shift change you are handing off a whole assignment, not one patient. AI can turn your running notes for the group into a prioritized briefing, so the oncoming team knows who needs them first.$lum$, $lum$Feed the tool your notes for the full assignment and ask for a triage-ordered briefing. It surfaces who is unstable, what is pending, and what is due, and you confirm the priorities match your clinical read.$lum$, $lum$growing$lum$, 7, 9, $lum$published$lum$),
  ($lum$876f6e22-cd9c-56b6-a504-f9b483db6f40$lum$::uuid, $lum$building-rubrics-and-assessment-frameworks$lum$, $lum$52bf84a8-edd6-5b0b-93f3-fcd138f3658d$lum$::uuid, $lum$Building Rubrics and Assessment Frameworks$lum$, $lum$A good rubric makes grading fair, fast, and defensible. Building one from scratch is the reason so many assignments end up graded on vibes.$lum$, $lum$Describe the assignment and what mastery looks like, and AI drafts a structured analytic rubric with criteria and parallel level descriptors you calibrate, turning a two-hour build into a focused review.$lum$, $lum$growing$lum$, 15, 26, $lum$published$lum$),
  ($lum$8c618ae8-3341-5322-805f-e812559ab2bf$lum$::uuid, $lum$building-your-response-template-library$lum$, $lum$52bf84a8-edd6-5b0b-93f3-fcd138f3658d$lum$::uuid, $lum$Building Your Response Template Library$lum$, $lum$You answer the same twenty questions every week, retyping a slightly different version each time. AI can turn those into a template library so every common reply starts at 80 percent.$lum$, $lum$Use AI to build reusable, well-structured response templates with clear placeholders, so common tickets start from a strong consistent base that you personalize per customer from your real systems.$lum$, $lum$growing$lum$, 15, 37, $lum$published$lum$),
  ($lum$27a7a2e1-02c9-5c58-a404-44ed2f094f2d$lum$::uuid, $lum$client-communication-legal$lum$, $lum$52bf84a8-edd6-5b0b-93f3-fcd138f3658d$lum$::uuid, $lum$Client Communication Templates for Legal Professionals$lum$, $lum$Build clear, reassuring client messages once, then reuse them for the updates you send all the time.$lum$, $lum$Use AI to build reusable, plain-language templates for routine client communication, with the specifics and legal judgment left to you and the confidential details kept out of public tools.$lum$, $lum$beginner$lum$, 15, 14, $lum$published$lum$),
  ($lum$fbe02c61-a252-57ed-9306-69e4883688a6$lum$::uuid, $lum$compliance-first-what-ai-cant-touch$lum$, $lum$52bf84a8-edd6-5b0b-93f3-fcd138f3658d$lum$::uuid, $lum$Compliance First: What AI Can't Touch$lum$, $lum$The fastest way to turn a productivity win into a regulatory incident is to paste the wrong thing into a chat box. In finance, what you put in matters as much as what you get out, and some things must never go in at all.$lum$, $lum$Before AI touches any task, know what is categorically off-limits. Material non-public information, client data, licensed professional judgment, and the system of record are lines you do not cross, because no convenience is ever worth a compliance breach.$lum$, $lum$growing$lum$, 15, 24, $lum$published$lum$),
  ($lum$b35395ca-efaa-5d68-9511-2de01975092b$lum$::uuid, $lum$confidentiality-and-ai-legal$lum$, $lum$52bf84a8-edd6-5b0b-93f3-fcd138f3658d$lum$::uuid, $lum$Confidentiality and AI: A Legal Professional's Guide$lum$, $lum$Client confidentiality and public AI tools do not mix. Here is how to use AI every day without ever crossing that line.$lum$, $lum$Treat public AI tools as untrusted with confidential information, so genericize details or use an approved private tool, and never paste privileged client material into a free service.$lum$, $lum$beginner$lum$, 15, 16, $lum$published$lum$),
  ($lum$2a197824-dfb4-505f-bed6-24ecfa0149ef$lum$::uuid, $lum$contract-summaries-with-ai$lum$, $lum$52bf84a8-edd6-5b0b-93f3-fcd138f3658d$lum$::uuid, $lum$Drafting Contract Summaries with AI$lum$, $lum$Turn a dense 40-page agreement into a clear summary of what actually matters, in minutes.$lum$, $lum$Paste the real contract text and ask for a plain-language summary of the specific terms you name, then verify each one against the document.$lum$, $lum$beginner$lum$, 15, 12, $lum$published$lum$),
  ($lum$ff2265be-c4fc-56f9-8a78-6583fbcea957$lum$::uuid, $lum$de-escalation-language-that-actually-works$lum$, $lum$52bf84a8-edd6-5b0b-93f3-fcd138f3658d$lum$::uuid, $lum$De-escalation Language That Actually Works$lum$, $lum$The gap between a customer who calms down and one who demands a manager is often a handful of words. AI can help you find the words that lower the temperature instead of the ones that raise it.$lum$, $lum$De-escalation is specific, learnable language: acknowledge first, avoid trigger phrases, take ownership, and offer a path with a choice. AI helps you draft and rehearse it; your real-time read of the customer makes it land.$lum$, $lum$growing$lum$, 15, 38, $lum$published$lum$),
  ($lum$c7ea1f73-35d8-5fcc-95b4-c83a9226c750$lum$::uuid, $lum$differentiated-materials-without-the-extra-hours$lum$, $lum$52bf84a8-edd6-5b0b-93f3-fcd138f3658d$lum$::uuid, $lum$Differentiated Materials Without the Extra Hours$lum$, $lum$Your one lesson has to reach a striving reader, a grade-level reader, and a student who finished early and is bored. Making three versions used to mean three times the work. It does not have to anymore.$lum$, $lum$Give AI one strong base text and your specific learners, and it produces leveled versions and supports in minutes, so differentiation becomes editing instead of rebuilding.$lum$, $lum$growing$lum$, 15, 22, $lum$published$lum$),
  ($lum$20fdcd20-fcc3-532e-af2b-e753af841a79$lum$::uuid, $lum$document-review-prep$lum$, $lum$52bf84a8-edd6-5b0b-93f3-fcd138f3658d$lum$::uuid, $lum$AI for Document Review Preparation$lum$, $lum$Walk into a stack of documents already knowing what to look for and how to spot it fast.$lum$, $lum$Use AI to build review checklists, organize what you find, and draft issue summaries, while the actual review judgment and confidentiality stay with you.$lum$, $lum$beginner$lum$, 15, 15, $lum$published$lum$),
  ($lum$d16618b2-d469-58ce-a524-6e01e22f8604$lum$::uuid, $lum$drafting-ai-use-policies-your-team-will-follow$lum$, $lum$52bf84a8-edd6-5b0b-93f3-fcd138f3658d$lum$::uuid, $lum$Drafting AI Use Policies Your Team Will Follow$lum$, $lum$A policy nobody reads is not a policy. It is a document that protects no one and changes nothing while everyone keeps doing exactly what they were already doing.$lum$, $lum$A usable AI policy is short, concrete, and example-driven. It names what is fine, what is off-limits, and where to ask, in language a new hire could follow on day one.$lum$, $lum$growing$lum$, 15, 32, $lum$published$lum$),
  ($lum$74da21a3-46b3-5d9b-a1bb-f6ca90aa103b$lum$::uuid, $lum$drafting-empathetic-responses-to-upset-customers$lum$, $lum$52bf84a8-edd6-5b0b-93f3-fcd138f3658d$lum$::uuid, $lum$Drafting Empathetic Responses to Upset Customers$lum$, $lum$When a customer is angry, the right words are hard to find and easy to get wrong. AI can hand you a calm, warm draft in seconds, so you reply from a clear head instead of a defensive one.$lum$, $lum$Give AI the situation, the fix you can offer, and the tone you want, and it drafts an empathetic reply you tailor, so you start from acknowledgment and a real fix instead of a blank reply box.$lum$, $lum$growing$lum$, 15, 36, $lum$published$lum$),
  ($lum$e7e4a939-b1bb-585a-9f10-2facefabb209$lum$::uuid, $lum$drafting-financial-narratives-and-board-reports$lum$, $lum$52bf84a8-edd6-5b0b-93f3-fcd138f3658d$lum$::uuid, $lum$Drafting Financial Narratives and Board Reports$lum$, $lum$The numbers took an hour to pull. The two pages explaining what they mean took the rest of the afternoon. That second part is where AI earns its place, as long as every figure still comes from you.$lum$, $lum$Feed AI your verified figures and the story you see in them, and it drafts clear, board-ready prose, so you spend your time on judgment and not on wording. The numbers and the interpretation stay yours.$lum$, $lum$growing$lum$, 15, 23, $lum$published$lum$),
  ($lum$3b249ae2-9972-55a7-8893-0d7ad7b2a3fb$lum$::uuid, $lum$employee-communication-templates$lum$, $lum$52bf84a8-edd6-5b0b-93f3-fcd138f3658d$lum$::uuid, $lum$Employee Communication Templates$lum$, $lum$Most HR messages are the same in shape and personal in detail. Build a reusable template library with AI so welcomes, reminders, and announcements start at 80 percent already done.$lum$, $lum$Ask AI for reusable STRUCTURES with clear bracketed placeholders, not one-off messages. The template is the 80 percent that stays the same; you fill the 20 percent from your own records, and you treat sensitive messages as a starting point, never a script.$lum$, $lum$growing$lum$, 15, 35, $lum$published$lum$),
  ($lum$083f1118-db9a-5a34-b410-0e78c3a43cd2$lum$::uuid, $lum$explain-it-in-plain-language-patient-communication$lum$, $lum$52bf84a8-edd6-5b0b-93f3-fcd138f3658d$lum$::uuid, $lum$Explain it in plain language: patient communication$lum$, $lum$A patient who does not understand their discharge instructions is a patient who comes back. AI can translate clinical language into plain words at a reading level real people use, without dumbing down what matters.$lum$, $lum$Give the tool the clinical content and the reading level you want, and it rewrites in plain language. You check that nothing important got lost in translation before it reaches the patient.$lum$, $lum$beginner$lum$, 15, 8, $lum$published$lum$),
  ($lum$54e500e6-97d1-5972-8df3-dfef93e16ecf$lum$::uuid, $lum$first-pass-market-and-competitive-research$lum$, $lum$52bf84a8-edd6-5b0b-93f3-fcd138f3658d$lum$::uuid, $lum$First-Pass Market and Competitive Research$lum$, $lum$The slow part of a market scan is the blank page, not the thinking. AI gives you the map and the question list in minutes, as long as you treat every figure it produces as a lead to verify, never a fact to cite.$lum$, $lum$Use AI to build the structure of your research fast: the questions, the categories, the comparison dimensions. Then confirm every fact, figure, and competitor claim against a primary source before it crosses into a memo or model.$lum$, $lum$growing$lum$, 15, 27, $lum$published$lum$),
  ($lum$57ae1d4b-0838-55a8-adbc-716a4de13b1a$lum$::uuid, $lum$giving-better-feedback-faster$lum$, $lum$52bf84a8-edd6-5b0b-93f3-fcd138f3658d$lum$::uuid, $lum$Giving Better Feedback, Faster$lum$, $lum$A stack of thirty essays does not have to cost you your weekend, and your students do not have to wait two weeks to hear from you.$lum$, $lum$AI turns your shorthand judgment into specific, kind, actionable feedback in the student's own context, so you grade the thinking and let the model do the wording.$lum$, $lum$growing$lum$, 15, 20, $lum$published$lum$),
  ($lum$086b0ab9-8050-523d-aced-d8b4ef392a93$lum$::uuid, $lum$keep-human-connection-in-care$lum$, $lum$52bf84a8-edd6-5b0b-93f3-fcd138f3658d$lum$::uuid, $lum$Keeping the Human Connection in Care$lum$, $lum$AI can write the patient message in seconds, but a message that sounds like a form letter can do more harm than no message at all. This lesson keeps the warmth in when the tool does the typing.$lum$, $lum$Let AI carry the clerical load so you have more time and attention for patients, but always add the human layer it cannot: the specific detail, the genuine reassurance, and a final read in your own voice before anything reaches a patient or family.$lum$, $lum$growing$lum$, 15, 18, $lum$published$lum$),
  ($lum$72db07d3-9a52-5545-a8e5-3eb81cdd8944$lum$::uuid, $lum$legal-research-first-passes$lum$, $lum$52bf84a8-edd6-5b0b-93f3-fcd138f3658d$lum$::uuid, $lum$AI for Legal Research First Passes$lum$, $lum$Use AI to orient yourself on an unfamiliar legal area fast, then verify every rule and citation in a real source before you rely on it.$lum$, $lum$AI is a strong starting point for understanding concepts and framing research questions, but every rule, citation, deadline, and element must be confirmed in an authoritative legal database before you act on it. Orientation from the tool, authority from the law.$lum$, $lum$beginner$lum$, 15, 13, $lum$published$lum$),
  ($lum$94ea936d-e667-5bab-94b4-a702f2f4030f$lum$::uuid, $lum$managing-the-ai-application-flood$lum$, $lum$52bf84a8-edd6-5b0b-93f3-fcd138f3658d$lum$::uuid, $lum$Managing the AI Application Flood$lum$, $lum$Candidates now apply with one click and a generated cover letter. You are not reading more applications. You are reading the same polished template a hundred times, and polish has stopped being evidence.$lum$, $lum$AI inflates application volume and polish, so screen on verifiable, job-related evidence rather than wording quality, and design steps that reward real capability over generated text.$lum$, $lum$growing$lum$, 15, 34, $lum$published$lum$),
  ($lum$8af17bac-51a5-5c21-9b9d-35c48b75aa32$lum$::uuid, $lum$performance-review-language-thats-specific-and-fair$lum$, $lum$52bf84a8-edd6-5b0b-93f3-fcd138f3658d$lum$::uuid, $lum$Performance Review Language That's Specific and Fair$lum$, $lum$"Strong communicator, keep it up" helps no one. The hard part of a review is not the rating; it is turning what you actually saw into specific, fair, usable language an employee can act on.$lum$, $lum$Feed AI your real examples and your honest assessment, and it drafts specific, behavior-based review language, so you replace vague praise with feedback an employee can act on. The judgment stays yours; the wording is what you delegate.$lum$, $lum$growing$lum$, 15, 33, $lum$published$lum$),
  ($lum$8a622838-3935-540c-96d7-468f3b67b0da$lum$::uuid, $lum$protect-clinical-judgment$lum$, $lum$52bf84a8-edd6-5b0b-93f3-fcd138f3658d$lum$::uuid, $lum$Protecting Your Clinical Judgment$lum$, $lum$AI can draft your notes and summarize a chart, but the moment it starts nudging what you think is wrong with the patient, it has crossed a line. This lesson keeps the tool on the right side of it.$lum$, $lum$Use AI to handle the words around care, never the clinical reasoning itself. Form your own assessment first, treat any AI suggestion as a prompt to think rather than an answer, and never let a fluent summary quietly replace your own read of the patient.$lum$, $lum$confident$lum$, 15, 17, $lum$published$lum$),
  ($lum$b86804f9-8ac7-5427-8116-0a2ad1cf94e3$lum$::uuid, $lum$spotting-ai-enabled-fraud-in-your-processes$lum$, $lum$52bf84a8-edd6-5b0b-93f3-fcd138f3658d$lum$::uuid, $lum$Spotting AI-Enabled Fraud in Your Processes$lum$, $lum$The same tools that draft your reports can now clone your CFO's voice, forge a flawless invoice, and write a phishing email with zero tells. The instinct that kept you safe last year is the exact thing attackers are counting on.$lum$, $lum$AI made fraudulent requests cheap, fast, and perfect-looking. The control that still holds is not your eye for fakes, it is verification through a separate trusted channel before any money moves.$lum$, $lum$growing$lum$, 15, 29, $lum$published$lum$),
  ($lum$1cc6bbd0-64d2-5fdf-bfa1-96e8f107401d$lum$::uuid, $lum$summarize-a-long-patient-chart-before-you-walk-in$lum$, $lum$52bf84a8-edd6-5b0b-93f3-fcd138f3658d$lum$::uuid, $lum$Summarize a long patient chart before you walk in$lum$, $lum$A complex patient can have 40 pages of history. You have four minutes before you walk in. AI can pull the picture that matters from the noise, so you arrive informed instead of guessing.$lum$, $lum$Ask for the clinical picture, not a page-by-page summary. A targeted prompt surfaces the active problems, recent changes, and open questions, and you verify the critical facts against the source before acting.$lum$, $lum$growing$lum$, 8, 7, $lum$published$lum$),
  ($lum$6bbe08e8-036f-51b6-9437-82f5c1103eb5$lum$::uuid, $lum$the-accuracy-and-privacy-guardrail-for-clinical-ai$lum$, $lum$52bf84a8-edd6-5b0b-93f3-fcd138f3658d$lum$::uuid, $lum$The accuracy and privacy guardrail for clinical AI$lum$, $lum$In most jobs an AI mistake costs a redo. In healthcare it can cost a patient. This lesson is the safety brief: where these tools fail, and the two rules that keep them useful instead of dangerous.$lum$, $lum$AI is a drafting assistant, never a clinical source. Verify anything that touches care against a real reference, and never put patient identifiers into a tool your organization has not approved.$lum$, $lum$beginner$lum$, 15, 11, $lum$published$lum$),
  ($lum$90c5ee5c-f9fb-5434-8084-e8569537c541$lum$::uuid, $lum$the-verification-rule-every-number-needs-a-source$lum$, $lum$52bf84a8-edd6-5b0b-93f3-fcd138f3658d$lum$::uuid, $lum$The Verification Rule: Every Number Needs a Source$lum$, $lum$AI will hand you a confident, specific, wrong number. The finance professionals who trust AI are the ones who never trust a figure without a source behind it.$lum$, $lum$Treat every figure AI produces as a claim to verify against a primary source, never as a fact. Build the cite-and-check habit into every AI-assisted finance task.$lum$, $lum$growing$lum$, 15, 21, $lum$published$lum$),
  ($lum$f26e0181-bb69-5bc5-af9a-3c6d94a2fd7e$lum$::uuid, $lum$turn-rough-encounter-notes-into-clean-documentation$lum$, $lum$52bf84a8-edd6-5b0b-93f3-fcd138f3658d$lum$::uuid, $lum$Turn rough encounter notes into clean documentation$lum$, $lum$Charting is the tax you pay at the end of every shift. AI can draft the structured note from your shorthand, turning 15 minutes of typing into 3 minutes of review.$lum$, $lum$Capture the encounter in shorthand while it is fresh, then let AI expand it into structured documentation. You review and correct; you never let it fill gaps with things that did not happen.$lum$, $lum$beginner$lum$, 15, 6, $lum$published$lum$),
  ($lum$8fd501bb-da66-5983-96ac-1dfcc2a2a773$lum$::uuid, $lum$using-ai-to-review-your-own-interactions$lum$, $lum$52bf84a8-edd6-5b0b-93f3-fcd138f3658d$lum$::uuid, $lum$Using AI to Review Your Own Interactions$lum$, $lum$The fastest way to get better at support work is honest feedback on your real conversations. AI gives you a private coach you can ask before anyone else ever sees your work.$lum$, $lum$Use AI as a private practice coach on your own de-identified interactions, asking specific and actionable questions, so you improve on your own terms before any formal review.$lum$, $lum$growing$lum$, 15, 41, $lum$published$lum$),
  ($lum$80375829-ef95-598c-8b3f-dc9da43e1617$lum$::uuid, $lum$working-alongside-ai-quality-monitoring$lum$, $lum$52bf84a8-edd6-5b0b-93f3-fcd138f3658d$lum$::uuid, $lum$Working Alongside AI Quality Monitoring$lum$, $lum$More and more support teams have AI scoring every conversation against a rubric. Learning how it works, and exactly where it goes blind, turns it from a thing to fear into a tool that makes you better.$lum$, $lum$AI quality monitoring scores patterns at scale but misses meaning and context, so treat its scores as signals to investigate, not verdicts, and keep a human in every consequential decision.$lum$, $lum$growing$lum$, 15, 39, $lum$published$lum$),
  ($lum$6fdd9be2-1452-5d0a-834a-82115aeb9f66$lum$::uuid, $lum$writing-clean-escalation-handoffs$lum$, $lum$52bf84a8-edd6-5b0b-93f3-fcd138f3658d$lum$::uuid, $lum$Writing Clean Escalation Handoffs$lum$, $lum$A bad handoff makes the customer repeat their whole story to the next person. A clean one is the difference between a smooth resolution and a furious "I already explained this."$lum$, $lum$A clean escalation handoff is a tight summary written for the receiver: the situation, what was tried, the customer's state, and what you need next. AI turns your messy mid-shift notes into that summary in seconds, but you confirm it is accurate before it goes.$lum$, $lum$growing$lum$, 15, 40, $lum$published$lum$),
  ($lum$a8f1356b-bd00-521a-aa75-8fb8f53cc00e$lum$::uuid, $lum$writing-job-descriptions-that-attract-real-candidates$lum$, $lum$52bf84a8-edd6-5b0b-93f3-fcd138f3658d$lum$::uuid, $lum$Writing Job Descriptions That Attract Real Candidates$lum$, $lum$Most job descriptions are a wishlist copied from the last one, written for the company and not the candidate. AI can help you write one that the right person actually wants to answer.$lum$, $lum$Give AI the real role, the must-haves versus nice-to-haves, and your audience, and it drafts a clear, inclusive posting you refine, so you stop scaring off the candidates you want.$lum$, $lum$growing$lum$, 15, 30, $lum$published$lum$),
  ($lum$b308eab3-6296-50eb-987a-05f8508d7a40$lum$::uuid, $lum$writing-to-parents-and-families$lum$, $lum$52bf84a8-edd6-5b0b-93f3-fcd138f3658d$lum$::uuid, $lum$Writing to Parents and Families$lum$, $lum$The message to a worried parent is the one you rewrite four times and still hit send with your stomach in a knot. AI can get you to a calm, clear draft in one pass.$lum$, $lum$Give AI the situation, the facts, the tone you want, and general family context, and it drafts a parent message you refine, so a hard note takes five minutes instead of a dreaded half hour.$lum$, $lum$growing$lum$, 15, 25, $lum$published$lum$),
  ($lum$9fd48222-5d86-5bfc-a8bd-9281206b8e54$lum$::uuid, $lum$disclosing-when-you-used-ai$lum$, $lum$469b3f2f-fa76-5c2f-9227-5293bfcd6e50$lum$::uuid, $lum$Knowing When to Disclose You Used AI$lum$, $lum$Nobody discloses using spell-check. People do expect to know if a condolence note was written by a machine. The line between is worth getting right.$lum$, $lum$Disclose AI use when the other person reasonably expects human effort or authorship, or when it affects trust or stakes, and skip disclosure for routine assistance, using honesty and the recipient's expectations as your guide.$lum$, $lum$confident$lum$, 6, 3, $lum$published$lum$),
  ($lum$397ef739-dceb-509b-88e2-79705000275e$lum$::uuid, $lum$dont-outsource-your-thinking$lum$, $lum$469b3f2f-fa76-5c2f-9227-5293bfcd6e50$lum$::uuid, $lum$Don't Outsource Your Thinking$lum$, $lum$There is a difference between using AI to think faster and using it to stop thinking. The second one quietly erodes the skills you need most.$lum$, $lum$Protect your own judgment by using AI to extend your thinking rather than replace it: form your own view first, use AI to challenge and expand it, and keep practicing the skills you most rely on.$lum$, $lum$confident$lum$, 7, 1, $lum$published$lum$),
  ($lum$0b836e2a-c5c5-58b4-bec0-37583db519f7$lum$::uuid, $lum$owning-the-errors$lum$, $lum$469b3f2f-fa76-5c2f-9227-5293bfcd6e50$lum$::uuid, $lum$Owning the Errors AI Makes on Your Behalf$lum$, $lum$When AI gets something wrong and it goes out under your name, it is your mistake, not the tool's. Accountability does not transfer.$lum$, $lum$You own everything you send, regardless of whether AI helped make it, so build a final-check habit, and if an AI-assisted error slips through, own it cleanly rather than blaming the tool.$lum$, $lum$confident$lum$, 6, 4, $lum$published$lum$),
  ($lum$616a76c2-1770-55c0-a4fa-dfbfeb0873d4$lum$::uuid, $lum$set-your-personal-limits-and-spot-bias$lum$, $lum$469b3f2f-fa76-5c2f-9227-5293bfcd6e50$lum$::uuid, $lum$Set Your Personal Limits and Spot AI Bias$lum$, $lum$A mature AI user is not the one who uses it for everything. It is the one who has decided, on purpose, where they will not.$lum$, $lum$Draw your own lines for where AI does not belong, and stay alert to the bias baked into its answers, so you use the tool with judgment rather than letting it quietly set your standards for you.$lum$, $lum$confident$lum$, 7, 5, $lum$published$lum$),
  ($lum$b2973f7d-5cbf-5c2c-9f1e-7765e91fb253$lum$::uuid, $lum$support-your-decisions-dont-dodge-them$lum$, $lum$469b3f2f-fa76-5c2f-9227-5293bfcd6e50$lum$::uuid, $lum$Support Your Decisions, Don't Dodge Them$lum$, $lum$AI is a brilliant advisor and a terrible decision-maker. Knowing which role to give it is what keeps the decision, and the accountability, yours.$lum$, $lum$Use AI to inform decisions by gathering options, surfacing trade-offs, and stress-testing your reasoning, but make the actual call yourself, because you own the context, the values, and the consequences that AI cannot.$lum$, $lum$confident$lum$, 7, 2, $lum$published$lum$),
  ($lum$22f9642c-1580-58b1-9297-6a2884ea6dff$lum$::uuid, $lum$when-ai-just-agrees-with-you-sycophancy$lum$, $lum$469b3f2f-fa76-5c2f-9227-5293bfcd6e50$lum$::uuid, $lum$When AI Just Agrees With You$lum$, $lum$AI is trained to be agreeable, which means it will happily tell you your bad idea is brilliant. That is a trap worth knowing about.$lum$, $lum$AI tends to flatter and agree because it is built to please, so deliberately ask it to challenge you, argue the other side, and critique your idea, or you will mistake agreement for validation.$lum$, $lum$confident$lum$, 7, 0, $lum$published$lum$),
  ($lum$831e2277-4995-5fb1-a69d-51368c045f21$lum$::uuid, $lum$ai-and-your-privacy$lum$, $lum$a310baa4-1856-5cdd-82c1-5922ad725f39$lum$::uuid, $lum$AI and Your Privacy: What to Share and What Not To$lum$, $lum$One simple rule keeps you out of trouble: never paste anything you would not want on a billboard.$lum$, $lum$Public AI tools may store and review what you type, so strip out names and confidential details, or use an approved private tool, before you paste real work in.$lum$, $lum$growing$lum$, 6, 1, $lum$published$lum$),
  ($lum$f4f68c66-2f07-5f57-a5cd-d155c7e8e9ac$lum$::uuid, $lum$authentic-not-lazy-using-ai-with-integrity$lum$, $lum$a310baa4-1856-5cdd-82c1-5922ad725f39$lum$::uuid, $lum$Authentic, Not Lazy: Using AI With Integrity$lum$, $lum$There is a real line between using AI to do your thinking better and using it to skip thinking entirely. Staying on the right side of it is a skill.$lum$, $lum$Use AI to amplify your own judgment, ideas, and voice rather than to replace them, keeping yourself as the author who directs, checks, and owns the result.$lum$, $lum$growing$lum$, 7, 9, $lum$published$lum$),
  ($lum$7a53116d-422d-5bf5-8f0d-9f0386d02907$lum$::uuid, $lum$catching-the-subtle-errors$lum$, $lum$a310baa4-1856-5cdd-82c1-5922ad725f39$lum$::uuid, $lum$Catching the Subtle Errors AI Slips In$lum$, $lum$The dangerous AI mistakes are not the obvious ones. They are the small, plausible ones that read perfectly and are quietly wrong.$lum$, $lum$Make the AI expose its own weak points by asking it to flag uncertainty, separate fact from inference, and show its sources, so the subtle errors surface before you ship them.$lum$, $lum$confident$lum$, 7, 3, $lum$published$lum$),
  ($lum$7f51ef0c-7de2-5e87-87b5-a9bc9b764372$lum$::uuid, $lum$depth-not-surface-going-beyond-the-obvious-answer$lum$, $lum$a310baa4-1856-5cdd-82c1-5922ad725f39$lum$::uuid, $lum$Depth, Not Surface: Getting Past the Obvious Answer$lum$, $lum$AI's first answer is almost always the average answer: safe, generic, and forgettable. The good stuff is two prompts deeper.$lum$, $lum$AI defaults to the most common, surface-level response, so push past it by asking for the non-obvious angle, demanding specifics over generalities, and making it argue against itself.$lum$, $lum$confident$lum$, 7, 12, $lum$published$lum$),
  ($lum$8ffd3c5f-2e70-5524-9fee-aa386b344c1d$lum$::uuid, $lum$edit-dont-paste-raw$lum$, $lum$a310baa4-1856-5cdd-82c1-5922ad725f39$lum$::uuid, $lum$Edit, Don't Paste Raw: Finishing AI's Work$lum$, $lum$The single habit that separates people who use AI well from people who get caught: they never send the first draft as-is.$lum$, $lum$AI gives you a strong draft, not a finished product, so always do a short editing pass to cut filler, fix what's wrong, and make it sound like you before anything leaves your hands.$lum$, $lum$growing$lum$, 6, 13, $lum$published$lum$),
  ($lum$a1ad841a-5ac6-526b-b70c-5b48555e505b$lum$::uuid, $lum$fact-checking-ai-output$lum$, $lum$a310baa4-1856-5cdd-82c1-5922ad725f39$lum$::uuid, $lum$Fact-Checking AI: A Practical Method$lum$, $lum$A 60-second checking habit is the difference between looking sharp and getting caught out.$lum$, $lum$Treat every AI claim as a draft fact: scan for names, numbers, and dates, verify those against a real source, and never paste an unchecked specific.$lum$, $lum$growing$lum$, 7, 0, $lum$published$lum$),
  ($lum$2c4315ba-aff6-5e90-85c2-fa6bb19f65dd$lum$::uuid, $lum$is-this-a-fireable-offense-ai-policy-at-work$lum$, $lum$a310baa4-1856-5cdd-82c1-5922ad725f39$lum$::uuid, $lum$Is This a Fireable Offense? Reading AI Policy at Work$lum$, $lum$The scariest question about workplace AI is the one nobody asks out loud: am I allowed to use this, and could it get me in trouble?$lum$, $lum$Most AI trouble at work comes from data and disclosure, not the tool itself. Know your employer's policy, never paste confidential or personal data into unapproved tools, and when there is no policy, act as if there is one.$lum$, $lum$growing$lum$, 7, 5, $lum$published$lum$),
  ($lum$d9790939-c93b-5ffc-91a8-5e6f76cd6ff2$lum$::uuid, $lum$keeping-a-team-consistent-with-ai$lum$, $lum$a310baa4-1856-5cdd-82c1-5922ad725f39$lum$::uuid, $lum$Keeping a Whole Team Consistent With AI$lum$, $lum$When everyone on a team uses AI their own way, you get ten different voices and ten different quality levels. Shared setups fix that.$lum$, $lum$Turn your best prompts and standards into shared, reusable assets, a prompt library, a tone guide, and a clear what-to-verify rule, so the whole team produces consistent, on-brand work instead of each person reinventing it.$lum$, $lum$confident$lum$, 8, 7, $lum$published$lum$),
  ($lum$a47e35f8-d763-5560-805c-0f71db4a749b$lum$::uuid, $lum$keeping-your-message-sounding-human$lum$, $lum$a310baa4-1856-5cdd-82c1-5922ad725f39$lum$::uuid, $lum$Keeping Your Message Sounding Human$lum$, $lum$Everyone can now spot AI writing: the throat-clearing intros, the tidy lists, the words no human says out loud. Here is how to scrub it out.$lum$, $lum$AI writing has a recognizable generic sound, so strip the filler openings, the inflated vocabulary, and the over-tidy structure, and add a specific human detail, so your message reads like a person wrote it.$lum$, $lum$growing$lum$, 6, 10, $lum$published$lum$),
  ($lum$d5018f9e-63d8-511f-a528-d3266861a2ce$lum$::uuid, $lum$making-ai-stick-in-your-real-workflow$lum$, $lum$a310baa4-1856-5cdd-82c1-5922ad725f39$lum$::uuid, $lum$Making AI Stick in Your Real Workflow$lum$, $lum$The reason most people stop using AI is not that it failed. It is that they kept forgetting it existed.$lum$, $lum$AI only saves time if it becomes a habit, so attach it to tasks you already do, set a trigger that reminds you to reach for it, and start with one or two routines rather than trying to use it everywhere.$lum$, $lum$growing$lum$, 7, 6, $lum$published$lum$),
  ($lum$7c564a90-4ab6-51de-a61e-e02339f7c2b5$lum$::uuid, $lum$teaching-skeptics-and-bringing-your-team-along$lum$, $lum$a310baa4-1856-5cdd-82c1-5922ad725f39$lum$::uuid, $lum$Teaching Skeptics and Bringing Your Team Along$lum$, $lum$You cannot argue a skeptic into using AI. But you can show them one task it does well and let the result do the talking.$lum$, $lum$Win over reluctant colleagues by addressing the real fear underneath their resistance, then showing a small concrete win on a task they care about, instead of lecturing them on the technology.$lum$, $lum$confident$lum$, 7, 8, $lum$published$lum$),
  ($lum$4a73e2b9-e2fd-5255-b460-71f82cdfe8b3$lum$::uuid, $lum$trust-calibration-when-to-believe-ai$lum$, $lum$a310baa4-1856-5cdd-82c1-5922ad725f39$lum$::uuid, $lum$Trust Calibration: Knowing When to Believe AI$lum$, $lum$AI is right most of the time and wrong with total confidence the rest. The whole skill is telling which is which.$lum$, $lum$Match how hard you check to the type of claim, not your mood. Trust AI on shaping and explaining, verify it on specific facts, current events, and anything high-stakes.$lum$, $lum$growing$lum$, 7, 2, $lum$published$lum$),
  ($lum$aa6943e7-fdd2-587a-a4fe-4a3e7151625f$lum$::uuid, $lum$verifying-at-scale-without-burning-out$lum$, $lum$a310baa4-1856-5cdd-82c1-5922ad725f39$lum$::uuid, $lum$Verifying AI at Scale Without Burning Out$lum$, $lum$If checking AI takes as long as doing the work yourself, you have lost the point. The answer is a system, not more willpower.$lum$, $lum$Build a tiered checking routine so trivial output gets a glance, important output gets a targeted check, and high-stakes output gets full verification, instead of exhausting yourself checking everything equally.$lum$, $lum$confident$lum$, 8, 4, $lum$published$lum$),
  ($lum$008aaca3-dc6d-5151-9c6f-da1c07911371$lum$::uuid, $lum$wrongly-flagged-as-ai-what-to-do$lum$, $lum$a310baa4-1856-5cdd-82c1-5922ad725f39$lum$::uuid, $lum$Wrongly Flagged as AI: What to Do$lum$, $lum$AI detectors are unreliable, and they sometimes flag writing a human genuinely wrote. If it happens to you, panic is not a plan.$lum$, $lum$AI detectors guess and frequently get it wrong, so protect yourself by keeping evidence of your process, and if you are wrongly accused, respond calmly with proof rather than defensiveness.$lum$, $lum$growing$lum$, 6, 11, $lum$published$lum$)
insert into lesson_blocks (id, lesson_id, order_index, type, content, personalizable) values
  ($lum$b98080da-548b-5795-ac86-cfcaff66303b$lum$::uuid, $lum$fa87a7e0-7889-5673-981c-da2cf84fb515$lum$::uuid, 0, $lum$reading$lum$, $lum${"markdown":"Sharing your best prompts with your team multiplies their value. But there is a catch most people hit: they share a clever prompt, and nobody uses it. The prompt was built for how one person works, or it is vague, or it is buried where no one looks. Building templates a team will actually adopt is its own skill.\n\nHere is what makes a team template stick.\n\n**Solve a real, shared pain.** Template the tasks everyone already struggles with and does often: the weekly report, the customer reply, the meeting recap. If it does not address a frequent shared headache, it will not get used. Watch for what people complain about, that is your template list.\n\n**Make the blanks obvious.** A good template is fill-in-the-blank, not interpret-the-intent. Mark exactly what the user supplies with clear brackets: [customer name], [the issue], [desired tone]. The less thinking required to use it, the more it gets used.\n\n**Include an example.** Show a filled-in version alongside the blank one. People copy from examples far more readily than they follow instructions.\n\n**Keep instructions inside the template.** Build the guidance into the prompt itself rather than a separate doc. \"Write a reply to [customer] about [issue]. Be warm and accountable, under 120 words, and end with a clear next step.\" Everything they need is right there.\n\n**Store them where work happens.** A template no one can find does not exist. Put them where the team already works: a shared doc, a pinned channel post, the team's prompt library. Easy to reach beats comprehensive but buried.\n\n**Start small and iterate.** Launch with three strong templates, not thirty mediocre ones. Ask people what is awkward, fix it, and add more based on what they actually ask for.\n\nThe principle underneath all of this: adoption beats cleverness. A simple template people use every day delivers far more value than a brilliant one that sits unused. Build for the person who will reach for it on a busy Tuesday, and make using it easier than not."}$lum$::jsonb, false),
  ($lum$4f0b7c8e-0e73-58fc-9ab1-bfa73dd2bfad$lum$::uuid, $lum$fa87a7e0-7889-5673-981c-da2cf84fb515$lum$::uuid, 1, $lum$try_it_live$lum$, $lum${"instructions":"Turn a common team task into a template people will actually use. Name a frequent task your team does, or use the sample, and create a fill-in-the-blank template with clear brackets, built-in instructions, and an example. Sample: replying to a customer who reports a bug.","system_prompt":"You are helping a team lead create adoptable AI prompt templates. Given a common team task, produce a reusable template that has obvious bracketed blanks, instructions built into the prompt itself, and a short filled-in example beneath it. Keep it simple enough to use on a busy day. No em dashes, no jargon.","ideal_output":"Template: Customer bug-report reply\n\nPrompt to use: \"Write a reply to [customer name] who reported [describe the bug]. Acknowledge the problem clearly, tell them [current status or fix timeline], and reassure them without over-promising. Tone: warm and accountable. Keep it under 120 words and end with a clear next step.\"\n\nFilled-in example: \"Write a reply to Dana who reported that the export button does nothing on the reports page. Acknowledge the problem clearly, tell them our team has reproduced it and a fix is expected within two business days, and reassure them without over-promising. Tone: warm and accountable. Keep it under 120 words and end with a clear next step.\"\n\nUsage note: paste this in, fill the two brackets, and read the draft before sending.","input_placeholder":"Name a frequent team task and I'll build a template for it..."}$lum$::jsonb, true),
  ($lum$64ca2f52-30f2-5049-9bbc-8bc2ee8050f5$lum$::uuid, $lum$fa87a7e0-7889-5673-981c-da2cf84fb515$lum$::uuid, 2, $lum$multiple_choice$lum$, $lum${"stem":"You built a sophisticated, clever prompt and shared it with your team, but weeks later almost no one uses it. Based on this lesson, what most likely went wrong?","options":[{"id":"a","label":"It optimized for cleverness over adoption: too vague or buried, when a simple fill-in-the-blank template stored where work happens would have stuck.","is_correct":true,"explanation":"Correct. Adoption beats cleverness. A simple template with obvious blanks, built-in instructions, and an easy-to-find home gets used; a brilliant one that requires interpretation or hunting does not."},{"id":"b","label":"The prompt wasn't advanced enough, so the team needs an even more sophisticated version.","is_correct":false,"explanation":"More sophistication usually lowers adoption, not raises it. The person reaching for it on a busy Tuesday wants less thinking required, not more."},{"id":"c","label":"Team templates rarely work, so prompts should stay personal.","is_correct":false,"explanation":"Shared templates multiply value when built for adoption. The failure was in the design and placement, not in the idea of sharing."}]}$lum$::jsonb, false),
  ($lum$5be1864c-0ef8-5afe-956c-f0d05f64d359$lum$::uuid, $lum$6176690d-cee6-529a-ab80-6064ee4e0185$lum$::uuid, 0, $lum$reading$lum$, $lum${"markdown":"By now you have probably had moments where AI worked brilliantly: a prompt that nailed it, a setup that saved an hour. The problem is that most people lose those wins. They solve the same problem from scratch next week because they never saved what worked. A personal AI toolkit fixes that. It turns your best discoveries into reusable assets.\n\nYour toolkit has a few parts.\n\n**A saved-prompt library.** When a prompt works really well, save it. Keep them somewhere easy to reach: a note, a doc, or your tool's saved-prompts feature. Group them by job: writing, summarizing, planning, analysis. Next time the task comes up, you start from your proven prompt instead of a blank box.\n\n**Custom instructions.** Most AI tools let you set standing instructions that apply to every chat: who you are, how you like answers formatted, your tone, what to avoid. Set this once and every conversation starts already tuned to you. \"I am an operations manager. Give me concise, structured answers with bullet points. Avoid jargon and filler.\"\n\n**Reusable routines.** The multi-step workflows you have built, like your weekly report process or your content-repurposing chain. Document the steps so you run them the same way every time.\n\n**The right tool for the job.** Part of a mature toolkit is knowing which tool to reach for: a general chat tool for most things, a specialized tool where it clearly wins. You do not need many, you need to know yours well.\n\nHow to build it without it becoming a chore: do not try to assemble it all at once. Each time something works unusually well, take 30 seconds to save it. Over a couple of months, you accumulate a genuinely powerful personal kit that makes you faster than someone starting cold every time.\n\nThe mindset shift is from using AI to building with AI: treating your prompts and setups as tools you sharpen and keep, not throwaway questions."}$lum$::jsonb, false),
  ($lum$9e668cf1-4102-5ecf-9a67-3bdc72bbeb22$lum$::uuid, $lum$6176690d-cee6-529a-ab80-6064ee4e0185$lum$::uuid, 1, $lum$multiple_choice$lum$, $lum${"stem":"You just wrote a prompt that worked unusually well on a task you do every week. According to this lesson's toolkit mindset, what's the move?","options":[{"id":"a","label":"Take 30 seconds to save it, labeled by job, so next time you start from the proven prompt instead of a blank box.","is_correct":true,"explanation":"Correct. Saving wins as you find them is how a toolkit builds without becoming a chore. Over a couple of months these compound into a genuinely powerful personal kit."},{"id":"b","label":"Use it now and move on; you'll remember it next week if you need it.","is_correct":false,"explanation":"That's exactly how people lose their wins and solve the same problem from scratch later. Capturing it is the whole point of a toolkit."},{"id":"c","label":"Wait until you can set aside time to build the entire toolkit at once, then add everything together.","is_correct":false,"explanation":"Trying to assemble it all at once turns it into a chore you abandon. The sustainable method is small, incremental saves each time something works."}]}$lum$::jsonb, false),
  ($lum$e45206ba-c0a0-5230-86ca-ebda7ea789b7$lum$::uuid, $lum$6176690d-cee6-529a-ab80-6064ee4e0185$lum$::uuid, 2, $lum$mini_project$lum$, $lum${"brief":"Start your AI toolkit today with three real entries. First, find one prompt you have used recently that worked well, clean it up slightly, and save it in a dedicated note or doc labeled by its job. Second, write a short custom-instructions block describing who you are, how you like answers formatted, and what to avoid, and add it to your AI tool's settings if it supports them. Third, document one multi-step routine you do regularly as a numbered list of prompts you can rerun. Keep all three in one place. From now on, each time something works unusually well, add it. You are building a personal kit that compounds over time.","parts":[]}$lum$::jsonb, false),
  ($lum$d86267ca-bea9-5b5e-b4ba-ad5156b939f1$lum$::uuid, $lum$bd003094-cdd4-5fce-92db-48604e48f2cd$lum$::uuid, 0, $lum$reading$lum$, $lum${"markdown":"A multi-agent loop is a workflow where the output of one AI call becomes the input to another. Instead of asking one model to write, edit, and fact-check in one pass, you have three separate passes that specialize.\n\n**A simple multi-agent loop: research → draft → critique**\n\n**Agent 1: Researcher:** *\"Your job is to research and outline, not to write prose. Given [topic], produce: key facts, 3 competing viewpoints, and a recommended structure.\"*\n\n**Agent 2: Writer:** Feed Agent 1's output as context: *\"You are a writer. Using only the research provided, write [piece]. Focus entirely on clarity and voice.\"*\n\n**Agent 3: Critic:** Feed Agent 2's output: *\"You are an editor. Read the draft critically. Where is the logic weak? What would make a skeptical reader object? Suggest 3 specific improvements.\"*\n\n**Loop back:** Take the critique back to Agent 2: *\"Given this critique, rewrite sections 2 and 3.\"*\n\n**No-code tools for this:** Make.com and n8n both support chained AI calls with variable passing. You can build this loop visually in 30 minutes.\n\nThe quality improvement over single-pass generation is substantial, and the critique step especially surfaces things even skilled human reviewers often miss."}$lum$::jsonb, false),
  ($lum$b30d775a-6bd7-5413-ac48-dcac66af7928$lum$::uuid, $lum$bd003094-cdd4-5fce-92db-48604e48f2cd$lum$::uuid, 1, $lum$before_after$lum$, $lum${"question":"Same article, two approaches. One asks a single agent to do everything; the other runs a research, draft, critique loop. Notice where the quality comes from.","before_prompt":"Write a well-researched, well-edited, fact-checked 1,200-word article on the benefits of strength training for older adults.","after_prompt":"Step 1 (Researcher): Research and outline only, do not write prose. For 'strength training for older adults,' give me key facts, three competing viewpoints, and a recommended structure. Then I'll pass your output to a Writer agent for the draft, and pass that draft to a Critic agent ('You are a skeptical editor: find the three weakest claims and what a doubtful reader would object to') before a final rewrite.","changes":["Splits one overloaded pass into specialist roles, so each agent does one job well instead of juggling research, writing, and checking at once.","Adds an explicit critic step that hunts for weak logic and likely objections, surfacing problems even a careful single pass would miss.","Feeds the output of each step into the next, the critique loop that consistently beats one generalist agent doing everything."]}$lum$::jsonb, true),
  ($lum$51e19b14-84d3-5c4d-bd9e-0a958f8f62b9$lum$::uuid, $lum$bd003094-cdd4-5fce-92db-48604e48f2cd$lum$::uuid, 2, $lum$mini_project$lum$, $lum${"brief":"Your 5-minute exercise: Run the 3-agent loop above manually using ChatGPT tabs (one per agent). Use a piece of content you're working on. How does Agent 3's critique compare to what you would have caught yourself?","parts":[]}$lum$::jsonb, false),
  ($lum$7a539147-85f8-5ad9-b73d-f466aee524b4$lum$::uuid, $lum$f5ae420a-124f-5923-83cd-dc8ef5714c76$lum$::uuid, 0, $lum$reading$lum$, $lum${"markdown":"An API (Application Programming Interface) is a way for one piece of software to talk to another. An LLM API is a way to send text to a model and get text back programmatically, without a web interface, in a way you control and can automate.\n\n**The mental model:** Think of an API call as a very formal version of opening ChatGPT and typing a message. You send: a system prompt (permanent instructions), a user message (the actual input), and some parameters (how creative/focused the response should be). You receive: the model's response as text your code can use.\n\n**Why this matters for non-coders:** Once you can make an API call, you can: automate repetitive prompting tasks, connect AI to your own data, build simple tools for your team, and stop being dependent on whoever manages the ChatGPT account.\n\n**Getting started (no coding required):**\n1. Get an API key from OpenAI or Anthropic (takes 2 minutes, costs a few cents per call)\n2. Use Make.com, Zapier, or n8n, visual interfaces that let you make API calls without writing code\n3. Start with one simple automation: \"whenever I receive an email with [trigger], send it to the API with this prompt, and [do something with the output]\"\n\n**The one concept to understand:** Tokens. API calls are priced by tokens (roughly 4 characters = 1 token). A short email costs $0.001. This is not expensive."}$lum$::jsonb, false),
  ($lum$543f9424-ccc3-53a9-aaf8-5bd0256fd696$lum$::uuid, $lum$f5ae420a-124f-5923-83cd-dc8ef5714c76$lum$::uuid, 1, $lum$multiple_choice$lum$, $lum${"stem":"A colleague insists that calling an LLM API must require real coding skills. Based on this lesson's mental model, what's the most accurate reframe?","options":[{"id":"a","label":"An API call is just a structured message to the model, a system prompt, a user message, and a few parameters, and no-code tools like Make or Zapier can send it for you.","is_correct":true,"explanation":"Correct. The whole mental model is that an API call is a formal version of typing into a chat. Visual tools handle the call, so non-coders can automate without writing code."},{"id":"b","label":"They're right; without writing code you genuinely cannot make API calls.","is_correct":false,"explanation":"No-code platforms exist precisely to make API calls through a visual interface. Coding is not a prerequisite."},{"id":"c","label":"It's only worth it for large companies, since each call is expensive.","is_correct":false,"explanation":"Calls are priced by tokens and a short request costs around a tenth of a cent. Cost is not the barrier the lesson is addressing."}]}$lum$::jsonb, false),
  ($lum$7a9a057f-a0a2-5e49-a89f-2741bcd14013$lum$::uuid, $lum$f5ae420a-124f-5923-83cd-dc8ef5714c76$lum$::uuid, 2, $lum$mini_project$lum$, $lum${"brief":"Your 5-minute exercise: Go to platform.openai.com or console.anthropic.com and create an API key. Open the API playground and make one test call using the visual interface. What did the call cost?","parts":[]}$lum$::jsonb, false),
  ($lum$69da570d-f316-509b-97e1-ce5457fedf87$lum$::uuid, $lum$ac0470cf-2bca-594d-b34e-b4218d902d4a$lum$::uuid, 0, $lum$reading$lum$, $lum${"markdown":"Knowledge workers have a retrieval problem. We produce enormous volumes of notes, highlights, saved articles, meeting summaries, and documents. We can search within each tool. But we can't search *across* them, and we can't ask natural language questions of our own body of knowledge.\n\n**The personal knowledge base (PKB) stack:**\n\n**Step 1: Centralize input:** Pick one place where everything flows in. Notion (most flexible), Obsidian (most powerful for linking), or Roam (most opinionated). The right answer is the one you'll actually maintain.\n\n**Step 2: Add AI retrieval:**\n- **NotebookLM (Google, free):** Upload PDFs, docs, notes. Ask questions, get answers with citations.\n- **Mem.ai:** Takes notes and resurfaces them contextually, with AI synthesis.\n\n**Step 3: Capture habit:** A PKB is only as good as what goes into it. The sustainable minimum: one capture per day. Consistency beats completeness.\n\n**Step 4: Query it:** Once populated, ask questions you couldn't ask before: \"What did I think about remote work 2 years ago?\", \"What notes do I have about pricing strategy?\", \"What was the argument in that article about decision-making?\"\n\nThis is your second brain, queryable."}$lum$::jsonb, false),
  ($lum$23502e39-6a67-5e01-9dc0-35e2f6d7d5b1$lum$::uuid, $lum$ac0470cf-2bca-594d-b34e-b4218d902d4a$lum$::uuid, 1, $lum$multiple_choice$lum$, $lum${"stem":"You set up a personal knowledge base but keep forgetting to add things, so it stays nearly empty and useless. Which fix does this lesson point to?","options":[{"id":"a","label":"A sustainable capture habit, like one capture per day, since a PKB is only as good as what goes into it and consistency beats completeness.","is_correct":true,"explanation":"Correct. The capture habit is the load-bearing step. A modest, consistent input beats an ambitious system you stop feeding."},{"id":"b","label":"Switch to a more powerful note-taking app, since the tool is the real problem.","is_correct":false,"explanation":"The lesson says the right tool is the one you'll actually maintain. Swapping apps doesn't fix an empty base; a capture habit does."},{"id":"c","label":"Wait until you've built up a large backlog, then import everything in one big session.","is_correct":false,"explanation":"A big one-time import is the opposite of the sustainable minimum. Daily consistency is what keeps the base alive and useful."}]}$lum$::jsonb, false),
  ($lum$653bdc6a-af59-571c-a486-e8c3365a3a0c$lum$::uuid, $lum$ac0470cf-2bca-594d-b34e-b4218d902d4a$lum$::uuid, 2, $lum$mini_project$lum$, $lum${"brief":"Your 5-minute exercise: Upload 5 documents to NotebookLM. Ask it 3 questions that require synthesizing across all 5. What did it surface that you'd forgotten?","parts":[]}$lum$::jsonb, false),
  ($lum$cbbe357b-c80f-5e19-9d01-bef0b723d339$lum$::uuid, $lum$dde8fe13-0872-5089-81d5-8319ce926ada$lum$::uuid, 0, $lum$reading$lum$, $lum${"markdown":"\"AI saves me so much time.\" Almost everyone who uses it says this, and almost no one can back it up with a number. That is a problem when your manager asks whether the subscription is worth it, when you want to justify rolling a tool out to your team, or when you are simply trying to decide where AI actually helps versus where it just feels productive. The fix is not complicated: measure it. A rough but honest before-and-after beats a confident guess every time.\n\nThe trap to avoid is counting only the fast part. AI writes the first draft in twenty seconds, and it is tempting to call that the whole saving. But then you spend ten minutes editing it, checking a fact it got wrong, and reshaping the tone. The real number is the total time of the new way, editing and verifying included, against the total time of the old way. Measure the honest version or you will overstate the gain and get caught.\n\n**Pick a few recurring tasks worth measuring.** Do not try to measure everything. Choose three or four things you do often: the weekly status report, customer replies, summarizing a long document, drafting a routine email. Frequent tasks are where real time adds up, and they are easy to compare because you do them the same way each time.\n\n**Time the old way first, honestly.** Before you change anything, note how long the task normally takes you start to finish. A stopwatch on your phone is enough. Do this a couple of times so you have a fair baseline rather than one unusually good or bad run.\n\n**Time the new way, all of it.** Now do the same task with AI and time the entire thing: writing the prompt, waiting, reading the output, editing it, checking anything that needs checking, and finishing. The net saving is old time minus new time. Sometimes it is large. Sometimes, for a task AI is bad at, it is zero or negative, and that is genuinely useful to know.\n\n**Track it over a couple of weeks, then total it up.** One measurement is an anecdote. A handful across two weeks is evidence. Add up the minutes saved per week, and you have a real figure: \"AI saves me about four hours a week, mostly on reporting and first drafts.\" That sentence, backed by numbers, is worth far more than \"it helps a lot.\"\n\nThe point is not to turn your job into a time-and-motion study. It is to replace a vague feeling with something you can defend, so you invest your AI effort where it truly pays off and can make the case to anyone who asks."}$lum$::jsonb, false),
  ($lum$7ef58c69-1339-5c47-8b0a-f09232b53d34$lum$::uuid, $lum$dde8fe13-0872-5089-81d5-8319ce926ada$lum$::uuid, 1, $lum$multiple_choice$lum$, $lum${"stem":"AI drafts your weekly report in 20 seconds, but you then spend 10 minutes editing it and checking a figure it got wrong. What's the honest net saving to record?","options":[{"id":"a","label":"The full new-way time, editing and checking included, compared against the old-way total, since counting only the 20-second draft overstates the gain.","is_correct":true,"explanation":"Correct. The trap is counting only the fast part. The real number is total new time versus total old time, or you'll overstate the saving and get caught."},{"id":"b","label":"The 20-second draft time, because that's the part AI actually did for you.","is_correct":false,"explanation":"That ignores the ten minutes of editing and verifying, which is exactly the inflation this lesson warns against."},{"id":"c","label":"No need to measure; if the task feels faster, it's clearly saving time.","is_correct":false,"explanation":"A vague feeling is what the lesson tells you to replace. Sometimes the honest measurement shows zero or negative saving, which is useful to know."}]}$lum$::jsonb, false),
  ($lum$027d37e6-191f-5190-9e5d-aaf9c4b1d29a$lum$::uuid, $lum$dde8fe13-0872-5089-81d5-8319ce926ada$lum$::uuid, 2, $lum$mini_project$lum$, $lum${"brief":"Prove your real AI time savings with a two-week measurement, then write up the result. First, pick three or four recurring tasks you do often and currently use or could use AI for, such as a weekly report, routine emails, or document summaries. Second, for each task, time the old way honestly start to finish at least once to set a baseline, then time the AI way including prompt writing, editing, and fact-checking, and record the net minutes saved per instance. Third, over two weeks, keep a simple running tally of how many times you did each task and the minutes saved each time, and flag any task where AI saved little or nothing. Finally, total it into a single clear figure with a short breakdown, for example \"about four hours a week saved, mostly on reporting and first drafts, with customer replies saving almost nothing.\" The deliverable is a one-paragraph, numbers-backed summary of your real weekly time saving that you could hand to a manager, plus a short note on which tasks are not worth using AI for.","parts":[]}$lum$::jsonb, false),
  ($lum$a08630d0-1184-5740-95bc-ded5b67a45f0$lum$::uuid, $lum$4fadbee5-5a11-5314-a23a-5aac50a4071b$lum$::uuid, 0, $lum$reading$lum$, $lum${"markdown":"When a task is complex, the instinct is to write one enormous prompt that asks for everything at once. The result is usually mediocre, because the AI is juggling too many goals and does each one half-well. The fix is prompt chaining: break the job into a sequence of focused steps, where the output of one becomes the input to the next.\n\nThink of it like an assembly line instead of a single overworked station. Each prompt does one thing well, and you pass the result along.\n\nHere is a concrete example. Say you want to write a detailed article. Instead of \"write me a complete, well-researched, well-structured 1,500-word article on X,\" you chain:\n\n**Step 1, outline.** \"Create a detailed outline for an article on X, with section headings and the key point of each.\"\n\n**Step 2, review the outline.** You adjust it, reorder, cut a weak section. This checkpoint is the whole advantage. You catch problems before they get baked into 1,500 words.\n\n**Step 3, draft section by section.** \"Write the first section based on this outline point.\" Then the next. Each section gets the AI's full attention.\n\n**Step 4, refine.** \"Review this full draft for flow and tighten any weak transitions.\"\n\nThe benefits are real. Each step is higher quality because it is focused. You get checkpoints where you can steer before errors compound. And when something goes wrong, you fix one step instead of regenerating everything.\n\nWhen to chain rather than use a single prompt: any time the task has distinct stages, any time the output is long, and any time getting it wrong is expensive. Analysis then recommendation. Research then draft. Draft then critique then revise.\n\nOne practical note: because each step builds on the last, keep the chain in a single conversation so the AI retains the context, or paste the previous output into the next step explicitly. The connection between steps is what makes a chain more than a list."}$lum$::jsonb, false),
  ($lum$26de1b7a-a566-5f25-a5fa-17ed41ea7de8$lum$::uuid, $lum$4fadbee5-5a11-5314-a23a-5aac50a4071b$lum$::uuid, 1, $lum$before_after$lum$, $lum${"question":"Same goal, two strategies. Notice why breaking it into steps wins.","before_prompt":"Write me a complete, well-researched, persuasive 1,500-word proposal to convince leadership to adopt a four-day work week, with data, counterarguments, and an implementation plan.","after_prompt":"Let's build this in steps. Step 1: create a detailed outline for a persuasive proposal on adopting a four-day work week, with section headings and the key point of each, including a counterarguments section and an implementation section. Wait for me to approve the outline before we draft anything.","changes":["Breaks one overloaded request into a chain, starting with just the outline, so the AI gives each part its full attention.","Adds a checkpoint to approve the structure before drafting, catching problems before they get baked into 1,500 words.","Sets up a sequence where each step feeds the next, which produces higher quality than a single giant prompt and is easier to fix when one step goes wrong."]}$lum$::jsonb, true),
  ($lum$fa35f863-3577-5238-87d8-6637444b68fc$lum$::uuid, $lum$4fadbee5-5a11-5314-a23a-5aac50a4071b$lum$::uuid, 2, $lum$multiple_choice$lum$, $lum${"stem":"In the outline-then-draft chain, what is the single biggest advantage of pausing to review the outline before any drafting happens?","options":[{"id":"a","label":"It's a checkpoint where you catch structural problems and steer before they get baked into 1,500 words.","is_correct":true,"explanation":"Correct. The lesson calls this checkpoint the whole advantage: fixing a weak structure at the outline stage is far cheaper than after the full draft is written."},{"id":"b","label":"It makes the AI write the later sections faster.","is_correct":false,"explanation":"Speed isn't the point of the checkpoint. The value is catching and correcting problems early, before errors compound through a long draft."},{"id":"c","label":"It lets you skip the drafting step entirely.","is_correct":false,"explanation":"The outline doesn't replace drafting. It improves it, by letting you approve the structure before each section is written with full attention."}]}$lum$::jsonb, false),
  ($lum$057c318e-0ad4-59a5-8966-545e907ac855$lum$::uuid, $lum$a5667a30-ab8a-5786-a0fe-bd4f76c747ea$lum$::uuid, 0, $lum$reading$lum$, $lum${"markdown":"Web scraping sounds like a developer task. It's increasingly not. Several no-code tools make it possible to extract structured data from websites without writing code, and AI makes the extracted data useful.\n\n**The no-code scraping stack:**\n\n**Browse AI (browse.ai):** Point it at a URL, highlight what you want to extract (job titles, product prices, company names), and it builds a scraper you can run on a schedule. The free tier handles most research use cases.\n\n**Clay (clay.com):** Better for enriching lists. Give it a list of companies or people; it scrapes LinkedIn, websites, and other sources to add context.\n\n**ChatGPT with Web browsing:** For one-off scraping, paste a URL and ask for specific information. Not for large-scale, but useful for quick extractions.\n\n**What to do with the data:** Once you have structured data, the AI workflows from earlier modules kick in. \"Here's a list of 50 job postings from Competitor X over 6 months. What are they building?\" That's competitive intelligence that would otherwise take hours.\n\n**Legal note:** Always check a site's robots.txt and Terms of Service before scraping. Public data ≠ permitted to scrape."}$lum$::jsonb, false),
  ($lum$ab44f9d2-e9d0-5006-858b-a7cee1d7c4d0$lum$::uuid, $lum$a5667a30-ab8a-5786-a0fe-bd4f76c747ea$lum$::uuid, 1, $lum$multiple_choice$lum$, $lum${"stem":"Before running a no-code scraper on a public website, what does this lesson say you must do?","options":[{"id":"a","label":"Check the site's robots.txt and Terms of Service, since public data is not the same as data you're permitted to scrape.","is_correct":true,"explanation":"Correct. The legal note is explicit: publicly visible does not mean permitted. Checking robots.txt and the Terms is the responsible first step."},{"id":"b","label":"Nothing, because anything publicly visible is free to scrape at any scale.","is_correct":false,"explanation":"Public visibility and permission to scrape are different things. Ignoring the site's terms can put you on the wrong side of them."},{"id":"c","label":"Hire a developer to review your code, since scraping always requires programming.","is_correct":false,"explanation":"The whole point of the lesson is that no-code tools handle the scraping. The real prerequisite is checking that you're allowed to."}]}$lum$::jsonb, false),
  ($lum$2a48daf8-c8ba-5c14-ae9e-4ad64c3a5dd1$lum$::uuid, $lum$a5667a30-ab8a-5786-a0fe-bd4f76c747ea$lum$::uuid, 2, $lum$mini_project$lum$, $lum${"brief":"Your 5-minute exercise: Go to browse.ai and extract a list from any public website. What does the structured output look like? What could you do with it?","parts":[]}$lum$::jsonb, false),
  ($lum$2ac4069f-2762-5167-9440-b9dd2ec2d30f$lum$::uuid, $lum$28aa7ce9-cf8f-5704-815c-014672c045f5$lum$::uuid, 0, $lum$reading$lum$, $lum${"markdown":"We've spent 29 lessons building AI fluency: using models to draft, synthesize, research, analyze, and create. That's the first era of working with AI. The second era, already beginning for early adopters, is autonomous agents: systems that operate continuously, make decisions, and take actions without requiring your input for every step.\n\n**What's already possible:**\n- Email triage agents that prioritize, draft, and send routine responses based on rules you define\n- Research agents that monitor sources and deliver briefings without being asked\n- Content pipelines that generate, review, and schedule without a human in the loop\n- Customer service agents that handle tier-1 issues and escalate only edge cases\n\n**What the threshold moment looks like for you:** It's the day you realize you spent an hour on work that ran automatically in the background. And the quality was good enough that you approved it without changes.\n\n**How to prepare:**\n1. **Document your decision rules.** The processes you've made explicit are the candidates for automation. Agents can follow rules; they can't infer undocumented preferences.\n2. **Build tolerance for imperfect outputs.** The comparison isn't \"agent vs. perfection\": it's \"agent + your review vs. you doing it manually.\"\n3. **Start small and high-frequency.** Automate recurring low-stakes tasks first.\n\nThe 5 minutes you've invested each day for 30 days isn't about individual productivity tricks. It's about building the mental model to navigate a decade of change."}$lum$::jsonb, false),
  ($lum$184568d1-a8ec-528c-896f-0ec8c81b9f1e$lum$::uuid, $lum$28aa7ce9-cf8f-5704-815c-014672c045f5$lum$::uuid, 1, $lum$multiple_choice$lum$, $lum${"stem":"This lesson says to start preparing for autonomous agents now. Which preparation does it emphasize most?","options":[{"id":"a","label":"Documenting your decision rules, because agents can follow explicit rules but can't infer preferences that stay in your head.","is_correct":true,"explanation":"Correct. The processes you make explicit are the candidates for automation. Undocumented preferences can't be handed to an agent, so they stay manual."},{"id":"b","label":"Waiting for the technology to mature before changing anything about how you work.","is_correct":false,"explanation":"The lesson is about preparing now. Waiting leaves your rules undocumented, which is the exact thing that keeps work manual."},{"id":"c","label":"Automating your highest-stakes task first to prove the value quickly.","is_correct":false,"explanation":"Backwards. The advice is to start small and high-frequency on low-stakes tasks, not to put your riskiest work on autopilot first."}]}$lum$::jsonb, false),
  ($lum$4d92a606-a165-505e-b7cc-b61b6c77e0f4$lum$::uuid, $lum$28aa7ce9-cf8f-5704-815c-014672c045f5$lum$::uuid, 2, $lum$mini_project$lum$, $lum${"brief":"Your final exercise: Write down 3 recurring tasks in your workday that follow clear, documentable rules. For each, write the rules as if you were briefing an agent. These are your automation roadmap for the next 6 months.","parts":[]}$lum$::jsonb, false),
  ($lum$ed48542b-e14e-589c-9637-b8bd56c77082$lum$::uuid, $lum$b7ef57b8-a94f-5219-903f-9ba6b94811eb$lum$::uuid, 0, $lum$reading$lum$, $lum${"markdown":"Some of the best thinking happens out loud with a smart colleague who asks good questions. The problem is that the colleague is busy, the decision is at 11pm, or the matter is too sensitive to talk through with anyone nearby. AI fills that gap surprisingly well. It is an always-available thinking partner that never gets bored of your problem, as long as you treat it as a sounding board and not an oracle.\n\nThe goal is not to ask AI what to do. It is to use it to think more clearly than you would alone.\n\n**Lay out the situation, then ask it to reflect it back.** \"I am trying to decide whether to take on this big client who pays well but is known to be difficult. Here is the situation. First, summarize the real trade-off as you see it, so I know we are looking at the same thing.\" Hearing your own dilemma stated cleanly often sharpens it immediately.\n\n**Have it generate the options you have not considered.** \"What are my options here beyond the obvious yes or no?\" A good sounding board widens the frame, and AI is fast at surfacing the middle paths, the \"yes, but with these conditions\" choices you were not seeing.\n\n**Make it ask you the hard questions.** This is the most valuable move. \"Ask me the five questions a sharp, skeptical advisor would ask before I decide this.\" Then answer them honestly. The questions force out the assumptions and blind spots you would have walked right past.\n\n**Make it argue the side you are avoiding.** \"Make the strongest case for the option I am leaning against.\" If you are quietly set on a choice, this is how you check whether it survives real scrutiny or just feels comfortable.\n\nThen the line that runs through all responsible AI use: you decide. The AI does not know your gut read on the client, your team's current bandwidth, or the values you will not trade away. It helped you think; it does not get to choose. A sounding board that talks back, challenges you, and asks better questions than you would ask yourself is genuinely valuable, and it is available any time you are stuck, as long as you stay the one making the call."}$lum$::jsonb, false),
  ($lum$bc25b2b6-6486-566b-9db2-3f326842423f$lum$::uuid, $lum$b7ef57b8-a94f-5219-903f-9ba6b94811eb$lum$::uuid, 1, $lum$try_it_live$lum$, $lum${"instructions":"Use AI as a sounding board for a real decision you're weighing. Describe the decision and ask it to act as a sharp advisor. Or use the sample: you're deciding whether to hire a second person now, which strains the budget, or wait six months and risk burning out your current team.","system_prompt":"You are a sharp, supportive thinking partner helping someone reason through a decision. Given their situation, first restate the core trade-off in one or two sentences, then ask three to five pointed questions a skeptical advisor would ask before deciding. Do not tell them what to do or guess the answer; your job is to sharpen their thinking, surface assumptions, and widen the options. End by noting that the final call is theirs. No jargon, no em dashes.","ideal_output":"The core trade-off: you can buy capacity and relief now by hiring early, at the cost of financial strain and a rushed hire, or you can protect the budget by waiting, at the cost of risking burnout and possibly losing a current team member, which would cost far more than the salary. Before you decide, answer these: (1) How close to the edge is your team really, is burnout weeks away or months away? (2) If you wait six months and someone quits, what does replacing them actually cost in time, hiring, and lost work? (3) Can the budget genuinely absorb a hire now, or are you hoping it works out? (4) Is there a middle path, a part-time hire, a contractor, or shifting workload, that buys time without the full commitment? (5) What would you advise a peer in this exact spot? Sit with your honest answers, especially to questions 1 and 4. The decision is yours to make, but those answers should make it much clearer.","input_placeholder":"Describe the decision you're weighing and I'll help you think it through..."}$lum$::jsonb, true),
  ($lum$2c6ca63c-056b-515c-b767-2e2c9c2c1479$lum$::uuid, $lum$b7ef57b8-a94f-5219-903f-9ba6b94811eb$lum$::uuid, 2, $lum$multiple_choice$lum$, $lum${"stem":"This lesson calls one move the most valuable way to use AI as a decision sounding board. Which is it?","options":[{"id":"a","label":"Have it ask you the hard questions a sharp, skeptical advisor would ask, then answer them honestly, which forces out the assumptions and blind spots you would walk past.","is_correct":true,"explanation":"Correct. Making it interrogate you, and making it argue the side you are avoiding, is where a sounding board earns its keep. The final call still stays with you, grounded in context the AI does not have."},{"id":"b","label":"Ask it to make the decision for you, since it can weigh the options more objectively than you can.","is_correct":false,"explanation":"The lesson is explicit that the AI does not get to choose. It does not know your gut read, your team's bandwidth, or the values you will not trade away. It sharpens your thinking; you decide."},{"id":"c","label":"Have it confirm the choice you already prefer so you can move forward with confidence.","is_correct":false,"explanation":"That defeats the purpose. The lesson tells you to have it make the strongest case for the option you are leaning against, precisely so your choice survives scrutiny rather than just feeling comfortable."}]}$lum$::jsonb, false),
  ($lum$c9ca1b65-8f33-53ec-a812-c7be55eb4922$lum$::uuid, $lum$7d5bf106-8b58-59ab-bcd4-de5ebfbc3019$lum$::uuid, 0, $lum$reading$lum$, $lum${"markdown":"Your team sends the same kinds of messages all the time: status updates, project kickoffs, deadline reminders, meeting recaps, bad-news notices. Each one gets written from scratch, slightly differently, by whoever happens to be doing it. That is wasted effort and inconsistent results. A small library of AI-built templates fixes both.\n\nThe idea is to use AI once to create a strong, reusable template for each common message, then fill in the specifics each time instead of starting over.\n\nHere is how to build a good template with AI. Describe the message type, the audience, and what it always needs to include. \"Create a reusable template for a weekly project status update to stakeholders. It should always cover progress, risks, and next steps, in a calm and confident tone. Mark the parts I fill in each week with brackets.\"\n\nWhat comes back is a structure you can use every week: clear sections, the right tone baked in, and obvious blanks for the specifics. You are no longer writing the message, you are just dropping in this week's details.\n\nThe communication moments most worth templating:\n\n**Status updates.** Same shape every time, so a template saves real effort.\n\n**Bad news or delays.** A good template helps you stay calm, clear, and accountable when it is tempting to ramble or get defensive.\n\n**Recaps and follow-ups.** A template ensures action items and owners never get dropped.\n\n**Onboarding and how-to messages.** Write the explanation well once, reuse it forever.\n\nThe payoff is twofold: less time spent on routine writing, and more consistent, professional communication across the whole team. Build the templates once, and the quality holds even on a busy day."}$lum$::jsonb, false),
  ($lum$4dcfcf36-bb41-5bd0-bca4-4f64fa42c469$lum$::uuid, $lum$7d5bf106-8b58-59ab-bcd4-de5ebfbc3019$lum$::uuid, 1, $lum$before_after$lum$, $lum${"question":"You need to tell stakeholders a project is slipping. One prompt writes a one-time message, the other builds a reusable asset. Notice what the second one creates.","before_prompt":"Write a message telling stakeholders our launch is delayed by two weeks.","after_prompt":"Create a reusable template for a delay or bad-news notice to stakeholders. It should always open by stating the change plainly, give the reason without getting defensive, lay out the new plan, and close with what we are doing to prevent it next time. Calm, accountable tone. Mark every part I fill in each time with brackets, like [what slipped] and [new date], so I can reuse this whenever a delay comes up.","changes":["Asks for a reusable template rather than a one-off message, so the next delay notice is fill-in-the-blank instead of a blank page.","Bakes in the structure that keeps bad news calm and accountable, which is exactly when it is tempting to ramble or get defensive.","Marks the fill-in parts with brackets, so the quality holds every time even on a busy day."]}$lum$::jsonb, true),
  ($lum$94ef389f-5331-5506-a574-d7160d4f4542$lum$::uuid, $lum$7d5bf106-8b58-59ab-bcd4-de5ebfbc3019$lum$::uuid, 2, $lum$mini_project$lum$, $lum${"brief":"Identify the three messages your team sends most often. Common picks: a weekly status update, a meeting recap with action items, and a delay or bad-news notice. For each one, ask AI to build a reusable template: describe the audience, the tone, and what the message must always include, and ask it to mark the fill-in parts with brackets. Review each template, adjust the wording to fit how your team actually talks, and save all three somewhere your team can find them. You now have a starter communication library that turns routine writing into quick fill-in-the-blank work.","parts":[]}$lum$::jsonb, false),
  ($lum$12b96f62-af87-54d2-be0c-01f293354d8f$lum$::uuid, $lum$9e75bbdf-e265-5937-8ac3-8597413d6e6d$lum$::uuid, 0, $lum$reading$lum$, $lum${"markdown":"Lead research before an outreach or discovery call typically involves: checking the company website, skimming the LinkedIn profile, reading recent news, and trying to find a hook. Manually, this takes 20–30 minutes per lead. With a structured AI workflow, it takes 8–10.\n\n**The lead research stack:**\n\n**Step 1: Context dump.** Paste what you know: the company name, the contact's LinkedIn bio, any recent news you found.\n\n**Step 2: Research prompt.** *\"I'm preparing for an outreach to [contact] at [company]. Based on the context provided: 1) What are the likely pain points for someone in this role? 2) What business context should I know? 3) What are 3 potential hooks? 4) What one question would be most valuable to understand before this call?\"*\n\n**Step 3: Personalization brief.** *\"Now write a 3-sentence opening for an outreach email that references the most specific and relevant point above. Don't be generic.\"*\n\nThe full workflow takes 10 minutes per lead. At 20 leads/week, that's 3–4 hours saved, hours that go back into actual relationship-building."}$lum$::jsonb, false),
  ($lum$c83e76d2-80c2-5d78-bd36-7cc7d3d14800$lum$::uuid, $lum$9e75bbdf-e265-5937-8ac3-8597413d6e6d$lum$::uuid, 1, $lum$before_after$lum$, $lum${"question":"You are prepping outreach to a prospect. One prompt invites the model to guess, the other grounds it in what you found. Notice what you paste in.","before_prompt":"Tell me about Jordan Lee, the VP of Operations at Northwind Logistics, and write me an outreach email.","after_prompt":"I'm preparing outreach to Jordan Lee, VP of Operations at Northwind Logistics. Here is what I gathered: [paste their LinkedIn bio, the company about page, and a recent news item]. Based only on this context: 1) What are the likely pain points for someone in this role? 2) What business context should I know? 3) Give me three potential hooks. 4) What one question would be most valuable to understand before a call? Then write a three-sentence opening that references the most specific point and is not generic.","changes":["Pastes in real gathered material instead of asking the model to recall facts about a specific person, which it would otherwise invent.","Structures the research into role pain points, context, hooks, and the key question, so ten minutes of AI work replaces thirty of tab-switching.","Asks for a personalized opening anchored to a specific point, so the outreach lands as researched rather than mass-produced."]}$lum$::jsonb, true),
  ($lum$7cd044d2-8ed5-55c0-b49a-6c62435beac5$lum$::uuid, $lum$9e75bbdf-e265-5937-8ac3-8597413d6e6d$lum$::uuid, 2, $lum$mini_project$lum$, $lum${"brief":"Your 5-minute exercise: Pick a real prospect you're planning to reach out to. Run the 3-step research stack above. How does the output compare to what you'd have found in 20 minutes of manual research?","parts":[]}$lum$::jsonb, false),
  ($lum$f58f0a24-4c23-5a5c-9da1-c0c428682663$lum$::uuid, $lum$3019a899-ab5e-51b6-9fea-351fd5741163$lum$::uuid, 0, $lum$reading$lum$, $lum${"markdown":"Before you automate anything, you need a sense for which tasks are a good fit for AI and which are not. Picking the wrong ones leads to frustration. Picking the right ones gives you hours back every week.\n\nA task is a strong candidate for AI when it has these traits:\n\n**It repeats.** You do it the same basic way again and again: weekly reports, sorting emails, formatting notes. Repetition is what makes the time saved add up.\n\n**It is mostly about text.** Reading, writing, summarizing, rewriting, categorizing. These are AI's home turf.\n\n**It follows a pattern.** There is a recognizable structure to the input and the output, so the AI can learn what good looks like.\n\n**A human can quickly check the result.** You can glance at the output and tell whether it is right. This safety net matters.\n\nAnd a task is a poor fit, or needs real caution, when:\n\n**It requires facts the AI cannot know.** Current data, internal figures, anything it would have to invent.\n\n**The cost of an error is high and hard to catch.** Legal filings, medical decisions, financial commitments. Use AI to assist, never to act alone.\n\n**It needs genuine human judgment or relationship.** A hard conversation, a sensitive HR matter, a strategic call. AI can help you prepare, but the judgment stays yours.\n\nThe simplest way to start: list the tasks you do every week, then circle the ones that repeat, are about text, follow a pattern, and are easy to check. Those are your first automation targets. Hand those over, keep your judgment on the rest, and the time savings start immediately."}$lum$::jsonb, false),
  ($lum$1c7e51d4-2bd4-59ae-a2b1-a16c31bf1dcd$lum$::uuid, $lum$3019a899-ab5e-51b6-9fea-351fd5741163$lum$::uuid, 1, $lum$fill_blank$lum$, $lum${"template":"The best first tasks to hand to AI are ones that {{1}} often, are mostly about text, follow a pattern, and produce a result a human can quickly {{2}}.","blanks":[{"id":"1","accept":["repeat","recur","repeats"],"ideal":"repeat"},{"id":"2","accept":["check","verify","review"],"ideal":"check"}],"explanation":"Repetitive, text-based, pattern-following tasks where you can quickly check the output are the safest, highest-value place to start with AI."}$lum$::jsonb, false),
  ($lum$b8ca075e-f033-5e4a-997d-da0cb3da7698$lum$::uuid, $lum$3019a899-ab5e-51b6-9fea-351fd5741163$lum$::uuid, 2, $lum$multiple_choice$lum$, $lum${"stem":"Which of these tasks does this lesson say is a poor fit for handing to AI, or one that needs real caution?","options":[{"id":"a","label":"A task where the cost of an error is high and hard to catch, like a legal filing or a financial commitment, so AI should assist but never act alone.","is_correct":true,"explanation":"Correct. High-stakes work where mistakes are expensive and hard to spot, work needing facts the AI cannot know, and work needing genuine human judgment are all poor fits for handing over. AI can help you prepare, but the judgment stays yours."},{"id":"b","label":"Sorting incoming emails into categories each morning, a repetitive text task you can glance at and check.","is_correct":false,"explanation":"That is a strong candidate, not a poor fit. It repeats, it is about text, it follows a pattern, and you can quickly check the result, which is exactly the profile the lesson says to hand over first."},{"id":"c","label":"Reformatting messy meeting notes into a consistent structure every week.","is_correct":false,"explanation":"This is a good fit. It is repetitive, text-based, pattern-following, and easy to verify at a glance, so it belongs in your first wave of automation, not the caution pile."}]}$lum$::jsonb, false),
  ($lum$521eb2bc-9b40-5624-9512-8f9dbde0859b$lum$::uuid, $lum$f09a279f-4fba-5fce-914c-afbd586ae263$lum$::uuid, 0, $lum$reading$lum$, $lum${"markdown":"The frustration with generic AI outputs often comes from the model not knowing your company's specific context: your product, your customers, your voice, your internal terminology. Custom GPTs (or Claude Projects) solve this by letting you inject persistent context that applies to every conversation.\n\n**What to include in a custom GPT for your team:**\n\n**Company context:** What does your company do? Who are your customers? What are the names of your products/features?\n\n**Voice and tone guide:** How does your company communicate? Any words to avoid? Any phrases that are distinctly yours? Paste 3–5 examples of writing you love.\n\n**Common task templates:** Your most frequent workflows: the meeting debrief format, the weekly update structure, the customer email template. Define these as named tasks: \"When I say 'debrief mode', use this format...\"\n\n**Reference documents:** FAQs, pricing tables, product specs, anything the model might need to answer common questions accurately.\n\n**Building it:** In ChatGPT, go to \"Explore GPTs\" → \"Create.\" In Claude, use \"Projects.\" The setup takes 30–60 minutes once, and every team member can then use it."}$lum$::jsonb, false),
  ($lum$feeb84fa-a37f-53f8-9581-4bddb3303441$lum$::uuid, $lum$f09a279f-4fba-5fce-914c-afbd586ae263$lum$::uuid, 1, $lum$multiple_choice$lum$, $lum${"stem":"What specific problem does building a custom GPT (or Claude Project) for your team solve, according to this lesson?","options":[{"id":"a","label":"It injects persistent context (your products, customers, voice, and terminology) into every conversation, so outputs fit your specific situation instead of being generic.","is_correct":true,"explanation":"Correct. Generic outputs come from the model not knowing your company's context. Loading that context once so it applies to every chat is exactly what a custom GPT or Project does."},{"id":"b","label":"It makes the underlying model smarter and more accurate at general reasoning tasks.","is_correct":false,"explanation":"A custom GPT does not change the model's reasoning ability. It supplies your context, which is what makes the answers fit your situation, not a smarter model."},{"id":"c","label":"It removes the need to ever review outputs, since the helper now knows everything about your company.","is_correct":false,"explanation":"Persistent context improves relevance, but it does not remove your responsibility to check the output. Reference documents can still be misread or go out of date."}]}$lum$::jsonb, false),
  ($lum$30f58eff-3fd8-5716-a34a-47bf42eca693$lum$::uuid, $lum$f09a279f-4fba-5fce-914c-afbd586ae263$lum$::uuid, 2, $lum$mini_project$lum$, $lum${"brief":"Your 5-minute exercise: Write the first draft of a system prompt for a custom GPT for your team. Start with: what the company does, 3 voice guidelines, and one common task template.","parts":[]}$lum$::jsonb, false),
  ($lum$199ce47d-9032-52bb-ad71-53de275cf3de$lum$::uuid, $lum$ebc313c3-7d32-5f03-933b-151179686c92$lum$::uuid, 0, $lum$reading$lum$, $lum${"markdown":"Most people use AI one question at a time, starting fresh each time. That is fine for one-off tasks. But the real time savings come from building a workflow: a repeatable routine for a task you do over and over.\n\nA workflow is not complicated. It is just a job broken into steps, with a reliable prompt for each step, that you can run the same way every time. Think of a recipe you do not have to reinvent.\n\nHere is how to build one. Pick a task you repeat, say, processing incoming customer feedback. Break it into the steps you actually take:\n\n**Step 1:** Sort each piece of feedback into a category (bug, feature request, praise, complaint).\n\n**Step 2:** Summarize the main point in one sentence.\n\n**Step 3:** Draft a suggested response.\n\nNow write a clear prompt for each step, and save those prompts somewhere you can reuse them. Each week, you paste in the new feedback and run the same three prompts. The task that used to take an hour now takes ten minutes, and the output is consistent every time.\n\nThe key habits that make workflows reliable:\n\n**Make each step do one thing.** Small, single-purpose steps are easier to get right than one giant prompt that tries to do everything.\n\n**Save your prompts.** A workflow only saves time if you do not rewrite it each time. Keep your prompts in a doc, a note, or the tool's saved-prompts feature.\n\n**Keep a checkpoint.** Build in a moment where you review the output before it goes anywhere. The workflow speeds up the work, but you still approve the result.\n\nStart with one task you do every week. Turn it into a workflow once, and it pays you back every week after."}$lum$::jsonb, false),
  ($lum$4dcafdcd-a80e-561e-9dea-611ac713eb0a$lum$::uuid, $lum$ebc313c3-7d32-5f03-933b-151179686c92$lum$::uuid, 1, $lum$before_after$lum$, $lum${"question":"Same recurring task, two approaches. Notice why the second one keeps paying off.","before_prompt":"Help me deal with this week's customer feedback. [pastes a pile of feedback and improvises a new prompt every week]","after_prompt":"I run the same three steps on customer feedback each week, so here is my saved workflow. Step 1: sort each item into bug, feature request, praise, or complaint. Step 2: summarize each in one sentence. Step 3: draft a suggested reply for the complaints. Here is this week's feedback: [paste]. Run step 1 first and wait for me to confirm before moving on.","changes":["Breaks the task into clear, single-purpose steps instead of one vague request, so each step is reliable.","Reuses the same saved prompt every week rather than improvising, so the work gets faster and more consistent over time.","Builds in a checkpoint to confirm before continuing, keeping you in control of the output."]}$lum$::jsonb, true),
  ($lum$3fd5d523-17ce-5dc8-8933-7eada1ff7af8$lum$::uuid, $lum$ebc313c3-7d32-5f03-933b-151179686c92$lum$::uuid, 2, $lum$multiple_choice$lum$, $lum${"stem":"This lesson lists the habits that make an AI workflow reliable. Which best captures them?","options":[{"id":"a","label":"Make each step do one thing, save your prompts so you do not rewrite them, and keep a checkpoint where you review the output before it goes anywhere.","is_correct":true,"explanation":"Correct. Small single-purpose steps are easier to get right than one giant prompt, saved prompts are what make the workflow actually save time, and the checkpoint keeps you approving the result."},{"id":"b","label":"Combine every step into one large prompt so the AI can do the whole task in a single pass.","is_correct":false,"explanation":"The lesson advises the opposite. One giant prompt that tries to do everything is harder to get right than small, single-purpose steps you can check along the way."},{"id":"c","label":"Rewrite the prompts fresh each week so they stay tailored to that week's data.","is_correct":false,"explanation":"Rewriting each time defeats the purpose. A workflow only pays you back if you save the prompts and reuse them, dropping in the new data each run."}]}$lum$::jsonb, false),
  ($lum$9f90633e-6060-5fac-93d4-0232d492c2c3$lum$::uuid, $lum$b7df9934-e2fd-594b-aee9-272078b3ac75$lum$::uuid, 0, $lum$reading$lum$, $lum${"markdown":"Understanding your competition or a new market usually means drowning in scattered information: a website here, a review there, a pricing page, a few articles. The work of turning that mess into a clear picture is exactly what AI is good at, if you feed it real material and give it a structure.\n\nThe most important rule first: do not ask AI to tell you facts about a specific competitor from memory. It will confidently invent prices, features, and claims that are simply wrong. Instead, gather the real information yourself, then use AI to organize and analyze it.\n\nHere is the workflow that works:\n\n**Gather first.** Collect the raw material: paste in a competitor's pricing page, their about page, a handful of customer reviews, a product description. Real text, not the AI's recollection.\n\n**Give it a framework.** Tell the AI how to organize it. \"Based only on the text I pasted, build a comparison of these three competitors across price, target customer, key features, and what customers praise or complain about. Put it in a table.\"\n\n**Ask for the insight.** Once it is organized, push further. \"Based on this, where is there a gap none of them are filling? What do customers consistently complain about across all three?\" This is where AI earns its keep, spotting patterns across the material.\n\nThe division of labor is clear. You bring the real facts. AI brings the organization and pattern-spotting. And because you gathered the source material, you can trust the analysis far more than if you had let the AI invent it.\n\nAlways sanity-check the standout claims against your source material before you put the analysis in front of anyone. Organized does not automatically mean accurate, and you are the one who knows what is real."}$lum$::jsonb, false),
  ($lum$fc477a1e-0c0d-5ffa-a26f-5e18d159636f$lum$::uuid, $lum$b7df9934-e2fd-594b-aee9-272078b3ac75$lum$::uuid, 1, $lum$try_it_live$lum$, $lum${"instructions":"Turn raw competitor material into a structured comparison. Paste real text you have gathered about two or three competitors, or use the sample, and ask for an organized analysis with a framework. Sample: short descriptions of three meal-kit services with their prices and a few customer comments each.","system_prompt":"You are a research analyst helping a non-technical professional. Using only the source text the user provides, organize it into a clear comparison across sensible dimensions (price, target customer, key features, common praise and complaints) and then identify patterns and gaps. Do not add facts that are not in the provided text. If something is not stated, say so. No em dashes.","ideal_output":"Here is a comparison based only on the text you provided.\n\nPrice: A is the cheapest at the entry tier, B sits in the middle, C is premium.\nTarget customer: A targets budget-conscious families, B targets busy couples, C targets foodies who want gourmet options.\nKey features: all three offer weekly boxes; only C offers a chef-designed premium line; only B offers a flexible skip-a-week option mentioned in the text.\nCommon praise: across all three, customers praise ingredient freshness.\nCommon complaints: A and B both get complaints about packaging waste; C gets complaints about price.\n\nPattern and gap: every service is praised for freshness and several are criticized for packaging waste, so an eco-friendly packaging angle is a gap none of them clearly fills based on this text. Note: none of the source text mentions delivery speed, so I cannot compare that.","input_placeholder":"Paste real competitor text and I'll organize and analyze it..."}$lum$::jsonb, true),
  ($lum$a0110c53-22d3-5bfd-a9e2-288683800e6a$lum$::uuid, $lum$b7df9934-e2fd-594b-aee9-272078b3ac75$lum$::uuid, 2, $lum$multiple_choice$lum$, $lum${"stem":"This lesson opens with one rule it calls the most important for competitive research. Which is it?","options":[{"id":"a","label":"Do not ask AI for facts about a specific competitor from memory, because it will confidently invent prices, features, and claims. Gather the real material yourself, then use AI to organize and analyze it.","is_correct":true,"explanation":"Correct. The division of labor is the whole point: you bring the real facts, AI brings the organization and pattern-spotting. Because you gathered the source text, you can trust the analysis."},{"id":"b","label":"Always ask AI for the most recent pricing and feature data, since it stays current with competitor websites.","is_correct":false,"explanation":"The lesson warns directly against this. The model does not have reliable current data on a specific competitor and will fabricate it. You must paste in the real material."},{"id":"c","label":"Once AI organizes the comparison into a table, you can present it as is, because structure guarantees accuracy.","is_correct":false,"explanation":"Organized does not mean accurate. The lesson says to sanity-check the standout claims against your source material before putting the analysis in front of anyone."}]}$lum$::jsonb, false),
  ($lum$d1266491-5bb6-5dc7-933c-c5557634ccb2$lum$::uuid, $lum$60792d9c-de45-5fcb-a425-4e6d113f382e$lum$::uuid, 0, $lum$reading$lum$, $lum${"markdown":"Competitive intelligence is one of those things everyone agrees is important and almost no one does consistently. The problem is collection: someone has to go check all the sources on some cadence, and that person usually stops after two weeks.\n\n**The monitoring stack:**\n\n**Tier 1: Free, automated:**\n- Google Alerts for competitor names + key terms\n- LinkedIn notifications on competitor company pages\n- RSS feeds for their blog (Feedly, free tier)\n\n**Tier 2: Weekly synthesis:**\nOnce per week, dump any alerts/posts/news into ChatGPT: *\"Here are updates from my competitors this week: [paste]. Summarize: 1) Any product changes, 2) Any positioning shifts, 3) Any strategy signals, 4) One implication for us.\"*\n\n**Tier 3: Quarterly deep dive:**\nEvery quarter, give ChatGPT each competitor's current homepage copy, pricing page, and job postings: *\"Compare these competitors across: positioning, target customer, price point, growth signals. What gaps are they leaving that we could own?\"*\n\nThe stack requires setup once and 20 minutes weekly. Most teams track competitors 0 hours per week until they're surprised."}$lum$::jsonb, false),
  ($lum$92c4897e-fc0c-574b-b8b5-09db98817b40$lum$::uuid, $lum$60792d9c-de45-5fcb-a425-4e6d113f382e$lum$::uuid, 1, $lum$fill_blank$lum$, $lum${"template":"Competitive intelligence usually fails not because people doubt its value but because of {{1}}: someone has to keep checking the sources on a cadence and most people stop after two weeks. The stack fixes this by automating collection, synthesizing every {{2}}, and running a deep dive every quarter.","blanks":[{"id":"1","answer":"collection","alternatives":["the collection","gathering"]},{"id":"2","answer":"week","alternatives":["weekly"]}]}$lum$::jsonb, false),
  ($lum$e30bcecc-e01a-5a77-89be-88835165b101$lum$::uuid, $lum$60792d9c-de45-5fcb-a425-4e6d113f382e$lum$::uuid, 2, $lum$mini_project$lum$, $lum${"brief":"Your 5-minute exercise: Set up Google Alerts for your two main competitors right now. While you're there, write one sentence describing each competitor's current positioning.","parts":[]}$lum$::jsonb, false),
  ($lum$5f9b6a5b-f646-5e8a-ae3b-9b5b08f2340a$lum$::uuid, $lum$8672ffe6-572f-5736-8f76-b31f71352a5b$lum$::uuid, 0, $lum$reading$lum$, $lum${"markdown":"Data cleaning (removing duplicates, standardizing formats, filling gaps, reshaping tables) is the part of analytics work that takes the most time and delivers the least insight. It's also the part AI handles remarkably well.\n\n**The plain English approach:**\n\nInstead of learning VLOOKUP or writing Python, describe what you want. Paste a sample of your data (10–20 rows is enough) and explain the problem:\n\n*\"I have a CSV with customer names in inconsistent formats (some 'First Last', some 'Last, First'). I need them all as 'First Last'. Here's a sample: [paste]. Give me: 1) An Excel formula to standardize column A, 2) A Python pandas snippet for batch processing, 3) A list of rows I need to manually review.\"*\n\n**What this handles well:**\n- Format standardization (dates, phone numbers, names)\n- Duplicate detection logic\n- Missing value imputation rules\n- Table reshaping (wide to long, long to wide)\n\n**What to verify:** Always spot-check 10 random rows after running any AI-generated formula. Edge cases (unusual characters, empty cells) can produce unexpected results.\n\nYou don't need to become a data analyst. You need to describe your data problem clearly."}$lum$::jsonb, false),
  ($lum$093ed94a-8288-5bfd-92d0-685ad2fee44d$lum$::uuid, $lum$8672ffe6-572f-5736-8f76-b31f71352a5b$lum$::uuid, 1, $lum$multiple_choice$lum$, $lum${"stem":"You ran an AI-generated formula to standardize a column of customer names. What does this lesson tell you to do before trusting the result?","options":[{"id":"a","label":"Spot-check about 10 random rows, because edge cases like unusual characters or empty cells can produce unexpected results.","is_correct":true,"explanation":"Correct. AI handles the bulk transformation well, but odd inputs slip through. Checking a sample of rows is the safety net that catches the cases the formula mishandled."},{"id":"b","label":"Nothing, because describing the problem in plain English means the formula is guaranteed correct.","is_correct":false,"explanation":"Plain-English description makes the formula easy to generate, not guaranteed correct. Edge cases still need a spot-check before you rely on the output."},{"id":"c","label":"Re-learn the underlying Excel or pandas syntax so you can audit every cell by hand.","is_correct":false,"explanation":"The whole point is you do not need to master the syntax. A quick spot-check of a sample of rows is enough to catch the edge cases without auditing everything manually."}]}$lum$::jsonb, false),
  ($lum$2b0c74d7-0e96-54a0-b68b-f2c5413d5416$lum$::uuid, $lum$8672ffe6-572f-5736-8f76-b31f71352a5b$lum$::uuid, 2, $lum$mini_project$lum$, $lum${"brief":"Your 5-minute exercise: Find a messy spreadsheet. Pick one specific cleaning problem. Paste a sample and run the prompt above. Does it solve the problem?","parts":[]}$lum$::jsonb, false),
  ($lum$a3afe102-d127-5bad-a6ad-aecdab7db530$lum$::uuid, $lum$eb703d41-6063-5568-84e3-8a03b9c64f78$lum$::uuid, 0, $lum$reading$lum$, $lum${"markdown":"You have a pile of unstructured feedback: 200 survey responses, a quarter of support tickets, exit interview notes, comments from a town hall. Somewhere in there is the signal your team needs, but reading it all and holding the patterns in your head is genuinely impossible past a couple dozen entries. So most feedback gets skimmed, summarized by gut feel, and quietly wasted. AI is excellent at exactly this job: reading a large volume of text and surfacing the themes.\n\nHere is how to do it well.\n\n**Paste the raw feedback and ask for themes, not a summary.** \"Here are 150 open-ended survey responses. Group them into the main recurring themes. For each theme, give it a short name, tell me roughly how many responses mention it, and include two or three representative quotes.\" The counts turn vague impressions into something you can prioritize, and the quotes keep it grounded in real voices.\n\n**Ask it to separate the signal from the noise.** \"Which themes are most common, and which are rare but serious?\" A complaint that shows up twice but describes a safety problem matters more than a minor gripe mentioned fifty times. Ask the AI to flag both, so frequency does not bury severity.\n\n**Push for the actionable cut.** \"Based on these themes, what are the top three things we should consider changing, and what would each address?\" This moves you from \"here is what people said\" to \"here is what to do about it,\" which is the point of gathering feedback in the first place.\n\n**Mind the limits.** Two cautions. First, anonymize: strip names and identifying details before pasting feedback into a public tool, especially anything sensitive like HR or health comments. Second, the AI's counts are estimates, not exact tallies; if a precise number matters, treat its grouping as the map and verify the count yourself. The value is the pattern-finding, which would have taken you a full day, not perfect arithmetic.\n\nDone this way, a backlog of feedback that was too big to use becomes a clear, prioritized picture of what people actually think, in the time it takes to read this lesson."}$lum$::jsonb, false),
  ($lum$15755384-c3d3-5d1c-a4f7-892ef9213ad6$lum$::uuid, $lum$eb703d41-6063-5568-84e3-8a03b9c64f78$lum$::uuid, 1, $lum$multiple_choice$lum$, $lum${"stem":"When grouping a pile of feedback into themes, why does this lesson tell you to ask the AI which themes are rare but serious, not just which are most common?","options":[{"id":"a","label":"Because frequency can bury severity. A complaint mentioned twice that describes a safety problem matters more than a minor gripe mentioned fifty times.","is_correct":true,"explanation":"Correct. Asking it to flag both common and rare-but-serious themes keeps a low-frequency, high-stakes issue from being drowned out by volume."},{"id":"b","label":"Because the rare themes are always the most important and the common ones can be ignored.","is_correct":false,"explanation":"The lesson does not say rare always beats common. It says to surface both, so you weigh frequency and severity together rather than letting one hide the other."},{"id":"c","label":"Because the AI's counts are exact, so the rare themes are guaranteed to be the real priorities.","is_correct":false,"explanation":"The lesson is clear that the counts are estimates, not exact tallies. The reason to ask about rare-but-serious themes is severity, not precision of the numbers."}]}$lum$::jsonb, false),
  ($lum$7a03599d-fbac-52ac-a770-b744bf510cf1$lum$::uuid, $lum$eb703d41-6063-5568-84e3-8a03b9c64f78$lum$::uuid, 2, $lum$mini_project$lum$, $lum${"brief":"Turn a real pile of feedback you have access to into a themed, actionable summary. First, gather a batch of open-ended text, survey comments, support tickets, reviews, or meeting notes, and remove names or identifying details if you are using a public tool. Second, paste it in and ask the AI to group it into named themes, each with a rough count and two or three representative quotes. Third, ask it which themes are most common and which are rare but serious, so frequency does not hide severity. Finally, ask for the top three changes the feedback suggests and what each would address, then sanity-check the groupings against a quick skim of the raw text to make sure nothing important was flattened. The deliverable is a one-page theme summary with counts, quotes, and recommended actions, built from feedback you would otherwise never have fully read.","parts":[]}$lum$::jsonb, false),
  ($lum$c36d5f9c-b410-5221-bc8b-d35d2b11bcca$lum$::uuid, $lum$5ff60ffb-4eff-59d5-9497-fd5664b7b74d$lum$::uuid, 0, $lum$reading$lum$, $lum${"markdown":"Standard Operating Procedures (SOPs) are one of the most valuable and most-neglected assets in any growing company. The bottleneck is always the same: creating them is tedious and time-consuming.\n\n**The video-to-SOP workflow:**\n\n**Step 1: Record a walkthrough.** Have the person who knows the process record a 10–15 minute screen recording + voice narration walking through exactly what they do. Loom is free.\n\n**Step 2: Transcribe.** Use a transcription tool (Whisper, Otter.ai, or ChatGPT's voice input) to convert the narration to text.\n\n**Step 3: SOP generation.** Paste the transcript: *\"This is a transcription of a process walkthrough. Convert it into a step-by-step SOP with: 1) A one-sentence purpose statement, 2) Prerequisites, 3) Numbered steps with clear actions and expected outputs, 4) Common mistakes section, 5) A checklist at the end.\"*\n\n**Step 4: Review and verify.** Have the original person read the draft SOP and catch anything wrong or missing. This takes 10 minutes, not the 2 hours writing from scratch would have taken.\n\nThe bottleneck shifts from \"writing it\" to \"recording it.\" Recording is fast because people can speak their process naturally."}$lum$::jsonb, false),
  ($lum$380d47c9-63b7-5097-8710-d2842f1e7a46$lum$::uuid, $lum$5ff60ffb-4eff-59d5-9497-fd5664b7b74d$lum$::uuid, 1, $lum$multiple_choice$lum$, $lum${"stem":"After adopting the record-transcribe-prompt workflow for SOPs, where does the lesson say the bottleneck moves to?","options":[{"id":"a","label":"From writing the SOP to recording the walkthrough, and recording is fast because people can speak their process naturally.","is_correct":true,"explanation":"Correct. Writing SOPs from scratch was the tedious part. Once a spoken walkthrough plus transcription plus a structuring prompt does the drafting, the only real effort left is recording, which is quick."},{"id":"b","label":"To the transcription step, which is the slowest and most error-prone part of the workflow.","is_correct":false,"explanation":"Transcription is largely automated by tools like Whisper or Otter. The lesson points to recording, not transcription, as where the remaining effort sits."},{"id":"c","label":"Nowhere, because the workflow removes all human effort from creating SOPs.","is_correct":false,"explanation":"Effort does not disappear. It shifts to recording, and the original person still spends about ten minutes reviewing the draft to catch anything wrong or missing."}]}$lum$::jsonb, false),
  ($lum$0ca743fa-895d-5885-b809-c1fe3b2e2e19$lum$::uuid, $lum$5ff60ffb-4eff-59d5-9497-fd5664b7b74d$lum$::uuid, 2, $lum$mini_project$lum$, $lum${"brief":"Your 5-minute exercise: Record a 5-minute Loom of any repetitive process you do regularly. Run it through a transcriber and paste the transcript into the SOP prompt above. Is the output usable?","parts":[]}$lum$::jsonb, false),
  ($lum$a0e73eac-b840-5d6c-a210-fbdb177b6625$lum$::uuid, $lum$30724c39-9997-516e-91ae-2656cf35efe0$lum$::uuid, 0, $lum$reading$lum$, $lum${"markdown":"AI can help you build a presentation far faster, but there is a trap. If you let it generate the whole thing on autopilot, you get a deck that is technically complete and completely forgettable: vague bullet points, generic stock phrases, no spine. The skill is using AI for the parts it does well while keeping the parts that make a deck actually work.\n\nUse AI for structure first. A good presentation is a story, not a pile of slides. Tell the AI your goal and your audience, and ask for the arc. \"I am pitching a budget increase to leadership. Give me a slide-by-slide structure that builds a persuasive case, with one clear message per slide.\" A strong skeleton is half the battle.\n\nThen use it to sharpen each slide's message. The most common deck mistake is slides crammed with text. Ask: \"Rewrite this slide so it makes one clear point in under ten words, with two supporting sub-points.\" That alone makes a deck look professional.\n\nWhere you must stay in charge: the specifics and the proof. AI does not have your real numbers, your customer story, or the one example that will make leadership lean in. Those come from you. The structure and wording can be AI-assisted. The substance cannot be faked.\n\nThe other reason decks look \"AI-made\" is generic language: phrases like \"leverage synergies\" and \"unlock value\" that say nothing. Tell the AI explicitly to use plain, concrete language and to avoid buzzwords. Better yet, give it your real example and ask it to build the point around that.\n\nStructure and clarity from AI, substance and judgment from you. That combination produces a deck that moves fast to build and still feels like a real person made it."}$lum$::jsonb, false),
  ($lum$46f22181-2f49-5f39-9d69-30738b830c95$lum$::uuid, $lum$30724c39-9997-516e-91ae-2656cf35efe0$lum$::uuid, 1, $lum$multiple_choice$lum$, $lum${"stem":"You want AI to help with a leadership pitch deck without it looking generic and AI-made. Which approach gives the best result?","options":[{"id":"a","label":"Ask AI to generate the entire finished deck from a one-line topic and present it as is.","is_correct":false,"explanation":"A deck generated from a one-line topic has no real substance behind it. It will be full of vague bullets and generic phrases, which is exactly the AI-made look you want to avoid."},{"id":"b","label":"Use AI for the narrative structure and to tighten each slide's wording, while you supply the real numbers, examples, and proof.","is_correct":true,"explanation":"Correct. AI is strong at structure and clarity, and you bring the substance it cannot know. That combination is fast to build and still persuasive and authentic."},{"id":"c","label":"Let AI fill every slide with as much detail as possible so nothing important is left out.","is_correct":false,"explanation":"Slides crammed with text are the most common deck mistake. Strong slides make one clear point. More text is not more persuasive, it is harder to follow."}]}$lum$::jsonb, false),
  ($lum$a8d4a66c-f0aa-5b33-97c0-8a779c2e82e0$lum$::uuid, $lum$30724c39-9997-516e-91ae-2656cf35efe0$lum$::uuid, 2, $lum$before_after$lum$, $lum${"question":"Same budget pitch, two prompts. One produces a forgettable autopilot deck, the other a deck that persuades. Notice what you bring versus what AI builds.","before_prompt":"Make me a slide deck to ask leadership for a bigger budget.","after_prompt":"I am pitching a 20 percent budget increase for my support team to leadership. Audience: a CFO who cares about cost per ticket and customer retention. Give me a slide-by-slide structure that builds a persuasive case, one clear message per slide in under ten words each, with two supporting sub-points. Use plain, concrete language and no buzzwords. Leave a clearly marked placeholder on each slide where I will drop in my real numbers. The proof I have: response time fell from 14 hours to 3, and churn dropped 8 percent after we last expanded the team.","changes":["States the specific ask, the audience, and what that audience actually cares about, so the arc is built to persuade this person, not anyone.","Asks for a one-message-per-slide structure in plain language with buzzwords banned, which is what keeps a deck from looking AI-made.","Supplies the real proof and marks where your numbers go, so AI handles structure and wording while the substance stays yours."]}$lum$::jsonb, true),
  ($lum$9985d21b-0cc0-5acf-9125-ab60943e5433$lum$::uuid, $lum$5f4b4f39-02bc-57bd-8555-a15126e5f43c$lum$::uuid, 0, $lum$reading$lum$, $lum${"markdown":"Once you use AI for real writing, two annoying habits show up. The first is bloat: it pads everything. A simple point becomes three sentences, every answer opens with a windup, and it hedges so much that the actual content drowns. The second is format drift: you ask for a five-bullet summary and the first two are bullets, then it slides back into paragraphs, or it forgets halfway through a long piece that you wanted a casual tone. Both are fixable, and fixing them is what separates usable AI writing from the recognizable mush.\n\n**Bloat comes from vague, open instructions, so close them.** AI fills whatever space you give it. If you do not set a limit, it assumes more is better.\n\n- Set a hard cap: \"Maximum 90 words.\" \"Exactly five bullets, one line each.\" \"Two sentences, no more.\"\n- Ban the filler explicitly: \"No introduction, no summary, no throat-clearing. Start with the first real point.\" \"Do not hedge, give me the direct answer.\"\n- Demand the lean version on rewrite: \"Cut this by half without losing any real information.\" It is shocking how much it can drop while keeping the substance, because most of it was padding.\n\n**Format drift comes from long outputs and weak formatting cues, so reinforce them.** The longer the response, the more the model loses track of your earlier instructions.\n\n- State the format sharply and put it last: instructions at the end of the prompt stick better than ones buried at the top.\n- For long pieces, work in sections. Asking for one section at a time keeps the format tight, where one giant request invites drift.\n- When it drifts, do not re-explain everything. Just point: \"Keep the same content but put it back into the five-bullet format I asked for.\" It snaps back instantly.\n\nThe underlying skill is recognizing that AI does not push back on a loose request, it just fills the gap with padding and slowly forgets your constraints. Tight limits, banned filler, and a quick correction when it wanders give you writing that is lean and stays in the shape you wanted, which is most of what makes AI writing look professional instead of generic."}$lum$::jsonb, false),
  ($lum$51e98db5-c8b2-5bb7-94c3-5042595f239a$lum$::uuid, $lum$5f4b4f39-02bc-57bd-8555-a15126e5f43c$lum$::uuid, 1, $lum$before_after$lum$, $lum${"question":"Same request for a product update blurb. One invites bloat and drift, the other locks it down. Notice the constraints.","before_prompt":"Write an announcement for our new scheduling feature that saves users time. Make it engaging and include the key benefits.","after_prompt":"Write an announcement for our new scheduling feature. Constraints: maximum 70 words, no intro or windup, start with what the feature does. Plain, warm tone, no buzzwords, no hedging. End with exactly one clear call to action on its own line. Key facts to include: it auto-suggests meeting times, syncs with existing calendars, and is free for all current users.","changes":["Sets a hard word cap and bans the intro and hedging, which kills the bloat before it starts.","Supplies the specific facts to include, so the AI fills the space with substance instead of padding.","States the format sharply and puts the constraints where they stick, with a single clear call to action, so the output holds its shape."]}$lum$::jsonb, true),
  ($lum$971153c1-c830-5f55-9e19-2f60ccb24f8c$lum$::uuid, $lum$5f4b4f39-02bc-57bd-8555-a15126e5f43c$lum$::uuid, 2, $lum$multiple_choice$lum$, $lum${"stem":"This lesson explains the root cause of both AI bloat and format drift. What is it, and what fixes them?","options":[{"id":"a","label":"AI does not push back on a loose request, it fills the gap with padding and loses track of earlier instructions over long outputs. Hard limits, banned filler, and a quick format correction fix it.","is_correct":true,"explanation":"Correct. Bloat comes from vague, open instructions, and drift comes from long outputs and weak cues. Setting a hard cap, banning the windup, and pointing it back to the format when it wanders are the levers."},{"id":"b","label":"The model is simply too weak to follow instructions, so the only fix is to write everything yourself.","is_correct":false,"explanation":"The lesson shows these are controllable with the right instructions, not a sign you must abandon the tool. Tight limits and a quick correction get lean, on-format writing."},{"id":"c","label":"Bloat and drift are random, so you just keep regenerating until you get a clean version.","is_correct":false,"explanation":"They are not random. They have specific causes: open instructions and long ungrounded outputs. Regenerating wastes time when a word cap and a sharp format cue solve it directly."}]}$lum$::jsonb, false),
  ($lum$2ed8f63c-88d5-5095-ba1f-a1702902721e$lum$::uuid, $lum$610ed6f0-0e97-5367-b4fe-82e52c68da3e$lum$::uuid, 0, $lum$reading$lum$, $lum${"markdown":"Midjourney (and DALL-E, and Stable Diffusion) responds to prompts very differently from text models. Text models reward conversational clarity. Image models reward stacking of specific descriptors.\n\n**The image prompt formula:**\n[Subject] + [Context/setting] + [Lighting] + [Style/medium] + [Technical parameters]\n\nExample: \"Product designer at a wooden desk, morning light from a large window, warm ambient, cinematic editorial photography, 35mm, shallow depth of field --ar 16:9 --v 6\"\n\n**The five levers:**\n\n**Subject:** Be specific. \"A woman\" vs. \"a 30s product manager looking frustrated at a laptop\" produces different results.\n\n**Lighting:** This is the highest-leverage descriptor. \"Golden hour,\" \"overcast flat light,\" \"dramatic rim lighting\". Lighting changes the entire emotional register.\n\n**Style anchor:** Reference a known aesthetic. \"Shot in the style of Magnum Photos,\" \"Bauhaus design poster,\" \"1970s editorial magazine spread.\"\n\n**Camera language:** \"35mm lens,\" \"f/1.4,\" \"medium format,\" \"bird's-eye view\". These cue the model on composition.\n\n**Negative prompts:** Explicitly exclude things. \"--no text, watermarks, extra limbs, oversaturated\" clears the most common artifacts.\n\nStart with the formula, run it, then iterate on whichever lever produced the wrong output."}$lum$::jsonb, false),
  ($lum$bf778b24-fa6b-5998-bb81-06d9d1dbf405$lum$::uuid, $lum$610ed6f0-0e97-5367-b4fe-82e52c68da3e$lum$::uuid, 1, $lum$multiple_choice$lum$, $lum${"stem":"Of the five levers in the image prompt formula, this lesson calls one the highest-leverage descriptor. Which is it, and why?","options":[{"id":"a","label":"Lighting, because it changes the entire emotional register of the image. 'Golden hour' versus 'overcast flat light' produces a completely different feel.","is_correct":true,"explanation":"Correct. The lesson singles out lighting as the highest-leverage descriptor precisely because it shifts the whole emotional register, not just one detail of the scene."},{"id":"b","label":"The technical parameters like aspect ratio and version flags, since they control the final file the most.","is_correct":false,"explanation":"Technical parameters cue composition and format, but the lesson names lighting, not the flags, as the descriptor that most changes how the image lands."},{"id":"c","label":"The negative prompt, because excluding artifacts is what makes an image usable at all.","is_correct":false,"explanation":"Negative prompts clear common artifacts, which is useful cleanup, but they do not set the mood. Lighting is the lever that drives the emotional register."}]}$lum$::jsonb, false),
  ($lum$fdaea641-f430-57f8-8110-d7442c887b80$lum$::uuid, $lum$610ed6f0-0e97-5367-b4fe-82e52c68da3e$lum$::uuid, 2, $lum$mini_project$lum$, $lum${"brief":"Your 5-minute exercise: Think of an image you need for work. Build a prompt using the formula above. Run it in DALL-E (free in ChatGPT). What do you need to change in round 2?","parts":[]}$lum$::jsonb, false),
  ($lum$e5a3780d-c1d2-555b-8749-8ad207a5279c$lum$::uuid, $lum$df21dae9-377b-51cf-9099-5f078d85caa9$lum$::uuid, 0, $lum$reading$lum$, $lum${"markdown":"The most common complaint about AI writing is fair: it sounds like AI. Flat, over-formal, full of phrases no human would actually say. The good news is that this is a fixable problem, and the fix is simple once you know it.\n\nAI writes generically by default because you have not told it whose voice to use. Give it your voice to copy, and the difference is night and day.\n\nThere are two ways to do this, and they work best together.\n\n**Show, do not just tell.** Paste two or three samples of your own writing, then say: \"This is how I write. Study the tone, sentence length, and word choices. Now write the new piece in this same voice.\" Examples teach the AI more than any description could.\n\n**Name your style traits.** Describe what makes your writing yours. \"I write in short sentences. I avoid corporate buzzwords. I use the occasional dry joke. I never start with 'In today's fast-paced world.'\" Specifics like these steer the output hard.\n\nIf you write a lot in one place, save your voice description in the tool's custom instructions or memory so you do not retype it every time. Then every draft starts closer to you.\n\nOne more move that helps: after a draft comes back, point at what is off. \"This second paragraph sounds too corporate, rewrite it the way I would actually say it.\" The AI adjusts, and you have taught it one more thing about your voice.\n\nThe goal is not to hand your writing over to a machine. It is to get a first draft that already sounds like you, so the editing is light and the result is unmistakably yours."}$lum$::jsonb, false),
  ($lum$7bd5680a-2bf5-5ead-9e94-945ff52d3b5c$lum$::uuid, $lum$df21dae9-377b-51cf-9099-5f078d85caa9$lum$::uuid, 1, $lum$before_after$lum$, $lum${"question":"Same task, but the second prompt teaches the AI your voice. Notice what you have to give it.","before_prompt":"Write a LinkedIn post announcing that I'm starting a new job as operations lead.","after_prompt":"Here are two things I've written before so you can learn my voice: [paste two short samples]. My style: short sentences, plain words, a bit of warmth, no buzzwords, and I never use phrases like 'thrilled to announce' or 'humbled.' Now write a LinkedIn post announcing I'm starting a new job as operations lead, in that exact voice.","changes":["Gives the AI real samples of your writing to copy, which teaches it your voice better than any description alone.","Names specific style traits and banned phrases, so it avoids the generic announcement tone everyone recognizes as AI.","Turns a generic request into one anchored to how you actually sound, so the draft needs only light editing."]}$lum$::jsonb, true),
  ($lum$2e40bf46-ad42-50ab-ba7f-141e9fd46630$lum$::uuid, $lum$df21dae9-377b-51cf-9099-5f078d85caa9$lum$::uuid, 2, $lum$multiple_choice$lum$, $lum${"stem":"AI writing keeps coming back sounding generic and over-formal. According to this lesson, what is the most effective fix?","options":[{"id":"a","label":"Paste two or three samples of your real writing and name your specific style traits, so the model copies your actual voice instead of its default.","is_correct":true,"explanation":"Correct. Showing real samples teaches the model more than description alone, and naming traits like short sentences and banned phrases steers it hard. The two together work best."},{"id":"b","label":"Ask it to 'sound more human' and 'be less robotic' and trust it to figure out the rest.","is_correct":false,"explanation":"Vague instructions like that give the model nothing concrete to imitate. It writes generically by default because you have not shown it whose voice to use."},{"id":"c","label":"Accept that AI cannot match a personal voice and rewrite every draft from scratch yourself.","is_correct":false,"explanation":"The lesson's whole point is that this is a fixable problem. With samples and named traits, you get a first draft that already sounds like you and needs only light editing."}]}$lum$::jsonb, false),
  ($lum$d30f4ab2-73e3-51e0-9cb8-28c0bcf99274$lum$::uuid, $lum$383cf262-4694-5db7-a82a-52d56a8cfbc1$lum$::uuid, 0, $lum$reading$lum$, $lum${"markdown":"Here is a quiet superpower for anyone who creates anything: you do not have to start from scratch for every channel. Write one good thing, then use AI to turn it into the five different shapes you need.\n\nThink about how much you already produce that gets used once and forgotten. A detailed report. A long email. A set of meeting notes. A webinar transcript. Each of those is raw material that could become several useful pieces with almost no extra effort.\n\nThe move is simple. Start with one strong source piece, then ask AI to transform it for a specific place and audience. The ideas stay the same. The format and tone change.\n\nSome transformations that work well:\n\n**Long to short.** \"Turn this 1,000-word article into a 5-bullet summary for a busy executive.\"\n\n**Formal to casual.** \"Rewrite this report's key finding as a friendly two-sentence message for our team channel.\"\n\n**One audience to another.** \"I wrote this for customers. Now adapt it for our internal sales team, focusing on what they need to know to sell it.\"\n\n**One format to another.** \"Turn these meeting notes into a clear follow-up email with action items.\"\n\nThe reason this works is that AI is genuinely good at preserving meaning while changing form. You did the hard part, which is having something worth saying. The reshaping is the easy part, and now it is automatic.\n\nA reminder: each repurposed version still deserves a quick read. Different audiences need different things, and you know your audiences better than the AI does. It reshapes, you approve."}$lum$::jsonb, false),
  ($lum$2d60102c-326c-5601-bc3a-02a52b000998$lum$::uuid, $lum$383cf262-4694-5db7-a82a-52d56a8cfbc1$lum$::uuid, 1, $lum$before_after$lum$, $lum${"question":"You wrote a strong customer report and want a version for your team channel. One prompt reshapes well, the other just shrinks it. Notice what the second one names.","before_prompt":"Make this report shorter for my team. [pastes the report]","after_prompt":"Below is a customer-facing report I wrote. Reshape it into a casual update for our internal sales team channel. Keep the core finding, but focus on what sales needs: which customer pain point this addresses and the one line they can use on a call. Friendly tone, three short bullets, under 80 words. Keep my meaning, just change the form. [pastes the report]","changes":["Names the new audience and the place it is going, so the reshape targets the sales team rather than producing a generic shorter version.","Says which angle matters to that audience, so AI surfaces the pain point and the usable line instead of trimming at random.","Sets tone, format, and length and tells it to preserve meaning, so the ideas stay yours and only the form changes."]}$lum$::jsonb, true),
  ($lum$185e919e-66a7-503e-bd3c-73503e36c14a$lum$::uuid, $lum$383cf262-4694-5db7-a82a-52d56a8cfbc1$lum$::uuid, 2, $lum$mini_project$lum$, $lum${"brief":"Take one thing you have already written this month: a report, a long email, a set of notes, anything with real content in it. In a single AI chat, repurpose it into three different formats for three different places. For example: a short summary for a busy executive, a casual update for your team channel, and a follow-up email with clear action items. Paste the source piece once, then ask for each transformation in turn, naming the audience and format each time. Review each version, adjust anything that does not fit the audience, and notice how one piece of work now serves three purposes.","parts":[]}$lum$::jsonb, false),
  ($lum$a9c0a0a0-e6b7-5751-a368-7af0c4271c22$lum$::uuid, $lum$bf5913d3-d1c9-5723-910d-2f1edf820e2b$lum$::uuid, 0, $lum$reading$lum$, $lum${"markdown":"There's a critical difference between asking AI to *rewrite* something and asking it to *restructure* it. Rewriting replaces your words with the model's words. Restructuring keeps your language but reorganizes the logic, the flow, and the hierarchy.\n\n**The structural edit prompt:**\n*\"I've written this [piece]. Don't rewrite the language: I want to keep my voice. Instead: 1) Tell me if the structure makes logical sense, 2) Identify where I've buried the lede, 3) Suggest a better order for the sections, 4) Flag any paragraphs that repeat an idea I already made. Keep my exact wording unless I specifically ask you to change it.\"*\n\nThis gives you editorial feedback without homogenizing your writing.\n\n**When to let it rewrite:** Sections you've already identified as weak. Not the whole piece. Say: \"Paragraph 3 is clunky. Rewrite it in the same general voice as paragraph 1.\"\n\n**The voice preservation trick:** Before editing, paste a sample of writing you love (your own or someone else's). Say: \"Keep edits consistent with this voice: [paste].\" The model uses it as a style anchor.\n\n**What to watch for:** AI has a reflex toward parallel structure and clean transitions. These can smooth out the intentional roughness that makes writing interesting. Read the output critically before accepting."}$lum$::jsonb, false),
  ($lum$4f591ab4-3fac-5d1c-b0c0-3e739a725a71$lum$::uuid, $lum$bf5913d3-d1c9-5723-910d-2f1edf820e2b$lum$::uuid, 1, $lum$before_after$lum$, $lum${"question":"You have a blog post draft you like the wording of but the flow feels off. One prompt erases your voice, the other keeps it. Notice the difference between rewrite and restructure.","before_prompt":"Here's my draft. Rewrite it so it flows better and reads more professionally. [pastes the draft]","after_prompt":"Here is a draft I have written. Do not rewrite the language, I want to keep my voice. Instead: tell me if the structure makes logical sense, point out where I have buried the lede, suggest a better order for the sections, and flag any paragraph that repeats a point I already made. Keep my exact wording unless I specifically ask you to change a section. [pastes the draft]","changes":["Asks for structural feedback instead of a rewrite, so the model diagnoses the flow without replacing your words with its own.","Names the specific structural problems to look for, like a buried lede and repeated points, so the feedback is concrete and actionable.","Tells it to keep your exact wording unless asked, which preserves the voice that a full rewrite would homogenize away."]}$lum$::jsonb, true),
  ($lum$59a11853-fea3-50b0-94b7-42441b644ee2$lum$::uuid, $lum$bf5913d3-d1c9-5723-910d-2f1edf820e2b$lum$::uuid, 2, $lum$mini_project$lum$, $lum${"brief":"Your 5-minute exercise: Take something you've written in the past month. Run the structural edit prompt above. Focus only on the structure feedback. Does it surface something you already half-knew wasn't working?","parts":[]}$lum$::jsonb, false),
  ($lum$9b3a7be6-0860-5464-9710-268ecacaf992$lum$::uuid, $lum$adcfe362-f983-574c-b70d-6c5a10c9fce4$lum$::uuid, 0, $lum$reading$lum$, $lum${"markdown":"Research synthesis is one of the highest-value things AI can do for knowledge workers. But most people approach it wrong: they paste one document at a time and lose the cross-document threads that are the actual value.\n\n**The synthesis workflow:**\n\n**Step 1: Chunk strategically.** Group documents by theme or argument. Process related documents together so the model can surface agreements and contradictions.\n\n**Step 2: Extract before synthesizing.** For each chunk: *\"What are the 3 most important claims in this document? What evidence does it use? What does it assume?\"* Build an extraction document before asking for synthesis.\n\n**Step 3: Cross-document synthesis.** With your extractions: *\"Here's what each document says about [topic]. Where do they agree? Where do they contradict? What question do they collectively fail to answer?\"*\n\n**Step 4: The 1-pager.** *\"Write a 1-page executive summary of the above synthesis. Structure: key finding, three supporting points, one major caveat, one open question.\"*\n\n**What the model can't do:** Evaluate the *quality* of sources or the credibility of methodology. That's your job. Use the model to handle volume; use your judgment to handle quality."}$lum$::jsonb, false),
  ($lum$f52a8a53-3375-5562-8a69-9b35ded26809$lum$::uuid, $lum$adcfe362-f983-574c-b70d-6c5a10c9fce4$lum$::uuid, 1, $lum$multiple_choice$lum$, $lum${"stem":"In the synthesis workflow, why does the lesson tell you to extract claims from each document before asking for a synthesis?","options":[{"id":"a","label":"Building an extraction document first lets the model compare structured claims across sources, surfacing the agreements and contradictions you would miss reading one document at a time.","is_correct":true,"explanation":"Correct. The cross-document threads are the real value, and they only appear when you extract each document's claims, evidence, and assumptions first, then synthesize from those extractions."},{"id":"b","label":"Extraction is just a formality, and you would get the same result by pasting all the documents in at once and asking for a summary.","is_correct":false,"explanation":"Pasting everything at once loses the cross-document threads, which is exactly the mistake the lesson warns against. The extraction step is what makes patterns comparable."},{"id":"c","label":"Because the model can judge which sources are credible once it has the extractions side by side.","is_correct":false,"explanation":"Evaluating source quality and methodology is your job, not the model's. Extraction is about volume and pattern-finding; credibility stays with your judgment."}]}$lum$::jsonb, false),
  ($lum$48091de6-e04f-5543-8f7c-6caf7c878ee8$lum$::uuid, $lum$adcfe362-f983-574c-b70d-6c5a10c9fce4$lum$::uuid, 2, $lum$mini_project$lum$, $lum${"brief":"Your 5-minute exercise: Find 3 documents about the same topic. Run steps 1–3 above. What thread across all three did you miss when reading them individually?","parts":[]}$lum$::jsonb, false),
  ($lum$5787f2e4-f564-55e9-aaf4-ae22e9382e64$lum$::uuid, $lum$a716986f-7c00-5153-a743-95ce7a1cfa3d$lum$::uuid, 0, $lum$reading$lum$, $lum${"markdown":"Brainstorming with AI works best when you treat it as an iterative loop rather than a single prompt. The first output is almost always too generic. The value comes from what you do with it next.\n\n**The loop:**\n\n**Round 1: Diverge:** Ask for 10 options, not 3. More options means more raw material. Prompt: \"Give me 10 different angles on [problem]. Make them genuinely different from each other, not variations on the same theme.\"\n\n**Round 2: Interrogate:** Pick the 2-3 that have something interesting. Ask: \"Why does option 7 work? What's the underlying insight? What would make it stronger?\"\n\n**Round 3: Constrain:** Add a constraint that forces creativity. \"Give me 5 more options, but each one has to be framed around [a constraint you haven't tried].\"\n\n**Round 4: Combine:** \"Take the tension from option 3 and the specificity from option 8 and create something new.\" Combination is often where the best ideas live.\n\nThe whole loop takes 15 minutes and produces something genuinely yours, because you made every curatorial decision. The AI generated the clay; you shaped it."}$lum$::jsonb, false),
  ($lum$215b522d-1873-530e-aafe-f098ee0d78a7$lum$::uuid, $lum$a716986f-7c00-5153-a743-95ce7a1cfa3d$lum$::uuid, 1, $lum$multiple_choice$lum$, $lum${"stem":"What is the core reason brainstorming with AI works better as a multi-round loop than as a single prompt?","options":[{"id":"a","label":"The first output is almost always too generic, so the value comes from interrogating, constraining, and combining the raw options across rounds, with you making every curatorial decision.","is_correct":true,"explanation":"Correct. The AI generates the clay and you shape it. Asking for ten options, probing the interesting ones, adding a constraint, then combining is where the genuinely good, genuinely yours idea emerges."},{"id":"b","label":"Because running more prompts uses the model harder, and a tired model eventually produces better ideas.","is_correct":false,"explanation":"That is not how it works. The loop helps because each round adds your judgment and a new angle, not because of any effect on the model itself."},{"id":"c","label":"Because the best idea is reliably in the first batch, and the later rounds just confirm it.","is_correct":false,"explanation":"The lesson says the opposite: the best idea is almost never in the first output. The combine round, where you fuse the tension of one option with the specificity of another, is often where it lives."}]}$lum$::jsonb, false),
  ($lum$31eb2b88-cb16-55f5-bfe9-7039165c59d9$lum$::uuid, $lum$a716986f-7c00-5153-a743-95ce7a1cfa3d$lum$::uuid, 2, $lum$mini_project$lum$, $lum${"brief":"Your 5-minute exercise: Pick a problem you've been stuck on. Run all 4 rounds above, spending about 2 minutes per round. What did you arrive at that you didn't have going in?","parts":[]}$lum$::jsonb, false),
  ($lum$af57477c-7d89-5d83-a273-5d6b2727dd1d$lum$::uuid, $lum$c8ad5de6-5654-5ad1-8d52-6276f4eaa213$lum$::uuid, 0, $lum$reading$lum$, $lum${"markdown":"Long-form content fails at the outline stage 90% of the time. Either there's no outline (you're writing into the void) or the outline is too vague to be useful. The result is writing that meanders, repeats itself, and doesn't build toward anything.\n\n**The AI outline method:**\n\n**Phase 1: Brain dump.** Tell the model everything you know and think about the topic in 200 words of stream-of-consciousness. Don't edit. Don't organize. Just dump.\n\n**Phase 2: Structure extraction.** *\"Based on my brain dump, give me 5 possible structural approaches. For each: a title, a 3-sentence description of the argument arc, and who it's best for.\"* Pick one.\n\n**Phase 3: Section breakdown.** *\"Now break this into sections. For each section: a heading, 2-sentence summary of what it covers, and what the reader should feel or know by the end.\"*\n\n**Phase 4: Write section by section.** Now you're not writing a 2,000-word piece: you're writing 8 chunks of 250 words each, each with a clear purpose. That's a completely different and much easier task.\n\nThe outline is where you make the decisions. The writing is where you execute them."}$lum$::jsonb, false),
  ($lum$02dd6dae-b509-514d-91bb-a0e0a01cf68a$lum$::uuid, $lum$c8ad5de6-5654-5ad1-8d52-6276f4eaa213$lum$::uuid, 1, $lum$fill_blank$lum$, $lum${"template":"The blank page problem disappears when you separate {{1}} from writing. After the outline, you are no longer writing one 2,000-word piece into the void. You are writing eight chunks of about 250 words, each with a clear {{2}}, which is a much easier task.","blanks":[{"id":"1","answer":"structure","alternatives":["the structure","structuring"]},{"id":"2","answer":"purpose","alternatives":["job","point"]}]}$lum$::jsonb, false),
  ($lum$f30a64e5-6953-5b45-bb2f-c1bf59a50c75$lum$::uuid, $lum$c8ad5de6-5654-5ad1-8d52-6276f4eaa213$lum$::uuid, 2, $lum$mini_project$lum$, $lum${"brief":"Your 5-minute exercise: Pick a piece of content you've been avoiding. Do phases 1 and 2 above. Does having 5 structural options change how you think about the piece?","parts":[]}$lum$::jsonb, false),
  ($lum$dfe3826d-9deb-5f3e-8c31-7459e802805f$lum$::uuid, $lum$d60b3cae-8932-51e5-83b0-ad4fc1129abd$lum$::uuid, 0, $lum$reading$lum$, $lum${"markdown":"The cruelest part of writing is the blank page. Editing something bad is easy. Creating something from nothing is hard. AI flips the problem: it gives you a draft to react to, so you skip straight to the part your brain is good at.\n\nBut there is a right way and a wrong way to do this. The wrong way is \"write me a blog post about productivity.\" You will get bland, forgettable filler that sounds like everyone else. The right way is to feed the AI enough of your thinking that the draft is genuinely yours to refine.\n\nBefore you ask for a draft, give it four things:\n\n**The point of view.** What is the one thing you actually want to say? \"Most productivity advice fails because it ignores energy, not time.\" A real angle beats a neutral topic every time.\n\n**The audience.** Who is reading, and what do they already believe? \"Busy managers who have tried and abandoned a dozen systems.\"\n\n**The key points.** The two or three things that must be in there, even as rough notes.\n\n**The shape.** Length, format, and tone. \"About 400 words, conversational, no clichés.\"\n\nNow ask for the draft. What comes back will not be perfect, and that is fine. It is a starting block, not a finish line. Your job now is the satisfying part: cut what is weak, sharpen what is strong, add the specific example only you know, and make it sound like you.\n\nThe honest truth: a first draft from AI is usually a B-minus. But a B-minus you can edit beats an A-plus you never start. And the editing is where your taste and expertise turn it into something good."}$lum$::jsonb, false),
  ($lum$b9c7c60f-922c-5d7b-b416-162a6208236b$lum$::uuid, $lum$d60b3cae-8932-51e5-83b0-ad4fc1129abd$lum$::uuid, 1, $lum$try_it_live$lum$, $lum${"instructions":"Generate a first draft worth editing. Give your point of view, audience, key points, and the shape you want, or use the sample. Sample topic: a short internal post arguing your team should hold fewer but better meetings.","system_prompt":"You are a drafting partner for non-technical professionals. Given a point of view, an audience, key points, and a desired shape, write a solid first draft in plain, natural language. It should have a clear angle and be easy to edit. No clichés, no jargon, no em dashes.","ideal_output":"Title: Fewer meetings, better meetings\n\nWe do not have a meeting problem because we meet too much. We have one because most of our meetings have no clear decision to make. Here is a simple fix. Before anyone books a meeting, they write one sentence: the decision we need to walk out with. If they cannot write that sentence, it is an email, not a meeting. For the meetings that survive that test, we cut them to 25 minutes and send the relevant material a day ahead so people arrive ready. This is not about doing less. It is about protecting the focused time real work actually needs. Let's try it for two weeks and see how it feels.","input_placeholder":"My angle, my audience, my key points, the shape I want..."}$lum$::jsonb, true),
  ($lum$f41629a6-d7bd-5b29-bcb5-361135d6838a$lum$::uuid, $lum$d60b3cae-8932-51e5-83b0-ad4fc1129abd$lum$::uuid, 2, $lum$multiple_choice$lum$, $lum${"stem":"This lesson argues that an AI first draft is usually a B-minus. Why is that still worth using?","options":[{"id":"a","label":"A B-minus you can edit beats an A-plus you never start, because editing something rough is far easier than creating from a blank page, and the editing is where your taste makes it good.","is_correct":true,"explanation":"Correct. AI flips the hard part: it gives you a draft to react to. Once you feed it your angle, audience, key points, and shape, the rough draft is genuinely yours to sharpen."},{"id":"b","label":"Because a B-minus draft is good enough to send as is, so you save the editing time entirely.","is_correct":false,"explanation":"The lesson is clear that the draft is a starting block, not a finish line. You still cut the weak parts, add the specific example only you know, and make it sound like you."},{"id":"c","label":"Because asking for a draft about a broad topic like 'productivity' reliably produces strong, original writing.","is_correct":false,"explanation":"A bare topic produces bland, forgettable filler. The draft is only worth editing when you feed it your point of view, audience, key points, and desired shape first."}]}$lum$::jsonb, false),
  ($lum$669a71e2-1970-54b3-b621-bfc38f9d82c6$lum$::uuid, $lum$a41df8a9-a2bb-5f3d-bab6-e68d44b81877$lum$::uuid, 0, $lum$reading$lum$, $lum${"markdown":"When you need to get up to speed on something unfamiliar, a new regulation, a competitor, a medical term, a software tool, AI can save you hours. But research is also where AI is most dangerous if you trust it blindly, because it will state guesses with total confidence.\n\nSo use it for what it is great at, and verify what it is shaky on.\n\nAI is excellent at orientation. It can take a topic you know nothing about and give you the lay of the land: the main concepts, the key terms, how the pieces fit together. \"Explain how commercial leases typically work, in plain language, as if I am brand new to this. Cover the main types and the terms I should watch for.\"\n\nIt is also great at leveling and reframing. \"Explain this like I am a complete beginner.\" \"Now explain it like I am a manager who needs to make a decision.\" \"What are the most common misconceptions about this?\" Each angle deepens your understanding fast.\n\nWhere it gets risky is specifics. Exact statistics, current prices, recent events, named studies, legal citations: these are the things AI is most likely to invent. Anything called a hallucination tends to live in the details.\n\nSo the workflow is: use AI to understand the shape of a topic and learn the vocabulary, then take any specific fact you plan to rely on and confirm it against a real source, the official site, the actual document, or a trusted expert. Orientation from AI, verification from the world.\n\nDone this way, AI does not replace research. It makes you a faster, better-oriented researcher who knows the right questions to ask."}$lum$::jsonb, false),
  ($lum$ca274a3b-8e76-54d7-b7ce-e816bdcecb05$lum$::uuid, $lum$a41df8a9-a2bb-5f3d-bab6-e68d44b81877$lum$::uuid, 1, $lum$multiple_choice$lum$, $lum${"stem":"You used AI to get oriented on a new industry regulation. Which part of its answer should you be most careful to verify before relying on it?","options":[{"id":"a","label":"The plain-language explanation of what the regulation is generally about.","is_correct":false,"explanation":"General orientation is exactly what AI does well. It is a reasonable starting map, though you will still confirm specifics before acting."},{"id":"b","label":"The exact effective date, the specific dollar thresholds, and the precise legal citation it gave.","is_correct":true,"explanation":"Correct. Specifics like dates, numbers, and citations are the most likely to be invented. Confirm each one against the official source before you rely on it."},{"id":"c","label":"The list of common misconceptions about the topic.","is_correct":false,"explanation":"Reframing and surfacing common misconceptions is a strong use of AI for learning. The risky parts are the hard specifics, not the conceptual framing."}]}$lum$::jsonb, false),
  ($lum$7b754014-6f35-5011-ab6e-59a0c63f9bd7$lum$::uuid, $lum$a41df8a9-a2bb-5f3d-bab6-e68d44b81877$lum$::uuid, 2, $lum$before_after$lum$, $lum${"question":"Same unfamiliar topic, two prompts. One invites confident guesses, the other gets orientation you can safely verify. Notice the difference.","before_prompt":"Tell me everything I need to know about the new data privacy regulation, including the exact effective dates, the fine amounts, and which companies it applies to.","after_prompt":"I'm new to this area. Explain, in plain language, how the new data privacy regulation generally works: the main concepts, the key terms I should know, and how the pieces fit together. Then give me a short list of the specific facts (exact dates, fine amounts, who it applies to) that I should confirm against the official source before I rely on them.","changes":["Stops demanding hard specifics as settled fact, which is exactly where AI invents confident, wrong details.","Asks for orientation, the concepts, terms, and shape of the topic, which is what AI does genuinely well.","Turns the risky specifics into a verify list aimed at the official source, so you get oriented fast without trusting the guess-prone parts."]}$lum$::jsonb, true),
  ($lum$6aca776e-b6c5-5d28-9c3f-70460d2e7c35$lum$::uuid, $lum$d7ed7045-1f7c-54da-9b42-06f024dabc70$lum$::uuid, 0, $lum$reading$lum$, $lum${"markdown":"A big task with a distant deadline does something cruel to your motivation. \"Organize the company offsite\" or \"launch the new website by Q3\" is too large to hold in your head, so you do not know where to start, so you do not start. The problem is not the work; it is that the work has not been broken down yet. AI is genuinely good at this kind of decomposition, turning a vague mountain into a numbered set of footholds.\n\nHere is how to get a plan you can actually act on.\n\n**Give it the goal, the deadline, and your reality.** \"I need to plan and run a 40-person team offsite. It is in 10 weeks. I work on this about 3 hours a week and I have no events experience. Break this into a week-by-week plan with clear milestones.\" The constraints (your time, your experience, the date) are what make the plan realistic instead of a generic checklist.\n\n**Ask for order and dependencies.** \"What has to happen before what? Flag anything I should start early because it has a long lead time.\" This catches the classic planning trap, the thing you needed to book two months out that you discover too late.\n\n**Request the first concrete step.** End with \"What is the single first thing I should do this week?\" A plan you cannot start is just a longer way of feeling stuck. One clear first action breaks the paralysis.\n\n**Then apply what only you know.** This is the part the AI cannot do. It does not know that your venue contact is slow to reply, that the holiday week is dead, or that your boss wants to approve the agenda personally. Take its plan and adjust the timing and order against your real-world knowledge. The AI gives you the skeleton; you make it fit reality.\n\nA plan from AI is a draft, not a command. But going from \"this is overwhelming and I have not started\" to \"here are my weekly milestones and my first task is booking the venue\" is often the entire difference between a project that drifts and one that gets done."}$lum$::jsonb, false),
  ($lum$16c03480-92b5-53c0-bc93-da2d7452672c$lum$::uuid, $lum$d7ed7045-1f7c-54da-9b42-06f024dabc70$lum$::uuid, 1, $lum$before_after$lum$, $lum${"question":"Same overwhelming project, two prompts. One returns a generic checklist, the other a plan you can actually start. Notice what the second one supplies.","before_prompt":"Give me a plan to organize a company offsite.","after_prompt":"I need to plan and run a 40-person team offsite. It's in 10 weeks, I can give it about 3 hours a week, and I have no events experience. Break it into a week-by-week plan with clear milestones, flag anything with a long lead time I should start early, and tell me the single first thing to do this week.","changes":["Supplies the deadline, your weekly time, and your inexperience, so the plan is realistic instead of a generic checklist.","Asks for dependencies and long-lead items, catching the thing you'd otherwise discover too late to book.","Requests one concrete first action, which is what breaks the paralysis and turns a plan into movement."]}$lum$::jsonb, true),
  ($lum$9cd56992-8fc8-5799-b9e4-b3656fb4366e$lum$::uuid, $lum$d7ed7045-1f7c-54da-9b42-06f024dabc70$lum$::uuid, 2, $lum$mini_project$lum$, $lum${"brief":"Take a real project you have been putting off and turn it into a timeline you can start this week. First, write down the project, the hard deadline, and your honest constraints: how much time per week you can give it and any relevant inexperience or dependencies. Second, ask AI to break it into an ordered, week-by-week plan with clear milestones, then ask a follow-up about dependencies and anything with a long lead time you should start early. Third, ask for the single first action to take this week. Finally, edit the plan against what you actually know: adjust any timing that is unrealistic, reorder steps based on real-world dependencies the AI could not know, and remove anything that does not apply. The deliverable is a dated milestone plan and one concrete first step, taking you from paralyzed to moving.","parts":[]}$lum$::jsonb, false),
  ($lum$d1800dc1-f81d-5a09-bd99-0cacc56b8456$lum$::uuid, $lum$48448dca-5fe6-52df-8bb1-004ae444b592$lum$::uuid, 0, $lum$reading$lum$, $lum${"markdown":"Comparing two documents is one of those tasks that is simple in theory and miserable in practice. Two versions of a contract, an old policy and a revised one, a draft and the edited return, your proposal and a competitor's. The differences are in there somewhere, but finding them by reading both line by line is slow, and it is exactly the kind of careful task where tired eyes miss the one change that mattered.\n\nAI is excellent at this, because comparing text is squarely in its wheelhouse. Here is how to do it.\n\n**Paste both, clearly labeled.** Give the AI both documents and mark which is which. \"Here is version A, our current contract. Here is version B, the one they sent back. Compare them.\" The labeling keeps the AI from getting confused about direction.\n\n**Tell it what you care about.** A raw \"what changed\" can return trivial differences alongside critical ones. Aim it: \"Focus on changes to payment terms, deadlines, and liability. Ignore formatting and wording tweaks that do not change the meaning.\" Now you get signal, not noise.\n\n**Ask for the changes grouped by importance.** \"List the changes in three groups: critical (affects money, obligations, or risk), moderate, and minor.\" This turns a flat list into a triage you can act on, so you spend your attention on the clauses that matter.\n\n**Ask what it means, not just what changed.** Follow up with \"For each critical change, explain in plain language what it means for me and whether I should be concerned.\" That is the difference between knowing a clause moved and understanding why you should care.\n\nOne important caution: for anything legal, financial, or binding, AI's comparison is your fast first pass, not your final authority. It can miss a subtle change or misread a clause. Use it to find what to look at, then read those specific sections yourself, or have the right expert confirm them. The AI saves you from reading 20 pages; you still read the 3 that count."}$lum$::jsonb, false),
  ($lum$6ef01e6d-9e71-54b2-8c6d-e7cc0f7d49c8$lum$::uuid, $lum$48448dca-5fe6-52df-8bb1-004ae444b592$lum$::uuid, 1, $lum$before_after$lum$, $lum${"question":"Two versions of a contract to compare, two prompts. One buries you in trivia, the other triages what matters. Notice the difference.","before_prompt":"Here are two versions of our contract. What changed?","after_prompt":"Here is version A, our current contract, and version B, the one they sent back. Compare them, focusing only on changes to payment terms, deadlines, and liability, and ignore formatting and wording tweaks that don't change meaning. Group the changes as critical, moderate, and minor, and for each critical one, explain in plain language what it means for me.","changes":["Labels which document is which, so the AI doesn't get the direction of changes backwards.","Aims the comparison at the clauses that carry money and risk and tells it to ignore noise, so you get signal.","Asks for changes grouped by importance and explained in plain language, turning a flat diff into a triage you can act on."]}$lum$::jsonb, true),
  ($lum$dee6fbaa-892a-5095-8d49-4459a135cd84$lum$::uuid, $lum$48448dca-5fe6-52df-8bb1-004ae444b592$lum$::uuid, 2, $lum$mini_project$lum$, $lum${"brief":"Use AI to compare two real versions of a document you actually need to review. First, gather both versions (a current and a revised policy, two drafts of a proposal, an original and an edited document) and remove any confidential names or details if you are using a public tool. Second, paste both in clearly labeled as A and B, and ask the AI to list what changed, focusing only on the differences that affect meaning, not formatting. Third, ask it to group the changes by importance (critical, moderate, minor) and to explain in plain language what each critical change means for you. Finally, take the AI's list of critical changes and read those specific sections in the real document yourself to confirm them. The goal is to go from \"I have to read both of these end to end\" to \"I know the three changes that matter and I verified them,\" in a fraction of the time.","parts":[]}$lum$::jsonb, false),
  ($lum$b14edd9e-2d44-5c4c-9ef7-4fa97e4bda39$lum$::uuid, $lum$dcef9dfc-dd6d-53ec-8244-881e82cff2f7$lum$::uuid, 0, $lum$reading$lum$, $lum${"markdown":"Some documents seem almost designed to make you feel stupid. A lease full of legal clauses, an insurance explanation of benefits, a software contract, a letter from a specialist, a dense technical spec. The information you need is in there, buried under jargon and formal phrasing that assumes you already speak the language. AI is one of the best plain-English translators ever made, and this is a perfect job for it.\n\nThe core move is simple: paste the confusing text and ask for it in plain language, at the level you actually need.\n\n**Set your starting point.** \"Explain this like I have never seen a contract before.\" \"Explain this to me as a small business owner, not a lawyer.\" The AI calibrates to whatever level you name, so tell it where you are rather than getting an answer pitched too high or too low.\n\n**Ask it to define the terms as it goes.** \"Rewrite this paragraph in plain English, and for any necessary technical term, give me a one-line definition in parentheses.\" Now you understand the content and pick up the vocabulary at the same time.\n\n**Pull out what affects you.** Beyond translating, ask \"What does this actually require me to do, and by when?\" or \"What am I agreeing to here that I should be aware of?\" The plain-language version is useful; the so-what is what you were really after.\n\n**Ask your dumb questions freely.** This is the underrated part. Once it has explained something, you can ask the follow-up you would be embarrassed to ask a person. \"Wait, what does 'indemnify' mean here?\" The AI never sighs. Keep asking until it genuinely makes sense.\n\nThe one caution, as always: for anything binding or high-stakes, AI gives you understanding, not authority. Use it to grasp what a contract or medical letter is saying so you can ask smart questions, but confirm the consequential parts with the actual professional before you sign or act. Understanding from AI, decisions from you and the right expert."}$lum$::jsonb, false),
  ($lum$6c930245-bd6d-5019-8ef9-a3946231d39f$lum$::uuid, $lum$dcef9dfc-dd6d-53ec-8244-881e82cff2f7$lum$::uuid, 1, $lum$try_it_live$lum$, $lum${"instructions":"Practice turning dense jargon into plain English. Paste a confusing passage you've received, or use the sample, and ask for a plain-language version plus what it requires of you. Sample: 'The Lessee shall indemnify and hold harmless the Lessor from any and all liabilities, claims, or damages arising from the Lessee's use of the premises, and shall maintain commercial general liability coverage of no less than $1,000,000 per occurrence.'","system_prompt":"You are a plain-language translator for non-experts. Given a dense or jargon-heavy passage, rewrite it in clear everyday English a beginner can understand, define any unavoidable technical term in parentheses, and then state in one or two lines what the passage actually requires the reader to do. Do not add obligations that are not in the text. No jargon, no em dashes.","ideal_output":"In plain English: If anyone gets hurt or something gets damaged because of how you (the renter) use the space, you are responsible for it, not the owner, and you have to cover any resulting claims or costs (indemnify means you agree to bear those costs and protect the owner from them). You also must carry business liability insurance worth at least 1 million dollars for any single incident. What this requires of you: (1) Buy and keep commercial general liability insurance of at least 1,000,000 dollars per occurrence. (2) Accept that you, not the landlord, are on the hook for injury or damage claims tied to your use of the space. Confirm the exact insurance wording with your insurer before signing.","input_placeholder":"Paste a confusing clause or paragraph and I'll translate it..."}$lum$::jsonb, true),
  ($lum$318f277e-9e03-5a69-b5e6-68105993255a$lum$::uuid, $lum$dcef9dfc-dd6d-53ec-8244-881e82cff2f7$lum$::uuid, 2, $lum$multiple_choice$lum$, $lum${"stem":"AI gives you a clear plain-English translation of a binding contract clause. According to this lesson, how far does that get you?","options":[{"id":"a","label":"It gives you understanding so you can ask smart questions, but for anything binding you still confirm the consequential parts with the actual professional before you sign or act.","is_correct":true,"explanation":"Correct. Understanding from AI, decisions from you and the right expert. The translation helps you grasp the text; it is not authority to act on a high-stakes document."},{"id":"b","label":"It's authoritative, so you can sign based on the AI's explanation alone.","is_correct":false,"explanation":"AI gives understanding, not authority. It can misread a clause, so a binding decision needs confirmation from the actual professional."},{"id":"c","label":"It's useless for legal text, so you should never use AI on contracts.","is_correct":false,"explanation":"Too far the other way. AI is an excellent plain-language translator that helps you understand and ask smart questions; you just verify the consequential parts."}]}$lum$::jsonb, false),
  ($lum$cb9f7828-648f-5cda-baa9-b5d915b7c105$lum$::uuid, $lum$41d7b1af-4664-5fc0-b4b7-e65e289112ab$lum$::uuid, 0, $lum$reading$lum$, $lum${"markdown":"The hardest part of most work emails is not the writing. It is starting. You know roughly what you need to say, but turning a tense or awkward situation into something professional takes more energy than it should. You write a sentence, delete it, rewrite it, and twenty minutes later you still have nothing in the box. This is one of the things AI does genuinely well, and it can give you back that twenty minutes every single day.\n\nThe catch is that the quality of what comes back depends entirely on what you put in. Type \"write a professional email\" and you get a hollow template full of phrases like \"I hope this message finds you well\" and \"please do not hesitate to reach out.\" It reads like a form letter because that is exactly what you asked for: an email about nothing in particular. The good stuff comes from feeding the AI your specifics.\n\nThere are four things worth handing the AI every time. First, the situation: who this is going to and what is actually happening. Second, the points to make: the two or three things that must land. Third, the tone: how you want to come across. Fourth, the constraints: length, format, anything to avoid. Once you brief all four, the draft that comes back is usually ninety percent of the way there."}$lum$::jsonb, false),
  ($lum$37a3a735-4284-57b2-a354-9d41af5e9b89$lum$::uuid, $lum$41d7b1af-4664-5fc0-b4b7-e65e289112ab$lum$::uuid, 1, $lum$multiple_choice$lum$, $lum${"stem":"You need to email a vendor about a billing error. Which approach produces the most usable draft?","options":[{"id":"a","label":"Brief the AI on the situation, the specific points to make, the tone you want, and a length limit, then read and adjust the draft before sending.","is_correct":true,"explanation":"Right. The four inputs (situation, points, tone, constraints) turn a generic template into a draft that is ninety percent there, and reading before sending keeps you the author."},{"id":"b","label":"Type 'write a professional email about a billing error' and send whatever comes back, since the AI knows professional language.","is_correct":false,"explanation":"A vague request produces a hollow template full of filler. Without your specifics and a final read, you are sending something generic with your name on it."},{"id":"c","label":"Write a long, very formal prompt packed with corporate phrases so the email sounds important.","is_correct":false,"explanation":"Formality and length are not what makes an email work. Concrete specifics and a named tone are, and corporate filler usually makes the email worse, not better."}]}$lum$::jsonb, false),
  ($lum$841138f2-c827-569f-8434-fc35f1021c94$lum$::uuid, $lum$41d7b1af-4664-5fc0-b4b7-e65e289112ab$lum$::uuid, 2, $lum$reading$lum$, $lum${"markdown":"Here is what that looks like in practice. Say you manage an office and a vendor has invoiced you twice for the same delivery. You could stew over how to flag it without sounding accusatory, or you could write: \"Draft an email to a vendor I have a good relationship with. They invoiced us twice for the September cleaning supplies order, invoice numbers 4471 and 4488, same items. I want them to void the duplicate and confirm. Tone: friendly and matter of fact, assume it was an honest mistake. Under 100 words.\" What comes back names the invoices, makes the ask cleanly, and keeps the relationship intact. You read it once and send.\n\nTake a second case. A paralegal needs to decline a request from a partner to take on extra document review because they are already buried, but saying no to a partner feels dangerous. The brief: \"Write an email declining a partner's request to handle the Reyes document review. I am already at capacity on the Tanaka and Brooks matters with deadlines this week. I want to say no clearly but show I take their request seriously and offer an alternative. Tone: respectful, confident, not apologetic or groveling. Under 120 words.\" The draft acknowledges the request, states the conflict in terms of existing deadlines rather than personal preference, and suggests checking back next week. That framing protects you. It says no without sounding like you are dodging work."}$lum$::jsonb, false),
  ($lum$766ca01c-5a1c-52fa-95ac-98e8d3629ed1$lum$::uuid, $lum$41d7b1af-4664-5fc0-b4b7-e65e289112ab$lum$::uuid, 3, $lum$fill_blank$lum$, $lum${"template":"In the paralegal example, the decline is framed around existing {{1}} on the Tanaka and Brooks matters rather than personal {{2}}, which is what makes the no land as professional.","blanks":[{"id":"1","accept":["deadlines","capacity","workload","commitments"],"ideal":"deadlines"},{"id":"2","accept":["preference","preferences","choice","feelings"],"ideal":"preference"}],"explanation":"The draft states the conflict in terms of existing deadlines rather than personal preference, so it reads as a real scheduling constraint, not as dodging work."}$lum$::jsonb, false),
  ($lum$b29f7744-8eeb-51eb-85cd-a56e358e7f32$lum$::uuid, $lum$41d7b1af-4664-5fc0-b4b7-e65e289112ab$lum$::uuid, 4, $lum$reading$lum$, $lum${"markdown":"Tone is the lever most people forget to pull, and it changes everything. The exact same facts can be delivered as warm, firm, apologetic, or coolly professional, and the AI will follow your lead if you name it. A teacher emailing a parent about a missed assignment can ask for \"supportive and non-judgmental, assume the parent wants to help.\" An HR manager confirming a policy change can ask for \"neutral and clear, no warmth needed, just the facts.\" If you do not name a tone, the AI defaults to a generic middle that often reads as either stiff or weirdly chummy. Naming it costs you four words and saves you a rewrite.\n\nA few smaller moves sharpen the result further. Tell the AI to skip jargon and filler if you hate corporate-speak: \"no buzzwords, no 'circle back,' plain language.\" Give it a length so it does not ramble: a chasing email should be three sentences, not three paragraphs. And if you have written similar emails before, paste one in and say \"match this voice.\" The AI is good at mirroring a style once it has a sample.\n\nNow the part that matters most, and the part no prompt can do for you. Always read the draft before you send, and read it as the person receiving it. The AI does not know your history with this person. It does not know that this vendor already apologized last month, or that this colleague is going through something hard, or that one sentence in the draft will land wrong because of a conversation you had last week. You know all of that. So the workflow is not \"AI writes my email.\" It is \"AI drafts, I decide.\" You are still the author. The AI just gets you past the blank box and into editing, which is the easy part. When you hit send, that email is yours, with your name on it, and you are accountable for every word. Treat the draft as a strong first pass from a helpful assistant, never as a finished product you can fire off unread."}$lum$::jsonb, false),
  ($lum$bba674f8-f391-51f4-992d-205ffefb372f$lum$::uuid, $lum$41d7b1af-4664-5fc0-b4b7-e65e289112ab$lum$::uuid, 5, $lum$multiple_choice$lum$, $lum${"stem":"According to this segment, if you do not name a tone in your brief, what tends to happen?","options":[{"id":"a","label":"The AI refuses to write the email until you supply one.","is_correct":false,"explanation":"The AI does not refuse. It simply picks a default, which is the whole problem with leaving the tone unnamed."},{"id":"b","label":"The AI defaults to a generic middle that often reads as either stiff or weirdly chummy.","is_correct":true,"explanation":"Right. Naming the tone costs four words and steers the email, while leaving it out lands you in that stiff or chummy default."},{"id":"c","label":"The AI automatically matches the tone of the last email you sent.","is_correct":false,"explanation":"It only mirrors a style when you paste a sample and ask it to match that voice. Without a named tone or a sample, it falls back to a generic default."}]}$lum$::jsonb, false),
  ($lum$50072d5e-7548-5d97-ae59-5ce08528743f$lum$::uuid, $lum$41d7b1af-4664-5fc0-b4b7-e65e289112ab$lum$::uuid, 6, $lum$reading$lum$, $lum${"markdown":"The most common mistake is treating the AI's first draft as finished. People brief it well, get back something that reads smoothly, and hit send without reading it as the recipient would. Then they find out the draft thanked a client for \"your continued partnership\" when this was a brand-new client, or it apologized profusely when the situation called for a firm correction, not an apology. A smooth draft is not a correct draft. The AI writes confident-sounding sentences about things it cannot possibly know: your history with this person, the politics in the room, the one detail that changes the whole message. Reading every draft before sending is not optional. It is the job.\n\nThe second mistake is skipping the tone instruction and accepting whatever default comes out. Left to its own devices, the AI tends toward a chummy, over-friendly register, lots of exclamation points and \"I'd love to\" and \"so excited.\" For a nurse emailing a doctor about a scheduling conflict, that tone is wrong and undermines you. Name the tone explicitly every time. \"Professional and brief,\" \"warm but firm,\" \"neutral, just the facts.\" Four words steer the entire email."}$lum$::jsonb, false),
  ($lum$eadf638f-3caa-5a94-abfb-c98dfc171a61$lum$::uuid, $lum$41d7b1af-4664-5fc0-b4b7-e65e289112ab$lum$::uuid, 7, $lum$fill_blank$lum$, $lum${"template":"Before sending an AI-drafted email, always {{1}} it as the recipient would, because the AI cannot know your {{2}} with that person.","blanks":[{"id":"1","accept":["read","review","reread","check"],"ideal":"read"},{"id":"2","accept":["history","relationship","context","past"],"ideal":"history"}],"explanation":"A smooth draft is not a correct draft. The AI writes confident sentences about things it cannot know, so reading every draft as the recipient and catching anything that clashes with your real history is the step that keeps you the author."}$lum$::jsonb, false),
  ($lum$318f99f1-5928-5cca-b39c-04477a3224fd$lum$::uuid, $lum$41d7b1af-4664-5fc0-b4b7-e65e289112ab$lum$::uuid, 8, $lum$reading$lum$, $lum${"markdown":"The third mistake is the opposite problem: over-briefing into a stiff, robotic result. Some people, worried about sounding unprofessional, ask for \"highly formal corporate language\" and end up with an email so starchy it reads like a legal notice. A frustrated colleague who gets a reply dripping with \"per my previous correspondence\" feels handled, not heard. Aim for how a thoughtful human actually writes. \"Clear and human, no corporate jargon\" almost always beats \"formal.\"\n\nA fourth trap is pasting in confidential details without thinking. If you are drafting an email about a patient, a client matter, or an employee's performance, do not paste names, medical details, or sensitive specifics into a tool your workplace has not approved. Describe the situation in general terms (\"an employee who missed three deadlines\") and add the real names yourself in the final draft. Check your organization's policy on what can go into AI tools before you paste anything sensitive.\n\nThe last mistake is asking the AI to handle something it should not. An email firing someone, denying a serious complaint, or delivering legally significant news is not a \"draft it and tweak it\" task. The stakes are too high and the wording carries real consequences. Use the AI for the everyday volume: the chasers, the scheduling notes, the polite declines, the status updates. For the genuinely sensitive sends, write them yourself or get a human to review, because those are the emails where a wrong word actually costs you."}$lum$::jsonb, false),
  ($lum$ef11ecc0-44db-50e9-adf4-0dcee7d64d20$lum$::uuid, $lum$41d7b1af-4664-5fc0-b4b7-e65e289112ab$lum$::uuid, 9, $lum$multiple_choice$lum$, $lum${"stem":"Based on this segment, how should you handle confidential details like patient or employee names when drafting with an unapproved AI tool?","options":[{"id":"a","label":"Paste everything in so the AI has full context, then delete the sensitive parts afterward.","is_correct":false,"explanation":"Once you paste sensitive details into an unapproved tool, deleting them later does not undo the exposure. The point is not to paste them in the first place."},{"id":"b","label":"Describe the situation in general terms and add the real names or specifics yourself in the final draft.","is_correct":true,"explanation":"Right. General terms like 'an employee who missed three deadlines' keep the brief useful while you add the sensitive specifics yourself, and you check your organization's policy first."},{"id":"c","label":"Avoid drafting any email with AI if it touches a person, no matter how general.","is_correct":false,"explanation":"You can still draft these emails. The segment says to describe the situation generally and add real names yourself, not to avoid the tool entirely."}]}$lum$::jsonb, false),
  ($lum$abc9df51-afeb-58e3-b2d1-e4c712a49a0b$lum$::uuid, $lum$41d7b1af-4664-5fc0-b4b7-e65e289112ab$lum$::uuid, 10, $lum$before_after$lum$, $lum${"question":"You need to chase a client who is two weeks late paying an invoice, without damaging the relationship. Same goal, two prompts. See how the second one earns a better email.","before_prompt":"Write an email asking a client to pay an overdue invoice.","after_prompt":"Draft a short email chasing a client about invoice 2210 for $3,400, which was due May 15 and is now two weeks overdue. This is a long-term client I value, and I assume it is an oversight, not a refusal. I want to remind them clearly, make it easy to pay, and keep the relationship warm. Tone: friendly and low-pressure, not accusatory. Under 90 words, plain language, no corporate filler.","changes":["Names the specific invoice, amount, and dates, so the email is concrete and the client knows exactly what is owed.","States the relationship and the assumption (an oversight, not a refusal), so the tone stays warm instead of legalistic.","Sets a clear tone and a length limit, so the result is a short, easy-to-act-on nudge rather than a stiff demand letter."]}$lum$::jsonb, true),
  ($lum$f9635cd2-bd9a-5400-8574-050af6d8f318$lum$::uuid, $lum$41d7b1af-4664-5fc0-b4b7-e65e289112ab$lum$::uuid, 11, $lum$multiple_choice$lum$, $lum${"stem":"In the overdue-invoice example, why does adding 'I assume it is an oversight, not a refusal' improve the draft?","options":[{"id":"a","label":"It steers the AI toward a warm, low-pressure tone that protects a valued client relationship instead of sounding accusatory.","is_correct":true,"explanation":"Right. Telling the AI how to read the situation shapes the tone of the whole email, which is exactly the lever you want to pull when the relationship matters."},{"id":"b","label":"It makes the email longer and more formal, which clients respond to better.","is_correct":false,"explanation":"The brief actually asks for under 90 words and plain language. Length and formality are not the point; the framing of the relationship is."},{"id":"c","label":"It lets the AI decide on its own whether the client meant to skip the payment.","is_correct":false,"explanation":"The AI cannot know the client's intent. You are supplying the assumption on purpose, precisely because the AI has no way to judge it."}]}$lum$::jsonb, false),
  ($lum$69fb69a4-d279-5291-af0e-11fbe610fee3$lum$::uuid, $lum$41d7b1af-4664-5fc0-b4b7-e65e289112ab$lum$::uuid, 12, $lum$mini_project$lum$, $lum${"brief":"Pick a real email you have been putting off, the kind that sits in your head as a low-grade dread. A polite decline, an overdue chase, a reply to someone who is frustrated, a correction you need to make without causing offense. Draft it with AI using the four-part brief, then own the send.","parts":[{"id":"1","prompt":"Write your brief covering all four inputs: the situation (who and what is happening), the two or three points that must land, the tone you want in your own words, and the constraints (length, no jargon, anything to avoid)."},{"id":"2","prompt":"Run it, then read the draft out loud as if you were the person receiving it. Mark every spot that does not sound like you or that clashes with something the AI could not know about your history with this person."},{"id":"3","prompt":"Rewrite those spots in your own words, add any real names or details you kept out for privacy, and tighten the length. Send the version you would be comfortable having your name on, and note how long the whole thing took compared to writing it from scratch."}]}$lum$::jsonb, false),
  ($lum$e9ddb883-e38a-5ed7-b279-8b2e0449d7c3$lum$::uuid, $lum$c39f644b-abab-5e67-a543-71193829437b$lum$::uuid, 0, $lum$reading$lum$, $lum${"markdown":"Most professional emails follow a handful of patterns: updates, requests, declines, follow-ups, introductions. Once you recognize the pattern, drafting becomes mostly structural, and structure is exactly what AI is good at.\n\n**The triage system:**\n\n**Tier 1: Auto-draft:** Routine emails (status updates, meeting confirmations, standard follow-ups). Paste the incoming email + your 2-3 bullet points of what you want to say. Prompt: *\"Draft a professional reply to this email. My key points: [bullets]. Tone: [warm/direct/formal]. Max 150 words.\"*\n\n**Tier 2: Draft + edit:** Sensitive or relationship-important emails. Let the AI draft, but you edit substantively. Use it to get past the blank page, not to sign off without reading.\n\n**Tier 3: Write yourself:** Anything where the nuance is everything, a difficult conversation, a negotiation, something that will be forwarded or quoted.\n\nThe mistake people make is applying Tier 3 effort to Tier 1 emails. A meeting confirmation doesn't need your full creative attention.\n\n**The voice trick:** For Tier 1 emails, voice-dictate your thoughts in 30 seconds. That dictation becomes your brief."}$lum$::jsonb, false),
  ($lum$f8c9d463-f4e6-50de-8c1a-3680bd8b28c9$lum$::uuid, $lum$c39f644b-abab-5e67-a543-71193829437b$lum$::uuid, 1, $lum$multiple_choice$lum$, $lum${"stem":"According to this lesson, what's the most common mistake people make with email triage?","options":[{"id":"a","label":"Applying Tier 3 effort (full hand-writing and agonizing) to Tier 1 emails like meeting confirmations that just need a 30-second auto-draft.","is_correct":true,"explanation":"Correct. Around 80 percent of email is Tier 1. Spending your full creative attention on a routine confirmation wastes the cognitive load you need for the 20 percent that matters."},{"id":"b","label":"Auto-drafting the sensitive, relationship-critical emails to save the most time.","is_correct":false,"explanation":"Those are Tier 2 or 3, where nuance matters and you edit substantively or write yourself. Auto-drafting is for the routine Tier 1 messages."},{"id":"c","label":"Reading every incoming email carefully before deciding how to respond.","is_correct":false,"explanation":"The point of triage is classifying first so you don't over-invest. The mistake the lesson names is mismatched effort, not careful reading."}]}$lum$::jsonb, false),
  ($lum$d083e891-4790-5ed6-ac71-0766801c25f6$lum$::uuid, $lum$c39f644b-abab-5e67-a543-71193829437b$lum$::uuid, 2, $lum$mini_project$lum$, $lum${"brief":"Your 5-minute exercise: Find 3 emails in your drafts or inbox that you've been avoiding. Classify each as Tier 1, 2, or 3. Draft the Tier 1 ones using the auto-draft method above. Send at least one.","parts":[]}$lum$::jsonb, false),
  ($lum$247a2bb6-faf7-5fd8-b1d6-77458af378aa$lum$::uuid, $lum$c69000a0-7a79-598c-b2b0-9e98f9493c6f$lum$::uuid, 0, $lum$reading$lum$, $lum${"markdown":"Learning something new at work used to mean digging through help documentation written for someone who already understands it, or sitting through a 20-minute video to find the 30 seconds you needed. AI changes the shape of learning, because you can ask your exact question, in your own words, and get an answer pitched to where you actually are.\n\nWhether it is a new software tool, an unfamiliar concept, or a process you have never run, the approach is the same: treat AI as a patient tutor who never makes you feel slow.\n\n**State your goal and your starting point.** \"I need to set up an automatic email rule in Outlook. I am not technical and I have never used the rules feature. Walk me through it step by step.\" Telling it your level gets you instructions you can follow instead of jargon you cannot.\n\n**Ask for it the way you learn.** \"Give me the steps as a simple numbered list.\" \"Explain the concept with an everyday analogy first.\" \"Just tell me the fastest way to do this one thing, skip the background.\" You control the format, so ask for the one that works for your brain.\n\n**Keep asking follow-ups until it clicks.** This is the real advantage over a static tutorial. \"I do not see that menu, where is it?\" \"What does that setting actually do?\" \"Can you explain that last step again, simpler?\" A tutorial cannot answer you. The AI will go around as many times as you need, without judgment.\n\n**Learn the why, not just the steps.** When you have time, ask \"why does it work this way?\" Understanding the logic means you can handle the next, slightly different version of the problem yourself instead of coming back for every variation.\n\nOne honest caution for software especially: tools change their menus and features constantly, and the AI's knowledge has a cutoff date, so it may describe an older version or an option that moved. Use its instructions as a strong guide, but if a step does not match what you see on screen, trust the screen and ask the AI to help you find the current location. For facts and concepts, verify anything important the same way you would from any single source. A tutor that is right most of the time and instantly available still beats hunting through docs, as long as you keep your eyes open."}$lum$::jsonb, false),
  ($lum$60d3ba39-c368-58f1-97ae-e33cfbc0704d$lum$::uuid, $lum$c69000a0-7a79-598c-b2b0-9e98f9493c6f$lum$::uuid, 1, $lum$try_it_live$lum$, $lum${"instructions":"Practice using AI as a patient tutor. Pick something you want to learn (a software feature, a work concept, a process) and write the prompt that gets you a beginner-level, step-by-step answer. Or use the sample: you need to create a pivot table in Excel to total sales by month, and you've never made one.","system_prompt":"You are a patient, encouraging tutor for non-technical professionals. Given a learner's goal and their stated experience level, give clear step-by-step instructions in plain language at that level, using a short everyday analogy if it helps, and invite follow-up questions. For software steps, note that menus may differ by version and tell them what to do if a step doesn't match their screen. No jargon without a plain definition, no em dashes.","ideal_output":"A pivot table is just a way to let Excel total things up for you automatically, like asking a clerk to sort a stack of receipts into monthly piles and add each pile. Here's how, step by step: (1) Click any cell inside your sales data. (2) In the top menu, click Insert, then click PivotTable. (3) In the box that appears, confirm it selected your data range, and choose to put the table in a New Worksheet, then click OK. (4) A panel opens on the right with your column names. Drag your date or month column into the Rows area. (5) Drag your sales amount column into the Values area. Excel now shows a total of sales for each month. If your menu looks different, tell me which version of Excel you have and what you see, and I'll point you to the right spot. Want me to show how to switch it to show each month as a percentage of the year?","input_placeholder":"What do you want to learn, and what's your starting level?..."}$lum$::jsonb, true),
  ($lum$327ac07f-9f50-524a-b073-80672cdb5923$lum$::uuid, $lum$c69000a0-7a79-598c-b2b0-9e98f9493c6f$lum$::uuid, 2, $lum$multiple_choice$lum$, $lum${"stem":"You're following AI's step-by-step instructions for a software feature, but step 3 mentions a menu you don't see on your screen. What does this lesson tell you to do?","options":[{"id":"a","label":"Trust the screen over the AI, since tools change menus and the model's knowledge has a cutoff date, then ask the AI to help you find the current location.","is_correct":true,"explanation":"Correct. Software menus and features move, and the AI may describe an older version. When a step doesn't match, trust what you see and ask the AI to help you relocate the option."},{"id":"b","label":"Trust the AI's instructions and keep clicking until the menu appears, since it read the documentation.","is_correct":false,"explanation":"The AI hasn't read your current version's screen. Forcing its outdated steps onto a changed interface leads you in circles. The live screen is the authority."},{"id":"c","label":"Abandon the task, since the AI's instructions are outdated and can't be trusted at all.","is_correct":false,"explanation":"Overcorrection. The instructions are a strong guide; you just reconcile them with the live screen and ask the AI to point you to where the option moved."}]}$lum$::jsonb, false),
  ($lum$39fb1e3f-f3dc-5254-b399-9e55d767ff66$lum$::uuid, $lum$d5a233df-02f7-532c-bc58-6266a397975e$lum$::uuid, 0, $lum$reading$lum$, $lum${"markdown":"Most meetings go sideways for one reason: nobody really prepared. People show up, talk in circles, and leave without a decision. You can be the exception, and AI makes it almost effortless.\n\nThe trick is to use AI before the meeting to think through it with you. You bring what you know, and it helps you turn that into a plan, sharper questions, and a heads-up on what might go wrong.\n\nThink of three things you can prepare in minutes:\n\n**A focused agenda.** Tell the AI the purpose and who is attending, and ask for a short agenda with time estimates. \"I have a 30-minute meeting with my manager to get approval for a new hire. Draft an agenda that gets us to a yes.\"\n\n**The questions you should ask.** Ask the AI what you might be missing. \"What questions should I be ready to answer, and what should I ask them?\" This surfaces blind spots before you are in the room.\n\n**The likely objections.** This is the high-value move. \"What are the three most likely reasons my manager would push back, and how should I respond to each?\" Now you are ready instead of caught off guard.\n\nFor meetings you are running, you can also use AI afterward to turn your rough notes into clear next steps and an email recap. Prep on the front end, capture on the back end, and the whole thing gets sharper.\n\nA reminder: the AI does not know your manager or your office politics. Use its suggestions as a starting checklist, then adjust with what only you know about the people in the room."}$lum$::jsonb, false),
  ($lum$98ac9e43-f77c-5d96-8a63-126eeabeb3fc$lum$::uuid, $lum$d5a233df-02f7-532c-bc58-6266a397975e$lum$::uuid, 1, $lum$multiple_choice$lum$, $lum${"stem":"This lesson calls one meeting-prep move the high-value one. Which is it?","options":[{"id":"a","label":"Asking AI for the three most likely reasons the other person will push back and how to respond to each, so objections don't catch you off guard.","is_correct":true,"explanation":"Correct. Anticipating objections is the high-value move. It takes you from being caught off guard to walking in ready for the pushback that actually comes."},{"id":"b","label":"Asking AI to write the longest possible agenda so the meeting fills the whole time slot.","is_correct":false,"explanation":"A focused agenda with time estimates is useful, but length for its own sake isn't the point, and it isn't the high-value move the lesson highlights."},{"id":"c","label":"Asking AI what your manager personally thinks, since it knows your office dynamics.","is_correct":false,"explanation":"The AI doesn't know your manager or your office politics. Its prep is a starting checklist you adjust with what only you know about the people in the room."}]}$lum$::jsonb, false),
  ($lum$3c541354-3ee2-5b99-9b01-9f896cf0a9f4$lum$::uuid, $lum$d5a233df-02f7-532c-bc58-6266a397975e$lum$::uuid, 2, $lum$mini_project$lum$, $lum${"brief":"Pick a real meeting on your calendar this week. In one AI chat, prepare three things back to back: first ask for a tight agenda with time estimates, then ask what questions you should be ready for, then ask for the three most likely objections and how to handle each. Read through the results, cross out anything that does not fit your situation, and keep the rest as your prep sheet. The whole exercise should take under ten minutes and you will walk in noticeably more ready.","parts":[]}$lum$::jsonb, false),
  ($lum$8558ef9f-3550-5698-ac3d-54861ec1d118$lum$::uuid, $lum$685dced9-5a32-50b3-a8a2-e15bcfefd143$lum$::uuid, 0, $lum$reading$lum$, $lum${"markdown":"An angry customer email triggers the exact instinct you should not act on. Your defenses go up, you want to explain why they are wrong, and anything you write in that state tends to pour fuel on the fire. AI has no ego to bruise, which makes it genuinely useful here: it can draft the calm, professional reply that the angry part of your brain cannot produce in the moment.\n\nHere is how to use it well.\n\n**Give it the complaint and the facts, separately.** Paste what the customer said (with their name and any account details removed if you are on a public tool), then tell the AI the true situation and what you can actually offer. \"Customer is furious their order arrived broken. The facts: it shipped on time but was damaged in transit, we can send a replacement today and refund the shipping.\" The AI needs both the emotion to address and the reality to work with.\n\n**Ask it to acknowledge before solving.** The single most important move in an angry-customer reply is to make the person feel heard before you explain anything. Tell the AI: \"Open by genuinely acknowledging their frustration, then give the solution. Do not get defensive or make excuses.\" A reply that leads with the fix and skips the empathy reads as cold, even when the fix is good.\n\n**Set the tone and the limits.** \"Warm, accountable, and human. No corporate jargon, no 'we apologize for any inconvenience.' Under 120 words.\" Those tired corporate phrases are exactly what enrages people further, so banning them helps.\n\nThen comes the part that is yours alone. Read the draft against reality: is every promise in it true and one you can keep? Does it fit the history with this customer? An apology is worthless if it commits to a refund you cannot give, or misses the context that this is their third complaint this month. The AI drafts the composure; you supply the truth and the judgment.\n\nUsed this way, you respond from a calm, professional footing even when you are privately fuming, and angry threads cool down instead of escalating."}$lum$::jsonb, false),
  ($lum$37ebad4c-50b3-59b6-aef3-21096e8e6638$lum$::uuid, $lum$685dced9-5a32-50b3-a8a2-e15bcfefd143$lum$::uuid, 1, $lum$before_after$lum$, $lum${"question":"An angry customer wrote in. One reply gets defensive, the other de-escalates. Notice the order of acknowledgment and solution.","before_prompt":"Write a reply to a customer complaining their order arrived broken.","after_prompt":"Draft a reply to an upset customer whose order arrived broken. The facts I can act on: it shipped on time but was damaged by the courier, I can send a free replacement today and refund the shipping cost. Open by genuinely acknowledging how frustrating this is, then give the solution clearly. Do not get defensive, do not blame the courier, and avoid phrases like 'we apologize for any inconvenience.' Warm, accountable, human, under 120 words.","changes":["Provides the real facts and the concrete remedy, so the reply offers a true solution instead of an empty apology.","Tells the AI to acknowledge the frustration before solving, which is what actually de-escalates an angry customer.","Bans defensive and canned corporate phrases and sets a tight length, so the message reads as a sincere human reply rather than a form letter."]}$lum$::jsonb, true),
  ($lum$aa9fbb39-3ebf-50cb-8599-f9c5d34aa834$lum$::uuid, $lum$685dced9-5a32-50b3-a8a2-e15bcfefd143$lum$::uuid, 2, $lum$multiple_choice$lum$, $lum${"stem":"What's the single most important move when drafting a reply to an angry customer, according to this lesson?","options":[{"id":"a","label":"Genuinely acknowledge their frustration before giving the solution, since a reply that leads with the fix and skips empathy reads as cold.","is_correct":true,"explanation":"Correct. Make the person feel heard before you explain anything. Even a good solution lands badly if it skips the acknowledgment."},{"id":"b","label":"Lead immediately with the solution to show efficiency, and leave out the emotional part.","is_correct":false,"explanation":"Leading with the fix and skipping empathy reads as cold and can keep the customer angry, even when the fix itself is fine."},{"id":"c","label":"Explain in detail why the customer is mistaken about what happened.","is_correct":false,"explanation":"That's the defensive instinct the lesson warns against. It pours fuel on the fire instead of de-escalating."}]}$lum$::jsonb, false),
  ($lum$b04fbcf0-7a0f-58f5-a3e6-8ac018bed2cf$lum$::uuid, $lum$2619ae8e-1c6c-5f35-be89-86ec671c690f$lum$::uuid, 0, $lum$reading$lum$, $lum${"markdown":"Here is a workflow that changes how writing feels. Instead of trying to write something polished from the start, you split the job in two: you do the thinking, the AI does the tidying.\n\nThe reason this works is that the hard part of writing is having the ideas, not arranging the commas. When you try to do both at once, you freeze. So do not. Get the raw material out of your head in whatever messy form it comes, then let AI structure it.\n\nStep one: brain-dump. Open a chat and just type everything you want to say, in any order, full of fragments and half-thoughts. Do not edit. \"ok need to update the team on the launch slipping to march, reason is the vendor delay, want to reassure them it is on track otherwise, mention the new testing phase, keep it calm not alarming.\"\n\nStep two: hand it over. \"Turn these rough notes into a clear, calm team update of about 150 words. Keep my points and my meaning, just organize and tighten it.\"\n\nWhat comes back is your thinking, made readable. Because the ideas started with you, it sounds like you and says what you meant, which is the whole problem with starting from a blank AI prompt.\n\nThis works for almost anything: a status update, a proposal, a tricky message, a set of instructions. Dump first, shape second.\n\nTwo things to keep in mind. Read the result to make sure the AI did not change your meaning or add a claim you did not make. And if a line does not sound like you, change it. The polish is a draft, not a verdict."}$lum$::jsonb, false),
  ($lum$beaa4854-ad87-59ed-93a4-37598f93ba20$lum$::uuid, $lum$2619ae8e-1c6c-5f35-be89-86ec671c690f$lum$::uuid, 1, $lum$before_after$lum$, $lum${"question":"The left is a real brain-dump. The right is what you would hand off. Notice the order of operations.","before_prompt":"ok need to tell the team the launch is moving to march, vendor delay caused it, everything else is fine, want them calm not worried, also mention we added a testing phase which is actually a good thing","after_prompt":"Turn these rough notes into a calm, reassuring team update of about 150 words, in plain language. Keep all my points and my meaning, just organize and tighten it. Here are the notes: launch is moving to march because of a vendor delay, everything else is on track, and we added a testing phase that will make the release stronger.","changes":["Keeps the messy brain-dump as the raw material instead of trying to write it perfectly the first time.","Gives a clear instruction for length, tone, and the rule to preserve meaning, so the AI organizes rather than rewrites your intent.","Separates thinking from polishing, which is why the result still sounds like you and says what you meant."]}$lum$::jsonb, true),
  ($lum$a871368c-9ada-502f-a65d-beeca4fa57da$lum$::uuid, $lum$2619ae8e-1c6c-5f35-be89-86ec671c690f$lum$::uuid, 2, $lum$multiple_choice$lum$, $lum${"stem":"Why does the dump-first, shape-second workflow produce writing that still sounds like you?","options":[{"id":"a","label":"Because the ideas start with you in the brain-dump, so the AI is organizing your own thinking rather than inventing content from a blank prompt.","is_correct":true,"explanation":"Correct. The hard part of writing is having the ideas. When they come from you, the polished version still says what you meant and sounds like you."},{"id":"b","label":"Because the AI rewrites everything into a polished corporate voice that's better than yours.","is_correct":false,"explanation":"That's the opposite of the goal. A generic corporate voice is exactly what you avoid by supplying your own raw thinking first."},{"id":"c","label":"Because you skip reading the result once the AI returns the polished draft.","is_correct":false,"explanation":"You still read to check the AI didn't change your meaning or add a claim, and fix any line that doesn't sound like you. The polish is a draft, not a verdict."}]}$lum$::jsonb, false),
  ($lum$886d697f-f7b9-5485-9499-ffe37e10686d$lum$::uuid, $lum$aeaba649-bfe8-5541-9e0c-ed1f2b45ec04$lum$::uuid, 0, $lum$reading$lum$, $lum${"markdown":"You know the feeling. A 30-page policy update lands in your inbox, or a 12-page vendor contract, or a meeting transcript that ran ninety minutes, and you do not have an hour to wade through it. You need to know what it means for you, and you need to know now. Reading every word is a luxury you rarely get. This is one of the things AI does genuinely well, and done right it turns an hour of dense reading into a two-minute brief you can actually act on.\n\nThe mistake almost everyone makes is asking for a plain \"summarize this.\" That gives you a shorter version of the document, which is still generic and still not aimed at anything in particular. A neutral summary treats every part of the document as equally important, but you do not care about every part equally. You have a specific question or decision in front of you, and a good summary is shaped by that purpose. The difference between a useless summary and a great one is whether you told the AI what you are trying to do.\n\nSo hand the AI three things along with the document. First, who you are: your role and what you care about. Second, what you are trying to decide or do. Third, how you want the answer shaped: the format, the length, the focus. Those three pieces turn a generic recap into a brief aimed straight at your job."}$lum$::jsonb, false),
  ($lum$5d1c4e08-71ca-5471-ba80-0ff2ab246e50$lum$::uuid, $lum$aeaba649-bfe8-5541-9e0c-ed1f2b45ec04$lum$::uuid, 1, $lum$multiple_choice$lum$, $lum${"stem":"According to the reading, what is the difference between a useless summary and a great one?","options":[{"id":"a","label":"The great one is much longer and covers every section of the document.","is_correct":false,"explanation":"Length is not the point. A neutral summary that weights every part equally is exactly the generic result the reading warns against."},{"id":"b","label":"Whether you told the AI what you are trying to do, so the summary is shaped by your purpose.","is_correct":true,"explanation":"Right. The reading says a good summary is shaped by your purpose, and the difference comes down to whether you told the AI what you are trying to do."},{"id":"c","label":"Whether you used a paid AI tool instead of a free one.","is_correct":false,"explanation":"The reading never ties quality to the tool you pay for. It ties it to giving the AI your role, your decision, and the shape you want."}]}$lum$::jsonb, false),
  ($lum$64f829b6-8bf9-5903-9466-1e755f480b07$lum$::uuid, $lum$aeaba649-bfe8-5541-9e0c-ed1f2b45ec04$lum$::uuid, 2, $lum$reading$lum$, $lum${"markdown":"Here is a real example. An office manager gets a revised travel and expense policy, 22 pages long, most of it boilerplate. Instead of reading it all, she pastes it in and writes: \"I am an office manager and I need to know whether this new policy changes how my team books travel and submits expenses. Pull out only the parts about booking, approvals, and reimbursement limits. Give me five plain bullet points, and flag anything that needs me to take action or change a process. Ignore the legal background.\" What comes back is exactly the slice she needs: the new approval threshold, the changed per-diem rate, the deadline to update the booking tool. The other seventeen pages of context she never has to touch.\n\nThe kind of summary you ask for should match the kind of document, because different material hides different things. For a contract, ask for the obligations and the risks: \"I am reviewing this service agreement before we sign. List every commitment we are making, every fee or penalty, any auto-renewal or cancellation terms, and flag anything unusual or one-sided. Plain language, no legalese.\" For a meeting transcript, ask for decisions and owners: \"From this transcript, give me the decisions we made, the action items with who owns each one, and any open questions left unresolved.\" For a dense research report or a technical paper, ask for plain-language translation: \"Explain the main finding of this study as if I have no background in the field, then tell me in one sentence why it matters for a school like mine.\" Naming the kind of summary you need is what separates a useful answer from a shorter wall of text."}$lum$::jsonb, false),
  ($lum$74307f84-6ae5-5cc7-b004-b299abf74b89$lum$::uuid, $lum$aeaba649-bfe8-5541-9e0c-ed1f2b45ec04$lum$::uuid, 3, $lum$multiple_choice$lum$, $lum${"stem":"You get a 22-page travel policy and need to know if it changes how your team books trips. What gets you the most useful summary?","options":[{"id":"a","label":"Tell the AI your role, the specific decision you face, and the format you want, then check the key numbers against the document.","is_correct":true,"explanation":"Right. A summary shaped by your role and decision filters out the boilerplate and surfaces what you must act on, and spot-checking the numbers keeps you from acting on an error."},{"id":"b","label":"Paste it in and type 'summarize this,' since a shorter version is all you need.","is_correct":false,"explanation":"A plain summary treats every part as equally important and returns a generic recap. It will not aim at your specific question about booking and expenses."},{"id":"c","label":"Ask the AI to reproduce the full document word for word so you do not miss anything.","is_correct":false,"explanation":"That defeats the point of a summary. The value is a purpose-shaped, actionable few points, then a spot-check of the parts that matter against the source."}]}$lum$::jsonb, false),
  ($lum$b4fdf397-6426-5a68-9da2-1e1235525fe1$lum$::uuid, $lum$aeaba649-bfe8-5541-9e0c-ed1f2b45ec04$lum$::uuid, 4, $lum$reading$lum$, $lum${"markdown":"A few moves make summaries far more valuable. Ask for the decision, not just the content. \"What should I do differently after reading this?\" is often worth more than a neutral recap, because it pushes the AI to connect the document to your situation. Ask what is missing or unclear: \"What questions should I ask before agreeing to this?\" turns the AI into a thinking partner instead of just a text-shrinker. And request the exact structure you want. A one-paragraph overview, five bullets, a pros-and-cons table, a list of risks ranked by seriousness. Name the format and you will get it, which means you can drop the result straight into your own notes or an email without reformatting.\n\nNow the discipline that keeps you safe. For anything that matters, spot-check the summary against the real document, especially numbers, dates, names, and any claim you are about to act on. AI summaries can quietly get a figure wrong, blur two points into one, or state something confidently that the document does not actually say. If the summary tells you the contract auto-renews on December 1, find that line in the contract before you put it in your calendar. If it says the policy raises the expense limit to $75, check the actual number. The summary is a fast first read that tells you where to look, not the final word you quote to your boss. Think of it as a sharp intern's memo: usually right, occasionally wrong in ways that matter, and always worth verifying before you stake a decision on it. Used that way, summarizing is one of the biggest time savings AI offers a knowledge worker, and one of the safest, as long as you keep your eyes on the source for the parts that count."}$lum$::jsonb, false),
  ($lum$c5874644-659b-500a-9015-d470ca8b8817$lum$::uuid, $lum$aeaba649-bfe8-5541-9e0c-ed1f2b45ec04$lum$::uuid, 5, $lum$multiple_choice$lum$, $lum${"stem":"The reading suggests asking 'What should I do differently after reading this?' Why is that often worth more than a neutral recap?","options":[{"id":"a","label":"It guarantees the AI will never make a factual error in the summary.","is_correct":false,"explanation":"Nothing guarantees that. The reading is clear that summaries can get figures wrong or state things the document does not say, which is why you still spot-check."},{"id":"b","label":"It produces a longer answer, and longer answers are more trustworthy.","is_correct":false,"explanation":"The reading does not equate length with value. The point of the question is to connect the document to your situation, not to add words."},{"id":"c","label":"It pushes the AI to connect the document to your situation instead of just shrinking the text.","is_correct":true,"explanation":"Right. The reading says asking for the decision pushes the AI to connect the document to your situation, which is worth more than a neutral recap."}]}$lum$::jsonb, false),
  ($lum$16a1927d-0d4a-5b8e-9fc5-9309bf2336b1$lum$::uuid, $lum$aeaba649-bfe8-5541-9e0c-ed1f2b45ec04$lum$::uuid, 6, $lum$reading$lum$, $lum${"markdown":"The biggest mistake is trusting the summary without ever opening the source. People paste in a contract, get back a clean list of terms, and act on it as if they read the contract themselves. Then they discover the AI missed an auto-renewal clause, or rounded a penalty figure, or stated a deadline the document never mentioned. AI summaries are confident even when they are wrong, and a missing point looks exactly like a document that did not contain that point. For anything you will act on, find the key claims in the source before you rely on them, especially numbers, dates, and obligations.\n\nThe second mistake is asking for an unaimed \"summarize this\" and accepting the generic result. Without your role and your decision, the AI has no way to know which parts matter, so it gives every section equal weight and you get a shorter version of the same wall of text. The fix is one sentence: say who you are and what you need to decide. \"I am a team lead checking whether this affects my budget\" produces a completely different, far more useful summary than no framing at all."}$lum$::jsonb, false),
  ($lum$c22bcd3f-6780-595b-9340-382bd56c6659$lum$::uuid, $lum$aeaba649-bfe8-5541-9e0c-ed1f2b45ec04$lum$::uuid, 7, $lum$multiple_choice$lum$, $lum${"stem":"The AI summary of a contract says it auto-renews on December 1. What should you do before putting that date in your calendar?","options":[{"id":"a","label":"Find that clause in the actual contract and confirm the date, because AI summaries can state dates or numbers the document does not support.","is_correct":true,"explanation":"Right. Summaries are confident even when wrong. Verifying key dates, numbers, and obligations against the source is the step that keeps you from acting on an error."},{"id":"b","label":"Trust it and set the reminder, since the AI read the whole document and you did not.","is_correct":false,"explanation":"A confident summary is not a verified one. A missing or misstated clause looks identical to a correct one, so anything you act on needs a check against the source."},{"id":"c","label":"Ask the AI a second time and go with whichever date it gives twice.","is_correct":false,"explanation":"Repeating the question to the same tool can repeat the same error. The authority is the document itself, so check the clause there."}]}$lum$::jsonb, false),
  ($lum$1cd5028c-73d8-559c-8b0b-6642156135b8$lum$::uuid, $lum$aeaba649-bfe8-5541-9e0c-ed1f2b45ec04$lum$::uuid, 8, $lum$reading$lum$, $lum${"markdown":"The third mistake is asking the wrong kind of summary for the document. A contract summarized as a neutral overview buries the risks; you needed obligations and penalties flagged, not a friendly recap. A meeting transcript summarized as prose buries the action items; you needed a list of decisions and owners. Match the request to what the document is for. Ask a contract for risks, a transcript for decisions and owners, a research paper for a plain-language finding.\n\nA fourth trap is pasting sensitive material into a tool your workplace has not approved. Patient records, client matters, employee files, and confidential contracts may not belong in a public AI tool. Check your organization's policy first, and when in doubt, summarize a redacted version or describe the document in general terms rather than pasting the real thing.\n\nThe last mistake is letting the summary replace your own judgment on the parts that carry weight. A summary is a fast first read that tells you where to focus, not a substitute for reading the clause your signature depends on. Use it to triage a long document quickly, then read the few sections that actually matter in full. The time you save on the boilerplate is real; the time you spend verifying the critical parts is not optional."}$lum$::jsonb, false),
  ($lum$9a3497c5-3e93-546b-baf9-eda12fa95080$lum$::uuid, $lum$aeaba649-bfe8-5541-9e0c-ed1f2b45ec04$lum$::uuid, 9, $lum$multiple_choice$lum$, $lum${"stem":"The reading warns against pasting sensitive material into an unapproved tool. What does it suggest doing when you are in doubt?","options":[{"id":"a","label":"Paste the full document anyway, since the AI will keep it confidential.","is_correct":false,"explanation":"The reading says the opposite. Patient records, client matters, and confidential contracts may not belong in a public AI tool at all."},{"id":"b","label":"Check your organization's policy first, and summarize a redacted version or describe the document in general terms.","is_correct":true,"explanation":"Right. The reading says to check the policy first and, when in doubt, summarize a redacted version or describe the document in general terms instead of pasting the real thing."},{"id":"c","label":"Wait until after the deadline so the material is no longer sensitive.","is_correct":false,"explanation":"The reading never suggests timing as a fix. The concern is the tool's approval and the data itself, so you redact, generalize, or check the policy."}]}$lum$::jsonb, false),
  ($lum$28f522cf-4dfc-5819-a075-b4eb5bfe4f27$lum$::uuid, $lum$aeaba649-bfe8-5541-9e0c-ed1f2b45ec04$lum$::uuid, 10, $lum$before_after$lum$, $lum${"question":"You are a team lead handed a 30-page quarterly report and you only need to know if it touches your budget next quarter. Same document, two requests. See how the second one does the thinking for you.","before_prompt":"Summarize this quarterly report. [pastes a 30-page report]","after_prompt":"I am a team lead and I need to know whether anything in this quarterly report affects my team's budget or headcount next quarter. From the report below, give me five plain bullet points covering only budget and headcount, flag anything I need to act on, and list any numbers I should double-check against the source. Ignore the marketing and strategy sections. [pastes the report]","changes":["States your role and the specific decision, so the summary aims at your budget question instead of recapping the whole report.","Narrows the focus to budget and headcount and tells the AI to ignore the irrelevant sections, filtering out most of the document.","Asks for an action flag and a list of numbers to verify, so you get something you can act on and you know exactly what to spot-check against the source."]}$lum$::jsonb, true),
  ($lum$c77d1bad-0d14-5d46-99cd-4f6527076c7b$lum$::uuid, $lum$aeaba649-bfe8-5541-9e0c-ed1f2b45ec04$lum$::uuid, 11, $lum$multiple_choice$lum$, $lum${"stem":"In the quarterly-report example, why ask the AI to 'list any numbers I should double-check against the source'?","options":[{"id":"a","label":"It points you straight to the figures most worth verifying, so you can confirm the critical numbers in the report instead of trusting the summary blindly.","is_correct":true,"explanation":"Right. The summary is a fast first read. Knowing which numbers to verify lets you spot-check the parts you will act on without re-reading all 30 pages."},{"id":"b","label":"It makes the summary longer so it feels more thorough.","is_correct":false,"explanation":"Length is not the goal. The point is to direct your verification to the figures that matter, not to pad the output."},{"id":"c","label":"It lets you skip checking the document entirely, since the AI already flagged the numbers.","is_correct":false,"explanation":"The opposite is true. The flag tells you where to look in the source; the AI flagging a number is the reason to verify it, not to skip verification."}]}$lum$::jsonb, false),
  ($lum$c0a7dfaf-e9b7-5fce-8331-8558bd4ae8f2$lum$::uuid, $lum$aeaba649-bfe8-5541-9e0c-ed1f2b45ec04$lum$::uuid, 12, $lum$mini_project$lum$, $lum${"brief":"Take a real long document sitting in your inbox or files right now, something you have been avoiding because it is too long to read closely: a policy update, a contract, a long report, or a meeting transcript. Turn it into a purpose-shaped brief you can actually use, then verify it.","parts":[{"id":"1","prompt":"Write a summary request that names your role, the specific decision or question you have, and the exact format you want (five bullets, a risks list, decisions and owners, whatever fits the document). Match the kind of summary to the kind of document."},{"id":"2","prompt":"Run it, then ask one follow-up that pushes the AI further: \"What should I do differently after reading this?\" or \"What questions should I ask before agreeing?\" Capture anything new it surfaces."},{"id":"3","prompt":"Pick the three most important claims in the summary (a number, a date, an obligation, an action item) and find each one in the original document to confirm it is accurate. Note any place the summary was wrong, vague, or missing something, so you learn where this tool needs your check the most."}]}$lum$::jsonb, false),
  ($lum$14b1faf7-2cb4-5af1-9689-53f512404782$lum$::uuid, $lum$f3c48a5e-7040-5855-98f2-61b1c8514c55$lum$::uuid, 0, $lum$reading$lum$, $lum${"markdown":"The problem with meetings isn't the meeting: it's what happens in the 15 minutes after. People scatter. Action items get buried. By the next day, everyone remembers the discussion but not the decisions.\n\n**The protocol:** Within 5 minutes of ending any meeting, open ChatGPT and paste or voice-type your rough notes. Use this prompt:\n\n*\"I just had a [type of meeting] with [who]. Here are my rough notes: [paste]. Please: 1) Summarize the key decisions made, 2) List action items with owners if mentioned, 3) Flag any open questions that weren't resolved, 4) Draft a 3-sentence follow-up message I can send to the group.\"*\n\nThe output becomes your meeting record and your follow-up email draft in under 2 minutes.\n\n**Why rough notes work fine:** You don't need to clean up your notes before pasting: the model handles messy, stream-of-consciousness input well. Abbreviations, half-sentences, bullet fragments: all fine.\n\n**The voice shortcut:** On mobile, use voice-to-text to dictate your notes immediately after hanging up. The raw transcript feeds directly into the prompt. No typing, no cleanup.\n\nThis protocol works because it forces you to extract the cognitive value while the meeting is still fresh, but outsources the formatting and drafting to the model."}$lum$::jsonb, false),
  ($lum$1926c02a-b2b8-5080-a74f-a52f566785a3$lum$::uuid, $lum$f3c48a5e-7040-5855-98f2-61b1c8514c55$lum$::uuid, 1, $lum$multiple_choice$lum$, $lum${"stem":"The protocol says to run your notes within 5 minutes of the meeting ending, and that rough, messy notes are fine. Why both?","options":[{"id":"a","label":"Running it immediately captures the decisions while the meeting is still fresh in your head, and rough notes work because the model handles messy, fragmentary input well.","is_correct":true,"explanation":"Correct. The timing preserves the cognitive value before it fades, and you can hand over abbreviations and half-sentences because the model cleans up the formatting and drafting for you."},{"id":"b","label":"You must clean up your notes into full sentences first, or the model will misread them, and the 5-minute window is just a productivity habit.","is_correct":false,"explanation":"The lesson says the opposite: you do not need to clean notes up, because the model handles stream-of-consciousness input. And the 5-minute window matters because memory fades fast, not as an arbitrary habit."},{"id":"c","label":"The 5 minutes is for the model to process, and rough notes are fine because the meeting was recorded anyway.","is_correct":false,"explanation":"The window is about your memory, not processing time, and the protocol assumes no recording, just your own rough notes feeding the prompt."}]}$lum$::jsonb, false),
  ($lum$144922ac-8946-50c2-98ca-ea1c10b39a67$lum$::uuid, $lum$f3c48a5e-7040-5855-98f2-61b1c8514c55$lum$::uuid, 2, $lum$mini_project$lum$, $lum${"brief":"Your 5-minute exercise: After your next meeting, write 5-10 rough bullet points of what happened. Run them through the protocol above. How does the output compare to your usual post-meeting notes?","parts":[]}$lum$::jsonb, false),
  ($lum$e3d49108-5968-58ec-9989-2662a82979a2$lum$::uuid, $lum$f78c5f60-14ea-54cc-a7b7-a9c5eb3bed5c$lum$::uuid, 0, $lum$reading$lum$, $lum${"markdown":"Slack is a river, not a document. By the time you get to a thread that happened while you were in meetings, there are 40 messages, three topic changes, and two decisions buried somewhere in the middle.\n\n**The rule:** Never read a long Slack thread linearly. Copy and summarize.\n\nSelect all the messages in a thread, copy them, and paste into ChatGPT with: *\"Summarize this Slack thread. What was discussed? What was decided? What action items or open questions remain? Keep it to bullet points, 5 max.\"*\n\nThis takes 15 seconds and gives you a better read of the thread than reading it yourself, because it surfaces the signal without the noise (the jokes, the \"+1\"s, the \"sounds good\" messages that make up 60% of most threads).\n\n**Channel-level summaries:** If you've been away for a day and need to catch up on a busy channel, copy the last N messages and run the same prompt.\n\n**The boundary:** This doesn't work for threads where you need to feel the emotional temperature of the conversation. For those, read. For everything else, summarize.\n\nThe rule works because it forces you to extract meaning rather than consume content."}$lum$::jsonb, false),
  ($lum$68cb17b1-fc52-5369-9648-5b1032ade39e$lum$::uuid, $lum$f78c5f60-14ea-54cc-a7b7-a9c5eb3bed5c$lum$::uuid, 1, $lum$fill_blank$lum$, $lum${"template":"Never read a long Slack thread {{1}}. Copy the messages and ask AI to {{2}} them into five bullets, which surfaces the signal under the noise. The one exception is a thread where you need to feel the emotional {{3}} of the conversation: read that one yourself.","blanks":[{"id":"1","answer":"linearly","alternatives":["top to bottom","in order"]},{"id":"2","answer":"summarize","alternatives":["summarise"]},{"id":"3","answer":"temperature","alternatives":["tone"]}]}$lum$::jsonb, false),
  ($lum$61107eda-a865-5b71-801d-16304dc0c887$lum$::uuid, $lum$f78c5f60-14ea-54cc-a7b7-a9c5eb3bed5c$lum$::uuid, 2, $lum$mini_project$lum$, $lum${"brief":"Your 5-minute exercise: Find the longest Slack thread from the past 48 hours. Copy all the messages and run the summary prompt. How long would reading it have taken vs. the 15 seconds this took?","parts":[]}$lum$::jsonb, false),
  ($lum$54e69274-485a-519e-9085-e23b0406c323$lum$::uuid, $lum$cca9dfe2-ad9f-54a3-83a0-835db3624cfc$lum$::uuid, 0, $lum$reading$lum$, $lum${"markdown":"A bad brief produces a bad deliverable. This is true for design agencies, copywriters, developers, and any external collaborator. The problem is that most people write briefs that describe what they want without explaining why they want it or what bad looks like.\n\n**The AI-assisted brief template:**\n\n1. **Background:** What's the context? What exists already?\n2. **Objective:** What does success look like in one measurable sentence?\n3. **Audience:** Who is this for? What do they know? What do they care about?\n4. **Deliverables:** Exact list of outputs with specs (format, length, deadline)\n5. **Constraints:** What's off-limits? What tone/style to avoid?\n6. **Examples:** Links or pastes of things you like (and briefly why)\n7. **Questions:** Things you need answered before work can start\n\nExplain your situation to ChatGPT and ask it to draft a brief using this structure. The model will produce a first draft in 60 seconds. You edit it. The resulting brief is 3x more detailed than what most people send, which means 3x fewer revision rounds.\n\n**The meta-benefit:** Writing the brief often reveals that you haven't made the decisions yet. Better to find out before the kickoff call than during the third revision."}$lum$::jsonb, false),
  ($lum$1c7b2dc9-11db-5608-bbf4-b2d6ad73b15d$lum$::uuid, $lum$cca9dfe2-ad9f-54a3-83a0-835db3624cfc$lum$::uuid, 1, $lum$multiple_choice$lum$, $lum${"stem":"According to this lesson, what separates a brief that cuts revision rounds from the one most people send?","options":[{"id":"a","label":"It explains why you want the thing and defines what 'bad' looks like, not just a description of what you want.","is_correct":true,"explanation":"Correct. Most briefs describe the desired output but skip the reasoning and the constraints. Spelling out the why and the off-limits gives the collaborator enough to make good calls without guessing, which is what cuts revision rounds."},{"id":"b","label":"It is as long as possible, so the collaborator has every detail spelled out and nothing is left to interpretation.","is_correct":false,"explanation":"Length is not the point. A brief that explains intent and constraints can be concise; padding it with detail does not help if the why is still missing."},{"id":"c","label":"It leaves the objective open so the external team can bring their own creative direction.","is_correct":false,"explanation":"An open objective is exactly what produces the wrong deliverable. The template asks for success defined in one measurable sentence so everyone is aiming at the same target."}]}$lum$::jsonb, false),
  ($lum$6cd18df7-71c8-521e-b346-a231d19e3b5e$lum$::uuid, $lum$cca9dfe2-ad9f-54a3-83a0-835db3624cfc$lum$::uuid, 2, $lum$mini_project$lum$, $lum${"brief":"Your 5-minute exercise: Pick an upcoming project with an external collaborator. Use ChatGPT to draft a brief using the 7-part template. Share it and note how the quality of the first questions back changes.","parts":[]}$lum$::jsonb, false),
  ($lum$601fc2c1-edbf-5bfb-b58e-a07981cc9db9$lum$::uuid, $lum$3ab28d12-c367-55f2-8b6e-8c93dfc40d77$lum$::uuid, 0, $lum$reading$lum$, $lum${"markdown":"Some messages sit in your drafts for days. Not because they are long, but because they are hard: declining a request, telling a vendor their work missed the mark, pushing back on your boss, saying no to a favor you genuinely cannot do. You want to be honest without being harsh, and finding that balance under stress is exhausting. This is a place AI quietly earns its keep.\n\nThe trick is the same one that powers good email drafting, but the inputs matter more here because the stakes are personal.\n\nGive the AI three things: **the situation, your actual position, and the relationship you want to keep.**\n\nFor example: \"I need to decline a colleague's request to join their committee. I genuinely do not have the time and I am not willing to overcommit again. But I respect them and want to stay on good terms. Draft a short, warm message that says no clearly, gives a brief honest reason, and does not leave the door falsely open.\"\n\nThat last instruction matters. A common failure in hard messages is the soft no that sounds like a maybe, which only prolongs the discomfort for both people. Telling the AI to be clear, not wishy-washy, gets you a message that actually closes the loop.\n\nA few moves that make hard messages land well:\n\n**Name the tone explicitly.** \"Warm but firm.\" \"Apologetic but not groveling.\" \"Direct without being cold.\" The tone is the whole game in a hard message, so do not leave it to chance.\n\n**Ask for brevity.** Hard messages get worse the longer they ramble. \"Keep it under 100 words\" forces the AI to be clean and direct, which is exactly what these messages need.\n\n**Keep the honesty yours.** The AI can find graceful wording, but you decide what is true and what you are willing to say. Read it and make sure it reflects your real position, not a smoother version you do not mean.\n\nThen do the thing you always do: read it once, adjust the one detail only you know, and send. The message that haunted your drafts folder for three days goes out in three minutes, and it sounds like a thoughtful adult wrote it, because one did."}$lum$::jsonb, false),
  ($lum$9dcb9faa-2e11-5bfa-a07f-0a1738ecf619$lum$::uuid, $lum$3ab28d12-c367-55f2-8b6e-8c93dfc40d77$lum$::uuid, 1, $lum$before_after$lum$, $lum${"question":"You need to turn down a colleague's request. One prompt produces a vague soft no, the other a graceful clear one. Notice what you have to specify.","before_prompt":"Write a message declining my coworker's request to help with their project.","after_prompt":"Help me decline a coworker's request to help with their project. The truth: I'm at capacity and I overcommitted last quarter, so I need to hold this line. I respect them and want to keep a good working relationship. Draft a short message (under 90 words) that says no clearly, gives one honest brief reason, does not leave a false maybe open, and offers a small genuine gesture like pointing them to a resource. Tone: warm but firm.","changes":["Supplies your real position and reason, so the message is honest rather than a generic brush-off.","Explicitly asks for a clear no with no false maybe, avoiding the soft-no trap that drags the discomfort out.","Names the tone and a length limit and protects the relationship, so the no stays kind without becoming wishy-washy."]}$lum$::jsonb, true),
  ($lum$6068c1b0-671f-57f8-bbb5-0af886aa78ea$lum$::uuid, $lum$3ab28d12-c367-55f2-8b6e-8c93dfc40d77$lum$::uuid, 2, $lum$multiple_choice$lum$, $lum${"stem":"This lesson names one common failure that makes hard messages worse. Which is it?","options":[{"id":"a","label":"The soft no that sounds like a maybe, which only prolongs the discomfort for both people instead of closing the loop.","is_correct":true,"explanation":"Correct. A no dressed up to feel gentle but read as a maybe leaves the other person hoping and drags the awkwardness out. Telling the AI to be clear and not leave a false door open is what actually resolves it."},{"id":"b","label":"Being too direct, since any clear no will damage the relationship no matter how it is worded.","is_correct":false,"explanation":"The lesson argues the opposite: a clear, warm no protects the relationship better than a vague one. Clarity and kindness are not in conflict here."},{"id":"c","label":"Making the message too short, because hard news needs a long, thorough explanation to feel respectful.","is_correct":false,"explanation":"The lesson advises brevity, noting hard messages get worse the longer they ramble. A tight message under 100 words is the goal, not a long one."}]}$lum$::jsonb, false),
  ($lum$4533d00b-7645-53ce-82a8-93f0d9fa4ad5$lum$::uuid, $lum$01bbfdc0-3784-5623-ac50-69d0e853b466$lum$::uuid, 0, $lum$reading$lum$, $lum${"markdown":"Here's a frustration almost everyone hits early: you ask a simple question and get an essay. Five headings, a bulleted list, a summary, and a cheerful offer to go deeper. You wanted a sentence. This isn't AI being unhelpful, it's AI guessing that more is safer than less. The fix is in your hands, and it's almost embarrassingly simple.\n\n**The default is \"comprehensive.\" You have to ask for \"brief.\"** Left to its own devices, the model pads. It would rather over-explain than risk leaving something out. So the single most useful instruction you can add is a limit: \"in one sentence,\" \"three bullets max,\" \"just the answer, no preamble,\" \"under 50 words.\" State the size you want and the wall of text disappears.\n\n**Specify the shape, not just the length.** Length is half of it; format is the other half. Tell it *how* you want the answer arranged:\n- \"Just give me the bottom line first, then one line of why.\"\n- \"Answer with a yes or no, then a single sentence.\"\n- \"Give me three options as a short list, no explanations.\"\n- \"A table with two columns: option and main tradeoff.\"\n\nThe clearer the shape, the less you have to dig through to find what you actually came for.\n\n**Ask for less, then ask for more.** It feels backwards, but it's faster. Start with the short version. If you want depth on one point, ask for it: \"expand the second bullet.\" This beats receiving everything up front and hunting for the 10% you needed. You stay in control of how deep to go, instead of the AI deciding for you.\n\n**Why this matters beyond annoyance:** a tight answer is one you'll actually read, check, and use. A wall of text gets skimmed, and skimming is exactly how wrong details slip past you. Short isn't just more pleasant; it's safer, because you can actually see what it said.\n\nSo next time the box fills with paragraphs, don't sigh and scroll. Add five words about length and shape, and ask again."}$lum$::jsonb, false),
  ($lum$df988d8e-24e2-5ccf-8118-b511b6e2ffde$lum$::uuid, $lum$01bbfdc0-3784-5623-ac50-69d0e853b466$lum$::uuid, 1, $lum$before_after$lum$, $lum${"question":"Same question, but the second version controls the size and shape of the answer.","before_prompt":"Should I use a subject line with a question or a statement for my newsletter?","after_prompt":"Should I use a question or a statement in my newsletter subject line? Give me a one-line recommendation, then two short bullets on when to break that rule. Under 60 words total.","changes":["Sets a clear length cap (under 60 words) so the answer doesn't balloon into an essay.","Specifies the shape: a one-line recommendation followed by two bullets, so the useful part is right up top.","Leaves room to go deeper later by asking for more on either bullet, instead of getting everything at once."]}$lum$::jsonb, false),
  ($lum$51e4794f-d93d-5142-bea9-7c54891c7220$lum$::uuid, $lum$88ae3149-d332-5be1-a850-8e342251cdc3$lum$::uuid, 0, $lum$reading$lum$, $lum${"markdown":"The moment you sign up, you'll see the pitch: a paid plan, usually around twenty dollars a month, promising the \"smartest\" model and more of everything. It's tempting to assume the real value is behind the paywall. For a beginner, it usually isn't. Here's how to think about it without overspending or under-equipping yourself.\n\n**The free tier is a real product, not a crippled demo.** On the major assistants, the free version can draft, summarize, explain, brainstorm, and handle the everyday tasks this whole module is about. You can build the entire habit, and finish this course, without paying a cent. Start there. Spending money before you know what you need is just a more expensive way to procrastinate.\n\n**Paid tiers buy three things, mostly.** When you do hit the limits, here's what your money actually gets you:\n- **Smarter models for hard tasks.** The top-tier model reasons better on complex, multi-step problems. For rewriting an email, you won't notice. For untangling a thorny analysis, you might.\n- **Higher limits.** Free tiers cap how much you can use the best model per day. Heavy users hit that wall; occasional users rarely do.\n- **Extra features.** Things like file uploads, image generation, web browsing, or connecting to your documents are sometimes gated to paid plans, and this varies by tool.\n\n**Upgrade when you can name the wall.** Don't pay on a vague feeling that paid is \"better.\" Pay when you can finish this sentence: \"I keep hitting *this specific limit* and it's slowing down *this real task*.\" Maybe you keep running out of the good model mid-afternoon, or you need to upload documents and can't. That's a real reason. \"It might be better\" is not.\n\n**If your employer provides a tool, use that first.** Many workplaces hand out a paid Copilot or Gemini seat that's already connected to your email and files. That's a paid tier someone else is funding. Check before you buy your own.\n\nFree until it pinches, then upgrade with a reason. That's the whole decision."}$lum$::jsonb, false),
  ($lum$1ca547d9-c78d-5be0-8247-c330b2b66485$lum$::uuid, $lum$88ae3149-d332-5be1-a850-8e342251cdc3$lum$::uuid, 1, $lum$multiple_choice$lum$, $lum${"stem":"Which is the right reason for a beginner to upgrade to a paid plan?","options":[{"id":"a","label":"The paid plan is advertised as the smartest, so it must produce better emails","is_correct":false,"explanation":"For everyday tasks like emails, you won't notice the difference. 'It's advertised as better' is a marketing feeling, not a real need."},{"id":"b","label":"You keep hitting the daily limit on the good model right when you need it for real work","is_correct":true,"explanation":"Exactly. A specific, repeatable wall that slows down real work is precisely the signal that paying will actually buy you something."},{"id":"c","label":"Everyone online says the free version is for amateurs","is_correct":false,"explanation":"The free tier handles the vast majority of beginner tasks. Social pressure is not a limit you've actually hit."}]}$lum$::jsonb, false),
  ($lum$b555c391-00db-5188-969c-556f291322ec$lum$::uuid, $lum$f1b7ebba-a8a7-5762-b108-b4317e2c6dba$lum$::uuid, 0, $lum$reading$lum$, $lum${"markdown":"AI is most helpful when you give it the real thing. Real emails, real drafts, real numbers, real situations produce far better answers than a vague description. This lesson is the guardrail on that advice, because \"real\" sometimes means \"sensitive,\" and the chat box is not the private vault people assume it is.\n\nStart with the honest truth about where your text goes. When you paste something into a free, public AI tool, assume it may be stored, may be used to help train future models, and may be seen by a human reviewer checking quality or safety. That is not paranoia; it is how many consumer tools work by default. The right mental picture is not a sealed envelope. It is a postcard. Most postcards are completely fine to send. You just would not write your bank PIN on one.\n\nSo here is the test that does all the work. Before you hit enter, ask yourself: would I be comfortable posting this exact text on a public bulletin board in the office lobby, where any coworker, client, or stranger could read it? If yes, paste away. If something in you flinches, that flinch is the signal. You do not need to memorize privacy law. You need that one half-second pause."}$lum$::jsonb, false),
  ($lum$8e307747-a4b9-529a-902c-0d039bd3e390$lum$::uuid, $lum$f1b7ebba-a8a7-5762-b108-b4317e2c6dba$lum$::uuid, 1, $lum$multiple_choice$lum$, $lum${"stem":"According to the reading, when you paste text into a free, public AI tool, what is the safest assumption to make about where that text goes?","options":[{"id":"a","label":"It stays private between you and the AI, like a sealed envelope no one else opens","is_correct":false,"explanation":"That is exactly the wrong mental picture. The reading says it is a postcard, not a sealed envelope, because the text may be stored or read by others."},{"id":"b","label":"It may be stored, used to help train future models, and seen by a human reviewer","is_correct":true,"explanation":"Right. The reading says to assume all three by default, which is why the postcard picture fits: fine to send most things, but not your bank PIN."},{"id":"c","label":"It is deleted instantly the moment you close the chat window","is_correct":false,"explanation":"Nothing in the reading suggests this. The honest truth is the opposite: assume it may be stored and reviewed, which is how many consumer tools work by default."}]}$lum$::jsonb, false),
  ($lum$4fd5f6c2-51b0-5689-b781-db0ed08fc044$lum$::uuid, $lum$f1b7ebba-a8a7-5762-b108-b4317e2c6dba$lum$::uuid, 2, $lum$reading$lum$, $lum${"markdown":"To make the flinch reliable, run a quick three-part check on the text in front of you.\n\nCould it identify a real person? Names, email addresses, phone numbers, home addresses, account numbers, dates of birth, medical details, or HR records. A patient's name next to their diagnosis is identifying. So is an employee's name next to a complaint about them.\n\nIs it confidential or under an agreement? Unreleased financial figures, anything stamped \"internal\" or \"privileged,\" client material covered by an NDA, contract terms, or proprietary work your company would not want public.\n\nWould it cause harm if it leaked? Passwords, security details, private medical or legal records, an employee's salary, or anything embarrassing or damaging if read out of context.\n\nIf all three are clearly \"no,\" you are safe; paste the real material and get a great answer. If any one is \"yes,\" do not just paste and hope. You have three good moves instead."}$lum$::jsonb, false),
  ($lum$14af1f99-7257-5b72-81ed-73ac2831a1bc$lum$::uuid, $lum$f1b7ebba-a8a7-5762-b108-b4317e2c6dba$lum$::uuid, 3, $lum$multiple_choice$lum$, $lum${"stem":"You are about to paste a paragraph into a free, public AI tool to get help rewording it. Which of these, if left in the text, is the unsafe one that goes wrong?","options":[{"id":"a","label":"A patient's full name sitting right next to their diagnosis and medical record number","is_correct":true,"explanation":"Right. A real person's name tied to a diagnosis and MRN is exactly the identifying, harmful-if-leaked material the bulletin-board test is built to catch. Strip it to a role before pasting."},{"id":"b","label":"A general description like 'an older adult being discharged after a heart failure flare-up'","is_correct":false,"explanation":"This is the substance with no identifiers attached. It points to no specific person, so it is safe to paste and is exactly what you keep after stripping."},{"id":"c","label":"A request for 'clear home-care instructions at a sixth-grade reading level'","is_correct":false,"explanation":"This is just an instruction about format and audience. It carries no names, numbers, or secrets, so there is nothing here that can go wrong."}]}$lum$::jsonb, false),
  ($lum$9ff05109-17a2-56a8-8bea-3c1e43f4d370$lum$::uuid, $lum$f1b7ebba-a8a7-5762-b108-b4317e2c6dba$lum$::uuid, 4, $lum$reading$lum$, $lum${"markdown":"Move one, and the one you will use most: strip and generalize. The AI almost never needs the identifying specifics to help you. Take a real example. A nurse wants help wording a discharge instruction. The note says \"Maria Gonzalez, DOB 4/2/1958, MRN 88214, discharged after CHF exacerbation.\" She does not paste that. She pastes: \"Patient is an older adult being discharged after a flare-up of heart failure. Help me write clear home-care instructions at a sixth-grade reading level.\" The AI writes an excellent set of instructions, and no patient identifier ever left the building. The real name added nothing useful anyway.\n\nSame move for a paralegal. Instead of pasting a settlement agreement with both parties' names, the firm's name, and the dollar figure, paste: \"I have a settlement agreement between two parties for a personal injury claim. Help me draft a plain-English summary letter explaining the key terms to a client. Here are the terms with names and the amount replaced by placeholders.\" Swap \"Henderson\" for \"the plaintiff\" and \"$47,500\" for \"[settlement amount].\" You get the same quality draft and hand over nothing identifying.\n\nMove two: use your work-approved tool. Many employers now provide an enterprise version of ChatGPT, Claude, or Copilot with a contract that says your data will not be used for training and will not be retained the way the free consumer version is. If your workplace offers one, that is where sensitive-but-permitted work belongs. Check with IT about what your specific tool is allowed to handle, because the rules differ. The free personal account on your phone is the postcard; the approved enterprise tool is closer to the sealed envelope, but only if your IT team confirms it.\n\nMove three: just do not paste it. Some things never belong in any chat box, approved or not. Passwords and login credentials. Full Social Security numbers. Bank account and routing numbers. A client's confidential legal records when you are not certain of the rules. When something is clearly in this category, do that piece yourself and let AI help with everything around it. You can still ask \"how should I structure a password-reset email\" without ever typing the password, and you can ask \"what should a wire-transfer confirmation note include\" without pasting the account number. The tool helps with the shape of the work while the secret stays with you.\n\nNotice the goal is not fear. The goal is one small reflex that costs you half a second and protects you automatically. Build it now, while the stakes are low and you are practicing, so it is already a habit the day you are rushing and the document in front of you actually matters."}$lum$::jsonb, false),
  ($lum$91a64fcf-401f-5100-9483-d7d060c9b0e5$lum$::uuid, $lum$f1b7ebba-a8a7-5762-b108-b4317e2c6dba$lum$::uuid, 5, $lum$multiple_choice$lum$, $lum${"stem":"A colleague forwards you an angry email from a named client and asks you to draft a calm reply using AI. What is the safest move that still gets you the help?","options":[{"id":"a","label":"Replace the client's name and account number with placeholders like 'the client' and '[account]', then paste and ask for the draft","is_correct":true,"explanation":"Right. Stripping the identifiers keeps them in your hands while the AI still gets everything it needs to write a great calm reply. The specifics added nothing."},{"id":"b","label":"Paste the whole email, name and account number included, so the AI has full context","is_correct":false,"explanation":"That hands a real person's identifying details to a tool that may store or review them. The AI does not need the name or account number to help you sound calm."},{"id":"c","label":"Refuse to use AI at all because the email involves a real person","is_correct":false,"explanation":"That is overcautious and costs you the speed. Once you strip the identifiers, the task is perfectly safe. The skill is stripping, not avoiding."}]}$lum$::jsonb, false),
  ($lum$ba59f2be-d34a-5ea0-aebe-39cbb16bf50e$lum$::uuid, $lum$f1b7ebba-a8a7-5762-b108-b4317e2c6dba$lum$::uuid, 6, $lum$reading$lum$, $lum${"markdown":"The most common mistake is treating the chat box like a private, secure document instead of a postcard. People reason \"it is just me typing to an AI, no one else is here,\" and paste a full patient record or a contract with everyone's name on it. The fix is the mental switch: assume anything in a free tool could be stored, used for training, or read by a reviewer, and act accordingly. You do not have to stop using the tool. You just have to pause before sensitive text.\n\nThe second mistake is the opposite overcorrection, deciding AI is too risky and refusing to paste anything real at all. These people describe their task so vaguely that the answers are useless, then conclude AI does not work for their job. It works fine; they skipped the actual skill, which is generalizing. You strip the names and specifics and keep the substance. \"Maria Gonzalez, MRN 88214, CHF\" becomes \"an older patient discharged after a heart failure flare-up,\" and the AI helps just as well. Avoidance is not safety; it is just throwing away the benefit out of fear."}$lum$::jsonb, false),
  ($lum$b9d68708-d439-5bc0-96b2-e2ef67211a1d$lum$::uuid, $lum$f1b7ebba-a8a7-5762-b108-b4317e2c6dba$lum$::uuid, 7, $lum$fill_blank$lum$, $lum${"template":"The most common mistake is treating the chat box like a private, secure document instead of a {{1}}. The opposite overcorrection is refusing to paste anything real at all, which throws away the benefit; the real skill you skipped is {{2}}.","blanks":[{"id":1,"accept":["postcard","a postcard"],"ideal":"postcard"},{"id":2,"accept":["generalizing","generalising","stripping and generalizing","stripping"],"ideal":"generalizing"}],"explanation":"The reading names both mistakes: treating the box as a secure document instead of a postcard, and refusing to paste anything real instead of generalizing. The fix in both cases is to keep the substance and strip the identifiers."}$lum$::jsonb, false),
  ($lum$5af47032-89f2-58fa-a908-7bde8365ebe5$lum$::uuid, $lum$f1b7ebba-a8a7-5762-b108-b4317e2c6dba$lum$::uuid, 8, $lum$reading$lum$, $lum${"markdown":"The third mistake is half-redacting. People remove the obvious name at the top but leave a dozen other identifiers buried in the text: the account number in paragraph three, the home address in the signature, the rare diagnosis that points to one specific person, the deal size only one client could have. Redaction has to cover the whole document, not just the headline. Before you paste, reread the text hunting for every name, number, and detail that could point back to a real person or a real secret.\n\nA subtler misconception is assuming all AI tools have the same rules. They do not. A free personal account and a company-paid enterprise account can have completely different data agreements. People who learn \"AI is safe at work\" on the enterprise tool sometimes paste the same sensitive material into their personal phone app at home, where the protections do not exist. Match the material to the tool, and when in doubt about what your work tool is actually cleared to handle, ask IT rather than guessing.\n\nThe last mistake is thinking this requires legal expertise. It does not. You are not memorizing regulations. You are building one reflex: the half-second pause and the bulletin-board question before pasting anything that involves a real person or a real secret. That pause is the whole skill. Everything else is just three simple responses to it: strip it, move it to the approved tool, or leave it out."}$lum$::jsonb, false),
  ($lum$64241822-e1fe-55bb-9044-9d177a4640be$lum$::uuid, $lum$f1b7ebba-a8a7-5762-b108-b4317e2c6dba$lum$::uuid, 9, $lum$multiple_choice$lum$, $lum${"stem":"The reading describes 'half-redacting.' What does that mistake actually look like?","options":[{"id":"a","label":"Removing the obvious name at the top but leaving buried identifiers like an account number, a home address, or a tell-tale deal size","is_correct":true,"explanation":"Right. Half-redacting is catching the headline name but missing the dozen other details buried in the text. Redaction has to cover the whole document, not just the top."},{"id":"b","label":"Believing a free personal account and an enterprise account follow the exact same data rules","is_correct":false,"explanation":"That is a different mistake in the reading, the assumption that all AI tools have the same rules. Half-redacting is specifically about missing buried identifiers in the text itself."},{"id":"c","label":"Thinking you need legal expertise before you can safely paste anything","is_correct":false,"explanation":"That is the last mistake the reading names, not half-redacting. Half-redacting is about leaving identifiers buried in the document after removing the obvious name."}]}$lum$::jsonb, false),
  ($lum$1bf32b08-8d6b-5af5-8cf0-bbfef863c851$lum$::uuid, $lum$f1b7ebba-a8a7-5762-b108-b4317e2c6dba$lum$::uuid, 10, $lum$before_after$lum$, $lum${"question":"A paralegal wants AI help summarizing a settlement for a client. Here is the unsafe paste versus the safe one that gets the same quality.","before_prompt":"Summarize this settlement for our client in plain English: Henderson v. Brightway Logistics, plaintiff Maria Henderson (SSN 555-12-9988), settled for $47,500, payable by Brightway Logistics within 30 days, releasing all claims related to the warehouse injury on 8/3/2024.","after_prompt":"I have a personal injury settlement agreement and need a plain-English summary letter for the client. Here are the terms with identifiers replaced: the plaintiff settled with the defendant company for [settlement amount], payable within 30 days, releasing all claims related to a workplace injury. Write a warm, clear summary letter at about an eighth-grade reading level.","changes":["Removed the real names, the SSN, and the exact dollar figure, so no identifying or sensitive data leaves the firm","Replaced the specifics with placeholders ('the plaintiff', '[settlement amount]') that the paralegal can swap back in privately after the AI drafts the letter","Kept the substance the AI actually needs (personal injury, 30-day payment, release of claims) so the summary is just as accurate","Added audience and tone (warm, eighth-grade reading level) so the draft fits a stressed, non-lawyer client"]}$lum$::jsonb, true),
  ($lum$8750876f-3bcf-5c13-ba1d-d3f12bcb2792$lum$::uuid, $lum$f1b7ebba-a8a7-5762-b108-b4317e2c6dba$lum$::uuid, 11, $lum$multiple_choice$lum$, $lum${"stem":"After stripping the names and the SSN, the paralegal kept 'personal injury, settled, payable within 30 days, releasing all claims.' Why keep those details?","options":[{"id":"a","label":"They are the substance the AI needs to write an accurate summary, and none of them identify a real person","is_correct":true,"explanation":"Exactly. The goal is to remove identifiers and secrets, not the substance. These terms describe the deal without pointing to anyone, so the draft stays accurate and safe."},{"id":"b","label":"You should actually remove those too, to be as cautious as possible","is_correct":false,"explanation":"Stripping the substance would leave the AI nothing to work with, and the summary would be useless. The skill is removing identifiers, not removing everything."},{"id":"c","label":"It does not matter what you keep once the name is gone","is_correct":false,"explanation":"It does matter. Half-redacting is a real risk, but here the kept details carry no identifiers, so they are safe and necessary. You have to judge each detail, not stop at the name."}]}$lum$::jsonb, false),
  ($lum$866e29ef-706b-5834-a868-f17bfca84e61$lum$::uuid, $lum$f1b7ebba-a8a7-5762-b108-b4317e2c6dba$lum$::uuid, 12, $lum$mini_project$lum$, $lum${"brief":"Take one real document from your actual work this week that you genuinely want AI's help with, and turn it into a safe-to-paste version.","parts":[{"id":"1","prompt":"Run the three-part check on it: could it identify a real person, is it confidential or under an agreement, would a leak cause harm? Write down each yes."},{"id":"2","prompt":"For every yes, create a stripped version: swap names for roles (\"the client,\" \"the patient,\" \"the employee\"), swap numbers for placeholders (\"[amount],\" \"[account]\"), and reread the whole thing to catch the buried identifiers most people miss."},{"id":"3","prompt":"Decide your move for this specific document: paste the stripped version into a public tool, use your work-approved tool, or keep one piece out and do it yourself."}]}$lum$::jsonb, false),
  ($lum$14320fbd-716a-5937-83c9-760c030c7ff6$lum$::uuid, $lum$6dd48206-2fd2-5f79-873a-be46f4172f6e$lum$::uuid, 0, $lum$reading$lum$, $lum${"markdown":"Once you're past your first few chats, three habits do most of the heavy lifting. They're simple, they stack, and almost nobody does all three at first. Build them in now and everything downstream gets easier.\n\n**1. Paste the actual material.** The single biggest upgrade to your results: stop describing your document and just paste it in. Don't say \"I have a long email from a client who's unhappy about a delay\" when you can paste the email itself. The AI can only work with what it can see. Real text in means specific, grounded answers out, instead of generic guesses about what your situation might be. Reports, emails, notes, a job posting, a contract clause: paste first, ask second.\n\n**2. Give it a role.** One short line at the front of your request reshapes the entire answer. \"You are a careful copy editor.\" \"Act as a skeptical financial reviewer.\" \"You're a friendly customer support rep.\" A role tells the AI what perspective, vocabulary, and priorities to bring. \"Edit this\" gets you a generic pass; \"you are a copy editor focused on clarity and cutting filler, edit this\" gets you a focused, professional one. It costs you five words.\n\n**3. Save the outputs that work.** When AI nails something, don't let it vanish into a scroll of old chats. Copy the prompt that produced it into a note, a doc, anywhere you'll find it again. The request that wrote a great status update last week will write this week's too, with small edits. Over a month you build a personal library of prompts that just work, and you stop reinventing the same instruction every time. This is how AI compounds instead of resetting every session.\n\n**Stacked together** they look like this: paste the messy meeting notes, prefix \"you are an executive assistant writing a crisp recap for busy leaders,\" get a clean summary, and save that prompt as your \"meeting recap\" template. Three habits, one smooth workflow, and you've just built something reusable."}$lum$::jsonb, false),
  ($lum$a7ccb3e5-65ee-5e16-9133-f5f8ad57bc3c$lum$::uuid, $lum$6dd48206-2fd2-5f79-873a-be46f4172f6e$lum$::uuid, 1, $lum$try_it_live$lum$, $lum${"instructions":"Practice all three habits in one request. Imagine you have a document to work with (or use the sample). Write a prompt that (1) assigns the AI a clear role, (2) references the pasted material, and (3) asks for an output clean enough to save and reuse. Sample document: messy bullet-point notes from a team meeting.","system_prompt":"You are a coach teaching a beginner three AI habits: paste real material, assign a role, and produce reusable output. Given a task, write an example prompt that opens with a specific role, clearly works from pasted material, and requests a clean, reusable result. Plain language, no jargon, no em dashes.","ideal_output":"You are an executive assistant who writes crisp meeting recaps for busy leaders. Here are my raw notes from today's team meeting: [paste notes]. Turn them into a recap with three sections: Decisions, Action items with owners, and Open questions. Keep it under 150 words and use plain language so I can paste it straight into an email.","input_placeholder":"You are a [role]. Here is my [document]: [paste]. Turn it into..."}$lum$::jsonb, false),
  ($lum$fca04bcb-9047-5036-803b-1fbc8f732ccf$lum$::uuid, $lum$db25e28a-6ea6-5eb2-8e40-e082b37b153f$lum$::uuid, 0, $lum$reading$lum$, $lum${"markdown":"Open a fresh chat with ChatGPT or Claude and it has no idea who you are. It does not know you are a school nurse, that your notes go into a student health record, that your district makes you write at a sixth-grade reading level, or that you hate the word \"utilize.\" So the first thing you do, every time, is explain all of that again. Then you ask your actual question. You have been writing the same paragraph of background for months without realizing it.\n\nThere is a place to put that background once. In ChatGPT it lives in Settings under \"Personalization,\" in a feature called Custom Instructions, plus a Memory toggle that lets the model save facts about you over time. In Claude it lives in Settings under \"Profile,\" where you can describe yourself and set your default response preferences. Different names, same idea: a permanent note the AI reads silently before it reads anything you type. You write it once and it follows you into every new conversation.\n\nThink of it like the standing instructions you would give a new assistant on day one. You would not re-explain your job to your assistant every morning. You would tell them once: here is my role, here is who we serve, here is how I like things written, here is what to never do. Custom instructions are that day-one briefing, except the assistant never forgets and never gets tired of it.\n\nHere is exactly what to put in there. Three pieces."}$lum$::jsonb, false),
  ($lum$5f69006d-3e61-533a-825f-9736a01f719f$lum$::uuid, $lum$db25e28a-6ea6-5eb2-8e40-e082b37b153f$lum$::uuid, 1, $lum$multiple_choice$lum$, $lum${"stem":"Where does ChatGPT keep this permanent background note about you?","options":[{"id":"a","label":"In a new chat window you have to reopen each morning","is_correct":false,"explanation":"No. The whole point is that you do not reopen it each time. It lives in Settings and is read silently before every conversation."},{"id":"b","label":"In Settings under 'Personalization,' in a feature called Custom Instructions","is_correct":true,"explanation":"Right. In ChatGPT it lives in Settings under 'Personalization' as Custom Instructions, with a Memory toggle that can save facts over time."},{"id":"c","label":"Nowhere; you have to retype your background at the start of every chat","is_correct":false,"explanation":"That is exactly the habit this lesson ends. There is a settings box that holds the background once so you stop retyping it."}]}$lum$::jsonb, false),
  ($lum$4a8f21cc-14c4-5147-b4f6-9925c6e4ec0f$lum$::uuid, $lum$db25e28a-6ea6-5eb2-8e40-e082b37b153f$lum$::uuid, 2, $lum$reading$lum$, $lum${"markdown":"First, who you are and who you serve. Be specific about the job, not vague about the industry. A paralegal at a small family-law firm should write: \"I am a paralegal at a three-attorney family law firm in Ohio. I draft client intake summaries, discovery requests, and correspondence. My readers are attorneys who want facts fast, and sometimes clients who are stressed and not legally trained.\" That one paragraph means the AI stops giving you generic \"legal\" answers and starts matching your actual workload.\n\nSecond, how you want answers written. This is where you stop fighting the AI's default habits. An office manager who is sick of bloated, flowery replies should write: \"Be direct and skip the preamble. Do not open with 'Certainly!' or 'Great question.' Use short paragraphs and bullet points for any list. Keep it to plain English at about an eighth-grade level. If you are not sure about a fact, say so instead of guessing.\" Every one of those lines is a habit you would otherwise have to correct by hand in every single chat.\n\nThird, your recurring context, meaning the stuff you find yourself typing again and again. A high school history teacher might add: \"I teach 11th grade U.S. History to about 140 students across five sections. My state standards are Texas TEKS. I differentiate for students reading below grade level. When I ask for worksheets or quizzes, default to that audience unless I say otherwise.\" Now \"make me a quiz on the New Deal\" produces something usable on the first try, because the AI already knows the grade, the subject, and the standards."}$lum$::jsonb, false),
  ($lum$3dd7c523-cb44-5756-b20d-e9b09daeae3b$lum$::uuid, $lum$db25e28a-6ea6-5eb2-8e40-e082b37b153f$lum$::uuid, 3, $lum$fill_blank$lum$, $lum${"template":"The first piece to include is who you are and who you serve, and it should be specific about the {{1}}, not vague about the {{2}}.","blanks":[{"id":1,"accept":["job","role","your job","your role"],"ideal":"job"},{"id":2,"accept":["industry","field","sector"],"ideal":"industry"}],"explanation":"The reading says to be specific about the job, not vague about the industry. 'Healthcare' or 'legal' is too broad; naming the exact role is what makes the AI match your real workload."}$lum$::jsonb, false),
  ($lum$4fef087b-916e-5538-b818-8cb8bf7a6a0c$lum$::uuid, $lum$db25e28a-6ea6-5eb2-8e40-e082b37b153f$lum$::uuid, 4, $lum$reading$lum$, $lum${"markdown":"Here is a full example for an HR manager, start to finish, the kind you could paste in today:\n\n\"I am an HR manager at a 200-person manufacturing company. I handle hiring, onboarding, policy questions, and difficult employee conversations. My readers are usually managers who are not HR experts, or employees who may be upset, so tone matters a lot. Write in a warm but professional voice. Be clear and brief. Never give me legal advice as if it were settled law; flag anything that an employment lawyer should review. Use bullet points for steps. Avoid corporate jargon like 'synergy' or 'circle back.'\"\n\nNotice what that does. The next time this person types \"help me write a message to a manager whose employee is always late,\" the AI already knows the audience is a non-expert manager, the tone should be warm, the format should be steps, and anything legally risky needs a flag. The HR manager just saved the four sentences of setup they used to write every time.\n\nOne important boundary: custom instructions are for who you are, not for one specific task. Do not put \"write me a quiz about the Civil War\" in there, because that would warp every future answer. Put the permanent facts: your role, your audience, your style, your standards. Save the one-off requests for the actual chat. And if your tool has a Memory feature that learns over time, glance at it occasionally to make sure it has not saved something stale, like a project that ended six months ago.\n\nFifteen minutes of setup. Then every conversation for the next year starts with the AI already knowing your job. That is the highest-return fifteen minutes you will spend on this tool."}$lum$::jsonb, false),
  ($lum$a01f6194-76e4-568e-9a6d-b3b317a58881$lum$::uuid, $lum$db25e28a-6ea6-5eb2-8e40-e082b37b153f$lum$::uuid, 5, $lum$multiple_choice$lum$, $lum${"stem":"What belongs in your custom instructions (or saved memory), as opposed to a normal chat message?","options":[{"id":"a","label":"The permanent facts about you: your role, who you serve, how you want answers written, and your recurring standards","is_correct":true,"explanation":"Right. Custom instructions are a day-one briefing that should be true in every conversation, so they hold your identity, audience, and style preferences."},{"id":"b","label":"The specific task you need done right now, like 'write a quiz on the New Deal'","is_correct":false,"explanation":"A one-off task does not belong there. If you put a single task in custom instructions, it warps every future answer. Keep tasks in the actual chat."},{"id":"c","label":"Nothing important; it is just a name and a greeting preference","is_correct":false,"explanation":"It is much more than a greeting. Used well, it carries your job, your audience, your tone, and your standards into every chat automatically."}]}$lum$::jsonb, false),
  ($lum$9d375573-1baf-575e-a4ac-12660f718dd4$lum$::uuid, $lum$db25e28a-6ea6-5eb2-8e40-e082b37b153f$lum$::uuid, 6, $lum$reading$lum$, $lum${"markdown":"Most people who try custom instructions make one of three predictable mistakes, and each one quietly cancels the benefit.\n\nThe first mistake is being vague. People write things like \"I work in healthcare\" or \"make answers good.\" That is so general the AI cannot do anything useful with it. \"Healthcare\" could mean a surgeon, a billing clerk, or a hospice chaplain, and \"good\" means nothing at all. The fix is to write as if you were describing your job to a temp who starts tomorrow. Not \"I work in healthcare\" but \"I am a charge nurse on a medical-surgical floor; I write shift handoff notes and patient education sheets.\" Specificity is the entire point. If your instructions would fit fifty different jobs, they are too thin.\n\nThe second mistake is stuffing a single task in there. Someone gets excited, writes \"always respond as a poem\" or \"I am working on the Henderson account,\" and forgets about it. A week later every answer is weirdly poetic, or every answer assumes a project that wrapped up. Remember the rule: custom instructions are for who you are, not what you need today. If you catch the AI behaving strangely across unrelated chats, the first place to check is your instructions for a leftover task."}$lum$::jsonb, false),
  ($lum$b79764cb-fddc-57ec-9bb1-dded9ae1ab30$lum$::uuid, $lum$db25e28a-6ea6-5eb2-8e40-e082b37b153f$lum$::uuid, 7, $lum$multiple_choice$lum$, $lum${"stem":"According to the reading, what is the fix for vague instructions like 'I work in healthcare'?","options":[{"id":"a","label":"Leave them broad on purpose so the AI can help with any topic","is_correct":false,"explanation":"Broad is the trap. If your instructions would fit fifty different jobs, they are too thin and the AI cannot do anything useful with them."},{"id":"b","label":"Add the single task you need done today instead","is_correct":false,"explanation":"That is a different mistake. Stuffing one task in there warps future answers. The fix for vagueness is specificity about your role, not a task."},{"id":"c","label":"Write as if describing your job to a temp who starts tomorrow, naming your exact role and the documents you produce","is_correct":true,"explanation":"Exactly. The reading says to be specific, like 'I am a charge nurse on a medical-surgical floor who writes shift handoff notes.' Specificity is the entire point."}]}$lum$::jsonb, false),
  ($lum$d1d06c2c-58c3-548e-bde0-ff288460be9e$lum$::uuid, $lum$db25e28a-6ea6-5eb2-8e40-e082b37b153f$lum$::uuid, 8, $lum$reading$lum$, $lum${"markdown":"The third mistake is the opposite problem: people fill it in once and never look again, even after their job changes. The teacher who switched from 9th grade to 11th grade still has \"I teach 9th grade\" sitting in there, so every quiz comes out at the wrong level. Treat your instructions like a job description that needs an occasional update. When your role, audience, or standards change, spend two minutes editing the box.\n\nThere is also a quieter misconception worth naming. Some people assume custom instructions are private and permanent in a way they are not. They are tied to your account and read by the model, which is fine for \"I am a paralegal who prefers bullet points.\" It is not the place for secrets. Do not paste a client's real name, a patient identifier, a password, or anything confidential into the settings box, the same way you would not write those things on a sticky note on your monitor. Keep it to professional context, not sensitive data.\n\nThe instinct to skip all of this entirely is the biggest mistake of all. People think it is an advanced feature for power users. It is the opposite: it is the lowest-effort upgrade available, because you do the work once and benefit on every chat afterward. The five minutes you spend re-explaining your job each day adds up to hours a month. Filling in the box ends that tax permanently. Vague is the trap, stale is the slow leak, and skipping it is leaving the easiest win on the table."}$lum$::jsonb, false),
  ($lum$257c8f6f-c341-5fe9-ad8a-d4e870365e06$lum$::uuid, $lum$db25e28a-6ea6-5eb2-8e40-e082b37b153f$lum$::uuid, 9, $lum$multiple_choice$lum$, $lum${"stem":"Your quizzes keep coming out at the wrong grade level even though you set up custom instructions months ago. What is the most likely problem?","options":[{"id":"a","label":"Your instructions are stale; they still describe the grade you used to teach, so update them","is_correct":true,"explanation":"Correct. Custom instructions are not self-updating. When your role or audience changes, you have to edit the box, or it keeps steering answers toward your old situation."},{"id":"b","label":"Custom instructions do not actually affect answers, so it is just coincidence","is_correct":false,"explanation":"They do affect answers; that is the whole point. Stale instructions affect them in the wrong direction, which is exactly what is happening here."},{"id":"c","label":"You need to re-explain your grade level in every single chat anyway","is_correct":false,"explanation":"That defeats the purpose. The fix is a two-minute edit to the instructions, after which every future chat is correct without re-explaining."}]}$lum$::jsonb, false),
  ($lum$30481dba-3cf8-549b-938a-71f273697b63$lum$::uuid, $lum$db25e28a-6ea6-5eb2-8e40-e082b37b153f$lum$::uuid, 10, $lum$before_after$lum$, $lum${"question":"An office manager wants to set up custom instructions. Here is what they almost wrote versus what actually works.","before_prompt":"I work in an office. Please give me good, helpful answers and be professional.","after_prompt":"I am the office manager for a 40-person architecture firm. I handle scheduling, vendor emails, internal announcements, and policy reminders. My readers are busy architects and our front-desk staff. Write in a friendly, clear, professional tone. Skip filler openers like 'Certainly.' Use short paragraphs and bullet points for any steps or lists. Keep language plain, no corporate jargon. When you draft an email for me, give me a subject line too. If something might need owner or HR sign-off, flag it.","changes":["Names the exact role and company so answers stop being generic 'office' advice and start matching real tasks like vendor emails and announcements","Describes the actual readers (architects and front-desk staff) so tone and reading level fit them","Sets concrete style rules (no filler openers, bullet points, subject lines) that would otherwise have to be corrected by hand in every chat","Adds a standing safety flag for anything needing sign-off, so the AI prompts caution without being asked each time"]}$lum$::jsonb, true),
  ($lum$ccfebff4-c6ec-551f-bff6-de31934e24e0$lum$::uuid, $lum$db25e28a-6ea6-5eb2-8e40-e082b37b153f$lum$::uuid, 11, $lum$multiple_choice$lum$, $lum${"stem":"Why is the office manager's second version so much more useful as a permanent instruction?","options":[{"id":"a","label":"It names the specific role, the real readers, and concrete style rules, so every future chat starts already tuned to that job","is_correct":true,"explanation":"Exactly. Specificity about role, audience, and style is what turns a generic note into a true day-one briefing that improves every answer."},{"id":"b","label":"It is longer, and longer instructions are always better","is_correct":false,"explanation":"Length is not the point. A long but vague note would not help. The second version works because it is specific and actionable, not merely longer."},{"id":"c","label":"It includes the firm's confidential client list, giving the AI more context","is_correct":false,"explanation":"It does not, and it should not. Confidential data does not belong in the settings box. The strength comes from role and style detail, not secrets."}]}$lum$::jsonb, false),
  ($lum$3055a92d-09f3-5696-8f3a-9977328f4f3b$lum$::uuid, $lum$db25e28a-6ea6-5eb2-8e40-e082b37b153f$lum$::uuid, 12, $lum$mini_project$lum$, $lum${"brief":"Write and save your own custom instructions today, using your real job. Open the settings: in ChatGPT go to Settings, then Personalization, then Custom Instructions; in Claude go to Settings, then Profile. Fill in three things in your own words.","parts":[{"id":"1","prompt":"Who you are and who you serve: your exact role, the kinds of documents you produce, and who reads them. Be specific enough that the description would not fit a different job."},{"id":"2","prompt":"How you want answers written: tone, reading level, format preferences, filler words to avoid, and one thing you always want flagged for caution."},{"id":"3","prompt":"Your recurring context: the facts you find yourself re-typing in chats, like your grade level, your standards, your audience, or your company size."}]}$lum$::jsonb, false),
  ($lum$a1b38514-21a9-5b4f-9b98-10419e46a02b$lum$::uuid, $lum$6343674a-601c-5d2d-92c6-60fe3784cb36$lum$::uuid, 0, $lum$reading$lum$, $lum${"markdown":"There is a habit almost everyone brings to AI from years of using Google: you type the shortest possible thing and expect the tool to figure out the rest. Search engines trained us to do this. AI is not a search engine, and that habit is the single biggest reason people get mediocre results.\n\nHere is the shift. A prompt is a question. A brief is a set of instructions. The difference is the same as the difference between turning to a brand-new assistant and saying \"write the newsletter\" versus sitting them down and explaining what the newsletter is for, who reads it, what tone the company uses, and what you do not want in it. With the first version you will get something generic and spend an hour fixing it. With the second you will get something close to right on the first try. The AI is exactly that assistant. It is capable, it is fast, and it knows nothing about your specific situation until you tell it.\n\nA good brief answers six things a competent assistant would ask before they started. You do not need a form. You just need to cover them."}$lum$::jsonb, false),
  ($lum$f8289e52-e98a-50b8-a3cd-3f8fcf44749b$lum$::uuid, $lum$6343674a-601c-5d2d-92c6-60fe3784cb36$lum$::uuid, 1, $lum$multiple_choice$lum$, $lum${"stem":"According to the reading, why does the Google habit of typing the shortest possible thing tend to produce mediocre AI results?","options":[{"id":"a","label":"AI is slower than a search engine, so short inputs waste its speed","is_correct":false,"explanation":"The reading actually calls the AI fast. Speed is not the issue. The issue is that a search-style short input does not tell the AI about your specific situation."},{"id":"b","label":"Search engines give better answers than AI, so the habit carries over poorly","is_correct":false,"explanation":"The reading does not rank the two tools that way. The point is that AI is not a search engine, so the search habit of typing the shortest thing does not fit it."},{"id":"c","label":"AI is not a search engine, and a one-line input leaves it knowing nothing about your situation","is_correct":true,"explanation":"Correct. Search engines trained us to type the shortest possible thing, but the AI knows nothing about your specific situation until you tell it, so the short input leaves it guessing."}]}$lum$::jsonb, false),
  ($lum$392188ef-a593-56b4-9f3f-2a8042b8710b$lum$::uuid, $lum$6343674a-601c-5d2d-92c6-60fe3784cb36$lum$::uuid, 2, $lum$reading$lum$, $lum${"markdown":"**Context:** What is the situation? What has already been decided? \"We are a 30-person nonprofit that runs an after-school reading program, and we just got a $50,000 grant we want to announce to our donor list\" gives the AI a world to work in. Without it, the AI is writing into a void.\n\n**Goal:** What is this supposed to accomplish? \"I want donors to feel proud they supported us, and I want to set up a future ask\" is a goal. When the AI knows what success looks like, it makes better choices about what to emphasize.\n\n**Audience:** Who reads this, and what do they already know? Writing for longtime donors who know your program is completely different from writing for strangers. \"These are donors who have given for at least two years and already know our staff by name\" changes every line.\n\n**Constraints:** What are the hard rules? Length, deadline, tone, and what must not appear. \"Under 200 words, warm but not gushing, do not mention the exact salary figures the grant covers.\"\n\n**Format:** What shape should it take? An email with a subject line, three social posts, a one-page letter. Say it, or the AI will guess.\n\n**Examples:** If you have a past piece you liked, paste it. \"Match the voice of this newsletter we sent in March: [paste]\" is the single fastest way to get your own tone back out of the AI."}$lum$::jsonb, false),
  ($lum$6f8ace77-dde0-5250-ba3e-730fbbc6eb9f$lum$::uuid, $lum$6343674a-601c-5d2d-92c6-60fe3784cb36$lum$::uuid, 3, $lum$multiple_choice$lum$, $lum${"stem":"An HR manager writes: \"Draft a message to the team about the new remote-work policy.\" What is the core reason this is a prompt and not a brief?","options":[{"id":"a","label":"It is too short; briefs must always be at least a paragraph long","is_correct":false,"explanation":"Length is not the rule. A brief can be short. The issue is that it leaves out the information the AI actually needs, like what the policy says and who reads it."},{"id":"b","label":"It names a topic but gives no context, goal, audience, constraints, or format","is_correct":true,"explanation":"Correct. It tells the AI the subject and nothing else. The AI does not know what the policy actually is, who it is for, what tone fits, or what shape the message should take, so it has to guess all of it."},{"id":"c","label":"It uses the word \"draft\" instead of \"write\"","is_correct":false,"explanation":"The verb is not the problem. The problem is the missing context, goal, audience, constraints, and format that a brief would supply."}]}$lum$::jsonb, false),
  ($lum$ea0f427b-417b-56b6-bea9-04bb138ce78d$lum$::uuid, $lum$6343674a-601c-5d2d-92c6-60fe3784cb36$lum$::uuid, 4, $lum$reading$lum$, $lum${"markdown":"Let me show you the gap with a real example. A school office administrator needs to tell parents that the school is switching to a new pickup system. The prompt version is \"write an email about the new pickup procedure.\" The AI returns a stiff, generic notice that misses every detail that matters, because it has none of them. It pads the whole thing with phrases like \"we are committed to student safety\" that say nothing. The model did not fail. It did exactly what you asked: write about a topic with no facts attached.\n\nThe brief version reads like this: \"I am the front-office administrator at an elementary school with about 400 students. Write an email to all parents announcing that, starting October 6th, afternoon pickup moves from the front circle to the back lot off Maple Street, and that every car needs the new numbered tag we mailed home last week. The goal is to prevent confusion and traffic backups on day one. Parents are busy and skim, so put the date, the new location, and the tag requirement near the top. Keep it under 180 words, friendly but clear, and do not bury the key change in a long intro. Format it as an email with a subject line, and end with a line telling parents to reply if they did not receive a tag.\" That brief produces a sendable email in one shot. The prompt produces a draft that needs three rounds of you typing \"no, also mention the tags\" and \"make it shorter.\"\n\nCount what the brief did. It gave the role, the situation, the exact change, the goal, the audience behavior, the constraints, the format, and a closing action. It took ninety seconds to write. The prompt took five seconds and cost twenty minutes of back-and-forth. Briefing is slower to start and faster to finish.\n\nHere is a second example. A freelance bookkeeper follows up with a client sixty days late on an invoice. The prompt \"write a payment reminder\" gives back a cold form letter that damages the relationship. The brief reads: \"I am a freelance bookkeeper. Write a follow-up email to a long-term client, a bakery owner named Dana, whose invoice for $1,200 is now sixty days past due. We have worked together three years and I want to keep things warm, so the tone should be friendly and assume good faith. The goal is to get it paid within a week without making Dana feel cornered. Mention I can split it into two payments if cash flow is tight. Keep it under 120 words, sign it from Maria, and do not use the words 'overdue' or 'failure to pay.'\" That brief produces an email Dana would respond to. The extra lines each remove a guess: the history sets the warmth, the payment split gives an easy yes, and the banned words steer the AI off the backfiring tone.\n\nThe mental move that makes this easy: before you type, picture handing the task to a smart new hire on their first day. Everything you would explain to them belongs in your brief. If they would have to ask \"who is this for?\" or \"how long should it be?\" then your brief is missing a piece. The AI will never ask a clarifying question on its own. It fills the gap with the most average answer, so answer the questions in advance."}$lum$::jsonb, false),
  ($lum$70989c28-9205-5d59-8394-48719fe3bbbf$lum$::uuid, $lum$6343674a-601c-5d2d-92c6-60fe3784cb36$lum$::uuid, 5, $lum$multiple_choice$lum$, $lum${"stem":"In the school pickup example, why did the prompt version (\"write an email about the new pickup procedure\") produce a stiff, generic notice?","options":[{"id":"a","label":"The AI failed to understand the request and made an error","is_correct":false,"explanation":"The reading is explicit that the model did not fail. It did exactly what was asked: write about a topic with no facts attached."},{"id":"b","label":"The prompt gave it a topic but none of the facts that matter, so it had nothing to work with","is_correct":true,"explanation":"Correct. The AI returns a generic notice that misses every detail because it has none of them, and it pads with empty phrases like \"we are committed to student safety.\""},{"id":"c","label":"The administrator used the wrong tone in the prompt","is_correct":false,"explanation":"Tone was not the issue. The problem was that the prompt attached no facts, so the AI wrote about a topic with nothing concrete to say."}]}$lum$::jsonb, false),
  ($lum$32d9249e-4a49-5fc6-b9a2-622a4a06433e$lum$::uuid, $lum$6343674a-601c-5d2d-92c6-60fe3784cb36$lum$::uuid, 6, $lum$reading$lum$, $lum${"markdown":"When people first try to write briefs instead of prompts, a handful of mistakes keep them stuck. Here is what goes wrong and how to fix each one.\n\n**Mistake 1: Most people add detail but forget the goal.** They will describe the situation in depth and still never say what the message is supposed to accomplish. A brief that explains the whole grant but never says \"I want donors to feel proud and set up a future ask\" leaves the AI guessing about what to emphasize. Always answer the question \"what do I want the reader to think, feel, or do after this?\" That one sentence steers everything else.\n\n**Mistake 2: People describe the audience as themselves.** They write for the version of the reader who already knows everything they know. A teacher writes a parent email full of school jargon because the jargon is obvious to her. State who the reader actually is and what they do not know. \"Parents who have never used our online portal\" is worth more than three sentences of instructions.\n\n**Mistake 3: People list what they want but never what they do not want.** Rejection criteria are half of a good brief and the half everyone skips. \"Do not start with 'We are excited to announce.' Do not use corporate jargon. Do not exceed 150 words.\" These negative rules are often more powerful than the positive ones, because they cut off the AI's most common bad habits before they appear."}$lum$::jsonb, false),
  ($lum$8825e9fa-2196-530b-a110-f3b59c9464bf$lum$::uuid, $lum$6343674a-601c-5d2d-92c6-60fe3784cb36$lum$::uuid, 7, $lum$multiple_choice$lum$, $lum${"stem":"The reading says one common mistake is describing the audience \"as themselves.\" What does that look like in practice?","options":[{"id":"a","label":"Writing for the reader as if they already know everything you know, like a teacher using school jargon parents will not follow","is_correct":true,"explanation":"Correct. People write for the version of the reader who knows everything they know. The fix is to state who the reader actually is and what they do not know."},{"id":"b","label":"Forgetting to state what the message should accomplish","is_correct":false,"explanation":"That is the goal mistake, described separately. Describing the audience as themselves is about assuming the reader already knows what you know."},{"id":"c","label":"Listing what you want but never what you do not want","is_correct":false,"explanation":"That is the missing rejection-criteria mistake. The audience mistake is writing for a reader who supposedly already knows everything you do."}]}$lum$::jsonb, false),
  ($lum$4db836b7-608e-54b7-928a-fa5370f22ef2$lum$::uuid, $lum$6343674a-601c-5d2d-92c6-60fe3784cb36$lum$::uuid, 8, $lum$reading$lum$, $lum${"markdown":"**Mistake 4: People treat the brief as one-and-done and never reuse it.** They write a careful brief for the monthly newsletter, get a great result, and then start from scratch the next month. Save your good briefs. The context, audience, and constraints rarely change. Next time you only swap in the new content and the AI gives you the same quality with a tenth of the effort. Keep a simple notes file with your three or four best briefs in it. A volunteer coordinator who saves the brief for \"monthly update to our 200 volunteers\" will reuse the same role, audience description, and tone rules every single month, and only paste in the new events. The first brief takes two minutes. Every reuse after that takes ten seconds.\n\n**Mistake 5: People stack so many constraints that they contradict each other.** A brief that says \"make it warm and personal, keep it strictly professional, be funny, and stay formal\" gives the AI four steering wheels pulling in different directions, and it will pick one at random. If you ask for \"under 80 words\" but also \"explain the full refund policy in detail,\" you have set a trap the AI cannot escape. When a result feels muddled, check whether your own instructions fight each other. Pick the constraint that matters most and let the smaller ones go.\n\nThe thread connecting all four is that a brief is not about writing more words. It is about answering the questions a real assistant would ask. Goal, audience, and what to avoid are the three that people most often leave out, and they are the three that matter most. When an AI answer disappoints you, do not blame the model. Reread your brief and find which question you never answered."}$lum$::jsonb, false),
  ($lum$2fb98d7e-3516-54ad-b67d-36c468ec6829$lum$::uuid, $lum$6343674a-601c-5d2d-92c6-60fe3784cb36$lum$::uuid, 9, $lum$fill_blank$lum$, $lum${"template":"The three parts of a brief that people most often skip are the {{1}} (what the message should accomplish), the real {{2}} (who reads it and what they do not know), and the {{3}} that tell the AI what to avoid.","blanks":[{"id":"1","accept":["goal","objective","purpose"],"ideal":"goal"},{"id":"2","accept":["audience","reader","readers"],"ideal":"audience"},{"id":"3","accept":["rejection criteria","constraints","negative rules","rules"],"ideal":"rejection criteria"}],"explanation":"A brief answers the questions a capable assistant would ask. Goal, audience, and what to avoid are the ones most people leave out, and they are the ones that change the output most."}$lum$::jsonb, false),
  ($lum$48fe8ed4-fdb5-5bd1-8dd5-dea08668f1bd$lum$::uuid, $lum$6343674a-601c-5d2d-92c6-60fe3784cb36$lum$::uuid, 10, $lum$try_it_live$lum$, $lum${"instructions":"Take this thin prompt and rewrite it as a full brief. Cover context, goal, audience, constraints, and format. The prompt is: \"Write a reminder email about the team meeting.\" Imagine you are an office manager whose Thursday 2pm planning meeting keeps getting low attendance.","system_prompt":"You are a writing coach who helps people turn one-line prompts into complete briefs. When given a thin prompt, do not write the final email. Instead, rewrite the request as a proper brief that covers context, goal, audience, constraints, and format, and briefly point out what each added part contributes.","ideal_output":"I am the office manager at a 25-person agency. Write a reminder email about our weekly planning meeting this Thursday at 2pm in the main conference room. Context: attendance has been low the last three weeks and people say they forget. Goal: get everyone to actually show up, without sounding like a scolding. Audience: busy account and design staff who skim email. Constraints: under 100 words, friendly and light, mention that we will cover the new client onboarding and that coffee will be there, and do not guilt-trip anyone. Format: an email with a clear subject line.","input_placeholder":"I am a [role]. Write [task]. Context... Goal... Audience... Constraints... Format..."}$lum$::jsonb, true),
  ($lum$e1a2298c-7a10-5635-8d07-43389e012f5b$lum$::uuid, $lum$6343674a-601c-5d2d-92c6-60fe3784cb36$lum$::uuid, 11, $lum$multiple_choice$lum$, $lum${"stem":"You wrote a detailed brief with full context, audience, and format, but the AI still returned something that opened with \"We are thrilled to announce\" and ran 280 words when you wanted 120. What did your brief most likely leave out?","options":[{"id":"a","label":"Rejection criteria and length constraints","is_correct":true,"explanation":"Right. A brief that never says \"under 120 words\" and \"do not open with an announcement cliche\" leaves those exact gaps. Telling the AI what to avoid is as important as telling it what to do."},{"id":"b","label":"More context about the company","is_correct":false,"explanation":"The question says context was already full. Adding more background would not have capped the length or stopped the cliche opener. That takes explicit constraints."},{"id":"c","label":"A clearer role for the AI to play","is_correct":false,"explanation":"The role was not the gap. The length and the cliche opener are controlled by constraints and rejection criteria, which were the missing pieces."}]}$lum$::jsonb, false),
  ($lum$5b693bb8-1be8-5d23-b43c-c349f5325c2d$lum$::uuid, $lum$6343674a-601c-5d2d-92c6-60fe3784cb36$lum$::uuid, 12, $lum$mini_project$lum$, $lum${"brief":"Find the next real piece of writing on your to-do list: an email, an announcement, a summary, a notice, anything you actually have to send this week. Instead of typing a one-line prompt, write a full brief for it.","parts":[{"id":"1","prompt":"Write your context and goal: the situation, what has already been decided, and what you want the reader to think, feel, or do afterward."},{"id":"2","prompt":"Write your audience and constraints: who reads this and what they do not already know, plus the hard rules on length, tone, deadline, and anything that must not appear."},{"id":"3","prompt":"Write your format and one rejection criterion: the shape you want (email with subject line, bullets, short message) and at least one clear \"do not do this.\""},{"id":"4","prompt":"Run the brief, then save it in a notes file. Next time you write something similar, reuse the brief and only swap the new content."}]}$lum$::jsonb, false),
  ($lum$d9bca4de-908f-5293-84b8-9ed6fce1c12f$lum$::uuid, $lum$3ac195ba-ec6e-5dab-80bd-1a0aae116991$lum$::uuid, 0, $lum$reading$lum$, $lum${"markdown":"Most people talk to AI the way they talk to a search engine. They type a few words, hit enter, and hope. Then the answer comes back generic and bland, and they decide AI just is not that smart. The problem is almost never the AI. The problem is that you handed it a topic when it needed a frame.\n\nFraming means setting up the request before you ask for the thing. It takes about ten seconds and it works every single time. There are exactly three steps, and once you learn them you will use them for the rest of your career.\n\n**Step 1: Give it a role and your context.** Tell the AI who is asking and what world they live in. This is not about telling it to \"act as an expert.\" It is about telling it about you. Compare these two openers. \"Write a reminder about flu shots\" gives the AI nothing. \"I am a charge nurse on a medical-surgical unit at a 200-bed hospital. I am writing to the nurses on my shift\" gives it your vocabulary, your audience, and your stakes. The AI now knows to use clinical shorthand instead of patient-friendly language, and to write peer-to-peer instead of top-down. The role tells the AI which version of itself to be."}$lum$::jsonb, false),
  ($lum$71c1ec2e-d9e3-51f8-ba98-3d77dc1a0cb7$lum$::uuid, $lum$3ac195ba-ec6e-5dab-80bd-1a0aae116991$lum$::uuid, 1, $lum$multiple_choice$lum$, $lum${"stem":"According to Step 1, what does giving the AI a role and your context actually mean?","options":[{"id":"a","label":"Telling the AI to \"act as an expert\" so it sounds more confident","is_correct":false,"explanation":"The reading says the role step is not about telling it to act as an expert. That is the opposite of the point being made."},{"id":"b","label":"Asking the AI to guess who you are from the topic","is_correct":false,"explanation":"Guessing is exactly what framing avoids. You are supposed to tell the AI who is asking, not leave it to fill in the blank."},{"id":"c","label":"Describing who is asking and what world they live in, like your job and your audience","is_correct":true,"explanation":"Right. The charge nurse example shows the role step is about telling the AI about you: your vocabulary, your audience, and your stakes, so it knows which version of itself to be."}]}$lum$::jsonb, false),
  ($lum$05d0c4a1-6424-5824-a50f-4efdc1e84c22$lum$::uuid, $lum$3ac195ba-ec6e-5dab-80bd-1a0aae116991$lum$::uuid, 2, $lum$reading$lum$, $lum${"markdown":"**Step 2: State the exact task and the constraints.** A topic is \"the flu shot reminder.\" A task is \"write a 4-sentence message reminding day-shift nurses that flu shot documentation is due by Friday, and that anyone who has not logged theirs needs to see me before they clock out.\" See the difference? The task names the output, the length, the deadline, and the action you want people to take. Constraints are the part almost everyone skips, and they are exactly what separates a vague paragraph from a message you can paste and send. Constraints include length, what to leave out, the deadline, and the one thing the reader must do.\n\n**Step 3: Specify the format.** Tell the AI the shape you want the answer to take. Do you want bullet points or full sentences? A table or a paragraph? An email with a subject line, or a quick Slack message? If you do not say, the AI guesses, and it usually guesses \"medium-length paragraph,\" which is rarely what you actually need. \"Give it to me as three bullets\" or \"format it as a short email with a subject line\" removes all the guessing.\n\nPut together, the frame is one breath: **\"I am a [role] doing [context]. I need [exact task with constraints]. Give it to me as [format].\"**"}$lum$::jsonb, false),
  ($lum$a39a7cad-9945-5f9e-ba96-b45356906659$lum$::uuid, $lum$3ac195ba-ec6e-5dab-80bd-1a0aae116991$lum$::uuid, 3, $lum$multiple_choice$lum$, $lum${"stem":"A paralegal types: \"I am a paralegal at a small estate-planning firm. I need a plain-English summary of this 12-page trust document for a client with no legal background, as five short bullet points.\" Which of the three framing steps is MISSING?","options":[{"id":"a","label":"Role and context","is_correct":false,"explanation":"The role is clearly stated: a paralegal at an estate-planning firm writing for a non-legal client. That step is covered."},{"id":"b","label":"Nothing is missing; all three steps are present","is_correct":true,"explanation":"Correct. Role and context (paralegal, non-legal client), task and constraint (summarize 12 pages in plain English), and format (five short bullets) are all there. This is a complete frame."},{"id":"c","label":"Format","is_correct":false,"explanation":"The format is specified: five short bullet points. That is exactly what the format step asks for."}]}$lum$::jsonb, false),
  ($lum$0beab583-b98c-5422-94a3-93603666d8fb$lum$::uuid, $lum$3ac195ba-ec6e-5dab-80bd-1a0aae116991$lum$::uuid, 4, $lum$reading$lum$, $lum${"markdown":"Here is the full thing for a real person. A high school history teacher needs a parent email about a field trip. The lazy version is \"write a field trip email.\" The framed version is this: \"I am a 10th-grade history teacher at a public high school. I need a short email to parents about a field trip to the state capitol on May 14th. It must mention that the permission slip is due May 7th, that lunch is provided, and that students need to wear closed-toe shoes. Keep it warm but professional, under 150 words, and format it as an email with a subject line.\" The first prompt gets a generic template the teacher has to rewrite. The second gets a sendable email with the subject line, the deadline, and the three logistics already baked in.\n\nOne more, for an office manager handling a touchy situation. The unframed version: \"write something about the kitchen being messy.\" That gets a passive-aggressive notice nobody respects. The framed version: \"I am the office manager at a 40-person marketing agency. I need a friendly all-staff message asking people to clean up after themselves in the shared kitchen. It should not name anyone, should not sound like a scolding, and should end with a light, positive note. Keep it under 100 words and format it as a Slack message.\" Now the AI knows the tone is light, the rule is no naming, and the channel is Slack, so it will not write a formal memo.\n\nNotice what every framed example has in common. None of them are longer because the person typed more words for the sake of it. They are longer because each sentence does a job: one sets the role, one sets the task and limits, one sets the shape. That is the whole technique. You are not writing a better prompt. You are briefing a capable assistant who needs to know who you are, what you actually want, and what it should look like when it is done.\n\nThe reason this works is simple. The AI does not know anything about your job, your reader, or your standards until you tell it. Every detail you leave out, it fills in with the most average guess possible. Framing is just the act of replacing those average guesses with your real situation, before they happen."}$lum$::jsonb, false),
  ($lum$6d149986-cdf3-5916-ab0d-b9ea3c87e7a6$lum$::uuid, $lum$3ac195ba-ec6e-5dab-80bd-1a0aae116991$lum$::uuid, 5, $lum$multiple_choice$lum$, $lum${"stem":"Based on the worked examples, why are the framed prompts longer than the lazy ones?","options":[{"id":"a","label":"Because each extra sentence does a job: one sets the role, one sets the task and limits, one sets the shape","is_correct":true,"explanation":"Right. The reading says none of them are longer for the sake of more words. They are longer because every sentence does one of the three jobs."},{"id":"b","label":"Because longer prompts always produce better answers from the AI","is_correct":false,"explanation":"The reading is explicit that the framed prompts are not longer just to type more words. Length itself is never the point here."},{"id":"c","label":"Because the AI needs polite filler words to take the request seriously","is_correct":false,"explanation":"Nothing in the examples adds polite filler. The added length is role, task with limits, and format, each doing a specific job."}]}$lum$::jsonb, false),
  ($lum$eec2b776-8e22-5e85-9256-4648ba143f55$lum$::uuid, $lum$3ac195ba-ec6e-5dab-80bd-1a0aae116991$lum$::uuid, 6, $lum$reading$lum$, $lum${"markdown":"Once people learn the three steps, the same predictable mistakes show up. Knowing them ahead of time saves you the frustration of wondering why your framed request still came back wrong.\n\n**Mistake 1: Most people confuse a topic with a task.** They write \"I am an HR manager. Help me with the new hire onboarding.\" They feel like they framed it because they added the role. But \"help me with onboarding\" is still a topic, not a task. The AI does not know if you want a checklist, an email, a schedule, or a policy. Fix it by naming the deliverable out loud: \"draft a day-one welcome email for a new hire starting Monday.\" The test is simple. If you cannot picture the finished thing in your head, the AI cannot either.\n\n**Mistake 2: People give a role but skip their real context.** \"Act as a marketing expert\" is the most common opener, and it is nearly useless. It tells the AI to sound confident but gives it nothing about your actual world. The role step is not about flattering the AI into expert mode. It is about describing you: your job, your company size, your audience. \"I run marketing for a 12-person dental practice\" beats \"act as a marketing expert\" every time, because it is true and specific."}$lum$::jsonb, false),
  ($lum$1f9088bc-e54a-5145-b1ea-62b1865b1b69$lum$::uuid, $lum$3ac195ba-ec6e-5dab-80bd-1a0aae116991$lum$::uuid, 7, $lum$fill_blank$lum$, $lum${"template":"A complete frame names your {{1}}, states the exact {{2}} along with constraints like length, and specifies the {{3}} you want the answer to take.","blanks":[{"id":"1","accept":["role","context","role and context"],"ideal":"role"},{"id":"2","accept":["task","output","deliverable"],"ideal":"task"},{"id":"3","accept":["format","shape","structure"],"ideal":"format"}],"explanation":"Role, task with constraints, and format. When an answer comes back generic, check which of these three you left out."}$lum$::jsonb, false),
  ($lum$4c76241c-372e-5803-9739-e87152a95a28$lum$::uuid, $lum$3ac195ba-ec6e-5dab-80bd-1a0aae116991$lum$::uuid, 8, $lum$reading$lum$, $lum${"markdown":"**Mistake 3: People skip constraints because they feel obvious.** You know the email should be short. You know not to mention the budget. But the AI does not know what is in your head. If you do not say \"under 100 words\" you will get 300. If you do not say \"do not mention the price increase\" it might lead with it. Constraints are not nitpicking; they are the difference between a draft you can send and a draft you have to rewrite. Say the obvious thing out loud.\n\n**Mistake 4: People believe a longer prompt is automatically a better prompt.** So they pile on detail that does not do any of the three jobs. Adding \"please be thorough and professional and high quality\" does nothing, because those words do not set a role, a task, or a format. Length is not the goal. Coverage is. A good frame can be three sentences. A bad one can be three paragraphs of filler.\n\nThe pattern behind all four mistakes is the same: people do part of the framing and assume the rest is understood. The AI never assumes what you meant. It only works with what you wrote. When an answer comes back off, do not retype the whole thing. Look at your frame and ask which of the three steps you left thin. Nine times out of ten, you skipped the task or the constraints."}$lum$::jsonb, false),
  ($lum$534043a7-4d16-5dab-9223-ceefdb1ab304$lum$::uuid, $lum$3ac195ba-ec6e-5dab-80bd-1a0aae116991$lum$::uuid, 9, $lum$multiple_choice$lum$, $lum${"stem":"According to Mistake 4, what makes a prompt good, since length is not the goal?","options":[{"id":"a","label":"Adding phrases like \"please be thorough and professional and high quality\"","is_correct":false,"explanation":"The reading singles out that exact phrase as doing nothing, because those words do not set a role, a task, or a format."},{"id":"b","label":"Making the prompt at least three paragraphs long","is_correct":false,"explanation":"The reading says a bad frame can be three paragraphs of filler. More paragraphs is not what makes a prompt good."},{"id":"c","label":"Writing in a confident, expert-sounding tone","is_correct":false,"explanation":"Tone is not the measure here. Mistake 4 is about coverage of the three jobs, not how confident the wording sounds."},{"id":"d","label":"Coverage: whether the prompt does the role, task, and format jobs, even in three sentences","is_correct":true,"explanation":"Right. The reading says length is not the goal, coverage is. A good frame can be three sentences as long as it covers role, task, and format."}]}$lum$::jsonb, false),
  ($lum$816fa581-e681-55e7-a094-26318753b225$lum$::uuid, $lum$3ac195ba-ec6e-5dab-80bd-1a0aae116991$lum$::uuid, 10, $lum$before_after$lum$, $lum${"question":"Same goal, two requests. Watch how the second one does all three framing jobs in three sentences.","before_prompt":"Write an email to staff about the parking changes.","after_prompt":"I am the office manager at a 60-person insurance firm. Write a short all-staff email letting people know that, starting March 1st, the north lot will be closed for repaving and everyone should use the street garage on Elm with their existing badge. Keep it under 120 words, do not sound alarmed, and end by thanking people for their patience. Format it as an email with a subject line.","changes":["Adds role and context: an office manager at a 60-person insurance firm, which sets the audience and tone.","Names the exact task and constraints: the date, the lot closing, the alternative garage, the badge detail, the 120-word limit, and the no-alarm rule.","Specifies the format: an email with a subject line, so the AI does not return a vague paragraph."]}$lum$::jsonb, true),
  ($lum$0e6b0c2a-84c4-50a7-9be7-5e6dfb66ce4e$lum$::uuid, $lum$3ac195ba-ec6e-5dab-80bd-1a0aae116991$lum$::uuid, 11, $lum$multiple_choice$lum$, $lum${"stem":"You framed a request with a clear role and a clear format, but the answer came back twice as long as you wanted and mentioned a detail you wished it had left out. Which framing step did you most likely leave thin?","options":[{"id":"a","label":"The task and its constraints","is_correct":true,"explanation":"Right. Length limits and what to leave out are constraints, which live in the task step. A missing word count gives you a long answer, and a missing exclusion gives you the detail you did not want."},{"id":"b","label":"The role and context","is_correct":false,"explanation":"The question says the role was clear. Role shapes tone and vocabulary, not length or which details get included."},{"id":"c","label":"The format","is_correct":false,"explanation":"The question says the format was clear. Format controls the shape, like bullets versus paragraphs, not the length or the content choices."}]}$lum$::jsonb, false),
  ($lum$0670c8ee-11a2-52be-82df-57e082dc75de$lum$::uuid, $lum$3ac195ba-ec6e-5dab-80bd-1a0aae116991$lum$::uuid, 12, $lum$mini_project$lum$, $lum${"brief":"Pick a message or document you actually have to produce this week: a parent email, a shift reminder, a client summary, an all-staff note, whatever is sitting on your list. Before you write it yourself, frame it for the AI using all three steps in order.","parts":[{"id":"1","prompt":"Write one sentence of role and context: your job, your company or unit, and who will read this."},{"id":"2","prompt":"Write one sentence of task and constraints: the exact deliverable, the length, the deadline if there is one, and anything the AI must leave out."},{"id":"3","prompt":"Write one sentence of format: bullets, table, email with a subject line, or short message."},{"id":"4","prompt":"Run the framed version, then delete the role sentence and run it again. Compare the two answers side by side and notice exactly what the role was buying you."}]}$lum$::jsonb, false),
  ($lum$93e6f47e-43fb-5741-9214-65ff8c55c245$lum$::uuid, $lum$353c8369-6493-519c-b0c8-0f86684a58ed$lum$::uuid, 0, $lum$reading$lum$, $lum${"markdown":"Here is the quiet habit that separates people who love AI from people who are frustrated by it. When the first answer is not quite right, the frustrated person sighs, deletes everything, and tries a brand-new prompt from scratch. The skilled person stays in the same conversation and steers. They treat the first answer as a rough draft from a junior colleague, not a verdict.\n\nThis works because of one fact most beginners do not know: the AI remembers everything you have said earlier in the same chat. You do not have to re-explain the task when you give feedback. You just react to what you got, the way you would react to a draft an assistant slid across your desk. \"Good start, but it is too formal\" tells the AI exactly what to keep and exactly what to change, without you rewriting the whole request.\n\nThe loop has three moves, and they are simple.\n\nMove one: react, do not restart. Instead of opening a fresh prompt, reply to the answer in front of you. Starting over throws away everything the AI got right and forces it to guess again. Replying keeps the good parts and corrects the bad parts.\n\nMove two: name the gap specifically. Vague feedback produces vague fixes. \"Make it better\" gives the AI nothing to act on, so it shuffles words around and you get something equally off. \"Cut this to half the length and use plainer words\" is a real instruction it can follow. The more precisely you name what is wrong, the more precisely it fixes it.\n\nMove three: repeat until it fits. Two or three rounds is normal. Each round you keep what works and fix one thing. The answer converges on what you actually wanted, fast."}$lum$::jsonb, false),
  ($lum$dec845f3-d26a-5256-b211-2cfef166792d$lum$::uuid, $lum$353c8369-6493-519c-b0c8-0f86684a58ed$lum$::uuid, 1, $lum$multiple_choice$lum$, $lum${"stem":"The first answer the AI gives you is close but too formal. What does an experienced user do next?","options":[{"id":"a","label":"Reply in the same chat naming what to keep and the one thing to change, like 'Good, but make it warmer and shorter'","is_correct":true,"explanation":"Right. Replying in the same chat keeps everything the AI got right and steers the one thing that is off. The conversation remembers the original task."},{"id":"b","label":"Delete it all and write a brand-new, longer prompt from scratch","is_correct":false,"explanation":"Starting over throws away the parts the AI already got right and forces it to guess again. Steering beats restarting almost every time."},{"id":"c","label":"Accept it as-is, since rewording will probably make it worse","is_correct":false,"explanation":"The first answer is round one, not the final draft. A specific follow-up note reliably improves it; accepting an answer you know is off wastes the loop."}]}$lum$::jsonb, false),
  ($lum$76dc5479-f2ed-5c69-8bc8-b61a54d262fc$lum$::uuid, $lum$353c8369-6493-519c-b0c8-0f86684a58ed$lum$::uuid, 2, $lum$reading$lum$, $lum${"markdown":"Let me show you a real three-turn loop. A middle-school teacher needs a parent email about a field trip.\n\nTurn one, she types: \"Write a short email to parents about a field trip to the science museum on March 14. They need to sign a permission slip and send $12 by March 7.\"\n\nThe AI returns a polished email, but it opens with \"Dear Esteemed Parents and Guardians\" and runs four long paragraphs. Too stiff and too long. A beginner would start over here. The teacher does not.\n\nTurn two, she replies in the same chat: \"Too formal and too long. Make it warm and friendly, like a teacher who knows these families. Cut it to about five sentences and put the date, the money, and the deadline in a short bulleted list so nobody misses them.\"\n\nThe AI rewrites it: friendlier opener, five sentences, a clean three-item list. Much closer. But the closing line says \"Please do not hesitate to contact me,\" which is exactly the stiff phrase she was trying to escape.\n\nTurn three: \"Perfect length and tone. Just swap the last line for something simpler, like telling them to email me with any questions.\" The AI fixes that one line. Done. Three turns, ninety seconds, and an email she would actually send. Notice she never re-typed the date, the price, or the deadline. The chat held all of that for her."}$lum$::jsonb, false),
  ($lum$c1cc20e6-0d64-58f3-ad18-2c39899cdcd6$lum$::uuid, $lum$353c8369-6493-519c-b0c8-0f86684a58ed$lum$::uuid, 3, $lum$fill_blank$lum$, $lum${"template":"In the teacher's loop, she does not restart after the stiff first draft; in turn two she keeps the task and asks for a {{1}} and friendly tone in about five sentences. In turn three she changes only the {{2}} line, and the chat still remembers the date, the price, and the deadline.","blanks":[{"id":"1","accept":["warm","warmer","warm and friendly","friendly"],"ideal":"warm"},{"id":"2","accept":["last","closing","final","last line","closing line"],"ideal":"last"}],"explanation":"Across the three turns she reacts instead of restarting: turn two asks for a warmer tone and a tighter length, and turn three swaps just the closing line. Because she stayed in the same chat, she never had to re-type the date, the money, or the deadline."}$lum$::jsonb, false),
  ($lum$6e46271c-35ae-56b3-b736-d9c0b53299d1$lum$::uuid, $lum$353c8369-6493-519c-b0c8-0f86684a58ed$lum$::uuid, 4, $lum$reading$lum$, $lum${"markdown":"Here is a second example, longer and more specific, because it shows the loop on something with real stakes. A small-business owner needs a job posting for a part-time bookkeeper.\n\nTurn one, he types: \"Write a job posting for a part-time bookkeeper for my landscaping company. About 20 hours a week, needs QuickBooks experience, remote is fine.\" The AI returns a full posting, but it reads like a giant corporation wrote it: a \"Position Overview\" header, a bulleted \"Key Responsibilities\" section with eight items, a \"Qualifications\" wall, and a closing about \"our commitment to diversity and a fast-paced dynamic environment.\" It is accurate but soulless, and it would scare off the exact person he wants, a detail-oriented local who likes working with a small team.\n\nA beginner would either ship that or start over. He does neither. Turn two, in the same chat: \"This feels too corporate for a six-person company. Rewrite it in a warmer, plain-spoken voice, like the owner talking directly to a candidate. Cut the responsibilities list to the four that actually matter: monthly reconciliations, invoicing, payroll, and quarterly tax prep. Keep it under 200 words.\" The AI rewrites it, friendlier and tighter, four clean responsibilities, the right length. Much better. But now it says \"competitive salary\" with no number, and he knows vague pay drives away serious applicants.\n\nTurn three: \"Great voice, keep all of it. One change: replace 'competitive salary' with '$28 to $34 an hour depending on experience.'\" The AI makes exactly that edit and leaves everything else untouched. Done. Three turns, and notice what he never re-typed: the company type, the hours, the QuickBooks requirement, the remote detail. The chat held all of it, and the posting went from generic boilerplate to something that sounds like a real person worth working for.\n\nThe reason this matters: the alternative is the \"perfect prompt\" myth, the idea that if you just word your first request perfectly enough, you will get a flawless answer in one shot. You will not, and chasing it is exhausting. You cannot predict every detail in advance, partly because you often do not know what you want until you see what you do not want. The first answer is information. It shows you the gap between what you asked for and what you meant. Then you close that gap one specific note at a time.\n\nStop treating the first answer as final. Treat it as round one of a quick conversation. Read it critically, say what is off and what to keep, ask for one change, and go again. That single shift, from rewriting prompts to steering answers, is the biggest jump in results most people ever get from these tools."}$lum$::jsonb, false),
  ($lum$3449cd7e-12c7-568c-aa4c-459200aea46c$lum$::uuid, $lum$353c8369-6493-519c-b0c8-0f86684a58ed$lum$::uuid, 5, $lum$multiple_choice$lum$, $lum${"stem":"In turn three of the bookkeeper example, the owner says 'Great voice, keep all of it' and asks for one swap. Why does he phrase it that way?","options":[{"id":"a","label":"To flatter the AI so it works harder on the next version","is_correct":false,"explanation":"Praise toward the AI is not the lever here. The point of naming what to keep is to protect the parts that already work, not to motivate the tool."},{"id":"b","label":"To protect the parts that already work while changing only the vague-pay line, so the rest stays untouched","is_correct":true,"explanation":"Right. Naming what to keep, then asking for one concrete change, is the loop done well. The AI fixes the salary line and leaves the good voice and length alone."},{"id":"c","label":"Because the posting was finished and he was just being polite before sending it","is_correct":false,"explanation":"It was not finished; it still said 'competitive salary' with no number, which he knew would drive away serious applicants. He was making a targeted fix, not signing off."}]}$lum$::jsonb, false),
  ($lum$bb5445de-da91-5fb6-8cb1-398e9f1d94a9$lum$::uuid, $lum$353c8369-6493-519c-b0c8-0f86684a58ed$lum$::uuid, 6, $lum$reading$lum$, $lum${"markdown":"The most common way people sabotage the iteration loop is feedback that is too vague. They reply \"make it better,\" \"I do not like it,\" or \"try again,\" and then they are surprised when the second answer is just as wrong as the first. The AI is not a mind reader. \"Make it better\" could mean shorter, longer, warmer, more formal, more detailed, or less detailed, so it guesses, and it usually guesses wrong. The fix is to name the specific gap: not \"better\" but \"cut it in half,\" not \"I do not like it\" but \"the tone is too salesy, make it matter-of-fact.\" Specific feedback gets a specific fix.\n\nThe second mistake is the restart reflex. The first answer disappoints, so people delete the chat and start a new one. Every restart erases the AI's memory of the task and every correction you already made, so you end up re-explaining the same context over and over and never building on progress. Stay in the thread. The whole power of the loop is that the conversation accumulates: round two builds on round one, round three builds on round two."}$lum$::jsonb, false),
  ($lum$5f145b98-1f07-53bc-acfd-51e7902b8c5e$lum$::uuid, $lum$353c8369-6493-519c-b0c8-0f86684a58ed$lum$::uuid, 7, $lum$fill_blank$lum$, $lum${"template":"When an answer misses, do not say {{1}}; instead, name the specific gap. And do not delete the chat to {{2}}, because the conversation remembers your task and every correction you have already made.","blanks":[{"id":"1","accept":["make it better","better","try again","vague feedback","do it better"],"ideal":"make it better"},{"id":"2","accept":["start over","restart","start from scratch","begin again","start a new chat"],"ideal":"start over"}],"explanation":"Vague feedback like 'make it better' gives the AI nothing to act on, and restarting erases the context and the corrections you already built. Specific notes inside the same chat are what move the answer forward."}$lum$::jsonb, false),
  ($lum$5283d239-ab14-5368-bcb3-e5b51c0dc8b8$lum$::uuid, $lum$353c8369-6493-519c-b0c8-0f86684a58ed$lum$::uuid, 8, $lum$reading$lum$, $lum${"markdown":"The third mistake is the opposite extreme, dumping ten complaints into one message. \"It is too long and too formal and missing the deadline and the tone is wrong and can you also add a table and change the greeting.\" The AI tries to juggle all of it and does most of them halfway. Change one or two things per turn. It feels slower, but it is faster, because each focused turn lands cleanly instead of needing its own cleanup.\n\nThere is also a giving-up-too-early problem. People expect the second answer to be perfect, and when it is merely better, they quit and settle for \"good enough\" or abandon the tool. Better is the signal that the loop is working. Two or three rounds is normal and expected, not a sign you are doing it wrong.\n\nFinally, a quieter misconception: many people genuinely believe a good enough first prompt removes the need to iterate, so they pour all their energy into crafting one giant opening message and none into the follow-up. A clear first prompt helps, but it never eliminates the back-and-forth, because you discover what you actually want by reacting to what you got. Put a reasonable amount of effort into the first ask, then save plenty of energy for steering. The follow-up is where the quality comes from."}$lum$::jsonb, false),
  ($lum$ababeded-7d21-508b-8b4a-099fc8401656$lum$::uuid, $lum$353c8369-6493-519c-b0c8-0f86684a58ed$lum$::uuid, 9, $lum$multiple_choice$lum$, $lum${"stem":"You have ten things you want changed about an answer. According to this segment, what should you do?","options":[{"id":"a","label":"Put all ten into one message so the AI fixes everything in a single pass","is_correct":false,"explanation":"When you dump ten complaints into one message the AI tries to juggle all of it and does most of them halfway. That is the exact mistake this segment warns against."},{"id":"b","label":"Pick the biggest one, then quit if the next answer is not perfect","is_correct":false,"explanation":"Quitting because the answer is only better is the giving-up-too-early problem. Better is the signal the loop is working, so you keep going for two or three rounds."},{"id":"c","label":"Change one or two things per turn, even though it feels slower","is_correct":true,"explanation":"Right. One or two focused changes per turn land cleanly. It feels slower but it is faster, because you avoid the halfway fixes that piling on ten complaints creates."}]}$lum$::jsonb, false),
  ($lum$e3dc7b14-eac8-5c3d-b4f8-537c64d8a9d2$lum$::uuid, $lum$353c8369-6493-519c-b0c8-0f86684a58ed$lum$::uuid, 10, $lum$before_after$lum$, $lum${"question":"An HR manager got a first draft of a policy reminder that is close but off. Here is weak follow-up feedback versus strong follow-up feedback.","before_prompt":"I do not really like this. Can you make it better and try again?","after_prompt":"The structure is good, keep the bulleted steps. Two changes: the tone reads like a warning letter, so soften it to a friendly reminder that assumes good intent, and it is too long, cut the second paragraph entirely. Keep the deadline line exactly as it is.","changes":["Tells the AI what to keep (the bulleted steps, the deadline line) so it does not accidentally rewrite the parts that already worked","Names the actual problem (tone reads like a warning) instead of the useless 'I do not like it', so the fix is targeted","Gives a concrete length instruction (cut the second paragraph) rather than a vague 'make it shorter'","Limits the request to two focused changes so the next answer lands cleanly instead of being half-fixed in five directions"]}$lum$::jsonb, true),
  ($lum$34269d81-e5a3-5c28-9443-f7b5d825cff0$lum$::uuid, $lum$353c8369-6493-519c-b0c8-0f86684a58ed$lum$::uuid, 11, $lum$multiple_choice$lum$, $lum${"stem":"Why is the HR manager's second message so much more effective as follow-up feedback?","options":[{"id":"a","label":"It says what to keep, names the exact problem, gives a concrete change, and limits itself to two focused fixes","is_correct":true,"explanation":"Exactly. Protecting what works, naming the specific gap, and changing only one or two things per turn is the whole iteration loop done right."},{"id":"b","label":"It is more polite, and politeness is what makes the AI try harder","is_correct":false,"explanation":"Tone toward the AI is not the lever. The second version works because it is specific and focused, not because it is nicer."},{"id":"c","label":"It asks for many changes at once, which gets everything fixed faster","is_correct":false,"explanation":"It deliberately does the opposite, limiting to two changes. Piling on ten complaints makes the AI fix each one halfway."}]}$lum$::jsonb, false),
  ($lum$df1af184-1d3f-582b-951c-b1cfa130fac7$lum$::uuid, $lum$353c8369-6493-519c-b0c8-0f86684a58ed$lum$::uuid, 12, $lum$mini_project$lum$, $lum${"brief":"Run a real three-turn loop on something you actually need this week. Pick a genuine task: a parent email, a client letter, a policy reminder, a job posting, a shift handoff note, whatever is on your plate.","parts":[{"id":"1","prompt":"Turn one: write your normal first request and read the answer critically. Note what it got right and the single biggest thing that is off."},{"id":"2","prompt":"Turn two: reply in the same chat. Name what to keep, name the specific problem (not \"better,\" but the actual gap), and ask for one or two concrete changes."},{"id":"3","prompt":"Turn three: react to the new version the same way and fix the last detail."}]}$lum$::jsonb, false),
  ($lum$d37af57f-6eca-56f9-8eb7-fc36401d1439$lum$::uuid, $lum$9f9624a6-e38e-567c-aea8-e7d197129d33$lum$::uuid, 0, $lum$reading$lum$, $lum${"markdown":"A lot of the intimidation around AI is just unfamiliar words thrown around as if everyone already knows them. They're not complicated once someone defines them plainly. Here are the ten that actually matter for everyday use. Skim it now, come back when a term trips you up.\n\n**Prompt.** What you type into the box. Your question, instruction, or request. That's all \"writing a prompt\" means.\n\n**Model.** The underlying AI engine doing the work. \"GPT,\" \"Claude,\" \"Gemini\" are model families. Newer or \"bigger\" models are generally more capable. You're usually picking one from a dropdown.\n\n**LLM (Large Language Model).** The technical name for the kind of AI behind chat assistants. It predicts likely text. When someone says \"LLM,\" they mean the thing powering ChatGPT and its cousins.\n\n**Token.** The unit AI reads and writes in, roughly a chunk of a word. It matters mostly because limits (\"context window,\" usage caps) are measured in tokens. You rarely need to count them.\n\n**Context window.** How much text the model can \"hold in mind\" at once, your prompt plus its reply plus the conversation so far. Hit the limit and it starts forgetting the start of a long chat.\n\n**Hallucination.** When AI states something false with total confidence. Not a glitch; a side effect of how it works. The reason you verify facts.\n\n**Training data / cutoff.** The pile of text the model learned from, frozen at a certain date. Anything after the cutoff is unknown to it unless it can browse the live web.\n\n**Fine-tuning.** Extra training that specializes a model for a particular job or style. Mostly a behind-the-scenes term; good to recognize, rarely something you do.\n\n**Prompt engineering.** A fancy phrase for \"writing your request clearly and specifically.\" You're already learning it in this module. Don't be intimidated by the label.\n\n**Custom instructions / system prompt.** Standing directions you set once so the AI remembers your role and preferences across chats. There's a whole lesson on this.\n\nThat's the core ten. You don't need to memorize them. You need to stop flinching when you see them, because none of them are hiding anything complicated."}$lum$::jsonb, false),
  ($lum$bbd43d10-b182-560b-9de3-0feedbfea355$lum$::uuid, $lum$9f9624a6-e38e-567c-aea8-e7d197129d33$lum$::uuid, 1, $lum$fill_blank$lum$, $lum${"template":"When AI states something false with total confidence, that's called a {{1}}. The text you type to it is a {{2}}, and the frozen date its knowledge stops at is its {{3}}.","blanks":[{"id":"1","accept":["hallucination","hallucinations"],"ideal":"hallucination"},{"id":"2","accept":["prompt"],"ideal":"prompt"},{"id":"3","accept":["cutoff","training cutoff","knowledge cutoff","cut-off"],"ideal":"cutoff"}],"explanation":"Hallucination, prompt, and cutoff are three of the ten terms that unlock most AI conversations and settings menus."}$lum$::jsonb, false),
  ($lum$cdf4aeb8-191a-5fec-8a6e-fa246b0b6fcf$lum$::uuid, $lum$7783e9f8-daf8-56d1-9340-d52994020e14$lum$::uuid, 0, $lum$reading$lum$, $lum${"markdown":"People who feel let down by AI usually aren't using it wrong; they're aiming it at the wrong targets. They ask it for a hard fact, get burned, and conclude it's useless. Meanwhile, the people who swear by it are quietly pointing it at the tasks it's genuinely built for. Here's how to tell those apart before you start, so you get a win instead of a letdown.\n\n**Green-light tasks (reach for AI first):**\n- **First drafts of anything.** Emails, posts, outlines, job descriptions, agendas. A rough draft in ten seconds beats a blank page every time, and editing is easier than creating.\n- **Reshaping text you already have.** Make it shorter, warmer, more formal, simpler. Turn bullet points into prose or prose into bullets. This is its single best skill.\n- **Explaining and simplifying.** \"Explain this clause in plain English.\" \"What does this error message mean?\" Great for getting unstuck.\n- **Brainstorming and getting unstuck.** Names, angles, counterarguments, twenty options to react to. It's a tireless thinking partner.\n- **Summarizing long things you provide.** Paste a report, get the gist. (Provide the text; don't trust it to recall a document from memory.)\n\n**Red-light tasks (don't trust it alone):**\n- **Specific facts, figures, dates, and quotes.** It will sound certain and may be wrong. Verify at the source.\n- **Math and precise calculations.** It fumbles arithmetic surprisingly often. Use a calculator or spreadsheet.\n- **Anything high-stakes if wrong.** Medical, legal, financial, or safety decisions need a qualified human, not a confident guess.\n- **Current events, unless it's browsing live.** Frozen training can't know this week.\n\n**The underlying pattern:** AI is brilliant when you're the editor and it's the drafter, and risky when you're trusting it as the source of truth. If a mistake would just cost you a quick re-read, green-light it. If a mistake would cost you money, reputation, or someone's wellbeing, keep a human firmly in charge and use AI only for the parts you can check.\n\nMatch the task to the tool, and the disappointment mostly disappears."}$lum$::jsonb, false),
  ($lum$115742b4-1959-5936-896e-af26f3a7f4e8$lum$::uuid, $lum$7783e9f8-daf8-56d1-9340-d52994020e14$lum$::uuid, 1, $lum$before_after$lum$, $lum${"question":"Same topic, two ways to use AI. One plays to its strengths; one walks into its weakness.","before_prompt":"What were the exact attendance numbers for our industry's biggest conference last year?","after_prompt":"Here are my rough notes from last year's conference [paste]. Turn them into a tight 5-bullet summary I can send my team, and flag anything that sounds like a specific number I should double-check.","changes":["Stops asking the AI to recall a precise fact from memory, which is a red-light task it will guess at.","Switches to reshaping text you provide, which is its single strongest skill.","Even builds in a verification habit by asking it to flag the numbers for you to confirm."]}$lum$::jsonb, false),
  ($lum$7ff666fb-7ee8-5415-b8d1-0d1d0e99ea40$lum$::uuid, $lum$a6462f1d-5f41-553a-870a-e490cb965021$lum$::uuid, 0, $lum$reading$lum$, $lum${"markdown":"You've opened the tool. There's a blinking cursor and a box that says \"Ask anything.\" This is the moment most people type \"hello,\" get a polite reply, and quietly close the tab. Let's not do that. Here's how to spend the next five minutes so you walk away with a real win.\n\n**Don't test it. Use it.** The instinct is to quiz the AI with a trivia question or \"tell me a joke.\" That teaches you nothing about how it helps *you*. Instead, grab something small and real from your actual day: an email you've been putting off, a paragraph that reads badly, a decision you're chewing on, a list you need to organize. Real work is where the value lives.\n\n**Give it the situation, not just a command.** Compare \"write an email\" with \"I need to tell my team our Friday meeting is moved to Monday at 10am, keep it short and friendly.\" The second one has context, and the answer will be ten times better. You don't need perfect phrasing. You just need to say what you'd tell a helpful colleague who's stepping in cold.\n\n**Read the answer like a draft, not a verdict.** The first response is a starting point. If it's too long, say \"make it shorter.\" If the tone is off, say \"more casual.\" You are allowed to talk back, and the answer improves every time you do. (There's a whole lesson on this loop coming up.)\n\n**Then actually use it.** Send the email. Paste the cleaned-up paragraph. The win isn't a clever conversation with a robot; it's a real task finished faster than usual. That's the feeling that turns AI from a curiosity into a habit.\n\nFive minutes, one real task, one finished result. That's the entire goal of your first session."}$lum$::jsonb, false),
  ($lum$827ffecd-a5aa-5498-a632-e3510bea12ab$lum$::uuid, $lum$a6462f1d-5f41-553a-870a-e490cb965021$lum$::uuid, 1, $lum$try_it_live$lum$, $lum${"instructions":"Practice the first move: turn a bare command into a request with context. Take a task you actually have today and write it the way you'd explain it to a colleague stepping in cold, including the situation, who it's for, and how long or what tone you want.","system_prompt":"You are a friendly onboarding coach helping a brand-new AI user write their first useful request. Given a vague task, rewrite it into a short, natural request that includes the situation, the audience, and a constraint on length or tone. Keep it plain and encouraging. No jargon, no em dashes.","ideal_output":"I need to email my book club to say I can't make this week's meeting but I've finished the chapters and have thoughts to share. Keep it warm and casual, about three sentences, and offer to send my notes so I'm not just bailing.","input_placeholder":"I need to [task]. It's for [who]. Keep it [length or tone]..."}$lum$::jsonb, false),
  ($lum$9625f932-42e9-5d50-85fd-71a14b0d3566$lum$::uuid, $lum$3c690267-cbaf-5596-b072-115de24e0cc3$lum$::uuid, 0, $lum$reading$lum$, $lum${"markdown":"The first thing to understand is that AI making things up is not a glitch that engineers forgot to fix. It is baked into how the tool works. A model like ChatGPT does not store facts and look them up. It predicts the most plausible-sounding next word, over and over. Most of the time the most plausible-sounding answer is also the correct one, which is why it feels reliable. But when it does not actually know something, it does not stop and say so. It produces the most plausible-sounding answer anyway, because that is the only thing it knows how to do. That confident-but-wrong output has a name: a hallucination, or sometimes a confabulation. The scary part is that a hallucination looks exactly as polished and certain as a correct answer. There is no flashing red light.\n\nLet me show you what this looks like in real work.\n\nCarlos is a paralegal. He asked ChatGPT to find case law supporting a motion, and it gave him three cases with full names, court names, dates, and quotes. They looked completely real. Two of them did not exist. The model had assembled a plausible-sounding case citation the same way it assembles a plausible-sounding sentence. This is not hypothetical: real lawyers have been sanctioned by judges for filing AI-invented cases. Carlos caught it only because he tried to pull the cases and could not find them.\n\nJenny is a nurse educator writing a patient handout. She asked for a \"recent study\" on a medication's side effects, and ChatGPT produced one: \"A 2021 study in the Journal of Clinical Nursing found that 68% of patients...\" It was specific, it had a percentage, it named a journal. None of it was real. The over-specific detail is part of how the lie works. Vague claims feel like guesses, so the model unconsciously dresses fabrications in precise numbers and named sources to make them feel earned.\n\nMarcus runs the support desk at a software company. He asked ChatGPT how to change a setting in a tool his team uses, and it walked him through a clear path: open Settings, click the Advanced tab, toggle the option under \"Data Retention.\" The steps were confident and well ordered. The problem was that the Advanced tab did not exist in that product, and neither did the toggle. The model had seen thousands of software menus during training and assembled the most typical-looking path, not the real one. Marcus only realized when he tried to follow his own instructions and could not find the screen. This is the same machinery as the fake citation and the fake study, just pointed at a different kind of fact. The model fills any gap with the most plausible-sounding shape, whether that shape is a court case, a percentage, or a menu that was never there."}$lum$::jsonb, false),
  ($lum$ac59666e-cc02-5a2f-96a2-07da05e2f59c$lum$::uuid, $lum$3c690267-cbaf-5596-b072-115de24e0cc3$lum$::uuid, 1, $lum$multiple_choice$lum$, $lum${"stem":"Why does ChatGPT produce confident, wrong answers instead of saying 'I don't know'?","options":[{"id":"a","label":"Because it predicts the most plausible-sounding next words rather than retrieving stored facts, so it generates a plausible answer even when it has no real one.","is_correct":true,"explanation":"Correct. Hallucination comes directly from how the model works: it always produces the most plausible-sounding output, true or not."},{"id":"b","label":"Because it was programmed to never admit uncertainty.","is_correct":false,"explanation":"It is not a deliberate rule against honesty. The behavior comes from prediction: it generates plausible text rather than checking whether it knows the answer."},{"id":"c","label":"Because the internet it learned from is full of lies.","is_correct":false,"explanation":"Bad training data can contribute, but hallucination happens even on well-documented topics because the model predicts plausible words rather than retrieving verified facts."}]}$lum$::jsonb, false),
  ($lum$ebbad585-5aa2-504f-b66d-9070a952ca70$lum$::uuid, $lum$3c690267-cbaf-5596-b072-115de24e0cc3$lum$::uuid, 2, $lum$reading$lum$, $lum${"markdown":"So how do you catch it? Watch for these tells.\n\nFirst, suspiciously specific details, especially citations. When AI gives you a study, a statistic, a court case, a quote, or a named source, treat it as unverified until you check it yourself. Invented citations are often more precise than real ones, with exact percentages and tidy years. Always go find the original.\n\nSecond, confident claims about anything recent. The model has a training cutoff and no live view of the world. If it tells you about this quarter's earnings, last week's news, or a current price without hedging, it is guessing. Recent plus confident equals verify.\n\nThird, no hedging where there should be. On genuinely uncertain or obscure topics, a careful answer will say \"I am not certain, but\" or \"this varies.\" When an answer charges straight through territory that should be murky with total confidence, that confidence is a warning sign, not a comfort.\n\nFourth, internal contradictions. Hallucinations sometimes disagree with themselves within the same response, saying the deadline is the 15th in one paragraph and the 20th in another. Read the whole answer before you act on any part of it."}$lum$::jsonb, false),
  ($lum$6db82d25-a57c-52cd-a66b-954d973afbe8$lum$::uuid, $lum$3c690267-cbaf-5596-b072-115de24e0cc3$lum$::uuid, 3, $lum$fill_blank$lum$, $lum${"template":"An invented citation is often {{1}} than a real one, with exact percentages and tidy dates, so when AI gives you a named source you should {{2}} it against the original instead of trusting it.","blanks":[{"id":"1","accept":["more specific","more precise","more detailed","specific","precise"],"ideal":"more specific"},{"id":"2","accept":["verify","check","confirm","cross-check"],"ideal":"verify"}],"explanation":"Over-specific detail is part of how hallucinations disguise themselves. The right response to a named source is to verify it against the original, not to trust the precision."}$lum$::jsonb, false),
  ($lum$3eafb6d0-0808-515d-9852-c1092fdf5645$lum$::uuid, $lum$3c690267-cbaf-5596-b072-115de24e0cc3$lum$::uuid, 4, $lum$reading$lum$, $lum${"markdown":"Now the practical part: how do you verify? You do not have to fact-check every word, only the parts you would stake your reputation on. Three quick habits cover most of it.\n\nAsk for sources, then actually check them. If ChatGPT names a study or a rule, ask \"what is the source for that?\" and then go find it on Google. If you cannot find the source, treat the claim as false, not as \"probably fine.\"\n\nCross-check the load-bearing facts. Take the one or two facts the whole document depends on, the dollar amount, the date, the legal rule, and confirm each one against a real source. Everything else can be lower stakes.\n\nUse the right tool for the fact in the first place. As you learned with Google versus ChatGPT, do not ask the writer for current facts at all. Get the verifiable fact from a real source and paste it in, so there is nothing for the model to invent.\n\nThe goal is not to stop using AI. It is to use it where \"mostly right and I will edit it\" is fine, which is most writing and brainstorming, and to verify hard before anything goes out with your name attached. The people who get burned are not the ones who use AI. They are the ones who paste its confident answer straight into a document without ever asking \"can I actually check this?\""}$lum$::jsonb, false),
  ($lum$27a93de4-8a9c-5807-bfd1-9cd206fc8f82$lum$::uuid, $lum$3c690267-cbaf-5596-b072-115de24e0cc3$lum$::uuid, 5, $lum$multiple_choice$lum$, $lum${"stem":"According to the verify step, how much of an AI-written document should you actually fact-check?","options":[{"id":"a","label":"Every single sentence, word by word, before you trust any of it.","is_correct":false,"explanation":"The reading says you do not have to fact-check every word. Checking everything is the trap that makes people give up."},{"id":"b","label":"Only the load-bearing parts you would stake your reputation on, like the dollar amount, the date, or the rule.","is_correct":true,"explanation":"Correct. The reading says to verify only the parts you would stake your reputation on, and to confirm the one or two facts the document depends on."},{"id":"c","label":"None of it, as long as the answer sounds confident and well written.","is_correct":false,"explanation":"Confidence is exactly what you cannot trust. The reading tells you to verify the load-bearing facts hard before your name goes on it."},{"id":"d","label":"Only the parts that already sound uncertain or hedged.","is_correct":false,"explanation":"The reading points you at the load-bearing facts, not at the tone. A confident-sounding claim still needs checking if the document rests on it."}]}$lum$::jsonb, false),
  ($lum$c3806639-bc71-53b4-b45b-0d7357b6d79a$lum$::uuid, $lum$3c690267-cbaf-5596-b072-115de24e0cc3$lum$::uuid, 6, $lum$reading$lum$, $lum${"markdown":"The most common mistake is treating confidence as evidence. People read a smooth, certain, well-formatted answer and feel it must be true, because in human conversation confidence usually tracks knowledge. With AI that link is broken. The tone is identical whether the answer is correct or invented. The fix is to mentally separate \"this sounds sure\" from \"this is verified\" and to remember that for AI, the first tells you nothing about the second.\n\nThe second mistake is verifying the wrong way: asking ChatGPT to check itself. People notice a shaky answer and reply \"are you sure?\" or \"is that real?\" The model will often double down with even more confident-sounding detail, or flip and apologize and invent a different wrong answer, because it is still just predicting plausible text. It cannot actually look up whether its own claim is true. The fix is to verify outside the tool, against a real source on Google or the original document, never by interrogating the model.\n\nThe third mistake is trusting the precise stuff most. Our instinct says a specific citation with a journal name and an exact percentage is more trustworthy than a vague claim. With hallucinations it is often the reverse: the specificity is the disguise. The fix is to flip your instinct. When AI hands you a number, a named study, a quote, or a court case, raise your guard rather than lowering it, and go confirm the original."}$lum$::jsonb, false),
  ($lum$7cf6648e-e573-59a0-a560-8290306a92e4$lum$::uuid, $lum$3c690267-cbaf-5596-b072-115de24e0cc3$lum$::uuid, 7, $lum$multiple_choice$lum$, $lum${"stem":"You notice a shaky claim and reply 'are you sure that's real?' Why is this the wrong way to verify?","options":[{"id":"a","label":"Because the model gets offended and stops answering.","is_correct":false,"explanation":"It is not about the model's feelings. The problem is that it still cannot look up whether its own claim is true."},{"id":"b","label":"Because asking twice wastes one of your daily messages.","is_correct":false,"explanation":"The reading never mentions message limits. The real issue is that the model cannot check itself."},{"id":"c","label":"Because the model is still just predicting plausible text, so it may double down or invent a new wrong answer instead of actually checking.","is_correct":true,"explanation":"Correct. The model cannot look up whether its own claim is true, so you verify outside the tool against a real source, never by interrogating the model."}]}$lum$::jsonb, false),
  ($lum$3290502b-a119-5b35-a994-a38e0c469bc6$lum$::uuid, $lum$3c690267-cbaf-5596-b072-115de24e0cc3$lum$::uuid, 8, $lum$reading$lum$, $lum${"markdown":"The fourth mistake is all-or-nothing verification. People either check nothing because it is tedious, or they try to fact-check every sentence and give up. Neither works. The fix is to find the load-bearing facts, the few claims the whole document rests on, and verify only those hard. A drafted email tone does not need a source. The dollar figure, the legal deadline, and the medication dose do. Spend your verification energy where being wrong actually hurts.\n\nA fifth mistake is assuming a tool that cites its sources is automatically safe. Newer assistants sometimes attach links to back up a claim, and people see the link and relax. But a link is not the same as a fact that matches it. The model can summarize a source incorrectly, or attach a real-looking URL that does not actually say what the sentence claims. A finance analyst once shipped a memo citing a \"press release\" link, and the page, when a colleague finally opened it, said the opposite of the memo. The fix is to open the link and read the relevant line yourself, not to treat the presence of a citation as proof. A source you have not read is just a more convincing version of an unverified claim, and the extra polish makes it easier, not harder, to wave through."}$lum$::jsonb, false),
  ($lum$b3aadec0-518c-5b1b-975f-d7d1e374af0f$lum$::uuid, $lum$3c690267-cbaf-5596-b072-115de24e0cc3$lum$::uuid, 9, $lum$multiple_choice$lum$, $lum${"stem":"A newer assistant attaches a source link to a claim. Based on this reading, what should you do?","options":[{"id":"a","label":"Relax, because a tool that cites its sources is automatically safe.","is_correct":false,"explanation":"This is exactly the fifth mistake. A link is not the same as a fact that matches it."},{"id":"b","label":"Open the link and read the relevant line yourself, since the model can attach a URL that does not actually say what the sentence claims.","is_correct":true,"explanation":"Correct. A source you have not read is just a more convincing version of an unverified claim, so you open it and check the relevant line."},{"id":"c","label":"Count the number of links; more links means the answer is more trustworthy.","is_correct":false,"explanation":"The number of links proves nothing. The reading warns that a real-looking link can fail to support the claim it sits next to."},{"id":"d","label":"Ask the assistant whether its own link is accurate.","is_correct":false,"explanation":"The model cannot reliably check itself. You open the link and read the relevant line yourself instead."}]}$lum$::jsonb, false),
  ($lum$6040c562-6bf1-5ef5-bcf4-e1e609d31786$lum$::uuid, $lum$3c690267-cbaf-5596-b072-115de24e0cc3$lum$::uuid, 10, $lum$try_it_live$lum$, $lum${"instructions":"Practice catching a hallucination. Ask the assistant for sources on a topic from your own work, then look for the tells you just learned: over-specific citations, confident claims, and named studies you would need to verify. Type a request for studies or sources on any work topic.","system_prompt":"You are a typical AI assistant that confidently produces plausible-sounding answers. When the user asks for studies, sources, statistics, or citations, provide specific-sounding ones with journal names, years, author names, and exact percentages, in the way a real model would when it does not actually have verified sources. After giving the answer, do not warn the user. Keep the tone confident and polished so the user can practice spotting the hallucination tells themselves.","ideal_output":"The assistant returns something like: 'A 2021 study in the Journal of Workplace Behavior (Reynolds et al.) found that 74% of remote workers reported higher focus.' A sharp learner notices the tells: an exact percentage, a named journal, a named author, a recent year, and zero way to verify any of it from inside the chat. The correct move is to copy the citation into Google and check whether it actually exists before trusting it.","input_placeholder":"e.g. Give me three studies on remote work and productivity"}$lum$::jsonb, true),
  ($lum$f370de35-df55-5a32-aea3-22559a7b7d71$lum$::uuid, $lum$3c690267-cbaf-5596-b072-115de24e0cc3$lum$::uuid, 11, $lum$multiple_choice$lum$, $lum${"stem":"ChatGPT gives you a study: 'A 2022 study in the Journal of Nursing Research found a 71% improvement.' What is the right next move?","options":[{"id":"a","label":"Copy the citation into Google and try to find the actual study; if you cannot find it, treat the claim as false.","is_correct":true,"explanation":"Correct. Named sources must be verified against the original, and an unfindable citation should be treated as fabricated, not as probably fine."},{"id":"b","label":"Ask ChatGPT 'are you sure that study is real?' and trust its reply.","is_correct":false,"explanation":"The model cannot reliably check its own claims; it may double down or invent a new wrong answer. Verify outside the tool."},{"id":"c","label":"Use it, because the exact percentage and named journal show it is well-sourced.","is_correct":false,"explanation":"Over-specific detail is exactly how hallucinations disguise themselves. Precision is not proof; verify the original."}]}$lum$::jsonb, false),
  ($lum$6aa60bbc-df91-5b93-b1d6-da62c9a8ab64$lum$::uuid, $lum$3c690267-cbaf-5596-b072-115de24e0cc3$lum$::uuid, 12, $lum$mini_project$lum$, $lum${"brief":"Run a real verification pass on something AI helped you write for work. Take a document where you used ChatGPT and that contains facts, statistics, sources, dates, or rules: a report, a patient handout, a client summary, a policy explainer, anything that will leave your desk.","parts":[{"id":"1","prompt":"Step one: Highlight every load-bearing fact in the document, the specific numbers, named sources, dates, quotes, and any claim about something recent. These are the parts that hurt if they are wrong."},{"id":"2","prompt":"Step two: Verify each highlighted fact against a real source on Google or in the original document, not by asking ChatGPT. Mark each one confirmed, corrected, or removed. Note how many you found that were wrong or unverifiable. Keep this two-step check as your standard habit before anything AI-assisted goes out with your name on it."}]}$lum$::jsonb, false),
  ($lum$3f2451e1-2264-5bf4-a97a-27b6d3a7bd4f$lum$::uuid, $lum$849b2638-cf39-5842-a9cc-96d99fa1d407$lum$::uuid, 0, $lum$reading$lum$, $lum${"markdown":"Forget the science-fiction version. A tool like ChatGPT is not a brain, not a search engine, and not a database of facts it looks things up in. Here's the one idea worth holding onto:\n\n**It predicts the next likely word, over and over, very fast.** You give it some text, and it produces the words that most plausibly come next, based on patterns it learned from an enormous amount of writing. That's it. There is no fact-checker inside, no little librarian confirming each claim. It's a spectacularly good guesser of what *sounds* right.\n\nOnce that clicks, the tool's whole personality makes sense.\n\n**Why it's great at some things.** Drafting an email, rephrasing a paragraph, brainstorming names, explaining a concept in simpler words, turning messy notes into clean prose: these are pattern tasks. The model has seen millions of examples, so its \"what comes next\" guesses are excellent. This is where it shines and where you should reach for it first.\n\n**Why it confidently gets things wrong.** Ask for a specific statistic, a court case, a quote, or yesterday's news, and it will still produce something that *sounds* authoritative, because sounding right is the only thing it's optimized to do. It has no built-in sense of true versus false. This is why it can invent a fake citation with a straight face. It isn't lying; it's pattern-matching past the edge of what it actually knows.\n\n**The practical takeaway:** trust it for shape, not for facts. Lean on it to draft, rephrase, structure, and explain. Verify anything specific, factual, recent, or high-stakes before you rely on it. Hold that line and most \"AI burned me\" stories simply never happen to you."}$lum$::jsonb, false),
  ($lum$033b0342-e3d0-533a-885a-cb8a3b7800ef$lum$::uuid, $lum$849b2638-cf39-5842-a9cc-96d99fa1d407$lum$::uuid, 1, $lum$multiple_choice$lum$, $lum${"stem":"Based on how a chatbot works, which task is it most naturally reliable for?","options":[{"id":"a","label":"Telling you the exact revenue a public company reported last quarter","is_correct":false,"explanation":"That's a specific, factual, recent number. The model predicts plausible text, so it may state a confident but wrong figure. Verify facts like this at the source."},{"id":"b","label":"Rewriting a blunt email so it sounds warmer and more professional","is_correct":true,"explanation":"Exactly. Rephrasing for tone is a pattern task, and predicting fluent, natural text is precisely what the model is built to do well."},{"id":"c","label":"Listing the page numbers where a fact appears in a specific book","is_correct":false,"explanation":"Precise citations are a classic place the model invents convincing-looking but fake details. Treat any specific reference as unverified until you check it."}]}$lum$::jsonb, false),
  ($lum$222e6092-a4df-5949-bb9e-c06e9e7fa8e6$lum$::uuid, $lum$849b2638-cf39-5842-a9cc-96d99fa1d407$lum$::uuid, 2, $lum$mini_project$lum$, $lum${"brief":"Your 5-minute exercise: ask AI to do two things back to back. First, \"rewrite this sentence to sound more confident: [paste any sentence].\" Then, \"what was the exact closing price of Apple stock on this day last year?\" Notice how fluent and useful the first answer is, and how the second one should make you reach for a real source. That contrast is the whole lesson.","parts":[]}$lum$::jsonb, false),
  ($lum$39d497fe-834d-5535-a02a-18e8d14f9342$lum$::uuid, $lum$fecbad02-d871-5221-95d0-9e2a34de1eeb$lum$::uuid, 0, $lum$reading$lum$, $lum${"markdown":"People rarely get burned by AI because the tool is bad. They get burned because they hand it a job it was never built to do. Once you know where it genuinely breaks down, you can use it hard for the right things and stay out of trouble on everything else. Almost every limit traces back to one fact: a tool like ChatGPT does not look things up and does not know anything. It predicts the next most likely word based on patterns in the text it was trained on. That single fact explains every limit below.\n\nIt cannot reliably give you current facts. The model learned from text up to a cutoff date and has no live connection to the world. It does not know what happened this week, what your company's policy says today, or what a price is right now, unless you paste that information in yourself. Worse, when it does not know, it usually does not stop. It invents a confident answer, a hallucination, that looks exactly as polished as a real one. So when Tom, an office manager, asked it for \"the current mileage reimbursement rate,\" he got a clean number that was two years out of date, with no warning at all.\n\nIt cannot do reliable math or counting on its own. This surprises people, because computers are supposed to be good at math. But ChatGPT is not calculating; it is predicting what the answer probably looks like. It can lay out the right steps and then quietly fumble the arithmetic, or miscount items in a list. When Dana, a bookkeeper, asked it to total a column of expenses, the steps were perfect and the sum was off by ninety dollars. Any number that matters must be checked, ideally in an actual calculator or spreadsheet."}$lum$::jsonb, false),
  ($lum$3fdcc053-e62c-5516-b2db-2f5622117813$lum$::uuid, $lum$fecbad02-d871-5221-95d0-9e2a34de1eeb$lum$::uuid, 1, $lum$multiple_choice$lum$, $lum${"stem":"Your boss asks for last quarter's exact revenue figure to put in a board deck. Why is ChatGPT the wrong place to get that number?","options":[{"id":"a","label":"It has no live access to your company's data and may invent a confident, wrong figure, so the number must come from your actual records.","is_correct":true,"explanation":"Correct. AI cannot know your private, current data and will produce a plausible-looking number anyway. Pull it from your real financial records."},{"id":"b","label":"ChatGPT refuses to answer questions about money.","is_correct":false,"explanation":"It will happily produce a number. The problem is it cannot know your real figure and may fabricate one that looks legitimate."},{"id":"c","label":"It is fine as long as you ask politely and clearly.","is_correct":false,"explanation":"No phrasing gives the model access to your private financial data. It still cannot know your actual revenue."}]}$lum$::jsonb, false),
  ($lum$4105182f-dc7f-54fc-b554-fe5ee3bfdf49$lum$::uuid, $lum$fecbad02-d871-5221-95d0-9e2a34de1eeb$lum$::uuid, 2, $lum$reading$lum$, $lum${"markdown":"It cannot know your private context. It does not know your client's name, your last email, your team's deadline, or what is in your files, unless you tell it. By default it is not connected to your inbox, your calendar, your shared drive, or your company systems. It is a stranger who is brilliant with words but knows nothing about your specific world until you brief it. This is also why pasting sensitive information into a public AI tool is risky: you are handing private details to an outside system.\n\nIt cannot exercise true judgment or take accountability. It can imitate the shape of advice, but it does not understand stakes, ethics, or consequences, and it cannot be held responsible when it is wrong. The responsibility never transfers to the tool. A nurse who uses AI to draft a patient note still signs that note and owns every word. A paralegal who uses AI to summarize a contract still owns the summary in front of the partner. A teacher who uses AI to write a parent email still answers for what it says. The accountability stays with the human, always.\n\nIt cannot verify its own claims. If you ask \"are you sure?\" it cannot actually go check. It will often just produce another confident-sounding answer, sometimes doubling down on a wrong one, sometimes flipping to a different wrong one. It has no way to look up whether what it just said is true. Verification has to come from you, against a real source, outside the tool. Picture Leah, a marketing coordinator, who got a campaign launch date from ChatGPT and typed back \"are you certain about that date?\" The model apologized and offered a completely different date, just as confidently. She had no way to know which one, if either, was right, because both were predictions, not lookups. The \"are you sure\" loop feels like quality control but produces nothing you can trust."}$lum$::jsonb, false),
  ($lum$7a6f327d-2bfe-5c27-af68-0c47beb7b795$lum$::uuid, $lum$fecbad02-d871-5221-95d0-9e2a34de1eeb$lum$::uuid, 3, $lum$multiple_choice$lum$, $lum${"stem":"You ask AI to summarize a contract and it does a great job. The summary turns out to contain a serious error that costs the client. According to the reading, who is accountable?","options":[{"id":"a","label":"The AI tool, since it produced the summary.","is_correct":false,"explanation":"The reading is explicit that responsibility never transfers to the tool. It cannot be held responsible when it is wrong."},{"id":"b","label":"Nobody, because everyone knows AI makes mistakes.","is_correct":false,"explanation":"The accountability does not disappear. It stays with the human who used the tool and owned the work."},{"id":"c","label":"The human who used it and owns the summary, because accountability never transfers to the tool.","is_correct":true,"explanation":"Correct. As the reading puts it, the paralegal who uses AI to summarize a contract still owns the summary. The accountability stays with the human, always."}]}$lum$::jsonb, false),
  ($lum$11d86c92-36f0-54be-8621-87d5fc262e88$lum$::uuid, $lum$fecbad02-d871-5221-95d0-9e2a34de1eeb$lum$::uuid, 4, $lum$reading$lum$, $lum${"markdown":"It cannot follow your evolving situation in real time. The model only knows what is in front of it in the current conversation. It does not remember that your project scope changed last Tuesday, that a teammate already handled the budget line, or that the client moved the meeting. If a detail is not in the chat, it is not in the model's head. Owen, a project lead, asked it to \"update the plan we discussed,\" forgetting the model had no record of the new constraints from his call that morning. It produced a confident plan built on the old assumptions. Anything situational has to be supplied fresh, every time.\n\nSo what should you never fully delegate? Anything where being wrong has real consequences and the responsibility is yours: final medical, legal, or financial decisions; sending current facts you have not verified; math that money or safety depends on; and anything involving private or confidential information you would not hand to a stranger. Use AI to draft, explain, restructure, and brainstorm. Keep the judgment, the verification, and the final sign-off for yourself.\n\nNone of this makes AI weak. It makes it a brilliant first-draft engine and a poor final authority. The whole game is to let it get you to eighty percent fast, then bring your own judgment, your private context, and your verification to the last twenty percent. People who understand this get enormous value with very little risk. People who skip it end up explaining to their boss why the confident document they sent was wrong."}$lum$::jsonb, false),
  ($lum$812dee76-d26b-54e4-85f9-8210e2a7b399$lum$::uuid, $lum$fecbad02-d871-5221-95d0-9e2a34de1eeb$lum$::uuid, 5, $lum$multiple_choice$lum$, $lum${"stem":"Owen asks AI to \"update the plan we discussed,\" but it had no record of the new constraints from his morning call. Why did it confidently produce a plan built on old assumptions?","options":[{"id":"a","label":"Because it was having a bad day and made a one-time mistake.","is_correct":false,"explanation":"This is not a glitch. The model simply cannot follow your evolving situation; it only knows what is in the current conversation."},{"id":"b","label":"Because the model only knows what is in front of it in the chat, so details not supplied are not in its head.","is_correct":true,"explanation":"Correct. The reading explains that if a detail is not in the chat, it is not in the model's head, so anything situational has to be supplied fresh every time."},{"id":"c","label":"Because it secretly remembered the wrong details from the call.","is_correct":false,"explanation":"It had no record of the call at all. It cannot remember things outside the current conversation, which is exactly the limit at play."}]}$lum$::jsonb, false),
  ($lum$c7c2240b-bb34-5b1a-ab1b-0178f8435d1f$lum$::uuid, $lum$fecbad02-d871-5221-95d0-9e2a34de1eeb$lum$::uuid, 6, $lum$reading$lum$, $lum${"markdown":"The most common mistake is treating AI as a search engine for current facts. People ask it for today's prices, this week's news, or what their policy says now, and accept the confident reply. Because it cannot know recent or private facts, it fills the gap with a hallucination that looks identical to a real answer. The fix is to never ask the model for a fact it cannot know. Get current and private facts from the real source, then paste them in so the model only has to do the wording.\n\nThe second mistake is trusting its math. People assume a computer is automatically good with numbers and copy its totals straight into invoices or reports. But it is predicting what the answer looks like, not calculating, so it can be quietly off. The fix is to treat any number that matters as unverified until you confirm it in a real calculator or spreadsheet, and to never let AI be the final arithmetic on anything involving money or safety.\n\nThe third mistake is assuming the tool shares the blame when something goes wrong. It does not. \"The AI told me\" has never protected anyone whose name was on the document. Consider an accountant who lets ChatGPT classify a client's expenses and files the return without reviewing the categories. When the deduction is challenged, the tax authority does not write to the chatbot. It writes to the accountant, whose license and reputation are on the line. The model felt like a colleague sharing the work, but accountability never left the human chair. The fix is to mentally keep ownership of everything you send: if your name signs it, you verified it, and you stand behind it, no matter how much AI helped draft it."}$lum$::jsonb, false),
  ($lum$36ab4688-a2c9-5fe2-a664-15a1e7dc5de5$lum$::uuid, $lum$fecbad02-d871-5221-95d0-9e2a34de1eeb$lum$::uuid, 7, $lum$fill_blank$lum$, $lum${"template":"AI cannot reliably do {{1}}, so any number that matters should be confirmed in a real calculator or spreadsheet. And when something goes wrong, the responsibility stays with the {{2}}, never the tool.","blanks":[{"id":"1","accept":["math","arithmetic","counting","calculations"],"ideal":"math"},{"id":"2","accept":["human","person","you","user"],"ideal":"human"}],"explanation":"AI predicts what answers look like rather than calculating, so it can be quietly wrong on numbers, and accountability for any AI-assisted work always stays with the human who signs it."}$lum$::jsonb, false),
  ($lum$f85b1cc1-2d72-5807-bd75-228fd448d16c$lum$::uuid, $lum$fecbad02-d871-5221-95d0-9e2a34de1eeb$lum$::uuid, 8, $lum$reading$lum$, $lum${"markdown":"The fourth mistake is asking the AI to check itself. When something feels off, people type \"are you sure?\" and trust the reply. The model cannot actually verify its own claims; it just generates more plausible text and may confidently repeat or replace the error. The fix is to verify outside the tool, against a real source, every time the stakes are real.\n\nThe last mistake is the most expensive: pasting confidential information into a public AI tool. People drop in client names, patient details, or internal data to get a better draft, forgetting they just sent private information to an outside system. The fix is to strip or anonymize sensitive details before you paste, or use an approved tool your organization has vetted."}$lum$::jsonb, false),
  ($lum$7f5a0572-8a81-5cab-a514-6dc42002310f$lum$::uuid, $lum$fecbad02-d871-5221-95d0-9e2a34de1eeb$lum$::uuid, 9, $lum$multiple_choice$lum$, $lum${"stem":"According to this segment, what is the fix for the most expensive mistake of pasting confidential information into a public AI tool?","options":[{"id":"a","label":"Ask the AI to promise it will keep the information secret.","is_correct":false,"explanation":"A promise from the tool does not protect anything. The information has already gone to an outside system."},{"id":"b","label":"Strip or anonymize sensitive details before you paste, or use an approved tool your organization has vetted.","is_correct":true,"explanation":"Correct. The reading says to remove or anonymize private details first, or rely on a tool your organization has actually vetted."},{"id":"c","label":"Paste it quickly so the system has less time to read it.","is_correct":false,"explanation":"Speed makes no difference. Once private data is in an outside system, the risk is already there."}]}$lum$::jsonb, false),
  ($lum$59a13593-eefb-5972-8108-61dec6e6b360$lum$::uuid, $lum$fecbad02-d871-5221-95d0-9e2a34de1eeb$lum$::uuid, 10, $lum$before_after$lum$, $lum${"question":"Same task, two ways of using AI. Notice which one respects what AI cannot do and keeps you safe.","before_prompt":"What is our company's current refund policy deadline? Write a reply telling the customer when their refund must be requested. (then pasting the answer straight into a customer email)","after_prompt":"Here is our current refund policy text, copied from our official page: [paste the real policy]. Using only this text, write a clear, friendly two-sentence reply telling the customer the deadline to request their refund.","changes":["Stops asking the AI to recall a current fact it cannot know, which is exactly how a hallucination slips into a customer email.","Gives the AI the real, verified policy text so it summarizes from your source instead of inventing one.","Keeps you as the source of truth and lets the AI handle only the wording, which is the part it is actually good at."]}$lum$::jsonb, true),
  ($lum$a1361ea4-0c5c-53fa-a5f0-5f9d3b184755$lum$::uuid, $lum$fecbad02-d871-5221-95d0-9e2a34de1eeb$lum$::uuid, 11, $lum$multiple_choice$lum$, $lum${"stem":"In the strong version above, the policy text is pasted in and the AI is told to use only that text. Which limit of AI does this directly work around?","options":[{"id":"a","label":"That AI cannot know your current, private facts on its own, so you supply the verified source and let it only do the writing.","is_correct":true,"explanation":"Correct. The model has no access to your live policy, so giving it the real text removes the chance to invent one and uses it only for wording."},{"id":"b","label":"That AI is bad at being polite to customers.","is_correct":false,"explanation":"Tone is something AI handles well. The real issue is that it cannot know your current policy, which pasting the text solves."},{"id":"c","label":"That AI cannot write in two sentences.","is_correct":false,"explanation":"Length is not the limit being addressed. The fix targets the model's inability to know your current, private facts."}]}$lum$::jsonb, false),
  ($lum$38a4c59d-9af3-5d29-b17e-a000d91fe04e$lum$::uuid, $lum$fecbad02-d871-5221-95d0-9e2a34de1eeb$lum$::uuid, 12, $lum$mini_project$lum$, $lum${"brief":"Make a one-page \"never delegate\" list for your own job, so you have a clear line between what you hand to AI and what you keep. This becomes a quick reference you actually use before you trust an AI draft.","parts":[{"id":"1","prompt":"Step one: List the tasks in your real role that AI must never finish on its own, the ones where being wrong has real consequences and the responsibility is yours. Be specific to your work: for a nurse that might be final dosing or anything in a signed patient note; for a paralegal, final legal citations and filings; for an HR manager, anything involving an employee's confidential record. For each, write one sentence on why."},{"id":"2","prompt":"Step two: Next to that, list the tasks where AI genuinely helps as a first draft you will check, such as rewording an email, explaining a concept, structuring a document, or brainstorming options. For each, note the one verification step you will always do before it leaves your desk (confirm the numbers, check the source, strip private details). Keep the page where you can glance at it."}]}$lum$::jsonb, false),
  ($lum$3e25a813-d8ab-52d2-9b70-146a42698f18$lum$::uuid, $lum$4c0a103f-20e6-5158-ace5-64db3fb780da$lum$::uuid, 0, $lum$reading$lum$, $lum${"markdown":"Most people treat ChatGPT and Google as two doors to the same room. They are not. They are two completely different machines, and using the wrong one wastes twenty minutes before you give up and switch anyway. Once you understand what each one actually does under the hood, you will pick correctly every time without thinking about it.\n\nHere is the core difference. Google is a librarian. When you type a question, Google does not know the answer. It goes and finds pages other people wrote, ranks them, and hands them to you with the source attached. You can click the link and see exactly where the fact came from. That is why Google is the right tool whenever the answer already exists somewhere in the world and you need to be sure it is true.\n\nChatGPT is a writer, not a librarian. It does not look anything up. It was trained on a huge amount of text, and when you ask it something, it predicts the most plausible-sounding response one word at a time. There is no link to click, no source attached, and its training has a cutoff date, so it has no idea what happened this week. What it is genuinely good at is the kind of thinking a librarian cannot do for you: turning a messy idea into a clear paragraph, explaining a hard concept in plain words, or generating five different versions of something so you can choose."}$lum$::jsonb, false),
  ($lum$be6b0931-37e3-500c-8ad2-20e43831201f$lum$::uuid, $lum$4c0a103f-20e6-5158-ace5-64db3fb780da$lum$::uuid, 1, $lum$multiple_choice$lum$, $lum${"stem":"You need to know the exact current minimum wage in your state to put it in a job posting. Which tool is the right first stop, and why?","options":[{"id":"a","label":"Google, because this is a single verifiable fact that exists in the world and you can check the source.","is_correct":true,"explanation":"Correct. A current legal figure has one right answer with a source you can verify, which is exactly what Google is built for."},{"id":"b","label":"ChatGPT, because it can explain wage law clearly.","is_correct":false,"explanation":"ChatGPT might give an outdated number from before its training cutoff, with no source to check. You need a verifiable current fact here."},{"id":"c","label":"Either one, since both will give the same answer.","is_correct":false,"explanation":"They will not reliably give the same answer. ChatGPT can confidently state a wrong or outdated figure, while Google links you to the real source."}]}$lum$::jsonb, false),
  ($lum$d60be1ea-3fe5-5e45-bb7b-541d4bdc9322$lum$::uuid, $lum$4c0a103f-20e6-5158-ace5-64db3fb780da$lum$::uuid, 2, $lum$reading$lum$, $lum${"markdown":"So here is the test. Before you type your question anywhere, ask yourself one thing: does this question have a single correct answer that already exists out in the world? If yes, go to Google. If the answer needs to be created, reasoned through, rewritten, or judged, go to ChatGPT. That is the whole 10-second test.\n\nLet me make this concrete with three real situations.\n\nMaria is an office manager. She needs to know whether the company can deduct a client lunch on this year's taxes. This has one correct answer that exists in tax rules, and getting it wrong has real consequences. This is a Google question. If she asks ChatGPT, it will give her a confident, polished answer that might be based on tax rules from three years ago, and she will have no way to tell. She should Google the current IRS guidance, or better, ask her accountant.\n\nDavid teaches eighth-grade science. He has to send a tricky email to a parent whose child is failing, and he is dreading writing it. There is no \"correct\" email sitting on a web page. This needs to be created with care and tone. This is a ChatGPT question. He can tell it the situation, the tone he wants (firm but warm), and the facts, and it will draft something he can edit in two minutes instead of agonizing for thirty.\n\nPriya is an HR manager comparing two health insurance plans for the company. This one needs both tools, and this is where most people miss out. She uses Google to pull the actual plan documents and current premium numbers from the insurers, because those are verifiable facts that must be exactly right. Then she pastes the real details into ChatGPT and asks it to build a side-by-side comparison table and explain the tradeoffs in plain language for her team. Google supplied the facts. ChatGPT did the thinking. Neither tool could have done both halves well."}$lum$::jsonb, false),
  ($lum$7b50c9d0-1de8-5674-ba7c-0637efb7f072$lum$::uuid, $lum$4c0a103f-20e6-5158-ace5-64db3fb780da$lum$::uuid, 3, $lum$fill_blank$lum$, $lum${"template":"When a question has one correct answer that already exists in the world, use {{1}} so you can verify the source. When the answer must be created or reasoned through, use {{2}}.","blanks":[{"id":"1","accept":["google","search","a search engine"],"ideal":"Google"},{"id":"2","accept":["chatgpt","chat gpt","an ai chatbot","ai"],"ideal":"ChatGPT"}],"explanation":"The whole decision comes down to whether the answer already exists and must be verified (Google) or needs to be created and reasoned through (ChatGPT)."}$lum$::jsonb, false),
  ($lum$5d4dc936-7a9c-51eb-a1ac-8967c2a3103e$lum$::uuid, $lum$4c0a103f-20e6-5158-ace5-64db3fb780da$lum$::uuid, 4, $lum$reading$lum$, $lum${"markdown":"One more case shows the trap from the other direction. Sam runs a small bakery and wants to write a punchy Instagram caption for a new seasonal pastry. He starts Googling \"best bakery captions\" and scrolls through pages of recycled one-liners, none of which mention his pistachio croissant or his neighborhood. That is wasted effort, because there is no correct caption waiting on a web page. The moment he switches to ChatGPT, describes the pastry, and asks for five caption options in a warm, slightly playful voice, he gets tailored choices in seconds. The lesson cuts both ways: Google is useless for creation, and ChatGPT is unsafe for verifiable facts. Sam was reaching for the librarian when he needed the writer.\n\nThat last pattern has a name: research synthesis. You use Google to find the primary sources, because a source you can verify is the whole point of facts. Then you use ChatGPT to help you understand, compare, and summarize what you found. This combination is the single most useful AI habit a knowledge worker can build, and almost nobody does it on purpose.\n\nOne more thing to keep in your head. ChatGPT recently gained some ability to search the web inside certain modes, which blurs this line a little. That is helpful, but it does not change the mental model. When accuracy matters and you need to point to a source, you still want to see and verify that source yourself. The librarian-versus-writer distinction is still the safest way to think, because it keeps you in the habit of asking \"can I verify this?\" before you trust an answer with your name on it.\n\nThe payoff is simple. Match the tool to the job and you stop getting confident-sounding wrong answers from the writer, and you stop getting fourteen generic listicles from the librarian when you actually needed something written for your exact situation."}$lum$::jsonb, false),
  ($lum$dc14671c-c6f1-522d-8edf-e45df64db6e8$lum$::uuid, $lum$4c0a103f-20e6-5158-ace5-64db3fb780da$lum$::uuid, 5, $lum$multiple_choice$lum$, $lum${"stem":"Sam Googled \"best bakery captions\" and got nowhere. According to this segment, why was that wasted effort?","options":[{"id":"a","label":"Because Google ranks bakery pages poorly compared to other businesses.","is_correct":false,"explanation":"The problem was not ranking. The issue is that there is no correct caption sitting on a web page for Google to find."},{"id":"b","label":"Because he should have searched for captions about croissants specifically.","is_correct":false,"explanation":"A narrower search would still return recycled one-liners. The point is that a caption for his pastry has to be created, not retrieved."},{"id":"c","label":"Because there is no correct caption waiting on a web page, so creation is a ChatGPT job, not a Google job.","is_correct":true,"explanation":"Right. A caption tailored to his pistachio croissant must be created, which is what ChatGPT does well and what Google cannot do."},{"id":"d","label":"Because he needed to verify the caption against a source first.","is_correct":false,"explanation":"Verification matters for facts, not for creative writing. This was a creation task, so there was nothing to verify."}]}$lum$::jsonb, false),
  ($lum$e85920b1-e6ae-5236-9e64-12a3a238ead7$lum$::uuid, $lum$4c0a103f-20e6-5158-ace5-64db3fb780da$lum$::uuid, 6, $lum$reading$lum$, $lum${"markdown":"The most common mistake is asking ChatGPT for current facts. People type \"what is the current interest rate?\" or \"what does my state's overtime law say?\" and get a clean, confident answer. The danger is that the answer looks identical whether it is right or invented. ChatGPT has no live connection to the world and a training cutoff, so for anything recent or anything legal, it is often guessing in a very convincing voice. The fix: any time you catch yourself wanting a current number, a price, a date, or what an official rule actually says, route that to Google instead. If you must use ChatGPT, paste the real fact in yourself and let it only do the writing.\n\nThe opposite mistake is just as common: Googling things that need to be created. People search \"how should I word a layoff announcement?\" or \"performance review template for a defensive employee\" and scroll through fourteen listicles that are generic, padded with ads, and not about their actual situation. None of those pages knows your employee, your tone, or your facts. This is a creation task, and ChatGPT will produce something tailored in one pass. The fix: if you are searching for how to write, phrase, structure, or explain something specific to your situation, that is a ChatGPT job, not a Google job."}$lum$::jsonb, false),
  ($lum$2312dc55-933f-5c8c-b74c-14d3aadfef1d$lum$::uuid, $lum$4c0a103f-20e6-5158-ace5-64db3fb780da$lum$::uuid, 7, $lum$multiple_choice$lum$, $lum${"stem":"According to this segment, why is the answer ChatGPT gives to \"what does my state's overtime law say?\" so risky?","options":[{"id":"a","label":"Because ChatGPT refuses to answer legal questions.","is_correct":false,"explanation":"ChatGPT will usually answer. The risk is not refusal; it is that the answer can be wrong in a convincing way."},{"id":"b","label":"Because the answer looks identical whether it is right or invented, and ChatGPT has no live connection and a training cutoff.","is_correct":true,"explanation":"Correct. A confident answer reads the same whether it is accurate or guessed, and ChatGPT cannot check current or legal facts, so route those to Google."},{"id":"c","label":"Because ChatGPT always adds too many sources you have to read.","is_correct":false,"explanation":"The opposite is true: ChatGPT attaches no source to click, which is part of why current facts are risky to ask it for."},{"id":"d","label":"Because overtime law is the same in every state, so the question is pointless.","is_correct":false,"explanation":"Overtime rules vary, which is exactly why you want a verifiable current source from Google rather than a guess."}]}$lum$::jsonb, false),
  ($lum$8f68bc42-f79c-5ba9-8ad9-9e3f7e944846$lum$::uuid, $lum$4c0a103f-20e6-5158-ace5-64db3fb780da$lum$::uuid, 8, $lum$reading$lum$, $lum${"markdown":"A third trap is the all-or-nothing belief that you should pick one tool and stick with it for the whole task. Research is where this costs you the most. People either trust ChatGPT alone and end up with unverifiable claims, or they bury themselves in twenty Google tabs and never synthesize anything. The fix is to deliberately split the work: Google for the verifiable inputs, ChatGPT for the reasoning on top of them. Naming it out loud (\"now I am gathering facts, now I am synthesizing\") keeps you from collapsing the two steps.\n\nThe last misconception is the most dangerous because it sounds responsible: \"I will just double-check ChatGPT's facts with Google afterward.\" In practice almost nobody does, because a confident answer feels finished, and verifying is boring. Picture a recruiter who asks ChatGPT for the current H-1B filing fee, gets a tidy figure, and tells herself she will confirm it before the deadline. The number sits in her draft looking official, the deadline rush arrives, and the unchecked figure ships to a client. The better habit is to never ask ChatGPT for the fact in the first place. Get the fact from Google up front, then hand it to ChatGPT. You cannot forget to verify a fact you never asked the writer to invent."}$lum$::jsonb, false),
  ($lum$35340be0-42cb-588d-bb39-8707e0f37b3c$lum$::uuid, $lum$4c0a103f-20e6-5158-ace5-64db3fb780da$lum$::uuid, 9, $lum$multiple_choice$lum$, $lum${"stem":"This segment calls \"I will just double-check ChatGPT's facts with Google afterward\" the most dangerous misconception. What does it suggest you do instead?","options":[{"id":"a","label":"Double-check the facts twice to be safe.","is_correct":false,"explanation":"Checking twice still relies on a verify-later step that the segment says almost nobody actually does."},{"id":"b","label":"Trust the confident answer, since a finished-looking answer is usually correct.","is_correct":false,"explanation":"The segment warns that a confident answer only feels finished, which is exactly why people skip verifying it."},{"id":"c","label":"Stick with one tool for the whole task to keep things simple.","is_correct":false,"explanation":"That is the all-or-nothing trap from earlier. The fix here is about where the fact comes from, not about using a single tool."},{"id":"d","label":"Never ask ChatGPT for the fact at all: get it from Google up front, then hand it to ChatGPT.","is_correct":true,"explanation":"Right. You cannot forget to verify a fact you never asked the writer to invent, so source it from Google first."}]}$lum$::jsonb, false),
  ($lum$ac5bffaa-23a7-5b89-b6d0-2c622cc1649d$lum$::uuid, $lum$4c0a103f-20e6-5158-ace5-64db3fb780da$lum$::uuid, 10, $lum$before_after$lum$, $lum${"question":"You are comparing two project management tools to recommend one to your boss. Here is the weak way and the strong way to use AI for it.","before_prompt":"Which is better for my team, Asana or Trello? Give me the current pricing and a recommendation.","after_prompt":"I pulled these details from each company's pricing page today: [paste Asana plan, price, and key features] and [paste Trello plan, price, and key features]. Using only these details, build a side-by-side comparison table and explain in plain language which fits a 6-person marketing team that needs deadline tracking.","changes":["Stops asking ChatGPT to recall current pricing, which it cannot know reliably and may invent.","Uses Google first to grab the verifiable facts from the real pricing pages, then hands them to ChatGPT.","Lets ChatGPT do what it is good at: synthesizing the facts into a clear comparison for your specific team."]}$lum$::jsonb, true),
  ($lum$5b3b1884-9a6a-5f24-a766-92622033f5b0$lum$::uuid, $lum$4c0a103f-20e6-5158-ace5-64db3fb780da$lum$::uuid, 11, $lum$multiple_choice$lum$, $lum${"stem":"In the strong version above, why is it better to paste the pricing in yourself rather than ask ChatGPT to find it?","options":[{"id":"a","label":"Because ChatGPT cannot reliably know current prices, so giving it the verified facts prevents it from inventing them and lets it focus on synthesis.","is_correct":true,"explanation":"Exactly. You supply the verifiable facts from Google and let ChatGPT do the reasoning, which is the research synthesis pattern."},{"id":"b","label":"Because ChatGPT works faster when you give it less to read.","is_correct":false,"explanation":"Speed is not the point. The point is accuracy: ChatGPT cannot verify current prices, so you provide them."},{"id":"c","label":"Because pasting text is the only way ChatGPT can make a table.","is_correct":false,"explanation":"ChatGPT can make tables from many inputs. The reason to paste is to give it verified facts it cannot reliably retrieve itself."}]}$lum$::jsonb, false),
  ($lum$47bbdcef-38d7-50fe-abfa-aedb218ba477$lum$::uuid, $lum$4c0a103f-20e6-5158-ace5-64db3fb780da$lum$::uuid, 12, $lum$mini_project$lum$, $lum${"brief":"Build a real research brief for a decision you actually have to make at work this month: which vendor to pick, which plan to recommend, which policy to adopt, or something similar. Do it in two clearly separate steps so you practice the synthesis pattern.","parts":[{"id":"1","prompt":"Step one (Google): Find and write down the verifiable facts from primary sources. Pull current prices, official policy language, real feature lists, or actual dates, and note the source link next to each one so you can prove it later."},{"id":"2","prompt":"Step two (ChatGPT): Paste those verified facts into ChatGPT and ask it to build a side-by-side comparison and a plain-language recommendation for your specific situation (name your team size, your constraints, and what matters most). Then read it critically and edit it in your own voice. The finished one-page brief is something you can send to your boss or team."}]}$lum$::jsonb, false),
  ($lum$36d0bba3-31db-5ce8-a773-988350276bc7$lum$::uuid, $lum$cf17c072-349e-5c46-8281-d17d4183041a$lum$::uuid, 0, $lum$reading$lum$, $lum${"markdown":"The AI landscape looks overwhelming: ChatGPT, Claude, Gemini, Copilot, and a new logo every week. The good news is that for everyday work, the differences between the big chat assistants are smaller than the marketing suggests. You do not need to pick the perfect one. You need to pick one and learn it well. Here's how to cut through the noise.\n\n**The big chat assistants are broadly interchangeable for beginners.** ChatGPT, Claude, and Gemini all draft, summarize, explain, and brainstorm at a high level. If your workplace already provides one (Copilot and Gemini often come bundled with email and documents), start there: it's free to you and already connected to your work. Otherwise, pick the one your colleagues use so you have people to ask. Switching later is easy; the skills transfer.\n\n**The one setting that changes the answer: is it online?** This matters more than which brand you chose. Some AI tools answer only from what they learned during training, which has a cutoff date in the past. Others can browse the live web and cite current sources. The difference is enormous:\n\n- **Offline mode** is fine for timeless tasks: rewriting, explaining a concept, drafting from information you provide.\n- **Online mode** is what you need for anything current: today's news, recent prices, a company's latest announcement, \"what changed this year.\"\n\nIf you ask an offline tool about a recent event, it won't say \"I don't know.\" It will confidently make something up. So before you trust an answer about anything recent, ask yourself: *could this tool actually have seen this?* Many assistants now browse automatically and show source links; when you see real, clickable citations, you're in online mode. When you don't, assume the answer is frozen in the past.\n\n**The practical rule:** one mainstream assistant, learned well, covers the vast majority of your work. Just stay aware of whether it's drawing on live information or its frozen training, because that's the line between a useful answer and a confident fiction."}$lum$::jsonb, false),
  ($lum$085c1989-7bd0-58b2-a462-6f2563b0b720$lum$::uuid, $lum$cf17c072-349e-5c46-8281-d17d4183041a$lum$::uuid, 1, $lum$fill_blank$lum$, $lum${"template":"If a task depends on {{1}} information, you need a tool in {{2}} mode; for timeless tasks like rewriting, an {{3}} tool is fine.","blanks":[{"id":"1","accept":["current","recent","live","up-to-date","new"],"ideal":"current"},{"id":"2","accept":["online","browsing","web","connected"],"ideal":"online"},{"id":"3","accept":["offline","frozen"],"ideal":"offline"}],"explanation":"Whether the tool can reach the live web is the setting that decides if an answer about anything recent can be trusted."}$lum$::jsonb, false),
  ($lum$6554c012-41c4-5ebd-8c33-9d21f246ee86$lum$::uuid, $lum$cf17c072-349e-5c46-8281-d17d4183041a$lum$::uuid, 2, $lum$mini_project$lum$, $lum${"brief":"Your 3-minute exercise: open whichever assistant you have access to and ask it one current-events question, like \"what major thing happened in the news this week?\" Look at the answer. Does it show real source links you can click? If yes, it's browsing live. If it gives a vague or oddly dated answer with no links, it's working from frozen training, and now you know the difference for everything you ask next.","parts":[]}$lum$::jsonb, false),
  ($lum$db6a0282-32af-5395-859f-6061cbff9788$lum$::uuid, $lum$1bf42333-a27b-5898-8458-43b8d8a35ca7$lum$::uuid, 0, $lum$reading$lum$, $lum${"markdown":"If you've been avoiding AI, it's usually one of two reasons. Either you feel like everyone else already figured it out and you missed the bus, or some part of you feels that leaning on it is cutting corners. Let's take both apart, because both are holding you back for no good reason.\n\n**You're not behind.** The tools most people use today became genuinely useful only recently. The person at work who seems fluent has been at it for months, not decades. There is no advanced track you failed to enroll in. Almost everyone is figuring this out at the same time, in public, by trial and error. A few focused hours puts you ahead of most of your colleagues, not because you're special, but because most people haven't sat down to actually try.\n\n**It's not cheating.** When calculators arrived, people worried that using them was a way to avoid real math. Today nobody thinks twice. AI is the same kind of shift. Using it to draft an email, summarize a report, or untangle a messy idea is not skipping the work: it's doing the work faster so your judgment goes where it matters. The skill that counts now is knowing what to ask, spotting when the answer is wrong, and deciding what to keep. That is real work, and it's the skill this course builds.\n\n**The only real mistake is not starting.** Every hour you wait, the gap between you and the people who started feels bigger, even though it isn't. The fix is not to study harder. It's to open the tool and use it for one small thing today. Competence comes from reps, not from reading about reps.\n\nSo drop the guilt and drop the catching-up story. You're early, you're allowed, and the next lesson gets your hands dirty."}$lum$::jsonb, false),
  ($lum$0614c80c-b1db-510e-89b4-fd3d67cc86e8$lum$::uuid, $lum$1bf42333-a27b-5898-8458-43b8d8a35ca7$lum$::uuid, 1, $lum$mini_project$lum$, $lum${"brief":"Your 3-minute exercise: write down the one task you've been *not* using AI for because it felt like cheating or because you assumed it was too late to learn. Just name it. You'll come back to that exact task by the end of this module and do it with AI, on purpose, with a clear conscience.","parts":[]}$lum$::jsonb, false),
  ($lum$49702f37-0735-5a15-9400-c89fad0f057b$lum$::uuid, $lum$d14e9d54-e16a-50d2-b2e3-2436208ccd1e$lum$::uuid, 0, $lum$reading$lum$, $lum${"markdown":"Handoffs are where care continuity breaks. Research has put preventable handoff-related adverse events at a significant slice of total hospital harm. You already know this from experience: the 3am admission whose medication allergy never made it to the dayshift, the post-surgical patient whose blood pressure trend got summarized as \"a little low\" and lost its urgency by the time it reached the oncoming nurse. SBAR exists to prevent exactly this, but the format only works if the content is complete and the structure is tight. That is where AI enters the picture.\n\n**What AI actually does in this workflow**\n\nThe tool does not know your patient. It has not seen the chart, assessed the lung sounds, or watched the family's face when you explained the plan. What it can do is take the fragments you carry in your head and your shift notes and organize them into a clean, scannable structure. You bring the clinical knowledge. The tool brings the format. That division of labor is the whole point.\n\nHere is the prompt you will use:\n\n*\"Reformat these de-identified shift notes into an SBAR handoff for the oncoming nurse. Situation: current status and the key concern right now. Background: relevant history, admission reason, and any significant past medical history that affects today. Assessment: my clinical read on what is happening and what I am watching. Recommendation: specific actions, things to monitor, and any pending results the next nurse needs to follow up on. Use only the information I provide. Do not add vitals, findings, interventions, or details that I have not stated.\"*\n\nThat final instruction is not boilerplate. It is the guardrail that separates a useful handoff tool from a liability. More on that in the next section."}$lum$::jsonb, false),
  ($lum$0027e834-f990-5c74-abb2-36961ef60840$lum$::uuid, $lum$d14e9d54-e16a-50d2-b2e3-2436208ccd1e$lum$::uuid, 1, $lum$multiple_choice$lum$, $lum${"stem":"A nurse pastes her shift notes into the SBAR prompt and gets back a draft that includes 'patient received Lasix 40mg IV at 1700 per order.' She never mentioned Lasix in her notes. What happened and what should she do?","options":[{"id":"a","label":"The AI pulled the medication from the EMR in the background. She should verify it against the MAR before using it.","is_correct":false,"explanation":"Consumer and most enterprise AI tools do not have access to the EMR. They can only work with what you paste. This is a hallucination, not a retrieval."},{"id":"b","label":"The AI fabricated a plausible clinical detail that was never observed. She should delete it and rerun the prompt with the explicit constraint not to add details she did not state.","is_correct":true,"explanation":"Correct. Without an explicit constraint, the model fills gaps with realistic-sounding content. A hallucinated medication in a handoff can drive the oncoming nurse to document or act on something that never happened. The fix is the constraint phrase: 'Use only what I gave you. Do not add vitals, medications, or findings I did not state.'"},{"id":"c","label":"The AI summarized a medication that was implied by the patient's diagnosis. She should accept it since Lasix is a common order for this presentation.","is_correct":false,"explanation":"Clinical plausibility does not make something true. If you did not observe or document it, it cannot go in the handoff. Accepting implied details is exactly how fabrication enters the medical record."},{"id":"d","label":"The AI made a formatting error. She should resubmit without changing the prompt.","is_correct":false,"explanation":"This is not a formatting error. The model generated clinical content that was not in the input. Resubmitting without changing the prompt will likely produce the same result."}]}$lum$::jsonb, false),
  ($lum$4009dd5d-a299-58a5-b6f0-dc3e2ec88960$lum$::uuid, $lum$d14e9d54-e16a-50d2-b2e3-2436208ccd1e$lum$::uuid, 2, $lum$reading$lum$, $lum${"markdown":"**Clinical example 1: Post-op hip patient with a blood pressure trend**\n\nConsider a 72-year-old woman, post-operative day one from a left hip ORIF for a femoral neck fracture. Her baseline systolic runs around 130. At 1400 her BP was 108/64. At 1600 it dropped to 96/58. She received 500 mL of normal saline at 1500. You notified the surgeon at 1630 and got an order for repeat labs at 1800. The patient is alert but says she feels dizzy when she sits up.\n\nYour working notes look like this: \"72F, L hip ORIF POD1, BP trending down, 108 at 2, 96 at 4, got fluid, told surgeon, labs ordered, dizzy with positioning, family at bedside.\"\n\nYou paste those notes with the prompt above. The tool structures: Situation as a post-op hip patient with a hypotensive trend on POD1, Background covering the ORIF and the saline bolus, Assessment noting ongoing hypotension despite fluid, Recommendation flagging the 1800 labs and orthostatic precautions.\n\nWhat you get is not a finished handoff. It is a first draft you now read critically. You confirm the times are right, the interventions match what actually happened, and nothing has been added that you did not state. Then you use it.\n\n**Clinical example 2: A medication change mid-shift with a communication gap**\n\nA 58-year-old man admitted for COPD exacerbation has been on scheduled albuterol nebulizers every four hours. At 1100 the hospitalist discontinued the scheduled nebs and changed him to PRN based on improved breath sounds. The change happened in the EMR but you are not certain the respiratory therapist who covered during your lunch break was notified. The patient also has a new SpO2 order to titrate supplemental oxygen to keep sats between 88 and 92.\n\nYour rough notes: \"58M COPD exacer, albuterol changed from scheduled to PRN at 1100, RT may not know, new O2 titration order 88-92, breath sounds improved, no distress.\"\n\nAfter running that through the prompt, the SBAR Recommendation section will flag: confirm RT is aware of the schedule change, hold scheduled nebs, respond to O2 sat per new titration parameters. The structure surfaces a communication gap you noted but that can easily get compressed or lost in a verbal handoff when the unit is busy."}$lum$::jsonb, false),
  ($lum$c2a3dd32-be9a-58e7-a8fa-0b435b6d3437$lum$::uuid, $lum$d14e9d54-e16a-50d2-b2e3-2436208ccd1e$lum$::uuid, 3, $lum$fill_blank$lum$, $lum${"template":"In Clinical example 1, the post-op hip patient's blood pressure dropped from 108/64 at 1400 to {{1}} at 1600, and she received 500 mL of {{2}} at 1500.","blanks":[{"id":"1","accept":["96/58","96 over 58"],"ideal":"96/58"},{"id":"2","accept":["normal saline","saline","NS","0.9% saline"],"ideal":"normal saline"}],"explanation":"The example gives a BP trend of 108/64 at 1400 falling to 96/58 at 1600, with a 500 mL normal saline bolus at 1500. These are the precise values the nurse paraphrases into the notes, and they are exactly the kind of specifics the SBAR draft must match against the original notes."}$lum$::jsonb, false),
  ($lum$3c14482c-3464-57d8-956e-1b7f8941bd1a$lum$::uuid, $lum$d14e9d54-e16a-50d2-b2e3-2436208ccd1e$lum$::uuid, 4, $lum$reading$lum$, $lum${"markdown":"**Clinical example 3: A declining elderly patient whose family needs to be part of the plan**\n\nAn 84-year-old man, admitted for a UTI with altered mental status, has not returned to his baseline cognition after 48 hours of IV antibiotics. His daughter, who is his healthcare proxy, is at the bedside and expressed concern this morning that \"he does not seem like himself.\" He had a fall attempt overnight at 0200 caught by staff. The care team discussed goals of care briefly at rounds but no formal family meeting has been documented.\n\nYour rough notes: \"84M, UTI with AMS, day 2 abx, still confused, not back to baseline, daughter proxy concerned, fall attempt 0200, GOC not formally documented.\"\n\nThe tool structures that into a Recommendation that names three discrete items: document the goals of care conversation or initiate a formal meeting, fall precautions are in place but a bed alarm review is warranted, and follow up with the team on whether a delirium consult has been considered. Nothing in that output was invented. All of it came from what you wrote. But now it is organized so the oncoming nurse has a clear action list instead of a vague worry.\n\n**The one non-negotiable before you run any of this**\n\nDo not paste your patient's full name, date of birth, medical record number, or any combination of details that would identify them into a consumer AI product such as a public chatbot, a free web tool, or any application your organization has not specifically approved for use with protected health information. That is a HIPAA violation regardless of how useful the output is. Use initials, a room number, or the word \"the patient.\" If your organization has licensed a healthcare-specific AI tool with a business associate agreement, follow its guidelines for what identifiers are permissible. When in doubt, de-identify first."}$lum$::jsonb, false),
  ($lum$cb74b7e2-fcd9-509f-8e4b-2611db34d8d4$lum$::uuid, $lum$d14e9d54-e16a-50d2-b2e3-2436208ccd1e$lum$::uuid, 5, $lum$multiple_choice$lum$, $lum${"stem":"In Clinical example 3, the 84-year-old man with a UTI and altered mental status had a fall attempt overnight and his daughter (his proxy) is concerned, but no formal family meeting is documented. Why does the AI organize these into a Recommendation action list rather than the nurse simply relying on a verbal mention?","options":[{"id":"a","label":"The AI adds clinical detail the nurse forgot, such as ordering a delirium consult on its own initiative.","is_correct":false,"explanation":"The lesson is explicit that nothing in the output was invented and all of it came from what the nurse wrote. The tool does not add orders or initiate consults on its own."},{"id":"b","label":"A structured action list turns a vague worry into discrete, named items the oncoming nurse can act on, surfacing things that get glossed over in a busy verbal handoff.","is_correct":true,"explanation":"Correct. The example shows the tool organizing the nurse's own notes into three discrete items so the oncoming nurse has a clear action list instead of a vague worry. The structure is the value; the clinical content stays the nurse's."},{"id":"c","label":"The AI replaces the nurse's clinical judgment so the next shift does not have to think about goals of care.","is_correct":false,"explanation":"The tool brings structure, not judgment. The goals-of-care conversation and any delirium workup remain clinical decisions for the team, not something the format decides."},{"id":"d","label":"A written list is required documentation that replaces the family meeting note in the chart.","is_correct":false,"explanation":"The output is a communication aid, not a charted note. It even flags that the goals-of-care conversation still needs to be documented; it does not substitute for that documentation."}]}$lum$::jsonb, false),
  ($lum$1b7bcc0a-4812-52b2-ac91-bb1bb34f1a1f$lum$::uuid, $lum$d14e9d54-e16a-50d2-b2e3-2436208ccd1e$lum$::uuid, 6, $lum$reading$lum$, $lum${"markdown":"**Common mistakes healthcare workers make when using AI for SBAR handoffs**\n\nNurses and coordinators who start using AI for handoffs make a predictable set of errors. They come from habits built around other tools: copy-pasting from the EMR, trusting printed reports, relying on colleagues to fill gaps. AI does not work like any of those things, and the mistakes that transfer are worth naming directly.\n\n**Mistake 1: Pasting patient identifiers into an unapproved tool**\n\nMost nurses know that protected health information cannot leave the organization's approved systems. In practice, when you are eight minutes from shift end, the fastest path is to copy the chart note and paste it into whatever tool is open. That note has the patient's name, MRN, date of birth, and diagnosis. Pasting that into a public consumer chatbot is a HIPAA violation, full stop. The output is not worth the exposure.\n\nWhat to do instead: strip identifiers before you paste. Replace the name with \"the patient\" or initials. Remove the MRN and DOB entirely. Use the room number if you need a reference. If your organization has a BAA-covered tool, learn what it permits and use it exclusively for patient-related work.\n\n**Mistake 2: Trusting AI-generated vitals or findings that were never observed**\n\nThis is the highest-stakes mistake because it travels through the handoff invisibly. You paste notes mentioning a BP trend, and the AI output includes a creatinine value or medication dose that sounds right for the diagnosis but was never in your notes. Without a read-back, that invented detail reaches the next nurse as if it happened.\n\nMost nurses who make this mistake are not skimming carelessly. The AI output is well-formatted, so a plausible-looking lab value scans as real. The fix is a two-part habit: use the explicit constraint phrase in your prompt, and do a read-back where you tick each item against your actual notes. If you cannot find where it came from, it does not go in."}$lum$::jsonb, false),
  ($lum$be842b15-d708-5e75-a47c-dd4a2ea06bfc$lum$::uuid, $lum$d14e9d54-e16a-50d2-b2e3-2436208ccd1e$lum$::uuid, 7, $lum$multiple_choice$lum$, $lum${"stem":"A clinical coordinator is preparing SBAR handoffs for three patients before a care conference. She pastes each patient's chart summary, including full name and MRN, into a popular consumer chatbot to speed things up. The output is accurate and helpful. What is the problem?","options":[{"id":"a","label":"The outputs may not follow the SBAR format precisely, which reduces their usefulness in the conference.","is_correct":false,"explanation":"Format quality is not the issue here. The problem is what was pasted into the tool, not what came out."},{"id":"b","label":"Pasting names and MRNs into an unapproved consumer tool is a HIPAA violation regardless of how accurate or useful the output is.","is_correct":true,"explanation":"Correct. The quality of the output does not change the compliance status of the input. Protected health information sent to a tool without a business associate agreement is a violation, even when the tool is genuinely helpful."},{"id":"c","label":"Consumer chatbots are not able to process clinical language, so the outputs are likely inaccurate.","is_correct":false,"explanation":"Many consumer tools handle clinical language well. The concern is not capability but compliance: PHI cannot go into an unapproved tool."},{"id":"d","label":"The tool may time out on long inputs, causing her to lose the work.","is_correct":false,"explanation":"Technical reliability is not the issue. This is a privacy violation that exists whether or not the tool performs flawlessly."}]}$lum$::jsonb, false),
  ($lum$4ba02d3c-4da7-5300-a95a-b24feb0830be$lum$::uuid, $lum$d14e9d54-e16a-50d2-b2e3-2436208ccd1e$lum$::uuid, 8, $lum$reading$lum$, $lum${"markdown":"**Mistake 3: Sending the draft without reading it back**\n\nThe value of AI-assisted SBAR is a clean draft faster than you could write it yourself. The risk is that the draft becomes the final product without clinical review. The AI does not know that the BP you mentioned was from a positional check, not a resting measurement. It does not know that the family concern you noted was about discharge planning, not about acuity. Context is yours. The tool only has what you typed.\n\nBefore any AI-drafted SBAR leaves your hands, read it back against your actual patient knowledge. One pass, thirty seconds. If a line does not match what you know, fix it or cut it.\n\n**Mistake 4: Using vague language in the input and expecting precise output**\n\n\"BP a little low\" and \"patient seemed off\" are shorthand that works in verbal handoffs between colleagues who share context. They do not give the AI enough to work with, and the output will be vague or, worse, will fill gaps with specifics that sound right but were never observed. Put in the number. Put in the time. Put in the specific behavior you noticed. Specificity is what makes an SBAR actionable.\n\n**Mistake 5: Assuming the AI-generated SBAR constitutes documentation**\n\nThe handoff tool produces a communication aid, not a charted note. Do not copy the AI output into the EMR as your nursing note or shift summary without reviewing and editing it to reflect your actual clinical assessment. AI-generated text entered into the record without review is not an accurate representation of your clinical judgment, and an audit will treat it as if it is."}$lum$::jsonb, false),
  ($lum$eebcb6f3-ae27-5df1-93cb-4d54d4be438e$lum$::uuid, $lum$d14e9d54-e16a-50d2-b2e3-2436208ccd1e$lum$::uuid, 9, $lum$multiple_choice$lum$, $lum${"stem":"A nurse mentioned a blood pressure in her notes that she took as a positional (orthostatic) check. The AI-drafted SBAR presents it as a resting measurement. Which mistake does this illustrate, and what is the safeguard?","options":[{"id":"a","label":"Mistake 4, vague input. The fix is to always paste the full chart note including identifiers so the tool has complete context.","is_correct":false,"explanation":"Pasting identifiers would be a HIPAA violation, and the issue here is not that the input was too vague to parse. The tool simply lacks the context that the reading was positional."},{"id":"b","label":"Mistake 3, sending the draft without reading it back. The safeguard is a thirty-second read-back against your own patient knowledge, fixing or cutting any line that does not match.","is_correct":true,"explanation":"Correct. The lesson uses this exact scenario: the AI does not know the BP came from a positional check rather than a resting measurement, because context is yours and the tool only has what you typed. A read-back before the draft leaves your hands catches it."},{"id":"c","label":"Mistake 5, treating the SBAR as documentation. The safeguard is to chart the AI output directly so the record is complete.","is_correct":false,"explanation":"Charting the AI output without review is itself the mistake the lesson warns against. The problem here is an unreviewed mismatch, and copying it into the record would make things worse, not better."},{"id":"d","label":"Mistake 2, trusting fabricated vitals. The safeguard is the constraint phrase, which would have prevented the tool from misreading the value.","is_correct":false,"explanation":"The value was not fabricated; the nurse did provide it. The constraint phrase stops invented details, but it cannot supply context the nurse never typed. The fix is the read-back, which is Mistake 3."}]}$lum$::jsonb, false),
  ($lum$107f50fa-44d8-5c75-bc73-f70bf0e9eba9$lum$::uuid, $lum$d14e9d54-e16a-50d2-b2e3-2436208ccd1e$lum$::uuid, 10, $lum$before_after$lum$, $lum${"question":"Same shift notes, two prompts. Notice which one gets a precise, usable SBAR and which one invites fabrication.","before_prompt":"Turn my notes into an SBAR handoff: 72yo, hip surgery, BP a bit low this afternoon, seemed more confused at 1500, family worried.","after_prompt":"Reformat these de-identified shift notes into an SBAR handoff for the oncoming nurse. 72-year-old patient, post-operative day 1 from left hip ORIF. BP 108/64 at 1400, dropped to 96/58 at 1600, baseline approximately 130/80. Received 500 mL normal saline at 1500. Surgeon notified at 1630, repeat labs ordered for 1800. New onset confusion noted at 1500, oriented to person only. Family at bedside, expressing concern about the change in alertness. Situation: current status and key concern. Background: relevant surgical and medical history. Assessment: my clinical read. Recommendation: specific next steps and pending follow-ups. Use only what I have provided. Do not add vitals, medications, findings, or interventions that I did not state.","changes":["Replaces vague language ('BP a bit low', 'seemed more confused') with specific values, times, and baselines so the SBAR reflects what actually happened rather than a general impression.","Adds the explicit constraint phrase so the tool cannot fill gaps with fabricated clinical details such as an invented lab result or a medication that was never given.","Structures the request so the tool knows exactly what belongs in each SBAR section, keeping the nurse's clinical judgment in the Assessment and the concrete action items in the Recommendation."]}$lum$::jsonb, true),
  ($lum$59898d1f-3fef-5be2-83db-4197e2a863d8$lum$::uuid, $lum$d14e9d54-e16a-50d2-b2e3-2436208ccd1e$lum$::uuid, 11, $lum$multiple_choice$lum$, $lum${"stem":"After running her shift notes through the SBAR prompt, a nurse gets a clean draft. The Recommendation section says 'follow up on troponin trend and cardiology consult.' She never mentioned troponin or cardiology in her notes. What is the right response?","options":[{"id":"a","label":"Keep it. Troponin monitoring is standard for this type of patient, so the AI is giving a clinically appropriate recommendation.","is_correct":false,"explanation":"Clinical appropriateness is not the test. The test is whether the nurse observed, ordered, or documented this. If she did not, it cannot go in the handoff. A fabricated recommendation that the next nurse acts on can drive a workup that was never indicated."},{"id":"b","label":"Delete those lines. They were not in the input notes, so they are fabricated content that must not be handed off to the next nurse.","is_correct":true,"explanation":"Correct. The tool invented a clinically plausible recommendation that was never part of this patient's actual plan. Delete it, and check the rest of the draft for similar additions. If a troponin trend is actually pending, add it yourself in your own words."},{"id":"c","label":"Forward the draft to the charge nurse so she can verify whether a troponin was ordered.","is_correct":false,"explanation":"This transfers the error instead of catching it. The nurse who ran the prompt is responsible for reviewing the output before it moves forward. The charge nurse should not need to fact-check a handoff for fabricated content."},{"id":"d","label":"Add a question mark next to those lines so the oncoming nurse knows they are uncertain.","is_correct":false,"explanation":"Flagging a fabrication with a question mark still puts unverified content in the handoff. Remove it. If there is a genuine uncertainty about a pending order, write that in your own words based on what you actually know."}]}$lum$::jsonb, false),
  ($lum$b4caab89-3527-5e76-a788-13023e640a17$lum$::uuid, $lum$d14e9d54-e16a-50d2-b2e3-2436208ccd1e$lum$::uuid, 12, $lum$mini_project$lum$, $lum${"brief":"On your next shift, before you give report on one patient, pull the rough notes you would normally use for a verbal handoff. Strip any identifying information, replacing the patient's name with \"the patient,\" removing MRN and DOB, and using the room number if you need a reference. Run the de-identified notes through the SBAR prompt in a tool your organization has approved, or in a consumer tool if you have removed all PHI first.","parts":[{"id":"1","prompt":"Compare the AI-drafted SBAR line by line against your actual notes and mark any item that was not in your input, then delete every marked item before you use the draft."},{"id":"2","prompt":"Deliver the handoff to the oncoming nurse using the cleaned draft, then ask her one question: was anything missing that she needed to know?"},{"id":"3","prompt":"Write two sentences in a personal note (not in the chart): one thing the structured format surfaced that you might have glossed over verbally, and one thing it missed or got wrong that you had to correct."}]}$lum$::jsonb, false),
  ($lum$9c7d9715-ac75-5f66-bcac-9db0e0f5699a$lum$::uuid, $lum$718e3671-24db-5972-be29-4525de9c9e27$lum$::uuid, 0, $lum$reading$lum$, $lum${"markdown":"Picture Maya, a recruiter staring at 300 applications for one open role on a Friday afternoon. She has an AI tool right there, and the temptation is enormous: paste them all in, ask for the top 20, go home. The pitch sells itself. Faster. Consistent. Objective. That last word is exactly where the danger lives, because objective is the trap, and it is worth slowing down to see why before you ever click a button.\n\nA model does not understand fairness. It learns patterns from data. When you ask an AI to predict which candidates are good, it has to learn what good looks like from somewhere, and that somewhere is almost always historical hiring data: who applied before, who got interviewed, who got hired, who got promoted. But that history is not a clean record of merit. It is a record of every decision your industry and your company already made, including the biased ones. So when the model learns to predict who looks like a strong hire, it can quietly learn to reproduce who got hired before. If people with employment gaps were passed over in the past, the model learns gaps are bad. If certain schools or certain names or certain non-traditional career paths were historically screened out, the model learns to screen them out too. It does all of this without malice and without anyone choosing it, while presenting the output as a neutral score. The bias did not disappear. It got faster and quieter and harder to see. That is the core idea worth tattooing on your brain: bias does not vanish when you automate it, it scales."}$lum$::jsonb, false),
  ($lum$8ab5cbb7-3b95-53ac-a27b-d38a6a3b7958$lum$::uuid, $lum$718e3671-24db-5972-be29-4525de9c9e27$lum$::uuid, 1, $lum$multiple_choice$lum$, $lum${"stem":"Why does this lesson call the word 'objective' a trap when an AI ranks candidates?","options":[{"id":"a","label":"Because AI runs slower than a human and slow processes feel less objective to applicants.","is_correct":false,"explanation":"Speed is not the issue. AI is fast at sorting. The trap is that a neutral-looking output can carry hidden bias."},{"id":"b","label":"Because a model learns 'good candidate' from historical hiring data, so it can reproduce past biased decisions at scale while presenting the result as a neutral score.","is_correct":true,"explanation":"Correct. The output looks objective, but it is patterned on a biased history, so it scales that bias consistently across every applicant."},{"id":"c","label":"Because objectivity is impossible to define, so any screening method is equally unreliable.","is_correct":false,"explanation":"Written, job-related criteria applied consistently by a human are defensible. The specific problem is a model inheriting bias from past data, not a general claim that nothing is reliable."}]}$lum$::jsonb, false),
  ($lum$85ae6014-a9fe-5cf5-b741-094714826be5$lum$::uuid, $lum$718e3671-24db-5972-be29-4525de9c9e27$lum$::uuid, 2, $lum$reading$lum$, $lum${"markdown":"Scaling is the part HR people underestimate. When a single biased manager rejects a candidate, that is one bad decision affecting one person. When a biased model ranks 300 applications, the same flawed logic touches all 300 at once, consistently, every single time, applied identically across every future role you point it at. Consistency feels like fairness. Here it is the opposite. It is consistent unfairness at scale, with a clean interface on top.\n\nNow bring in Devon, an HR generalist who is trying to build a fair screening process from scratch and assumes the legal risk lives with the obviously bad actors. It does not. Hiring is regulated, and the standard that matters most here is disparate impact: if your screening process produces meaningfully worse outcomes for a protected group, that is a liability regardless of whether a human or a tool produced it, and regardless of whether anyone intended it. You cannot point at the vendor and say the algorithm did it. On top of that, a growing number of places now attach specific obligations to automated employment decision tools: disclosure to candidates that a tool is being used, independent bias audits, and in some cases consent. The details vary by jurisdiction and they keep changing, so the practical takeaway is not a citation to memorize. It is a posture: assume that if a tool is making or heavily shaping a hiring decision, you owe someone an explanation, an audit trail, and a defensible, job-related reason."}$lum$::jsonb, false),
  ($lum$fe8fb911-fdf9-5c64-89ad-bf03bc1ca6f0$lum$::uuid, $lum$718e3671-24db-5972-be29-4525de9c9e27$lum$::uuid, 3, $lum$multiple_choice$lum$, $lum${"stem":"Under the disparate impact standard described here, when does a screening process create legal liability for the employer?","options":[{"id":"a","label":"Only when a recruiter can be shown to have personally intended to discriminate against a protected group.","is_correct":false,"explanation":"Intent is not required. The lesson states the liability holds regardless of whether anyone intended it."},{"id":"b","label":"Only when a human, rather than a tool, produced the worse outcomes for a protected group.","is_correct":false,"explanation":"It does not matter whether a human or a tool produced the outcome. You cannot point at the vendor and say the algorithm did it."},{"id":"c","label":"Whenever the process produces meaningfully worse outcomes for a protected group, whether a human or a tool produced it and whether or not anyone intended it.","is_correct":true,"explanation":"Correct. Disparate impact attaches to the outcome itself, independent of who or what produced it and independent of intent."}]}$lum$::jsonb, false),
  ($lum$e36d6ee8-7fb4-51fd-8fe2-c092e30eb7fb$lum$::uuid, $lum$718e3671-24db-5972-be29-4525de9c9e27$lum$::uuid, 4, $lum$reading$lum$, $lum${"markdown":"So where does that leave AI in screening? In a genuinely useful place, as long as you draw one clean line. Think about Priya, a hiring manager who is nervous about legal exposure but also drowning in volume. AI is excellent at the administrative half of screening: organizing and summarizing. It can take one application and your written job requirements and tell you, in plain language, which of the listed must-have qualifications appear to be present, which are not evidenced, and which are unclear. It can structure messy resumes into a consistent format so a human reviewer compares like with like instead of getting charmed by a pretty layout. It can pull out whether a specific, written, job-related requirement (a particular certification, a language, years in a defined function) is mentioned. That is administrative support. It makes the human faster and more consistent without ever making the call.\n\nWhat AI must never do is rank, score, or reject. Those are evaluative judgments, and evaluative judgments in hiring must be made by a person against explicit, job-related criteria. The moment a tool outputs an ordering or a number that tells you who is in and who is out, you have handed the regulated decision to the model and inherited all of its hidden inheritance. The clean line is this: AI may make applications easier for a human to evaluate fairly, but AI may never be the evaluator.\n\nThe discipline that protects you here is the same discipline that produces better hires anyway. Write your screening criteria down. Tie every one of them to the actual job. Apply them consistently to every candidate. When your criteria are explicit, job-related, and consistently applied, you have something you can defend if a regulator or a rejected applicant ever asks, and you also have a process that finds talent the old gut-feel approach quietly missed. Maya, Devon, and Priya all end up in the same good place: AI does the reading, a person does the judging, and the criteria are on paper where everyone can see them."}$lum$::jsonb, false),
  ($lum$49764b86-8c10-567a-857c-79ec1c27dff3$lum$::uuid, $lum$718e3671-24db-5972-be29-4525de9c9e27$lum$::uuid, 5, $lum$multiple_choice$lum$, $lum${"stem":"According to the clean line drawn here, which of these is the one thing AI must never do in screening?","options":[{"id":"a","label":"Output an ordering, a score, or a reject decision that determines who is in and who is out.","is_correct":true,"explanation":"Correct. Ranking, scoring, and rejecting are evaluative judgments that must be made by a person against explicit, job-related criteria."},{"id":"b","label":"Structure a messy resume into a consistent format so a human can compare like with like.","is_correct":false,"explanation":"This is administrative support. It helps the human review fairly without making the call, so it stays on the safe side of the line."},{"id":"c","label":"State whether a written, job-related must-have appears present, not evidenced, or unclear.","is_correct":false,"explanation":"This is organizing and summarizing against written requirements. It informs the human reviewer rather than deciding for them."}]}$lum$::jsonb, false),
  ($lum$d9a92bc1-2428-5dd3-879f-26f0dff63502$lum$::uuid, $lum$718e3671-24db-5972-be29-4525de9c9e27$lum$::uuid, 6, $lum$reading$lum$, $lum${"markdown":"The mistakes here rarely look like mistakes in the moment. They look like efficiency. Maya's first wrong turn is the most common one: asking the AI to \"rank the top 20\" or \"score these out of 10.\" That output is an evaluative decision dressed as a summary, and once you act on the ranking, the model made the call. A related trap is the soft version: \"Just tell me which ones I should probably skip.\" Skip is a rejection. Renaming a rejection does not move it back across the line.\n\nA second mistake is trusting a tool because a vendor labeled it bias-free or audited. An audit is a snapshot, not a guarantee, and a tool that was fair on one role or one applicant pool can behave very differently on yours. Devon's instinct to ask vendors hard questions is right, but the answers do not transfer your accountability to them. If the tool shapes a decision and that decision lands harder on a protected group, the disparate impact is still your liability.\n\nA third mistake is feeding the AI things that have nothing to do with the job and everything to do with bias: photos, ages, addresses, graduation years, names, personal details. Even when you are only asking for a summary, an AI that can see a name or a neighborhood can let it leak into the tone or emphasis of what it writes back. The fix is to anchor every request to written, job-related requirements and to explicitly forbid inferences from protected characteristics."}$lum$::jsonb, false),
  ($lum$8f658a07-6674-5f66-9e1c-033411afa469$lum$::uuid, $lum$718e3671-24db-5972-be29-4525de9c9e27$lum$::uuid, 7, $lum$multiple_choice$lum$, $lum${"stem":"A vendor tells Devon their screening AI is 'independently audited and bias-free.' What is the right takeaway?","options":[{"id":"a","label":"He can let the tool rank and reject candidates now, since the audit transfers legal accountability to the vendor.","is_correct":false,"explanation":"Accountability does not transfer. If the tool's decisions create a disparate impact, the liability is still the employer's."},{"id":"b","label":"An audit is reassuring but it is a snapshot, not a guarantee, and it does not move accountability off Devon. The tool still must not be the one ranking or rejecting.","is_correct":true,"explanation":"Correct. Audits help, but the employer remains accountable for outcomes, and the evaluative decision must stay with a person on job-related criteria."},{"id":"c","label":"Audits are meaningless, so he should refuse to use any AI in screening at all.","is_correct":false,"explanation":"AI can still safely organize and summarize against written requirements. The lesson draws a line around deciding, not around all AI use."}]}$lum$::jsonb, false),
  ($lum$cacc5c12-882c-5f72-9212-ccf61d6c3808$lum$::uuid, $lum$718e3671-24db-5972-be29-4525de9c9e27$lum$::uuid, 8, $lum$reading$lum$, $lum${"markdown":"A fourth mistake is having no paper trail. Priya summarizes applications with AI but writes her criteria nowhere, so when a strong candidate is passed over and asks why, there is no consistent, job-related reason on record. Undocumented judgment is exactly what disparate-impact scrutiny is built to catch, because without written criteria you cannot show that two similar candidates were treated the same way for the same reasons.\n\nA fifth mistake is the slow drift back across the line. A team starts with a clean rule that AI only summarizes, and then someone notices the summaries already make the strong candidates obvious, so it feels harmless to let the tool also flag its favorites. Then the flags become a shortlist, and the shortlist becomes the decision, and nobody remembers choosing to let the model evaluate. Maya can avoid this by treating the line as a hard rule, not a preference: the tool reports facts against requirements, and a human does the comparing every time, even when the answer feels obvious.\n\nThe throughline is simple. The failures come from letting the tool quietly cross from organizing into deciding, from outsourcing accountability to a vendor, from letting bias-rich data into the room, and from keeping no record. Keep AI on the administrative side, keep humans on the judgment, and keep the criteria written down, and most of these mistakes never get a chance to happen."}$lum$::jsonb, false),
  ($lum$ec26050e-3699-59df-b72d-2a7b8a403775$lum$::uuid, $lum$718e3671-24db-5972-be29-4525de9c9e27$lum$::uuid, 9, $lum$multiple_choice$lum$, $lum${"stem":"Why does the 'slow drift' described here, where AI summaries quietly become flags, then a shortlist, then the decision, count as a real failure?","options":[{"id":"a","label":"Because summarizing applications was never a legitimate use of AI in the first place.","is_correct":false,"explanation":"Summarizing against written requirements is the safe, administrative use the lesson endorses. The drift is the problem, not the summary."},{"id":"b","label":"Because the tool gradually crosses from organizing into deciding, so the model ends up evaluating without anyone consciously choosing to let it.","is_correct":true,"explanation":"Correct. The line gets crossed in small steps until the model is the evaluator, which is exactly the regulated decision a person must keep."},{"id":"c","label":"Because flagging favorites is fine as long as a human signs off on the final shortlist at the end.","is_correct":false,"explanation":"Once the tool's flags shape the shortlist, the model is doing the comparing. The lesson says a human must do the comparing every time, even when the answer feels obvious."}]}$lum$::jsonb, false),
  ($lum$9f679742-0d07-5c18-b38c-a8a04a08162b$lum$::uuid, $lum$718e3671-24db-5972-be29-4525de9c9e27$lum$::uuid, 10, $lum$before_after$lum$, $lum${"question":"You want AI's help moving through a pile of applications fairly. Which prompt keeps it on the safe side of the line?","before_prompt":"Here are 50 resumes. Rank them best to worst and tell me the top 20 to interview.","after_prompt":"Here is one application and our written, job-related requirements for this role: [paste the must-have qualifications and responsibilities]. Do not rank, score, recommend, or reject this candidate. Instead summarize factually: for each listed must-have, state whether it is clearly present, not evidenced, or unclear, and cite the part of the application you based that on. Keep it neutral so a human reviewer can compare candidates consistently. Do not infer or comment on name, age, gender, address, or background.","changes":["Switches the task from ranking to summarizing against written, job-related requirements, so the decision stays with a human.","Forces a present / not-evidenced / unclear structure with citations so reviewers compare like with like and can audit the reasoning.","Explicitly forbids inferences from protected characteristics that could leak bias into the summary."]}$lum$::jsonb, true),
  ($lum$916c7764-4f8a-5c39-8b51-34ff55b99308$lum$::uuid, $lum$718e3671-24db-5972-be29-4525de9c9e27$lum$::uuid, 11, $lum$multiple_choice$lum$, $lum${"stem":"Which request is safely on the administrative side of the line, and not an evaluative decision the AI should not make?","options":[{"id":"a","label":"For this one application, list which of our written must-have qualifications are clearly present, not evidenced, or unclear, citing where in the application.","is_correct":true,"explanation":"Correct. This organizes and summarizes against written, job-related criteria. It informs a human reviewer without ranking, scoring, or rejecting."},{"id":"b","label":"Tell me which of these candidates I should probably skip to save time.","is_correct":false,"explanation":"'Skip' is a rejection in disguise. Renaming a reject decision does not make it administrative. That call must stay with a person."},{"id":"c","label":"Give each candidate a fit score out of 100 so I can sort the pile.","is_correct":false,"explanation":"A score is an evaluative judgment and an ordering. That is exactly the regulated, bias-prone decision the tool must not make."}]}$lum$::jsonb, false),
  ($lum$659d95f9-b3a4-544c-ad67-310bb5e54c4e$lum$::uuid, $lum$718e3671-24db-5972-be29-4525de9c9e27$lum$::uuid, 12, $lum$mini_project$lum$, $lum${"brief":"Map how screening actually happens on your team right now and find every point where a judgment is made: shortlisting, ranking, rejecting. For each judgment point, decide what AI could safely do to support it (summarizing against written requirements, checking for a specific must-have, structuring messy applications) without making the decision itself. Then put your screening criteria on paper the way you would defend them if a rejected applicant or a regulator asked, and build a neutral summary template that AI can fill in.","parts":[{"id":"1","prompt":"Write your job-related screening criteria explicitly, with every criterion tied to an actual responsibility or must-have for the role."},{"id":"2","prompt":"Draft a reusable AI summary prompt that reports each requirement as present, not evidenced, or unclear with citations, and forbids inferences from protected characteristics."},{"id":"3","prompt":"Define where the human evaluative step sits, so a person always makes the ranking and rejection calls against your written criteria with a record of the reasons."}]}$lum$::jsonb, false),
  ($lum$aac31671-8d53-5d6e-9c33-6d537b3f3a38$lum$::uuid, $lum$5243155b-34ae-5912-b919-d188baa6b766$lum$::uuid, 0, $lum$reading$lum$, $lum${"markdown":"Lesson planning is the work that quietly eats teachers' evenings and weekends. The thinking is not the hard part. The volume of structure is. Every week you lay out a five-day arc, sequence objectives, draft warm-ups, write a check for understanding, and list the materials each day needs. That scaffolding is real labor, and it is exactly the part AI can draft for you, so your time goes to the instructional decisions only you can make. The goal is not to hand your week to a machine. The goal is to skip the blank page and start from a frame you react to.\n\nThe most common mistake is asking for too little. \"Give me a lesson on fractions\" returns something generic and gradeless, useless to a real classroom. A good request gives the AI what a substitute teacher would need before walking into your room. Tell it five things: the grade level, the subject and specific topic, the standard you are teaching to, how long each class runs, and anything true about your students that shapes how you teach. Those five inputs turn a vague request into a draft you can actually use."}$lum$::jsonb, false),
  ($lum$e6affa9e-650a-5d5c-a00f-dbe54479b983$lum$::uuid, $lum$5243155b-34ae-5912-b919-d188baa6b766$lum$::uuid, 1, $lum$multiple_choice$lum$, $lum${"stem":"You want AI to draft a usable week, not something generic. Which request gives it what it needs?","options":[{"id":"a","label":"\"Make me a fun lesson about the water cycle.\"","is_correct":false,"explanation":"This has no grade, no standard, no class length, and no student notes. The AI will guess at all of it and hand you something gradeless and generic."},{"id":"b","label":"\"I teach 5th grade science, introducing the water cycle toward my state's standard on Earth's water systems, 45-minute periods, students who read below grade level. Draft a five-day arc with an objective, warm-up, activity, check for understanding, and materials per day.\"","is_correct":true,"explanation":"Correct. It names grade, topic, standard, class length, and a real student note, then asks for the exact structure you need. That is what turns a vague request into a draft you can actually shape."},{"id":"c","label":"\"Plan my whole week and make all the teaching decisions for me.\"","is_correct":false,"explanation":"The AI does not know your students or your pacing, so it cannot make your teaching decisions. Its job is to build the frame; the decisions stay with you."},{"id":"d","label":"\"Give me a lesson on the water cycle.\"","is_correct":false,"explanation":"Too thin. With no grade, standard, length, or student context, you get a generic result that needs as much work as starting from scratch."}]}$lum$::jsonb, false),
  ($lum$15d0b98f-9b17-577b-8a9d-d6b5f4e811e4$lum$::uuid, $lum$5243155b-34ae-5912-b919-d188baa6b766$lum$::uuid, 2, $lum$reading$lum$, $lum${"markdown":"Here is what that looks like in a real classroom. Picture a 4th grade math teacher introducing equivalent fractions, working toward the state fraction-equivalence standard, with 50-minute periods, and a handful of students still shaky on their multiplication facts. The request might be: \"I teach 4th grade math. This week I am introducing equivalent fractions, aligned to my state's fraction-equivalence standard. Classes are 50 minutes. Several students are still shaky on multiplication facts. Draft a five-day arc, one day per lesson, each with an objective, a warm-up, a main activity, a quick check for understanding, and the materials I will need.\" What comes back is a week with a logical build: day one uses folded paper strips to show that one half and two fourths cover the same length, day two introduces multiplying numerator and denominator by the same number, later days add a fraction wall and a sorting game. You did not write any of that from scratch. You react to it. You move objectives, swap the sorting game for something your class responds to, and cut whatever does not fit your pacing.\n\nNow picture a 7th grade life-science teacher opening a unit on cell structure, working toward the state standard on cells as the basic unit of life, with 45-minute periods and a class that did well on the last lab but struggles with vocabulary. The same five inputs produce a different shaped week: a warm-up that surfaces what students already think a cell is, a main activity building a labeled model, a check that asks students to name the job of one organelle in their own words. Because you told the AI the class struggles with vocabulary, you can push it further and ask for a word bank and a sentence frame for the exit ticket. The frame is generic until your inputs make it specific, and the student note is what makes it specific."}$lum$::jsonb, false),
  ($lum$1149e984-a894-5ad9-8950-43ef658d6e75$lum$::uuid, $lum$5243155b-34ae-5912-b919-d188baa6b766$lum$::uuid, 3, $lum$multiple_choice$lum$, $lum${"stem":"In the worked examples, the 7th grade class struggles with vocabulary. How does that single student note change what you can ask the AI for?","options":[{"id":"a","label":"It tells the AI to skip the main activity, since vocabulary-heavy classes cannot build a model.","is_correct":false,"explanation":"The note does not remove the model-building activity. It lets you add support around the lesson, not strip the activity out."},{"id":"b","label":"It means you should switch to the 4th grade fractions plan instead.","is_correct":false,"explanation":"The grade and topic do not change because of a student note. The note shapes the support inside the same plan, not the subject of the lesson."},{"id":"c","label":"You can push the AI further and ask for a word bank and a sentence frame for the exit ticket.","is_correct":true,"explanation":"Correct. The student note is what makes a generic frame specific. Telling the AI the class struggles with vocabulary lets you request a word bank and a sentence frame tied to that need."},{"id":"d","label":"It guarantees the AI will produce a perfect, ready-to-teach lesson with no editing.","is_correct":false,"explanation":"A good note sharpens the draft, but you still react to it and shape it. The note makes the frame specific; it does not remove your teacher pass."}]}$lum$::jsonb, false),
  ($lum$2d63c981-019e-56bd-8d83-d9611e23dd29$lum$::uuid, $lum$5243155b-34ae-5912-b919-d188baa6b766$lum$::uuid, 4, $lum$reading$lum$, $lum${"markdown":"One more. A high-school history teacher planning a single lesson on the causes of World War One, aimed at the state standard on analyzing causes of major conflicts, with an 80-minute block and students who can recall facts but struggle to connect them into an argument. Here the teacher does not want five days of recall. They want one day of analysis. So the request names that: \"Draft one 80-minute lesson where students move from listing causes to building a short claim about which cause mattered most, with evidence.\" The AI returns a structure, a sorting activity, a claim-and-evidence organizer, a closing write. The teacher keeps the bones and brings the judgment about which sources to use and how hard to push.\n\nAcross all three, the pattern is the same. You give the AI the grade, the topic, the standard, the class length, and the student notes. It builds the frame. You make the teaching decisions the frame exists to serve. That division of labor is the whole point. The AI does not know your students, your room, or your pacing, and it is not supposed to. It clears the structural work off your plate so the part that needs a teacher gets a teacher.\n\nWhat you should expect from a good draft is coherence, not perfection. The days should connect. The objectives should build on each other. The checks for understanding should actually match the day's objective. When something is off, that is information: it tells you where your own thinking needs to go. Reacting to a flawed draft is faster than facing an empty planner, and the editing you do is the real instructional design. By the end you have a week that is yours, built in minutes, shaped by judgment."}$lum$::jsonb, false),
  ($lum$55e4e267-8c33-5af3-8927-3abf733e8dc4$lum$::uuid, $lum$5243155b-34ae-5912-b919-d188baa6b766$lum$::uuid, 5, $lum$multiple_choice$lum$, $lum${"stem":"The lesson says you should expect coherence, not perfection, from a good draft. What does it say to do when part of the draft is off?","options":[{"id":"a","label":"Treat the off part as information that tells you where your own thinking needs to go.","is_correct":true,"explanation":"Correct. A flaw is a signal. It points to where your judgment is needed, and reacting to a flawed draft is faster than facing an empty planner."},{"id":"b","label":"Start the whole week over from a blank planner, since a flawed draft is worthless.","is_correct":false,"explanation":"The lesson says the opposite. Reacting to a flawed draft is faster than facing an empty planner, and the editing you do is the real instructional design."},{"id":"c","label":"Keep it as written, since coherence means the draft is finished.","is_correct":false,"explanation":"Coherence is not perfection. The draft is a starting point you shape, not a finished plan you leave untouched."},{"id":"d","label":"Hand the off part back to the AI and let it make the final teaching call.","is_correct":false,"explanation":"The teaching decisions inside the frame are yours. The AI does not know your students, your room, or your pacing, so the call stays with you."}]}$lum$::jsonb, false),
  ($lum$e8655cae-d123-5216-b3a0-85c3fb926a9d$lum$::uuid, $lum$5243155b-34ae-5912-b919-d188baa6b766$lum$::uuid, 6, $lum$reading$lum$, $lum${"markdown":"The fastest way to get burned by an AI-drafted week is to treat the draft as an authority instead of a starting point. Three errors show up again and again, and all three are avoidable once you know to look for them.\n\nFirst, verify any standard the AI names or quotes. This is the most common failure in planning specifically. The model works from memory, and it will confidently produce a standard code that looks official, format it neatly next to each objective, and still have it wrong. It misattributes codes, and it paraphrases the wording of standards in ways that drift from the official text. Your alignment has to be exact, because that is what your plan book, your evaluations, and your reporting depend on. So before any standard goes in your plan, pull the exact code and wording from your official standards document, not from the draft. Consistency is a trap here: the AI can apply the same wrong code across all five days, and a uniformly formatted mistake is still a mistake.\n\nSecond, check any factual content the AI builds a lesson around, especially in science and history. This is where a confident wrong detail does real damage, because it travels straight from the draft into your slides and out of your mouth in front of thirty students. The AI might give a 7th grade life-science class an organelle the wrong job, or hand a high-school history class a date or a cause that is subtly off. The draft will not flag any of this. It states wrong facts with the same calm tone it uses for right ones. So treat every factual claim in a science or history lesson as unverified until you have confirmed it against a source you trust. The structure can be a gift while the content still needs your eyes."}$lum$::jsonb, false),
  ($lum$1e961c09-50c7-54e1-a5a9-a0c62c6e2f43$lum$::uuid, $lum$5243155b-34ae-5912-b919-d188baa6b766$lum$::uuid, 7, $lum$fill_blank$lum$, $lum${"template":"Before you put an AI-drafted week in your plan book, verify every standard the AI names against your {{1}}, because the model misattributes codes and paraphrases wording. And for any science or history lesson, check the {{2}} the AI states, since a confident wrong detail travels straight into your slides.","blanks":[{"id":"1","accept":["official standards document","official document","standards document","official standards","state standards document"],"ideal":"official standards document"},{"id":"2","accept":["facts","factual content","factual claims","facts it states","content","details"],"ideal":"facts"}],"explanation":"Standards must come from the authoritative source, not the model's memory, because it misattributes codes and paraphrases wording. And factual content in science and history needs checking, because the AI states wrong details as confidently as right ones."}$lum$::jsonb, false),
  ($lum$beb3b90e-8753-526d-be0d-cd658842d2fe$lum$::uuid, $lum$5243155b-34ae-5912-b919-d188baa6b766$lum$::uuid, 8, $lum$reading$lum$, $lum${"markdown":"Third, and underneath both of the above, do not mistake the AI draft for teaching judgment. The draft does not know your students. It does not know that third period moves faster than first, that you have two students who need the warm-up scaffolded, or that your real periods run short on assembly days. It does not know your pacing, your room, or your read on which activity will land. When the draft says \"ten minutes of partner discussion,\" it is guessing. You know whether your class can sustain that. The error is letting the draft's confident specificity override what you actually know. The fix is a habit: treat every piece of the draft as a proposal you approve, edit, or reject, never as an instruction you follow. The AI built the frame. The teaching decisions inside that frame are yours, and the whole value of the tool depends on you keeping them."}$lum$::jsonb, false),
  ($lum$01505c34-362e-54cc-98d6-9f05ad4d9566$lum$::uuid, $lum$5243155b-34ae-5912-b919-d188baa6b766$lum$::uuid, 9, $lum$multiple_choice$lum$, $lum${"stem":"The draft says \"ten minutes of partner discussion\" for a day. According to the lesson, what is the right way to read that instruction?","options":[{"id":"a","label":"As a fixed requirement, since the draft was specific about the timing.","is_correct":false,"explanation":"Confident specificity is not knowledge. The draft is guessing at the timing; letting that override what you know about your class is exactly the error to avoid."},{"id":"b","label":"As proof the AI understands your pacing and your room.","is_correct":false,"explanation":"The draft does not know your pacing, your room, or which activity will land. A specific number does not mean the AI knows your students."},{"id":"c","label":"As a reason to ask the AI whether your class can sustain ten minutes.","is_correct":false,"explanation":"The AI cannot answer that. You are the one who knows whether your class can sustain it; the judgment is yours, not the model's."},{"id":"d","label":"As a proposal you approve, edit, or reject, because you know whether your class can sustain it.","is_correct":true,"explanation":"Correct. The fix is a habit: treat every piece of the draft as a proposal, never as an instruction you follow. The teaching decisions inside the frame are yours."}]}$lum$::jsonb, false),
  ($lum$67d2025c-9bc4-501e-b787-29bb77c20fec$lum$::uuid, $lum$5243155b-34ae-5912-b919-d188baa6b766$lum$::uuid, 10, $lum$try_it_live$lum$, $lum${"instructions":"Draft a week of lessons you can refine. Give the AI your grade, subject and topic, the standard, your class length, and anything about your students. Or use the sample: 4th grade math, introducing equivalent fractions, 50-minute classes, with several students still shaky on multiplication facts.","system_prompt":"You are an experienced K-12 curriculum coach helping a classroom teacher. Given a grade, subject, topic, standard, class length, and notes about the students, draft a five-day lesson arc, one day per lesson. For each day give a clear objective, a short warm-up, a main activity, a quick check for understanding, and a materials list. Keep activities concrete and age-appropriate. Remind the teacher to confirm the exact standard wording against their official document, since you may paraphrase it. No jargon. No em dashes.","ideal_output":"Here is a five-day arc for introducing equivalent fractions in 4th grade math, 50-minute periods. Please confirm the exact wording of your fraction-equivalence standard against your official document, since I am working from a paraphrase.\n\nDay 1. Objective: students recognize that two fractions can name the same amount. Warm-up: a quick review of multiplication facts as skip-counting, to support the students who are shaky. Main activity: fold paper strips to show that one half and two fourths cover the same length. Check: students draw one pair of equivalent fractions. Materials: paper strips, markers.\n\nDay 2. Objective: students build equivalent fractions by multiplying numerator and denominator by the same number. Warm-up: name a fraction shown on a number line. Main activity: guided practice multiplying top and bottom by the same number, tied back to the paper strips. Check: three exit problems. Materials: number-line handout.\n\nDay 3. Objective: students compare two fractions using a fraction wall. Warm-up: skip-count by threes and fours. Main activity: build a fraction wall and find equivalent rows. Check: name two equivalent fractions from the wall. Materials: fraction wall printout.\n\nDay 4. Objective: students sort fractions into equivalent groups. Warm-up: quick true-or-false on equivalence. Main activity: partner sorting game with fraction cards. Check: explain in one sentence why two cards belong together. Materials: fraction card sets.\n\nDay 5. Objective: students show what they have learned. Warm-up: a single confidence-builder problem. Main activity: short formative quiz, then a fix-it review. Check: the quiz itself. Materials: quiz copies.\n\nWant me to expand any single day into a full lesson with timings?","input_placeholder":"Grade, subject and topic, the standard, class length, and notes about your students..."}$lum$::jsonb, true),
  ($lum$b17bfe90-82e1-50ab-8f58-82d796b5f69a$lum$::uuid, $lum$5243155b-34ae-5912-b919-d188baa6b766$lum$::uuid, 11, $lum$multiple_choice$lum$, $lum${"stem":"Your AI-drafted week looks great, and day three's main activity rests on a science fact you are not sure about. What is the right move before you teach it?","options":[{"id":"a","label":"Teach it as written, since the draft was coherent and the rest of the week checked out.","is_correct":false,"explanation":"Coherence is not accuracy. The AI states wrong facts in the same confident tone as right ones, and a science error travels straight into your lesson if you do not catch it."},{"id":"b","label":"Confirm the fact against a source you trust before it goes in your slides, because the AI states wrong details as confidently as right ones.","is_correct":true,"explanation":"Correct. Factual content in science and history needs verification. The draft will not flag its own errors, so a confident wrong detail is yours to catch before it reaches students."},{"id":"c","label":"Delete day three entirely, since you cannot trust anything the AI produced.","is_correct":false,"explanation":"That overcorrects. The structure is still useful. You verify the one fact you are unsure about rather than throwing out a whole day of usable planning."},{"id":"d","label":"Ask the AI to confirm whether its own fact is correct.","is_correct":false,"explanation":"The model can restate a wrong fact just as confidently the second time. Verification has to come from a source you trust, not from the same memory that produced the error."}]}$lum$::jsonb, false),
  ($lum$06a2056c-f4be-5ffd-94a8-42f9baccb4e5$lum$::uuid, $lum$5243155b-34ae-5912-b919-d188baa6b766$lum$::uuid, 12, $lum$mini_project$lum$, $lum${"brief":"Pick a real topic you are teaching next week and build its frame in one AI chat, then do the teacher pass that makes it yours. Give the AI your grade, subject, the specific topic, the standard, your class length, and one true detail about your students, then ask for a five-day arc with an objective, warm-up, main activity, check for understanding, and materials for each day. The draft is your starting point, not your plan. The value is in the edit pass you do next.","parts":[{"id":"1","prompt":"Open your official standards document and confirm every standard the AI named, fixing any code or wording that drifted, since the model paraphrases and misattributes."},{"id":"2","prompt":"Check every factual claim in any science or history day against a source you trust, because a confident wrong detail goes straight into your slides."},{"id":"3","prompt":"Apply your judgment: swap at least one activity for something your class actually responds to, adjust the pacing to fit your real periods, and cut whatever does not serve your students."}]}$lum$::jsonb, false),
  ($lum$b5119a8e-8d2d-504f-becb-181ea7d7bec2$lum$::uuid, $lum$e23574ab-93e9-5d78-b3ca-774ad04fab25$lum$::uuid, 0, $lum$reading$lum$, $lum${"markdown":"UX writing (the words inside product interfaces) is disproportionately impactful and disproportionately neglected. Button labels, error messages, empty states, onboarding copy: these are often written in 10 minutes by the engineer who built the component.\n\n**AI for UX writing:**\n\n**Tone system prompt:** *\"You are a UX writer for [product]. Our voice is [3 adjectives]. We speak to [audience]. We never use [banned phrases]. Use these principles for every output.\"*\n\n**Copy-fitting:** When space is constrained: *\"I need this copy to fit in 32 characters: '[current copy]'. The message must convey [key meaning]. Give me 5 options.\"*\n\n**Error messages:** *\"Write 3 options for an error message when a user's payment fails. Each should: say what happened in plain language, tell them what to do next, and not make them feel stupid. Under 2 lines.\"*\n\n**Empty states:** *\"Write copy for an empty state when a user first lands on their dashboard with no data. Should be friendly, explain what they'll see here, and give one clear action.\"*\n\n**Consistency audit:** *\"Here are all the button labels from our product: [paste]. Flag any that are inconsistent in verb tense, length, or formality.\"*\n\nGood UX copy is invisible when it's right and painful when it's wrong."}$lum$::jsonb, false),
  ($lum$b89fbf8d-7d0f-549e-9cae-faaf58129ab2$lum$::uuid, $lum$e23574ab-93e9-5d78-b3ca-774ad04fab25$lum$::uuid, 1, $lum$multiple_choice$lum$, $lum${"stem":"A user's payment fails. Which error message best follows the rules in this lesson (say what happened, what to do next, do not make them feel stupid)?","options":[{"id":"a","label":"\"Your payment didn't go through. Check your card details or try another card, and we'll keep your cart saved.\"","is_correct":true,"explanation":"Correct. It says what happened in plain language, gives a clear next action, and reassures rather than blames. The saved-cart line removes the fear of losing progress."},{"id":"b","label":"\"Error 402: Transaction declined.\"","is_correct":false,"explanation":"A status code tells the user nothing they can act on and feels cold. Plain language and a next step are missing."},{"id":"c","label":"\"Payment failed. Please ensure you entered everything correctly this time.\"","is_correct":false,"explanation":"\"This time\" subtly blames the user. The rule is to never make them feel stupid; a failed payment is usually not their mistake."},{"id":"d","label":"\"Something went wrong.\"","is_correct":false,"explanation":"Too vague. It names neither what happened nor what to do, which leaves the user stuck."}]}$lum$::jsonb, false),
  ($lum$8a5c4ed3-20d9-5baa-a671-cd6925845942$lum$::uuid, $lum$e23574ab-93e9-5d78-b3ca-774ad04fab25$lum$::uuid, 2, $lum$try_it_live$lum$, $lum${"instructions":"Copy-fit under a hard constraint. Rewrite this empty-state heading so it fits in 32 characters, stays friendly, and still tells a first-time user what this screen is for. Original: 'You don't have any projects yet, but you can create one to get started.'","system_prompt":"You are a UX writer. Rewrite UI copy to fit a strict character limit while keeping it warm, plain, and clear about what the user should do. Count characters carefully and never exceed the limit. Offer a few options. No em dashes.","ideal_output":"Here are three options, each at 32 characters or fewer:\n1. \"No projects yet. Create your first\" (33, trim to \"No projects yet. Add your first\" = 31)\n2. \"Start your first project\" (24)\n3. \"Nothing here yet. Make one\" (26)\nOption 2 is the cleanest: it is an action, it is friendly, and it fits comfortably.","input_placeholder":"Paste the UI string and the character limit it has to fit..."}$lum$::jsonb, true),
  ($lum$ef1cc7f0-3585-5088-ba23-f1f0e5a2ce23$lum$::uuid, $lum$e23574ab-93e9-5d78-b3ca-774ad04fab25$lum$::uuid, 3, $lum$mini_project$lum$, $lum${"brief":"Your 5-minute exercise: Find 5 UI strings in a product you use or work on. Run them through the consistency audit prompt. How many fail the check?","parts":[]}$lum$::jsonb, false),
  ($lum$d0ca1a4f-81ff-5ecf-b6eb-5488baa5f977$lum$::uuid, $lum$7b107772-ee1a-5040-a84c-68ac406b48df$lum$::uuid, 0, $lum$reading$lum$, $lum${"markdown":"You already know the painful truth about most P&L analysis: it gets produced, it gets emailed, it gets skimmed in the first ninety seconds of a meeting, and then it gets filed and forgotten. The format is the problem. Dense tables, percentage changes with no context, and a narrative paragraph that restates the numbers instead of explaining what to do about them. As an FP&A analyst, a controller, or a finance manager, you are not short on data. You are short on a fast way to turn that data into the three or four things leadership actually needs to discuss. That is exactly where a careful AI workflow earns its place, and exactly where a careless one gets you into trouble.\n\nPicture an FP&A analyst named Dana, prepping a board P&L review for a SaaS company. The board deck is due Thursday. Dana has the quarter close, she has the prior quarter, she has the plan, and she has about three hours. The instinct is to start writing commentary line by line. The better move is to let the model do the first pass of pattern-spotting so Dana can spend her three hours on judgment instead of formatting. The workflow has four moves, and the order matters."}$lum$::jsonb, false),
  ($lum$564a058e-2e79-5a78-a99a-3669146c6bd9$lum$::uuid, $lum$7b107772-ee1a-5040-a84c-68ac406b48df$lum$::uuid, 1, $lum$multiple_choice$lum$, $lum${"stem":"Why does the lesson argue that the format of most P&L analysis is the core problem?","options":[{"id":"a","label":"Finance teams do not collect enough data to support a real analysis.","is_correct":false,"explanation":"The lesson says the opposite: you are not short on data, you are short on a fast way to turn it into the few things leadership needs to discuss."},{"id":"b","label":"The numbers are usually wrong because they are produced under deadline pressure.","is_correct":false,"explanation":"The problem the lesson names is presentation, not accuracy. Dense tables and restated narrative, not bad arithmetic, are what get the analysis filed and forgotten."},{"id":"c","label":"Dense tables and narrative that restates the numbers never surface the three or four things leadership actually needs to discuss.","is_correct":true,"explanation":"Correct. The format buries the decisions. The work is turning data into the handful of items leadership needs, which is where a careful AI workflow earns its place."}]}$lum$::jsonb, false),
  ($lum$973e3b3e-0a06-547b-ae80-3db37ee6492e$lum$::uuid, $lum$7b107772-ee1a-5040-a84c-68ac406b48df$lum$::uuid, 2, $lum$reading$lum$, $lum${"markdown":"The first move is to anonymize and paste the actual numbers. This sounds trivial and it is the step people skip, which is why their analysis drifts into fiction. If your data is sensitive, replace company identifiers and absolute figures with placeholders or scaled values, but paste the real structure: every line item, both periods, in a clean table the model can read. The reason is simple. A model that is summarizing from a pasted statement is constrained by that statement. A model that is asked to \"analyze our Q3\" with no numbers will invent a plausible-sounding quarter, and plausible-sounding is the most dangerous output in finance. Paste first, always, so that every figure the model mentions can be traced straight back to a cell you can point to.\n\nThe second move is to ask for a bounded, plain-language summary. Bounded is the key word. You are not asking for an essay. Dana might ask for a five-sentence summary covering the overall health signal, the two biggest contributors to the period's performance, any unusual line items, and the trend direction. The boundary forces prioritization. When a model can write as much as it wants, it writes everything, and everything is the same as nothing for a board that has eleven minutes for finance. A tight summary gives Dana a draft of the \"so what\" that she can then sharpen with the context only she has."}$lum$::jsonb, false),
  ($lum$f7868d3b-5183-51b3-bfa8-d22b5adac226$lum$::uuid, $lum$7b107772-ee1a-5040-a84c-68ac406b48df$lum$::uuid, 3, $lum$multiple_choice$lum$, $lum${"stem":"Dana wants the model to draft board commentary from her closed-quarter P&L. What should she do first to keep the output trustworthy?","options":[{"id":"a","label":"Describe the quarter in words and let the model reconstruct the likely numbers.","is_correct":false,"explanation":"This invites the model to invent plausible figures. In finance, plausible-but-fabricated is the most dangerous output, because it reads as real."},{"id":"b","label":"Paste the actual P&L table, both periods, anonymized if needed, so every figure the model cites traces back to a real cell.","is_correct":true,"explanation":"Correct. Pasting the real structure constrains the model to your data. You can anonymize identifiers and scale figures, but the line items and both periods must be real so nothing is invented."},{"id":"c","label":"Ask the model to estimate industry benchmarks and compare her company against them.","is_correct":false,"explanation":"Benchmarks the model recalls from memory are unverifiable and often wrong. That is a separate, riskier task and not the foundation of an honest summary of her own numbers."}]}$lum$::jsonb, false),
  ($lum$8d5eeff6-d976-5f7f-8cf1-2ab1f6db3649$lum$::uuid, $lum$7b107772-ee1a-5040-a84c-68ac406b48df$lum$::uuid, 4, $lum$reading$lum$, $lum${"markdown":"The third move is variance analysis, and this is where you have to frame the request carefully. A controller named Marcus is explaining a margin swing: gross margin dropped four points quarter over quarter and the CFO will ask why. The weak version is to ask the model \"why did margin drop.\" It does not know why. It was not in the room. So Marcus asks instead for each significant variance to come back as two or three possible explanations, a read on whether the move is likely signal or noise, and one clarifying question he should go answer. Now the output is honest about its own limits. It hands Marcus a structured set of hypotheses to test against reality rather than a confident wrong answer he might repeat to the CFO.\n\nThe fourth move is decision framing, and the discipline here is to ask for questions, not recommendations. A finance manager named Priya is framing leadership decisions for the next thirty days. She asks the model for the three most important financial decisions leadership should be discussing, each phrased as a question rather than a recommendation. \"Should we reallocate the unspent travel budget into demand generation before year end?\" is a question Priya's leadership team is equipped to answer. \"Reallocate the travel budget\" is a recommendation the model has no business making, because it cannot see strategy, timing, cash position, or the conversation that happened in last week's leadership offsite. Questions invite the human judgment; recommendations pretend the judgment is already done.\n\nHold the whole workflow together with one principle: the model surfaces patterns and frames questions, and you do every interpretation. It can see that marketing rose while revenue stayed flat. It cannot know whether that was a deliberate brand investment with a lag, a one-time event, or a genuine problem. That gap is not a flaw to engineer away. It is the line between what the tool does and what you are paid to do. Used this way, the four moves give Dana, Marcus, and Priya a faster first draft and a sharper set of questions, while every figure still traces to the real statement and every judgment still belongs to a person who understands the business."}$lum$::jsonb, false),
  ($lum$1f0ff737-d64e-554a-8da7-ada84916054d$lum$::uuid, $lum$7b107772-ee1a-5040-a84c-68ac406b48df$lum$::uuid, 5, $lum$multiple_choice$lum$, $lum${"stem":"Marcus asks the model for variance explanations and Priya asks it to frame decisions. What distinguishes a well-framed request in both moves?","options":[{"id":"a","label":"The request keeps the model surfacing patterns and framing questions, leaving every interpretation and verdict to the person with company context.","is_correct":true,"explanation":"Correct. Marcus asks for possible explanations plus a clarifying question; Priya asks for decisions phrased as questions. Both keep the model inside detection and framing, never deciding."},{"id":"b","label":"The request asks the model directly why margin dropped and which budget to cut, so leadership gets fast answers.","is_correct":false,"explanation":"That is the weak version. The model was not in the room and cannot see strategy or cash position, so a direct 'why' or 'which' returns a confident wrong answer."},{"id":"c","label":"The request tells the model to phrase everything as recommendations so the deck reads decisively.","is_correct":false,"explanation":"Recommendations pretend the judgment is already done. The lesson's discipline is questions, not recommendations, because questions invite the human judgment the model cannot supply."},{"id":"d","label":"The request asks the model to fill in any missing company context from what it already knows.","is_correct":false,"explanation":"The model has no company context to fill in. That gap is the line between what the tool does and what you are paid to do, not something to engineer away."}]}$lum$::jsonb, false),
  ($lum$a64d0eb6-c424-5384-824a-c50141658d41$lum$::uuid, $lum$7b107772-ee1a-5040-a84c-68ac406b48df$lum$::uuid, 6, $lum$reading$lum$, $lum${"markdown":"The workflow is simple, but there are a handful of ways confident users still walk it into a wall. Knowing them in advance is most of the protection.\n\nThe most common failure is treating the model's framing as a finding. Marcus runs his variance pass and the model writes, \"Marketing spend rose forty percent while revenue was flat, a likely inefficiency to address.\" The phrase \"likely inefficiency\" feels like a conclusion, so it is tempting to drop it straight into the deck. But the model only saw two numbers move in opposite directions. It has no idea the spend was a deliberate brand campaign with a two-quarter payback. The fix is a habit: read every model conclusion as a question to investigate, never as a verdict to repeat. Detection is the model's job. Interpretation is yours.\n\nThe second failure is unbounded prompts. Ask for \"a full analysis\" and you get three pages that restate the table in sentences. The board does not have time for that, and neither do you on a Thursday. Bound everything: five sentences, three decisions, two to three explanations per variance. The constraint is what produces prioritization, and prioritization is the whole point."}$lum$::jsonb, false),
  ($lum$bc61f191-8e48-574b-a875-b7d496de8933$lum$::uuid, $lum$7b107772-ee1a-5040-a84c-68ac406b48df$lum$::uuid, 7, $lum$multiple_choice$lum$, $lum${"stem":"Marcus's variance pass returns: 'Marketing spend rose forty percent while revenue was flat, a likely inefficiency to address.' What is the right way to use that line?","options":[{"id":"a","label":"Treat it as a question to investigate, because the model has no context on timing, strategy, or what the spend was for.","is_correct":true,"explanation":"Correct. A forty percent spend rise with flat revenue could be a deliberate brand investment with a lag, a one-time event, or a real problem. The model detects the pattern; Marcus supplies the context before anything reaches the CFO."},{"id":"b","label":"Put 'marketing is inefficient' in the deck, since the model already analyzed it.","is_correct":false,"explanation":"The model saw two numbers, not the strategy behind them. Repeating its framing as a finding is how good analysis turns into a wrong claim in front of leadership."},{"id":"c","label":"Drop the observation entirely, because models cannot read financial statements.","is_correct":false,"explanation":"Too far. Spotting that spend rose while revenue stayed flat is a legitimate, useful pattern. The limit is interpretation, not detection."},{"id":"d","label":"Ask the model to decide whether the spend was justified.","is_correct":false,"explanation":"It lacks company context, so its verdict would be a guess dressed as analysis. Use it to frame the question; Marcus and his team answer it."}]}$lum$::jsonb, false),
  ($lum$b866b2ec-17ae-5bbb-a276-17d7f2081b0b$lum$::uuid, $lum$7b107772-ee1a-5040-a84c-68ac406b48df$lum$::uuid, 8, $lum$reading$lum$, $lum${"markdown":"The third failure is asking the model to decide. Priya is tired and types, \"Tell me whether we should cut the contractor budget.\" The model will answer, confidently, and its answer will be a guess wearing the costume of analysis. It cannot see cash runway, the hiring plan, or the commitment leadership made to a client last month. When you ask for a verdict, you get a fluent one, and fluency is easy to mistake for being right. Keep the model framing questions and leave the deciding to the people with context.\n\nThe fourth failure is letting figures drift. Someone pastes a P&L, then asks a follow-up question, then a third, and three turns later the model is referencing a \"twelve percent decline\" that does not appear anywhere in the original statement. Models will paraphrase numbers and occasionally round or recombine them. Before any figure leaves your screen and enters a deck, trace it back to the actual statement. If you cannot point to the cell, the number does not ship.\n\nThe last failure is forgetting to anonymize when the data is genuinely sensitive, then over-correcting by pasting nothing at all. Both extremes break the workflow. Pasting raw confidential figures into a tool you do not control is a real risk; pasting a vague description instead is how you get fiction. The middle path is to scale or mask the sensitive parts while preserving the real structure and the real relationships between line items. Get that habit right once and the rest of the workflow stays both safe and honest."}$lum$::jsonb, false),
  ($lum$6d0bb09b-9c79-593a-9079-45a826e76ee9$lum$::uuid, $lum$7b107772-ee1a-5040-a84c-68ac406b48df$lum$::uuid, 9, $lum$fill_blank$lum$, $lum${"template":"If you ask the model 'tell me whether we should cut the contractor budget,' you get a verdict that is really a {{1}}, because the model cannot see cash runway or prior commitments. And before any number the model cites reaches a deck, you must {{2}} it back to the actual statement, or it does not ship.","blanks":[{"id":"1","accept":["guess","guess wearing the costume of analysis","guess dressed as analysis","fluent guess"],"ideal":"guess"},{"id":"2","accept":["trace","trace back","trace it"],"ideal":"trace"}],"explanation":"Asking the model to decide returns a fluent guess, since it lacks the context to truly decide. And because models paraphrase and recombine figures, every number must trace back to a cell in the original statement before it enters a deck."}$lum$::jsonb, false),
  ($lum$d42c2f28-cfd9-5c12-aefc-929a38aafb64$lum$::uuid, $lum$7b107772-ee1a-5040-a84c-68ac406b48df$lum$::uuid, 10, $lum$before_after$lum$, $lum${"question":"Same P&L, two prompts. Notice which one produces something a board can actually act on.","before_prompt":"Analyze this P&L and tell me how we did.","after_prompt":"Here is our P&L for Q3, figures anonymized: [paste full table, both periods]. First, write a five-sentence plain-language summary covering the overall health signal, the two biggest contributors, any unusual line items, and the trend direction. Then, for each significant variance, give two to three possible explanations, note whether it is likely signal or noise, and suggest one clarifying question. Finally, frame the three most important decisions leadership should discuss in the next thirty days as questions, not recommendations. Use only the numbers I pasted.","changes":["Pastes the actual data, both periods, and tells the model to use only those numbers, instead of a vague 'how did we do' with nothing to anchor to.","Bounds every output: five sentences, two to three explanations per variance, three decisions, so the result prioritizes instead of restating the table.","Asks for variances framed as signal versus noise plus clarifying questions, and decisions framed as questions, keeping the model out of judgments it has no context to make."]}$lum$::jsonb, true),
  ($lum$980239fa-fd42-5a3e-bdf1-79bec29d2945$lum$::uuid, $lum$7b107772-ee1a-5040-a84c-68ac406b48df$lum$::uuid, 11, $lum$multiple_choice$lum$, $lum${"stem":"Priya is framing leadership decisions from the P&L for the next thirty days. Which request best fits what the model can responsibly produce?","options":[{"id":"a","label":"'Tell me whether we should cut the contractor budget this quarter.'","is_correct":false,"explanation":"This asks for a verdict. The model cannot see cash runway, the hiring plan, or prior commitments, so it returns a confident guess dressed as analysis."},{"id":"b","label":"'Recommend the three budget changes we should make based on these numbers.'","is_correct":false,"explanation":"Recommendations pretend the judgment is already done. The model has no strategy or context, so its picks are unanchored. Priya needs questions she can take to people who do have that context."},{"id":"c","label":"'Phrase the three most important financial decisions leadership should be discussing as questions, not recommendations.'","is_correct":true,"explanation":"Correct. Questions invite the human judgment and stay inside what the model can do well, which is framing. Priya's leadership team is equipped to answer them; the model is not equipped to decide them."}]}$lum$::jsonb, false),
  ($lum$d5ef400c-a0d6-57d8-a437-d8820cd62e5a$lum$::uuid, $lum$7b107772-ee1a-5040-a84c-68ac406b48df$lum$::uuid, 12, $lum$mini_project$lum$, $lum${"brief":"Pick a real P&L you can work with: your own most recent monthly or quarterly close, or a public company's quarterly earnings release if you would rather not use internal data. Anonymize or scale anything sensitive, keep the structure intact, and run the full four-move workflow on it: paste, bounded summary, variance pass framed as signal versus noise with clarifying questions, and three decisions framed as questions. Then compare the model's framing against how the analysis was originally presented, and stress-test the output for the failures from this lesson.","parts":[{"id":"1","prompt":"Trace every figure the model cites back to a specific line in the original statement, and flag any number you cannot locate."},{"id":"2","prompt":"Rewrite at least one of the model's \"findings\" into the investigate-this question it should have been, noting the company context the model was missing."},{"id":"3","prompt":"Decide which of the three framed questions you would actually put in front of leadership, and write one sentence on why the other two stay off the agenda for now."}]}$lum$::jsonb, false),
  ($lum$f6b68b94-96cc-5dc7-938a-f8583688bfa5$lum$::uuid, $lum$b5aecf38-58f5-5cbf-82e8-b772e2f132dc$lum$::uuid, 0, $lum$reading$lum$, $lum${"markdown":"If you work in or around law, AI can take a lot of the grind out of your day. It can draft routine correspondence, summarize a long deposition transcript, organize discovery, and give you a rough first pass at research. Used well, it clears the busywork so you can spend your hours on the parts of the job that actually need a trained legal mind. But the legal field has a hard line, and crossing it has real consequences for clients, for your firm, and for you. So let's be precise about what AI can do for legal work and what it absolutely cannot.\n\nStart with the single most important fact, because everything else follows from it. AI is not a source of legal authority. A tool like ChatGPT predicts likely text one word at a time. It does not look anything up in a law library. It does not check a real reporter or a real docket. When you ask it for a case, it produces something that looks exactly like a case, with a plausible name, a plausible court, and a plausible citation, because it has seen thousands of real citations and learned the pattern. The pattern is real. The case may be completely invented. This is not a rare glitch you can engineer around. It is how the tool works.\n\nHere is the most famous version of what happens when people forget that. In a 2023 federal case in New York, two attorneys filed a brief that cited several court decisions to support their argument. The cases did not exist. An AI tool had fabricated them, complete with quotations and citations, and when one of the lawyers asked the tool whether the cases were real, it cheerfully confirmed that they were. They were not. The judge sanctioned the attorneys, ordered them to pay a fine, and required them to notify the real judges whose names had been falsely attached to the fake opinions. The lesson is blunt. A citation that looks perfect tells you nothing about whether it is real. Nothing AI produces is legal authority until you confirm it in an actual legal source like Westlaw, Lexis, or an official reporter."}$lum$::jsonb, false),
  ($lum$01aea763-7fb3-5775-ae5f-164cbcb3da09$lum$::uuid, $lum$b5aecf38-58f5-5cbf-82e8-b772e2f132dc$lum$::uuid, 1, $lum$multiple_choice$lum$, $lum${"stem":"A paralegal asks an AI tool for cases supporting a legal argument, and it returns three case names with full citations. What is the right next step?","options":[{"id":"a","label":"Include the cases in the draft, since the AI provided complete citations.","is_correct":false,"explanation":"AI invents realistic-looking case names and citations. Attorneys have been sanctioned for filing AI-fabricated cases. A complete-looking citation is not evidence the case is real."},{"id":"b","label":"Ask the AI to confirm that the cases are real and rely on its answer.","is_correct":false,"explanation":"Asking the AI to verify itself does not help. In the famous New York sanctions case, the tool confidently confirmed cases it had invented. Verification must come from a real legal source, not the same tool."},{"id":"c","label":"Verify each case in an actual legal research database before relying on it, and discard any that do not check out.","is_correct":true,"explanation":"Correct. AI is not a legal source. Every citation must be confirmed in a real database like Westlaw or Lexis, because fabricated cases are a known and serious failure mode."}]}$lum$::jsonb, false),
  ($lum$430fd964-f805-5dc5-af70-ad6076812a22$lum$::uuid, $lum$b5aecf38-58f5-5cbf-82e8-b772e2f132dc$lum$::uuid, 2, $lum$reading$lum$, $lum${"markdown":"With that line drawn clearly, here is where AI genuinely earns its keep in a legal workflow.\n\nConsider a paralegal drafting routine correspondence. A status-update letter to a client, an engagement-letter first draft, a cover note for a document production. These are templated, low-stakes documents where most of the words are the same every time and only the details change. AI can produce a clean first version in seconds. The paralegal then edits for accuracy, tone, and the specifics of the matter, fills in the facts of the actual file, and a supervising attorney reviews anything that goes out the door. The blank page is gone, but a human still owns every word that leaves the office.\n\nConsider summarizing deposition notes. You have three hundred pages of transcript and you need the key admissions, the timeline, and the topics that came up. AI is genuinely strong at compressing and structuring text you give it. It can pull a rough summary and a topic list you can scan in minutes. You still read the passages that matter in the original transcript before you rely on them, because a summary can flatten a crucial qualifier, but the first pass saves real time.\n\nConsider explaining a clause to a client. A non-compete provision or an indemnification clause written in dense legal language can be reframed into plain English a client can actually follow. AI is good at that translation. The attorney confirms the explanation is correct for this contract and this jurisdiction before sending it, because the plain-language version is only as good as the human who checks it."}$lum$::jsonb, false),
  ($lum$a8f490c5-68ad-5176-a72c-540386587817$lum$::uuid, $lum$b5aecf38-58f5-5cbf-82e8-b772e2f132dc$lum$::uuid, 3, $lum$fill_blank$lum$, $lum${"template":"AI is genuinely strong at {{1}} the text you already give it, like compressing a long deposition into a topic list, but it is never trusted to {{2}} legal authority such as the cases or citations behind an argument.","blanks":[{"id":"1","accept":["summarizing","summarize","organizing","organize","compressing","structuring","drafting"],"ideal":"summarizing"},{"id":"2","accept":["supply","provide","produce","source","invent","generate"],"ideal":"supply"}],"explanation":"The use cases share one pattern: AI works on material you hand it, like correspondence, transcripts, or a clause, and a human still owns the result. It is never asked to supply the legal authority itself, because that is where it fabricates."}$lum$::jsonb, false),
  ($lum$f501f1b6-3a05-5cba-afd6-d81622744d11$lum$::uuid, $lum$b5aecf38-58f5-5cbf-82e8-b772e2f132dc$lum$::uuid, 4, $lum$reading$lum$, $lum${"markdown":"And here is what stays firmly with a qualified human, no exceptions. Legal advice and judgment, meaning what a client should actually do, is a professional decision and never an AI output. Final accuracy and authority, meaning every fact, every quoted rule, and every citation, must be verified by a person against a primary source. Anything filed with a court or relied upon in a transaction carries responsibility and liability that never transfers to the tool. If it goes out the door, a licensed human owns it.\n\nThe mindset that keeps you safe is simple. Treat AI as a fast, fluent junior assistant whose work you always check. It is wonderful for the first draft and the rough summary. It is never a stand-in for professional judgment, and it is never a substitute for verified legal sources. The fluency is exactly the trap. The more confident and polished an AI answer sounds, the more it tempts you to skip the verification step, and the verification step is the whole job."}$lum$::jsonb, false),
  ($lum$e5b1fa6a-9251-5d5a-a2b7-625c8f342e6c$lum$::uuid, $lum$b5aecf38-58f5-5cbf-82e8-b772e2f132dc$lum$::uuid, 5, $lum$multiple_choice$lum$, $lum${"stem":"Based on what stays with a qualified human, which task can never be handed off to an AI tool?","options":[{"id":"a","label":"Producing a clean first draft of a routine status-update letter.","is_correct":false,"explanation":"A first draft of routine correspondence is exactly the kind of low-stakes, templated work AI handles well, as long as a human edits and a supervising attorney reviews it."},{"id":"b","label":"Deciding what a client should actually do and signing off on a filing.","is_correct":true,"explanation":"Correct. Legal advice and judgment is a professional decision, and responsibility for anything filed or sent never transfers to the tool. A licensed human owns it."},{"id":"c","label":"Compressing a long transcript into a rough summary you will check.","is_correct":false,"explanation":"Summarizing text you provide is something AI is strong at. A human still reads the key passages in the original before relying on them, but the first pass is a fair use."},{"id":"d","label":"Reframing a dense clause into plain English for a human to confirm.","is_correct":false,"explanation":"Plain-language translation is a good use of AI, provided the attorney confirms the explanation is correct for the contract and jurisdiction before sending it."}]}$lum$::jsonb, false),
  ($lum$fe41ac3c-3ff5-5d3b-ae87-110661651340$lum$::uuid, $lum$b5aecf38-58f5-5cbf-82e8-b772e2f132dc$lum$::uuid, 6, $lum$reading$lum$, $lum${"markdown":"Knowing the rule is one thing. The mistakes that actually get legal workers in trouble come from forgetting it under deadline pressure, when an answer looks finished and the clock is running. Here are the ones that show up again and again, so you can spot them before they cost you.\n\nThe first is filing AI-fabricated citations without checking them. This is not hypothetical. In the 2023 New York case, real attorneys filed real briefs built on cases that an AI simply made up, and they were sanctioned for it. Since then, judges across multiple jurisdictions have caught and penalized the same mistake, and some courts now require lawyers to certify whether AI was used in a filing. The failure is always the same shape. The citation looked perfect, so nobody pulled it up to confirm it existed.\n\nThe second is pasting privileged or confidential client material into a public tool. When you drop a client's contract, settlement terms, medical records, or case strategy into a free consumer chatbot, that information may be stored, may be used to train the model, and is no longer under your control. That can breach client confidentiality and waive privilege, which is one of the most serious things a legal professional can do. Sensitive client material does not belong in a public tool, period. If your firm has an approved, contractually protected legal AI platform, use that and follow its rules instead."}$lum$::jsonb, false),
  ($lum$f00656b5-5b93-581a-ba67-132b7f5f07e7$lum$::uuid, $lum$b5aecf38-58f5-5cbf-82e8-b772e2f132dc$lum$::uuid, 7, $lum$multiple_choice$lum$, $lum${"stem":"A legal assistant is on deadline and wants AI help summarizing a sensitive client settlement agreement. Which action creates the most serious problem?","options":[{"id":"a","label":"Pasting the full agreement, including client names and settlement terms, into a free public chatbot.","is_correct":true,"explanation":"Correct. Confidential client material in a public tool can be stored, used for training, and exposed, which may breach confidentiality and waive privilege. Sensitive client data does not belong in a public tool."},{"id":"b","label":"Reading the AI summary and then checking the key terms against the original agreement.","is_correct":false,"explanation":"This is the safe approach. The summary is a first pass, and a human verifies the terms against the source before relying on them."},{"id":"c","label":"Using a firm-approved, contractually protected legal AI platform that follows the firm's confidentiality rules.","is_correct":false,"explanation":"This is a reasonable option when the platform is approved and protected. The danger is the public tool, not careful use of an approved one."}]}$lum$::jsonb, false),
  ($lum$0e177f4f-9aad-5dcf-b883-f2e9517ab2a9$lum$::uuid, $lum$b5aecf38-58f5-5cbf-82e8-b772e2f132dc$lum$::uuid, 8, $lum$reading$lum$, $lum${"markdown":"The third is treating a fluent AI answer as legal authority. The tool writes in a calm, confident, professional voice. It sounds like a senior associate. That tone has nothing to do with accuracy. AI will state a rule that was repealed years ago, or describe the law of the wrong state, with exactly the same confidence it uses when it is right. Fluency is not authority, and a polished paragraph is not a verified one.\n\nThe fourth is asking the AI to verify its own work. When you ask a tool whether the cases it gave you are real, you are asking the same prediction engine that invented them to grade itself. It will often say yes. Self-confirmation proves nothing. The check has to come from outside the tool, from a real legal database or the primary source itself.\n\nThe fifth ties them all together. Using AI output without a qualified human reviewing it. Even when every citation is real and no confidential data was exposed, a licensed professional still has to own the legal judgment, the accuracy, and anything that gets filed or sent. The responsibility never transfers to the software. If you remember one thing, remember that AI can speed up the work but it can never sign off on it."}$lum$::jsonb, false),
  ($lum$ac300aad-adc8-5178-94c9-e116df8b54a8$lum$::uuid, $lum$b5aecf38-58f5-5cbf-82e8-b772e2f132dc$lum$::uuid, 9, $lum$multiple_choice$lum$, $lum${"stem":"An AI tool gives a calm, confident answer citing a rule, and then confirms its own cases are real when asked. What do these two facts tell you about the answer's reliability?","options":[{"id":"a","label":"The confident tone and the self-confirmation together make it safe to rely on.","is_correct":false,"explanation":"Both signals are worthless as proof. The tool uses the same confident voice when it is wrong, and asking it to grade itself just re-runs the engine that may have invented the answer."},{"id":"b","label":"They tell you almost nothing, because fluency is not authority and self-confirmation proves nothing.","is_correct":true,"explanation":"Correct. A polished paragraph is not a verified one, and the same prediction engine confirming its own work cannot validate it. The check must come from outside the tool."},{"id":"c","label":"The self-confirmation is enough on its own, so the tone does not matter.","is_correct":false,"explanation":"Self-confirmation is exactly the trap. In the New York case the tool confidently confirmed cases it had fabricated. Verification has to come from a real legal database or primary source."}]}$lum$::jsonb, false),
  ($lum$b0d2d8cc-edf5-5714-b27f-65b185711a7e$lum$::uuid, $lum$b5aecf38-58f5-5cbf-82e8-b772e2f132dc$lum$::uuid, 10, $lum$before_after$lum$, $lum${"question":"Same non-compete research task, two prompts. Notice which one keeps the tool on the safe side of the line.","before_prompt":"Find me three cases that support the argument that this non-compete is unenforceable, with citations.","after_prompt":"Here is the governing rule and the two cases I already pulled and confirmed in our legal database on non-compete enforceability: [paste rule and verified cases]. Using only this material and no outside cases, draft a plain-language explanation of how these authorities apply to my client's facts, and list the open questions I still need to research. Do not add any cases, statutes, or citations of your own.","changes":["Stops asking the tool to supply legal authority, which is exactly where it invents fake cases and citations, and instead feeds it authority the human already verified.","Redirects the model to what it is genuinely good at, which is explaining and organizing verified material in plain language.","Explicitly bars it from adding its own cases or citations, so nothing unverified can slip into the work product."]}$lum$::jsonb, true),
  ($lum$7a54cdae-0850-54ee-996f-8697db833732$lum$::uuid, $lum$b5aecf38-58f5-5cbf-82e8-b772e2f132dc$lum$::uuid, 11, $lum$multiple_choice$lum$, $lum${"stem":"Why is the rewritten prompt safer for legal work than the original one?","options":[{"id":"a","label":"It asks the AI for more cases, so there is more authority to choose from.","is_correct":false,"explanation":"More AI-supplied cases means more fabrication risk, not more safety. Asking the tool for authority is the dangerous part."},{"id":"b","label":"It gives the AI already-verified authority and forbids it from adding cases, so it only explains material a human confirmed.","is_correct":true,"explanation":"Correct. The human supplies the verified law, and the tool is restricted to explaining it. The fabrication failure mode is removed because the AI is never asked to produce authority."},{"id":"c","label":"It is longer, and longer prompts always produce more accurate legal results.","is_correct":false,"explanation":"Length is not what makes it safe. What makes it safe is feeding the tool verified authority and barring it from inventing its own."}]}$lum$::jsonb, false),
  ($lum$56d02f28-ae25-5117-a31f-40e83fa9b982$lum$::uuid, $lum$b5aecf38-58f5-5cbf-82e8-b772e2f132dc$lum$::uuid, 12, $lum$mini_project$lum$, $lum${"brief":"Build your before-it-leaves-my-desk verification checklist. AI-assisted legal work is only safe when a verification step is built into the process, so write a short checklist you will run on anything AI helped produce before it is filed with a court or sent to a client. Keep it to a few lines you can actually run every time, and tape it where you will see it. At minimum, your checklist should make you do the following.","parts":[{"id":"1","prompt":"Confirm every case, statute, and citation in an authoritative legal database like Westlaw or Lexis, not in the AI, and delete anything that does not check out."},{"id":"2","prompt":"Verify that no confidential or privileged client information was pasted into a public tool, and that any AI use went through a firm-approved platform."},{"id":"3","prompt":"Name the qualified, licensed human who reviewed the work and takes responsibility for its legal accuracy before it goes out."}]}$lum$::jsonb, false),
  ($lum$11f85554-ed5e-5ff7-9c68-b30cca58ba6e$lum$::uuid, $lum$e8029024-e784-57fb-a991-3e398563877a$lum$::uuid, 0, $lum$reading$lum$, $lum${"markdown":"Marketing is the function where AI has the most immediate, measurable impact. The reason is simple: marketing is about volume plus quality. And AI allows you to hit quality at volume for the first time.\n\n**The campaign drafting system:**\n\n**Positioning brief first:** Before touching AI, write: target audience (1 specific person), primary pain point (1 sentence), your solution (1 sentence), key proof point (1 statistic). This takes 10 minutes and makes everything downstream 5x better.\n\n**Copy variants:** *\"I'm running a campaign targeting [audience] with this positioning: [brief]. Write: 3 subject lines, 3 headline variants, 2 full email body versions, 5 CTA button options. Each should feel genuinely different.\"*\n\n**Channel adaptation:** *\"Take the winning headline. Adapt it for: a LinkedIn post (150 words), a Twitter opener, a paid ad headline (under 40 characters).\"*\n\n**Iteration signal:** When you run A/B tests, feed results back: *\"Version A won with 34% higher open rate. Why might X have won? Give me 5 more headline variations that push further in that direction.\"*\n\nThis isn't replacing your creative judgment: it's removing the blank page problem across every channel simultaneously."}$lum$::jsonb, false),
  ($lum$e918248d-5711-52ab-9994-54c355b4475d$lum$::uuid, $lum$e8029024-e784-57fb-a991-3e398563877a$lum$::uuid, 1, $lum$before_after$lum$, $lum${"question":"Same campaign, two prompts. Notice what the positioning brief does to the output.","before_prompt":"Write me 3 subject lines and a marketing email for our new feature.","after_prompt":"I'm running a campaign targeting operations managers at 200-person logistics firms. Positioning: they lose hours reconciling delivery exceptions by hand; our tool auto-flags exceptions in real time; teams using it cut reconciliation time 60%. Write 3 subject lines, 3 headline variants, and 2 full email bodies, each genuinely different in angle.","changes":["Front-loads a four-part positioning brief (audience, pain, solution, proof) so the copy speaks to one specific person instead of everyone.","Names a concrete proof point (60% time cut) the model can build hooks around, instead of leaving it to invent vague benefits.","Asks for distinct variants at volume, turning the model into a draft engine while the curatorial pick stays with the marketer."]}$lum$::jsonb, true),
  ($lum$dc0307aa-2baf-533c-ae22-f7b4c4bf1b21$lum$::uuid, $lum$e8029024-e784-57fb-a991-3e398563877a$lum$::uuid, 2, $lum$multiple_choice$lum$, $lum${"stem":"AI lets a marketing team produce copy at 10x the volume. Which part of the work becomes MORE important as a result, not less?","options":[{"id":"a","label":"The curatorial judgment: choosing which variants are on-brand and on-strategy, and killing the ones that are not.","is_correct":true,"explanation":"Correct. When drafting is cheap, the bottleneck moves to selection. Your value shifts from writing every word to deciding which of the many machine-generated options actually deserve to ship."},{"id":"b","label":"Typing speed, since you now have far more copy to produce by hand.","is_correct":false,"explanation":"The whole point is that the model produces the volume. You are not typing more; you are choosing more."},{"id":"c","label":"Nothing changes; AI simply does the same job faster with no shift in what you focus on.","is_correct":false,"explanation":"The job does change. Removing the blank-page problem moves your effort from generation to positioning and curation."},{"id":"d","label":"Writing the positioning brief becomes optional once the model can generate freely.","is_correct":false,"explanation":"The opposite. A weak brief multiplied across 10x the output just produces 10x the off-target copy. The brief matters more, not less."}]}$lum$::jsonb, false),
  ($lum$87c46693-b8d8-55bd-a670-a6a0642fefae$lum$::uuid, $lum$e8029024-e784-57fb-a991-3e398563877a$lum$::uuid, 3, $lum$mini_project$lum$, $lum${"brief":"Your 5-minute exercise: Write a 4-sentence positioning brief for any current campaign. Run the copy variants prompt. Pick the strongest 3 and note why they work.","parts":[]}$lum$::jsonb, false),
  ($lum$7616e69a-069f-57fd-8fe3-c6044341652e$lum$::uuid, $lum$8af01945-b2ba-5d93-a1ee-e8e12655f57f$lum$::uuid, 0, $lum$reading$lum$, $lum${"markdown":"Operations teams live and die by process clarity. A process that lives in someone's head is a process that breaks when that person is on vacation. Process mapping (making the implicit explicit) is tedious, which is why it doesn't happen until something breaks.\n\n**The AI-assisted process mapping workflow:**\n\n**Step 1: Interview capture.** Have a 20-minute conversation with the process owner. Ask: \"Walk me through every step, including everything you consider obvious.\" Record and transcribe.\n\n**Step 2: Initial map generation.** *\"Here's a transcription describing [process]. Generate: 1) A numbered step-by-step map, 2) A swimlane description (who does what in which system), 3) A list of decision points, 4) Dependencies.\"*\n\n**Step 3: Gap identification.** *\"Given this process map, what are: 1) Single points of failure, 2) Steps lacking a clear owner, 3) Likely bottlenecks, 4) Steps that could be automated?\"*\n\n**Step 4: Automation candidates.** For flagged steps: *\"What tools or integrations could eliminate the manual work here? What would the integration look like?\"*\n\nOperations improvement starts with seeing the process clearly. Most teams can't do that until it's on paper."}$lum$::jsonb, false),
  ($lum$c73591a9-0cce-5fdc-b639-51e7cf4c5548$lum$::uuid, $lum$8af01945-b2ba-5d93-a1ee-e8e12655f57f$lum$::uuid, 1, $lum$before_after$lum$, $lum${"question":"Same process, two prompts. Notice which one can actually produce an accurate map.","before_prompt":"Map out our customer onboarding process.","after_prompt":"Here is a transcript of the onboarding owner walking through every step, including the obvious ones: [paste transcript]. From only this transcript, generate: 1) a numbered step-by-step map, 2) a swimlane view of who does what in which system, 3) the decision points, 4) the dependencies. Do not add steps that are not in the transcript.","changes":["Feeds the model the real captured process instead of asking it to guess what onboarding looks like, which is how invented steps creep in.","Asks for the specific artifacts (steps, swimlanes, decision points, dependencies) rather than a vague map.","Constrains it to the transcript, so the map reflects how the work actually happens, not a generic textbook version."]}$lum$::jsonb, true),
  ($lum$e98d4345-b581-5fbf-9fef-e4675cdfdb81$lum$::uuid, $lum$8af01945-b2ba-5d93-a1ee-e8e12655f57f$lum$::uuid, 2, $lum$multiple_choice$lum$, $lum${"stem":"You give AI a clean process map and ask it for single points of failure, unowned steps, and bottlenecks. How should you treat what it returns?","options":[{"id":"a","label":"As a strong list of candidates to investigate, which you confirm against how the work really runs before acting.","is_correct":true,"explanation":"Correct. AI is good at surfacing where a process looks fragile, but it only sees the words in the map. The flagged risks are leads to verify with the people doing the work, not conclusions."},{"id":"b","label":"As a finished risk assessment you can hand to leadership as-is.","is_correct":false,"explanation":"The model reasons only from the map you gave it. It can miss a real bottleneck the map glossed over or flag a step that is fine in practice. Treat it as a draft to verify."},{"id":"c","label":"As proof that the flagged steps must be automated immediately.","is_correct":false,"explanation":"Flagging a step as an automation candidate is not the same as confirming automation is worth it. That is a judgment call requiring cost, risk, and context the model does not have."},{"id":"d","label":"Ignore it; AI cannot say anything useful about a process it did not design.","is_correct":false,"explanation":"Too far. Surfacing likely failure points from a documented process is exactly the kind of structured analysis AI does well. You just verify before acting."}]}$lum$::jsonb, false),
  ($lum$015eb771-3bee-5e65-855a-beff2fa6da0b$lum$::uuid, $lum$8af01945-b2ba-5d93-a1ee-e8e12655f57f$lum$::uuid, 3, $lum$mini_project$lum$, $lum${"brief":"Your 5-minute exercise: Pick one recurring process. Spend 3 minutes writing every step you can think of, including the 'obvious' ones. Run step 2 above. What did you miss?","parts":[]}$lum$::jsonb, false),
  ($lum$dcc10792-383f-55f7-b649-344184decff5$lum$::uuid, $lum$3cc781f0-49a5-5b87-b4c9-1349311f1976$lum$::uuid, 0, $lum$reading$lum$, $lum${"markdown":"Product specs (PRDs, feature briefs, technical requirements) are the highest-leverage documents a PM writes. They're also the most time-consuming. The good news: they're almost entirely structured, which makes them excellent candidates for AI assistance.\n\n**The spec writing workflow:**\n\n**Step 1: Problem statement.** Write this yourself. AI is bad at identifying problems; it's good at everything that comes after. Your 3-sentence problem statement should describe: who has the problem, what they currently do, and what makes that inadequate.\n\n**Step 2: AI-assisted scaffolding.** *\"I'm writing a PRD for [feature]. The problem: [your statement]. Generate: 1) 3 user stories, 2) A draft success metrics section, 3) Potential edge cases, 4) A list of dependencies.\"*\n\n**Step 3: Scope definition.** *\"What's the minimum viable version? What am I including that could be cut for v1? What would make this scope creep?\"*\n\n**Step 4: Review checklist.** *\"What critical sections are typically in a PRD that aren't yet in this draft?\"*\n\nThe judgment calls stay with you. The scaffolding, structure, and completeness checks become fast."}$lum$::jsonb, false),
  ($lum$6c996ae7-8109-5457-a84b-95f07454442b$lum$::uuid, $lum$3cc781f0-49a5-5b87-b4c9-1349311f1976$lum$::uuid, 1, $lum$multiple_choice$lum$, $lum${"stem":"In the spec-writing workflow, which single part should you write yourself rather than delegate to AI?","options":[{"id":"a","label":"The problem statement: who has the problem, what they do now, and why that is inadequate.","is_correct":true,"explanation":"Right. AI is good at everything downstream of the problem, but it cannot identify the actual problem worth solving. A scaffolding generated on top of a wrong problem statement is a polished spec for the wrong thing."},{"id":"b","label":"The list of potential edge cases.","is_correct":false,"explanation":"Edge-case generation is exactly what AI is strong at. Give it a clear problem statement and it will surface cases you would have missed."},{"id":"c","label":"The draft success-metrics section.","is_correct":false,"explanation":"Drafting a metrics section is structured scaffolding work, a good delegation. You still edit it, but AI gives you a solid starting frame."},{"id":"d","label":"The list of dependencies.","is_correct":false,"explanation":"Dependency lists are structural and well-suited to AI. The judgment call you cannot delegate is naming the real problem."}]}$lum$::jsonb, false),
  ($lum$a95cf2ec-5b07-5ba2-b6f6-22e244499588$lum$::uuid, $lum$3cc781f0-49a5-5b87-b4c9-1349311f1976$lum$::uuid, 2, $lum$before_after$lum$, $lum${"question":"Same feature, two ways to ask for scaffolding. Notice what the second prompt brings that the first cannot.","before_prompt":"Write me a PRD for a new in-app notifications feature.","after_prompt":"I'm a PM at a B2B scheduling tool. The problem: admins miss last-minute booking changes because we only notify by email, which they check a few times a day, so they show up unprepared. Using that problem statement, generate: 1) three user stories, 2) a draft success-metrics section, 3) likely edge cases, 4) a dependency list. Do not restate the problem; build on it.","changes":["Leads with a real problem statement written by the PM, so the scaffolding is built on the actual problem instead of an invented one.","Names the concrete artifacts to produce (user stories, metrics, edge cases, dependencies) rather than asking for a vague whole PRD.","Keeps the judgment call (what problem we are solving) with the human and delegates only the structure to the tool."]}$lum$::jsonb, true),
  ($lum$b3c3b18d-2252-5ad8-b3f3-b7d40e3bc1b6$lum$::uuid, $lum$3cc781f0-49a5-5b87-b4c9-1349311f1976$lum$::uuid, 3, $lum$mini_project$lum$, $lum${"brief":"Your 5-minute exercise: Think of the last feature you were involved in specifying. Run step 2 above for it. Does the model surface edge cases that weren't in the original spec?","parts":[]}$lum$::jsonb, false),
  ($lum$1070bbc2-64e3-5201-aeb8-d803ad64b1bb$lum$::uuid, $lum$150c8973-03f5-5e8e-bc31-fb560101630d$lum$::uuid, 0, $lum$reading$lum$, $lum${"markdown":"The conversation about AI in schools usually skips the most useful step. We debate whether students should be allowed to use it while the students themselves are already using it, with no shared understanding of what counts as fair help and what counts as cheating. Silence is not a neutral policy. It just means every student is guessing, and the careful, rule-following kids lose ground to the ones willing to push. If you have ever graded two essays and quietly wondered which one a chatbot wrote, you already know the cost of leaving this unspoken.\n\nSetting honest expectations starts with one distinction that does almost all the work: AI is useful where it supports the thinking, and harmful where it replaces the thinking your assignment exists to build. The line is not the tool. It is the skill the task was designed to grow. Once you hold onto that, most hard cases sort themselves out. Let me show you what that looks like in three real classrooms."}$lum$::jsonb, false),
  ($lum$96bf79be-884f-5045-91a9-790298b8e89f$lum$::uuid, $lum$150c8973-03f5-5e8e-bc31-fb560101630d$lum$::uuid, 1, $lum$multiple_choice$lum$, $lum${"stem":"According to this segment, what single distinction does almost all the work when you set honest expectations about AI?","options":[{"id":"a","label":"Whether the AI tool is a simple one or an advanced one.","is_correct":false,"explanation":"The segment is explicit that the line is not the tool. The same tool can help or harm depending on the task, so the simple-versus-advanced framing misses the point entirely."},{"id":"b","label":"Whether the student is honest enough to admit they used AI.","is_correct":false,"explanation":"Honesty matters elsewhere in the lesson, but the core distinction here is about support versus replacement of thinking, not about whether a student confesses to using the tool."},{"id":"c","label":"Whether AI supports the thinking or replaces the thinking the assignment exists to build.","is_correct":true,"explanation":"Correct. The segment names this as the one distinction that does almost all the work: AI is useful where it supports the thinking and harmful where it replaces the skill the task was designed to grow."},{"id":"d","label":"Whether the school has a written policy banning AI use.","is_correct":false,"explanation":"A written ban is not the distinction the segment draws. The lesson treats silence and blanket bans alike as ways of dodging the real call about what skill each task builds."}]}$lum$::jsonb, false),
  ($lum$c2649651-d7d3-57d6-9a19-172085924598$lum$::uuid, $lum$150c8973-03f5-5e8e-bc31-fb560101630d$lum$::uuid, 2, $lum$reading$lum$, $lum${"markdown":"Take a 9th grade English essay assigned so students can practice building an argument. The whole point is the wrestling: picking a claim, finding evidence, deciding what order convinces a reader. If a student asks AI to brainstorm possible topics or to push back on a thesis that feels weak, that supports the thinking. The student still has to choose, defend, and write. But if the same student asks AI to generate a draft of the essay, the tool has done the exact skill the assignment was built to develop. The student gets a grade and learns nothing about argument. Same tool, opposite outcomes, and the difference is the skill, not the software.\n\nNow picture a middle school math class working through multi-step word problems. The task exists to build reasoning: translating a messy real-world situation into the right operations and deciding what to do in what order. A student who sets up the problem, decides that a sale price means subtracting before multiplying, solves it, and then uses AI to check whether the arithmetic is correct is using it like a calculator with manners. That supports the work. A student who pastes in the whole word problem and copies back the answer and the steps has skipped the reasoning the problem was written to teach. The arithmetic was never the point. The thinking was, and that is what got replaced.\n\nFinally, a research project where students compare three sources on a historical event and write their own analysis. Here the line falls in an interesting place. Using AI to summarize a dense source so the student can grasp it faster can be reasonable support, the way a good study guide is, because comprehension is a doorway, not the destination. But the assignment exists to build the student's ability to weigh sources against each other and form a judgment. The moment AI writes the analysis, comparing the sources and drawing the conclusion, it has done the actual work being assessed. Summarizing to understand is support. Analyzing to conclude is replacement. You, the teacher, are the only one who knows which side of that line each part of your assignment sits on."}$lum$::jsonb, false),
  ($lum$490b19f5-2d63-5a3c-9d8f-d6bf52ea0c65$lum$::uuid, $lum$150c8973-03f5-5e8e-bc31-fb560101630d$lum$::uuid, 3, $lum$multiple_choice$lum$, $lum${"stem":"You are deciding where to draw the line on AI use across several different assignments. Which principle best reflects this lesson's way of setting expectations?","options":[{"id":"a","label":"Ban AI from all assignments, since any use of it undermines learning.","is_correct":false,"explanation":"A blanket ban misses the distinction. AI used to brainstorm, get unstuck, or check arithmetic can support learning. The lesson treats a policy that bans it everywhere as one that skipped the judgment only you can supply."},{"id":"b","label":"Allow AI where it supports the thinking and restrict it where it replaces the specific skill the assignment was built to develop.","is_correct":true,"explanation":"Correct. The line is not the tool, it is the skill the task exists to grow. Brainstorming topics or checking arithmetic supports learning, while generating the essay or solving the reasoning problem replaces the exact skill being assessed."},{"id":"c","label":"Allow AI everywhere and trust students to use it responsibly without specifics.","is_correct":false,"explanation":"'Use it responsibly' means nothing without concrete yes and no examples. Allowing it everywhere ignores that some tasks exist precisely to make students do the thinking themselves."},{"id":"d","label":"Decide based on which AI tool the student used, allowing simple ones and banning advanced ones.","is_correct":false,"explanation":"The line is never the tool. The same tool can support learning on one task and replace it on another. What matters is the skill the assignment was built to develop, not the software's brand or power."}]}$lum$::jsonb, false),
  ($lum$5e0cf61b-4ac1-580b-b18d-2aff44bacdce$lum$::uuid, $lum$150c8973-03f5-5e8e-bc31-fb560101630d$lum$::uuid, 4, $lum$reading$lum$, $lum${"markdown":"That last point matters, so let me be direct about it. You can and should use AI to help you draft this policy, and it genuinely speeds things up. Ask it to write a short, plain-language classroom AI policy for your grade level that separates allowed support from off-limits replacement, with concrete examples on each side. But the judgment about where the line actually falls is yours, because only you know what each assignment is teaching. A draft that bans AI everywhere or allows it everywhere has skipped the one decision you have to make yourself. The AI can format your thinking. It cannot do your thinking, which is exactly the lesson you are trying to teach your students.\n\nTwo more things make a policy work in practice. First, write it in language a student and a parent can both understand, not policy jargon, and give examples, because \"use AI responsibly\" means nothing until it becomes \"yes to this, no to that.\" Vague rules are unfair rules, because the confident students decode them generously and the anxious ones freeze. Second, model the honesty you are asking for. Tell students how you use AI in your own work and where you stop. Maybe you use it to brainstorm warm-up questions but write your own feedback on their writing, because the feedback is the part that has to come from you. When students see you drawing the same kind of line you are asking them to draw, the policy stops feeling like a trap and starts feeling like a shared standard. Expectations you name plainly, and visibly live yourself, are the ones students can actually follow."}$lum$::jsonb, false),
  ($lum$c432d162-e578-5898-8ddd-69c3f95e4bc9$lum$::uuid, $lum$150c8973-03f5-5e8e-bc31-fb560101630d$lum$::uuid, 5, $lum$multiple_choice$lum$, $lum${"stem":"Based on this segment, why should you draft your classroom AI policy yourself even though AI can speed up the writing?","options":[{"id":"a","label":"Because the judgment about where the line falls is yours, since only you know what each assignment is teaching.","is_correct":true,"explanation":"Correct. The segment says AI can format your thinking but cannot do your thinking. A draft that bans or allows AI everywhere has skipped the one decision only you can make, because only you know what each task is built to teach."},{"id":"b","label":"Because AI tools are not allowed to be used by teachers when writing official documents.","is_correct":false,"explanation":"The segment says the opposite: you can and should use AI to help draft the policy, and it genuinely speeds things up. The point is about keeping the judgment, not avoiding the tool."},{"id":"c","label":"Because a policy written by AI will always contain factual errors about your school.","is_correct":false,"explanation":"The concern is not factual errors. It is that an AI draft cannot supply the per-assignment judgment about what skill each task teaches, which is the decision only the teacher can make."},{"id":"d","label":"Because students can tell when a policy was written by AI and will trust it less.","is_correct":false,"explanation":"Detection by students is not the reason given here. The segment's point is that AI can format your thinking but cannot do it, so the line-drawing decision has to stay with you."}]}$lum$::jsonb, false),
  ($lum$88fbdadd-c404-5ab2-8f56-eb345c8a550b$lum$::uuid, $lum$150c8973-03f5-5e8e-bc31-fb560101630d$lum$::uuid, 6, $lum$reading$lum$, $lum${"markdown":"The way teachers get this wrong is rarely careless. It usually comes from trying to be fair and ending up vague, or trying to be safe and ending up rigid. Watch for these four patterns, because each one looks responsible and quietly fails.\n\nThe first is the \"use AI responsibly\" policy with no examples. It sounds balanced and trusting, but it hands students a rule they cannot actually apply. A 10th grader staring at a research paper at 10 p.m. does not know if summarizing a source counts as responsible. The phrase has no edges. In practice it means the bold students interpret it loosely, the anxious students interpret it strictly, and you have created the exact unfairness you were trying to avoid. A policy without concrete yes and no examples is not a policy. It is a vibe.\n\nThe second is the blanket ban or the blanket allow, both of which skip your judgment. A total ban treats AI as uniformly corrupting and punishes legitimate support like checking grammar or getting unstuck on a topic. A total allow treats every assignment as if the skill it builds does not matter. Both are attractive because they are easy: no per-assignment thinking required. But the easiness is the tell. The whole job is deciding, assignment by assignment, what skill is being built and therefore what help is fair. A policy that removes that decision has removed the only part that needed a teacher."}$lum$::jsonb, false),
  ($lum$3458bf4d-11a4-5d3d-aac2-bd948019a8fd$lum$::uuid, $lum$150c8973-03f5-5e8e-bc31-fb560101630d$lum$::uuid, 7, $lum$fill_blank$lum$, $lum${"template":"A 'use AI responsibly' policy with no examples fails because the phrase has no {{1}}, leaving bold students to interpret it loosely and anxious students to interpret it {{2}}.","blanks":[{"id":"1","accept":["edges","edge"],"ideal":"edges"},{"id":"2","accept":["strictly","strict","tightly","narrowly"],"ideal":"strictly"}],"explanation":"The segment says the phrase 'use AI responsibly' has no edges, so the bold students interpret it loosely while the anxious ones interpret it strictly, which recreates the exact unfairness a teacher was trying to avoid."}$lum$::jsonb, false),
  ($lum$dcd7b8aa-ccf6-5c3a-b912-c48191de114f$lum$::uuid, $lum$150c8973-03f5-5e8e-bc31-fb560101630d$lum$::uuid, 8, $lum$reading$lum$, $lum${"markdown":"The third pitfall is treating an AI-drafted policy as the authority. This is the one most tied to the broader theme of these lessons. When you ask AI to write your classroom policy, it will produce something confident and well-formatted, and it is tempting to adopt it as is because it sounds official. But the AI does not know that your 9th grade essay is about argument while your 11th grade essay is about close reading. It cannot set the line for your specific assignment, because it does not know what your assignment is for. The draft is a starting point you edit, not an answer you accept. The moment you let the polished output stand in for your own judgment, you have made the exact mistake you are warning students against: letting AI do the thinking that was supposed to be yours. AI output is a draft, never a verdict.\n\nThe fourth is failing to model the honesty you demand. If you forbid students from using AI to generate text but quietly run all your feedback through a chatbot, students notice, and your policy loses its moral weight overnight. This does not mean you cannot use AI. It means you have to be open about where you use it and where you refuse to, on the same support-versus-replacement logic you ask of them. A teacher who says \"I use AI to brainstorm discussion questions, but I write your feedback myself because that part has to come from me\" has more authority than any policy document. Asking for an honesty you will not show yourself is the fastest way to teach students that the rules are for the powerless.\n\nThe thread running through all four is the same: AI can format and suggest, but it cannot supply the judgment. The line-drawing is yours, the modeling is yours, and the per-assignment call is yours. Hand any of those to the tool and the policy hollows out, exactly like a student essay that a chatbot wrote."}$lum$::jsonb, false),
  ($lum$4183a06d-9255-5b75-bcc7-97fc3f321eb5$lum$::uuid, $lum$150c8973-03f5-5e8e-bc31-fb560101630d$lum$::uuid, 9, $lum$multiple_choice$lum$, $lum${"stem":"A colleague asks AI to write a classroom AI policy, gets a polished one-page document, and posts it unchanged because it 'sounds official.' What is the core mistake?","options":[{"id":"a","label":"They treated the AI-drafted policy as the authority instead of setting the per-assignment line themselves, which AI cannot do because it does not know what each assignment teaches.","is_correct":true,"explanation":"Correct. The polished draft is a starting point to edit, not a verdict to accept. Only the teacher knows the skill each assignment builds, so only the teacher can draw the actual line. Accepting the output as-is is the exact mistake we warn students against."},{"id":"b","label":"They used AI at all, when policies should always be written entirely by hand.","is_correct":false,"explanation":"Using AI to draft the policy is fine and even recommended. The lesson encourages it for speed. The problem is not the drafting, it is adopting the draft without supplying your own per-assignment judgment."},{"id":"c","label":"The policy was only one page, which is too short to cover classroom AI use.","is_correct":false,"explanation":"Length is not the issue. A short, plain-language policy is exactly the goal. The failure is that it was posted unedited, with no teacher judgment about where the line falls for specific assignments."},{"id":"d","label":"They posted it publicly instead of emailing it to families first.","is_correct":false,"explanation":"Distribution method is not the point. The mistake is substantive: letting the AI's confident output stand in for the teacher's own line-drawing, which no tool can do for you."}]}$lum$::jsonb, false),
  ($lum$66be145d-c1c3-5803-ba76-5072fd5d28b7$lum$::uuid, $lum$150c8973-03f5-5e8e-bc31-fb560101630d$lum$::uuid, 10, $lum$before_after$lum$, $lum${"question":"You want AI to help you draft a classroom AI policy. Which prompt produces something students and families can actually follow?","before_prompt":"Write an AI policy for my classroom.","after_prompt":"Draft a short, plain-language AI use policy for my 9th grade English class, written so a student and a parent can both understand it. Build it around one idea: AI is welcome when it supports thinking and off-limits when it replaces the thinking an assignment is meant to build. Give three concrete 'yes' examples, like brainstorming essay topics, checking grammar, and summarizing a dense source to understand it. Give three concrete 'no' examples, like generating a draft of an essay we write to practice argument, solving a math word problem we use to practice reasoning, and writing the analysis in a research project. Keep it under 200 words, warm in tone, and end with one line inviting students to ask when they are unsure. I will adjust where the line falls per assignment.","changes":["Names the audience and reading level, a student and a parent in plain language, instead of leaving the tone and complexity to chance.","Anchors the policy on the support-versus-replacement principle with specific yes and no examples, which is what turns 'be responsible' into a rule students can actually apply.","Reserves the per-assignment line-drawing for the teacher, signaling that the AI drafts the wording while the judgment stays with the person who knows what each task teaches."]}$lum$::jsonb, true),
  ($lum$cb7b00f0-ce73-5b5f-a7ac-ed6caf48c02a$lum$::uuid, $lum$150c8973-03f5-5e8e-bc31-fb560101630d$lum$::uuid, 11, $lum$multiple_choice$lum$, $lum${"stem":"In the improved prompt, why does the teacher add the sentence 'I will adjust where the line falls per assignment'?","options":[{"id":"a","label":"To make the policy longer so it seems more thorough to families.","is_correct":false,"explanation":"Length is not the goal, and the prompt actually caps the policy under 200 words. The sentence is about preserving judgment, not padding the document."},{"id":"b","label":"To shift responsibility for any unfairness onto the AI if students complain.","is_correct":false,"explanation":"It does the opposite. The sentence keeps responsibility with the teacher, stating that the human will set the real line. It is about owning the judgment, not deflecting it."},{"id":"c","label":"To keep the line-drawing judgment with the teacher, since the AI cannot know what skill each specific assignment is built to develop.","is_correct":true,"explanation":"Correct. The AI can draft clear wording and examples, but only the teacher knows that one essay practices argument and another practices close reading. The sentence reserves that per-assignment call for the human, where it belongs."}]}$lum$::jsonb, false),
  ($lum$8a7addab-3955-533d-aab6-d727a15fcd9f$lum$::uuid, $lum$150c8973-03f5-5e8e-bc31-fb560101630d$lum$::uuid, 12, $lum$mini_project$lum$, $lum${"brief":"Draft a real AI policy for one class you teach, and make the judgment yours before you let AI touch the wording. Start by picking one upcoming assignment and naming, in a sentence, the specific skill it is built to develop, so you can decide what AI help would support that skill versus replace it. Then have AI draft a short, plain-language policy with concrete yes and no examples at your grade level. Finally, edit the draft so the line matches your judgment rather than a generic default, and add one honest line about how you use AI in your own work and where you stop, because the expectations you model are the ones students follow.","parts":[{"id":"1","prompt":"Choose one upcoming assignment and write a single sentence naming the skill it exists to build, then list two AI uses that support that skill and two that would replace it."},{"id":"2","prompt":"Prompt AI to draft a under-200-word policy for your grade level with three concrete \"yes\" examples and three concrete \"no\" examples in plain language a parent could read."},{"id":"3","prompt":"Edit the draft to fit your own line, then add one honest sentence about where you use AI in your work and where you refuse to, and share it with the class."}]}$lum$::jsonb, false),
  ($lum$2a6b7b8d-4541-5adc-8d05-f24e246f9d41$lum$::uuid, $lum$002434d9-17a1-51ca-89c2-b55857bb9fa8$lum$::uuid, 0, $lum$reading$lum$, $lum${"markdown":"A single patient handoff is hard. A shift-change report on four, five, or six patients is harder, because now you are not just transferring facts, you are transferring priorities. The oncoming nurse needs to know, in order, who could go bad, what is still pending, and what is due in the next hour. Get the order wrong and the sickest patient waits.\n\nMost end-of-shift notes are organized by room number, which is the least useful order for the person taking over. AI can re-sort them by what actually matters.\n\n**The briefing prompt:**\n\n*\"Here are my de-identified notes for my full assignment this shift. Build a shift-change briefing for the oncoming nurse. Order it by clinical priority, not room number: least stable or highest-risk patients first. For each, give one line on status, what is pending (labs, consults, results), and what is due in the next two hours. Flag anything time-sensitive at the top. Use only what I provided.\"*\n\n**Why priority order changes everything.** When the report leads with the patient who needs watching, the oncoming nurse builds the right mental model from the first sentence. A room-number list buries the lede.\n\n**You own the triage call.** The tool orders based on the words you gave it. If it ranks two patients wrong, you reorder them, because you saw them and it did not.\n\n**Privacy:** de-identify the full set before pasting, or use an approved tool. A whole-assignment note is dense with identifiers."}$lum$::jsonb, false),
  ($lum$f5b56a41-6718-5067-81a0-aab583c0e92a$lum$::uuid, $lum$002434d9-17a1-51ca-89c2-b55857bb9fa8$lum$::uuid, 1, $lum$before_after$lum$, $lum${"question":"Same assignment, two prompts. Notice which one builds the right mental model for the oncoming nurse.","before_prompt":"Summarize my notes for my five patients so I can hand off at shift change.","after_prompt":"Here are my de-identified notes for my full assignment. Build a shift-change briefing for the oncoming nurse. Order it by clinical priority, not room number: least stable or highest-risk first. For each, give one line on status, what is pending (labs, consults, results), and what is due in the next two hours. Flag anything time-sensitive at the top. Use only what I provided.","changes":["Asks for priority order instead of a flat summary, so the report leads with the patient who could go bad rather than burying them at room 4.","Specifies the three things the oncoming nurse needs per patient: status, what is pending, and what is due soon.","Pulls time-sensitive items to the top, so the most urgent handoff information lands in the first sentence."]}$lum$::jsonb, true),
  ($lum$fb08512b-9f04-5713-a5f0-898efb357d7c$lum$::uuid, $lum$002434d9-17a1-51ca-89c2-b55857bb9fa8$lum$::uuid, 2, $lum$multiple_choice$lum$, $lum${"stem":"The AI briefing ranks Patient C (stable, awaiting a routine discharge) above Patient A (new-onset chest pain, troponin pending). You saw both. What do you do?","options":[{"id":"a","label":"Reorder it so Patient A leads. You assessed them; the tool only ranked the words you typed, and it got the triage wrong.","is_correct":true,"explanation":"Correct. The tool orders based on the language you gave it, not a clinical exam. You own the triage call, so when its order does not match your read of who is least stable, you fix it."},{"id":"b","label":"Leave it; the AI processed all your notes and likely weighed something you missed.","is_correct":false,"explanation":"The tool cannot see the patient or weigh acuity the way you can. Pending troponin on new chest pain outranks a routine discharge, and your judgment overrides the model's ordering."},{"id":"c","label":"Ask the AI to explain its ranking and adopt whatever reasoning it gives.","is_correct":false,"explanation":"Its explanation will be a plausible rationalization of a flawed order. The fix is your clinical judgment, not the model's justification."},{"id":"d","label":"Re-sort the whole list by room number to be safe.","is_correct":false,"explanation":"Room-number order is the least useful for a handoff; it buries the sickest patient. Reorder by clinical priority using your own read."}]}$lum$::jsonb, false),
  ($lum$98ff936b-dfb9-5e96-81d7-b28a7bfb68eb$lum$::uuid, $lum$002434d9-17a1-51ca-89c2-b55857bb9fa8$lum$::uuid, 3, $lum$mini_project$lum$, $lum${"brief":"Your 5-minute exercise: Near the end of your next shift, gather your de-identified notes for the whole assignment and run the briefing prompt. Compare the AI's priority order to the order you would have reported in. Where do you disagree, and why does your clinical judgment override it?","parts":[]}$lum$::jsonb, false),
  ($lum$fea17941-f21e-5fe5-bce7-d1cdab445c82$lum$::uuid, $lum$876f6e22-cd9c-56b6-a504-f9b483db6f40$lum$::uuid, 0, $lum$reading$lum$, $lum${"markdown":"Every teacher knows a clear rubric is worth the effort. It makes expectations visible to students before they start, it keeps your grading consistent across thirty papers, and it gives you something concrete to point to when a grade gets questioned at conferences. The problem is the build. Writing four performance levels across five criteria, with language that genuinely distinguishes a 3 from a 4, is slow, fiddly work that competes with lesson planning, grading, and everything else on your plate. So the rubric becomes the thing you meant to make, and the assignment gets graded by feel.\n\nThis is structured drafting, and it is squarely in what AI does well. You describe the assignment and what mastery looks like in your own words, and the model lays out the grid: criteria as rows, performance levels as columns, a short observable descriptor in each cell. The tedious parallel phrasing, the part where you have to write four versions of the same idea that step up cleanly, gets done in seconds. Your job shifts from building to reviewing, which is faster and plays to your judgment. A blank rubric template is a two-hour staring contest. A drafted one is a fifteen-minute read where you mostly nod and occasionally fix.\n\nBe specific about what you are assessing. The more concrete your description, the less generic the draft. Here is what that looks like across three real assignments."}$lum$::jsonb, false),
  ($lum$912c4926-3609-578c-8bea-a415bf9c58d7$lum$::uuid, $lum$876f6e22-cd9c-56b6-a504-f9b483db6f40$lum$::uuid, 1, $lum$multiple_choice$lum$, $lum${"stem":"According to this segment, why does the rubric so often end up being the thing a teacher meant to make but never finished?","options":[{"id":"a","label":"Because rubrics rarely make expectations visible to students or help during grade disputes.","is_correct":false,"explanation":"The segment says the opposite: a clear rubric makes expectations visible, keeps grading consistent, and gives you something to point to when a grade is questioned. The payoff is not in doubt."},{"id":"b","label":"Because the build is slow, fiddly work, writing parallel level descriptors that distinguish a 3 from a 4, and it competes with everything else on a teacher's plate.","is_correct":true,"explanation":"Correct. The segment names the build as the problem: writing performance levels across criteria with language that truly separates them is slow work that loses to lesson planning and grading, so the assignment gets graded by feel."},{"id":"c","label":"Because students prefer to be graded by feel rather than against explicit criteria.","is_correct":false,"explanation":"Student preference is never mentioned. The obstacle described is the labor of building the rubric, not anyone's preference for vibe-based grading."},{"id":"d","label":"Because most assignments are too simple to need more than one performance level.","is_correct":false,"explanation":"Nothing in the segment suggests assignments are too simple. The difficulty is precisely that good rubrics need several parallel levels, which is what makes them tedious to write."}]}$lum$::jsonb, false),
  ($lum$58511a6c-6466-5f7f-b973-271abae17af9$lum$::uuid, $lum$876f6e22-cd9c-56b6-a504-f9b483db6f40$lum$::uuid, 2, $lum$reading$lum$, $lum${"markdown":"Take a 10th grade argumentative essay. You might ask: \"Build a four-level analytic rubric for a 10th grade argumentative essay. Criteria: thesis clarity, use of evidence, counterargument, organization, and conventions. Levels run from Beginning to Exemplary. For each cell write a short descriptor in observable language a student could self-check against.\" The draft comes back with thesis clarity moving from \"no clear claim, or the claim shifts\" at Beginning up to \"a precise, arguable claim that frames the whole essay\" at Exemplary, and counterargument moving from \"none\" up to \"fairly represents and convincingly rebuts a real opposing view.\" That is the grid you were dreading, already drafted, with the level-to-level steps spelled out so you can see whether they hold.\n\nNow a middle-school science fair project. The criteria are different, and the AI should follow your lead. You describe it: \"Build a three-level rubric for a 7th grade science fair project. Criteria: testable question, controlled procedure, data and analysis, and presentation board. Levels: Approaching, Meets, Exceeds.\" The model lays out a controlled-procedure row that runs from \"one variable changes but others are not controlled\" at Approaching, to \"the independent variable is isolated and the test is repeated\" at Meets, to \"controls are documented and the student explains why each one matters\" at Exceeds. You can read straight down a column and picture what a Meets project actually looks like on the gym floor.\n\nOr an elementary oral presentation. Younger grades need student-friendly language and fewer levels. You ask for \"a three-level rubric for a 2nd grade oral presentation on a favorite animal, criteria of speaking voice, eye contact, content, and using a visual, with descriptors a 7-year-old could understand.\" The speaking-voice row comes back as \"hard to hear\" at the bottom, \"loud enough most of the time\" in the middle, and \"clear and easy to hear the whole time\" at the top. Short, observable, and something a child could check themselves against before they present."}$lum$::jsonb, false),
  ($lum$63f1b592-12ed-5646-b99a-e7646e4a7c98$lum$::uuid, $lum$876f6e22-cd9c-56b6-a504-f9b483db6f40$lum$::uuid, 3, $lum$fill_blank$lum$, $lum${"template":"Across the three sample assignments, you did not change the {{1}} from one to the next. You changed the {{2}}, the grade, the format, and what mastery looks like, and the rubric's structure followed.","blanks":[{"id":"1","accept":["tool","AI","model"],"ideal":"tool"},{"id":"2","accept":["description","prompt","assignment description"],"ideal":"description"}],"explanation":"The essay had four levels and academic criteria, the science fair had three levels focused on procedure, and the 2nd grade presentation used child-sized language. The tool stayed the same; only the description changed, and the structure adjusted to match."}$lum$::jsonb, false),
  ($lum$4b1b3cf9-f7a9-52db-8c60-8334ee6c387b$lum$::uuid, $lum$876f6e22-cd9c-56b6-a504-f9b483db6f40$lum$::uuid, 4, $lum$reading$lum$, $lum${"markdown":"Notice what changed across the three. The argumentative essay had four levels and five academic criteria. The science fair had three levels and a focus on procedure. The 2nd grade presentation had child-sized language and a visual-aid row. You did not adjust the tool, you adjusted the description, and the structure followed. That is the point of describing the assignment in your own words: the more specific you are about grade, format, and what mastery looks like, the closer the first draft lands to something you can actually use.\n\nTwo things keep every one of these yours. First, the criteria have to reflect what you actually value, not a generic list. If creativity matters in your assignment and the model left it out, add it. If a criterion it suggested is not something you taught, cut it. The rubric should match your instruction, not the other way around. Second, read each level descriptor for fairness and clarity. The model can write a distinction that sounds fine but is impossible to grade the same way on paper one and paper thirty, or it can set a bar that does not fit your students. That review is where your expertise lives. The AI gives you a complete, consistently phrased starting point, and you calibrate it to the real classroom in front of you.\n\nThe payoff is simple. The rubric exists, finished and usable, on the day you actually need it. You hand it to students before they start, you grade against it consistently, and when a grade gets questioned you have observable language to stand behind. The hours you would have spent fighting parallel phrasing go back to teaching."}$lum$::jsonb, false),
  ($lum$46b02c91-661a-5138-b275-d1758c245944$lum$::uuid, $lum$876f6e22-cd9c-56b6-a504-f9b483db6f40$lum$::uuid, 5, $lum$multiple_choice$lum$, $lum${"stem":"What is the right division of labor when using AI to build an analytic rubric?","options":[{"id":"a","label":"You describe the assignment and what mastery looks like, the AI lays out the grid with parallel level descriptors, and you calibrate the criteria and descriptors to your classroom.","is_correct":true,"explanation":"Correct. The AI handles the structured drafting, the rows, columns, and parallel phrasing. You bring the assignment, the values, and the judgment to adjust criteria and check that each descriptor can be graded consistently."},{"id":"b","label":"You give the AI the grade levels and let it choose the criteria, the standards, and the final descriptors so the rubric stays objective.","is_correct":false,"explanation":"Handing over the criteria produces a generic rubric that may not match what you taught. The criteria and the final bar are exactly the parts you have to own."},{"id":"c","label":"You write the full rubric yourself, then ask the AI only to proofread the spelling.","is_correct":false,"explanation":"That throws away the biggest time savings. The slow part is drafting parallel level descriptors, which is precisely what the AI does well. Let it draft, then you review."},{"id":"d","label":"You accept whatever the AI produces because a structured grid is more consistent than a teacher's judgment.","is_correct":false,"explanation":"A neat grid is not the same as a fair one. Descriptors can sound clean yet be impossible to apply consistently, and the criteria may miss what you value. Your calibration is what makes it usable."}]}$lum$::jsonb, false),
  ($lum$e8ca3f0c-193f-536e-8c2a-4b61a9b79a8c$lum$::uuid, $lum$876f6e22-cd9c-56b6-a504-f9b483db6f40$lum$::uuid, 6, $lum$reading$lum$, $lum${"markdown":"The rubric draft comes back looking polished, and that polish is exactly where teachers get tripped up. A few predictable errors show up on the job, and knowing them turns a risky shortcut into a reliable one.\n\nThe first is accepting a generic criteria list that omits what you actually teach. The model defaults to the conventional criteria for an assignment type, which means it often leaves out the things that make your version yours. Ask for an argumentative essay rubric and you may get thesis, evidence, and organization, but nothing for the original argument or creative framing you spent two weeks coaching. The fix is a habit: read the criteria first, before you ever look at the descriptors, and ask whether the row list matches what you taught and weighted. Add what is missing, cut what you did not assign. The rubric follows your instruction, not the reverse. If you adjust your teaching to match the AI's list, you have let a generic template quietly rewrite your unit."}$lum$::jsonb, false),
  ($lum$3b2ed618-be5c-50fe-af30-89805b2e0cc1$lum$::uuid, $lum$876f6e22-cd9c-56b6-a504-f9b483db6f40$lum$::uuid, 7, $lum$multiple_choice$lum$, $lum${"stem":"This segment says the first predictable error is accepting a generic criteria list. What habit does it recommend to catch it?","options":[{"id":"a","label":"Read the level descriptors first and assume the criteria are fine if the descriptors sound polished.","is_correct":false,"explanation":"The segment recommends the reverse order. Polished descriptors are not evidence that the criteria are right; you check the rows before the cells precisely so polish does not lull you."},{"id":"b","label":"Adjust what you teach next time so it lines up with the criteria the model produced.","is_correct":false,"explanation":"The segment warns against exactly this: if you adjust your teaching to match the AI's list, you have let a generic template quietly rewrite your unit. The rubric follows your instruction, not the reverse."},{"id":"c","label":"Trust the model's defaults because conventional criteria for an assignment type are usually complete.","is_correct":false,"explanation":"The default conventional list is the problem, not the safeguard. It often leaves out the things that make your version yours, like an original-argument or creative-framing row."},{"id":"d","label":"Read the criteria first, before the descriptors, and confirm the rows match what you taught and weighted, adding what is missing and cutting what you did not assign.","is_correct":true,"explanation":"Correct. The recommended habit is to check the criteria rows first against your instruction, then add or cut so the rubric reflects your unit rather than a generic template."}]}$lum$::jsonb, false),
  ($lum$9f9b01c4-e013-5002-9fcd-80705b22ac28$lum$::uuid, $lum$876f6e22-cd9c-56b6-a504-f9b483db6f40$lum$::uuid, 8, $lum$reading$lum$, $lum${"markdown":"The second is trusting level descriptors that sound fine but cannot be graded consistently. This is the subtle one. A descriptor like \"shows strong analysis\" reads well and means nothing you can apply the same way twice. The real test is not whether a descriptor sounds good in isolation. It is whether you could grade the gap between Proficient and Exemplary the same way on the first paper and the thirtieth, at 4pm on a Friday. Watch for vague intensifiers, \"somewhat,\" \"strong,\" \"effective,\" that distinguish levels in tone but not in anything observable. Watch for adjacent levels that are the same sentence with a word swapped. When you spot one, rewrite it around something a student or a colleague could actually point to in the work. That is what protects you when a grade gets questioned.\n\nThe third is treating the AI rubric as an authority instead of a draft you calibrate. The grid arrives complete and confident, and it is tempting to read that confidence as correctness. But the model does not know your students, your standards, or where your bar sits this year. It might set Exemplary at a level only a handful of your students could reach, or set Proficient so low that nearly everyone clears it, flattening the distinctions you need. The rubric is a strong starting point, not a verdict. You hold it up against your real roster and your real expectations and you move the bar until it fits. The teacher who skips that step inherits someone else's standards without noticing.\n\nAcross all three mistakes the pattern is the same. The AI is fast and structured, and it is genuinely useful for that. What it cannot do is know what you value, picture your specific students, or feel where consistency breaks down across a stack of papers. Treat the draft as the first ninety percent of a tedious job and your review as the ten percent that makes it fair, and you get the speed without the cost."}$lum$::jsonb, false),
  ($lum$d150da59-9469-5f26-bbfd-8558cbf7026b$lum$::uuid, $lum$876f6e22-cd9c-56b6-a504-f9b483db6f40$lum$::uuid, 9, $lum$fill_blank$lum$, $lum${"template":"When you review an AI-drafted rubric, read the {{1}} first to confirm the rows match what you actually taught and value. Then check that each level descriptor can be graded {{2}} across every paper in the stack, rewriting any that sound fine but cannot be applied the same way twice.","blanks":[{"id":"1","accept":["criteria","criterion list","criteria list","rows"],"ideal":"criteria"},{"id":"2","accept":["consistently","the same way","reliably","consistent"],"ideal":"consistently"}],"explanation":"Two checks protect you. First, confirm the criteria match your instruction, adding what is missing and cutting what you did not assign. Second, make sure each descriptor can be graded consistently from paper one to paper thirty, not just that it reads well."}$lum$::jsonb, false),
  ($lum$d2c54bdc-e92e-522c-87e3-b779b7ea989f$lum$::uuid, $lum$876f6e22-cd9c-56b6-a504-f9b483db6f40$lum$::uuid, 10, $lum$try_it_live$lum$, $lum${"instructions":"Ask the AI to draft an analytic rubric you can refine. Describe the assignment, the criteria you genuinely care about, and how many performance levels you want. Or use the sample: a four-level analytic rubric for a 10th grade argumentative essay covering thesis, evidence, counterargument, organization, and conventions.","system_prompt":"You are an assessment specialist helping a K-12 teacher draft an analytic rubric. Given an assignment, a set of criteria, and a number of performance levels, produce a rubric with one row per criterion and one column per level, with a short descriptor in each cell. Use observable, student-facing language a learner could self-check against, and make the levels genuinely distinguishable rather than the same sentence with an intensifier added. After the rubric, remind the teacher to confirm the criteria match what they actually taught and to check that each descriptor can be graded consistently across a full stack of papers. No jargon. No em dashes.","ideal_output":"Here is a four-level analytic rubric for your 10th grade argumentative essay. Levels run Beginning, Developing, Proficient, Exemplary. I wrote each cell in language a student could check their own draft against.\n\nThesis clarity. Beginning: no clear claim, or the claim shifts during the essay. Developing: a claim is present but vague or overly broad. Proficient: a clear, arguable claim stated early. Exemplary: a precise, arguable claim that frames the whole essay.\n\nUse of evidence. Beginning: little or no support, or unrelated detail. Developing: some evidence, but thin or not explained. Proficient: relevant evidence for each point, briefly explained. Exemplary: well-chosen evidence, clearly tied to the claim and analyzed.\n\nCounterargument. Beginning: none. Developing: names an opposing view but does not respond to it. Proficient: states and answers one counterargument. Exemplary: fairly represents and convincingly rebuts a real opposing view.\n\nOrganization. Beginning: ideas jump with no clear order. Developing: a basic order, but transitions are missing. Proficient: a logical order with clear transitions. Exemplary: a deliberate structure that builds the argument.\n\nConventions. Beginning: frequent errors that block meaning. Developing: errors that distract but do not block meaning. Proficient: few errors. Exemplary: clean, controlled writing.\n\nTwo things to confirm before you use this. First, do these five criteria match what you actually taught and weighted, and is anything you care about, such as original framing, missing? Second, can you picture grading the gap between Proficient and Exemplary the same way on paper one and paper thirty? Adjust any descriptor that feels hard to apply, and tell me if you want to add or drop a criterion.","input_placeholder":"Describe the assignment, the criteria you care about, and how many levels you want..."}$lum$::jsonb, true),
  ($lum$35c9cc79-90da-5172-a89a-539d931b4556$lum$::uuid, $lum$876f6e22-cd9c-56b6-a504-f9b483db6f40$lum$::uuid, 11, $lum$multiple_choice$lum$, $lum${"stem":"The AI hands back a clean five-criterion rubric, but it left out creativity, which is central to the assignment you are grading. What does this lesson say to do?","options":[{"id":"a","label":"Keep the rubric as is, since the AI's five criteria are probably the standard ones experts use.","is_correct":false,"explanation":"A generic list is not the goal. If creativity is central to the assignment and it is missing, grading without it would be unfair to what you actually asked students to do."},{"id":"b","label":"Drop creativity from the assignment so it matches the rubric the AI produced.","is_correct":false,"explanation":"That is backwards. The rubric should follow your instruction, not reshape it. Change the rubric to fit what you teach, not your teaching to fit the rubric."},{"id":"c","label":"Add the missing criterion, because the rubric should match what you actually teach and value, not the model's generic list.","is_correct":true,"explanation":"Correct. The rubric exists to measure your instruction. If something you taught and care about is missing, you add it, and you cut anything the model suggested that does not fit. You are calibrating it to your classroom."},{"id":"d","label":"Ask the AI whether creativity belongs and defer to its answer.","is_correct":false,"explanation":"The model does not know your assignment or what you taught. The call about which criteria belong is yours, and deferring it just reintroduces the generic-template problem."}]}$lum$::jsonb, false),
  ($lum$13dc4e8b-c5ce-5ed5-bbd2-9532fdf57f37$lum$::uuid, $lum$876f6e22-cd9c-56b6-a504-f9b483db6f40$lum$::uuid, 12, $lum$mini_project$lum$, $lum${"brief":"Choose a real assignment you grade, ideally one you currently grade without a formal rubric. List the criteria you genuinely care about and decide how many performance levels you want. Ask the AI to build the analytic rubric with a short, observable descriptor in every cell, then calibrate it: confirm the criteria match what you actually taught, add or cut any that do not, and read each level descriptor asking whether you could apply it the same way on paper one and paper thirty. You should end with a finished, fair rubric you can hand to students before they start.","parts":[{"id":"1","prompt":"Pick one assignment from your current unit and write down the three to five criteria you most want to see, including anything personal to your version of it."},{"id":"2","prompt":"Prompt the AI for an analytic rubric with your criteria and level count, then check the criteria rows first and adjust them before reading the descriptors."},{"id":"3","prompt":"Rewrite any descriptor that uses vague intensifiers or sets the wrong bar for your students, so every cell points to something observable you could grade consistently."}]}$lum$::jsonb, false),
  ($lum$dffd52e9-93f4-54b0-af08-f3a12636b099$lum$::uuid, $lum$8c618ae8-3341-5322-805f-e812559ab2bf$lum$::uuid, 0, $lum$reading$lum$, $lum${"markdown":"Most support volume is repetitive. A handful of question types make up the bulk of your tickets: password resets, refund requests, shipping delays, how-to questions, and account changes. You answer each one slightly differently every time, and that retyping is slow. Worse, the variation creates an inconsistent experience, so two customers with the same problem get different quality answers depending on who happens to be on shift. A response template library fixes both problems, and AI is excellent at building the first version of one fast.\n\nThe whole trick is to ask AI for reusable structures, not single replies. There is a real difference. A one-off reply solves today's ticket and then disappears. A template is a stable skeleton you fill in again and again. So instead of \"write a response to this customer whose package is late,\" you ask: \"Draft a reusable template for a shipping-delay inquiry. Use clear placeholders for the order number, the new estimated delivery date, and the customer name. Lead with acknowledgment, keep the tone warm and efficient, and end with a clear next step.\" That gives you something you can use a hundred times.\n\nHere is what a shipping-delay template looks like once AI drafts it and you tidy it up:\n\n> Hi [customer name],\n> Thanks for reaching out, and I am sorry your order [order number] has not arrived yet. I completely understand wanting to know where it is.\n> Good news: your order is now expected to arrive by [new estimated date]. You do not need to do anything on your end, it is on its way.\n> If it has not arrived by [new estimated date], just reply here and I will make it right.\n> Thanks for your patience,\n> [agent name]\n\nNotice the shape. There is acknowledgment, then the key information, then a concrete next step. The bracketed parts are the only things that change per customer. That structure is the stable 80 percent. The specifics, the name, the order number, the new date, are the 20 percent you fill from your own order system, never by pasting a real customer's details into a public AI tool."}$lum$::jsonb, false),
  ($lum$ed1c7cc0-060d-5f9b-a6dc-20c0c9f0be33$lum$::uuid, $lum$8c618ae8-3341-5322-805f-e812559ab2bf$lum$::uuid, 1, $lum$multiple_choice$lum$, $lum${"stem":"Your manager asks you to use AI to speed up your most common replies. What is the right thing to ask the AI for?","options":[{"id":"a","label":"A reusable template for each common ticket type, with clear bracketed placeholders for the parts that change per customer, like name, order number, and date.","is_correct":true,"explanation":"Correct. The template is the stable 80 percent you reuse, and the placeholders mark the 20 percent you personalize from your own systems each time. That is what makes a reply fast and consistent."},{"id":"b","label":"A finished, ready-to-send reply for the specific customer who is in front of you right now.","is_correct":false,"explanation":"That solves one ticket and then disappears. You would be back asking the AI again for the next near-identical ticket. The goal is a reusable structure, not a single throwaway reply."},{"id":"c","label":"A long, formal policy document that explains the rules behind refunds and shipping for your reference.","is_correct":false,"explanation":"Useful background, but it is not a response template. A template is the actual customer-facing message with placeholders, built so you can send it again and again with small personalizations."}]}$lum$::jsonb, false),
  ($lum$9337bd2b-7f17-5570-be8f-51f495fe548a$lum$::uuid, $lum$8c618ae8-3341-5322-805f-e812559ab2bf$lum$::uuid, 2, $lum$reading$lum$, $lum${"markdown":"A refund-request template follows the same logic, just with different blanks:\n\n> Hi [customer name],\n> Thanks for letting me know, and I am happy to help with your refund for order [order number].\n> I have processed a refund of [refund amount] back to your [payment method]. You should see it within [refund timeframe], depending on your bank.\n> If you do not see it by then, reply here and I will track it down for you.\n> Take care,\n> [agent name]\n\nThe placeholders for amount, payment method, and timeframe are the four things you pull from your refund system each time. The reassurance at the end is baked into the template, so every customer gets it, not just the ones you remember to reassure.\n\nA password-reset template is shorter but earns its place in the library because you send it constantly:\n\n> Hi [customer name],\n> Happy to help you get back into your account. I have sent a password reset link to [email on file]. It is good for [link expiry window], so use it soon.\n> If the email is not in your inbox in a few minutes, check your spam folder. Still nothing? Reply here and I will send a fresh link.\n> Cheers,\n> [agent name]"}$lum$::jsonb, false),
  ($lum$85c9005b-0b26-5f77-8c05-eec7ef04352a$lum$::uuid, $lum$8c618ae8-3341-5322-805f-e812559ab2bf$lum$::uuid, 3, $lum$fill_blank$lum$, $lum${"template":"In the refund template, the parts you pull from your refund system each send, like the {{1}}, are written as bracketed placeholders, while the {{2}} at the end is baked into the template so every customer receives it.","blanks":[{"id":"1","accept":["refund amount","amount","payment method","refund timeframe","timeframe","order number","specifics","details"],"ideal":"refund amount"},{"id":"2","accept":["reassurance","reassuring line","closing reassurance","promise to help","follow-up offer"],"ideal":"reassurance"}],"explanation":"The variable details such as the refund amount, payment method, and timeframe are placeholders you fill from your own system. The reassurance at the close is built into the template so every customer gets it, not just the ones you remember to reassure."}$lum$::jsonb, false),
  ($lum$4dee7a9c-e9e2-5976-9b48-fbe861139907$lum$::uuid, $lum$8c618ae8-3341-5322-805f-e812559ab2bf$lum$::uuid, 4, $lum$reading$lum$, $lum${"markdown":"Build ten or fifteen of these across your common cases and your team stops starting from zero on routine work. A how-to question about resetting two-factor authentication gets the same clear walkthrough every time. An account-change request to update a billing email follows the same verify, confirm, reassure path on every ticket. The payoff shows up in two places. First, speed. You open the right template, fill four blanks from your systems, and send a polished reply in under a minute instead of staring at a blank box. Second, consistency as a real asset. A shared library means every customer with the same issue gets your best answer, written once when you were thinking clearly, instead of the version you can muster on a busy Friday afternoon when ten chats are open at once.\n\nThere is a discipline that keeps a library healthy. The template is a starting point, not a wall to hide behind. The placeholders are not decoration, they are the contract that says \"this part must be personalized before send.\" And the library only stays good if you treat each template as something you wrote on purpose, with a tone you chose and information you verified, rather than whatever the AI happened to produce. Get the base right once, personalize each send from your real systems, and you free up your real attention for the tickets that do not fit a mold. That is the point of the whole exercise: not to sound like a robot at scale, but to handle the easy 80 percent so well that you have energy left for the hard 20."}$lum$::jsonb, false),
  ($lum$2c0e1092-37db-5415-9649-08c46871f9b7$lum$::uuid, $lum$8c618ae8-3341-5322-805f-e812559ab2bf$lum$::uuid, 5, $lum$multiple_choice$lum$, $lum${"stem":"According to this segment, what are the two main payoffs of building a shared template library?","options":[{"id":"a","label":"Lower software costs and fewer tickets overall, because templates discourage customers from writing in.","is_correct":false,"explanation":"The segment never claims templates reduce ticket volume or cut software costs. The payoffs it names are speed and consistency, not deflection or budget savings."},{"id":"b","label":"Speed, since you fill a few blanks and send a polished reply in under a minute, and consistency, since every customer with the same issue gets your best answer.","is_correct":true,"explanation":"Correct. The segment names exactly these two: speed from filling a few blanks instead of starting blank, and consistency as a real asset, written once when you were thinking clearly."},{"id":"c","label":"Perfect grammar and a fully automated inbox that needs no human review before sending.","is_correct":false,"explanation":"The discipline part stresses the opposite: a template is a starting point you personalize and verify each send, not a hands-off automation. Speed and consistency are the stated payoffs."}]}$lum$::jsonb, false),
  ($lum$e6f7060e-b80a-563e-a684-32f8ef39b31b$lum$::uuid, $lum$8c618ae8-3341-5322-805f-e812559ab2bf$lum$::uuid, 6, $lum$reading$lum$, $lum${"markdown":"Templates save enormous time, but a few predictable mistakes can quietly undo the benefit. Knowing them in advance keeps your library an asset instead of a liability.\n\nThe first and most serious is pasting real customer data into a public AI tool to generate or tweak a template. It feels harmless because you are \"just making a template,\" but the moment you drop in a real name, email, order number, or address, you have sent that person's information to an outside system you do not control. Templates are generic by design. Build them with placeholders like [customer name] and [order number], and fill the real details only inside your own approved systems, where they belong.\n\nThe second mistake is hiding behind a template for a ticket that needs a human. A template is built for the common, straightforward case. When a ticket is unusual, or the customer is clearly upset, angry, or distressed, forcing them into a generic slot reads as cold and processed. A grieving customer asking to close a deceased relative's account does not want your refund template with the blanks filled in. The skill is recognizing the exception and writing to the person directly. Templates handle the routine so you have the time and attention to do exactly that."}$lum$::jsonb, false),
  ($lum$55d33c7e-ca03-56f0-8af2-12620308c162$lum$::uuid, $lum$8c618ae8-3341-5322-805f-e812559ab2bf$lum$::uuid, 7, $lum$multiple_choice$lum$, $lum${"stem":"A ticket comes in: a customer is clearly distressed and the situation is unusual and sensitive. What does this lesson advise?","options":[{"id":"a","label":"Use the closest matching template anyway, because consistency matters most when emotions are running high.","is_correct":false,"explanation":"A distressed customer pushed into a generic template tends to feel processed, not helped. Consistency serves routine tickets, but sensitive or unusual ones need a reply written to the person."},{"id":"b","label":"Set the template aside and write to the person directly, because templates are built for common cases, not unusual or emotionally charged ones.","is_correct":true,"explanation":"Correct. Recognizing the exception is the skill. Templates handle the routine bulk so you have the attention to write individually for exactly the tickets that need a human touch."},{"id":"c","label":"Conclude that templates do not work and delete the library so this never happens again.","is_correct":false,"explanation":"That overcorrects. Templates handle the bulk of routine volume well. The point is to write individually for the exceptions, not to abandon a library that serves most of your tickets."}]}$lum$::jsonb, false),
  ($lum$16c339da-f0b9-5429-be10-933d3ea15d22$lum$::uuid, $lum$8c618ae8-3341-5322-805f-e812559ab2bf$lum$::uuid, 8, $lum$reading$lum$, $lum${"markdown":"The third mistake is adding a template to the library without reviewing it first. AI drafts are a strong starting point, not a finished product. If a template has an awkward phrase, a wrong policy detail, or a tone that is a touch too breezy, that flaw does not stay small. A template sent five hundred times is a flaw repeated five hundred times. Read every new template out loud, check it against your actual policies, and fix the off notes before it joins the library. One careful review up front saves you from a mistake that compounds across hundreds of customers.\n\nThe fourth mistake is treating the AI's output as authority. The AI does not know your refund window, your shipping carriers, or your account-change rules. It will happily write \"you should see your refund within three to five business days\" even if your real timeframe is different, simply because it sounds plausible. Never let a confident-sounding sentence stand in for a fact you have not checked. You are the one who knows the policy, so you are the one who verifies every claim a template makes about money, timing, or process before it ships.\n\nPut simply: keep real customer data out of public tools, write individually when a ticket needs a person, review every template before it joins the library, and verify the facts rather than trusting the AI's tone. Do those four things and your library stays a tool you can rely on instead of a quiet source of repeated errors."}$lum$::jsonb, false),
  ($lum$6699653c-bc08-515b-bae1-a08fdec52ffb$lum$::uuid, $lum$8c618ae8-3341-5322-805f-e812559ab2bf$lum$::uuid, 9, $lum$multiple_choice$lum$, $lum${"stem":"The AI confidently writes that a refund will land in three to five business days. Based on this segment, why should you not trust that line as written?","options":[{"id":"a","label":"Because three to five days is always too slow, and customers expect refunds the same day.","is_correct":false,"explanation":"The segment makes no claim about what timeframe is fast or acceptable. The issue is not the number itself but that the AI cannot know your real refund window."},{"id":"b","label":"Because the AI writes in a tone that is too formal for refund messages and needs to be softened first.","is_correct":false,"explanation":"Tone is a separate review point. The specific problem here is factual: the AI does not know your actual policy and may state a plausible-sounding timeframe that is simply wrong."},{"id":"c","label":"Because the AI does not know your real refund window and will state a plausible-sounding figure anyway, so you must verify every claim about money, timing, or process before it ships.","is_correct":true,"explanation":"Correct. The segment warns against treating the AI's output as authority. A confident sentence is not a checked fact, so you verify claims about money, timing, and process yourself before the template ships."}]}$lum$::jsonb, false),
  ($lum$ce345937-c646-52da-b2d1-51f95026bca2$lum$::uuid, $lum$8c618ae8-3341-5322-805f-e812559ab2bf$lum$::uuid, 10, $lum$try_it_live$lum$, $lum${"instructions":"Ask the AI for a reusable template, not a one-off reply. Name the ticket type, the tone you want, and the placeholders it should include. Or use the sample: a shipping-delay inquiry, warm and efficient, with placeholders for order number, new estimated date, and customer name. Keep real customer details out of the tool and use bracketed placeholders instead.","system_prompt":"You are a customer-support operations partner who helps agents build a reusable response template library. When the user asks for a template, produce a reusable structure with clearly bracketed placeholders for anything that changes per customer, such as [customer name], [order number], and [new estimated date]. Lead with acknowledgment, give the key information clearly, and end with a concrete next step. Use the tone the user specifies and keep it concise. Do not ask for or include real customer data, since the template is generic by design and gets personalized from the agent's own systems. Remind the user that templates suit common, straightforward tickets and that unusual or emotionally charged cases should be written individually. No jargon. No em dashes.","ideal_output":"Here is a reusable shipping-delay template. The bracketed parts are placeholders you fill from your own system right before sending.\n\nHi [customer name],\n\nThanks for reaching out, and I am sorry your order [order number] has not arrived yet. I completely understand wanting to know where it is.\n\nGood news: your order is now expected to arrive by [new estimated date]. You do not need to do anything on your end, it is on its way.\n\nIf it has not arrived by [new estimated date], just reply here and I will make it right.\n\nThanks for your patience,\n[agent name]\n\nA quick note on using this. It fits a standard delay inquiry. If the customer is especially upset, or the situation is unusual, set this aside and write to them directly instead. Want me to build matching templates for a lost-package case and a partial-shipment case so the whole set stays consistent?","input_placeholder":"Name the ticket type, the tone you want, and the placeholders to include..."}$lum$::jsonb, true),
  ($lum$9eabb34d-085d-56fd-999d-1ad31f26267d$lum$::uuid, $lum$8c618ae8-3341-5322-805f-e812559ab2bf$lum$::uuid, 11, $lum$multiple_choice$lum$, $lum${"stem":"The AI just drafted you a clean refund template. What is the right next step before it goes into your shared library?","options":[{"id":"a","label":"Add it to the library right away so the team can start using it, since AI output is reliable and editing wastes time.","is_correct":false,"explanation":"An unreviewed template multiplies any flaw across every send. The AI does not know your real refund window or policy, so an unchecked draft can repeat a wrong detail hundreds of times."},{"id":"c","label":"Send it to a few real customers first to see how they react, then decide whether to keep it.","is_correct":false,"explanation":"That tests an unverified template on real people. Review and correct it before it touches any customer, not after. You check the policy and tone yourself, up front."},{"id":"b","label":"Read it against your actual refund policy and timeframes, fix any wrong details or off notes, then add it once it is correct.","is_correct":true,"explanation":"Correct. One careful review up front catches errors before they compound. You verify the facts the AI cannot know, fix the tone, and only then let the template into the library."}]}$lum$::jsonb, false),
  ($lum$e64fa2e6-0ba1-5c68-8e2b-75e9513ae748$lum$::uuid, $lum$8c618ae8-3341-5322-805f-e812559ab2bf$lum$::uuid, 12, $lum$mini_project$lum$, $lum${"brief":"Build the first real version of your response template library. Pull your last fifty or so tickets and group them by type, then look for the handful of categories that cover most of your volume. Those top categories, often password resets, refund requests, shipping delays, how-to questions, and account changes, are your template targets. For each one, use AI to draft a reusable template with clearly bracketed placeholders and the acknowledge, inform, next-step structure, then review it against your real policies before it joins the library. Keep every template generic, with no real customer data in any tool.","parts":[{"id":"1","prompt":"Pull your last ~50 tickets, sort them by type, and pick the three categories that show up most."},{"id":"2","prompt":"For each of those three, have AI draft a reusable template with bracketed placeholders for the parts that change, then read it against your actual policy and fix any wrong detail or off note."},{"id":"3","prompt":"Write yourself a one-line rule for when to set a template aside and respond individually, and save it at the top of your library."}]}$lum$::jsonb, false),
  ($lum$fd29a476-80e0-599c-94e0-57c0c7e12e1c$lum$::uuid, $lum$27a7a2e1-02c9-5c58-a404-44ed2f094f2d$lum$::uuid, 0, $lum$reading$lum$, $lum${"markdown":"Clients live in the dark, and it scares them. They do not know what discovery means, why a hearing got pushed, or whether silence from your office is good news or bad. Clear, timely communication is one of the most valued things a legal professional offers, and it is also one of the most repetitive. Status updates, document requests, appointment confirmations, explanations of next steps, delay notices. You write the same kinds of messages over and over, with only the names and the facts changing. That repetition is exactly where AI helps, if you use it the right way.\n\nHere is the core idea, and it is the whole lesson in one sentence: template the recurring message, not the individual matter. The shape of a status update is the same whether your client is a small business in a contract dispute or a parent in a custody case. The shape of a document request is the same no matter what document you need. So you build the reusable shell once, with AI, and you fill in the confidential specifics yourself, by hand, where no outside tool can see them."}$lum$::jsonb, false),
  ($lum$37a34328-27c9-5a3a-a4a6-3b6ab9789d32$lum$::uuid, $lum$27a7a2e1-02c9-5c58-a404-44ed2f094f2d$lum$::uuid, 1, $lum$multiple_choice$lum$, $lum${"stem":"What is the core idea behind using AI for routine client communication?","options":[{"id":"a","label":"Template the recurring message with bracketed placeholders, and fill in the confidential specifics and legal substance yourself.","is_correct":true,"explanation":"Correct. The shape of a status update or document request repeats across matters, so you build the reusable shell with AI and keep the confidential details and your judgment off the tool."},{"id":"b","label":"Hand each individual client matter to the AI so it can write the most accurate, customized message.","is_correct":false,"explanation":"That means pasting confidential matter details into the tool, which is the exact thing to avoid. You template the recurring message, not the individual case."},{"id":"c","label":"Let the AI both draft the wording and decide what to tell the client about their case.","is_correct":false,"explanation":"AI can shape wording, but what a client is told about their matter is legal substance and professional judgment, which stays with you."}]}$lum$::jsonb, false),
  ($lum$36071618-58bd-5a69-9327-adf2fac690c6$lum$::uuid, $lum$27a7a2e1-02c9-5c58-a404-44ed2f094f2d$lum$::uuid, 2, $lum$reading$lum$, $lum${"markdown":"Think about three messages that come up constantly. First, the status update. You ask AI, \"Create a plain-language template for a client status update letter. Reassure the client, summarize where things stand in general terms, explain the next step, and set realistic expectations for timing. Mark every fill-in part with brackets like [client name] and [matter description], and use no real names or facts.\" What you get back is a warm, professional shell you can reuse for years. Second, the document request. A client who has never been in litigation does not know what a \"responsive document\" is, and a cold checklist makes them panic. Ask for a template that explains, in plain words, what you need and why, with brackets for [client name], [document list], and [deadline]. Third, the appointment confirmation, which sounds trivial until a client misses a deposition because the email was confusing. A clean confirmation template with [date], [time], [location or video link], and [what to bring] prevents real problems.\n\nPlain language is where AI earns its keep. Your clients are not lawyers, and legal vocabulary makes anxious people more anxious. One of the most useful prompts you can run is, \"Rewrite this explanation of the discovery process for a client with no legal background, in a calm, clear tone, and keep it under 150 words.\" Imagine telling a first-time client, \"Discovery is the part of the case where both sides exchange information and documents. It can feel slow, and that is normal. It does not mean anything has gone wrong.\" That single calm paragraph saves you three worried phone calls. You can build the same kind of plain-language explainer for what an interrogatory is, why a continuance happened, or what a settlement conference will be like. Each one of these is a small template you write once and reuse with every new client who hits that same moment of confusion, so the second time a client asks \"what is a deposition,\" you are not starting from a blank page."}$lum$::jsonb, false),
  ($lum$fff011ae-5b2e-5f15-9cd5-ea9b68957206$lum$::uuid, $lum$27a7a2e1-02c9-5c58-a404-44ed2f094f2d$lum$::uuid, 3, $lum$fill_blank$lum$, $lum${"template":"When clients are not lawyers, legal vocabulary makes anxious people more anxious, so a strong prompt asks AI to rewrite an explanation in a {{1}} tone. Each plain-language explainer is a small {{2}} you write once and reuse with every new client who hits the same moment of confusion.","blanks":[{"id":"1","accept":["calm","calm, clear","clear","calm and clear"],"ideal":"calm"},{"id":"2","accept":["template","reusable template","shell"],"ideal":"template"}],"explanation":"The segment recommends a calm, clear tone so legal vocabulary does not raise anxiety, and it frames each plain-language explainer as a template you write once and reuse with every new client."}$lum$::jsonb, false),
  ($lum$a7926056-569b-56eb-b078-0bf17a2e57ed$lum$::uuid, $lum$27a7a2e1-02c9-5c58-a404-44ed2f094f2d$lum$::uuid, 4, $lum$reading$lum$, $lum${"markdown":"Tone matters as much as clarity, and here legal work has a special trap. Legal outcomes are uncertain, so your templates must be reassuring and honest at the same time, without ever over-promising. A delay notice is the classic case. You want a template that says, in effect, \"I want to keep you informed. The [hearing or filing] has been moved to [new date]. This kind of scheduling change is common and does not affect the strength of your position.\" Notice what it does not say. It does not say \"we will win\" or \"this is great news.\" Ask AI directly, \"Write a template for telling a client about an unexpected delay that is honest, calm, and does not promise any particular result.\" The same balance applies to a settlement update. You can reassure the client that an offer has arrived and that you are reviewing it carefully, without ever stating in the template that they should accept or that the number is good, because that judgment belongs to you and depends on facts the template can never hold.\n\nNow the two rules that protect you and your client, and these are not optional. First, never paste confidential client details into a public AI tool. Not the client's name, not the opposing party, not the settlement figure, not the diagnosis or the arrest or the dollar amount. Everything sensitive lives in a bracket, like [client name] and [matter description], and you fill it in offline or in a private, firm-approved tool. The moment a real detail goes into a free public chat box, it has left your control. Second, the legal substance is yours. AI shapes the wording of a message. What you actually tell a client about their matter, whether to counter an offer, how to characterize their odds, what their next move should be, is your professional judgment, made and verified by you. Build a small library of these templates once, and your routine communication gets faster and more consistent, while the care and judgment your clients truly value stay firmly in your hands."}$lum$::jsonb, false),
  ($lum$63fd8fe2-908e-5f50-95de-fad07314e9c7$lum$::uuid, $lum$27a7a2e1-02c9-5c58-a404-44ed2f094f2d$lum$::uuid, 5, $lum$multiple_choice$lum$, $lum${"stem":"According to this segment, how should a template handle the tension between reassurance and uncertain legal outcomes?","options":[{"id":"a","label":"Promise a favorable result so the client feels confident and stays calm.","is_correct":false,"explanation":"Legal outcomes are uncertain, so the segment warns against over-promising. A template must never say 'we will win' or 'this is great news.'"},{"id":"b","label":"Be reassuring and honest at the same time, reassuring the process without promising any particular result, and leave the legal substance to your own judgment.","is_correct":true,"explanation":"Correct. The segment says templates must be reassuring and honest without over-promising, and that what you tell a client about their matter is your professional judgment."},{"id":"c","label":"Avoid reassurance entirely and only state cold facts so nothing can be misread.","is_correct":false,"explanation":"The segment values a warm, reassuring tone; the point is to reassure the process, not to strip out reassurance altogether."}]}$lum$::jsonb, false),
  ($lum$b707b447-782c-592d-a1a9-e5f3cf793975$lum$::uuid, $lum$27a7a2e1-02c9-5c58-a404-44ed2f094f2d$lum$::uuid, 6, $lum$reading$lum$, $lum${"markdown":"Knowing the right approach is not the same as avoiding the wrong one, and the wrong ones in legal work can cost a license. Here are the mistakes that show up most often.\n\nThe big one is pasting a real client name, the opposing party, and a settlement figure into a public AI tool to \"make the message accurate.\" Picture typing, \"Write a status update for Maria Chen about her wrongful termination case against Acme Corp, where we received an $85,000 settlement offer.\" In one sentence you have disclosed a client's identity, the existence of her matter, who she is fighting, and a confidential negotiation number, all to an outside service. That is a confidentiality breach, full stop. It does not matter that you were trying to help her.\n\nThe second mistake is believing you can undo it by deleting the chat. You cannot. The moment you hit send, those details left your office and reached an outside server. Deleting the conversation from your screen does not pull the data back. The disclosure already happened."}$lum$::jsonb, false),
  ($lum$e6f834b2-9410-5f22-bff5-e466dca186ab$lum$::uuid, $lum$27a7a2e1-02c9-5c58-a404-44ed2f094f2d$lum$::uuid, 7, $lum$multiple_choice$lum$, $lum${"stem":"A colleague pastes a client's real name and a settlement figure into a public AI chat, then deletes the conversation. What actually happened?","options":[{"id":"a","label":"The data was already sent to an outside service when it was pasted, so deleting the chat does not undo the disclosure.","is_correct":true,"explanation":"Correct. Deletion only clears your screen. The confidential details left your control the moment they were submitted, so the breach already occurred."},{"id":"b","label":"Deleting the chat removes the data from the AI provider, so confidentiality is restored.","is_correct":false,"explanation":"Deletion does not pull the data back from the outside server. The disclosure happened on submission and cannot be reversed by clearing the chat."},{"id":"c","label":"No problem occurred, because only the name and a number were shared, not the full case file.","is_correct":false,"explanation":"A name tied to the existence of a matter is confidential on its own, and a settlement figure is sensitive negotiation data. Both leaving your control is a breach."},{"id":"d","label":"It is fine as long as the colleague did not include the opposing party's name.","is_correct":false,"explanation":"Omitting one detail does not cure the others. The client name and settlement figure are already enough to constitute a confidentiality breach."}]}$lum$::jsonb, false),
  ($lum$cb18295b-a106-59d8-b4a3-8eec8b60c14e$lum$::uuid, $lum$27a7a2e1-02c9-5c58-a404-44ed2f094f2d$lum$::uuid, 8, $lum$reading$lum$, $lum${"markdown":"The third mistake is letting the AI decide what to tell the client about their matter. AI is happy to generate advice, and it will sound confident, but it does not know your client, the judge, the jurisdiction, or the facts. Whether to counter an offer, how to describe the odds, what the next move should be, that is your call to make and verify. Use AI for the wording, never for the legal substance.\n\nThe fourth mistake is subtle and very common: including just the client's name \"because a name is harmless.\" It is not. A name tied to the existence of a legal matter is itself confidential. The fact that \"Maria Chen is our client\" can reveal that she is being sued, getting divorced, or under investigation. Put the name in a bracket, [client name], every time.\n\nThe fifth mistake lives inside the templates themselves: over-promising in the name of reassurance. A warm tone is good, but a template that tells every client \"we are confident this will resolve in your favor\" is a promise you cannot keep, and it can come back to haunt the firm. Reassure the process, not the outcome. Say the delay is normal, not that the case is won. The same caution applies to timelines. A template that says \"this will be resolved by next month\" sets a deadline you do not control, so write \"we expect the next step around [date]\" instead, and let the bracket hold a date you can actually stand behind.\n\nIf you notice a pattern in these mistakes, it is this: each one trades a long-term protection for a short-term convenience. Pasting real details feels faster, deleting the chat feels safe, letting the AI decide feels efficient, dropping in a name feels harmless, and promising a result feels kind. Every one of them is a shortcut that puts the client, and your standing, at risk. The slower, bracketed, judgment-stays-with-you habit is the one that keeps you out of trouble."}$lum$::jsonb, false),
  ($lum$8ef11240-b1b9-5e3c-93fe-da34f07ce183$lum$::uuid, $lum$27a7a2e1-02c9-5c58-a404-44ed2f094f2d$lum$::uuid, 9, $lum$multiple_choice$lum$, $lum${"stem":"Why does this segment say that including just the client's name is not actually harmless?","options":[{"id":"a","label":"Because a name takes up space the AI could use for the actual matter details.","is_correct":false,"explanation":"The concern is not space. The problem is that the name itself is confidential when tied to the existence of a legal matter."},{"id":"b","label":"Because the AI might misspell the name and produce an inaccurate message.","is_correct":false,"explanation":"Accuracy of spelling is not the issue. The segment's point is that disclosing the name is itself a confidentiality problem."},{"id":"c","label":"Because a name tied to the existence of a legal matter is itself confidential and can reveal that the person is being sued, getting divorced, or under investigation.","is_correct":true,"explanation":"Correct. The segment explains that 'Maria Chen is our client' can reveal sensitive facts, so the name belongs in a bracket every time."}]}$lum$::jsonb, false),
  ($lum$04c1d750-8a57-5a61-9231-711957f1d7cd$lum$::uuid, $lum$27a7a2e1-02c9-5c58-a404-44ed2f094f2d$lum$::uuid, 10, $lum$before_after$lum$, $lum${"question":"Same client status update, two prompts. Notice which one keeps client confidentiality intact.","before_prompt":"Write a status update for my client Maria Chen about her wrongful termination case against Acme Corp, where we just received their settlement offer of $85,000 and I need to advise her to counter.","after_prompt":"Create a reusable, plain-language template for a client status update letter. It should reassure the client, summarize where things stand in general terms, explain the next step, and set realistic expectations for timing. Mark every fill-in part with brackets like [client name], [matter description], and [next step], and use no real names, parties, or dollar figures.","changes":["Builds a reusable template instead of pasting a real client's name, opposing party, and settlement figure into a public tool, which would breach confidentiality.","Uses bracketed placeholders like [client name] and [matter description] so the confidential specifics get filled in offline or in an approved private tool, never typed into the AI.","Keeps the legal substance, whether to counter and at what number, out of the prompt entirely, since that is the professional's judgment and not a templating task."]}$lum$::jsonb, true),
  ($lum$1c0030b1-0971-5e1e-aac8-f27e3aa58e2f$lum$::uuid, $lum$27a7a2e1-02c9-5c58-a404-44ed2f094f2d$lum$::uuid, 11, $lum$multiple_choice$lum$, $lum${"stem":"You need a delay notice for a real client matter. Which prompt applies the lesson correctly?","options":[{"id":"a","label":"Paste the client's name and the reason for the delay so the AI can write the most personal, accurate notice.","is_correct":false,"explanation":"This puts confidential details into the tool. The identity and the matter facts should stay in brackets and be filled in offline."},{"id":"b","label":"Ask for a reusable delay-notice template with brackets like [client name] and [new date], honest and calm, that does not promise any particular result, then fill in the specifics yourself.","is_correct":true,"explanation":"Correct. You template the recurring message with placeholders, keep the tone reassuring without over-promising, and add the confidential details by hand."},{"id":"c","label":"Ask the AI to write a notice that reassures the client the delay means the case is going well.","is_correct":false,"explanation":"That over-promises an outcome you cannot guarantee. Reassure the process, that delays are normal, not the result of the case."}]}$lum$::jsonb, false),
  ($lum$55260a1a-b70b-5c0d-89e2-1bb3f26c5cc7$lum$::uuid, $lum$27a7a2e1-02c9-5c58-a404-44ed2f094f2d$lum$::uuid, 12, $lum$mini_project$lum$, $lum${"brief":"Build a starter client communication library so your most common messages are ready to reuse. Pick the three messages you send clients most often, for example a status update, a document request, and a delay or schedule-change notice. For each one, have AI draft a plain-language, reassuring template with every fill-in part marked in brackets and no real client details anywhere. Then make each template sound like your firm, and confirm it sets honest expectations without promising a result.","parts":[{"id":"1","prompt":"Ask AI to create each template using only generic placeholders like [client name], [matter description], and [next step], with no real names, parties, or figures."},{"id":"2","prompt":"Review and edit each draft so the tone matches how your firm speaks to clients, and remove any line that over-promises an outcome."},{"id":"3","prompt":"Save the three finished templates where you can reuse them, and fill in confidential specifics offline or in an approved private tool, never in a public one."}]}$lum$::jsonb, false),
  ($lum$07dcf5f1-7dc1-5bd3-9001-55765eedcc13$lum$::uuid, $lum$fbe02c61-a252-57ed-9306-69e4883688a6$lum$::uuid, 0, $lum$reading$lum$, $lum${"markdown":"Most AI guidance focuses on getting better output. In finance, the more urgent skill is knowing what you are never allowed to put in, and what AI is never allowed to do. A public AI tool is, by default, a third party you are sharing data with. When you type something into a general chatbot, that text leaves your control. Treat it the way you would treat reading a document aloud in a crowded elevator. Some documents you can read aloud safely. Some you absolutely cannot. The whole discipline of compliance-first AI is learning to tell the difference before you open the chat box, not after.\n\nStart with the line that ends careers: material non-public information. Picture an analyst named Priya who has the unreleased quarterly earnings sitting in a spreadsheet. The numbers are strong, the beat is real, and the press release goes out in two days. She wants AI to help her draft a clean summary, so she is tempted to paste the figures in. Stop. Those numbers are material non-public information. Feeding them into a public tool is sharing them with an outside party before the public has them, which is exactly the conduct insider-trading and Regulation FD rules exist to prevent. It does not matter that Priya has no intent to trade. The exposure is in the act of disclosure, not in her motive. The same logic applies to a controller, call him David, staring at a draft 10-Q. That filing contains the company's unreleased financial position. Pasting the draft into a chatbot to \"tighten the language\" is not a copy-edit. It is moving confidential, market-moving information outside the company before it is filed. The convenience is real. The risk is your firm's reputation and your own standing."}$lum$::jsonb, false),
  ($lum$d32678d7-a8c4-5ecc-a259-07d1d5b57fa0$lum$::uuid, $lum$fbe02c61-a252-57ed-9306-69e4883688a6$lum$::uuid, 1, $lum$multiple_choice$lum$, $lum${"stem":"An analyst has unreleased quarterly earnings figures and wants a public AI assistant to help draft a summary. What does a compliance-first approach require?","options":[{"id":"a","label":"Paste the figures in, since the AI needs the real numbers to write an accurate summary.","is_correct":false,"explanation":"Those figures are material non-public information. Putting them into a public tool discloses them to an outside party before release, which is exactly the exposure insider-trading and Regulation FD rules exist to prevent."},{"id":"b","label":"Keep the unreleased numbers out of the public tool entirely; use AI only for the general structure or wording and apply the real figures yourself after release or inside an approved system.","is_correct":true,"explanation":"Correct. Material non-public information never enters a public tool. You can still get help with structure and language using the generic shape of the task, then add the real figures in a cleared environment."},{"id":"c","label":"Paste the figures in but ask the AI to keep them confidential.","is_correct":false,"explanation":"A chatbot has no duty or ability to keep your data confidential, and the breach happens the moment the data is transmitted. Asking the tool to be discreet does not undo the disclosure."}]}$lum$::jsonb, false),
  ($lum$17ec6b9a-b7dc-556d-bd6a-3fd2cb0a33c4$lum$::uuid, $lum$fbe02c61-a252-57ed-9306-69e4883688a6$lum$::uuid, 2, $lum$reading$lum$, $lum${"markdown":"Next comes client data and personally identifiable information. An accountant named Marcus is doing tax returns and has a stack of W-2s, Social Security numbers, and account balances. He wants AI to help explain a deduction to a client, so the temptation is to paste the client's actual return. Stop again. SSNs, account numbers, names tied to financial details, and similar personal data are protected, and a public tool is not an approved home for them. The fix is almost always available: work with the shape of the problem, not the live data. Marcus can ask AI to explain how a particular deduction works in general, then apply it to the real return himself inside his secured software. The AI never needs to see a single SSN to be useful.\n\nNow the part people miss most often. There are tasks AI is not allowed to do even when no sensitive data is involved, because they require a licensed professional's judgment and authority. AI cannot sign an audit opinion. AI cannot take a tax position and stand behind it. AI cannot be the authority on a regulatory filing. These are not formatting tasks. They are professional acts that carry legal weight and require a credentialed human to own them. AI can help you think, draft, and check. It cannot be the one accountable. When an auditor relies on an opinion, when a client relies on a tax position, when a regulator receives a filing, a named professional is standing behind that work. A chatbot cannot stand anywhere. It has no license to lose and no duty to uphold, which is precisely why it can never hold the authority."}$lum$::jsonb, false),
  ($lum$e0b7be72-66a3-5fab-8dc8-ffa923ff9f5f$lum$::uuid, $lum$fbe02c61-a252-57ed-9306-69e4883688a6$lum$::uuid, 3, $lum$multiple_choice$lum$, $lum${"stem":"Marcus wants AI to help explain a deduction, but the only copy he has is the client's actual tax return with SSNs and balances. Which response fits both the client-data and licensed-judgment boundaries?","options":[{"id":"a","label":"Paste the full return so the AI has accurate context, then sign off on whatever position it suggests.","is_correct":false,"explanation":"This breaks two boundaries at once: protected personal data enters a public tool, and a credentialed professional hands the tax position to a machine that cannot own it."},{"id":"b","label":"Remove only the client's name and paste the rest, then let the AI decide whether the deduction is allowed.","is_correct":false,"explanation":"SSNs and account balances can re-identify a person on their own, so dropping the name is not anonymization, and AI still cannot take or stand behind a tax position."},{"id":"c","label":"Ask AI to explain how the deduction works in general, then apply it to the real return and own the position himself inside his secured software.","is_correct":true,"explanation":"Correct. Working on the abstract shape keeps protected data out of the tool, and the licensed professional verifies and owns the position, which AI is never allowed to do."}]}$lum$::jsonb, false),
  ($lum$e8a3a7f6-b5dd-5660-98e4-9cb276183abc$lum$::uuid, $lum$fbe02c61-a252-57ed-9306-69e4883688a6$lum$::uuid, 4, $lum$reading$lum$, $lum${"markdown":"The fourth boundary ties the others together: AI output is never the system of record. Whatever the tool gives you is a draft, a suggestion, a starting point. The official numbers live in your ledger, your tax software, your filing system, your approved enterprise platform. If a figure matters, it gets verified against the real source and recorded in the real system, every time. AI is a thinking aid sitting beside your work, never the place the truth lives. The moment you treat its output as the authoritative record, you have handed a machine a responsibility that belongs to a person and a controlled system.\n\nSo the first move with any AI task is not the prompt. It is the classification question: what kind of data is involved, what kind of judgment does the task require, and where does the answer have to live? Run that check and the boundaries become obvious. Material non-public information stays out. Client and personal data stays out. Anything requiring a licensed professional's sign-off stays with the professional. And the system of record stays the system of record.\n\nThis is not a reason to avoid AI. It is the boundary that lets you use it with confidence. Huge amounts of finance work involve none of these traps: explaining a concept, structuring a generic template, rephrasing public information, drafting a policy summary, learning a standard. The professional habit is to make the check a reflex. Before you open the chat box, you already know which bucket your data sits in, whether the task needs a license, and where the real answer must be stored. When you are unsure, you treat it as off-limits and confirm, because the cost of asking is a minute and the cost of guessing wrong can be your license. AI will cheerfully accept whatever you paste and confidently answer whatever you ask. The boundary is yours to hold."}$lum$::jsonb, false),
  ($lum$cbded793-fdaf-566b-a89a-11cfd74e3d2e$lum$::uuid, $lum$fbe02c61-a252-57ed-9306-69e4883688a6$lum$::uuid, 5, $lum$multiple_choice$lum$, $lum${"stem":"Before writing a single prompt, what is the first move a compliance-first professional makes with any AI task?","options":[{"id":"a","label":"Ask the classification question: what kind of data is involved, what kind of judgment the task requires, and where the answer has to live.","is_correct":true,"explanation":"Correct. Running that check first makes the boundaries obvious before any data is pasted, so MNPI and client data stay out, licensed judgment stays with the professional, and the system of record stays the record."},{"id":"b","label":"Write the most detailed prompt possible so the AI has full context to work from.","is_correct":false,"explanation":"Leading with the prompt skips the classification step, which is exactly where sensitive data slips into the tool. The first move is the check, not the prompt."},{"id":"c","label":"Avoid AI entirely, since finance work is too sensitive for it to be useful.","is_correct":false,"explanation":"The boundary is not a reason to avoid AI. Plenty of work involves none of the traps, and the classification reflex is what lets you use AI with confidence."},{"id":"d","label":"Paste the data first and decide afterward whether it should have gone in.","is_correct":false,"explanation":"The breach happens on input. Deciding after the paste is too late, which is why the classification question comes before the chat box is even open."}]}$lum$::jsonb, false),
  ($lum$25813141-9df8-5ea4-b30a-a1292518a3e2$lum$::uuid, $lum$fbe02c61-a252-57ed-9306-69e4883688a6$lum$::uuid, 6, $lum$reading$lum$, $lum${"markdown":"The mistakes here rarely come from bad intent. They come from a convenient moment overriding a quiet rule, so it helps to see the exact shapes the trouble takes.\n\nThe most common is the \"just this once\" paste. David, the controller, is on deadline with the draft 10-Q and the language is clunky. He tells himself a single paste to tighten a paragraph is harmless. It is not. The filing is unreleased, market-moving information, and moving it into a public tool is the breach, full stop. Deadlines do not change data classifications. The fix is to copy only the non-sensitive structure of what he needs, or to use an approved enterprise tool with the right agreements in place.\n\nThe second mistake is believing cleanup fixes a leak. People think deleting the chat, or turning on a \"do not train\" setting, makes a sensitive paste safe after the fact. It does not. The data was already transmitted to and processed by a third party the instant you hit enter. The breach happens on input, not on cleanup. The only safe move is to never put the protected data in to begin with."}$lum$::jsonb, false),
  ($lum$bcc971db-f12a-505f-a565-53cfddf8a272$lum$::uuid, $lum$fbe02c61-a252-57ed-9306-69e4883688a6$lum$::uuid, 7, $lum$fill_blank$lum$, $lum${"template":"Pasting unreleased earnings or a draft filing into a public AI tool is a breach the moment you hit enter, because the harm happens on {{1}}, not on cleanup, and AI output must never be treated as the {{2}}, which always lives in your verified, approved system.","blanks":[{"id":"1","accept":["input","the input","transmission","sending"],"ideal":"input"},{"id":"2","accept":["system of record","record","source of truth","official record"],"ideal":"system of record"}],"explanation":"The breach occurs on input, the moment protected data is transmitted to a third party, so deleting the chat afterward does not help. And AI output is never authoritative: the system of record is the verified, approved place where the real numbers live."}$lum$::jsonb, false),
  ($lum$75e76fb6-4a9c-5e00-916d-f1c0a1afd506$lum$::uuid, $lum$fbe02c61-a252-57ed-9306-69e4883688a6$lum$::uuid, 8, $lum$reading$lum$, $lum${"markdown":"The third is mistaking partial redaction for safety. Marcus removes the client's name from the tax return but leaves the SSN, the account balances, and the employer. Stripping one identifier while leaving others is not anonymization. Account numbers, SSNs, and specific financial details can re-identify a person on their own. If you cannot fully separate the data from the individual, treat the whole thing as off-limits and work on the abstract shape instead.\n\nThe fourth is letting AI quietly become the authority. An accountant asks AI whether a deduction is allowed, likes the confident answer, and puts it straight on the return without checking the actual rule. Now a machine has effectively taken a tax position, and a credentialed human is supposed to own that. AI can help you understand and draft, but the professional must verify against the real authority and stand behind the position. The same goes for audit opinions and regulatory filings: AI assists, the licensed human decides.\n\nThe fifth is treating AI output as the record. Someone asks AI to total a set of figures, likes the number, and pastes it into a report as final. AI can make arithmetic and citation errors that look completely confident. The official number has to come from, and be verified against, the real system of record, every time. AI sits beside your ledger. It never becomes your ledger.\n\nThe thread through all five is the same. The convenience feels small and the rule feels abstract, right up until it does not. Knowing the line in advance, and holding it even when you are rushed, is the entire skill."}$lum$::jsonb, false),
  ($lum$11f49d16-8e37-5a8c-846c-bcc288497bbf$lum$::uuid, $lum$fbe02c61-a252-57ed-9306-69e4883688a6$lum$::uuid, 9, $lum$multiple_choice$lum$, $lum${"stem":"An accountant removes a client's name from a tax return but leaves the SSN, account balances, and employer before pasting it into a public AI tool. Why is this still a breach?","options":[{"id":"a","label":"It is fine, because removing the name fully anonymizes the document.","is_correct":false,"explanation":"Stripping one identifier while leaving others is not anonymization. The remaining details still point straight back to the individual."},{"id":"b","label":"Account numbers, SSNs, and specific financial details can re-identify a person on their own, so partial redaction does not make the data safe to paste.","is_correct":true,"explanation":"Correct. If you cannot fully separate the data from the individual, treat the whole thing as off-limits and work on the abstract shape of the problem instead."},{"id":"c","label":"It is a breach only if the AI provider later trains on the data.","is_correct":false,"explanation":"The breach happens on input, the instant the protected data is transmitted to a third party, regardless of any later training decision."},{"id":"d","label":"It is safe as long as the accountant deletes the chat afterward.","is_correct":false,"explanation":"Cleanup does not undo a leak. The data was already sent and processed, so the only safe move is to never put the protected details in to begin with."}]}$lum$::jsonb, false),
  ($lum$e23fb108-c1a2-5a08-b164-3a17a003b79a$lum$::uuid, $lum$fbe02c61-a252-57ed-9306-69e4883688a6$lum$::uuid, 10, $lum$before_after$lum$, $lum${"question":"You want help drafting talking points about a client's situation. Which prompt respects the data boundary while still getting useful help?","before_prompt":"Help me prepare for a meeting with my client Janet Powell. Here are her account holdings and balances: [pastes full statement with name, account number, SSN, and positions].","after_prompt":"I am preparing for a client meeting and want help structuring my talking points. With no client identifiers, account numbers, or personal data, here is the general situation: a retiree with a moderate-risk portfolio that is currently overweight in a single sector and underweight in fixed income relative to their stated goals. Draft a clear, plain-language framework for discussing rebalancing trade-offs, the questions I should raise, and how to explain the reasoning. I will apply the specifics and confirm any figures myself inside our approved system, which stays the system of record.","changes":["Strips the client name, account number, SSN, and live holdings, so no identifiable or regulated data ever enters the tool.","Describes the abstract shape of the situation instead of the real account, which is all the AI needs to help structure the thinking.","Keeps the specifics and final figures inside the approved system, applied and verified by the licensed professional rather than the chatbot."]}$lum$::jsonb, true),
  ($lum$0bfb5253-1910-5ed0-ace0-183d7695363e$lum$::uuid, $lum$fbe02c61-a252-57ed-9306-69e4883688a6$lum$::uuid, 11, $lum$multiple_choice$lum$, $lum${"stem":"AI gives you a confident answer about whether a specific tax deduction is allowed for a client. What is the compliance-first way to handle it?","options":[{"id":"a","label":"Use the AI explanation to understand the concept, then verify the position against the real tax authority and take it yourself, because AI cannot hold a tax position or be the system of record.","is_correct":true,"explanation":"Correct. AI can help you understand and draft, but a licensed professional must verify against the actual rule and own the position. The official record lives in your approved system, never in the chatbot's answer."},{"id":"b","label":"Put the AI's answer straight on the return, since it sounded confident and detailed.","is_correct":false,"explanation":"Confidence is not authority. AI can be confidently wrong, and letting it set a tax position hands a credentialed professional's responsibility to a machine that has no license and no accountability."},{"id":"c","label":"Ask the AI to confirm it is completely sure, then rely on that confirmation.","is_correct":false,"explanation":"A tool reassuring you about its own answer is not verification. The position must be checked against the real authority and owned by the licensed human, not by the AI's self-assessment."}]}$lum$::jsonb, false),
  ($lum$e52c29b8-ddcd-5071-9cfa-c4332b2e5274$lum$::uuid, $lum$fbe02c61-a252-57ed-9306-69e4883688a6$lum$::uuid, 12, $lum$mini_project$lum$, $lum${"brief":"Build your own one-page off-limits map before your next AI task, so the boundary is a reflex rather than a judgment call made under deadline pressure. List the categories of information and tasks you handle, then write the single rule for each: what can go into AI, what must never, and where the real answer has to live. Take three real things you might want AI's help with this week and run each through the map, rewriting the off-limits ones so they work on the abstract shape of the problem instead of the live data or the licensed decision. Keep the map somewhere you will see it before you open a chat box.","parts":[{"id":"1","prompt":"For each category (material non-public information, client and personal data, licensed-judgment tasks like audit opinions or tax positions, and general or public work), write one plain rule: out, out, professional-only, or fine to use."},{"id":"2","prompt":"Take three real tasks from your week, sort each into a category, and for every off-limits one rewrite it to use the generic shape of the problem or name the approved tool it would require."},{"id":"3","prompt":"For any task that produces a number or position, write down where the verified system of record lives, so AI output is never mistaken for the official answer."}]}$lum$::jsonb, false),
  ($lum$6e927a83-59de-59ae-875e-3281fb5cbfb8$lum$::uuid, $lum$b35395ca-efaa-5d68-9511-2de01975092b$lum$::uuid, 0, $lum$reading$lum$, $lum${"markdown":"For legal professionals, confidentiality is not a preference, it is a professional duty. It is one of the first things you learned and one of the few rules with no soft edges. AI tools create a real risk to that duty if you are not careful, because what you type into a public tool can leave your control the instant you hit enter. The good news is that you can still use AI for real legal work every day. You just need a few habits that keep privileged material on the right side of the line. This lesson is that set of habits.\n\nStart with how these tools actually handle your text, because the risk is invisible if you do not understand it. When you type into a free, public AI service, your input does not just vanish after it answers. It may be stored on the company's servers, reviewed by its staff for quality and safety, and used to train future versions of the model. That last part matters most. Information used in training can resurface later in ways no one can fully predict or pull back. None of that is compatible with privileged and confidential client information. Pasting a client's name, their matter details, or a privileged communication into a public tool can be a breach even if nothing visibly goes wrong, because the disclosure already happened the moment the text was sent."}$lum$::jsonb, false),
  ($lum$ca720e9b-5291-5546-8299-0d7114f547ca$lum$::uuid, $lum$b35395ca-efaa-5d68-9511-2de01975092b$lum$::uuid, 1, $lum$multiple_choice$lum$, $lum${"stem":"When you type confidential text into a free, public AI service, what does the lesson say can happen to that input?","options":[{"id":"a","label":"It is automatically deleted once the tool finishes answering, so it never persists.","is_correct":false,"explanation":"The lesson states the opposite: the input does not just vanish after the tool answers. It can persist on the company's servers."},{"id":"b","label":"It may be stored on the company's servers, reviewed by staff, and used to train future versions of the model.","is_correct":true,"explanation":"Correct. The lesson lists exactly these three outcomes, and notes that training use matters most because the information can resurface later in unpredictable ways."},{"id":"c","label":"It stays encrypted and inaccessible to anyone at the company under all circumstances.","is_correct":false,"explanation":"The lesson says staff may review the input for quality and safety, so it is not inaccessible to everyone at the company."}]}$lum$::jsonb, false),
  ($lum$710a43fc-9c0f-5b54-b497-32e715540132$lum$::uuid, $lum$b35395ca-efaa-5d68-9511-2de01975092b$lum$::uuid, 2, $lum$reading$lum$, $lum${"markdown":"Picture a concrete example. A paralegal at a small firm is helping with an employment dispute. The client, a warehouse worker, says she was fired days after reporting blocked fire exits to her manager. To save time, the paralegal pastes the full story into a free chatbot, client name and employer included, and asks for a list of legal issues. The summary that comes back is genuinely useful. But the client's identity, the employer's name, and the heart of a privileged matter have now left the firm and entered an outside company's system. Nothing on screen looks wrong. The breach is real anyway. Now take a second example from litigation. An assistant pastes a draft settlement figure and the opposing party's name into a public tool to clean up the language. That figure and that pairing are exactly what the firm is obligated to keep private, and they are now sitting in a system the firm does not control. In both cases the work felt routine, and that is precisely why the risk is easy to miss."}$lum$::jsonb, false),
  ($lum$fc626696-c99c-52bc-aced-16c032c9ac6a$lum$::uuid, $lum$b35395ca-efaa-5d68-9511-2de01975092b$lum$::uuid, 3, $lum$fill_blank$lum$, $lum${"template":"In the examples, the breach happens even though nothing on {{1}} looks wrong, because the disclosure already occurred the moment the text {{2}} the firm.","blanks":[{"id":"1","accept":["screen","the screen","screen looks wrong","the screen looks wrong"],"ideal":"screen"},{"id":"2","accept":["left","left the firm","leaves","left control of"],"ideal":"left"}],"explanation":"The lesson stresses that the work felt routine and nothing on screen looked wrong, yet the confidential material had already left the firm and entered an outside system. The breach is tied to the moment of disclosure, not to any visible error."}$lum$::jsonb, false),
  ($lum$058dca46-884c-5361-9ffa-ccf6af5e54c2$lum$::uuid, $lum$b35395ca-efaa-5d68-9511-2de01975092b$lum$::uuid, 4, $lum$reading$lum$, $lum${"markdown":"So here are the rules that keep you safe. They are simple, and together they cover almost every situation you will face.\n\n**Treat public AI tools as untrusted with confidential data.** The mental model that works: a free public tool is like talking in a crowded room. You would not discuss a client's matter at full volume in a coffee shop, so do not type anything privileged or client-confidential into a public tool. If you would not say it out loud among strangers, do not paste it.\n\n**Genericize before you paste.** You can still get excellent help by removing the identifying and sensitive parts first. Replace the client name with [client], the specific company with [a manufacturing company], the dollar figures and dates with placeholders. Take a contract matter as an example. Instead of pasting \"review the indemnification clause in the supply agreement between Halloran Foods and Tri-State Logistics,\" you can ask the AI to \"explain what to check in an indemnification clause in a supply agreement between [a food company] and [a logistics provider].\" The AI drafts and summarizes just as well from the generic version, and nothing client-identifying ever leaves your firm.\n\n**Use approved, private tools for sensitive work.** Many firms now provide an enterprise AI tool backed by a contract that prohibits training on your data and adds stronger privacy protections. For anything genuinely confidential, use that approved tool, not a personal free account. If you do not know what your firm permits, ask before you paste, not after. A two-minute question to your supervisor or IT is far cheaper than a disclosure you cannot reverse.\n\n**When unsure, keep it out.** If you are not certain whether something is safe to share, that hesitation is your answer. Genericize it or keep it offline. The cost of being careful is a few extra minutes. The cost of being wrong is a breach of a client's trust and your professional duty.\n\n**Know your obligations.** Confidentiality rules apply to you directly, and emerging AI-specific guidance from bar associations and courts increasingly speaks to exactly this situation. The convenience of a tool never overrides your duty to the client. You are responsible for what you put into a tool, the same way you are responsible for what you put in an email.\n\nNone of this means avoiding AI. It means being deliberate. Generic inputs go into public tools, sensitive work goes only into approved ones, and client confidentiality stays protected at every step. Once these habits are automatic, you get the speed of AI without ever putting a client at risk."}$lum$::jsonb, false),
  ($lum$a378ec37-440b-5263-b456-55e957a998ec$lum$::uuid, $lum$b35395ca-efaa-5d68-9511-2de01975092b$lum$::uuid, 5, $lum$multiple_choice$lum$, $lum${"stem":"A paralegal wants to use a free public AI tool to help draft a memo summarizing issues in an active client matter. What is the appropriate way to proceed?","options":[{"id":"a","label":"Paste the full matter details and client name in, as long as the chat is deleted afterward.","is_correct":false,"explanation":"Deleting the chat does not undo the disclosure. The confidential information was already sent to and possibly stored by an outside service the moment it was pasted, which can breach confidentiality."},{"id":"b","label":"Paste everything but add an instruction telling the AI to keep the information confidential.","is_correct":false,"explanation":"An instruction in the prompt does not control how the company stores or reviews your input. The tool's data policy governs that, not your request, so the confidential data is still exposed."},{"id":"c","label":"Remove the client name and identifying details and work from a genericized version, or use the firm's approved private tool for the confidential content.","is_correct":true,"explanation":"Correct. Genericizing protects confidentiality while still getting AI help, and an approved private tool with proper data protections is the right place for genuinely confidential material."}]}$lum$::jsonb, false),
  ($lum$86d0ebd5-955c-542d-978e-2a907c86111c$lum$::uuid, $lum$b35395ca-efaa-5d68-9511-2de01975092b$lum$::uuid, 6, $lum$reading$lum$, $lum${"markdown":"The rules are clear, so the trouble usually comes from small habits that feel harmless in the moment. Here are the mistakes that catch careful people, and why each one still counts as a breach.\n\n**Pasting full matter details and the client name, then deleting the chat.** This is the most common one, and the deletion is what makes it feel safe. It is not. The disclosure happened the instant you sent the text. Deleting the conversation on your screen does nothing about the copy that already reached the company's servers. You cannot undo a disclosure by closing a window.\n\n**Adding an instruction that tells the AI to \"keep this confidential.\"** It feels responsible, like a disclaimer at the bottom of an email. But the AI does not enforce your prompt. How your input is stored, reviewed, and used is set by the company's data policy, not by a sentence you typed. Telling a public tool to keep a secret does not change what the tool is allowed to do with it."}$lum$::jsonb, false),
  ($lum$a63af36a-b2c5-549a-a5d6-829c81139bc1$lum$::uuid, $lum$b35395ca-efaa-5d68-9511-2de01975092b$lum$::uuid, 7, $lum$multiple_choice$lum$, $lum${"stem":"Why does deleting the chat after pasting full matter details and the client name fail to fix the problem?","options":[{"id":"a","label":"Because the firm's policy requires you to keep a record of every AI conversation you start.","is_correct":false,"explanation":"The lesson does not raise a record-keeping requirement here. The problem with deletion is about disclosure, not retention rules."},{"id":"b","label":"Because deleting the chat actually triggers the tool to train on the text faster.","is_correct":false,"explanation":"The lesson makes no such claim. Deletion is ineffective because the disclosure already happened, not because it speeds up training."},{"id":"c","label":"Because the disclosure happened the instant the text was sent, and deleting the window does nothing about the copy that already reached the company's servers.","is_correct":true,"explanation":"Correct. The lesson states you cannot undo a disclosure by closing a window, since the copy already reached the company's servers when you sent it."}]}$lum$::jsonb, false),
  ($lum$50b8122f-a8e9-50eb-9f61-d605d922d219$lum$::uuid, $lum$b35395ca-efaa-5d68-9511-2de01975092b$lum$::uuid, 8, $lum$reading$lum$, $lum${"markdown":"**Including just the client name, thinking a name alone is harmless.** A name tied to a matter is confidential. If you ask a public tool a question about \"the Delgado custody case,\" you have linked a real person to a legal proceeding, which is exactly the kind of fact you are obligated to protect. The name plus the context is the breach, even without the details.\n\n**Using a personal free account for sensitive work instead of the firm's approved tool.** Maybe the approved tool is slower to open, or you are working from home, so you reach for the free one out of habit. The firm's tool exists precisely because it has a contract that protects client data. Skipping it for convenience puts the matter into a system with none of those protections.\n\n**Assuming nothing went wrong because nothing visibly broke.** AI tools do not show an error when you overshare. You get a helpful answer, the day moves on, and the breach is silent. The absence of an alarm is not proof of safety. Judge your own actions by what you sent, not by whether anything looked wrong on screen.\n\nThe thread running through all five is the same. Confidentiality is breached at the moment of disclosure, not at the moment something visibly fails. None of these mistakes come from carelessness about the client. They come from trusting the wrong signals, a deleted window, a polite instruction, the lack of an error message, and assuming those signals mean you are safe. Build your habits around the moment of disclosure instead, and these mistakes stop happening."}$lum$::jsonb, false),
  ($lum$9c2e40a4-8df4-5247-bf94-0a61aa08f130$lum$::uuid, $lum$b35395ca-efaa-5d68-9511-2de01975092b$lum$::uuid, 9, $lum$multiple_choice$lum$, $lum${"stem":"A legal assistant types into a free public chatbot: \"Summarize the dispute in the Delgado custody case and keep everything confidential.\" Why is this a problem?","options":[{"id":"a","label":"It is fine, because the request explicitly tells the tool to keep the information confidential.","is_correct":false,"explanation":"The AI does not enforce your instruction. The company's data policy governs how your input is stored and used, so the confidential information is exposed regardless of what the prompt says."},{"id":"b","label":"It links a real client name to a legal matter inside a public tool, which is a disclosure of confidential information, and the 'keep it confidential' instruction does nothing to prevent that.","is_correct":true,"explanation":"Correct. A client name tied to a matter is confidential on its own, the disclosure happens the moment it is sent, and a prompt instruction cannot override the tool's data policy."},{"id":"c","label":"It is only a problem if the assistant forgets to delete the chat afterward.","is_correct":false,"explanation":"Deleting the chat does not undo the disclosure. The information already left the firm when it was sent, so deletion changes nothing about the breach."}]}$lum$::jsonb, false),
  ($lum$a37a3529-31e9-5890-bf50-bf12667981d5$lum$::uuid, $lum$b35395ca-efaa-5d68-9511-2de01975092b$lum$::uuid, 10, $lum$before_after$lum$, $lum${"question":"Same memo request, two prompts. Notice which one keeps you inside your duty of confidentiality.","before_prompt":"Help me draft a memo on the issues in Jennifer Walsh's employment dispute with Riverside Manufacturing, where she alleges she was fired after reporting safety violations on the night shift.","after_prompt":"Help me draft an issue memo for an employment matter. The setup, genericized: [an employee] alleges termination shortly after [reporting workplace safety concerns] to [the employer]. Organize the likely issues to analyze and the questions to investigate. Use only this generic description; I will add the confidential specifics in our approved private tool.","changes":["Strips the real client name, the employer, and the identifying facts before anything reaches a public tool, which is what keeps a privileged matter from leaving your control.","Replaces the specifics with bracketed placeholders so the AI can still produce a useful structure from the generic version.","Reserves the confidential details for an approved private tool, treating the public tool like a crowded room where privileged information is never spoken."]}$lum$::jsonb, true),
  ($lum$02935276-aad9-5e05-b0d2-5a4c587ed512$lum$::uuid, $lum$b35395ca-efaa-5d68-9511-2de01975092b$lum$::uuid, 11, $lum$multiple_choice$lum$, $lum${"stem":"After genericizing the Walsh matter for a public tool, where should the actual client name, employer, and specific facts go when you need the AI to work with them?","options":[{"id":"a","label":"Into the firm's approved private tool that has a no-training contract and stronger privacy protections.","is_correct":true,"explanation":"Correct. Genuinely confidential specifics belong only in an approved private tool whose contract prohibits training on your data, never in a public free service."},{"id":"b","label":"Back into the same public tool, since you already removed the details once and built trust with it.","is_correct":false,"explanation":"A public tool does not become safe through repeated use. Its data policy is unchanged, so putting the confidential specifics there is still a disclosure outside your control."},{"id":"c","label":"Into a personal free account so it stays separate from the genericized version.","is_correct":false,"explanation":"A personal free account has none of the contractual data protections of an approved tool. Separating the files does nothing to protect the confidential content inside the free service."}]}$lum$::jsonb, false),
  ($lum$5dba7dba-2fab-502a-81f6-171f7def8fbd$lum$::uuid, $lum$b35395ca-efaa-5d68-9511-2de01975092b$lum$::uuid, 12, $lum$mini_project$lum$, $lum${"brief":"Take one real, active matter from your current workload and produce a genericized version you could safely use with a public AI tool. The goal is a clean, reusable draft that carries the legal substance of the matter while stripping every detail that could identify the client. When you finish, you will have a template you can apply to the next matter in minutes.","parts":[{"id":"1","prompt":"Write the matter out in one or two sentences exactly as you would describe it internally, with the real client name, the company, the figures, and the key dates included."},{"id":"2","prompt":"Rewrite it replacing the client name with [client], the company with a generic descriptor like [a manufacturing company], and every figure, date, and identifying fact with a bracketed placeholder, then read it back and confirm that nothing left in it could identify the client or the matter."},{"id":"3","prompt":"Mark which parts of the work you could safely run in a public tool using the generic version, and which parts must wait for your firm's approved private tool, so you know exactly where each step belongs."}]}$lum$::jsonb, false),
  ($lum$d8b25824-68d4-5aa2-8fc9-3b2847ee4078$lum$::uuid, $lum$2a197824-dfb4-505f-bed6-24ecfa0149ef$lum$::uuid, 0, $lum$reading$lum$, $lum${"markdown":"Reading contracts is slow work, and the parts that matter are buried in dense language across forty pages. AI can give you a fast, structured first read of an agreement, as long as you treat it as a first read and not the final word. Done right, this is one of the highest-value uses of AI in any legal job, whether you are a paralegal triaging incoming agreements or an attorney prepping for a client call.\n\nThe single most important move is this: work from the real pasted text, never from the AI's memory. If you type \"summarize a standard NDA for me,\" the AI has no document in front of it, so it invents plausible terms. It will confidently describe a two-year confidentiality period, a mutual non-disclosure structure, and a carve-out for publicly available information, and none of that may match the NDA actually sitting on your desk. The output reads beautifully and describes a contract that does not exist. The danger is that an invented summary looks identical to an accurate one, so there is no warning sign on the page telling you it is wrong. That is why you always paste the actual contract or clause first, then ask for the summary you need from that text and nothing else. The text on the page is the only thing the AI should be summarizing."}$lum$::jsonb, false),
  ($lum$2f90c532-b1db-510d-ae69-2412489bd86e$lum$::uuid, $lum$2a197824-dfb4-505f-bed6-24ecfa0149ef$lum$::uuid, 1, $lum$multiple_choice$lum$, $lum${"stem":"You ask an AI to 'summarize a standard NDA for me' without pasting any document. Why is this risky?","options":[{"id":"a","label":"It will refuse to answer because no document was provided.","is_correct":false,"explanation":"It will not refuse. With no document in front of it, the AI happily generates a plausible-sounding summary, which is exactly the problem."},{"id":"b","label":"The summary will be too short to be useful.","is_correct":false,"explanation":"Length is not the issue. The output often reads beautifully and at full length, while describing a contract that does not exist."},{"id":"c","label":"With no real document in front of it, the AI invents plausible terms, and an invented summary looks identical to an accurate one with no warning sign that it is wrong.","is_correct":true,"explanation":"Correct. The danger is that the invented summary reads just like an accurate one, so you always paste the actual contract or clause first."},{"id":"d","label":"The AI will always describe a two-year confidentiality period regardless of input.","is_correct":false,"explanation":"The two-year period was just one example of an invented term. The real point is that any invented detail may not match the NDA on your desk."}]}$lum$::jsonb, false),
  ($lum$38064017-6d64-5689-a27e-6a332426f4cc$lum$::uuid, $lum$2a197824-dfb4-505f-bed6-24ecfa0149ef$lum$::uuid, 2, $lum$reading$lum$, $lum${"markdown":"Once the real text is in front of the AI, name the specific terms you care about. Do not ask for a vague overall summary. Tell it exactly what to pull. For a service agreement, you might write: \"From the agreement below, summarize the termination terms, the payment schedule, the liability cap, the indemnification obligations, and any auto-renewal clause.\" Naming the terms focuses the output on what drives risk and money, instead of giving you a polite paragraph about the parties and the recitals that you did not need. The terms worth naming are almost always the same handful: how the contract ends, who pays what and when, how much each side can be on the hook for, who covers whom if something goes wrong, and whether the thing renews on its own. When you name them up front, the AI stops summarizing the boilerplate and starts summarizing the substance.\n\nAsk for plain English a client could understand. A line like \"explain each of these in plain language a non-lawyer client could read without a dictionary\" turns dense legalese into something you can drop into a client email or a memo. This matters because translating contract language is a real part of the job, and a clear summary saves you from writing one from scratch.\n\nAsk the AI to flag and quote, not to advise. The right instruction is: \"Flag anything unusual or one-sided compared to a typical agreement of this type, and quote the exact clause for each thing you flag, but do not give legal advice.\" This keeps the AI doing what it is good at, which is surfacing places to look, while the legal judgment stays with you. Asking for the exact quote also makes your verification instant, because the AI shows you the source language right next to its flag.\n\nRequest a scannable format. A labeled bullet list or a table, with one row per term, makes the summary easy to read and easy to check against the document. \"Format as a table with columns for the term, the plain-language summary, and the exact quoted clause\" gives you something you can scan in seconds."}$lum$::jsonb, false),
  ($lum$f0f74add-f99b-570a-83a2-3997b2dc9573$lum$::uuid, $lum$2a197824-dfb4-505f-bed6-24ecfa0149ef$lum$::uuid, 3, $lum$multiple_choice$lum$, $lum${"stem":"You need a summary of the indemnification and liability terms in a service agreement. What is the right way to use AI for this?","options":[{"id":"a","label":"Ask the AI to summarize a typical service agreement's indemnification and liability terms from its general knowledge.","is_correct":false,"explanation":"The AI has no document in front of it, so it will invent plausible terms that may not match your actual agreement. The summary will read well and describe a contract that does not exist."},{"id":"b","label":"Paste the actual agreement text, name the indemnification and liability terms you want, and ask for plain language with the exact clauses quoted.","is_correct":true,"explanation":"Correct. Working from the real pasted text prevents invented terms, naming the specific terms focuses the output, and quoting the exact clauses makes verification fast."},{"id":"c","label":"Describe the agreement to the AI in your own words and ask it to summarize what you described.","is_correct":false,"explanation":"Your description is not the contract. The AI can only be accurate if it works from the real text, so paste the document rather than paraphrasing it."},{"id":"d","label":"Ask the AI for its legal opinion on whether the indemnification terms are enforceable.","is_correct":false,"explanation":"AI should flag unusual clauses and quote them, not give legal advice. The judgment on enforceability stays with a qualified attorney."}]}$lum$::jsonb, false),
  ($lum$b09ea278-925d-5ff5-965c-81b35fd79b70$lum$::uuid, $lum$2a197824-dfb4-505f-bed6-24ecfa0149ef$lum$::uuid, 4, $lum$reading$lum$, $lum${"markdown":"Here is how this plays out on real documents. Take a commercial lease. You paste the full lease text and ask for the rent and escalation terms, the termination conditions, and any auto-renewal clause, formatted as a labeled list with quoted clauses. The AI shows you a three percent annual escalation, a sixty-day termination notice requirement, and an auto-renewal that triggers unless the tenant gives ninety days written notice. Now you know exactly where to look in the document to confirm each one.\n\nTake a service agreement between a marketing vendor and a client. You name the payment schedule, the liability cap, and the indemnification clause. The AI flags that the liability cap is set at one month of fees, which is unusually low, and quotes the exact sentence. That flag, with its quote, points you straight to a term worth negotiating.\n\nTake an NDA a new hire is being asked to sign. You paste it and ask for the confidentiality period, the definition of confidential information, and any non-solicitation language. The AI flags a five-year confidentiality term and a non-solicit clause buried in the definitions section, and quotes both. You would have found these eventually, but the summary got you there in two minutes instead of twenty. In each of these three cases the AI did the same job: it read the text you gave it, pulled the terms you named, put them in plain language, and pointed you to the exact clauses with quotes you can confirm.\n\nA full prompt that ties all of this together looks like this: \"Here is the agreement: [paste text]. Using only this text, summarize the termination, payment schedule, liability cap, indemnification, and auto-renewal terms in plain language a client could understand. Format as a table with columns for the term, the summary, and the exact quoted clause. Flag anything unusual or one-sided for that type of agreement, but do not give legal advice.\" That one prompt covers the real text, the named terms, the plain English, the scannable format, and the flag-and-quote instruction at once.\n\nUsed this way, AI turns hours of dense reading into a focused review where you spend your attention on the clauses that actually need it."}$lum$::jsonb, false),
  ($lum$209c74f5-f67c-5dc8-99de-1d757415f958$lum$::uuid, $lum$2a197824-dfb4-505f-bed6-24ecfa0149ef$lum$::uuid, 5, $lum$multiple_choice$lum$, $lum${"stem":"Across the commercial lease, the service agreement, and the NDA examples, what job did the AI do the same way each time?","options":[{"id":"a","label":"It read the text you gave it, pulled the terms you named, put them in plain language, and pointed you to the exact clauses with quotes you can confirm.","is_correct":true,"explanation":"Correct. In all three cases the AI worked from the pasted text, summarized the named terms in plain language, and quoted the exact clauses so you can verify them fast."},{"id":"b","label":"It decided which contract terms were legally enforceable and advised whether to sign.","is_correct":false,"explanation":"The AI flags and quotes rather than advising. Deciding enforceability or whether to sign stays with the human, not the model."},{"id":"c","label":"It summarized each agreement from its general knowledge of that contract type.","is_correct":false,"explanation":"In every example you paste the real text first. Summarizing from general knowledge is exactly the invented-terms trap the lesson warns against."},{"id":"d","label":"It replaced your review entirely so you did not need to open the documents.","is_correct":false,"explanation":"The summary points you to where to look so you can confirm each term in the document. It speeds the review, it does not replace reading the source."}]}$lum$::jsonb, false),
  ($lum$8dc88b4d-a598-51b1-bd61-8b27170cc141$lum$::uuid, $lum$2a197824-dfb4-505f-bed6-24ecfa0149ef$lum$::uuid, 6, $lum$reading$lum$, $lum${"markdown":"The fastest way to get burned by an AI contract summary is to trust it without checking each term against the actual clause. The classic failure is a flipped negation. The AI summarizes a clause as \"the tenant may terminate with thirty days notice,\" but the lease actually says the tenant \"shall not terminate\" within the first year. A single dropped \"not\" inverts the legal meaning, and the summary reads just as smoothly either way. In a contract, \"shall\" and \"shall not\" are the difference between an obligation and a prohibition, so you check the source clause every time before you rely on the summary.\n\nA second mistake is a confidentiality breach. Pasting a privileged or confidential contract into a public AI tool can expose client information and waive privilege. Before any document goes into a tool, confirm it is approved for that use, or genericize the text by stripping party names, dollar figures, and identifying details first. Many firms have specific rules here, and a convenient summary is not worth a privilege problem.\n\nA third mistake is asking the AI to summarize a contract from memory. If you reference \"the Acme master services agreement\" without pasting it, the AI does not have it and will invent terms that sound right. Always paste the text you want summarized."}$lum$::jsonb, false),
  ($lum$248c4d18-783d-5c4c-a6b1-8757a57871ab$lum$::uuid, $lum$2a197824-dfb4-505f-bed6-24ecfa0149ef$lum$::uuid, 7, $lum$fill_blank$lum$, $lum${"template":"Before relying on an AI contract summary, check each term against the actual {{1}} in the document, paying special attention to negations like 'shall not,' which the AI can flip; and never paste a confidential or {{2}} contract into a public AI tool.","blanks":[{"id":"1","accept":["clause","text","source","wording","language"],"ideal":"clause"},{"id":"2","accept":["privileged","confidential","sensitive","protected"],"ideal":"privileged"}],"explanation":"Verification means reading the actual clause, because the AI can invert a negation without the summary looking wrong. And privileged or confidential documents must never go into a public tool, since that can expose client information and waive privilege."}$lum$::jsonb, false),
  ($lum$bdba1da5-5cc5-5665-9606-23622bd3638d$lum$::uuid, $lum$2a197824-dfb4-505f-bed6-24ecfa0149ef$lum$::uuid, 8, $lum$reading$lum$, $lum${"markdown":"A fourth mistake is accepting \"usually right\" on the details that carry the most risk: numbers, dates, and negations. An AI summary that gets a liability cap off by a zero, a notice period off by thirty days, or a renewal date off by a month is worse than no summary, because it reads with full confidence. These are exactly the items you verify character by character against the document.\n\nA fifth mistake is re-summarizing until two outputs agree and treating that agreement as proof. Two AI summaries can both make the same misread and confirm each other, especially on a tricky negation or a poorly worded clause. The authority is never another summary. The authority is the clause in the contract, so verification means reading the source text, not comparing AI outputs against each other. If you find yourself asking the AI \"are you sure?\" three times, stop and open the document instead.\n\nThe pattern across all five is the same. The summary is a fast way to find the clauses that matter, and the contract itself is the only thing you trust for what those clauses say."}$lum$::jsonb, false),
  ($lum$7d924c81-c472-5904-8e28-0bec25256259$lum$::uuid, $lum$2a197824-dfb4-505f-bed6-24ecfa0149ef$lum$::uuid, 9, $lum$multiple_choice$lum$, $lum${"stem":"You run an AI contract summary twice and both outputs report the same notice period. Why is that agreement not proof the term is correct?","options":[{"id":"a","label":"Because the AI is never useful for numbers or dates and should not be used on them at all.","is_correct":false,"explanation":"Too far. The AI can surface where these details live; the discipline is verifying numbers, dates, and negations character by character, not abandoning the tool."},{"id":"b","label":"Because two summaries always disagree, so matching ones must be a glitch.","is_correct":false,"explanation":"Matching outputs are not a glitch. The problem is that matching does not equal correct, since both can repeat the same misread."},{"id":"c","label":"Because the second run automatically copies the first, so they can never differ.","is_correct":false,"explanation":"That is not how it works mechanically. The real issue is that two independent summaries can still share the same misread and falsely confirm each other."},{"id":"d","label":"Because two summaries can make the same misread and confirm each other, so the authority is the clause in the contract, not another summary.","is_correct":true,"explanation":"Correct. Agreement between outputs proves nothing on a tricky negation or worded clause. Verification means reading the source text, not comparing AI outputs."}]}$lum$::jsonb, false),
  ($lum$e4587b36-107c-5143-8f7d-c7603e0394bf$lum$::uuid, $lum$2a197824-dfb4-505f-bed6-24ecfa0149ef$lum$::uuid, 10, $lum$before_after$lum$, $lum${"question":"Same commercial lease, two prompts. Notice which one protects you from invented terms and makes verification fast.","before_prompt":"Summarize a standard commercial lease for me.","after_prompt":"Here is the lease agreement text: [paste the actual lease]. Using only this text, summarize the rent and escalation terms, the termination conditions, the liability provisions, and any auto-renewal clause, in plain language a client could understand. Format it as a table with columns for the term, the plain-language summary, and the exact quoted clause. Flag anything unusual or one-sided compared to a typical commercial lease, but do not give legal advice.","changes":["Works from the real pasted lease text instead of asking the AI to recall a generic lease, which is how invented terms creep in.","Names the specific terms to summarize and asks for plain language and a scannable table, so the output is focused and easy to check.","Asks the AI to flag and quote the exact clause rather than advise, keeping legal judgment with the human and making verification against the source instant."]}$lum$::jsonb, true),
  ($lum$aa4508b9-a0ab-5029-9192-bf078c0c7840$lum$::uuid, $lum$2a197824-dfb4-505f-bed6-24ecfa0149ef$lum$::uuid, 11, $lum$multiple_choice$lum$, $lum${"stem":"An AI summary of a lease reads: 'The tenant may terminate with 30 days notice.' The actual clause says the tenant 'shall not terminate' within the first year. What does this teach you about using AI summaries?","options":[{"id":"a","label":"The AI is usually right, so you can trust the summary and skip re-reading the clause.","is_correct":false,"explanation":"In contracts, 'usually right' is not safe enough. A flipped negation changes the legal effect entirely, and only checking the source catches it."},{"id":"b","label":"You should ask the AI to re-summarize until two summaries agree, then trust them.","is_correct":false,"explanation":"Two summaries can agree and both be wrong. The authority is the contract clause itself, so verification means reading the source, not comparing AI outputs."},{"id":"c","label":"The model can misread a negation like 'shall not' as 'shall,' flipping the meaning, so every summarized term must be checked against the exact clause before you rely on it.","is_correct":true,"explanation":"Correct. A single dropped 'not' inverts a contract term, and the summary still reads smoothly. The summary is a fast way to find the right clauses, never a substitute for reading them."},{"id":"d","label":"It means AI should never be used for contracts at all.","is_correct":false,"explanation":"Too far. AI is genuinely useful for a fast first read. The discipline is verifying each summarized term against the actual text, not abandoning the tool."}]}$lum$::jsonb, false),
  ($lum$666ff1b0-bbb0-5bd9-9bbc-cc16742b737f$lum$::uuid, $lum$2a197824-dfb4-505f-bed6-24ecfa0149ef$lum$::uuid, 12, $lum$mini_project$lum$, $lum${"brief":"Take a real contract or clause from your work, and if it is confidential, genericize it first by stripping party names, dollar figures, and identifying details. Run the focused summary prompt: paste the real text, name the specific terms you care about, ask for plain language with a labeled list or table, and ask the AI to quote the exact clause for anything it flags. Then verify each summarized term against the source line by line, watching negations, dates, and dollar figures most closely, and note how long verification took compared to reading the whole document cold.","parts":[{"id":"1","prompt":"Paste the real (or genericized) contract text and run a prompt naming the specific terms you need, asking for the exact clause quoted next to each one."},{"id":"2","prompt":"Check every summarized term against the source clause line by line, flagging any \"shall\" versus \"shall not,\" wrong date, or wrong figure you find."},{"id":"3","prompt":"Write one or two plain-language sentences per key term that you could send to a client, and note where the summary and the actual clause diverged."}]}$lum$::jsonb, false),
  ($lum$70761a83-a061-5e96-993d-75fc38bf7049$lum$::uuid, $lum$ff2265be-c4fc-56f9-8a78-6583fbcea957$lum$::uuid, 0, $lum$reading$lum$, $lum${"markdown":"De-escalation feels like a personality trait, something some agents just have and the rest of us do not. It is actually a set of specific language moves you can learn, and the moves are surprisingly consistent across almost every angry conversation you will ever handle. There are four of them. You acknowledge the emotion before you address the problem. You avoid the phrases that predictably make people angrier. You take ownership instead of deflecting. And you give the customer back a sense of control by offering a path forward with a choice. Because these patterns are concrete and repeatable, AI is a genuinely useful tool for drafting them and rehearsing them until they feel natural.\n\nStart with the trigger phrases, because cutting them does half the work. \"Calm down\" tells someone their feelings are the problem. \"As I already said\" tells them they are too slow to keep up. \"That is our policy\" tells them you have stopped thinking about their situation. \"There is nothing I can do\" tells them you have given up. Every one of these is technically true in some moment and almost never helps. The skill is having something better ready, so you do not reach for the dismissive phrase out of habit when the pressure is on."}$lum$::jsonb, false),
  ($lum$f11b076d-f238-5a78-ab4d-db93e52d53b6$lum$::uuid, $lum$ff2265be-c4fc-56f9-8a78-6583fbcea957$lum$::uuid, 1, $lum$multiple_choice$lum$, $lum${"stem":"According to the lesson, how many core de-escalation language moves are there, and what role do trigger phrases play?","options":[{"id":"a","label":"There is one master move, sounding sympathetic, and trigger phrases are harmless as long as you say them gently.","is_correct":false,"explanation":"The lesson names four distinct moves, not one. And trigger phrases like 'calm down' are not harmless; they almost never help no matter how gently delivered."},{"id":"b","label":"There are four moves, and trigger phrases are fine to use because they are technically true.","is_correct":false,"explanation":"There are indeed four moves, but the point about trigger phrases is the opposite: even though each is technically true in some moment, it almost never helps, so the skill is having something better ready."},{"id":"c","label":"There are four moves, acknowledge the emotion, avoid trigger phrases, take ownership, and offer a path with a choice, and cutting trigger phrases does about half the work.","is_correct":true,"explanation":"Correct. The four moves are acknowledge first, avoid the predictably escalating phrases, take ownership, and give back control with a choice, and the lesson says cutting the trigger phrases does half the work."}]}$lum$::jsonb, false),
  ($lum$09904161-cde7-5de5-be5f-0dc2b024cf8e$lum$::uuid, $lum$ff2265be-c4fc-56f9-8a78-6583fbcea957$lum$::uuid, 2, $lum$reading$lum$, $lum${"markdown":"Here is the work in concrete terms. Imagine a customer whose package was marked delivered but never arrived, and your blunt instinct is: \"There is nothing I can do, that is our policy, you will have to file a claim with the carrier.\" Run that through AI with a clear instruction: \"Rewrite this reply to a frustrated customer using de-escalation principles. Acknowledge their frustration first, drop any dismissive phrasing, take ownership of helping, and offer a clear next step with a choice. Keep it honest and do not promise anything we cannot deliver.\" What comes back sounds more like: \"I am sorry, that is genuinely frustrating, you paid for something and it is not in your hands. Let me get this sorted with you. I can open a carrier investigation right now, or if you would rather not wait on that, I can reship today and chase the original separately. Which would you prefer?\" Same facts, same policy limits, completely different temperature. Nothing was promised that cannot be done. The feeling got named, ownership got taken, and the customer got a choice.\n\nA second example. A subscriber is furious that they were charged after they thought they had canceled, and your draft is: \"Our records show the cancellation went through after the billing date, so the charge is valid.\" That is accurate and it will escalate. The de-escalation version keeps every fact and changes the framing: \"I can see why this feels wrong, you went in to cancel and still got charged, that is a bad surprise. Looking at the timing, the cancellation landed just after the billing ran, so the system charged for the cycle that had already started. I would rather not leave you paying for a service you are done with, so I can refund this charge as a one-time exception, or credit it toward something useful to you. Tell me which is better.\" You did not hide the timeline. You acknowledged the feeling, owned the outcome, and offered a real choice."}$lum$::jsonb, false),
  ($lum$1139f840-dce8-5a52-8b0f-8039d0a74b05$lum$::uuid, $lum$ff2265be-c4fc-56f9-8a78-6583fbcea957$lum$::uuid, 3, $lum$multiple_choice$lum$, $lum${"stem":"In both worked examples (the missing package and the post-cancellation charge), what stays the same between the blunt draft and the de-escalation rewrite?","options":[{"id":"a","label":"The facts and the policy limits stay the same; only the framing changes, with the feeling named, ownership taken, and a real choice offered.","is_correct":true,"explanation":"Correct. Both rewrites keep every fact and the same policy limits, promise nothing extra, and simply change the temperature by acknowledging the feeling, taking ownership, and offering a choice."},{"id":"b","label":"The rewrite wins by promising the customer something extra the blunt version withheld.","is_correct":false,"explanation":"The lesson is explicit that nothing was promised that cannot be done. The rewrite offers a choice among honest options, not a new promise the blunt version was hiding."},{"id":"c","label":"The rewrite drops the inconvenient facts, like the cancellation timing, to avoid upsetting the customer.","is_correct":false,"explanation":"The opposite is true: 'You did not hide the timeline.' The de-escalation version keeps every fact and only changes how it is framed."}]}$lum$::jsonb, false),
  ($lum$b32677f5-c545-5359-8c46-ac7ae135b38c$lum$::uuid, $lum$ff2265be-c4fc-56f9-8a78-6583fbcea957$lum$::uuid, 4, $lum$reading$lum$, $lum${"markdown":"Notice what AI is doing in both cases. It is not finding magic words. It is reliably applying the four moves to your own raw reply, faster and more consistently than you can under pressure, and that repetition is how you learn the pattern. Seeing your blunt instinct transformed a few dozen times teaches your ear what dismissive sounds like and what warm sounds like, so eventually you produce the better version yourself without a tool.\n\nThe most valuable use, though, is rehearsal, not the live moment. AI is a strong sparring partner. You can tell it: \"Role-play an upset customer who has been on hold twice and is now demanding a manager because their refund was denied. Push back on me. I will respond and you tell me, after each turn, whether anything I said would land as dismissive.\" That is low-stakes practice on the exact scenario that rattles you, and it is hard to get any other way. A live human in a heated exchange will not stop to coach you. The model will, every turn, as many times as you need before your next real shift.\n\nTwo cautions hold this together. First, de-escalation language has to stay genuine. The goal is to communicate real respect and a real willingness to help, not to deploy smooth scripts that customers can feel being used on them. A phrase chosen to manage someone rather than help them tends to backfire harder than the blunt version would have. Second, in a live, heated exchange you are reading the person in real time, their tone, their pauses, what they actually want underneath the anger. That read is your judgment, not the model's. Use AI to build the skill and prepare the language, then bring your own read to the actual moment. The words AI helps you learn only work when you mean them."}$lum$::jsonb, false),
  ($lum$9b81e0db-aa64-5bb3-987f-3f3c3765e639$lum$::uuid, $lum$ff2265be-c4fc-56f9-8a78-6583fbcea957$lum$::uuid, 5, $lum$multiple_choice$lum$, $lum${"stem":"What is the right way to think about the de-escalation language AI helps you craft?","options":[{"id":"a","label":"As a set of clever scripts to deploy on customers to manage them into backing down.","is_correct":false,"explanation":"Manipulative scripts backfire because people sense them. The point is real respect and a real willingness to help, not phrases used to manage someone rather than serve them."},{"id":"b","label":"As genuine language you learn and mean, drafted and rehearsed with AI but delivered through your own real-time read of the customer.","is_correct":true,"explanation":"Correct. De-escalation works when it is sincere. AI helps you learn, draft, and rehearse the moves, but it has to stay genuine, and your read of the person in the live moment is what makes it land."},{"id":"c","label":"As a replacement for your own judgment, since the AI knows the right thing to say in every heated situation.","is_correct":false,"explanation":"In a live exchange you are reading the person in real time, which is your judgment, not the model's. AI builds the skill and prepares the language; you bring the read to the actual moment."}]}$lum$::jsonb, false),
  ($lum$ffd9c45d-d120-5d9e-990b-ab3796ff9581$lum$::uuid, $lum$ff2265be-c4fc-56f9-8a78-6583fbcea957$lum$::uuid, 6, $lum$reading$lum$, $lum${"markdown":"The mistakes here are subtle because the language can look perfect and still fail. The first one is treating AI-crafted phrases as scripts to recite. You get a beautifully de-escalating reply, you memorize it, and you deliver it word for word to the next angry customer regardless of what they actually said. People feel that. A line that does not fit their specific problem reads as a canned response, and a canned response to real anger is its own insult. The customer who said \"I have called three times about this exact thing\" does not want a smooth template that ignores the three calls. The fix is to use the AI rewrite to learn the moves, then produce your own version that fits the person in front of you. The phrasing has to be yours and it has to be true to their situation, or the warmth is fake and they know it.\n\nThe second mistake is treating AI as the authority on what to say in a live, heated exchange. It is tempting, when a chat is going sideways in real time, to paste the customer's last message into a tool and let it tell you how to respond. The problem is that the model cannot hear the customer's tone, cannot see that they have actually started to soften, cannot tell that this particular person wants to be heard more than they want a refund. You can. The model is excellent before the conversation, building the skill and rehearsing the hard scenarios, and it is fine after, reviewing a draft for dismissive phrasing. In the live moment, your read of the human is the thing that decides which move to make, and outsourcing that to a tool that is blind to the room makes you worse, not better. Prepare with AI, then trust your own judgment when it counts."}$lum$::jsonb, false),
  ($lum$0ede6f39-780e-5acc-a250-62b1afeb1680$lum$::uuid, $lum$ff2265be-c4fc-56f9-8a78-6583fbcea957$lum$::uuid, 7, $lum$multiple_choice$lum$, $lum${"stem":"Why is treating AI as the authority on what to say during a live, heated exchange a mistake?","options":[{"id":"a","label":"Because AI tools are always too slow to respond before the customer hangs up.","is_correct":false,"explanation":"Speed is not the reason the lesson gives. The problem is what the model cannot perceive in the live moment, not how fast it types."},{"id":"b","label":"Because reciting AI replies in the moment violates your employer's privacy policy in every case.","is_correct":false,"explanation":"Privacy is a separate, real concern addressed elsewhere, but it is not the reason live authority fails. The issue here is the model's blindness to the actual conversation."},{"id":"c","label":"AI is best used before and after the conversation; recite it live and you reach for a dismissive phrase from habit.","is_correct":false,"explanation":"AI is indeed best before and after, but the lesson does not say leaning on it live makes you reach for dismissive habits. It says the model is blind to the room, so it cannot pick the right move."},{"id":"d","label":"The model cannot hear tone, see the person softening, or tell what they want underneath, so your real-time read, not the blind tool, must decide the move.","is_correct":true,"explanation":"Correct. In the live moment the model is blind to the room: it cannot hear tone or notice softening. Your read of the human decides which move to make, and outsourcing that makes you worse, not better."}]}$lum$::jsonb, false),
  ($lum$0444526d-e6e3-57a8-9163-67a99aca102b$lum$::uuid, $lum$ff2265be-c4fc-56f9-8a78-6583fbcea957$lum$::uuid, 8, $lum$reading$lum$, $lum${"markdown":"The third mistake is a privacy one, and it is easy to make when you are stressed and just want help fast. Do not paste a customer's identifying details or the full conversation thread into a public AI tool. The angry message often contains a name, an order number, an email address, an account ID, sometimes a phone number or partial card details. A public tool is not a safe place for that, and your employer almost certainly has rules against it. When you want AI to help you de-escalate, strip the specifics first. Describe the situation in general terms: \"a customer charged after a late cancellation,\" not the actual record. You lose nothing for learning the language, and you protect the person whose trust you are trying to win back. The whole point of de-escalation is respect, and leaking their data is the opposite of that.\n\nOne smaller misconception worth naming: people assume de-escalation means giving in. It does not. You can hold a firm \"no\" and still de-escalate, because the moves are about how you carry the message, not whether you cave. \"I cannot refund this, and here is what I can do instead\" is de-escalation. Acknowledging the feeling and offering a real alternative does not require abandoning the policy, it requires delivering the limit with respect and a path."}$lum$::jsonb, false),
  ($lum$ba4ce565-8666-5033-ad30-51d0bdef128d$lum$::uuid, $lum$ff2265be-c4fc-56f9-8a78-6583fbcea957$lum$::uuid, 9, $lum$fill_blank$lum$, $lum${"template":"Two common ways AI use backfires on a live escalation: reciting a polished AI reply as a {{1}} the customer can feel is canned, and pasting the customer's name, order number, or full thread into a public tool, which is a {{2}} risk your employer likely forbids.","blanks":[{"id":"1","accept":["script","scripts","manipulative script","canned script","template"],"ideal":"script"},{"id":"2","accept":["privacy","data privacy","data","confidentiality","security"],"ideal":"privacy"}],"explanation":"A recited script reads as canned and insults a person with a real problem, so produce your own version that fits them. And public AI tools are not a safe place for a customer's identifying details, so strip the specifics and describe the situation in general terms."}$lum$::jsonb, false),
  ($lum$69bd8876-a554-5180-916f-8f991e50c517$lum$::uuid, $lum$ff2265be-c4fc-56f9-8a78-6583fbcea957$lum$::uuid, 10, $lum$before_after$lum$, $lum${"question":"A customer is escalating fast and you have a blunt reply ready. Which prompt turns it into language that lowers the temperature and teaches you the pattern?","before_prompt":"Make this reply to an angry customer sound nicer: 'There is nothing I can do, that is our policy.'","after_prompt":"Rewrite this reply to a frustrated customer using de-escalation principles. Original: 'There is nothing I can do, that is our policy.' Acknowledge their frustration genuinely first, drop any defensive or dismissive phrasing, take ownership of helping, and offer a clear path forward with a choice where one exists. Keep it honest, do not promise anything we cannot actually do, and keep it warm rather than scripted. Then briefly point out which words in my original would have escalated things, so I learn the pattern. I have described the situation generally and left out the customer's name, order number, and account details.","changes":["Names the de-escalation moves explicitly: acknowledge first, drop dismissive phrasing, take ownership, and offer a path with a choice.","Keeps the rewrite honest and warm rather than a manipulative script, and bars promising anything you cannot deliver.","Asks for a note on which original words escalated, turning the rewrite into a lesson, and confirms no identifying customer details were pasted in."]}$lum$::jsonb, true),
  ($lum$28313e23-9772-5513-b028-b3ed8eb52da1$lum$::uuid, $lum$ff2265be-c4fc-56f9-8a78-6583fbcea957$lum$::uuid, 11, $lum$multiple_choice$lum$, $lum${"stem":"You are about to use AI to help with a heated refund dispute. Which approach actually applies the lesson?","options":[{"id":"a","label":"Paste the customer's full message, including their name and order number, into a public tool and send back whatever reply it produces, word for word.","is_correct":false,"explanation":"Two mistakes at once: pasting identifying details into a public tool is a privacy risk your employer likely forbids, and reciting the reply verbatim reads as a canned script that ignores this customer's specifics."},{"id":"b","label":"During the live chat, send each of the customer's messages to AI and let it decide your every response, since it knows the right words.","is_correct":false,"explanation":"In a live exchange the model cannot hear tone or see that the person is softening. Your real-time read decides which move to make; outsourcing that to a blind tool makes you worse, not better."},{"id":"c","label":"Describe the situation in general terms, ask AI to rewrite your blunt draft using the four moves and flag which words escalated, then deliver your own version shaped to this customer.","is_correct":true,"explanation":"Correct. You protect the customer's data, learn the pattern from the rewrite, and keep the read and the final wording yours so it fits the actual person and stays genuine."}]}$lum$::jsonb, false),
  ($lum$3d1a3cd6-1a0a-5556-b6c7-5a5d33ecad57$lum$::uuid, $lum$ff2265be-c4fc-56f9-8a78-6583fbcea957$lum$::uuid, 12, $lum$mini_project$lum$, $lum${"brief":"Build your own de-escalation reference from real conversations. Collect three or four replies you actually sent to frustrated customers, or three phrases you catch yourself reaching for under pressure, like \"that is our policy\" or \"as I already said.\" For each one, describe the situation to AI in general terms with no names or order numbers, ask it to rewrite the reply using the four moves, acknowledge first, drop dismissive phrasing, take ownership, and offer a path with a choice, and have it flag which of your original words would escalate. Then run a rehearsal: have AI role-play an upset customer in a scenario you genuinely face on your shifts, push you turn by turn, and tell you after each response whether anything you said landed as dismissive. Keep every rewrite honest and genuine, never manipulative, and bring your own version to the next real conversation.","parts":[{"id":"1","prompt":"Gather three or four of your own real replies or trigger phrases, with all customer identifying details removed before anything goes into a tool."},{"id":"2","prompt":"Run each through AI for a de-escalation rewrite that names which words escalated, then write your own version that fits the specific customer."},{"id":"3","prompt":"Do a live role-play rehearsal of a scenario you actually face, getting per-turn feedback on whether your wording would land as dismissive."}]}$lum$::jsonb, false),
  ($lum$f956c94d-4db9-5bc1-b961-bca8ec532622$lum$::uuid, $lum$c7ea1f73-35d8-5fcc-95b4-c83a9226c750$lum$::uuid, 0, $lum$reading$lum$, $lum${"markdown":"Differentiation is one of those words that sounds reasonable in a staff meeting and feels impossible at 9pm. The principle is sound. A single reading or task rarely fits every student in the room. But building a striving-reader version, a grade-level version, and an extension for the kids who race ahead has always meant doing the work two or three times over. So most of us pick one version and hope the rest of the class catches up or coasts.\n\nAI changes the math, because differentiation is mostly transformation, and transformation is exactly what these models are good at. You write or choose one strong base text. Then you ask the model to produce the variations. You are not asking it to invent content. You are asking it to recast content you already trust into shapes that fit different readers. That is a much smaller and much safer job, and it is one a model can do well.\n\nEverything starts from quality. The base text has to be accurate and well written, because every version inherits whatever you feed it. A vague or sloppy base text produces vague and sloppy levels. A precise one produces precise levels. So the first move is always the same. Get one strong text right, then transform it. Once you have that, you name your learners concretely. \"Rewrite this passage at a 3rd grade reading level for students still building vocabulary, and keep every key fact\" gives you a real support. \"Create three comprehension questions that climb in difficulty, and make the last one open-ended\" gives you a ladder instead of a worksheet. \"Write a two-sentence challenge prompt for students who finish early that deepens thinking rather than just adding more reading\" gives you the extension you never had time to build."}$lum$::jsonb, false),
  ($lum$796dd9bd-7114-5997-ac70-c2bb640a5bd7$lum$::uuid, $lum$c7ea1f73-35d8-5fcc-95b4-c83a9226c750$lum$::uuid, 1, $lum$multiple_choice$lum$, $lum${"stem":"What is the core move that makes AI-assisted differentiation work?","options":[{"id":"a","label":"Generate several independent passages from scratch, one for each reading level, and pick the best.","is_correct":false,"explanation":"Building each level independently brings back the multiplied work and risks inconsistent facts across versions. The point is to transform one trusted text, not write several new ones."},{"id":"b","label":"Start from one strong, accurate base text, then ask for leveled transformations, since every version inherits what you feed it.","is_correct":true,"explanation":"Correct. Quality flows from the base text into every level. Get one text right, then ask the model to recast it. That keeps facts consistent and turns differentiation into editing rather than rebuilding."},{"id":"c","label":"Ask the AI to guess the reading levels in your class so you do not have to describe your learners.","is_correct":false,"explanation":"The model cannot see your students. You name the learners concretely so the transformations fit them. Letting the AI guess produces generic levels that may fit no one in the room."},{"id":"d","label":"Always make the simplified version as short as possible, because shorter automatically means easier.","is_correct":false,"explanation":"Length is not the goal. A short passage can still be too hard, and trimming can drop key facts. You lower the reading load while keeping every key concept intact."}]}$lum$::jsonb, false),
  ($lum$9788af8e-87d8-5d03-963d-9f713cc28955$lum$::uuid, $lum$c7ea1f73-35d8-5fcc-95b4-c83a9226c750$lum$::uuid, 2, $lum$reading$lum$, $lum${"markdown":"Here is what that looks like in a real room. Take a 5th grade science class working through a paragraph on the water cycle. You have a few striving readers who lose the thread when sentences run long, and two students who finish everything in four minutes and start drawing on their desks. You feed the AI your one solid paragraph. You ask for a simplified version at roughly a 3rd grade level that keeps all four stages, evaporation, condensation, precipitation, and collection, named and in order. You ask for the grade-level version lightly cleaned up. Then you ask for an extension: \"A puddle disappears on a sunny day but there was no rain. Which stage explains where the water went, and what would have to happen for it to come back as rain?\" Now your striving readers get the same science in sentences they can hold, and your early finishers get a question that makes them reason instead of just read more.\n\nTake a different case. A middle-school social studies class is reading a textbook passage on the causes of a historical conflict, and you have a newcomer English-language learner who reads fluently in her first language but is still building academic English. You do not want to dumb the content down, because she is perfectly capable of the thinking. You want the language load lowered while the ideas stay intact. So you ask the AI to rewrite the passage with shorter sentences, plainer connective words, and a short glossary of the five hardest academic terms with one-line definitions, while keeping every cause and every name. She gets access to the same argument her classmates are wrestling with, just through a door she can actually walk through. The history does not change. The sentence length and the vocabulary scaffolding do."}$lum$::jsonb, false),
  ($lum$1753cadd-3be0-5c01-9112-ac9b1de0150f$lum$::uuid, $lum$c7ea1f73-35d8-5fcc-95b4-c83a9226c750$lum$::uuid, 3, $lum$multiple_choice$lum$, $lum${"stem":"For the newcomer English-language learner who reads fluently in her first language, what does the lesson say you should adjust?","options":[{"id":"a","label":"Cut the number of causes and names so there is less content for her to process.","is_correct":false,"explanation":"Dropping causes and names changes the content and underestimates her. The lesson keeps every cause and every name intact; she is capable of the thinking."},{"id":"b","label":"Replace the passage with a simpler topic she already knows well.","is_correct":false,"explanation":"Swapping the topic denies her the same argument her classmates are wrestling with. The goal is access to the real content, not a substitute."},{"id":"c","label":"Lower the language load with shorter sentences, plainer connective words, and a short glossary, while keeping every cause and name.","is_correct":true,"explanation":"Correct. You lower the sentence length and add vocabulary scaffolding so the ideas stay intact. The history does not change; the language load does."},{"id":"d","label":"Translate the whole passage into her first language so she never has to read English.","is_correct":false,"explanation":"She is building academic English, and the aim is a door she can walk through into the same content, not avoiding English entirely."}]}$lum$::jsonb, false),
  ($lum$745ec454-5e38-5e04-943d-a834749a9777$lum$::uuid, $lum$c7ea1f73-35d8-5fcc-95b4-c83a9226c750$lum$::uuid, 4, $lum$reading$lum$, $lum${"markdown":"Take a third. A 4th grade class is reading a short excerpt from a primary source, a letter or a speech in older, formal English, and you have a struggling reader who shuts down the moment the language feels old. You ask the AI for a simplified retelling that keeps the speaker's main point and one memorable line of the original quoted directly, so the student still touches the real voice but is not drowning in the syntax. You pair it with the original side by side. The struggling reader gets a way in, and the authentic source stays in the room rather than getting cut for being too hard.\n\nIn all three cases the pattern is identical. One base text in, several right-sized versions out, and the key facts preserved across every one. The model handles the recasting. You handle the judgment about whether each version actually serves the child you had in mind.\n\nThe result is not a robot teaching your class. It is you, finally able to hand three students three right-sized versions of the same lesson, because making them took fifteen minutes instead of three hours. Differentiation stops being the thing you skip when you are tired and becomes the thing you edit when you have the materials in front of you. That is a real shift. You move from building from scratch to reviewing a strong draft, and reviewing is faster, calmer, and far more sustainable across a full week of planning."}$lum$::jsonb, false),
  ($lum$18236560-68b5-54ab-b1fd-3601addcb623$lum$::uuid, $lum$c7ea1f73-35d8-5fcc-95b4-c83a9226c750$lum$::uuid, 5, $lum$multiple_choice$lum$, $lum${"stem":"With the 4th grade primary source, why quote one memorable line of the original directly inside the simplified retelling?","options":[{"id":"a","label":"Because a direct quote makes the simplified version count as longer and therefore harder.","is_correct":false,"explanation":"Length is not the reason and is not the goal. The quote is about contact with the real voice, not adding difficulty or word count."},{"id":"b","label":"Because quoting the source means you no longer have to check the simplified retelling for accuracy.","is_correct":false,"explanation":"A quote does not remove your responsibility to verify the retelling. The reason for the quote is keeping the authentic voice in the room, not skipping checks."},{"id":"c","label":"Because the original is too hard, so the quote replaces it entirely and the source can be cut.","is_correct":false,"explanation":"The opposite is intended. The point is that the authentic source stays in the room rather than getting cut for being too hard."},{"id":"d","label":"So the struggling reader still touches the real voice and the authentic source stays in the room, not drowning in old syntax.","is_correct":true,"explanation":"Correct. The retelling keeps the speaker's main point with one memorable line quoted directly, giving the reader a way in while the authentic source stays present rather than being cut for being too hard."}]}$lum$::jsonb, false),
  ($lum$473e79f3-028d-53ff-8fe1-51de28ff2a4e$lum$::uuid, $lum$c7ea1f73-35d8-5fcc-95b4-c83a9226c750$lum$::uuid, 6, $lum$reading$lum$, $lum${"markdown":"A few predictable mistakes turn this from a time-saver into a liability. They are worth knowing before you lean on the tool in front of real students.\n\nThe first is trusting a simplified version without reading it against the original. Simplifying is exactly the moment meaning slips. The model shortens a sentence and quietly drops a qualifier, and now your 3rd grade water cycle text says rain comes from clouds without mentioning that the water evaporated first, which breaks the whole cycle. Or a history passage gets simplified and a cause becomes the effect, or \"one of several reasons\" becomes \"the reason.\" In science and history especially, a small flattening can produce something that is not just easier but wrong, and your striving readers are the least equipped to catch it. So you always read the simplified version against the source and confirm every key fact survived the trip. This check takes two minutes and it is non-negotiable.\n\nThe second is pasting a student's private information into a public tool. It is tempting to give the AI full context: \"Adapt this for Marcus, who has an IEP for dyslexia and a reading goal of, \" and then the specifics. Stop there. A student's name, IEP details, diagnoses, or any identifying information should not go into a public AI tool, because you do not control where that text lives afterward. You can get an excellent accommodation without naming the child. Describe the need, not the student. \"Lower the language load and chunk the text for a reader who decodes slowly\" gets you the support. \"for Marcus, IEP for dyslexia\" gets you a privacy problem you did not need."}$lum$::jsonb, false),
  ($lum$9230e00c-8339-5228-9441-39384f9596e9$lum$::uuid, $lum$c7ea1f73-35d8-5fcc-95b4-c83a9226c750$lum$::uuid, 7, $lum$fill_blank$lum$, $lum${"template":"Before handing out an AI-simplified passage, read it against the original to confirm it kept every {{1}} and did not flatten the meaning into something wrong. And never paste a student's name or {{2}} details into a public AI tool, because you do not control where that text lives afterward.","blanks":[{"id":"1","accept":["key fact","key facts","fact","facts","key concept","key concepts"],"ideal":"key fact"},{"id":"2","accept":["IEP","IEP details","identifying","identifying information","private","personal","confidential"],"ideal":"IEP"}],"explanation":"Simplifying is where meaning slips, so you verify the facts survived. And IEP or other identifying details should never go into a public tool. Describe the need, not the student."}$lum$::jsonb, false),
  ($lum$940a7da8-c53e-595a-85b5-3e9ed661908d$lum$::uuid, $lum$c7ea1f73-35d8-5fcc-95b4-c83a9226c750$lum$::uuid, 8, $lum$reading$lum$, $lum${"markdown":"The third is treating the AI's accommodation as authority. The model can draft a smart-sounding support, and it will sound confident doing it. But it has never met your student. Only you know that this particular child shuts down at long paragraphs but lights up with a question, or that this newcomer is academically advanced and would be insulted by a baby-talk version. The AI drafts the accommodation. You decide whether it actually serves the kid. When the model's suggestion and your read of the child disagree, you win, every time. The tool is a fast first drafter, not the person who knows the student.\n\nThe thread tying all three together is the same. AI is fast and fluent, and fluent is easy to trust. Your job is to stay the editor. Check the facts, protect the privacy, and keep the final call about each child where it belongs, with you."}$lum$::jsonb, false),
  ($lum$346b8f24-1b95-54dd-b197-f20239cd85f0$lum$::uuid, $lum$c7ea1f73-35d8-5fcc-95b4-c83a9226c750$lum$::uuid, 9, $lum$multiple_choice$lum$, $lum${"stem":"The AI drafts an accommodation that disagrees with what you know about a specific child. According to the lesson, who decides?","options":[{"id":"a","label":"The AI, because it can draft a smart-sounding, confident support faster than you can.","is_correct":false,"explanation":"Sounding confident is not the same as knowing the child. The model has never met your student, so confidence is not authority."},{"id":"b","label":"You do, because you know the actual child and the tool is a fast first drafter, not the person who knows the student.","is_correct":true,"explanation":"Correct. The AI drafts the accommodation, but you decide whether it serves the kid. When its suggestion and your read of the child disagree, you win every time."},{"id":"c","label":"Whichever option sounds more confident, since confidence usually signals the better support.","is_correct":false,"explanation":"The lesson warns that fluent and confident output is easy to trust by mistake. Your job is to stay the editor, not defer to whoever sounds surest."},{"id":"d","label":"Send both versions to the student and let them pick the one they prefer.","is_correct":false,"explanation":"The final call belongs with you, the person who knows the child. Outsourcing the judgment to the student is not the editor role the lesson describes."}]}$lum$::jsonb, false),
  ($lum$de282458-65c8-5b03-935e-50d82b7578f3$lum$::uuid, $lum$c7ea1f73-35d8-5fcc-95b4-c83a9226c750$lum$::uuid, 10, $lum$try_it_live$lum$, $lum${"instructions":"Hand the AI one base text and ask for leveled versions. Give it a short passage you actually teach, then ask for a simplified version that keeps every fact, a grade-level version, and a short extension for early finishers. Or use the sample: a paragraph on the water cycle for a 5th grade class with a few striving readers and two students who need a challenge.","system_prompt":"You are an instructional designer helping a K-12 teacher differentiate one text for a mixed-readiness class. Given a base passage and a description of the learners, produce three things: (1) a simplified version at a stated lower reading level that keeps every key fact intact, (2) the grade-level version lightly cleaned up, and (3) a short extension prompt for early finishers that deepens thinking rather than just adding more work. Preserve factual accuracy in every version and never drop a key concept to make text easier. Flag any place where simplifying risks changing the meaning so the teacher can check it. Do not ask for or use any student's name or private information. No jargon. No em dashes.","ideal_output":"Here are three versions of your water cycle passage. I kept the same four stages in all of them, so no key fact is lost.\n\nSimplified, around 3rd grade level: The sun heats water in oceans and lakes. The water turns into a gas called water vapor and rises into the sky. Up high it cools and forms clouds. When the clouds get heavy, the water falls back down as rain or snow. Then the whole thing starts again.\n\nGrade level, 5th grade: The sun's heat causes water in oceans, lakes, and rivers to evaporate into water vapor. As the vapor rises and cools, it condenses into clouds. When enough water collects, it falls as precipitation, rain or snow, and gathers again to repeat the cycle.\n\nExtension for early finishers: A puddle disappears on a sunny day, but there was no rain. Which stage of the water cycle explains where the water went, and what would have to happen for it to come back as rain?\n\nOne flag: in the simplified version I called water vapor a gas, which is accurate, but you may want to confirm your class has met the word gas in this context before they read it.","input_placeholder":"Paste your base passage and describe your learners: reading levels, language needs, who needs a challenge..."}$lum$::jsonb, true),
  ($lum$20ad1337-1ca8-5615-8ac3-c5ff48b60aba$lum$::uuid, $lum$c7ea1f73-35d8-5fcc-95b4-c83a9226c750$lum$::uuid, 11, $lum$multiple_choice$lum$, $lum${"stem":"You ask AI to simplify a 5th grade science passage for your striving readers. Before you photocopy it, what does this lesson tell you to do first?","options":[{"id":"a","label":"Read the simplified version against the original to confirm it kept every key fact and did not flatten the meaning into something inaccurate.","is_correct":true,"explanation":"Correct. Simplifying is exactly where a qualifier gets dropped or a cause becomes an effect. In science and history a small flattening can become flat wrong, so you verify the facts survived before it reaches students."},{"id":"b","label":"Count the words to make sure the simplified version is at least half the length of the original.","is_correct":false,"explanation":"Length is not the measure. A shorter passage can still be too hard or can have lost a key fact. What you check is whether it stayed accurate while becoming more readable."},{"id":"c","label":"Trust it as is, since you started from a strong, accurate base text.","is_correct":false,"explanation":"A strong base text helps, but the transformation itself can introduce errors. Simplifying is the step where meaning shifts, so you still read it against the source."},{"id":"d","label":"Send it to the AI a second time and ask if it is correct.","is_correct":false,"explanation":"Asking the model to grade its own work is not a reliable check. You are the one who knows the content, so you compare the simplified version to the original yourself."}]}$lum$::jsonb, false),
  ($lum$3b9bc603-1924-5479-90db-333fbd46125a$lum$::uuid, $lum$c7ea1f73-35d8-5fcc-95b4-c83a9226c750$lum$::uuid, 12, $lum$mini_project$lum$, $lum${"brief":"Pick one text or task you are teaching this week and one real range of learners in your class, for example a science paragraph for a group with a few striving readers and two students who finish early. Feed the AI your single base text and ask for three versions: a lower reading-level version that keeps all the facts, a set of comprehension questions that climb in difficulty, and a short extension prompt for early finishers. Then do the part only you can do. Read the simplified version against the original and confirm nothing important got lost, and check that each version fits the specific students you had in mind.","parts":[{"id":"1","prompt":"Choose one accurate base text and write one sentence naming your actual learners and their needs, without using any student's name or private details."},{"id":"2","prompt":"Prompt the AI for the three versions, requiring that every key fact stays intact and that it flags any spot where simplifying might change the meaning."},{"id":"3","prompt":"Read the simplified version line by line against the original, fix anything that drifted, and decide for each version whether it truly serves the child it is for."}]}$lum$::jsonb, false),
  ($lum$3c6b422d-d041-5001-8d0a-757caf9cc7a2$lum$::uuid, $lum$20fdcd20-fcc3-532e-af2b-e753af841a79$lum$::uuid, 0, $lum$reading$lum$, $lum${"markdown":"Document review is slow, detailed work, and it is easy to lose the thread across hundreds of pages. The most important thing to understand before you start is this: AI does not do the review for you, and it should not. What it does is make you faster and more organized at every stage around the review. The reading, the comparing, the deciding what matters: that stays in your hands. AI handles the scaffolding so your trained attention goes where it counts.\n\nThink of a document review job as three phases. There is the work before you open the first document, the work while you are reading, and the work after you have flagged everything. AI helps in all three, in different ways.\n\n**Before you start: build a review framework.** The fastest way to fall behind is to open a stack of contracts and start reading with no plan. You end up noticing different things in document one than in document forty, and your review is inconsistent. Inconsistency is how real issues slip through, because the thing you would have caught on a fresh morning gets missed at the end of a long afternoon. Instead, tell AI the matter type and what you are reviewing for, and ask it to build you a checklist. Say you are a paralegal supporting a due diligence matter where your firm is reviewing a target company's employment contracts. You might prompt: \"I am reviewing employment agreements in an M&A due diligence matter. Build me a checklist of clauses and red flags to look for in each one, including change-of-control provisions, non-compete terms, severance triggers, and assignment of inventions.\" Now you read every contract through the same clear lens. You are not hunting blind, and nothing slips because you were tired by document forty. The checklist is yours to edit, too: cross off what does not apply, add the items the AI did not know to include, and you have a tool you can reuse on the next matter of the same type."}$lum$::jsonb, false),
  ($lum$1c466aeb-c906-5869-8039-1d56ee57fe0b$lum$::uuid, $lum$20fdcd20-fcc3-532e-af2b-e753af841a79$lum$::uuid, 1, $lum$multiple_choice$lum$, $lum${"stem":"According to the lesson, why should you build a review checklist with AI before opening the first document?","options":[{"id":"a","label":"So the AI can read the contracts for you and flag the issues automatically.","is_correct":false,"explanation":"The checklist does not hand the reading to the AI. You still read every contract yourself; the checklist just keeps your attention consistent."},{"id":"b","label":"So your review stays consistent across every document, since reading with no plan means you notice different things in document one than in document forty.","is_correct":true,"explanation":"Correct. Inconsistency is how real issues slip through, and a shared checklist means you read every contract through the same clear lens even late in a long matter."},{"id":"c","label":"So you never have to edit or adjust the list once the AI produces it.","is_correct":false,"explanation":"The opposite is true. The checklist is yours to edit: cross off what does not apply and add the items the AI did not know to include."}]}$lum$::jsonb, false),
  ($lum$8ee4ad85-da89-5003-8410-cfcb15bf217c$lum$::uuid, $lum$20fdcd20-fcc3-532e-af2b-e753af841a79$lum$::uuid, 2, $lum$reading$lum$, $lum${"markdown":"**During: organize what you find.** As you read and flag, your notes pile up fast and lose shape. Here AI turns scatter into a record. Imagine you are reviewing a batch of commercial leases for a real estate acquisition, and across twelve leases you have flagged assorted clauses about renewal options, assignment restrictions, and early termination. Paste your flagged text in and prompt: \"Here are the clauses I flagged across these twelve leases. Organize them into a table with columns for document name, clause type, and the issue I noted.\" In seconds you have a clean grid instead of a messy list, and you can see patterns, like three leases sharing the same problematic assignment clause, that were invisible in your running notes.\n\n**After: draft the issue summary.** When the review is done, someone needs a memo. AI can give you the first structure. Picture a compliance review where you flagged data-handling problems across a set of vendor agreements. You prompt: \"Based on the flagged issues below, draft an issue summary memo organized by severity, from highest risk to lowest.\" You get a clean skeleton organized the way the partner wants to read it, with the worst problems up top and the minor ones below. Then you edit every line and verify each point, but you did not start from a blank page. For a tired reviewer at the end of a long matter, that first structure is the difference between a memo that goes out tonight and one that waits until tomorrow."}$lum$::jsonb, false),
  ($lum$fb1434cf-516e-5d66-a49e-f31507b7c8cf$lum$::uuid, $lum$20fdcd20-fcc3-532e-af2b-e753af841a79$lum$::uuid, 3, $lum$fill_blank$lum$, $lum${"template":"During the review, AI turns your scattered notes into a {{1}} so patterns become visible; when the review is done, it can draft the first {{2}} of an issue summary memo for you to edit and verify.","blanks":[{"id":"1","accept":["table","grid","record"],"ideal":"table"},{"id":"2","accept":["structure","draft","skeleton"],"ideal":"structure"}],"explanation":"AI organizes flagged clauses into a clean table where patterns like a shared assignment clause stand out, and it gives you a first memo structure so you are not starting from a blank page. You still edit every line and verify each point."}$lum$::jsonb, false),
  ($lum$5d38247e-70bf-5ce9-907a-78b6f5b1a87c$lum$::uuid, $lum$20fdcd20-fcc3-532e-af2b-e753af841a79$lum$::uuid, 4, $lum$reading$lum$, $lum${"markdown":"Now the limits, and these are not optional in legal work.\n\n**The review judgment is yours.** What counts as a problem, what is material to this deal, what needs to go up the chain for escalation: these are professional calls AI cannot make. The tool only sees the text you handed it. It has no view of the deal strategy, the client's risk appetite, or the leverage in a negotiation. It helps you prepare and organize. It does not decide what matters.\n\n**Verify every organized item against the source.** Anything AI summarizes, tables, or restates must be checked against the actual document. A single misread clause can flip a meaning entirely. If a non-compete says the restriction does not apply after termination and the AI table drops the word \"not,\" your memo now says the opposite of the truth. Always read the entry back against the source clause before you rely on it.\n\n**Protect confidentiality.** Do not paste privileged or confidential material into a public AI tool. Privileged documents belong only in an approved, private tool your firm has cleared for sensitive content. Where you can, genericize: strip names, deal terms, and identifying facts, and work with the structure rather than the secrets.\n\nThe pattern, one more time: AI handles the checklists, the organizing, and the first-draft structure, and your trained judgment handles the review itself."}$lum$::jsonb, false),
  ($lum$94c19e94-37b1-5602-a781-03cfbbff8597$lum$::uuid, $lum$20fdcd20-fcc3-532e-af2b-e753af841a79$lum$::uuid, 5, $lum$multiple_choice$lum$, $lum${"stem":"What is the core thing AI does for document review?","options":[{"id":"a","label":"It performs the review and tells you which documents have problems so you can move on.","is_correct":false,"explanation":"AI does not perform the review. It cannot weigh what is material to a matter, and trusting it to do so means relying on a tool that only sees the text you gave it."},{"id":"b","label":"It makes you faster and more organized around the review by building checklists, structuring findings, and drafting summaries, while you keep the review judgment.","is_correct":true,"explanation":"Correct. AI handles the scaffolding before, during, and after the review. The reading, the deciding what matters, and the verification stay with you."},{"id":"c","label":"It replaces the need for a review checklist, since it already knows what to flag in any matter.","is_correct":false,"explanation":"AI does not know your matter. You build the checklist with it precisely so your review is consistent and tuned to the specific matter type and risks."}]}$lum$::jsonb, false),
  ($lum$780f343c-5ae9-514b-a67f-58a288ba1193$lum$::uuid, $lum$20fdcd20-fcc3-532e-af2b-e753af841a79$lum$::uuid, 6, $lum$reading$lum$, $lum${"markdown":"Most problems with AI in document review do not come from the tool being wrong. They come from leaning on it for the part that is supposed to be yours. Here are the mistakes that bite paralegals and small-firm attorneys most often.\n\n**Treating the AI's \"material\" labels as a real materiality assessment.** This is the big one. You ask AI to organize flagged clauses and it helpfully marks some as \"material\" or \"high risk.\" It feels authoritative. But the tool only sees the text you pasted. It has no idea that this acquisition hinges on retaining two key engineers, so a weak non-compete is the single most material issue in the stack, while a typo in the governing-law clause is noise. Materiality depends on strategy, stakes, and context the AI never had. Use its labels as a rough sort at most, then apply your own judgment.\n\n**Pasting privileged documents into a public tool.** A quick paste into a free, public chatbot can put privileged client material onto a third party's servers. That is a confidentiality and privilege problem, and it does not un-happen. Use only a tool your firm has approved for sensitive material, and genericize whatever you can before it goes anywhere near AI."}$lum$::jsonb, false),
  ($lum$cf8feb71-4b9a-50d1-8772-a7be73ba0c35$lum$::uuid, $lum$20fdcd20-fcc3-532e-af2b-e753af841a79$lum$::uuid, 7, $lum$fill_blank$lum$, $lum${"template":"The most common mistake is treating the AI's {{1}} labels as a real assessment, when the tool only sees the text you gave it; the professional {{2}} about what actually matters to the matter stays with you.","blanks":[{"id":"1","accept":["material","materiality","high-risk","risk"],"ideal":"material"},{"id":"2","accept":["judgment","judgement","decision"],"ideal":"judgment"}],"explanation":"AI can sort and organize, but it has no view of the matter's strategy or stakes, so its 'material' labels are guesses. Deciding what is truly material is a judgment that remains a human responsibility, verified against the source."}$lum$::jsonb, false),
  ($lum$dc3c7426-0431-540f-9a26-0cd01b9d86ba$lum$::uuid, $lum$20fdcd20-fcc3-532e-af2b-e753af841a79$lum$::uuid, 8, $lum$reading$lum$, $lum${"markdown":"**Skipping verification of organized entries against the source.** When AI produces a clean table, it looks finished, and a finished-looking thing is tempting to trust. But organizing involves restating, and restating can drift. A clause about a 90-day cure period might land in the table as \"30-day cure period.\" Always read each entry back against the actual clause before it goes in a memo or a deal point.\n\n**Treating review judgment as mechanical.** It is easy to talk yourself into believing the review is just pattern-matching that AI can do. It is not. Deciding what is a real problem, what needs escalation, and what to advise on is the trained, professional core of the work. That is the part you do not outsource.\n\n**Trusting an AI-drafted issue memo without checking each cited clause.** The memo may read beautifully and cite \"Section 7.2.\" Before it goes out, open the document and confirm Section 7.2 says what the memo claims. A confident, well-written memo built on one misread clause is more dangerous than messy notes, because no one questions it.\n\nThe thread through all of these: AI is excellent at structure and terrible at significance. Keep it on the structure."}$lum$::jsonb, false),
  ($lum$0065ad06-f30c-51c9-8202-2a9cccaf5e6a$lum$::uuid, $lum$20fdcd20-fcc3-532e-af2b-e753af841a79$lum$::uuid, 9, $lum$multiple_choice$lum$, $lum${"stem":"An AI-organized table looks clean and finished, and an AI-drafted memo reads beautifully and cites 'Section 7.2.' Why is this still dangerous?","options":[{"id":"a","label":"Because organizing involves restating, which can drift, so a 90-day cure period might land as '30-day,' and a confident memo built on one misread clause goes unquestioned.","is_correct":true,"explanation":"Correct. A finished-looking output is tempting to trust, but you must read each entry back against the source and confirm every cited clause before relying on it."},{"id":"b","label":"Because AI output can never be used in legal work and must always be retyped by hand.","is_correct":false,"explanation":"Organizing findings is exactly what AI is good for. The fix is to verify each entry against the source, not to throw the output away."},{"id":"c","label":"Because a clean table proves the review judgment was already done correctly.","is_correct":false,"explanation":"A clean appearance proves nothing about significance. AI is excellent at structure and terrible at significance, so the judgment and verification remain yours."}]}$lum$::jsonb, false),
  ($lum$9e88e93a-47c0-5050-99bf-49386af83605$lum$::uuid, $lum$20fdcd20-fcc3-532e-af2b-e753af841a79$lum$::uuid, 10, $lum$before_after$lum$, $lum${"question":"You are a paralegal about to review a set of commercial leases in a real estate acquisition. Rewrite a prompt that hands the judgment to the AI into one that keeps the judgment with you.","before_prompt":"Review these commercial leases and tell me which clauses are material to the acquisition.","after_prompt":"Build me a red-flag checklist for commercial leases in a real estate acquisition. List the clause types and specific terms I should examine in each lease, such as assignment and change-of-control restrictions, renewal and termination options, and estoppel requirements. I will apply the materiality judgment myself as I review.","changes":["Stops asking the AI to decide what is material and asks it to build a review framework instead.","Names the real scenario, commercial leases in a real estate acquisition, so the checklist is tuned to the matter.","States explicitly that the materiality judgment stays with you, which is the part the tool cannot do."]}$lum$::jsonb, true),
  ($lum$5c03d5ec-4d0e-5559-81fa-6971c3d98655$lum$::uuid, $lum$20fdcd20-fcc3-532e-af2b-e753af841a79$lum$::uuid, 11, $lum$multiple_choice$lum$, $lum${"stem":"You used AI to build a red-flag checklist for employment agreements in a due diligence matter, then had it organize your flagged clauses into a table marking some as 'material.' What is the right next step before you write your memo?","options":[{"id":"a","label":"Apply your own materiality judgment to the matter and verify each table entry against the actual source clause, then write the memo.","is_correct":true,"explanation":"Correct. The AI's structure is a starting point. You decide what is truly material given the deal, and you confirm every organized entry against the source before relying on it."},{"id":"b","label":"Copy the AI's 'material' labels straight into the memo, since the table already reviewed all the clauses together.","is_correct":false,"explanation":"The table did not review anything. The tool only sees the text you pasted and has no view of the deal's stakes, so its labels are guesses you must replace with your own judgment."},{"id":"c","label":"Have the AI draft the full memo and send it once it reads cleanly, to save time.","is_correct":false,"explanation":"A clean-reading memo can be built on a misread clause. Before anything goes out, you must check each cited clause against the source and supply the materiality judgment yourself."},{"id":"d","label":"Discard the table and re-sort everything by hand, since AI output cannot be used in review work.","is_correct":false,"explanation":"That throws away a legitimate, useful step. Organizing findings is exactly what AI is good for. You just add the judgment and verify against the source rather than starting over."}]}$lum$::jsonb, false),
  ($lum$b7810ad9-dbdc-51b5-b666-1dfdb7993da3$lum$::uuid, $lum$20fdcd20-fcc3-532e-af2b-e753af841a79$lum$::uuid, 12, $lum$mini_project$lum$, $lum${"brief":"Pick one real review task you actually do, name the matter type and what you are reviewing for, and use AI to build a reusable review checklist for it. Then put the checklist and the tool through a real test: feed it a few genericized sample clauses, have it organize them, and watch for the spot where its judgment is wrong and yours has to correct it. The deliverable is one checklist you can use again plus a short note on where your judgment beat the tool.","parts":[{"id":"1","prompt":"Prompt AI to build a clause-and-red-flag checklist for your chosen matter (for example, employment agreements in an M&A due diligence review), then mark what it missed and what it surfaced that you would not have listed."},{"id":"2","prompt":"Paste in a few genericized sample clauses and ask AI to organize them into a table by document, clause type, and issue, then verify each entry against the source text."},{"id":"3","prompt":"Write a one-paragraph note identifying at least one place where the AI's labeling or organizing was wrong and your review judgment had to override it."}]}$lum$::jsonb, false),
  ($lum$d5948f6b-a48d-5362-97df-fc736268e758$lum$::uuid, $lum$d16618b2-d469-58ce-a524-6e01e22f8604$lum$::uuid, 0, $lum$reading$lum$, $lum${"markdown":"Your employees are already using AI. That is not a future risk you are deciding whether to allow. It is happening right now, in your company, today. The only real question is whether your people are doing it with guidance or guessing. When there is no clear answer, they invent one, and they each invent a slightly different one. HR usually responds with a policy, and most AI policies fail in exactly the same way. They are long. They are abstract. They are written from fear. And they are dressed in legal language that nobody finishes reading.\n\nPicture the sentence that shows up in almost every one of these documents: \"Employees must use AI responsibly and in accordance with all applicable policies.\" Read that as one of your colleagues would. Does it tell you whether you can paste a customer's complaint email into a chatbot to get help writing a calmer reply? It does not. It tells you nothing. So the person makes a call on their own, gets on with their day, and the policy you spent two weeks drafting has changed nothing about what actually happens. It protected the company on paper and no one in practice.\n\nThink about Priya, an HR generalist at a 90-person company with no AI policy at all. People keep asking her if they are allowed to use these tools, and she keeps saying some version of \"be careful.\" That is not guidance. It is worry passed along. Or think about Daniel, a people-ops lead who inherited a scary two-thousand-word legalese draft from an old legal review. It bans almost everything in language no one reads, so the team quietly ignores it and uses AI anyway, just without telling anyone. Both of them have the same problem. The document on file is not the thing shaping behavior."}$lum$::jsonb, false),
  ($lum$396ba70c-fbeb-5565-88f2-3a11e865909e$lum$::uuid, $lum$d16618b2-d469-58ce-a524-6e01e22f8604$lum$::uuid, 1, $lum$multiple_choice$lum$, $lum${"stem":"According to the opening, which statement best describes the real situation HR faces with AI at work?","options":[{"id":"a","label":"Employees are already using AI today, so the question is whether they do it with guidance or guessing.","is_correct":true,"explanation":"Correct. The lesson opens by stating use is already happening now, not a future decision, and the open question is guidance versus guessing."},{"id":"b","label":"AI use is a future risk HR gets to decide whether to permit before anyone starts.","is_correct":false,"explanation":"The lesson explicitly rejects this framing. It says AI use is not a future risk you are deciding whether to allow; it is happening right now."},{"id":"c","label":"Most employees wait for a written policy before they touch any AI tool.","is_correct":false,"explanation":"The opposite is described. When there is no clear answer, people invent their own, each a slightly different one, rather than waiting."},{"id":"d","label":"A vague sentence like 'use AI responsibly' is enough to guide a colleague through a real task.","is_correct":false,"explanation":"The Priya and Daniel framing and the chatbot example show vague lines tell people nothing, so they make their own call and the policy changes nothing."}]}$lum$::jsonb, false),
  ($lum$6a43ebe7-0001-5ab9-ba25-2b019ac5b957$lum$::uuid, $lum$d16618b2-d469-58ce-a524-6e01e22f8604$lum$::uuid, 2, $lum$reading$lum$, $lum${"markdown":"A policy people actually follow has different properties, and they are not complicated. First, it is short. A person should be able to read the whole thing in about two minutes. Second, it is concrete. It is built on real examples of how your people genuinely work, not on hypothetical scenarios a lawyer imagined. Third, it is framed around enabling good use, not only forbidding things. A document that says nothing but no gets ignored the very first time AI is genuinely helpful, because people are not going to leave an obvious win on the table just because a PDF told them to. The goal is a document that changes what people do, not one that covers the company while everyone improvises underneath it.\n\nThis is where AI can genuinely help you, and it is well suited to the task. A model can produce a clean structure and plain, readable language fast. It can take your messy notes and turn them into something a new hire could follow. What it absolutely cannot do is supply the judgment. The model does not know your specific risks. It does not know your data classifications, which tools you have actually approved, what your customers expect, or the day-to-day realities of your teams. A generic AI-generated policy that either bans everything or permits everything has skipped exactly the part that you, the HR professional, exist to provide. The drafting is the easy half. The judgment is yours, and it is the half that matters."}$lum$::jsonb, false),
  ($lum$f6990da4-c798-59b8-8119-fb70d2bfbf08$lum$::uuid, $lum$d16618b2-d469-58ce-a524-6e01e22f8604$lum$::uuid, 3, $lum$multiple_choice$lum$, $lum${"stem":"The lesson says AI is well suited to drafting a policy. What does it say AI cannot do?","options":[{"id":"a","label":"Produce a clean structure and plain, readable language quickly.","is_correct":false,"explanation":"This is named as something AI is good at. The lesson says a model can produce clean structure and readable language fast."},{"id":"b","label":"Turn messy notes into something a new hire could follow.","is_correct":false,"explanation":"This is also listed as a strength. AI can take your messy notes and turn them into something readable; it is the drafting half."},{"id":"c","label":"Supply the judgment, since it does not know your risks, data classifications, approved tools, or team realities.","is_correct":true,"explanation":"Correct. The lesson states the model cannot supply judgment because it does not know your specific risks, data classifications, approved tools, or daily realities. That half is yours."},{"id":"d","label":"Write any usable text at all without legal supervision.","is_correct":false,"explanation":"The lesson credits AI with doing the drafting well; the gap is judgment, not the ability to write usable text."}]}$lum$::jsonb, false),
  ($lum$7a2c19b4-40ec-5e07-a896-9fbdd0291737$lum$::uuid, $lum$d16618b2-d469-58ce-a524-6e01e22f8604$lum$::uuid, 4, $lum$reading$lum$, $lum${"markdown":"So what makes a policy stick? A few concrete pieces. You want clear green-light examples, the things people can just go ahead and do: drafting and editing internal documents, brainstorming ideas, summarizing public or non-sensitive material, learning how to do something. Naming these matters more than it sounds, because permission removes the hesitation that pushes good use into hiding. You also want clear red-light examples, the genuine lines: pasting customer data, personal information, or confidential figures into tools that are not on your approved list, and letting AI make a final decision about a person, such as a hire, a promotion, or a termination. Those are the situations where a wrong move actually hurts someone.\n\nBetween green and red sits the gray zone, and the gray zone is where most people get stuck. Someone has a task that is not obviously fine and not obviously forbidden, and they have no idea what to do. A good policy gives them a named, easy way to ask. Not \"consult the appropriate channels,\" which is just legalese for \"you figure it out.\" A real one: ask in the team chat, or message a specific named person, and you will never be penalized for checking first. That single line does more work than three pages of rules, because it gives people a path that is not guessing.\n\nAnd finally, plain language. Write it so a new hire on day one could read it, understand it, and act on it without asking anyone what a phrase means. If your policy needs a translator, it is not a policy people will follow. It is a document. The difference between those two things is the entire point of this lesson."}$lum$::jsonb, false),
  ($lum$106353cf-3f2e-507c-be62-f864f9d3187b$lum$::uuid, $lum$d16618b2-d469-58ce-a524-6e01e22f8604$lum$::uuid, 5, $lum$multiple_choice$lum$, $lum${"stem":"Two draft AI policies land on your desk. Which one is more likely to actually change how employees behave?","options":[{"id":"a","label":"A comprehensive ten-page document in formal legal language that covers every conceivable scenario.","is_correct":false,"explanation":"Length and legalese are exactly what makes a policy go unread. If people do not finish it, or cannot tell what applies to their task, they improvise and the document protects no one."},{"id":"b","label":"A two-minute read with concrete green-light and red-light examples and a named way to ask when unsure.","is_correct":true,"explanation":"Correct. Short, concrete, example-driven policies with a clear path for the gray zone get read and followed. The specificity is what turns a document into behavior."},{"id":"c","label":"A one-line policy that simply bans all use of AI tools at work.","is_correct":false,"explanation":"A blanket ban gets ignored the moment AI is genuinely useful, and it drives usage underground with no guidance. A usable policy enables good use and draws clear lines instead of forbidding everything."}]}$lum$::jsonb, false),
  ($lum$66b4089f-c336-5e62-b133-890c44efd627$lum$::uuid, $lum$d16618b2-d469-58ce-a524-6e01e22f8604$lum$::uuid, 6, $lum$reading$lum$, $lum${"markdown":"The most common way these policies go wrong is that HR hands the whole job to the AI and ships whatever comes back. You ask a model to \"write an AI use policy,\" and it produces something that looks polished and professional. It reads well. And it is useless, because it is generic. It bans pasting \"sensitive data\" without ever naming what your company counts as sensitive. It references \"approved tools\" without knowing which tools you approved. It is a beautiful template with the actual decisions left blank, and those blanks are the only part that protects anyone. The model wrote the easy half and skipped the half that is your job.\n\nThe second failure is fear-driven framing. When a policy is built only from worry, it becomes a wall of no. Daniel, the people-ops lead, inherited exactly this: a draft so focused on everything that could go wrong that it forbade nearly everything useful. The predictable result is that people stop reading it and stop trusting it. Worse, a fear-only policy pushes AI use into hiding. If every honest question feels like it might get you in trouble, you stop asking and just quietly do the thing. Now you have less visibility into AI use than before you wrote the policy, which is the exact opposite of the goal."}$lum$::jsonb, false),
  ($lum$a6706f81-4b57-5389-834c-7d2a8c3a6ccd$lum$::uuid, $lum$d16618b2-d469-58ce-a524-6e01e22f8604$lum$::uuid, 7, $lum$multiple_choice$lum$, $lum${"stem":"Why does the lesson call a generic, AI-written policy useless even when it reads polished and professional?","options":[{"id":"a","label":"Because it is too short for anyone to take seriously.","is_correct":false,"explanation":"Length is not the complaint here. The problem is that the polished draft is generic, not that it is short."},{"id":"b","label":"Because it uses too many concrete examples specific to one team.","is_correct":false,"explanation":"The opposite is true. The generic draft lacks specifics; it bans 'sensitive data' and cites 'approved tools' without naming either."},{"id":"c","label":"Because legal review always rejects AI-generated text.","is_correct":false,"explanation":"The lesson does not mention legal review rejecting it. The flaw is that the actual decisions are left blank, which is the only part that protects anyone."},{"id":"d","label":"Because it leaves the actual decisions blank, banning 'sensitive data' and citing 'approved tools' without naming what they are.","is_correct":true,"explanation":"Correct. The lesson says it is a beautiful template with the decisions left blank, and those blanks are the only part that protects anyone; the model did the easy half and skipped your job."}]}$lum$::jsonb, false),
  ($lum$7d7c8f9d-7145-5bd7-8e25-37acd9977bfd$lum$::uuid, $lum$d16618b2-d469-58ce-a524-6e01e22f8604$lum$::uuid, 8, $lum$reading$lum$, $lum${"markdown":"A third failure is skipping the gray zone. Many policies list some greens and some reds and then stop, as if every situation falls neatly into one bucket. Real work is full of in-between cases. Can I summarize this internal report that is not public but also not exactly confidential? When the policy is silent, the careful person freezes and the casual person guesses, and neither outcome is what you wanted. Naming one easy way to ask resolves almost all of this. It is the cheapest, highest-value line in the document.\n\nThe fourth failure is vagueness disguised as completeness. \"Use AI responsibly.\" \"Exercise good judgment.\" \"Comply with applicable regulations.\" These sound like rules but contain no instruction. A new hire reading them learns nothing about what to actually do on Tuesday morning. The fix is a test you can run yourself: hand the draft to someone on the team, describe three real tasks, and ask them to tell you what the policy says they should do. If they cannot answer quickly and confidently, the policy is still too abstract, no matter how thorough it looks. Revise until the answers come fast. That is the line between a document that exists and a policy that works."}$lum$::jsonb, false),
  ($lum$c3a4d0a7-9c1a-5aa8-868c-127793d8fe84$lum$::uuid, $lum$d16618b2-d469-58ce-a524-6e01e22f8604$lum$::uuid, 9, $lum$fill_blank$lum$, $lum${"template":"A policy that lists only what is forbidden tends to be {{1}} the moment AI is genuinely useful, and the single highest-value line you can add is a named, easy way to {{2}} when a situation falls in the gray zone.","blanks":[{"id":"1","accept":["ignored","ignored entirely","disregarded","bypassed"],"ideal":"ignored"},{"id":"2","accept":["ask","ask for help","check first","raise it"],"ideal":"ask"}],"explanation":"A forbid-only policy gets ignored as soon as AI offers a real win, because people will not skip obvious value just because a document said no. The fix for the in-between cases is giving people a named, easy way to ask rather than leaving them to guess."}$lum$::jsonb, false),
  ($lum$d7e438f4-111d-536a-84b8-b422dd0c5350$lum$::uuid, $lum$d16618b2-d469-58ce-a524-6e01e22f8604$lum$::uuid, 10, $lum$try_it_live$lum$, $lum${"instructions":"Ask the AI to draft a short, usable AI policy you can adapt. Give it your team, your approved tools, and the data that must never go into unapproved tools. Or use this sample: a small customer-support team, one approved enterprise AI assistant, and a hard rule that customer records and personal information never go into any tool that is not on the approved list.","system_prompt":"You are an HR policy partner helping a non-technical HR professional draft a short, usable internal AI policy. Keep it readable in about two minutes, in plain language a new hire could follow on day one. Structure it as: a one-line purpose, three to five concrete green-light examples, three to five concrete red-light examples, and a named, easy way to ask when something is unclear. Avoid legal jargon and fear-based framing. Frame it around enabling good use within clear lines. Remind the user that you do not know their specific risks, approved tools, or data classifications, so they must confirm the specifics before they publish. No em dashes.","ideal_output":"Here is a short draft AI policy. Please confirm the specifics, your approved tools and your data rules, against what your organization has actually decided, since I am working only from what you told me.\n\nPurpose: Use AI to do better work faster while keeping our customers and our company data safe.\n\nGreen light, go ahead: drafting and editing internal documents and emails, brainstorming ideas, summarizing public or non-sensitive material, and learning how to do something. Use [your approved tool] for anything work-related.\n\nRed light, do not: paste customer records, personal information, confidential figures, or anything not yet public into any AI tool that is not on our approved list. Do not let AI make a final decision about a person, such as a hire, a promotion, or a termination.\n\nNot sure? Ask in the team chat or message [named person] before you do it. Asking is always the right call, and you will never be penalized for checking first.\n\nWant me to tailor the examples to a specific team and their daily tasks?","input_placeholder":"Describe your team, your approved tools, and the data that must never go into unapproved tools..."}$lum$::jsonb, true),
  ($lum$cd969efa-16ed-54a7-971a-8a26eedd7d5e$lum$::uuid, $lum$d16618b2-d469-58ce-a524-6e01e22f8604$lum$::uuid, 11, $lum$multiple_choice$lum$, $lum${"stem":"An HRBP keeps fielding the same question from staff: 'Can I use this AI tool for this task?' What single addition to the policy would reduce that bottleneck the most?","options":[{"id":"a","label":"A named, easy way to ask in the gray zone, such as a specific channel or person, with a promise that checking is never penalized.","is_correct":true,"explanation":"Correct. Most repeat questions come from in-between cases the green and red lists do not cover. A clear, safe path to ask resolves them quickly and keeps usage visible rather than hidden."},{"id":"b","label":"A longer, more detailed list of forbidden activities so fewer situations are left unaddressed.","is_correct":false,"explanation":"You cannot enumerate every situation, and a longer ban list makes the policy harder to read while still leaving gray-zone cases. People will keep asking, or stop asking and guess."},{"id":"c","label":"A statement directing employees to use good judgment and comply with applicable policies.","is_correct":false,"explanation":"Vague language that sounds like a rule but gives no instruction is what produced the questions in the first place. It tells the HRBP's colleagues nothing about what to actually do."}]}$lum$::jsonb, false),
  ($lum$1336f3b0-3ced-5c87-8184-4e048cd8d49c$lum$::uuid, $lum$d16618b2-d469-58ce-a524-6e01e22f8604$lum$::uuid, 12, $lum$mini_project$lum$, $lum${"brief":"Draft a real one-page AI policy for your organization or for one team inside it, and treat the judgment as the part only you can supply. Begin by writing down your actual approved tools, your real do-not-touch data categories, and the two or three situations your people most often run into, the ones an HRBP keeps getting asked about. Then use AI to turn those raw notes into a two-minute read with concrete green-light and red-light examples and a clearly named way to ask in the gray zone. Finally, pressure-test it the way the lesson described, so you ship a policy that changes behavior rather than a document that sits in a folder.","parts":[{"id":"1","prompt":"List your approved tools, your real do-not-touch data categories, and your two or three most common situations before you open any AI tool."},{"id":"2","prompt":"Use AI to draft a two-minute version with concrete greens, concrete reds, and one named, easy way to ask, then strip out any vague phrase like \"use good judgment.\""},{"id":"3","prompt":"Hand the draft to a teammate, name three real tasks, and ask what the policy says they should do; if any answer is slow or unsure, revise until a new hire could follow it on day one."}]}$lum$::jsonb, false),
  ($lum$8e3dd2c9-09c1-517d-bf7e-020b6a831c12$lum$::uuid, $lum$74da21a3-46b3-5d9b-a1bb-f6ca90aa103b$lum$::uuid, 0, $lum$reading$lum$, $lum${"markdown":"The hardest replies in customer service are the ones to people who are genuinely upset. The customer is frustrated, sometimes unfair, sometimes blaming you for something a warehouse or a billing system did. Meanwhile you have thirty other tickets waiting and a queue timer ticking. Under that pressure it is easy to write something defensive, robotic, or accidentally cold, and the wrong tone turns a recoverable problem into an escalation, a chargeback, or a one-star review with your name in it. The real skill is responding with genuine warmth while still being clear and efficient, and that is exactly the kind of writing AI is good at helping you start.\n\nHere is the thing to be honest about: the value is not that AI feels empathy. It does not feel anything. The value is that it can phrase acknowledgment and a path forward in calm, warm language faster than you can when you are stressed and rushed. You bring the facts and the resolution. The model helps you say it well. That distinction matters, because it tells you what to expect and what to never outsource. The empathy in the final reply is real because you made it real for this specific person. The AI just got you to clear, human language fast."}$lum$::jsonb, false),
  ($lum$b7726fc4-9358-533d-b11e-c99a40c251f9$lum$::uuid, $lum$74da21a3-46b3-5d9b-a1bb-f6ca90aa103b$lum$::uuid, 1, $lum$multiple_choice$lum$, $lum${"stem":"What actually makes an AI-drafted reply to an upset customer work?","options":[{"id":"a","label":"The AI genuinely understands and feels the customer's frustration, so the empathy is authentic.","is_correct":false,"explanation":"The AI does not feel anything. Believing it does leads you to trust the draft blindly. The empathy in the final reply is real only because you make it real for this specific person."},{"id":"b","label":"It phrases acknowledgment and a concrete fix in calm, warm language faster than you can when you are stressed, while you supply the facts and the resolution.","is_correct":true,"explanation":"Correct. The value is speed to clear, human phrasing under pressure. You bring the situation and the real fix, and the model helps you say it well. That is the working partnership."},{"id":"c","label":"It writes a long, detailed apology that covers every possible angle so nothing is left out.","is_correct":false,"explanation":"Length is not the goal. Upset customers want acknowledgment plus a clear fix, not a wall of text. Concise and human beats long and exhaustive."},{"id":"d","label":"It uses formal, corporate language that signals the company is taking the matter seriously.","is_correct":false,"explanation":"Corporate, scripted phrasing is what makes upset customers feel processed rather than heard. Warm and human is what defuses, not formality."}]}$lum$::jsonb, false),
  ($lum$4e24624f-029f-5a6f-88b6-3b8f8cae079b$lum$::uuid, $lum$74da21a3-46b3-5d9b-a1bb-f6ca90aa103b$lum$::uuid, 2, $lum$reading$lum$, $lum${"markdown":"Let me make this concrete with scenarios you have probably lived.\n\nFirst, the late and damaged order. A customer ordered something for a specific occasion, it arrived almost two weeks late, and when it finally showed up the box was crushed and the item inside was broken. They are angry, and they have a right to be. You can refund and reship today. A weak reply opens with \"We apologize for any inconvenience,\" which reads like a form letter and makes things worse. A strong prompt looks like this: \"A customer's order arrived about two weeks late and damaged. We can issue a full refund and reship today at no cost. Draft a warm, genuinely apologetic reply that acknowledges their frustration first, takes responsibility without excuses, then clearly lays out the refund and reshipment. Keep it concise and human, not corporate.\" What comes back leads with acknowledgment, owns the failure, and states the fix in plain words. You then add the customer's name and the order specifics from your system.\n\nSecond, the double charge. A subscriber notices they were billed twice this month for the same plan, and now they are worried money is gone and nobody is watching their account. This is a trust problem as much as a money problem. You confirm the duplicate charge and you can reverse it. The prompt: \"A customer was accidentally charged twice for their monthly subscription. I have confirmed the duplicate and can reverse it within three to five business days. Draft a calm, reassuring reply that takes the worry seriously, confirms the error is real and on us, and explains exactly when the refund lands. No jargon.\" The draft reassures without minimizing, which is what a worried customer needs. You verify the refund timing against your actual process before it goes out."}$lum$::jsonb, false),
  ($lum$3b28d80c-ca5e-5c68-8022-b3fd1ea1ffda$lum$::uuid, $lum$74da21a3-46b3-5d9b-a1bb-f6ca90aa103b$lum$::uuid, 3, $lum$multiple_choice$lum$, $lum${"stem":"In the double-charge scenario, what does a strong prompt deliberately ask the draft to do?","options":[{"id":"a","label":"Take the worry seriously, confirm the error is real and on us, and explain exactly when the refund lands, with no jargon.","is_correct":true,"explanation":"Correct. A double charge is a trust problem as much as a money problem, so the prompt asks for reassurance that names the worry, owns the error, and states clear timing in plain language."},{"id":"b","label":"Downplay the charge as a minor glitch so the customer does not overreact while the refund processes.","is_correct":false,"explanation":"Minimizing is exactly what a worried customer does not need. The draft reassures without minimizing, taking the worry seriously instead of brushing it off."},{"id":"c","label":"Open with the company's billing policy in full so the customer understands the system that caused it.","is_correct":false,"explanation":"Leading with policy and jargon reads as dodging the feeling. The prompt explicitly asks for no jargon and for the error to be confirmed as real and on us."},{"id":"d","label":"Ask the customer to forward their bank statement before any refund can be promised.","is_correct":false,"explanation":"In this scenario you have already confirmed the duplicate and can reverse it. The reply confirms the fix and the timing rather than putting the work back on the customer."}]}$lum$::jsonb, false),
  ($lum$2cf9df0b-23ec-5e25-aea7-7dd0e35716a1$lum$::uuid, $lum$74da21a3-46b3-5d9b-a1bb-f6ca90aa103b$lum$::uuid, 4, $lum$reading$lum$, $lum${"markdown":"Third, the broken promise. A customer was told they would get a callback to sort out a problem, and the callback never came. Now they are back, more frustrated than before, because the issue is still unsolved and they feel ignored. This one is delicate, because the company already let them down once. A good prompt names that: \"A customer was promised a callback that never happened, and their original issue is still open. Draft a sincere reply that acknowledges we dropped the ball on the callback, apologizes specifically for that, and commits to a clear next step with a real timeframe. Warm and direct, no excuses about being busy.\" The draft owns the miss instead of glossing over it. You fill in the real next step you can actually deliver, because a second broken promise is unforgivable.\n\nNotice the pattern across all three. You describe the situation in general terms, you state the actual resolution you can offer, and you ask for a specific tone and structure: acknowledge first, take responsibility, then lay out the fix. That order matters for upset people. Lead with the fix and you sound like you are dodging the feeling. Lead with the feeling and forget the fix and you sound hollow. The AI handles the shape. You handle the substance, the real name, the real policy, the real timeframe.\n\nThe draft gets you to calm, clear, human language fast, which is precisely what is hardest to produce when your heart rate is up and the queue is full. That speed is the whole point. It lets you respond from a steady place instead of a defensive one. And it protects the customer relationship at the exact moment it is most fragile, because the reply that goes out when someone is angry is the one they remember and the one they screenshot. A steady, warm, specific answer in that moment is often what turns a furious customer back into a loyal one, and starting from a solid draft makes that answer far easier to write well every single time."}$lum$::jsonb, false),
  ($lum$df6860f8-ef3f-5391-816a-d47c7207fcbc$lum$::uuid, $lum$74da21a3-46b3-5d9b-a1bb-f6ca90aa103b$lum$::uuid, 5, $lum$multiple_choice$lum$, $lum${"stem":"According to the pattern across all three scenarios, what is the right order for a reply to an upset customer?","options":[{"id":"a","label":"Lay out the fix first, then mention the feeling only if there is room left at the end.","is_correct":false,"explanation":"Leading with the fix makes you sound like you are dodging the feeling. The pattern puts acknowledgment first, before the remedy."},{"id":"b","label":"Acknowledge first, take responsibility, then lay out the fix.","is_correct":true,"explanation":"Correct. That order matters for upset people: acknowledge the feeling, own the failure, then state the concrete remedy. The AI handles the shape and you handle the substance."},{"id":"c","label":"Acknowledge the feeling warmly and stop there, since the emotion is what the customer cares about most.","is_correct":false,"explanation":"Lead with the feeling and forget the fix and you sound hollow. The acknowledgment has to be followed by responsibility and a real resolution."},{"id":"d","label":"Open with an explanation of why the company was too busy to handle it sooner.","is_correct":false,"explanation":"Excuses about being busy are exactly what the prompts rule out. The structure is acknowledge, take responsibility without excuses, then the fix."}]}$lum$::jsonb, false),
  ($lum$ed3e032c-4ce2-5e37-8976-c06b1531059c$lum$::uuid, $lum$74da21a3-46b3-5d9b-a1bb-f6ca90aa103b$lum$::uuid, 6, $lum$reading$lum$, $lum${"markdown":"A few ways this goes wrong on the job, all of them avoidable once you know to watch for them.\n\nThe first is a data mistake, and it is the most serious. Do not paste a customer's personal details, account number, billing information, or the full ticket thread with their name and email into a public AI tool. When you are rushed, it is tempting to just copy the whole ticket and say \"write a reply to this.\" Don't. Describe the situation generically instead: \"a customer whose order arrived damaged,\" not the actual order number and address. Add the real specifics yourself, by hand, from your own systems after you have the draft. The customer trusted you with that information. A public tool is not part of that trust."}$lum$::jsonb, false),
  ($lum$26bd941e-0d0a-5437-a4bc-341f337a7177$lum$::uuid, $lum$74da21a3-46b3-5d9b-a1bb-f6ca90aa103b$lum$::uuid, 7, $lum$multiple_choice$lum$, $lum${"stem":"You are rushed and the fastest move feels like copying the whole ticket into a public AI tool and asking it to write a reply. Why is that the most serious mistake?","options":[{"id":"a","label":"It wastes time, because pasting a long ticket takes longer than describing the situation.","is_correct":false,"explanation":"Speed is not the issue here. The problem is exposing data the customer trusted you with, not how many seconds the paste takes."},{"id":"b","label":"The AI cannot read long tickets accurately, so it will miss details in the thread.","is_correct":false,"explanation":"The reading is not the concern named here. The serious mistake is putting personal data into a public tool at all, regardless of how well it parses."},{"id":"c","label":"It puts the customer's personal details into a public tool that is not part of the trust they placed in you; describe the situation generically and add real specifics yourself.","is_correct":true,"explanation":"Correct. Personal details, account numbers, billing information, and the full thread should never go into a public tool. Describe it generically and add the specifics by hand from your own systems."},{"id":"d","label":"The tool will automatically send the reply before you have a chance to review it.","is_correct":false,"explanation":"Drafting tools do not send your replies for you. The actual risk is the customer's data leaving your trusted systems, not an accidental send."}]}$lum$::jsonb, false),
  ($lum$dc727742-dfd5-541b-b6c0-3cf374def10e$lum$::uuid, $lum$74da21a3-46b3-5d9b-a1bb-f6ca90aa103b$lum$::uuid, 8, $lum$reading$lum$, $lum${"markdown":"The second mistake is sending the draft without really reading it. An AI reply can sound empathetic while being subtly generic, and this is the trap, because it reads fine on a quick skim. \"We understand how frustrating this must be\" is technically warm and completely hollow. A genuinely upset customer can tell when a response is templated at them rather than written to them. The double-charged subscriber who is scared about their money does not want a paragraph that could have been sent to anyone. They want to feel that someone actually saw their specific problem. So read every draft as that specific customer would read it. Cut anything that sounds scripted. Add a detail that proves you read their message. If the draft does not pass that test, it is not done.\n\nThe third mistake is treating the AI draft as authority. The model will confidently write \"your refund will be processed within three to five business days\" whether or not that matches your actual process. It might promise a remedy your policy does not allow, or commit to a timeframe you cannot hit. For the customer who was already burned by a broken callback promise, a second wrong promise is a disaster. The draft is a starting point for your words, not a ruling on your policy. You apply your own judgment and your real, current policy to every commitment in it. If the draft says something you cannot actually deliver, you change it before it goes out. The AI does not know your company's rules. You do, and the customer is holding you to them, not the tool.\n\nPut simply: keep their data out of the tool, never send a draft you have not read as the customer, and never let the draft commit you to something you cannot do. Get those three right and AI makes you faster without making you careless."}$lum$::jsonb, false),
  ($lum$f6db876a-a064-5a48-964c-95e34de42d4c$lum$::uuid, $lum$74da21a3-46b3-5d9b-a1bb-f6ca90aa103b$lum$::uuid, 9, $lum$fill_blank$lum$, $lum${"template":"When drafting an empathetic reply with AI, keep the customer's personal {{1}} out of any public tool and add it yourself afterward, and always check that every commitment in the draft matches your real {{2}} before you send it.","blanks":[{"id":"1","accept":["data","details","information","identifiers","info"],"ideal":"data"},{"id":"2","accept":["policy","policies","process","rules","procedures"],"ideal":"policy"}],"explanation":"Two non-negotiables: personal data never goes into a public tool (you add it by hand from your own systems), and every promise in the draft gets checked against your actual policy, because the AI does not know your company's rules and the customer is holding you, not the tool, to them."}$lum$::jsonb, false),
  ($lum$1ff92be0-e983-50f6-885b-de9022db989c$lum$::uuid, $lum$74da21a3-46b3-5d9b-a1bb-f6ca90aa103b$lum$::uuid, 10, $lum$before_after$lum$, $lum${"question":"A customer is furious their order came late and damaged. Which prompt gets you a reply that defuses instead of inflames?","before_prompt":"Write a reply to a customer complaining about a late and damaged order.","after_prompt":"Help me draft a reply to an upset customer. Situation, without identifying details: their order arrived about two weeks late and damaged, and they are understandably frustrated. What we can do: a full refund and a replacement shipped today at no cost. Draft a warm, genuinely apologetic response that acknowledges the frustration first, takes responsibility without excuses, then clearly lays out the refund and reshipment. Keep it concise and human, not corporate or scripted. I will add the customer's name and order specifics myself.","changes":["Gives the situation and the actual resolution, so the reply leads with a real fix instead of a vague apology.","Asks for acknowledgment first, ownership without excuses, then the concrete remedy, which is the right order for an upset customer.","Specifies a human, non-corporate tone so the reply does not read as scripted at the customer."]}$lum$::jsonb, true),
  ($lum$0ce11b0b-c454-5aa5-a491-2b0a705e1f0f$lum$::uuid, $lum$74da21a3-46b3-5d9b-a1bb-f6ca90aa103b$lum$::uuid, 11, $lum$multiple_choice$lum$, $lum${"stem":"You briefed the AI with the situation and your fix, and the draft came back warm and smooth. What is the most important thing to do before you send it?","options":[{"id":"a","label":"Send it as is, since it already sounds empathetic and the customer is waiting.","is_correct":false,"explanation":"Smooth and warm-sounding is not the same as fitting. A reply that reads as templated can deepen an upset customer's frustration, and the AI may have promised something your policy does not allow."},{"id":"b","label":"Make it longer so it feels more thorough and apologetic.","is_correct":false,"explanation":"Length is not the fix. Adding more generic apology makes it read more scripted, not more genuine. The goal is fit and a deliverable promise, not volume."},{"id":"c","label":"Read it as that specific customer would, cut anything that sounds scripted, add their real name and specifics, and confirm every commitment matches your actual policy.","is_correct":true,"explanation":"Correct. This is the part only you can do: tailor it to this person, strip the generic phrasing an upset customer would detect, and verify the promises against your real policy before it goes out."},{"id":"d","label":"Paste the full original ticket into the tool and ask it to personalize the reply for you.","is_correct":false,"explanation":"Never put the customer's personal data and full ticket into a public tool. You add the real name and specifics yourself, by hand, from your own systems."}]}$lum$::jsonb, false),
  ($lum$f2c94251-c7b5-5e78-ac81-e204c7d6f31a$lum$::uuid, $lum$74da21a3-46b3-5d9b-a1bb-f6ca90aa103b$lum$::uuid, 12, $lum$mini_project$lum$, $lum${"brief":"Find a real upset-customer message you need to answer, or one you handled recently, the kind where someone is angry about a late order, a billing error, or a promise that got dropped. Your job is to produce one send-ready reply that acknowledges first, takes responsibility, and lays out a fix you can actually deliver, using AI to get to calm, human language fast and your own judgment to make it fit and make it true.","parts":[{"id":"1","prompt":"Brief the AI with the situation in general terms, the actual resolution you can offer, and the tone you want, warm and human, not corporate, with no customer identifiers in the tool."},{"id":"2","prompt":"Read the draft as that specific customer would read it, cut anything that sounds scripted, and add the real name and order or account specifics from your own systems."},{"id":"3","prompt":"Check every commitment in the reply against your actual current policy, fix any promise you cannot keep, then send it and notice how much faster you reached a calm, clear reply than starting from the blank box while stressed."}]}$lum$::jsonb, false),
  ($lum$ae24ef26-319d-5281-855f-16f25423c1a3$lum$::uuid, $lum$e7e4a939-b1bb-585a-9f10-2facefabb209$lum$::uuid, 0, $lum$reading$lum$, $lum${"markdown":"A board report is not a table. The table is the easy part, because you already have the numbers and they live in your model. The hard, slow part is the narrative: turning a spreadsheet into a few paragraphs that tell the board what happened, why it matters, and what you are doing about it, in language a non-finance director can follow. That writing is where finance professionals lose whole afternoons, and it is exactly the kind of work AI is built to accelerate. The promise here is simple and worth saying plainly. You will keep doing the thinking. The AI will do the typing.\n\nPicture Maya, an FP&A analyst who has to produce the quarterly board narrative every three months. She knows the quarter cold. Renewals came in strong, a couple of deals slipped, and margin softened because the team pulled hiring forward from Q4. She can explain all of this out loud in two minutes. But every quarter she sits in front of a blank document and the two minutes of clear thinking turn into three hours of rewriting sentences until they sound board-appropriate. That gap, between knowing the story and writing the story, is precisely the gap AI closes. Maya is not short on understanding. She is short on prose."}$lum$::jsonb, false),
  ($lum$d70cda80-dac4-5dee-84bc-b48fd3924af7$lum$::uuid, $lum$e7e4a939-b1bb-585a-9f10-2facefabb209$lum$::uuid, 1, $lum$multiple_choice$lum$, $lum${"stem":"The lesson opens by saying 'You will keep doing the thinking. The AI will do the typing.' Based on Maya's situation, which part of her quarterly work is the AI actually meant to take off her plate?","options":[{"id":"a","label":"Deciding what the quarter means, since she only has two minutes of clarity and needs help interpreting it.","is_correct":false,"explanation":"The opposite is true. Maya already knows the quarter cold and can explain it in two minutes. Interpretation is the thinking she keeps, not the work she hands off."},{"id":"b","label":"The three hours of rewriting sentences until they sound board-appropriate, the gap between knowing the story and writing it.","is_correct":true,"explanation":"Correct. Maya is not short on understanding, she is short on prose. The AI absorbs the slow rewriting work while she keeps the thinking."},{"id":"c","label":"Pulling and reconciling the underlying numbers from her model, which is the slow part of the job.","is_correct":false,"explanation":"The numbers already live in her model and are described as the easy part. The slow part is the narrative, not the data pull."}]}$lum$::jsonb, false),
  ($lum$2fed2c45-fad1-5eff-8d49-59cc3485c84d$lum$::uuid, $lum$e7e4a939-b1bb-585a-9f10-2facefabb209$lum$::uuid, 2, $lum$reading$lum$, $lum${"markdown":"The order of operations is the whole discipline, so hold onto it. You verify the numbers first, against your source of truth, the close file, the system export, the reconciled model. Then you form your own read of what they mean, because the AI cannot tell you what the quarter means and must never try. Only then do you hand it the verified figures and your interpretation and ask it to write the narrative. The prompt Maya uses sounds like this. \"Here are our Q3 actuals against budget. Revenue was 12.4 million versus a 11.8 million plan. Gross margin was 61 percent versus 64 percent planned. The story is that revenue beat on strong renewals, and margin slipped because we pulled forward some hiring. Draft a one-page board narrative with a short summary, the key drivers, and the outlook, written for directors who are not finance specialists.\" Notice what she gave it. The exact numbers, and the meaning she already assigned to them.\n\nWhat comes back is a clean, structured draft built on her numbers and her judgment. She is not asking the AI what to think about the quarter. She is asking it to express, clearly and quickly, what she already concluded. That distinction is the entire game, and it is the line you must never let blur. The moment you ask the model \"is this a good quarter?\" or \"what should the board take away?\" you have handed it the one job that is yours. It will answer confidently, and it will sometimes be wrong, because it does not know your business, your covenants, or the conversation the board had last quarter."}$lum$::jsonb, false),
  ($lum$f2f91f28-3ce8-5e94-b8e9-015a96544c6e$lum$::uuid, $lum$e7e4a939-b1bb-585a-9f10-2facefabb209$lum$::uuid, 3, $lum$multiple_choice$lum$, $lum${"stem":"Maya, an FP&A analyst, is about to draft her quarterly board narrative with AI. What does she do BEFORE she opens the AI tool?","options":[{"id":"a","label":"Verify her figures against the close file and decide herself what the quarter means, then bring both to the AI.","is_correct":true,"explanation":"Correct. Verification and interpretation are the human's job and must happen first. The AI only gets involved once the numbers are confirmed and Maya has formed her own read of them."},{"id":"b","label":"Paste her raw system export into the AI and ask it to figure out what the headline story is.","is_correct":false,"explanation":"This hands the AI the one job only Maya can do. It does not know her business and may misread renewals strength as a warning sign, or invent a story that sounds clean but is wrong."},{"id":"c","label":"Ask the AI to write the narrative first, then check the numbers against her model afterward to save time.","is_correct":false,"explanation":"Drafting before verifying means the prose may be built on unconfirmed figures. If a number is wrong, the polished narrative just makes the error more convincing. Verify first, always."}]}$lum$::jsonb, false),
  ($lum$6e8a5f8d-d8cf-5a8f-9770-e104664089f0$lum$::uuid, $lum$e7e4a939-b1bb-585a-9f10-2facefabb209$lum$::uuid, 4, $lum$reading$lum$, $lum${"markdown":"Consider a second person, Devin, a controller writing variance commentary for the monthly package. His task is narrower than Maya's but the principle is identical. He has the variances in front of him, operating expense ran 340 thousand over budget, and he knows why, a one-time legal settlement plus higher cloud costs from a usage spike. The verified number is his. The explanation is his. What he hands the AI is both of those, and what he asks for is plain, neutral commentary that a director can read without a finance degree. He does not ask the AI to guess why the variance happened. If he did, it would invent a plausible-sounding reason, and a plausible-sounding wrong reason in a board document is far more dangerous than a clumsy sentence.\n\nThere is a reason this matters so much in finance specifically. A board narrative is a representation. People make decisions on it. If the AI invents a figure, rounds something in a flattering direction, or describes a 3 point margin decline as a \"modest softening\" when your board would call it a problem, the document now misrepresents reality, and your name is on it. So the rule is firm: the AI shapes language, never numbers, and never strategic meaning. Every figure in the final draft must trace back to a number you verified. If a number appears that you did not provide, that is a red flag, not a nice surprise, and you delete it and ask where it came from.\n\nThink of the AI as a fast, tireless writing partner who is excellent at structure and tone and completely ignorant of your company. It can take \"revenue beat, margin slipped on timing, cash is fine\" and turn it into three tight, readable paragraphs in seconds. It cannot tell you whether that is good news. You bring the figures and the judgment. It brings the words. Used that way, it gives you back the afternoon and takes nothing that should stay yours."}$lum$::jsonb, false),
  ($lum$39de41d8-95ad-55b1-9313-6e6750ab54f9$lum$::uuid, $lum$e7e4a939-b1bb-585a-9f10-2facefabb209$lum$::uuid, 5, $lum$multiple_choice$lum$, $lum${"stem":"Devin, a controller, knows the operating-expense overspend came from a one-time legal settlement plus a cloud usage spike. Why does the lesson insist he hand the AI that explanation rather than ask the AI to figure out the cause?","options":[{"id":"a","label":"Because the AI would refuse to write commentary without being told the cause first.","is_correct":false,"explanation":"The AI will happily write a cause if asked. That is exactly the danger: it produces something fluent whether or not it knows the truth."},{"id":"b","label":"Because asking the AI to guess slows the draft down and Devin is trying to save time.","is_correct":false,"explanation":"Speed is not the concern here. Even a fast wrong answer is the problem, because the risk is accuracy and accountability, not minutes saved."},{"id":"c","label":"Because if asked to guess, the AI would invent a plausible-sounding reason, and a plausible-sounding wrong reason in a board document is more dangerous than a clumsy sentence.","is_correct":true,"explanation":"Correct. The verified number and its explanation are Devin's to own. A confident, invented cause reads as truth and misleads the board far more than awkward wording ever would."}]}$lum$::jsonb, false),
  ($lum$79fe8dfc-e40b-5098-8153-a824ca598a0e$lum$::uuid, $lum$e7e4a939-b1bb-585a-9f10-2facefabb209$lum$::uuid, 6, $lum$reading$lum$, $lum${"markdown":"The failures in this work are quiet, which is what makes them dangerous. Nothing crashes. You get back a fluent, confident draft, and fluency reads like correctness even when it is not. Here is where it goes wrong, and how each finance professional catches it.\n\nThe first failure is the invented figure. You give the AI revenue and margin, and the draft comes back mentioning a \"customer count of roughly 1,200\" or a \"year over year growth of 18 percent\" that you never provided. The model filled a gap with a plausible number because prose flows better with specifics. Devin, the controller, learned to scan every figure in the draft and ask one question: did I give it this number? If the answer is no, it gets deleted, no matter how reasonable it looks. A made-up number in a board document is not a typo, it is a misrepresentation.\n\nThe second failure is softened truth. A finance manager named Priya was preparing an executive summary for the leadership team after a weak quarter. She told the AI margin had \"declined significantly,\" and the draft rendered it as \"experienced some normalization.\" That is not a summary, that is a euphemism, and it would have let leadership walk into the meeting underprepared. The model is trained to sound smooth and reassuring, so it sands the edges off bad news unless you stop it. Priya now reads every draft asking: does this say the hard thing as plainly as I would say it out loud? If the AI made a real problem sound comfortable, she puts the sharpness back."}$lum$::jsonb, false),
  ($lum$3cb74d03-5a45-5000-9269-788bbb94c028$lum$::uuid, $lum$e7e4a939-b1bb-585a-9f10-2facefabb209$lum$::uuid, 7, $lum$fill_blank$lum$, $lum${"template":"When the AI adds a figure you never gave it, like a customer count of roughly 1,200, the right move is to {{1}} it, because in a board document an invented number is a {{2}}, not a harmless detail.","blanks":[{"id":"1","accept":["delete","remove","cut","strike"],"ideal":"delete"},{"id":"2","accept":["misrepresentation","fabrication","lie","falsehood"],"ideal":"misrepresentation"}],"explanation":"Devin's rule is to scan every figure and ask whether he provided it. Any number he did not give gets deleted, no matter how plausible, because a made-up figure in a board document is a misrepresentation rather than a typo."}$lum$::jsonb, false),
  ($lum$1c2012be-08f8-5e7e-8144-fac1bd5a1198$lum$::uuid, $lum$e7e4a939-b1bb-585a-9f10-2facefabb209$lum$::uuid, 8, $lum$reading$lum$, $lum${"markdown":"The third failure is the AI sneaking in strategic interpretation. You ask for a narrative and the draft adds a sentence like \"this positions the company well for an aggressive Q4 expansion.\" You never said that. That is the model guessing at strategy, and strategy is not its call. Delete the editorializing and keep only the meaning you actually own.\n\nThe fourth failure is putting confidential or material non-public information into a public tool. Maya almost pasted live, unannounced quarterly figures into a consumer chatbot to save a few minutes. The fix is policy, not cleverness: use your company's approved enterprise tool for real figures, or describe the shape of the story without the live numbers and add the real numbers yourself in the final document.\n\nThe pattern across all four is the same. The AI is excellent at language and indifferent to truth. It does not know which number is right, which problem is real, or which strategy is yours. Your edit pass is not optional polish, it is the control that keeps the document honest. Read the draft as the person accountable for it, because that is exactly who you are."}$lum$::jsonb, false),
  ($lum$d61a3bf9-75fa-5026-b938-2387b46eced1$lum$::uuid, $lum$e7e4a939-b1bb-585a-9f10-2facefabb209$lum$::uuid, 9, $lum$multiple_choice$lum$, $lum${"stem":"Maya almost pasted live, unannounced quarterly figures into a consumer chatbot to save a few minutes. According to the lesson, what is the correct fix for this fourth failure?","options":[{"id":"a","label":"Use the company's approved enterprise tool for real figures, or describe the shape of the story without live numbers and add the real numbers herself in the final document.","is_correct":true,"explanation":"Correct. The lesson calls this a matter of policy, not cleverness. Either use the sanctioned tool, or keep the live figures out of the public tool and insert them yourself afterward."},{"id":"b","label":"Paste the figures but ask the chatbot to keep them private and not store them.","is_correct":false,"explanation":"A public tool's promise about storage does not protect material non-public information. The lesson treats this as a policy boundary, not something a prompt instruction can solve."},{"id":"c","label":"Round the figures so they are no longer exact, then paste the approximate versions into the consumer chatbot.","is_correct":false,"explanation":"Distorting the numbers introduces inaccuracy and still leaks the shape of unannounced results. The fix is to keep real figures out of the public tool entirely, not to fuzz them."}]}$lum$::jsonb, false),
  ($lum$12d08030-c6d3-55ba-8355-a665321695c1$lum$::uuid, $lum$e7e4a939-b1bb-585a-9f10-2facefabb209$lum$::uuid, 10, $lum$try_it_live$lum$, $lum${"instructions":"Hand the AI your verified figures and your own honest read of them, then ask for a board-ready narrative. Or use this sample: Q3 revenue was 12.4 million versus an 11.8 million plan, gross margin was 61 percent versus 64 percent planned, the revenue beat came from strong renewals, the margin slipped because hiring was pulled forward from Q4, and cash runway is comfortable.","system_prompt":"You are a finance communications partner helping a finance professional write a board narrative. The user supplies verified figures and their own interpretation of what the numbers mean. Express their interpretation clearly. Never invent analysis and never add any figure the user did not provide. Use only the numbers given to you. Produce a one-page structure: a two to three sentence summary, a short key drivers section, and a brief outlook section, written for intelligent directors who are not finance specialists. Keep it honest and plain. If the user's narrative glosses over a weak spot, surface it neutrally rather than smoothing it away. Do not add strategic conclusions the user did not state. No jargon without a plain-language gloss. No em dashes.","ideal_output":"Here is a one-page board narrative built on the figures and read you gave me. I used only your numbers and added none of my own.\n\nSummary: Q3 revenue came in at 12.4 million against an 11.8 million plan, driven by stronger than expected renewals. Gross margin was 61 percent versus a planned 64 percent, the result of a deliberate decision to pull hiring forward from Q4. Cash runway remains comfortable.\n\nKey drivers: The revenue beat was concentrated in renewals rather than new logos, which points to retention strength and is worth watching as a growth signal. The 3 point margin movement was a timing choice and not a cost overrun, because the new hires were planned for Q4 and brought forward.\n\nOutlook: We expect margin to move back toward plan as the new hires reach productivity, assuming renewal strength holds. One item for the board to note: because the beat came from renewals, new-logo growth is the metric to track next quarter.\n\nWant me to tighten this to half a page, or hold the wording while you confirm the figures against your close file?","input_placeholder":"Paste your verified figures and your own read of what the quarter means..."}$lum$::jsonb, true),
  ($lum$700199ac-44f9-558e-a4bd-c21c10eb007e$lum$::uuid, $lum$e7e4a939-b1bb-585a-9f10-2facefabb209$lum$::uuid, 11, $lum$multiple_choice$lum$, $lum${"stem":"Devin, a controller, gets back a variance-commentary draft that includes the line: 'this overspend positions us for an aggressive expansion next quarter.' He never said anything about expansion. What is the right call?","options":[{"id":"a","label":"Keep it, because the AI may have spotted a strategic angle he missed and the board will appreciate the forward view.","is_correct":false,"explanation":"The AI does not know Devin's strategy and cannot spot a real angle in his business. This is the model guessing at meaning it was never given, and trusting that guess in a board document is exactly the risk to avoid."},{"id":"b","label":"Delete the line, because strategic interpretation he did not provide is the AI overstepping, and that judgment stays with the human.","is_correct":true,"explanation":"Correct. The AI shapes language, not strategy. Any conclusion Devin did not state himself is editorializing he does not own, so he removes it and keeps only the meaning he actually verified."},{"id":"c","label":"Ask the AI to expand the expansion idea into a full paragraph so the board has more context.","is_correct":false,"explanation":"This doubles down on a conclusion that originated with the model, not with Devin. Building more narrative on an unowned strategic claim makes the document less honest, not more useful."}]}$lum$::jsonb, false),
  ($lum$c1667f7e-b6f9-58a6-9f2b-28c36ff97bf1$lum$::uuid, $lum$e7e4a939-b1bb-585a-9f10-2facefabb209$lum$::uuid, 12, $lum$mini_project$lum$, $lum${"brief":"Take a recurring report you actually write, a board update, a monthly close summary, or a variance commentary, and run it through the full discipline once. Pull your verified figures from your source of truth and confirm them. Write two or three rough sentences of your own honest read: what happened, why, and what is next. Hand the AI the figures and your read, ask for a structured narrative aimed at your real audience, then edit it as the person accountable for the document.\n\nWhen you edit, run these three checks before you accept a single word.","parts":[{"id":"1","prompt":"Trace every figure in the draft back to a number you provided, and delete anything the AI added on its own."},{"id":"2","prompt":"Read each sentence about a problem and ask whether it says the hard thing as plainly as you would out loud, then restore any sharpness the model smoothed away."},{"id":"3","prompt":"Confirm the draft contains no strategic conclusion you did not state yourself, and cut any meaning the AI invented."}]}$lum$::jsonb, false),
  ($lum$c5670640-fa56-55ef-bd81-81d445f91633$lum$::uuid, $lum$3b249ae2-9972-55a7-8893-0d7ad7b2a3fb$lum$::uuid, 0, $lum$reading$lum$, $lum${"markdown":"Think about the messages that leave your outbox in a normal month. An onboarding welcome to a new hire. A benefits-enrollment reminder when the window opens. A policy-change announcement when the handbook updates. A return-to-office notice. Every so often, a sensitive announcement that you draft slowly and carefully. If you line these up, you notice something useful: most of them are repeatable in shape but personal in detail. The skeleton of a benefits reminder is the same every year. Only the dates, the plan year, the enrollment link, and the person's name change. That gap between what stays the same and what changes is exactly where AI earns its keep.\n\nThe problem with writing each message from scratch is not only that it is slow, though it is slow. The bigger cost is inconsistency. When you write every onboarding welcome a little differently, new hires get a slightly different first impression depending on who sent it and how rushed that day was. When two policy announcements describe the same rule in different words, employees notice, and sometimes the two versions quietly contradict each other. An inconsistent employee experience is not a small thing. It is the difference between a company that feels organized and one that feels like it is improvising. Templates fix both problems at once: they make routine communication fast, and they make it consistent."}$lum$::jsonb, false),
  ($lum$7621e387-fef0-5e01-9407-8a37beb2cf8d$lum$::uuid, $lum$3b249ae2-9972-55a7-8893-0d7ad7b2a3fb$lum$::uuid, 1, $lum$multiple_choice$lum$, $lum${"stem":"According to this opening, what is the deeper cost of writing every routine HR message from scratch, beyond the time it takes?","options":[{"id":"a","label":"Messages become too long, because writing freehand encourages overexplaining.","is_correct":false,"explanation":"Length is not the concern raised here. The passage names inconsistency as the bigger cost, not verbosity."},{"id":"b","label":"Inconsistency, because differently worded welcomes and announcements make the company feel like it is improvising rather than organized.","is_correct":true,"explanation":"Correct. The passage states the bigger cost is inconsistency, which makes the employee experience feel improvised rather than organized, and that templates fix both speed and consistency at once."},{"id":"c","label":"Legal exposure, because every freehand message must be cleared by counsel before sending.","is_correct":false,"explanation":"The passage does not raise legal review as the cost. Its point is that inconsistency, not legal risk, is what makes from-scratch writing expensive."},{"id":"d","label":"Nothing meaningful, since the only real downside is the few extra minutes each message takes.","is_correct":false,"explanation":"This contradicts the passage, which explicitly says the bigger cost goes beyond slowness and is inconsistency."}]}$lum$::jsonb, false),
  ($lum$a4396069-ac1d-5fa1-ae98-3166074e99bf$lum$::uuid, $lum$3b249ae2-9972-55a7-8893-0d7ad7b2a3fb$lum$::uuid, 2, $lum$reading$lum$, $lum${"markdown":"The move that makes this work is to ask AI for reusable STRUCTURES, not one-off messages. There is a real difference. If you ask for \"an email reminding people that benefits enrollment closes Friday,\" you get a single finished message about this Friday, useless next year. If you ask for \"a reusable template for a benefits-enrollment-window reminder, with clear bracketed placeholders for everything that changes, a warm and plain tone, and short enough that people actually read it,\" you get something you can use every year for the rest of your career. A good template has three qualities. It has obvious blanks, written as bracketed placeholders like [employee name] and [enrollment deadline], so anyone can see at a glance what needs filling in. It has a tone you chose deliberately, because tone is a decision, not an accident. And it has a reusable structure you do not have to rebuild each time. Picture an HR generalist who sends benefits reminders every single year. Once she has a strong template, that yearly task drops from a blank-page chore to a five-minute fill-in-the-blanks job."}$lum$::jsonb, false),
  ($lum$927b02b6-3757-50e1-bfc6-c77644cc1405$lum$::uuid, $lum$3b249ae2-9972-55a7-8893-0d7ad7b2a3fb$lum$::uuid, 3, $lum$multiple_choice$lum$, $lum${"stem":"An HR generalist asks AI: 'Write an email telling staff that open enrollment closes this Friday, December 12.' What is the main weakness of this request for someone building a template library?","options":[{"id":"a","label":"It produces a single finished message about one specific date, so it cannot be reused next year instead of a generic reusable structure.","is_correct":true,"explanation":"Correct. The request asks for a one-off message, not a reusable STRUCTURE. A template needs bracketed placeholders like [enrollment deadline] so it works on every future send, not just this December."},{"id":"b","label":"The tone will automatically be too formal for a benefits reminder.","is_correct":false,"explanation":"Tone is not the core issue here, and it was not even specified. The real problem is that the request asks for a single dated message rather than a reusable template with placeholders."},{"id":"c","label":"AI cannot write about benefits topics accurately at all.","is_correct":false,"explanation":"AI can draft a perfectly good benefits-reminder structure. The weakness is in how the request is framed, asking for one finished email rather than a reusable template."}]}$lum$::jsonb, false),
  ($lum$0bacf587-31c4-551b-b4dc-9a884b4b2eb2$lum$::uuid, $lum$3b249ae2-9972-55a7-8893-0d7ad7b2a3fb$lum$::uuid, 4, $lum$reading$lum$, $lum${"markdown":"The discipline that keeps this safe lives entirely in the placeholders and the personalization. The template is the 80 percent that is the same on every send. The 20 percent that changes, the names, the dates, the specific situation, is yours to fill in, and you fill it in from your real records. This is the rule worth tattooing on the inside of your eyelids: you never paste employee data into the AI tool to generate the template. The structure is generic on purpose. It says [employee name], not Maria Santos. It says [start date], not March 3rd. Keeping it generic is what makes it safe to draft, store, and reuse, because nothing private ever touched the tool. A people-ops coordinator standardizing onboarding messages across the company should build one clean, generic welcome template and then personalize each send from the HRIS, never the other way around. The template lives in the tool's world, generic and reusable. The real details live in your systems, private and accurate. You bridge the two by hand at send time.\n\nNow the part that takes judgment, because not every message belongs in a template library in the same way. Templates are perfect for routine, informational messages. They are only a STARTING POINT, not a script, for emotionally weighted ones. Layoffs, performance concerns, news that touches someone's personal circumstances: in these moments a templated tone reads as cold exactly when warmth matters most. Imagine an HRBP who is about to reuse a generic template for a layoff notice because it is faster. Faster, yes, and also a mistake, because the person reading it can feel boilerplate, and feeling like a form letter at the worst moment of their work life is its own small cruelty. For these messages, let the template give you structure and remind you what to cover, then personalize heavily so the human is unmistakable.\n\nThe second caution is quieter but just as important: review every template for accuracy and tone before it joins your library. A template is a force multiplier, and multipliers work in both directions. A polished, correct template repeated fifty times saves you enormous effort. A template with a wrong date format, an outdated policy reference, or one phrase that lands a little cold repeats that exact error fifty times before anyone catches it. Get the base right once, with real attention, because that attention pays off on every future send. Then personalize each message, and reserve your genuine human focus for the communications that truly need it. That is the whole craft: build the 80 percent carefully, fill the 20 percent from your own records, and know which messages deserve more than a template can give."}$lum$::jsonb, false),
  ($lum$7ce52538-ce30-5bd5-8b83-f20ab98938c2$lum$::uuid, $lum$3b249ae2-9972-55a7-8893-0d7ad7b2a3fb$lum$::uuid, 5, $lum$multiple_choice$lum$, $lum${"stem":"Where, according to this passage, should the real names, dates, and personal details actually be filled in?","options":[{"id":"a","label":"Inside the AI tool, by pasting employee records so the template comes back already personalized.","is_correct":false,"explanation":"This is exactly what the passage forbids. You never paste employee data into the AI tool; the structure stays generic with placeholders like [employee name]."},{"id":"b","label":"By hand at send time, from your own systems and records, while the template itself stays generic in the tool.","is_correct":true,"explanation":"Correct. The template lives generic in the tool's world, the real details live in your systems, and you bridge the two by hand at send time, for example personalizing from the HRIS."},{"id":"c","label":"Once, baked permanently into a single named version of the template so it never has to be filled again.","is_correct":false,"explanation":"A template is meant to stay reusable and generic with placeholders, not hard-coded to one person. The real details are filled fresh from your records on each send."},{"id":"d","label":"It does not matter, because emotionally weighted messages can be sent straight from the template as a script.","is_correct":false,"explanation":"The passage warns the opposite: sensitive messages are only a starting point, not a script, and a templated tone reads as cold when warmth matters most."}]}$lum$::jsonb, false),
  ($lum$78d81e62-51bb-50b8-b4e8-e98e29532601$lum$::uuid, $lum$3b249ae2-9972-55a7-8893-0d7ad7b2a3fb$lum$::uuid, 6, $lum$reading$lum$, $lum${"markdown":"The idea of a template library is simple, so the ways it goes wrong are usually about discipline slipping, not about misunderstanding the concept. Here are the failures that show up most often, and how to avoid each one.\n\nThe first and most serious mistake is pasting real employee data into the tool to \"make the template better.\" It feels harmless. You think, if I give it Maria's actual start date and team, it will write something more specific. But the moment you do that, you have handed private information to an outside tool for no good reason, and you have made a template that is secretly about one person instead of being a clean generic structure. The whole point is that the template says [employee name] and [start date]. Keep it generic in the tool, and fill the real details from your HRIS at send time. If you ever feel tempted to paste real data, that is your signal that you are personalizing in the wrong place.\n\nThe second mistake is shipping a template straight from the AI into your library without reading it as if you were the employee receiving it. AI drafts are confident and polished, which is exactly why an error hides well inside them. A wrong default-outcome description in a benefits reminder, an outdated policy name, a date written in a confusing format: any of these, repeated across fifty sends, becomes fifty small problems. The fix costs almost nothing. Read every template once, slowly, checking accuracy and tone, before it earns a place in the library. The HR generalist who reviews her benefits template carefully in year one saves herself five years of repeating the same buried error."}$lum$::jsonb, false),
  ($lum$958a22fd-4ac0-5760-a294-7cc83407e8f5$lum$::uuid, $lum$3b249ae2-9972-55a7-8893-0d7ad7b2a3fb$lum$::uuid, 7, $lum$multiple_choice$lum$, $lum${"stem":"A people-ops coordinator wants AI to personalize an onboarding welcome for a specific new hire, so she pastes the hire's name, start date, manager, and home address into the chat. What went wrong?","options":[{"id":"a","label":"Nothing; giving real details produces a more useful template.","is_correct":false,"explanation":"This is the exact trap. A template is supposed to stay generic with bracketed placeholders. Pasting real data does not make the library better, it exposes private information needlessly."},{"id":"b","label":"She put real employee data into an outside tool when the template should stay generic, with personalization done from her own records at send time.","is_correct":true,"explanation":"Correct. The structure should read [employee name] and [start date]. Real details get filled from the HRIS by hand at send time, never pasted into the tool to generate the template."},{"id":"c","label":"She should have asked for the message in a more formal tone first.","is_correct":false,"explanation":"Tone is not the problem. The problem is that private employee data was pasted into the tool, which breaks the rule that templates stay generic and safe to reuse."}]}$lum$::jsonb, false),
  ($lum$7811d776-00a0-5df1-961b-9b244b9d29f9$lum$::uuid, $lum$3b249ae2-9972-55a7-8893-0d7ad7b2a3fb$lum$::uuid, 8, $lum$reading$lum$, $lum${"markdown":"The third mistake is treating every message type as equally template-friendly. Routine and informational, like enrollment reminders and return-to-office notices, are ideal for send-as-is templates once personalized. Emotionally weighted messages are not. The HRBP who reuses a layoff template as a script, changing only the name, sends something that reads as a form letter at the moment a person most needs to feel seen. The lesson is not \"never template sensitive messages.\" It is \"mark them clearly as personalize-heavily starting points,\" so the structure helps you without flattening the humanity out of the message.\n\nThe last mistake is subtler: building too many slightly different templates for the same situation. If three coordinators each generate their own onboarding welcome, you are back to the inconsistency you were trying to escape. Pick one strong version per message type, agree on it, and reuse it. One good template beats five competing ones. Consistency is the prize, and it only shows up when the library has a single clear answer for each routine message you send."}$lum$::jsonb, false),
  ($lum$78ce0b4d-94f4-5df3-a739-c5f491abc621$lum$::uuid, $lum$3b249ae2-9972-55a7-8893-0d7ad7b2a3fb$lum$::uuid, 9, $lum$multiple_choice$lum$, $lum${"stem":"Three coordinators each generate their own slightly different onboarding welcome. According to this passage, why is that a mistake?","options":[{"id":"a","label":"It wastes AI credits, because generating three drafts costs three times as much as generating one.","is_correct":false,"explanation":"Cost of generation is not the concern. The passage's point is about consistency, not the expense of producing drafts."},{"id":"b","label":"It recreates the very inconsistency templates were meant to escape, when one strong agreed-upon version per message type beats five competing ones.","is_correct":true,"explanation":"Correct. The passage warns that too many slightly different templates for the same situation put you back into inconsistency; you should pick one strong version per message type and reuse it."},{"id":"c","label":"It is fine, because giving employees variety in their welcome messages keeps the experience fresh.","is_correct":false,"explanation":"The passage argues the opposite: consistency is the prize, and competing versions undermine it rather than helping."},{"id":"d","label":"It violates the rule against pasting real employee data into the tool.","is_correct":false,"explanation":"That rule is about a different mistake. The issue here is duplication and inconsistency from too many competing templates, not data handling."}]}$lum$::jsonb, false),
  ($lum$ad536f4c-0280-5f94-9227-13dd58174392$lum$::uuid, $lum$3b249ae2-9972-55a7-8893-0d7ad7b2a3fb$lum$::uuid, 10, $lum$try_it_live$lum$, $lum${"instructions":"Ask the AI for a reusable TEMPLATE, not a finished one-off message. Name the message type, the tone you want, and tell it to use clear bracketed placeholders for anything that changes per send. Try the sample: a benefits-enrollment-window reminder, warm and plain, short enough that people actually read it. Or pick your own routine message, like an onboarding welcome or a return-to-office notice.","system_prompt":"You are an HR communications partner who builds reusable employee-message templates. When asked for a template, produce a reusable STRUCTURE, not a one-off message. Mark every detail that changes per send as a clear bracketed placeholder, for example [employee name], [enrollment deadline], [enrollment link], [HR contact]. Use the tone the user specifies and keep messages short and readable. Never ask for or include real employee data. The template must stay generic by design so the user can personalize it from their own records at send time. If the user asks for an emotionally sensitive message type such as a layoff, a performance concern, or news touching personal circumstances, clearly flag that the template is a personalize-heavily starting point and not a script to send as is. No em dashes.","ideal_output":"Here is a reusable benefits-enrollment reminder template. Everything in brackets is a placeholder you fill from your own records before sending, so the structure stays generic and safe to reuse every year.\n\nSubject: Action needed: benefits enrollment closes [enrollment deadline]\n\nHi [employee name],\n\nA quick reminder that our benefits enrollment window is open and closes on [enrollment deadline]. This is your chance to review or change your coverage for [plan year].\n\nWhat to do: log in at [enrollment link], review your options, and confirm your selections before [enrollment deadline]. If you take no action, [describe default outcome].\n\nQuestions? Reach [HR contact name] at [contact method] and we are glad to walk through your options.\n\nThanks,\n[sender name]\n\nThis message is purely informational, so it is safe to send as is once you have filled in the placeholders. Want me to build matching templates for the confirmation message and a final-day reminder so the whole set stays consistent?","input_placeholder":"Name the message type, the tone you want, and ask for bracketed placeholders for anything that changes..."}$lum$::jsonb, true),
  ($lum$01d529e3-119e-5d3f-af06-cc498b73711e$lum$::uuid, $lum$3b249ae2-9972-55a7-8893-0d7ad7b2a3fb$lum$::uuid, 11, $lum$multiple_choice$lum$, $lum${"stem":"An HRBP has a clean, reviewed template library and now needs to send individual layoff notifications. The fastest option is to reuse the template as a script, changing only each person's name. What does this lesson advise?","options":[{"id":"a","label":"Send the template as is, because consistency matters most precisely in sensitive situations.","is_correct":false,"explanation":"Consistency serves routine messages. A sensitive message sent as boilerplate reads as a cold form letter at the worst possible moment, which deepens harm rather than reducing it."},{"id":"b","label":"Abandon the template entirely and write every word from scratch with no structure.","is_correct":false,"explanation":"That overcorrects. The structure is still useful for reminding you what to cover. The point is to personalize heavily on top of it, not to throw it away."},{"id":"c","label":"Treat the template as a personalize-heavily starting point, not a script, because a templated tone reads as cold exactly where warmth and human attention matter most.","is_correct":true,"explanation":"Correct. Templates fit routine informational messages. For emotionally weighted communication, the structure is only a base, and the message needs real human attention so it does not feel like boilerplate when that is most harmful."}]}$lum$::jsonb, false),
  ($lum$30064823-26f1-569a-9c01-0a41506bbb7d$lum$::uuid, $lum$3b249ae2-9972-55a7-8893-0d7ad7b2a3fb$lum$::uuid, 12, $lum$mini_project$lum$, $lum${"brief":"Build the first shelf of your own template library. List the five or six messages you send most often, ranging from routine reminders to the occasional sensitive announcement, then use AI to draft reusable structures for the routine ones and mark the sensitive ones clearly. Keep every template generic, with bracketed placeholders and no real employee data anywhere in the tool, and read each one slowly for accuracy and tone before it earns a place in your library.","parts":[{"id":"1","prompt":"Draft three reusable templates for routine messages (for example a benefits reminder, an onboarding welcome, and a return-to-office notice), each with clear bracketed placeholders and a tone you chose on purpose."},{"id":"2","prompt":"Review each template as if you were the employee receiving it, fixing any wrong date format, outdated reference, or phrase that lands cold, because an error in the template repeats on every future send."},{"id":"3","prompt":"Identify one emotionally weighted message on your list and label it a personalize-heavily starting point, not a send-as-is script, so future-you remembers to add real warmth and human attention."}]}$lum$::jsonb, false),
  ($lum$4c372d88-bb30-5eed-8949-6360f5a98126$lum$::uuid, $lum$083f1118-db9a-5a34-b410-0e78c3a43cd2$lum$::uuid, 0, $lum$reading$lum$, $lum${"markdown":"Health literacy is one of the quietest causes of readmission. The Joint Commission has estimated that low health literacy contributes to up to 80 percent of medical errors related to misunderstood instructions. We hand patients paperwork written in language built for charts and EMR fields, not for a kitchen table at 10 pm when someone is tired and scared and trying to understand what they are supposed to do next.\n\nThe problem is not that clinicians write poorly. It is that clinical language serves a different audience than the patient. \"Amoxicillin 500 mg PO q8h x10d, RTC ED for fever exceeding 101F, worsening erythema, or purulent drainage\" is precise. A nurse or a physician reads it in seconds. But a patient with a 6th-grade reading level, or a patient whose first language is not English, or a patient who just heard a scary diagnosis thirty minutes ago may read that sentence and walk out not knowing what PO means, what erythema looks like, or how to measure a fever at home.\n\nThis is where AI-assisted rewriting earns its place in clinical work. Clear plain-language rewriting is something current AI tools do reliably and quickly, and the time savings matter most in the busiest moments of a shift."}$lum$::jsonb, false),
  ($lum$5ea27296-5e10-575d-8874-78e2e1d8e9b2$lum$::uuid, $lum$083f1118-db9a-5a34-b410-0e78c3a43cd2$lum$::uuid, 1, $lum$multiple_choice$lum$, $lum${"stem":"According to the reading, what is the root reason patients fail to understand discharge paperwork?","options":[{"id":"a","label":"Clinicians are careless and write poorly.","is_correct":false,"explanation":"The reading explicitly says the problem is not that clinicians write poorly. The mismatch is about audience, not writing skill."},{"id":"b","label":"Patients do not pay attention when they are discharged.","is_correct":false,"explanation":"The reading does not blame patient attention. It points to the language itself being built for charts and EMR fields rather than for the patient."},{"id":"c","label":"Clinical language serves a different audience than the patient: it is precise for clinicians but opaque for someone reading at a 6th-grade level or in a second language.","is_correct":true,"explanation":"Correct. The reading states clinical language serves a different audience than the patient, which is why a precise note like the amoxicillin example reads in seconds to a clinician but leaves the patient lost."},{"id":"d","label":"Discharge paperwork is always too long for anyone to read.","is_correct":false,"explanation":"Length is not the cause the reading identifies. The issue is the vocabulary and audience mismatch, not the page count."}]}$lum$::jsonb, false),
  ($lum$562b4f62-4cd0-5653-ba94-571b67230f46$lum$::uuid, $lum$083f1118-db9a-5a34-b410-0e78c3a43cd2$lum$::uuid, 2, $lum$reading$lum$, $lum${"markdown":"**The core prompt structure**\n\nA plain-language rewrite prompt has three parts: what to rewrite, how to rewrite it, and what never to touch. Here is a template you can adapt:\n\n\"Rewrite these discharge instructions in plain language at about a 6th-grade reading level. Keep every medical instruction exactly accurate, especially doses, timing, and warning signs. Use short sentences and everyday words. Do not remove any safety information. Do not add any new advice.\"\n\nThe last two constraints are the load-bearing ones. Do not remove safety information means the AI cannot shorten instructions by leaving out a red flag. Do not add new advice means the AI cannot fill in what it thinks is helpful general health guidance. You wrote the clinical instructions. The AI only changes how those instructions read.\n\n**Clinical example 1: A post-procedure antibiotic course**\n\nA patient is discharged after incision and drainage of a skin abscess. The chart note reads: \"Amoxicillin 500 mg PO every 8 hours for 10 days. Return to ED if fever over 101 degrees F, increasing redness around wound, or purulent drainage from site.\"\n\nRun that through the prompt above and the output should read something like: \"Take one amoxicillin pill (500 mg) by mouth every 8 hours. Take it for 10 full days, even if you feel better. Come back to the emergency room right away if you have any of these: a fever over 101 degrees, redness around the wound that is getting worse or spreading, or any pus or cloudy fluid leaking from the wound.\"\n\nEvery piece of the original is still there. The dose is 500 mg. The interval is every 8 hours. The duration is 10 days. The return criteria are all three: fever threshold, worsening erythema described as spreading redness, and purulent drainage described as pus or cloudy fluid. The vocabulary changed. The instructions did not."}$lum$::jsonb, false),
  ($lum$e92e00aa-9713-56c6-addb-89da65e6f839$lum$::uuid, $lum$083f1118-db9a-5a34-b410-0e78c3a43cd2$lum$::uuid, 3, $lum$multiple_choice$lum$, $lum${"stem":"A medical assistant uses the plain-language rewrite prompt on discharge instructions for a patient taking warfarin. The original instructions say 'Avoid NSAIDs, including ibuprofen and naproxen, due to increased bleeding risk.' The AI rewrite says 'Be careful with pain medicine.' What is the problem?","options":[{"id":"a","label":"The AI simplified the substance, not just the wording. The specific drug names and the reason were removed, which changes what the patient knows to avoid.","is_correct":true,"explanation":"Correct. 'Be careful with pain medicine' does not tell the patient which medicines, and removes the bleeding-risk reason that makes the instruction meaningful. A patient on warfarin who takes ibuprofen for a headache has been failed by that rewrite."},{"id":"b","label":"The rewrite is fine because shorter is always better for low-literacy patients.","is_correct":false,"explanation":"Shorter is better only when the meaning survives. Here, critical safety content was dropped. A shorter instruction that is missing a drug name and a warning reason is not better. It is dangerous."},{"id":"c","label":"The rewrite is fine because ibuprofen and naproxen are too technical for a 6th-grade reading level.","is_correct":false,"explanation":"Brand familiarity does not reduce readability in this case. Most patients know the word ibuprofen from over-the-counter packaging. More importantly, the safety rule requires the names stay. The fix is: 'Do not take ibuprofen (Advil, Motrin) or naproxen (Aleve). These medicines can cause serious bleeding when you take warfarin.'"},{"id":"d","label":"The problem is that the AI used a passive sentence structure.","is_correct":false,"explanation":"Sentence structure is not the issue here. The issue is missing content. The names of the drugs and the reason for the warning were removed, not rephrased."}]}$lum$::jsonb, false),
  ($lum$831284b4-6db8-58a9-9d96-583cdfc89d1b$lum$::uuid, $lum$083f1118-db9a-5a34-b410-0e78c3a43cd2$lum$::uuid, 4, $lum$reading$lum$, $lum${"markdown":"**Clinical example 2: A new diabetes diagnosis**\n\nA coordinator is preparing education materials for a patient newly diagnosed with Type 2 diabetes. The physician note says: \"Initiate metformin 500 mg PO BID with meals. Monitor fasting BG daily. RTC if BG consistently greater than 250 or signs of hypoglycemia: diaphoresis, tremor, altered mental status.\"\n\nThe plain-language version should read: \"Start taking metformin, 500 mg, twice a day. Take it with breakfast and with dinner. Check your blood sugar every morning before you eat and write the number down. Call your doctor or go to the emergency room if your blood sugar is over 250 several days in a row, or if you feel shaky, sweaty, or confused.\"\n\nNotice that the AI needs to know BID means twice a day, that \"with meals\" maps to breakfast and dinner as the two named meal anchors, and that the three signs of hypoglycemia need to stay present. If you run this and the output drops \"altered mental status\" from the hypoglycemia list, the rewrite failed and you correct it before it reaches the patient.\n\n**Clinical example 3: A teach-back script for a wound care procedure**\n\nNurses and medical assistants often need to talk patients through a dressing change they will do at home. The teach-back script lives in the instructions but also needs to be rehearsed. You can prompt: \"Rewrite this wound care procedure as a spoken script I can read aloud to a patient at a 6th-grade level. Include a teach-back question at the end. Keep every step exact.\"\n\nFor a wound that requires twice-daily normal saline irrigation and non-adhesive dressing: the output should walk through wash your hands first, use plain saline solution, irrigate gently, apply the non-stick dressing, and end with a teach-back like \"Can you tell me in your own words what you will do if the wound starts looking red or starts leaking?\" That teach-back line confirms the patient retained the red-flag knowledge, not just the mechanical steps.\n\n**Why AI handles this task well and what limits it**\n\nAI tools are genuinely good at substituting everyday words for clinical terms, breaking long compound sentences into short sequential ones, and turning passive constructions into direct instructions. These changes raise readability without altering clinical meaning.\n\nThe tool is only as accurate as the instructions you give it. The prompt constraints are not formalities. They are the guardrails that make the output safe. After the rewrite, read it back as the clinician, aloud, not skimming. That step catches drops and additions that a quick visual scan misses.\n\nPlain-language rewriting is most useful for: post-procedure discharge instructions, new-diagnosis education sheets, medication reconciliation summaries, and procedure explanations before consent. It also helps with interpreter-assisted communication, because starting with a plain-language version reduces the chance that a clinical term creates ambiguity in the target language."}$lum$::jsonb, false),
  ($lum$67c893f5-b730-52ca-b6ed-91a911744d35$lum$::uuid, $lum$083f1118-db9a-5a34-b410-0e78c3a43cd2$lum$::uuid, 5, $lum$multiple_choice$lum$, $lum${"stem":"In the diabetes example, the physician note lists three signs of hypoglycemia: diaphoresis, tremor, and altered mental status. The reading says that if the rewrite drops 'altered mental status,' the rewrite failed. Why?","options":[{"id":"a","label":"Because 'altered mental status' is the only sign that needs a clinical term, so it must be kept verbatim.","is_correct":false,"explanation":"The reading does not require keeping the clinical term verbatim. 'Confused' is offered as the plain-language version. What matters is that the sign itself is not dropped."},{"id":"b","label":"Because dropping any one of the three warning signs leaves the patient without a complete list of when to seek help, even though the others survived.","is_correct":true,"explanation":"Correct. All three signs of hypoglycemia need to stay present. Losing 'altered mental status' (rendered as 'confused') means the patient is missing a warning sign, which is exactly the kind of substance change the prompt constraints are meant to prevent."},{"id":"c","label":"Because the rewrite should have kept the term 'hypoglycemia' rather than describing the symptoms.","is_correct":false,"explanation":"The plain-language version intentionally describes the symptoms (shaky, sweaty, confused) instead of using the word hypoglycemia. The failure is the missing third sign, not the choice to describe rather than name the condition."},{"id":"d","label":"Because BID was incorrectly translated to twice a day.","is_correct":false,"explanation":"Twice a day is the correct translation of BID, and the reading presents it as accurate. The failure is dropping a warning sign, not the dosing translation."}]}$lum$::jsonb, false),
  ($lum$b2121db0-48e9-5105-a5a2-24159c1418f3$lum$::uuid, $lum$083f1118-db9a-5a34-b410-0e78c3a43cd2$lum$::uuid, 6, $lum$reading$lum$, $lum${"markdown":"Even with a clear prompt and a reliable AI tool, the same four mistakes appear in clinical settings. Knowing them by name makes them easier to catch before they reach a patient.\n\n**Mistake 1: Pasting identifiable patient instructions into a non-approved tool**\n\nMost consumer AI tools are not cleared for protected health information. The default assumption is: this tool is not HIPAA-compliant unless your IT or compliance officer has confirmed it. A nurse who copies a discharge summary including the patient's name, date of birth, and MRN into a public chatbot has committed a privacy violation even if the rewrite itself is excellent.\n\nWhat to do instead: strip the document before pasting. Replace the patient name with \"the patient\" or \"you,\" and remove all identifiers. The clinical content, the medication, the dose, the warnings, does not need an identity attached to be rewritten. If you are not sure whether your facility's tool is approved for PHI, strip it first. That takes thirty seconds.\n\n**Mistake 2: Letting the AI simplify by removing a dose or a warning sign**\n\nThis is the most clinically dangerous mistake. The AI compresses for readability and in doing so drops the detail that actually matters. The 10-day course becomes \"for several days.\" The fever threshold of 101 degrees F disappears from the return-to-ED criteria. The instruction to take metformin with food becomes \"take your diabetes medicine.\"\n\nEach of those changes is technically a rewrite. None of them is acceptable.\n\nThe way to catch this is not to trust the prompt alone. Read the output against the original line by line. Every dose should appear with the same number. Every timing instruction should appear with the same interval. Every warning sign should appear by name, even if the name is now a plain description. If anything is missing, correct it manually before using the document."}$lum$::jsonb, false),
  ($lum$0dc3df10-56c2-5b02-b1e1-6a99f222d2a7$lum$::uuid, $lum$083f1118-db9a-5a34-b410-0e78c3a43cd2$lum$::uuid, 7, $lum$multiple_choice$lum$, $lum${"stem":"A clinical coordinator runs discharge instructions through an AI rewriting tool. The original says 'Return to ED for fever over 101.5 F, shortness of breath, or chest pain.' The rewrite says 'Come back if you feel unwell or have trouble breathing.' What type of mistake is this?","options":[{"id":"a","label":"The AI simplified the substance by removing the fever threshold and collapsing three specific warning signs into vague language.","is_correct":true,"explanation":"Correct. 'Feel unwell' does not tell a patient at what temperature to return. Chest pain disappeared entirely. 'Trouble breathing' is closer to shortness of breath but loses precision. Every one of those three specific criteria matters and each must survive the rewrite."},{"id":"b","label":"This is a privacy mistake because the original instruction contained clinical detail.","is_correct":false,"explanation":"Privacy concerns involve identifiable patient information, not clinical content. The problem here is accuracy: specific warning signs were removed or diluted, not that the patient's identity was exposed."},{"id":"c","label":"The rewrite is acceptable because 'trouble breathing' and 'shortness of breath' mean the same thing.","is_correct":false,"explanation":"They are close but the fever threshold and chest pain are both completely absent. A rewrite that drops two of three warning signs is not acceptable even if one survived in a near-equivalent form."},{"id":"d","label":"The rewrite is acceptable because the AI was trying to be concise.","is_correct":false,"explanation":"Conciseness does not justify removing safety criteria. The acceptable rewrite is: 'Come back to the emergency room right away if you have a fever over 101.5 degrees, any trouble breathing, or any chest pain.' That is both concise and complete."}]}$lum$::jsonb, false),
  ($lum$ee2f3493-7f02-5c7e-9db6-2494adb4c65e$lum$::uuid, $lum$083f1118-db9a-5a34-b410-0e78c3a43cd2$lum$::uuid, 8, $lum$reading$lum$, $lum${"markdown":"**Mistake 3: Sending the rewrite to the patient without a clinician reading it back**\n\nThe rewrite step is preparation, not the final step. A clinician must review the plain-language version before it leaves the building. That review catches two things the prompt cannot catch on its own: content that was dropped, and content that was added.\n\nThe added-content problem is subtler than missing content. An AI tool may add \"check your blood pressure at home twice a day\" to a hypertension instruction the physician wrote without that monitoring frequency. That is new clinical advice delivered under the appearance of physician guidance. Reading the output sentence by sentence catches both gaps and additions before the patient sees them.\n\n**Mistake 4: Accepting a rewrite that passes the reading-level test but fails the comprehension test**\n\nSome plain-language rewrites produce sentences that score well on readability formulas but that a scared or distracted patient would still misunderstand. \"Take the medicine as prescribed\" is short and simple and completely useless for a patient who does not remember what prescribed means. \"Monitor your incision daily\" uses a short sentence but \"monitor\" and \"incision\" are still clinical words for many patients.\n\nAfter the AI rewrites, read the output aloud the way you would read it at the bedside, to a real person who is anxious, who may not have slept well, and who is about to go home without a nurse nearby. If a sentence would stop you at the bedside because you would need to explain it, it is not plain enough yet. Ask for another revision with the specific word or phrase replaced."}$lum$::jsonb, false),
  ($lum$ce7cb4ff-e458-5353-b032-ebee5fc4434b$lum$::uuid, $lum$083f1118-db9a-5a34-b410-0e78c3a43cd2$lum$::uuid, 9, $lum$multiple_choice$lum$, $lum${"stem":"An AI rewrite of a hypertension instruction adds the line 'check your blood pressure at home twice a day,' a monitoring frequency the physician never wrote. Which mistake does this illustrate, and why is it dangerous?","options":[{"id":"a","label":"It is a privacy mistake, because home blood pressure readings are protected health information.","is_correct":false,"explanation":"Nothing identifiable was exposed here. The problem is invented clinical advice, not a privacy breach. Privacy mistakes involve identifiers like name, date of birth, or MRN."},{"id":"b","label":"It is the comprehension mistake, because the added sentence is too clinical for the patient.","is_correct":false,"explanation":"The comprehension mistake is about wording a patient cannot understand. This sentence is plain enough; the danger is that it is new advice the physician never gave, not that it is hard to read."},{"id":"c","label":"It is the dropped-content mistake, because the rewrite left out part of the original.","is_correct":false,"explanation":"This is the opposite of dropping content. Nothing was removed; something was added. The reading flags added content as a separate and subtler problem than missing content."},{"id":"d","label":"It is the added-content problem, which a clinician must catch on read-back because it delivers new clinical advice under the appearance of physician guidance.","is_correct":true,"explanation":"Correct. The reading describes this as the added-content problem, subtler than missing content. Reading the output sentence by sentence is what catches advice the physician never authorized before the patient sees it."}]}$lum$::jsonb, false),
  ($lum$ab1348b3-822b-5cce-95d6-134003608f85$lum$::uuid, $lum$083f1118-db9a-5a34-b410-0e78c3a43cd2$lum$::uuid, 10, $lum$try_it_live$lum$, $lum${"instructions":"Read the discharge instruction below. Rewrite it in plain language at about a 6th-grade reading level. Keep the dose, timing, and all warning signs exactly accurate. Use short sentences and everyday words. Do not remove any safety information. Do not add any new advice. Do not use em dashes.","system_prompt":"You rewrite clinical discharge instructions into plain language at about a 6th-grade reading level. Rules you must follow: keep every dose, timing interval, and warning sign exactly as written in the original. Use short sentences and everyday words. Do not remove any safety information. Do not add any new advice that was not in the original. Do not use em dashes.","ideal_output":"Take one amoxicillin pill (500 mg) by mouth every 8 hours. Take it for 10 full days, even if you start to feel better. Come back to the emergency room right away if you have any of these: a fever over 101 degrees, redness around the cut that is spreading or getting worse, or any pus or cloudy fluid leaking from the cut.","input_placeholder":"Administer amoxicillin 500mg PO every 8 hours for 10 days. Return to the ED for fever exceeding 101F, worsening erythema, or purulent drainage at the incision site."}$lum$::jsonb, true),
  ($lum$e6453bc9-aa33-59bc-b2e0-a9b4e0fce588$lum$::uuid, $lum$083f1118-db9a-5a34-b410-0e78c3a43cd2$lum$::uuid, 11, $lum$multiple_choice$lum$, $lum${"stem":"You run your amoxicillin discharge instructions through the AI rewriter. The output reads: 'Take your antibiotic three times a day for 10 days. Go to the ER if you get a fever, if the wound looks red, or if anything leaks from it.' You compare this to the original. What needs to be corrected before this goes to the patient?","options":[{"id":"a","label":"The dose (500 mg) is missing, and 'a fever' should specify 'a fever over 101 degrees' to match the original return criterion.","is_correct":true,"explanation":"Correct. 'Three times a day' is accurate for every-8-hours dosing, but the 500 mg dose was dropped entirely. 'A fever' without a threshold is vague: a patient who normally runs 98 degrees and hits 100 degrees might not go to the ED, when the instruction said 101 degrees is the line. Both must be corrected before this reaches the patient."},{"id":"b","label":"Nothing needs to be corrected. The rewrite is close enough to the original.","is_correct":false,"explanation":"A missing dose and a vague fever threshold are not close enough. Dose and return criteria are the two most clinically important pieces of information in this instruction. Both must survive exactly."},{"id":"c","label":"The word 'antibiotic' should be changed back to 'amoxicillin' because patients need to know the drug name.","is_correct":false,"explanation":"Using both is better: 'Take your antibiotic (amoxicillin), 500 mg.' But the primary problems are the missing dose and the vague fever number. Those are the corrections to make first."},{"id":"d","label":"The word 'leaks' should be changed back to 'purulent drainage' so it is medically precise.","is_correct":false,"explanation":"Plain-language rewrites intentionally replace clinical terms like purulent drainage with everyday language like pus or fluid leaking. That substitution is correct. The dose and fever threshold are the real gaps here."}]}$lum$::jsonb, false),
  ($lum$c6b61ad1-fcfa-532c-b71e-d0d3b6f8f956$lum$::uuid, $lum$083f1118-db9a-5a34-b410-0e78c3a43cd2$lum$::uuid, 12, $lum$mini_project$lum$, $lum${"brief":"Take a set of discharge instructions your unit or clinic actually uses, either a printed template or a standard after-visit summary you hand patients. Run the full rewrite prompt on that document, keeping the prompt constraints: keep every dose, timing, and warning sign exact; add no new advice; use short sentences and everyday words. Then read both versions aloud at a normal speaking pace, the way you would at the bedside with a patient who is tired, nervous, and about to go home. Compare them sentence by sentence to confirm every dose, interval, and warning sign survived.","parts":[{"id":"1","prompt":"Write down any dose, timing reference, or warning sign that appeared in the original but was missing or changed in the AI version. Note how you corrected each one."},{"id":"2","prompt":"Write one sentence describing the biggest readability difference between the two versions and why that difference matters for the specific patient population your unit serves."},{"id":"3","prompt":"Identify one sentence in the AI rewrite that still sounds clinical or confusing to a non-medical reader, and rewrite that sentence yourself in plain language without changing the meaning."}]}$lum$::jsonb, false),
  ($lum$9203e8f1-b65f-51d0-a9e7-d2a970ea810a$lum$::uuid, $lum$54e500e6-97d1-5972-8df3-dfef93e16ecf$lum$::uuid, 0, $lum$reading$lum$, $lum${"markdown":"Picture a Tuesday afternoon. You are a corporate development analyst, and your VP just dropped a new industry on your desk: vertical software for the dental industry. The board wants a sizing memo by Friday. You have never looked at this market in your life. The slow, miserable part of this job is not the thinking. It is the blank page. What are the players? What dimensions even matter here? What questions should you be asking? Where do you start? That orientation work, the scaffolding of the research, is exactly what AI does well, and it can turn a paralyzed afternoon into a structured starting point in about ten minutes.\n\nSo let us be precise about what AI is genuinely good for here, because the line matters more in this lesson than almost anywhere else. AI is excellent at generating the structure of research. Ask it, \"I am sizing the market for dental practice management software. What dimensions should a competitive comparison cover, what questions should I be asking the data, and what categories of source would answer each one?\" and you will get back a real map. It will suggest you compare on pricing model, target practice size, feature depth, integrations, and switching costs. It will remind you to separate the small-practice segment from large dental service organizations. It will point you toward the kinds of sources that hold the answers: company pricing pages, industry reports, review platforms, regulatory filings. That map is worth keeping. It is the part that saves you the afternoon."}$lum$::jsonb, false),
  ($lum$078fdd5a-2c5e-5337-bf8e-6df40ce9449c$lum$::uuid, $lum$54e500e6-97d1-5972-8df3-dfef93e16ecf$lum$::uuid, 1, $lum$multiple_choice$lum$, $lum${"stem":"An AI returns a strong research map for the dental software market: dimensions to compare, questions to ask, and the kinds of sources that hold the answers. According to the reading, what is this map best understood as?","options":[{"id":"a","label":"The orientation scaffolding that AI does well, worth keeping because it saves you the blank-page afternoon.","is_correct":true,"explanation":"Correct. The reading frames structuring the research, the dimensions, questions, and source categories, as exactly what AI is good for, turning a paralyzed afternoon into a structured start in about ten minutes."},{"id":"b","label":"A set of facts about the market that you can quote directly once it looks detailed enough.","is_correct":false,"explanation":"The map is structure, not facts. Detail and polish do not make the underlying specifics true, and the reading is careful to keep structure separate from factual claims."},{"id":"c","label":"A waste of time, since orienting on an unfamiliar industry is the part you should do entirely by hand.","is_correct":false,"explanation":"The reading argues the opposite: orientation is the slow, miserable part, and it is precisely where AI helps most by building the scaffolding fast."}]}$lum$::jsonb, false),
  ($lum$cdeeacf6-8703-55d8-a53a-64d770c777b7$lum$::uuid, $lum$54e500e6-97d1-5972-8df3-dfef93e16ecf$lum$::uuid, 2, $lum$reading$lum$, $lum${"markdown":"Now here is the trap, and it is a quiet one. That same model will also hand you a clean table of five competitors with market shares, a total addressable market of some confident-looking dollar figure, and a growth rate quoted to one decimal place. It will name companies. It will attribute a statistic to \"industry research.\" And a meaningful share of those specifics will be wrong, outdated, or invented outright. The model does not know it is guessing. It produces the shape of a fact because the shape is what it learned, not because it pulled the number from a real filing. A precise percentage is not a sourced percentage. A tidy table is not verified research. Specificity and clean formatting feel like evidence, and they are not.\n\nThis matters in finance in a way it does not matter for a casual question. If a fabricated market-size number travels from an AI scan into your board memo, and from your memo into a model that someone uses to justify a decision, you have laundered a guess into a citation. Nobody downstream can tell it was never real. The whole chain inherits the error, and your name is on the front page. That is the stakes. So the discipline is simple to state and requires actual spine to follow: treat every fact the AI gives you as a lead, not a finding."}$lum$::jsonb, false),
  ($lum$d9886d6a-d6d3-5169-9650-63dfedb98c11$lum$::uuid, $lum$54e500e6-97d1-5972-8df3-dfef93e16ecf$lum$::uuid, 3, $lum$multiple_choice$lum$, $lum${"stem":"You ask an AI to scope the dental software market and it returns a clean table of five competitors with market shares and a total market size to the dollar. What is the single most useful way to think about that table?","options":[{"id":"a","label":"As finished research, because it is specific, well organized, and reads like something from a real report.","is_correct":false,"explanation":"Specificity and tidy formatting are not evidence of accuracy. A model can produce a confident, polished table full of invented shares and a fabricated market size. Organized is not the same as verified."},{"id":"b","label":"As a lead list: the structure is useful, but every competitor, share, and figure must be confirmed against a primary source before any of it enters your memo.","is_correct":true,"explanation":"Correct. The map is worth keeping, but the specific facts can be wrong, stale, or invented. Each named player and number is a lead to confirm against filings or a named industry report, never a finding to cite as is."},{"id":"c","label":"As proof the market is exactly that size, since an AI would not invent a number that precise.","is_correct":false,"explanation":"A precise number is exactly the kind of thing models invent, because precision is the shape of a real fact and the model learned the shape. A clean figure is not a sourced figure."}]}$lum$::jsonb, false),
  ($lum$76b05383-ce8d-50fe-9326-57272f7158ed$lum$::uuid, $lum$54e500e6-97d1-5972-8df3-dfef93e16ecf$lum$::uuid, 4, $lum$reading$lum$, $lum${"markdown":"Think of it as two completely separate jobs the AI is doing in the same answer, and you keep them apart on purpose. Job one is structuring: the questions, the categories, the comparison dimensions, the rough orientation on how the industry hangs together. You keep that. Job two is factual claims: every named competitor, every market size, every growth rate, every statistic. Each of those is something you go confirm against a primary source before it enters anything you produce. The competitor list gets checked against the companies' own sites and filings. The market size gets checked against a reputable industry report you can actually name and cite. The growth rate gets checked against a real source with a real date on it. Only the confirmed version crosses the wall into your deliverable.\n\nTwo habits make this safe and fast. First, ask the AI for its reasoning and its source categories, not just its answers. Instead of \"what is this market worth,\" ask \"what would I need to find, and where, to size this market credibly?\" That turns the AI into a research planner instead of a fake encyclopedia, and it hands you a to-do list of things to verify rather than a number to be tempted by. Second, keep a hard wall between the draft and the deliverable. The AI's scan organizes your search. Only sourced, confirmed facts cross into the memo or the model.\n\nDone this way, you get the best of both. A strategy analyst orienting on an unfamiliar industry gets a usable framework in minutes instead of a day. An analyst building a competitive comp set gets a complete list of dimensions to compare and a checklist of where to look. Someone sizing a market for a board memo gets the full question list before they have read a single report. The speed is real. You just never let the AI's confidence substitute for the verification step, because that step is the entire reason anyone trusts the memo at the end."}$lum$::jsonb, false),
  ($lum$90681d35-1e5c-5436-9d59-b025239e96e8$lum$::uuid, $lum$54e500e6-97d1-5972-8df3-dfef93e16ecf$lum$::uuid, 5, $lum$multiple_choice$lum$, $lum${"stem":"The reading describes two separate jobs the AI does in the same answer. Which split correctly matches each job to how you should handle it?","options":[{"id":"a","label":"Job one is structuring, which you keep; job two is factual claims, every one of which you confirm against a primary source before it enters your work.","is_correct":true,"explanation":"Correct. Structuring covers the questions, categories, and comparison dimensions, and you keep that. Factual claims, named competitors, market sizes, growth rates, statistics, each get confirmed against a primary source first."},{"id":"b","label":"Job one is the factual claims, which you keep as is; job two is the structure, which you can safely discard.","is_correct":false,"explanation":"This reverses the reading. The factual claims are exactly what you must verify, and the structure is the part worth keeping."},{"id":"c","label":"Both jobs are factual, so you can let confirmed and unconfirmed material cross into the deliverable together.","is_correct":false,"explanation":"The reading insists on a hard wall: only sourced, confirmed facts cross into the memo or model. Structure and unverified claims are not the same thing and are not treated the same way."}]}$lum$::jsonb, false),
  ($lum$6bab2ea0-a9ec-516f-a6b3-ed1016c6a435$lum$::uuid, $lum$54e500e6-97d1-5972-8df3-dfef93e16ecf$lum$::uuid, 6, $lum$reading$lum$, $lum${"markdown":"The failure modes here are predictable, so you can guard against each one. The most common is laundering. You ask the AI for a quick scan, it hands you a market size, the number looks plausible, and because you are busy and the deadline is Friday, it slides straight into the memo. Two weeks later someone on the deal team asks for the source, and you realize you never had one. The number came from a model that does not cite. By then it has been quoted in two more documents. The fix is the hard wall: nothing crosses from the AI scan into the deliverable until you can name the primary source next to it.\n\nA second trap is anchoring. Once the AI tells you the market is \"roughly twelve billion dollars,\" that number lodges in your head. When you go find the real report, you unconsciously look for figures near twelve billion and wave past the ones that disagree. The AI did not just give you a lead, it gave you a bias. Protect yourself by treating the AI's number as a range to disprove, not a target to confirm. If the real sources cluster far from the AI's guess, trust the sources and notice that the AI was simply wrong."}$lum$::jsonb, false),
  ($lum$47ea8426-9ee7-5396-8023-96abb6795ee4$lum$::uuid, $lum$54e500e6-97d1-5972-8df3-dfef93e16ecf$lum$::uuid, 7, $lum$fill_blank$lum$, $lum${"template":"The most common failure mode is {{1}}, where an unsourced AI number slides into the memo and gets quoted again before anyone asks for a source. The fix is a hard wall: nothing crosses into the deliverable until you can name the {{2}} next to it.","blanks":[{"id":"1","accept":["laundering","laundering a guess","money laundering"],"ideal":"laundering"},{"id":"2","accept":["primary source","source","primary source you can name","real source"],"ideal":"primary source"}],"explanation":"Laundering is when a guess from a model that does not cite slides into your deliverable and gets requoted as if it were sourced. The hard wall stops it: nothing crosses until you can name the primary source beside it."}$lum$::jsonb, false),
  ($lum$033dc66a-7434-557e-8534-7dda8b66414a$lum$::uuid, $lum$54e500e6-97d1-5972-8df3-dfef93e16ecf$lum$::uuid, 8, $lum$reading$lum$, $lum${"markdown":"A third one is fake authority. Models love to attribute things: \"according to industry research,\" \"analysts estimate,\" \"a leading report found.\" These phrases are almost always decoration, not real citations. There is frequently no specific report behind them. When you see attribution language, do not relax. Treat it as a flashing sign that says \"go find the actual document,\" because the AI cannot hand you the document and often cannot even name it correctly.\n\nA fourth is the stale roster. You ask for the competitor set and get a list that was accurate two or three years ago. A company on it got acquired. A major new entrant is missing entirely. The AI's training has a horizon, and markets move past it. Always pull the current competitor list from a live source, and use the AI's list only to make sure you have not missed an obvious category of player.\n\nThe last mistake is the subtlest: asking the AI for facts at all when you should be asking it for structure. The moment your prompt is \"what is this market worth,\" you have pointed the tool at the one thing it is worst at. Point it at what it is best at instead. Ask \"what would I need to find, and where, to size this credibly?\" You will get a research plan you can execute and verify, rather than a number you will be tempted to trust. Keep the AI on the map, and keep yourself on the sources."}$lum$::jsonb, false),
  ($lum$aa5c9a16-4200-56b7-a858-ba8330dce49b$lum$::uuid, $lum$54e500e6-97d1-5972-8df3-dfef93e16ecf$lum$::uuid, 9, $lum$multiple_choice$lum$, $lum${"stem":"Your AI scan says the market is 'roughly twelve billion dollars, according to industry research.' You later find a real report that puts it closer to seven billion. What went wrong, and what should you do?","options":[{"id":"a","label":"Trust the real report and treat the AI's twelve billion as a guess that was simply wrong; the 'according to industry research' line was decoration, not a real citation.","is_correct":true,"explanation":"Correct. Attribution phrases like 'industry research' are usually filler, not a real source. The named report you actually found is the primary source. Update your number to the verified figure and do not let the AI's anchor pull you back."},{"id":"b","label":"Average the two numbers, since the truth is probably somewhere in between.","is_correct":false,"explanation":"Averaging a sourced number with an unsourced guess just contaminates the good number. The AI figure has no source behind it, so it gets no weight. Use the verified report."},{"id":"c","label":"Keep twelve billion, because the AI cited industry research and the report you found might be narrower in scope.","is_correct":false,"explanation":"The AI's 'industry research' is almost certainly not a real, nameable source, so it cannot outweigh a report you can actually read and cite. If scope differs, reconcile the scope from the real document, not from the AI's guess."}]}$lum$::jsonb, false),
  ($lum$289d135b-0e5d-5598-ad3c-be899606582e$lum$::uuid, $lum$54e500e6-97d1-5972-8df3-dfef93e16ecf$lum$::uuid, 10, $lum$try_it_live$lum$, $lum${"instructions":"Practice pointing the AI at structure instead of facts. Describe a market or competitor question you actually need to scope, and ask only for the comparison dimensions, the questions to investigate, and the categories of primary source that would answer each one. Or use this sample: a first-pass competitive scan of dental practice management software for small and mid-size practices.","system_prompt":"You are a research planning partner for a finance professional doing a first-pass market or competitive scan. Your job is to structure the research, not to supply facts. Provide three things: the dimensions a comparison should cover, the key questions to investigate, and the categories of primary source that would answer each question. If you mention any specific company, market size, growth rate, or statistic, you must explicitly label it 'unverified, confirm against a primary source,' because your figures may be outdated or invented. Never present a number or a competitor as established fact. Encourage the user to treat every specific as a lead to verify. Use plain language. No em dashes.","ideal_output":"Here is a structure for a first-pass scan of dental practice management software for small and mid-size practices. This is a research plan, not a set of facts. Treat any company or figure I mention as an unverified lead to confirm against a primary source.\n\nDimensions to compare: pricing model and per-provider cost, target practice size, core features versus paid add-ons, integrations with imaging and accounting tools, insurance and claims handling, and the customer support model.\n\nKey questions to investigate: How large is the small and mid-size practice segment specifically, separate from large dental service organizations? What is the realistic growth rate, and which dated source supports it? Where do incumbents lose customers, and why? What does it cost a new entrant to handle claims and compliance across states?\n\nSource categories that would answer these: company pricing pages and any public filings for the players, recognized industry research reports for sizing and growth, review platforms for switching reasons, and regulatory or insurance-authority sites for claims and compliance scope.\n\nThere are companies commonly associated with this space, but I am not listing them as fact here because my roster may be stale. Pull the current set from a live, reputable source and use my dimensions to check you have not missed a category. Want me to turn this into a two-column comparison template you can fill with verified data?","input_placeholder":"Describe the market or competitor set you need to scope..."}$lum$::jsonb, true),
  ($lum$79b43139-0057-503e-a73b-a170df3790af$lum$::uuid, $lum$54e500e6-97d1-5972-8df3-dfef93e16ecf$lum$::uuid, 11, $lum$multiple_choice$lum$, $lum${"stem":"You want the AI to help most with a first-pass scan of an unfamiliar industry without tempting you to cite a fabricated figure. Which prompt is the strongest?","options":[{"id":"a","label":"'What is this market worth, and who are the top five players by share?'","is_correct":false,"explanation":"This points the tool at exactly what it is worst at. It will hand you a confident size and a stale roster, both of which you will be tempted to trust. You have asked for facts the AI cannot source."},{"id":"b","label":"'Give me a finished market summary I can paste into my board memo.'","is_correct":false,"explanation":"This asks the AI to produce the deliverable, which collapses the wall between draft and memo. Anything it invents goes straight into the document. The AI should organize your search, not write your conclusions."},{"id":"c","label":"'What dimensions should I compare, what questions should I investigate, and what categories of primary source would answer each one?'","is_correct":true,"explanation":"Correct. This points the AI at structure, the thing it does well, and hands you a verifiable research plan instead of a number to trust. You keep the map and go confirm every specific against a real source yourself."}]}$lum$::jsonb, false),
  ($lum$472c2a15-2b3e-5875-9ed7-0d9c996ae6bc$lum$::uuid, $lum$54e500e6-97d1-5972-8df3-dfef93e16ecf$lum$::uuid, 12, $lum$mini_project$lum$, $lum${"brief":"Pick a real market or competitor question you actually need to scope this month: an industry you are orienting on, a comp set you are building, or a market you are sizing for a memo. Ask the AI only for structure, never for the answer. Get the comparison dimensions, the questions to investigate, and the categories of primary source that would answer each, with any specific name or figure flagged as unverified. Then build a two-column working doc and watch how many of the AI's confident specifics survive contact with a real source.","parts":[{"id":"1","prompt":"On the left column, capture the AI's structure and every lead it surfaced: each competitor name, each market-size guess, each growth rate, each statistic."},{"id":"2","prompt":"On the right column, copy an item over only after you have confirmed it against a primary source you can name and date, and write that source next to it."},{"id":"3","prompt":"At the end, count how many left-column specifics changed, vanished, or needed correction once you checked them, and note how fast you still reached a usable research plan."}]}$lum$::jsonb, false),
  ($lum$a674aec5-abce-58f1-8931-f61995cbf152$lum$::uuid, $lum$57ae1d4b-0838-55a8-adbc-716a4de13b1a$lum$::uuid, 0, $lum$reading$lum$, $lum${"markdown":"The hardest part of feedback is not deciding what is wrong. You can see in ten seconds that a paragraph has no evidence, or that an argument never answers the question, or that a lab report skipped the analysis and jumped straight to the conclusion. The hard part is writing all of that out, kindly and specifically, thirty times in a row, without turning into a tired person who just scrawls \"needs more detail\" in the margin at 9pm.\n\nThat gap, between what you notice and what you have time to write, is exactly where AI helps. You supply the judgment. The model supplies the wording.\n\nThe move is simple. You give the AI three things: the assignment or rubric you are grading against, the student's actual work, and your shorthand reaction. Your reaction can be rough and ugly, the way you actually think it. \"Thesis is fine, body paragraph two has no evidence, conclusion just repeats the intro\" is plenty. The model takes that and expands it into feedback the student can act on, written in a tone you choose. You stay the teacher. You just stop doing the typing.\n\nLet me show you what this looks like with real work."}$lum$::jsonb, false),
  ($lum$8e103dc0-ed5c-5011-baee-b2e29c9b9488$lum$::uuid, $lum$57ae1d4b-0838-55a8-adbc-716a4de13b1a$lum$::uuid, 1, $lum$multiple_choice$lum$, $lum${"stem":"You want AI to help you write feedback on a stack of essays without losing what makes the feedback yours. What do you hand the AI, and what do you keep for yourself?","options":[{"id":"a","label":"Hand it a blank essay and ask it to grade the work and write the feedback, then copy what it says.","is_correct":false,"explanation":"This gives away the one part that has to be yours: deciding whether the work is good. The AI is not a better judge of your student's essay than you are. Keep the judgment, hand off the wording."},{"id":"b","label":"Hand it the rubric, the student's work, and your own shorthand reaction, and keep the judgment about quality for yourself.","is_correct":true,"explanation":"Correct. You supply the assessment in rough form. The AI expands it into specific, warm, student-facing language. You stayed the teacher and skipped only the typing."},{"id":"c","label":"Hand it nothing about the assignment, just the essay, so it forms a fresh unbiased opinion of the work.","is_correct":false,"explanation":"Without the rubric you get generic essay advice, and without your reaction the AI is guessing at quality. The point is to tie feedback to what you actually assessed, not to outsource the assessment."}]}$lum$::jsonb, false),
  ($lum$f7d0f350-62ab-5df6-8d41-f1bb6fcf435c$lum$::uuid, $lum$57ae1d4b-0838-55a8-adbc-716a4de13b1a$lum$::uuid, 2, $lum$reading$lum$, $lum${"markdown":"Take a 7th grade persuasive essay arguing the school day should start later. Your rubric has three things on it: a clear claim, two pieces of evidence, and a counterargument. You read the essay and your honest reaction is, \"Claim is strong and clear. Only one piece of evidence and it is really just an opinion dressed up as a fact. No counterargument at all. The writing itself is lively and fun to read.\" That is your whole assessment, and it took you about forty seconds. Now you hand the AI the rubric, the essay, and that reaction, and you ask it to write warm, specific feedback addressed to the student: open with a real strength, name the two gaps with a concrete fix for each, and close with one encouraging next step. What comes back is a 120 word note that praises the lively voice, explains the difference between an opinion and a cited fact, asks for one source the student could add, points out that a counterargument was missing and shows where it would go, and ends on a \"you are close, here is the next move\" note. You read it, you tweak one sentence, it goes out. You did the thinking. The AI did the writing.\n\nNow scale it up. You have a stack of thirty biology lab reports on enzyme activity, all graded against the same rubric: hypothesis, procedure, data table, and analysis. As you skim each one, you are mostly writing the same three or four reactions in different combinations. \"Data table is clean, but the analysis just restates the numbers instead of explaining what they mean.\" \"Hypothesis is missing entirely, jumped straight into procedure.\" \"Strong analysis, but no control mentioned.\" You can write these shorthand reactions fast because you are a biology teacher and this is exactly the judgment you are trained to make. Then you batch them. You give the AI your rubric once, and for each report you paste the student's work and your two-line reaction, and it expands each one into a feedback paragraph in a consistent, encouraging voice. Thirty reports that would have taken you a full evening of margin-writing now take you the time to skim and react, plus a few minutes per report to read and approve the expanded note. The student gets a real paragraph instead of a checkmark."}$lum$::jsonb, false),
  ($lum$e2c0181e-0b50-5c54-8cee-258c23a80e21$lum$::uuid, $lum$57ae1d4b-0838-55a8-adbc-716a4de13b1a$lum$::uuid, 3, $lum$fill_blank$lum$, $lum${"template":"In the lab-report example, the teacher gives the AI the {{1}} only once, then for each report pastes the student's work and a two-line {{2}} for the model to expand.","blanks":[{"id":"1","accept":["rubric","the rubric"],"ideal":"rubric"},{"id":"2","accept":["reaction","shorthand reaction","shorthand","judgment"],"ideal":"reaction"}],"explanation":"The rubric is supplied once because it is the same for the whole stack, while the student's work and the teacher's short reaction change with each report. The AI expands the reaction into a full paragraph; it never forms the judgment itself."}$lum$::jsonb, false),
  ($lum$867b4068-848c-5099-9ae0-75d65fe15ee4$lum$::uuid, $lum$57ae1d4b-0838-55a8-adbc-716a4de13b1a$lum$::uuid, 4, $lum$reading$lum$, $lum${"markdown":"Or take something shorter. A set of short-answer history responses where students had to explain one cause of the Great Depression in three or four sentences. You read thirty of them. Some nail it, some confuse a cause with an effect, some give a real cause but no explanation of the mechanism. Your shorthand for one might be, \"Identified bank failures correctly, but never explained why a bank failure hurt ordinary families.\" That single sentence of judgment is the whole point. The AI turns it into two or three sentences of student-facing feedback that names the strength, explains the missing link, and points the student toward the connection they almost made. You would never have written that out by hand for all thirty. Now you can.\n\nIn every one of these cases, notice what you did and what the AI did. You read the work. You decided what was strong and what was weak. You made the call about whether bank failures were explained or just named. The AI never made a single judgment about quality. It took your judgment and made it longer, warmer, and more specific than a rushed margin note ever could be. That division of labor is the entire skill. Keep the judgment. Give away the typing."}$lum$::jsonb, false),
  ($lum$5d25f199-0283-583d-bde3-2d6618d5709a$lum$::uuid, $lum$57ae1d4b-0838-55a8-adbc-716a4de13b1a$lum$::uuid, 5, $lum$multiple_choice$lum$, $lum${"stem":"Across the essay, lab report, and history examples, what is the one thing the AI never does?","options":[{"id":"a","label":"Expand a short reaction into a longer, warmer, more specific note for the student.","is_correct":false,"explanation":"This is exactly what the AI does do in every example. It takes your shorthand and makes it longer and kinder than a rushed margin note."},{"id":"b","label":"Write feedback in a consistent, encouraging voice across a whole stack of work.","is_correct":false,"explanation":"This is one of the AI's jobs. It keeps the tone consistent across thirty reports so each student gets a real paragraph."},{"id":"c","label":"Decide whether the work was strong or weak in the first place.","is_correct":true,"explanation":"Correct. The passage is explicit that the AI never made a single judgment about quality. You read the work and made the call; the model only phrased it. That division of labor is the entire skill."},{"id":"d","label":"Point the student toward a connection they almost made.","is_correct":false,"explanation":"The history example shows the AI doing exactly this, pointing the student toward the link they nearly reached. It is part of the wording work, not the judgment."}]}$lum$::jsonb, false),
  ($lum$9ae9291b-6789-51b5-88c7-604ad60976bd$lum$::uuid, $lum$57ae1d4b-0838-55a8-adbc-716a4de13b1a$lum$::uuid, 6, $lum$reading$lum$, $lum${"markdown":"The workflow is simple, but there are a few ways it goes wrong on a real Tuesday with a real stack of papers. Knowing them ahead of time saves you from learning them the hard way.\n\nThe first is a privacy problem, and it is the one with real consequences. If you paste a student's actual work into a free public AI tool with their name on the page, you may be handing identifiable student data to a company whose terms let them keep and train on it. A 7th grader's essay with their name in the header is a student record. Strip names before pasting, or use a tool your school or district has approved for student data. This is not a judgment call you want to discover you got wrong after the fact, so build the habit of removing names every time, even when you are tired and it feels like a hassle.\n\nThe second is the temptation to outsource the assessment itself. It is genuinely faster to paste an essay and type \"is this a good essay, and write feedback.\" Do not do this. The AI does not know your students, your standards, or what this particular kid was capable of last month. It will produce a confident judgment that sounds right and may be wrong. The moment you let the model decide whether the work is good, you have given away the only part of grading that required you. Feed it your judgment, not a blank essay."}$lum$::jsonb, false),
  ($lum$a0fc97f7-65de-53f9-b6de-0b5d59baaa2c$lum$::uuid, $lum$57ae1d4b-0838-55a8-adbc-716a4de13b1a$lum$::uuid, 7, $lum$multiple_choice$lum$, $lum${"stem":"Why does the lesson tell you to strip a student's name out of their work before pasting it into a free public AI tool?","options":[{"id":"a","label":"Because a named essay is identifiable student data the tool's terms may let the company keep and train on.","is_correct":true,"explanation":"Correct. A 7th grader's essay with their name in the header is a student record, and a free public tool may keep and train on what you paste. Removing names protects that data."},{"id":"b","label":"Because the AI writes better feedback when it does not know whose work it is reading.","is_correct":false,"explanation":"The reason given is privacy, not feedback quality. The name has no bearing on how good the expanded note is."},{"id":"c","label":"Because the student should not know a tool was used to help write their feedback.","is_correct":false,"explanation":"The passage never frames it as hiding the tool from the student. The concern is handing identifiable student data to a company that may keep it."}]}$lum$::jsonb, false),
  ($lum$dbba4fe7-1a3b-5c5d-b916-38482055afca$lum$::uuid, $lum$57ae1d4b-0838-55a8-adbc-716a4de13b1a$lum$::uuid, 8, $lum$reading$lum$, $lum${"markdown":"The third shows up when you send AI feedback without reading it. The model is built to be encouraging, so it will invent a strength that is not in the work. It will tell a student their \"vivid use of evidence\" was wonderful when the whole problem was that there was no evidence. It will also soften a gap you wanted named plainly, turning \"you never answered the question\" into \"you might consider exploring the prompt further,\" which the student will not understand as a problem. Read every note before it goes out. You are the one signing the feedback, so it has to say what you mean.\n\nThe fourth is subtler and easy to slide into over a long grading session. You start treating the AI as the authority on the student's work instead of as a writing assistant for your conclusions. You catch yourself wondering if the AI is right and you are wrong about a paragraph. It is not the authority. It never read the assignment in class, never saw the student struggle with the same skill last week, never set the standard. You did all of that. The AI's job is to phrase your call well, not to make the call. If you keep that straight, every other mistake on this list gets easier to avoid, because you will never be tempted to send something you did not actually decide."}$lum$::jsonb, false),
  ($lum$db543b24-d699-5194-8a2d-cddffb88219e$lum$::uuid, $lum$57ae1d4b-0838-55a8-adbc-716a4de13b1a$lum$::uuid, 9, $lum$multiple_choice$lum$, $lum${"stem":"You expanded thirty lab reports with AI and you are about to send the feedback. One note praises a student's 'careful control group' that you do not remember seeing. What is the right move, and why?","options":[{"id":"a","label":"Send it anyway. If the AI saw a control group, it was probably there and you missed it while skimming.","is_correct":false,"explanation":"The AI is built to be encouraging and will invent strengths that are not in the work. Treating it as the authority on the student's report is exactly the mistake to avoid."},{"id":"b","label":"Delete the whole note and grade that one entirely by hand, since the AI clearly cannot be trusted at all.","is_correct":false,"explanation":"You do not need to throw out the workflow. You need to read and correct the output, which is the step that catches invented strengths. One fix, not a full retreat."},{"id":"c","label":"Check the report yourself, and if there is no control group, cut the false praise before the note goes out.","is_correct":true,"explanation":"Correct. Reading every note before it goes out is what catches the AI inventing a strength. You are the one signing the feedback, so it has to match the actual work."}]}$lum$::jsonb, false),
  ($lum$694ea246-f91f-5d33-89bd-5092c2dafd7e$lum$::uuid, $lum$57ae1d4b-0838-55a8-adbc-716a4de13b1a$lum$::uuid, 10, $lum$before_after$lum$, $lum${"question":"You jotted a quick reaction to a student's persuasive essay. Which prompt turns your shorthand into feedback the student can actually use?","before_prompt":"Give feedback on this student essay about why the school day should start later.","after_prompt":"You are helping me write feedback for a 7th grade persuasive essay on starting the school day later, graded against our rubric: a clear claim, two pieces of evidence, and a counterargument. The student's name has been removed. Here is my shorthand assessment: claim is strong and clear, only one piece of evidence and it is an opinion not a fact, no counterargument at all, the writing is lively. Turn this into warm, specific feedback addressed to the student. Open with a genuine strength, name the two gaps concretely with a fix for each, and end with one encouraging next step. Keep it to about 120 words. Do not praise anything I did not list, and do not soften the missing counterargument.","changes":["Supplies the rubric and notes the name was removed, so feedback is tied to what was assessed and student data is protected.","Feeds the teacher's own judgment instead of asking the AI to decide whether the essay is good.","Names the tone, structure, and length wanted, and tells the model not to invent strengths or soften the gap you wanted named plainly."]}$lum$::jsonb, true),
  ($lum$64532f5f-c93a-57a9-a010-c2a18b77d5c5$lum$::uuid, $lum$57ae1d4b-0838-55a8-adbc-716a4de13b1a$lum$::uuid, 11, $lum$multiple_choice$lum$, $lum${"stem":"Your shorthand on a history short-answer is 'identified bank failures as a cause but never explained why that hurt families.' Which instruction added to your prompt best protects the feedback from going wrong?","options":[{"id":"a","label":"Tell the AI to decide if the answer deserves full credit and grade it on a scale of one to ten.","is_correct":false,"explanation":"This hands the AI the judgment that has to be yours. The grade is your call. The AI's job is to phrase the feedback for the call you already made."},{"id":"b","label":"Tell the AI to make the feedback as encouraging as possible so the student feels good no matter what.","is_correct":false,"explanation":"Pushing for maximum encouragement is how you get invented strengths and softened gaps. You want warm and honest, with the missing explanation named plainly."},{"id":"c","label":"Tell the AI to name only the strength I listed, explain the missing link about families, and not add praise I did not write.","is_correct":true,"explanation":"Correct. Constraining the AI to your judgment keeps it from inventing a strength, and asking it to explain the missing mechanism turns your shorthand into something the student can act on."}]}$lum$::jsonb, false),
  ($lum$1198a8f4-8d16-5fb8-994a-ef2be9327b0e$lum$::uuid, $lum$57ae1d4b-0838-55a8-adbc-716a4de13b1a$lum$::uuid, 12, $lum$mini_project$lum$, $lum${"brief":"Take a real set of student work you actually need to grade, even just five pieces, and pick one rubric or assignment they all share. For each piece, read it and write your honest shorthand reaction in a sentence or two, the way you think it rather than the way you would say it to a student. Then strip the student names, hand the AI the rubric plus one student's work plus your shorthand, and ask it to expand your reaction into warm, specific feedback with one real strength, the concrete gaps with a fix for each, and an encouraging next step. Read every note before it goes out, cut any praise the model invented, and put back any plainness it softened. Compare how long this took to your usual pace, and notice whether the students got more specific feedback than they normally would.","parts":[{"id":"1","prompt":"Remove student names from every piece before it touches the AI tool, and use a tool your school has approved for student work."},{"id":"2","prompt":"Write your own one or two sentence judgment for each piece first, so the AI is expanding your assessment and never making it."},{"id":"3","prompt":"Read and correct each expanded note before it goes to a student, fixing invented strengths and restoring anything the model softened."}]}$lum$::jsonb, false),
  ($lum$403c6148-5437-52c8-aa47-2bbab06e3e8f$lum$::uuid, $lum$086b0ab9-8050-523d-aced-d8b4ef392a93$lum$::uuid, 0, $lum$reading$lum$, $lum${"markdown":"The promise of AI in patient communication is specific and real: if the tool handles the structure, the grammar, and the first draft, you get minutes back. The question is what happens to those minutes. This lesson is about making sure they land on patients, not on a longer task list, and about building the habits that keep every message you send sounding like it came from a person who knows and cares about the patient receiving it.\n\n**Use the time AI saves on people, not throughput.**\n\nEvery hour you save on documentation is an hour available for something else. That something else has a default: more charts, more administrative tasks, more items in the queue. The default feels reasonable because the queue is always real and always long. But the clinical case for AI-assisted communication is not throughput. It is presence. When a nurse practitioner in a busy primary care practice uses AI to draft routine follow-up messages in the morning, the gain is not sixteen more patients seen. The gain is that the four patients who called back with questions get an actual conversation instead of a voicemail and a three-day wait. The tool's value is only realized if the time it creates lands on direct patient contact.\n\nThis requires a deliberate choice, not a passive one. If your clinic does not actively redirect saved time toward patients, it will be absorbed into the operational backlog. That is not a technology problem. It is a workflow decision. Before you start using AI for any category of patient message, decide in advance what you are going to do with the time you get back."}$lum$::jsonb, false),
  ($lum$05b8773e-8359-531e-a04c-ddc29c86f821$lum$::uuid, $lum$086b0ab9-8050-523d-aced-d8b4ef392a93$lum$::uuid, 1, $lum$multiple_choice$lum$, $lum${"stem":"According to the reading, what is the clinical case for AI-assisted patient communication?","options":[{"id":"a","label":"Throughput: seeing more patients in the same number of hours.","is_correct":false,"explanation":"The reading explicitly states the case is not throughput. The example of the nurse practitioner makes clear the gain is not sixteen more patients seen."},{"id":"b","label":"Presence: the saved time lands on direct patient contact, like a real conversation instead of a voicemail and a three-day wait.","is_correct":true,"explanation":"Correct. The reading says the value is presence, not throughput, and that the tool's value is only realized if the time it creates lands on direct patient contact."},{"id":"c","label":"Cost reduction: fewer staff hours spent on documentation overall.","is_correct":false,"explanation":"Cost is not the argument made in the reading. The focus is on where the saved minutes go, specifically toward patients rather than the backlog."},{"id":"d","label":"Accuracy: AI drafts contain fewer errors than human-written ones.","is_correct":false,"explanation":"The reading does not claim AI is more accurate. Its point is about redirecting saved time toward patient presence, not about error rates."}]}$lum$::jsonb, false),
  ($lum$48e675cd-2a44-57ea-9162-d3de888980b3$lum$::uuid, $lum$086b0ab9-8050-523d-aced-d8b4ef392a93$lum$::uuid, 2, $lum$reading$lum$, $lum${"markdown":"**Never send a patient message in the AI's default voice.**\n\nAI writes competent, smooth, slightly hollow prose. For a logistics reminder, that may be fine. For anything emotional, hollow is cold, and cold lands badly. Consider the difference between two follow-up messages sent after a cancer screening with an inconclusive result. The first is an AI default: \"We are writing to inform you that your recent screening returned an inconclusive result. Please schedule a follow-up appointment at your earliest convenience.\" The second takes thirty additional seconds to revise: \"Hi Mrs. Reyes, I wanted to reach out personally about your recent screening. The result was inconclusive, which I know sounds worrying, but it does not mean we found something concerning. It means we need a clearer picture. I would like to schedule you for a follow-up in the next two weeks so we can be thorough. Please call us or reply here and we will get that on the calendar.\" Both messages carry the same clinical fact. One reads as care. The other reads as administration.\n\nThe rule is simple: use AI for the structure and the first draft, then add the specific human detail. That means the patient's actual concern, a line that sounds like you, a reassurance only someone who knows the situation can give. A medical assistant who fields six appointment-reminder messages a day can do this efficiently with one brief revision step. The goal is not to rewrite the whole message. The goal is to add the one or two lines that make the patient feel seen."}$lum$::jsonb, false),
  ($lum$c30f3e3c-4411-5fa6-a375-aa71ec387c9e$lum$::uuid, $lum$086b0ab9-8050-523d-aced-d8b4ef392a93$lum$::uuid, 3, $lum$fill_blank$lum$, $lum${"template":"The rule for AI-assisted messages is to use AI for the structure and the {{1}}, then add the specific human {{2}} that makes the patient feel seen.","blanks":[{"id":"1","accept":["first draft","draft","first-draft"],"ideal":"first draft"},{"id":"2","accept":["detail","details","human detail"],"ideal":"detail"}],"explanation":"The reading states the rule plainly: use AI for the structure and the first draft, then add the specific human detail, such as the patient's actual concern, a line that sounds like you, or a reassurance only someone who knows the situation can give."}$lum$::jsonb, false),
  ($lum$a9ab9d69-6cd6-5f8a-ad8f-bf83c8cfbb63$lum$::uuid, $lum$086b0ab9-8050-523d-aced-d8b4ef392a93$lum$::uuid, 4, $lum$reading$lum$, $lum${"markdown":"**Keep the hard conversations human from the start.**\n\nSome moments should not begin with an AI draft at all. A goals-of-care conversation with a family who has been managing a parent's late-stage dementia for two years. A call to a patient who just got a biopsy result that changes everything. A follow-up message after a stillbirth, when a coordinator reaches out to let the family know the care team is thinking of them. These are the core of clinical work. Patients and families can feel when words were outsourced. The clinical coordinator who writes a condolence message by hand, even imperfectly, delivers more care than one who sends a polished AI draft with a generic \"please know we are thinking of you.\"\n\nLet AI help you prepare for hard conversations: organize the points you need to cover, anticipate questions the family is likely to ask, draft a follow-up summary of what was discussed. But the conversation itself, and any message that opens an emotional exchange, starts with you.\n\n**Always do the final human read.**\n\nBefore any AI-assisted message reaches a patient or family, read it once as a person, not as an editor checking for errors. The question is not \"Is this technically correct?\" The question is \"Does this sound like care? Would I want to receive this message about someone in my own family?\" That read takes ten seconds. It is the easiest safeguard in this entire practice to skip, and it is the most worth keeping.\n\nA clinical coordinator at a large oncology clinic built a habit of reading every AI-assisted patient message out loud once before sending. Not to check the grammar. To hear whether it sounded like a person speaking to another person. The messages that passed that test without revision were usually the logistics ones: appointment confirmations, parking instructions, prescription pickup reminders. The messages that needed a revision were almost always the ones that touched something the patient was worried about. That pattern, logistics versus emotional, is a useful guide for where to spend your revision energy.\n\nDone well, AI in patient communication is not a wall between you and the patient. It is the thing that clears enough of the desk so you can be more present, more often, with the part of the work that was always the point: the actual human being in front of you or on the other end of the message."}$lum$::jsonb, false),
  ($lum$abdc8b2d-a0d8-5a93-b887-6f63cd847f7d$lum$::uuid, $lum$086b0ab9-8050-523d-aced-d8b4ef392a93$lum$::uuid, 5, $lum$multiple_choice$lum$, $lum${"stem":"Which of these messages should NOT begin with an AI draft?","options":[{"id":"a","label":"A message telling a family their loved one's condition has worsened and you need to discuss goals of care.","is_correct":true,"explanation":"Correct. Goals-of-care conversations and any message that opens a difficult emotional exchange should start with you, not with an AI draft. AI can help you prepare what to cover, but the words that begin this kind of contact need to be yours. Patients and families feel the difference."},{"id":"b","label":"A routine appointment reminder for a follow-up visit next Tuesday.","is_correct":false,"explanation":"A logistics reminder with no emotional weight is exactly the kind of message AI can draft to save you time. Review it before sending, but this is a good use of the tool."},{"id":"c","label":"A post-discharge instruction sheet for a patient going home after a knee replacement.","is_correct":false,"explanation":"Standard post-discharge instructions are structured and repetitive. An AI draft that you review for clinical accuracy is appropriate here. The key is your review before it goes out."},{"id":"d","label":"A clinic-wide notice about updated phone hours over the holiday weekend.","is_correct":false,"explanation":"An administrative announcement carries no emotional weight for the individual patient. An AI draft is fine. Save your revision energy for the messages that touch something personal."}]}$lum$::jsonb, false),
  ($lum$64f25059-b937-5275-8d2c-ef5ff9e181c4$lum$::uuid, $lum$086b0ab9-8050-523d-aced-d8b4ef392a93$lum$::uuid, 6, $lum$reading$lum$, $lum${"markdown":"**The mistakes that flatten patient communication.**\n\nThe most common errors with AI-assisted patient messaging are not dramatic failures. They are quiet ones: a message that was technically correct but felt like a form letter, a hard conversation that started poorly because the opening words were hollow, a time savings that never reached patients because it was silently absorbed into more documentation. Naming these mistakes makes them avoidable.\n\n**Mistake one: sending an emotional message in the AI's flat default voice.**\n\nMany clinicians run a prompt, read the output, decide it \"looks fine,\" and send it without revision. When the message is a parking reminder, this is probably okay. When the message is a borderline test result, an abnormal screening flag, or any communication a patient has been anxious about, sending the default output means sending something that reads like a form letter at exactly the moment the patient most needs to feel that a person is paying attention. The failure is not the AI output. The output is doing what it is supposed to do. The failure is treating an emotional communication task the same way you treat a logistics task. The fix is one extra step: after the AI draft, ask yourself whether this message touches something the patient is worried about. If it does, revise before sending.\n\n**Mistake two: starting a hard conversation with an AI draft.**\n\nSome clinicians use AI to draft the opening message before a goals-of-care conversation, a serious diagnosis disclosure, or a condolence. The intention is efficiency or preparedness. The result is that the patient or family receives words that were generated, not chosen, at the moment that matters most. A family receiving a message about transitioning a parent to comfort care does not need perfectly structured prose. They need to feel that the clinician writing to them actually thought about them. Starting with an AI draft in these situations is not a time savings. It is a liability, clinically and relationally. Reserve AI drafts for the messages where efficiency is the primary value. Let hard conversations begin with you."}$lum$::jsonb, false),
  ($lum$1add5501-4694-5de2-a714-1aeeecd3d9f6$lum$::uuid, $lum$086b0ab9-8050-523d-aced-d8b4ef392a93$lum$::uuid, 7, $lum$multiple_choice$lum$, $lum${"stem":"A clinical coordinator drafts a message for a patient whose thyroid panel came back slightly elevated, flagged for a repeat in three weeks. She runs the AI prompt, reads the output, decides it looks accurate, and sends it without revision. What is the most likely problem with this approach?","options":[{"id":"a","label":"The AI output will contain clinical errors that only a revision step can catch.","is_correct":false,"explanation":"Clinical accuracy is worth checking, but that is not the central problem described here. The coordinator already read the output and found it accurate. The issue is a different kind of gap."},{"id":"b","label":"The message will likely read as a form letter at the exact moment the patient needs to feel that someone thought about her specifically.","is_correct":true,"explanation":"Correct. A slightly elevated thyroid result with a repeat order is exactly the kind of message a patient will read with anxiety. Sending the AI default voice without revision means sending something that reads like administration, not care, at a moment that calls for reassurance. The fix is a brief revision to add a personal, human layer."},{"id":"c","label":"The coordinator should have used a different AI tool for medical results.","is_correct":false,"explanation":"The tool choice is not the issue here. The issue is the habit of skipping the revision step on emotional or anxiety-adjacent messages, regardless of which tool was used."},{"id":"d","label":"Sending without revision is only a problem if the message contains the patient's name.","is_correct":false,"explanation":"Including a name is one part of personalizing a message, but a message can include a name and still read as a form letter. The issue is whether the message acknowledges the patient's actual emotional situation, not just whether it includes identifying details."}]}$lum$::jsonb, false),
  ($lum$723abb25-57c5-5c65-b271-c8c265f2f8ca$lum$::uuid, $lum$086b0ab9-8050-523d-aced-d8b4ef392a93$lum$::uuid, 8, $lum$reading$lum$, $lum${"markdown":"**Mistake three: letting the time AI saves get absorbed into more charts.**\n\nThis is the most invisible mistake and the most common. When AI-assisted drafting saves a coordinator fifteen minutes a day, those minutes do not automatically become patient contact time. They become available time, and available time fills with the next thing on the list. The fix is intentional: before you start using AI for a task category, decide what you will do with the time it returns. Name a specific patient contact task that gets the time back.\n\n**Mistake four: skipping the final human read.**\n\nThe final read before sending is the simplest and most consistently skipped safeguard. It takes ten seconds. The reason it gets skipped is that a clean, grammatically correct AI draft makes the review step feel redundant. It is not. The final read is not a grammar check. It is a care check: does this message sound like a person, and does it serve this particular patient? That question catches the flat closing line, the clinical jargon that slipped through, and the missing acknowledgment that the patient was worried. Build the habit before you need it.\n\n**A note on privacy.**\n\nIf you are using an AI tool that has not been reviewed and approved for your organization's patient data policy, use de-identified or generic examples when drafting. Use a fictional name or a placeholder, and add the real patient detail yourself before sending. This protects patient privacy while still letting you benefit from the tool."}$lum$::jsonb, false),
  ($lum$9e61ec3d-4b1a-5977-b637-c560cb4fc8e8$lum$::uuid, $lum$086b0ab9-8050-523d-aced-d8b4ef392a93$lum$::uuid, 9, $lum$multiple_choice$lum$, $lum${"stem":"The reading calls letting AI-saved time get absorbed into more charts the most invisible and most common mistake. What does it recommend as the fix?","options":[{"id":"a","label":"Track the exact number of minutes saved each day so you can report them later.","is_correct":false,"explanation":"The reading does not suggest measuring or reporting the minutes. It warns that available time silently fills with the next thing on the list unless you act intentionally."},{"id":"b","label":"Use AI for fewer task categories so less time is saved in the first place.","is_correct":false,"explanation":"Saving less time is the opposite of the goal. The point is to capture the time AI saves and deliberately redirect it, not to avoid saving it."},{"id":"c","label":"Before using AI for a task category, decide what you will do with the time it returns and name a specific patient contact task that gets it back.","is_correct":true,"explanation":"Correct. The reading says the fix is intentional: decide in advance what you will do with the returned time, and name a specific patient contact task that gets it back, so it is not absorbed into the backlog."},{"id":"d","label":"Skip the final human read on logistics messages to save even more time.","is_correct":false,"explanation":"This conflates two separate mistakes. Mistake four warns against skipping the final read, and it is the simplest safeguard to keep. It is not a remedy for absorbed time."}]}$lum$::jsonb, false),
  ($lum$406d5da0-1b20-5094-a6a1-bafa05bc691d$lum$::uuid, $lum$086b0ab9-8050-523d-aced-d8b4ef392a93$lum$::uuid, 10, $lum$before_after$lum$, $lum${"question":"A patient named Mr. Owens sent a message through the portal saying he is worried about his borderline cholesterol result and asking whether he needs to change his diet immediately. He needs a repeat lipid panel in two weeks. Same task, two prompts. Notice where the humanity comes from.","before_prompt":"Write a message to a patient telling them their cholesterol result was borderline and they need to come back for a repeat test in two weeks.","after_prompt":"Help me draft a warm, reassuring portal message to a patient named Mr. Owens who wrote in worried about his borderline cholesterol result. He is asking whether he needs to change his diet right away. The result was borderline, not alarming. We are scheduling a repeat lipid panel in two weeks to be thorough, not because something is clearly wrong. Acknowledge that getting a borderline result when you were expecting to be told everything is fine is stressful. Explain in plain language that borderline means we want more information, not that he has a problem. Keep the tone calm and personal. I will add a specific line about his question on diet myself before sending.","changes":["Names the patient and his actual worry, so the message speaks to the person who wrote in rather than a generic recipient with a generic result.","Tells the AI the emotional job: acknowledge the stress of a result that was not what he expected, and defuse the fear that borderline means bad news.","Reserves the specific diet question for the clinician to answer personally, ensuring the final message contains something only someone who read his actual message could write."]}$lum$::jsonb, true),
  ($lum$d1708fc6-5f4c-59d6-96bf-7d6924363cb0$lum$::uuid, $lum$086b0ab9-8050-523d-aced-d8b4ef392a93$lum$::uuid, 11, $lum$multiple_choice$lum$, $lum${"stem":"Looking at the two prompts in the scenario above, what is the single most important difference between the before prompt and the after prompt?","options":[{"id":"a","label":"The after prompt asks for a longer message.","is_correct":false,"explanation":"Length is not the key variable. A short message can be warm and a long message can still read as a form letter. The meaningful difference is elsewhere."},{"id":"b","label":"The after prompt names the patient's actual worry and gives the AI the emotional job to do, not just the clinical fact to relay.","is_correct":true,"explanation":"Correct. The before prompt tells the AI a clinical fact. The after prompt tells the AI the patient's emotional state, what he is worried about, and what the message needs to accomplish for him. That instruction is what produces a message that sounds like care rather than administration."},{"id":"c","label":"The after prompt uses the patient's name, which is the main factor that makes a message feel personal.","is_correct":false,"explanation":"Using a name is part of personalization, but a message that uses someone's name and still describes only a clinical fact in a flat tone does not feel personal. The name matters less than whether the message acknowledges what the person is actually going through."},{"id":"d","label":"The after prompt avoids including medical information, which makes it safer to send.","is_correct":false,"explanation":"The after prompt does include medical context. The goal is not to remove clinical information but to frame it in a way that serves the patient emotionally. Safety in this context means the human reads and approves before sending, not that clinical content is withheld."}]}$lum$::jsonb, false),
  ($lum$00a08a7e-db91-58ab-8c11-1956ad9dc10a$lum$::uuid, $lum$086b0ab9-8050-523d-aced-d8b4ef392a93$lum$::uuid, 12, $lum$mini_project$lum$, $lum${"brief":"Choose one category of patient message you actually send on a regular basis: borderline result notifications, post-visit follow-ups, appointment reminders for anxious patients, or a similar type. Build a reusable warm-draft prompt for that category, one you can run in under a minute and then revise by hand. Test it on a realistic de-identified example (use a fictional name and generic details if your tool has not been cleared for patient data), and read the output critically for where it sounds generic or flat. Then revise it by hand to add the human layer.","parts":[{"id":"1","prompt":"Write a prompt template for your chosen message category that tells the AI the patient's general emotional context (waiting on a result, coming back after a scare, following up on something they were anxious about), instructs it to keep the tone warm and plain, and explicitly leaves a bracketed placeholder for one specific human detail you will fill in yourself before sending."},{"id":"2","prompt":"Run the prompt on a de-identified example, read the draft out loud once, and revise it by hand to add your personal layer: the patient's actual concern in your own words, a reassurance that reflects the specific situation, or a line that signals a real person read their message."},{"id":"3","prompt":"Write a two-line final-read checklist you will use before sending any AI-assisted patient message, for example: \"Does this sound like a person speaking to a person, not a system sending a notification? Is there one line in here that only someone who read this patient's actual message could have written?\" Keep the checklist somewhere you will actually see it."}]}$lum$::jsonb, false),
  ($lum$bbacf724-200b-590b-abca-b7b8e2c1a52f$lum$::uuid, $lum$72db07d3-9a52-5545-a8e5-3eb81cdd8944$lum$::uuid, 0, $lum$reading$lum$, $lum${"markdown":"Most legal research starts the same uncomfortable way. A matter lands on your desk in an area you are not yet fluent in, and you need to get up to speed fast enough to ask the attorney a smart question or pull the right materials. This is exactly where AI earns its place, and exactly where it can quietly sink you if you ask it to do the wrong job. The whole skill is keeping two roles separate. AI is for orientation. The law is for authority. Hold that line and the tool becomes a genuine research accelerator. Blur it and you end up citing a statute that does not exist.\n\nHere is the safe and effective way to use it, with the kind of work you actually do."}$lum$::jsonb, false),
  ($lum$ac092ef3-c7a3-57d0-8765-9d83cf8051c3$lum$::uuid, $lum$72db07d3-9a52-5545-a8e5-3eb81cdd8944$lum$::uuid, 1, $lum$multiple_choice$lum$, $lum${"stem":"AI explains a legal concept clearly and gives you a tidy list of the 'elements courts look at,' including a specific statute number. How should you use this?","options":[{"id":"a","label":"As orientation to understand the territory and frame sharper questions, then confirm every element, rule, and the statute itself in an authoritative source.","is_correct":true,"explanation":"Correct. Orientation from the tool, authority from the law. The explanation helps you stop starting cold, but the statute number and the elements are exactly the kind of thing AI fabricates or gets outdated, so they get verified in a real source."},{"id":"b","label":"Cite the statute in your memo, since the AI gave a specific number.","is_correct":false,"explanation":"A specific-looking statute number is not evidence it is real or current. AI invents and misstates citations, so none of it is authority until confirmed in the primary source."},{"id":"c","label":"Rely on the elements list because the explanation was clearly written and internally consistent.","is_correct":false,"explanation":"Fluent and consistent is not the same as correct or jurisdiction-specific. The list is a starting map to verify, not a finding."},{"id":"d","label":"Ask the AI which jurisdiction the statute applies to and trust that answer.","is_correct":false,"explanation":"The model does not reliably know your jurisdiction's current law or what changed recently. Jurisdiction and currency are precisely what you confirm in an authoritative database."}]}$lum$::jsonb, false),
  ($lum$c20db193-df08-50bd-bdf1-1019274c59a8$lum$::uuid, $lum$72db07d3-9a52-5545-a8e5-3eb81cdd8944$lum$::uuid, 2, $lum$reading$lum$, $lum${"markdown":"Use it to understand an unfamiliar concept in plain language. Say a tenant walks in upset that a neighbor has been mowing and fencing off a strip of their backyard for years and now claims it. You have heard the phrase adverse possession but you do not work in property disputes. A good first prompt is, \"Explain in plain language how adverse possession generally works, and the main elements courts usually look at.\" In seconds you learn that courts typically weigh things like open and notorious use, continuous possession over a statutory period, and use that is hostile to the owner's rights. Now you know the shape of the problem. You know the words to search and the questions to ask. You are no longer starting from a blank page, and that is the entire point of a first pass.\n\nUse it to frame research questions and build a checklist of angles. Imagine a client whose landlord kept the full security deposit after they moved out of an apartment, claiming vague \"cleaning and damages.\" You can prompt, \"I am researching a landlord-tenant dispute about a withheld security deposit. What are the key issues I should investigate, and what questions should I be asking?\" AI is genuinely good at this. It will surface angles you might want to check, such as whether the state requires the landlord to send an itemized list of deductions within a set number of days, whether failure to do so triggers penalties, whether there are limits on what counts as normal wear and tear, and whether the deposit had to be held in a separate account. That is a useful map of where to dig. It is not a finding. Every one of those angles still has to be confirmed against your state's actual statute and deadlines."}$lum$::jsonb, false),
  ($lum$f7726465-3f22-56fc-b3ef-5efdec8b3da2$lum$::uuid, $lum$72db07d3-9a52-5545-a8e5-3eb81cdd8944$lum$::uuid, 3, $lum$multiple_choice$lum$, $lum${"stem":"You ask AI to surface the key issues in a withheld security deposit dispute and it returns a clean checklist of angles, like itemized-deduction deadlines and limits on normal wear and tear. What have you actually obtained?","options":[{"id":"a","label":"A set of verified findings you can state as the law in your memo.","is_correct":false,"explanation":"The checklist is not a finding. Each angle still has to be confirmed against your state's actual statute and deadlines before it counts as law."},{"id":"b","label":"Confirmation that your state requires an itemized list within a set number of days.","is_correct":false,"explanation":"AI raising that angle does not confirm it applies in your state. Whether the deadline exists and what it is must be checked against the actual statute."},{"id":"c","label":"A useful map of where to dig, with every angle still needing confirmation against your state's actual statute and deadlines.","is_correct":true,"explanation":"Correct. Framing research questions is exactly what AI is good at. The output is a map of angles to investigate, not findings, so each one gets verified in the real statute."},{"id":"d","label":"Nothing useful, since AI cannot help frame research questions.","is_correct":false,"explanation":"AI is genuinely good at framing research questions and surfacing angles you might miss. The value is real; it is just orientation rather than authority."}]}$lum$::jsonb, false),
  ($lum$06203776-8e32-5b32-8733-7543a8a23a4b$lum$::uuid, $lum$72db07d3-9a52-5545-a8e5-3eb81cdd8944$lum$::uuid, 4, $lum$reading$lum$, $lum${"markdown":"Use it to translate dense statutory text into plain English. Paste in a paragraph of a building code or a tax provision written in the usual run-on legal style and ask for a plain-language restatement of what it requires and who it applies to. Picture a provision that reads, \"No lessor shall withhold any portion of a security deposit except for amounts reasonably necessary to remedy tenant defaults in the payment of rent or to repair damages to the premises exclusive of ordinary wear and tear.\" You can ask the tool to restate that in plain words and it will tell you, in effect, the landlord can only keep money for unpaid rent or real damage, not for normal aging of the apartment. This is one of the safer uses because you are giving the tool the authoritative text and asking it only to rephrase what you supplied, not to recall law from memory. You still read the original yourself, but the plain version helps you understand it faster, and it helps you spot the words that matter, like \"reasonably necessary\" and \"ordinary wear and tear,\" which are often where the dispute actually lives.\n\nNow the hard line, and it is not optional. Never treat AI output as legal authority. The tool invents statute numbers that look completely real. It fabricates case names and citations, complete with plausible volume and page numbers, for cases that were never decided. It states rules that sound right but are outdated, or that are correct in one state and flatly wrong in yours, and it does all of this with total confidence and no warning. It does not know what changed last month, and it does not know which jurisdiction governs your matter unless you tell it, and even then you should not trust its answer. A fluent, well-organized, internally consistent response is not evidence that anything in it is true. Consider a paralegal who asks for the filing deadline to answer a complaint and gets a clean, specific number of days. If that number is wrong, a missed deadline can end the case. That risk does not go away because the answer was confident.\n\nSo every rule, citation, deadline, and element you plan to rely on gets verified in an authoritative legal research database or the primary source itself. The workflow fits in one line. AI helps you understand the territory and ask sharper questions, then real legal sources give you the verified answers. Orientation from the tool, authority from the law."}$lum$::jsonb, false),
  ($lum$ea373eed-4574-599e-a544-f9eb607a0257$lum$::uuid, $lum$72db07d3-9a52-5545-a8e5-3eb81cdd8944$lum$::uuid, 5, $lum$multiple_choice$lum$, $lum${"stem":"Which use of AI in this lesson is described as one of the safer ones, and why?","options":[{"id":"a","label":"Asking it to recall the filing deadline for answering a complaint, because deadlines are simple facts.","is_correct":false,"explanation":"That is one of the riskier uses. A confident but wrong deadline can end the case, and the number must be verified in an authoritative source."},{"id":"b","label":"Pasting in a statutory paragraph and asking it to restate that text in plain words, because you supply the authoritative text and ask it only to rephrase, not to recall law from memory.","is_correct":true,"explanation":"Correct. Giving the tool the authoritative text and asking only for a plain-language restatement keeps it from inventing law, which is why this is one of the safer uses. You still read the original yourself."},{"id":"c","label":"Asking it to supply the controlling case names and citations, because it provides volume and page numbers.","is_correct":false,"explanation":"AI fabricates case names and citations with plausible-looking volume and page numbers for cases that were never decided. This is exactly what you must never treat as authority."},{"id":"d","label":"Asking it to confirm which state's law governs, because it answers with confidence.","is_correct":false,"explanation":"Confidence is not evidence. The tool does not reliably know which jurisdiction governs your matter, so this is not a safe use."}]}$lum$::jsonb, false),
  ($lum$fab51669-446a-51e1-bc67-38fae40f7394$lum$::uuid, $lum$72db07d3-9a52-5545-a8e5-3eb81cdd8944$lum$::uuid, 6, $lum$reading$lum$, $lum${"markdown":"The failures in this kind of research are predictable, which is good news, because predictable mistakes are easy to guard against once you can name them. Here are the ones that catch legal professionals most often.\n\nCiting a statute number the AI handed you without confirming it exists and is current. The number will look perfectly formatted and authoritative. That formatting tells you nothing. AI produces citations that point to nothing, or that point to a provision that was repealed or renumbered. Pull it up in your database before it goes anywhere near a memo or a filing.\n\nTrusting a fluent, internally consistent explanation as if it were a finding. When a paragraph reads smoothly and every part agrees with every other part, your brain wants to accept it. But coherence is not accuracy. A confident, tidy answer about the elements of a fraud claim can still be the wrong jurisdiction's version, or simply made up. Treat the explanation as a map of what to verify, never as the verified result.\n\nAssuming the AI knows your jurisdiction's current law. Non-compete rules, security deposit deadlines, and statutes of limitations vary sharply from state to state and change over time. The tool does not know which state governs your matter unless you tell it, and even then it may give you another state's rule or a version that was amended last year. Currency and jurisdiction are exactly the two things you confirm yourself."}$lum$::jsonb, false),
  ($lum$aba59b08-1f74-595a-96f9-b6dca920da25$lum$::uuid, $lum$72db07d3-9a52-5545-a8e5-3eb81cdd8944$lum$::uuid, 7, $lum$multiple_choice$lum$, $lum${"stem":"An AI explanation of the elements of a fraud claim reads smoothly, and every part agrees with every other part. Why is that not a reason to treat it as a finding?","options":[{"id":"a","label":"Because long explanations are always less accurate than short ones.","is_correct":false,"explanation":"Length is not the issue. The point is that coherence, at any length, does not establish accuracy."},{"id":"b","label":"Because a smooth explanation means the AI is guessing and a choppy one means it is confident.","is_correct":false,"explanation":"Writing style does not signal reliability either way. Fluent text can be wrong and is produced with the same confidence as correct text."},{"id":"c","label":"Because internally consistent answers are always fabricated.","is_correct":false,"explanation":"They are not always fabricated. The problem is that you cannot tell from coherence alone, so the explanation must be verified rather than assumed false or true."},{"id":"d","label":"Because coherence is not accuracy; a confident, tidy answer can still be the wrong jurisdiction's version or simply made up, so it is a map of what to verify, not the verified result.","is_correct":true,"explanation":"Correct. Your brain wants to accept smooth, self-consistent text, but coherence does not make it true or jurisdiction-correct. Treat it as a map of what to verify, never as the result."}]}$lum$::jsonb, false),
  ($lum$1b4214dd-4c4a-57c2-af8e-e139da356c96$lum$::uuid, $lum$72db07d3-9a52-5545-a8e5-3eb81cdd8944$lum$::uuid, 8, $lum$reading$lum$, $lum${"markdown":"Pasting confidential matter facts into a public tool while researching. It is tempting to drop in real client names, addresses, and case specifics to get a sharper answer. On a public consumer tool, that can breach client confidentiality and your duty to protect it. Research the general legal concept with the details stripped out, or use a tool your firm has approved for confidential work.\n\nAsking the AI which jurisdiction applies and trusting the answer. Choice of law is itself a legal question, sometimes a hard one. The tool can give you a guess that sounds definite, but where to file or which state's law governs is something you confirm through the actual rules and, when it matters, the supervising attorney. A confident guess on jurisdiction is still a guess.\n\nThe thread running through all five is the same. Confidence is not evidence. The tool's job ends when you have your bearings, and the law's job begins the moment anything needs to be true."}$lum$::jsonb, false),
  ($lum$9a107947-c662-5d8e-b307-3b3f7e1a90fe$lum$::uuid, $lum$72db07d3-9a52-5545-a8e5-3eb81cdd8944$lum$::uuid, 9, $lum$multiple_choice$lum$, $lum${"stem":"While researching a client's security deposit dispute, you want a sharper answer, so you consider pasting the client's name, address, and the landlord's letter into a public AI chatbot. What is the problem?","options":[{"id":"a","label":"Nothing, since the details just help the AI give a more accurate legal answer.","is_correct":false,"explanation":"More detail does not make AI authoritative, and the bigger issue is that putting real client facts into a public tool can breach confidentiality."},{"id":"b","label":"Putting confidential client facts into a public tool can breach client confidentiality, so research the general concept with identifying details stripped out or use a firm-approved tool.","is_correct":true,"explanation":"Correct. You can get oriented on the general legal question without exposing client information. Protect confidentiality first, and reserve real matter facts for tools your firm has approved."},{"id":"c","label":"The only risk is that the AI might be slow with a long letter.","is_correct":false,"explanation":"Speed is not the concern. The real risk is exposing protected client information on a public service."},{"id":"d","label":"It is fine as long as you delete the chat afterward.","is_correct":false,"explanation":"Deleting the chat does not undo the exposure or guarantee the data was not retained or used. Keep confidential facts out of public tools in the first place."}]}$lum$::jsonb, false),
  ($lum$dfd5f6bd-f7b6-5b43-8881-0af0946add09$lum$::uuid, $lum$72db07d3-9a52-5545-a8e5-3eb81cdd8944$lum$::uuid, 10, $lum$try_it_live$lum$, $lum${"instructions":"Use AI to frame a research first pass without treating it as authority. Describe a legal topic you need to get oriented on, or use the sample, and ask for the key issues and questions to investigate. Keep client-identifying details out. Sample: a small business owner asking whether a non-compete clause in an employee's contract is enforceable.","system_prompt":"You are a legal research orientation assistant for paralegals and legal professionals. Given an unfamiliar legal topic, explain the general concept in plain language and produce a structured list of issues to investigate and questions to research. Always state clearly that jurisdiction matters and that every rule and citation must be verified in an authoritative legal source. Never provide citations or claim to state the current law. No em dashes.","ideal_output":"Here is a starting orientation, not legal authority. Non-compete enforceability varies heavily by jurisdiction, so the first thing to confirm is which state's law applies.\n\nKey issues to investigate:\n1. Whether this jurisdiction enforces non-competes at all, since some states restrict or ban them.\n2. The reasonableness factors courts typically weigh, such as duration, geographic scope, and the legitimate business interest being protected.\n3. Whether the employee's role and access to sensitive information affect enforceability.\n4. Any required consideration the employee received in exchange for signing.\n\nQuestions to research in an authoritative source: What is the current statute or case law on non-competes in this jurisdiction? Have any recent changes affected it? Confirm every rule and citation in a real legal database before relying on it.","input_placeholder":"Describe the legal topic you need to get oriented on..."}$lum$::jsonb, true),
  ($lum$affc459f-80b9-565d-8ff1-7b5e7cbd1e51$lum$::uuid, $lum$72db07d3-9a52-5545-a8e5-3eb81cdd8944$lum$::uuid, 11, $lum$multiple_choice$lum$, $lum${"stem":"You run the orientation prompt and the AI returns a clean four-point list of non-compete factors plus a confident statement that your state 'fully enforces' them. What is the right next move?","options":[{"id":"a","label":"Drop the four factors and the 'fully enforces' conclusion straight into your memo, since the answer was specific and organized.","is_correct":false,"explanation":"Specific and organized is not the same as verified or current. Non-compete law varies by state and changes, so none of this is authority yet."},{"id":"b","label":"Treat the factors as a map of what to verify, then confirm in an authoritative source whether your jurisdiction enforces non-competes and what the current rules are.","is_correct":true,"explanation":"Correct. The list tells you what to go check. Whether your state enforces non-competes and on what terms is exactly the jurisdiction-and-currency question you confirm in a real legal source."},{"id":"c","label":"Ask the AI to cite the specific state statute it relied on and use that citation.","is_correct":false,"explanation":"Asking for a citation invites a fabricated one. AI invents real-looking statute numbers, so any citation it offers still has to be confirmed in the primary source before use."}]}$lum$::jsonb, false),
  ($lum$0b9024ea-c61f-55a1-81ca-4557108cf28f$lum$::uuid, $lum$72db07d3-9a52-5545-a8e5-3eb81cdd8944$lum$::uuid, 12, $lum$mini_project$lum$, $lum${"brief":"Pick a legal topic you are not yet fluent in, with any client-identifying details stripped out, and produce a short orientation-and-verification note like one you would hand a supervising attorney. Run the orientation prompt to get the concept in plain language and a list of issues and questions to investigate. Then choose one specific factual claim the tool made, such as a rule, an element, or a filing deadline, and verify that single claim in an authoritative legal source. Your note should make clear what came from orientation and what you actually confirmed.","parts":[{"id":"1","prompt":"Run the orientation prompt on your topic and capture the plain-language concept plus the list of issues and questions to investigate."},{"id":"2","prompt":"Pick one concrete claim it made, a rule, element, or deadline, and verify it in an authoritative legal database or the primary source, recording where you confirmed it."},{"id":"3","prompt":"Write two or three sentences noting where the orientation held up and where relying on it as authority would have led you wrong."}]}$lum$::jsonb, false),
  ($lum$8a44a21d-56f5-5d0e-a988-dfeff9a07848$lum$::uuid, $lum$94ea936d-e667-5bab-94b4-a702f2f4030f$lum$::uuid, 0, $lum$reading$lum$, $lum${"markdown":"Priya is a recruiter at a mid-sized logistics company, and she opened her applicant tracking system on a Monday to find a number she had to read twice. Her req for an operations coordinator, the kind of role that used to draw eighty applicants over two weeks, had four hundred. Not over two weeks. Over the weekend. She started reading, and somewhere around the fortieth cover letter she noticed something stranger than the volume. They were all good. Every letter was clean, every resume mirrored her job description almost line for line, every applicant claimed to be passionate about operational excellence in exactly the way her posting asked for. She could not tell them apart, because the things she used to read for had all gone uniformly excellent.\n\nThis is the flood, and it is worth understanding exactly what changed, because the change is not what it looks like at first. The same tools that help you write a sharp job posting in five minutes help a candidate write a tailored application in thirty seconds. A strong applicant and a weak one can now submit equally polished, perfectly mirrored resumes and cover letters, generated instantly, customized to your exact wording. So two things happen at once. Volume goes up, sometimes by five times or more, because applying costs almost nothing now. And the old signals you leaned on for years, a well-written cover letter, a resume that echoes the job description, a confident paragraph about why this role, stop separating the capable from the merely well-prompted. Polish used to be a rough proxy for effort and competence. Someone who wrote a thoughtful letter had probably thought about the job. That link is broken. Polish has stopped being evidence."}$lum$::jsonb, false),
  ($lum$03dcc364-67f4-5103-b43f-d21f1d712bcf$lum$::uuid, $lum$94ea936d-e667-5bab-94b4-a702f2f4030f$lum$::uuid, 1, $lum$fill_blank$lum$, $lum${"template":"Because AI makes resumes and cover letters look uniformly polished, {{1}} has stopped being evidence of capability, so you should redesign your early screen around verifiable, job-related {{2}} instead.","blanks":[{"id":"1","accept":["polish","presentation","wording quality","wording"],"ideal":"polish"},{"id":"2","accept":["evidence","signals","work samples","skills"],"ideal":"evidence"}],"explanation":"Generated text makes presentation uniformly strong, so polish no longer separates capable candidates from well-prompted ones. The fix is to anchor screening on verifiable, job-related evidence, like a work sample, that AI cannot produce on a candidate's behalf."}$lum$::jsonb, false),
  ($lum$1d3a871c-26b6-5cfe-9245-8702b244d446$lum$::uuid, $lum$94ea936d-e667-5bab-94b4-a702f2f4030f$lum$::uuid, 2, $lum$reading$lum$, $lum${"markdown":"Now watch the instinct that follows, because it is the trap. When the pile gets too big to read, the natural move is to fight fire with fire: point an AI at the four hundred applications and let it rank them, then read the top fifteen. It feels efficient and modern. It is the exact mistake from the screening lesson. The moment you let a tool rank and reject candidates, you have handed a regulated, legally consequential decision to a system you cannot fully explain, one that will quietly scale whatever bias sits in its training and your historical data across all four hundred people at once. You have not solved the flood. You have automated unfairness and made it faster. The volume pressure is real, but it does not justify giving away the evaluative call. It justifies something else entirely.\n\nThe better response is to change what you screen on. This is the whole lesson in one sentence, so sit with it. If wording quality no longer signals capability, stop rewarding wording quality. Stop reading for the polish that everyone now has for free, and start looking for the things AI cannot fake on a candidate's behalf. There are three of them, and they are concrete. First, specific verifiable accomplishments with details that hold up: not \"I improved logistics efficiency\" but a number, a method, a timeframe, and a name you could check. Generated text produces confident generalities. Real experience produces messy, specific details that survive a follow-up question. Second, evidence of the actual skill rather than claims about it. Anyone can write that they are proficient in route optimization. Far fewer can actually solve a small route optimization problem in front of you. Third, answers grounded in genuine experience, the kind where you ask \"tell me about a time the plan fell apart\" and the person who lived it gives you texture and tradeoffs while the person who did not gives you a tidy paragraph that says nothing."}$lum$::jsonb, false),
  ($lum$715b4c85-c73e-5b3b-a160-641468391b87$lum$::uuid, $lum$94ea936d-e667-5bab-94b4-a702f2f4030f$lum$::uuid, 3, $lum$multiple_choice$lum$, $lum${"stem":"Priya's req jumped from 80 to 400 applicants over a weekend, and every cover letter now reads as polished and tailored. What is the soundest response this lesson points to?","options":[{"id":"a","label":"Point an AI at the 400 applications and let it rank and reject them so she can read only the top fifteen.","is_correct":false,"explanation":"This hands a regulated, bias-prone decision to a tool, the exact trap from the screening lesson. Volume pressure does not justify giving away the evaluative call; it justifies screening on better signals."},{"id":"b","label":"Change what she screens on: prioritize verifiable, job-related evidence and a short work sample over wording quality, since polish no longer separates capable from well-prompted.","is_correct":true,"explanation":"Correct. When generated text makes everyone look equally polished, presentation stops being a signal. The fix is anchoring on evidence AI cannot fake on the candidate's behalf, like a relevant work sample and specifics that hold up under a follow-up question."},{"id":"c","label":"Raise the experience requirements on the posting so fewer people qualify to apply.","is_correct":false,"explanation":"Inflating requirements shrinks and skews the pool without improving signal, and it still screens on claims rather than evidence. The issue is what you measure, not how high you set an arbitrary bar."}]}$lum$::jsonb, false),
  ($lum$56c5f25c-66f2-54b4-aa95-ebab21dacb77$lum$::uuid, $lum$94ea936d-e667-5bab-94b4-a702f2f4030f$lum$::uuid, 4, $lum$reading$lum$, $lum${"markdown":"That points to a practical redesign of your early screen. Marcus, a talent acquisition lead at a healthcare staffing firm, did exactly this after his cover-letter screen became useless overnight. He moved the verifiable signals to the front of the funnel. He added a short, relevant work sample, fifteen minutes of the actual job, scored against a simple rubric. He swapped his generic \"why do you want this role\" questions for specific ones whose answers require real knowledge of the work. And he wrote his screening criteria around evidence rather than presentation, so reviewers were rating what a candidate could demonstrate, not how nicely they wrote. These signals are harder to generate convincingly and far more predictive than another flawless paragraph.\n\nNone of this means banning AI from your process. AI can genuinely help you on the administrative side: summarizing applications against your stated requirements, organizing responses so you can compare them, drafting the work sample itself. The single rule that keeps this safe is that the evaluative judgment stays with a person. AI can lay the responses out neatly. It does not decide who advances. The mindset shift is the real takeaway here. The flood is not a reason to trust AI more in your hiring. It is a reason to anchor harder on verifiable, job-related evidence, and to build a process where real capability, not the best prompt, is what moves someone forward. You will read less by weight and more by signal."}$lum$::jsonb, false),
  ($lum$76b10e57-9764-56ff-92c0-27904222f37a$lum$::uuid, $lum$94ea936d-e667-5bab-94b4-a702f2f4030f$lum$::uuid, 5, $lum$multiple_choice$lum$, $lum${"stem":"After his cover-letter screen became useless, Marcus added a fifteen-minute work sample and asked AI to summarize applications against his requirements and organize the responses. Which describes a sound version of this redesign?","options":[{"id":"a","label":"AI handles the administrative work like summarizing and organizing responses, but a person evaluates the evidence and makes every advance-or-not decision.","is_correct":true,"explanation":"Correct. The lesson allows AI on the administrative side, summarizing against requirements, organizing responses, even drafting the work sample, as long as the evaluative judgment stays with a person who decides who advances."},{"id":"b","label":"Because AI organized the responses neatly, it can also decide who advances, since it has already seen every application.","is_correct":false,"explanation":"Laying responses out neatly is administrative help, not evaluation. The single rule that keeps this safe is that AI does not decide who advances; that judgment stays with a person."},{"id":"c","label":"Adding a work sample means he should drop the human review entirely to save time, since the rubric now does the work.","is_correct":false,"explanation":"A rubric structures the human's judgment; it does not replace it. The point of the redesign is to have a person rate demonstrated evidence, not to remove the person from the loop."}]}$lum$::jsonb, false),
  ($lum$b25c278d-e23d-5779-ba42-ea54ddb0a0da$lum$::uuid, $lum$94ea936d-e667-5bab-94b4-a702f2f4030f$lum$::uuid, 6, $lum$reading$lum$, $lum${"markdown":"The redesign sounds clean on paper, so it helps to see where it goes wrong in practice, because good intentions slide back into old habits fast.\n\nThe most common failure is fake delegation. A hiring manager tells you the human stays in charge, then builds a workflow where the AI scores every applicant one to ten and the human \"reviews\" by rubber-stamping the top of the list. That is not human judgment. That is the AI deciding while a person watches. If the tool produces the ranking and you almost never overturn it, the tool is making the call, with all the bias risk intact. Keeping judgment with a person means a person actually evaluates the evidence, not that a person signs off on the machine's verdict.\n\nThe second mistake is building a work sample that AI can ace from the couch. If your \"sample\" is \"write a short paragraph about how you would approach this role,\" you have just recreated the cover letter you were trying to escape, and a candidate will paste it into a chatbot in ten seconds. A good work sample asks for the actual doing: read this messy shipment manifest and find the three errors, draft a reply to this annoyed client, prioritize these five tickets and explain your order. Real work, ideally with materials specific enough that a generic generated answer falls flat. The point is not to make it impossible to use AI. The point is to make the answer require knowledge or reasoning the candidate must actually have."}$lum$::jsonb, false),
  ($lum$911c83fa-eea8-556d-927e-db088c9cd4a4$lum$::uuid, $lum$94ea936d-e667-5bab-94b4-a702f2f4030f$lum$::uuid, 7, $lum$multiple_choice$lum$, $lum${"stem":"A team wants a work sample that resists generated answers. Their current draft asks candidates to 'write a short paragraph about how you would approach this role.' Why is that draft weak, and what fixes it?","options":[{"id":"a","label":"It is too short; making the paragraph longer would force candidates to reveal more genuine capability.","is_correct":false,"explanation":"Length is not the problem. A longer open-ended paragraph is just as easy to generate; it still rewards wording over demonstrated work."},{"id":"b","label":"Nothing is wrong; asking how someone would approach the role is the actual doing the lesson recommends.","is_correct":false,"explanation":"Describing an approach in prose is not doing the work. It recreates the cover letter the team was trying to escape, which a candidate can paste into a chatbot in seconds."},{"id":"c","label":"It just recreates the cover letter and is trivial to generate; replace it with the actual doing on specific materials, like finding three planted errors in a messy shipment manifest.","is_correct":true,"explanation":"Correct. A good work sample asks for real work on materials specific enough that a generic generated answer falls flat, so the answer requires knowledge or reasoning the candidate must actually have."}]}$lum$::jsonb, false),
  ($lum$36e5a2c0-fea0-57ce-a04c-d3aee806262c$lum$::uuid, $lum$94ea936d-e667-5bab-94b4-a702f2f4030f$lum$::uuid, 8, $lum$reading$lum$, $lum${"markdown":"The third trap is asking questions whose answers are easy to generate. \"Tell me about your greatest strength\" produces a flawless, meaningless paragraph from anyone. \"Walk me through a specific time a route or schedule fell apart on you, what you did in the first hour, and what you would do differently\" pulls for lived texture that generated text struggles to fake. Specific, experience-anchored, follow-up-able questions beat open invitations to perform every time.\n\nThe fourth mistake is overcorrecting into suspicion, treating every applicant as a suspected cheater and turning your process into an interrogation. That poisons candidate experience and pushes good people away, including the strong ones who have other offers and no patience for a process that feels like a trap. You are not trying to catch liars. You are trying to surface real signal. Design for evidence, keep the bar clear, stay warm, and let the strong candidates show you what they can do.\n\nOne last quiet failure ties them all together: redesigning the screen, then never checking whether it works. Marcus, the talent acquisition lead, did not just add a work sample and walk away. He looked back after a few hires to see whether the people who scored well on the sample were actually the ones succeeding in the role. If your new signals do not predict on-the-job performance any better than the old polish did, you have added effort without adding accuracy. Treat the redesign as something you tune against real outcomes, not a one-time fix you set and forget."}$lum$::jsonb, false),
  ($lum$984afe29-5fc1-51fe-9704-1a6b5050e325$lum$::uuid, $lum$94ea936d-e667-5bab-94b4-a702f2f4030f$lum$::uuid, 9, $lum$multiple_choice$lum$, $lum${"stem":"Marcus added a work sample and specific questions, then went back after a few hires to check whether high scorers were actually succeeding in the role. Why does this final step matter?","options":[{"id":"a","label":"It lets him treat every applicant as a suspected cheater, which is the safest stance once volume is high.","is_correct":false,"explanation":"Overcorrecting into suspicion is itself a named mistake; it poisons candidate experience and pushes strong people away. Checking outcomes is about accuracy, not policing applicants."},{"id":"b","label":"If the new signals do not predict on-the-job performance better than the old polish did, he has added effort without adding accuracy, so the screen must be tuned against real outcomes.","is_correct":true,"explanation":"Correct. A redesign is something you tune against real outcomes, not a one-time fix you set and forget. Validating that high scorers actually succeed is how you confirm the new signals earn their place."},{"id":"c","label":"It proves the work sample can now replace the human reviewer entirely, since the data has validated it.","is_correct":false,"explanation":"Checking outcomes refines the signals; it never hands the evaluative call to the tool. The human still evaluates the evidence and decides who advances."}]}$lum$::jsonb, false),
  ($lum$c2c844c3-103c-5179-bb08-1e90630b4500$lum$::uuid, $lum$94ea936d-e667-5bab-94b4-a702f2f4030f$lum$::uuid, 10, $lum$try_it_live$lum$, $lum${"instructions":"Pick one real high-volume role you screen for and name it. Then ask the AI to design a verifiable early screen for it. For example: 'Design an early screen for an operations coordinator role. The genuine must-have skills are spotting data errors in shipment manifests and writing clear client replies.' Use the model answer below to judge whether your result gives you a real work sample and specific questions, not another way to rank people.","system_prompt":"You are helping a non-technical HR professional design a verifiable early screening stage for a role they name, in response to AI inflating application volume and polish. Your job is to design process and signals only. You must NEVER rank, score, shortlist, or reject candidates, and you must NEVER suggest the AI make the advance-or-not decision; the human reviewer always makes the evaluative judgment. Ask for the role and its genuine must-have skills if not given. Then propose: one short, relevant work sample (about fifteen minutes of the actual job, using realistic materials a generic generated answer would fail) with a simple evidence-based rubric; two or three specific questions whose answers require real experience rather than confident generalities; and screening criteria tied to demonstrated evidence rather than presentation. Keep it practical and warm. No em dashes.","ideal_output":"Role: operations coordinator. Genuine must-have skills: spotting data errors in shipment data, and writing a clear client reply. Here is an early screen built on evidence a candidate cannot generate for free. Work sample, about fifteen minutes: send a short, realistic shipment manifest that contains three planted errors (a mismatched weight, a duplicate order number, and a delivery date before the ship date). Ask the candidate to find the errors and write a two-line note to the warehouse explaining each one. Rubric: did they find each specific error (3 points), and is the note clear and correct (2 points). A generic AI answer will miss the planted specifics because the manifest is yours. Specific questions: first, walk me through a real time a delivery schedule fell apart, what you did in the first hour, and what you changed afterward. Second, describe a system or spreadsheet you actually set up to track something, and one thing about it you would do differently now. Screening criteria: rate demonstrated accuracy on the sample and the concrete detail in the answers, not how polished the writing is. A human reviewer scores every sample and reads every answer. I do not rank, score, or reject anyone; that judgment stays with you.","input_placeholder":"Name your role and its real must-have skills, e.g. operations coordinator: catch data errors, write clear client replies"}$lum$::jsonb, true),
  ($lum$8842cdef-b3a0-5d60-a2c1-59664ef36c17$lum$::uuid, $lum$94ea936d-e667-5bab-94b4-a702f2f4030f$lum$::uuid, 11, $lum$multiple_choice$lum$, $lum${"stem":"A hiring manager says a person stays in charge, but his workflow has the AI score all 400 applicants one to ten and he approves the top of the list almost every time. What is the problem?","options":[{"id":"a","label":"Nothing is wrong; a human is reviewing the AI's output, so judgment stays with a person.","is_correct":false,"explanation":"If the AI produces the ranking and the human almost never overturns it, the tool is effectively making the decision. Watching a machine's verdict is not the same as a person evaluating the evidence."},{"id":"b","label":"The work sample is too long, so candidates will abandon it before finishing.","is_correct":false,"explanation":"Sample length is a real design concern, but it is not the issue here. The failure in this scenario is that the AI, not the person, is effectively deciding who advances."},{"id":"c","label":"This is fake delegation: the AI is really making the call while the human rubber-stamps it, so the regulated decision and its bias risk have been handed to the tool.","is_correct":true,"explanation":"Correct. Keeping judgment with a person means a person actually evaluates the evidence, not that they sign off on the machine's ranking. A rubber-stamp leaves all the bias and accountability risk of automated ranking in place."}]}$lum$::jsonb, false),
  ($lum$27e17d4e-3341-53b8-bad7-14c382c73463$lum$::uuid, $lum$94ea936d-e667-5bab-94b4-a702f2f4030f$lum$::uuid, 12, $lum$mini_project$lum$, $lum${"brief":"Take one real high-volume role you own and audit what your early screen currently rewards. If it leans on cover-letter quality or how closely a resume mirrors the posting, those signals are now easy to generate and no longer tell you much. Redesign the first stage around evidence AI cannot fake for a candidate, using AI only to draft materials and organize responses while you keep every advance-or-not call. The goal is a funnel where real capability, not the best prompt, is what moves a candidate forward.","parts":[{"id":"1","prompt":"Draft a short, relevant work sample, about fifteen minutes of the actual job, that uses specific materials a generic generated answer would fail, and write a simple rubric scoring demonstrated evidence rather than polish."},{"id":"2","prompt":"Replace two generic questions with specific, experience-anchored ones whose answers require real knowledge, and note the follow-up you would ask to test for lived detail."},{"id":"3","prompt":"Write down exactly where AI helps (summarizing against requirements, organizing responses) and confirm in one sentence that a named human makes every evaluative decision."}]}$lum$::jsonb, false),
  ($lum$618b8b29-bc77-5930-a4f6-d4db38df0e43$lum$::uuid, $lum$8af17bac-51a5-5c21-9b9d-35c48b75aa32$lum$::uuid, 0, $lum$reading$lum$, $lum${"markdown":"Performance reviews fail in a predictable way, and once you see the pattern you cannot unsee it. Under time pressure, a manager sits down with twelve reviews due Friday and reaches for the phrases that come fastest: \"strong communicator,\" \"needs to be more proactive,\" \"exceeds expectations,\" \"great team player.\" These feel safe and say almost nothing. The employee reads \"needs to be more proactive\" and has no idea what to change on Monday morning. Be proactive about what? In which meeting? Compared to whom? The phrase points at a vague impression, not an action.\n\nVague language causes three specific problems, and they stack. The first is that the employee cannot act on it. Feedback that does not name a behavior cannot be repeated or corrected, so the person stays exactly where they were, and next quarter you write the same recycled line again. The second is that it does not hold up if a decision is ever questioned. If that review feeds a promotion you gave or a raise you withheld, and someone asks you to explain the basis, \"needs to be more proactive\" is not a basis. It is a feeling wearing a tie. The third, and the most serious, is that vague language is where bias hides. Unexamined impressions, who reminds you of yourself, who you find easy to like, slide in under cover of phrases like \"not quite leadership material\" or \"a bit rough around the edges.\" Specific, behavior-based language forces those impressions into the open, where you can check whether they are fair. That is precisely why the lazy phrase feels more comfortable: it never makes you prove your case."}$lum$::jsonb, false),
  ($lum$6017a3a2-7746-5ed7-b342-2e09e9c34188$lum$::uuid, $lum$8af17bac-51a5-5c21-9b9d-35c48b75aa32$lum$::uuid, 1, $lum$multiple_choice$lum$, $lum${"stem":"Dana writes 'needs to be more proactive' in Priya's review. Beyond being vague, why is this phrase a real risk for the organization?","options":[{"id":"a","label":"It is too positive, so Priya will assume she has nothing to work on this quarter.","is_correct":false,"explanation":"The phrase is framed as a criticism, not praise, so over-positivity is not the issue. The problem is that it gives no behavior to act on and offers no defensible basis."},{"id":"b","label":"It gives Priya nothing to act on, would not hold up if the review were ever questioned, and is the kind of vague phrase where unexamined bias can hide.","is_correct":true,"explanation":"Correct. Vague language stacks three problems: the employee cannot change what is not named, the manager cannot defend a decision built on a feeling, and unexamined impressions slip in under cover of imprecise phrasing."},{"id":"c","label":"It uses the wrong tense and should be rewritten in the past tense to describe last quarter.","is_correct":false,"explanation":"Grammar and tense are not the issue. Even in flawless past tense, 'was not proactive enough' still names no behavior, defends no decision, and hides the same impressions."}]}$lum$::jsonb, false),
  ($lum$9270f931-c038-5756-bdb7-c63cce039fa6$lum$::uuid, $lum$8af17bac-51a5-5c21-9b9d-35c48b75aa32$lum$::uuid, 2, $lum$reading$lum$, $lum${"markdown":"So the fix is known. Tie every statement to an observed behavior and its impact. \"She led the Q3 campaign launch and hit the deadline despite a vendor delay by reworking the timeline herself\" is something the employee can recognize, repeat, and be proud of. It is also something you can defend to anyone who asks. The catch is that writing this way is slow. Naming the example, recalling the impact, phrasing it cleanly and constructively, across a whole team, takes real time you do not have during review season. So the specific version gets skipped, and the vague version wins by default. This is not a character flaw in managers. It is a time problem.\n\nThis is exactly where AI earns its place, and it comes with one firm condition that you should write on a sticky note: it works FROM your observations, never IN PLACE OF them. You supply the real examples and your honest judgment. The model turns your rough, messy notes into clear, specific, professionally worded feedback that names the example and its impact. Picture Dana, a team lead writing a quarterly review for Priya, a marketing coordinator, at 9 p.m. with the deadline tomorrow. Dana types her real notes the way she would mutter them to herself: \"led Q3 launch, hit deadline even though the vendor was late, reworked the timeline alone. Solid on execution. Growth area: waits to be asked before flagging concerns, so the budget risk surfaced late.\" Then she gives the model a clear instruction. \"Turn each of these points into specific, behavior-based feedback that names the example and its impact, written constructively. Keep my assessment intact. Do not soften it, do not inflate it, and do not add any example I did not give you.\""}$lum$::jsonb, false),
  ($lum$ce5728e5-7e60-50bb-8d34-5009a60a809c$lum$::uuid, $lum$8af17bac-51a5-5c21-9b9d-35c48b75aa32$lum$::uuid, 3, $lum$fill_blank$lum$, $lum${"template":"The reason the specific version of feedback so often gets skipped is that it is {{1}} to write, which makes vague language win by default. AI helps because it works FROM your observations and {{2}} in place of them.","blanks":[{"id":"1","accept":["slow","slower","time-consuming","time consuming"],"ideal":"slow"},{"id":"2","accept":["never","not","never works"],"ideal":"never"}],"explanation":"Writing specific, example-plus-impact feedback across a whole team is slow, so under deadline the vague version wins by default. The firm condition on using AI is that it works from your observations and never in place of them: you still supply the examples and judgment."}$lum$::jsonb, false),
  ($lum$31edc959-bde3-5b79-9f06-c3e423e558d3$lum$::uuid, $lum$8af17bac-51a5-5c21-9b9d-35c48b75aa32$lum$::uuid, 4, $lum$reading$lum$, $lum${"markdown":"What comes back reads like the review Dana wanted to write and did not have ninety minutes to phrase. The execution note becomes a clear paragraph that credits the timeline rework and the on-time delivery. The growth area becomes a constructive forward action: \"When you spot a budget or timeline risk, raise it early rather than waiting to be asked, so the team can adjust while there is still room to act.\" The substance, the rating, the examples, the judgment, every bit of it is Dana's. The model only did the wording. That is the whole trick, and it is a real time saver, because phrasing is the slow part and judgment is the fast part for someone who actually watched the work happen.\n\nNotice what this does for an HRBP coaching managers, too. When Marcus, an HR business partner, sits with a manager who keeps writing \"she's a strong communicator,\" he is not really fighting the manager's opinion. He is fighting the blank page and the clock. Pointing the manager toward this workflow, dump your honest notes, let the model phrase them, then check the result, gives the manager a way to be specific without spending the night on it. The coaching shifts from \"be more specific, somehow\" to \"here is a repeatable way to be specific in the time you have.\" That is a far easier ask, and it is one managers actually adopt because it removes the cost that made them vague in the first place.\n\nThe judgment stays human because the consequences are human. A review can move a salary, decide a promotion, or sit in a file that someone reads a year from now. The words have to be both fair and true, and no tool can carry that weight for you. AI gives you back the time the careful wording used to cost. What you do with that time, looking hard at whether your feedback is fair, is the part that is yours and only yours."}$lum$::jsonb, false),
  ($lum$bdd77c12-e357-5f53-8007-0028dfb709fa$lum$::uuid, $lum$8af17bac-51a5-5c21-9b9d-35c48b75aa32$lum$::uuid, 5, $lum$multiple_choice$lum$, $lum${"stem":"After the model turns Dana's notes into polished review language, which part of the work still belongs to Dana and cannot be handed off?","options":[{"id":"a","label":"The wording, because only the model can phrase feedback in clean, professional language.","is_correct":false,"explanation":"This reverses the division of labor. Wording is exactly the slow part the model handles well. What stays human is the substance and the fairness check."},{"id":"b","label":"Nothing meaningful, since the draft comes back polished and ready to sign as soon as it reads well.","is_correct":false,"explanation":"A polished draft is the starting line, not the finish line. The consequences of a review are human, so the judgment and fairness check cannot be delegated to the tool."},{"id":"c","label":"The judgment, the rating, the examples, and the fairness check, because the consequences are human and no tool can carry that weight.","is_correct":true,"explanation":"Correct. The model only did the wording. The substance, the rating, the examples, and the hard look at whether the feedback is fair stay with Dana, because a review can move a salary or decide a promotion."}]}$lum$::jsonb, false),
  ($lum$aecce56e-4f7d-5f69-997e-b638c2fc7620$lum$::uuid, $lum$8af17bac-51a5-5c21-9b9d-35c48b75aa32$lum$::uuid, 6, $lum$reading$lum$, $lum${"markdown":"The workflow is simple, so most of the ways it goes wrong come from quietly handing the AI a job that was never supposed to leave your hands. Watch for these.\n\nThe first and worst mistake is letting the model generate the assessment itself. A tired team lead types \"write a strong performance review for a solid marketing coordinator\" and pastes the result straight in. It reads smoothly and it is worthless, because it is built from a generic idea of \"solid coordinator,\" not from anything Priya actually did. It will praise strengths she may not have and miss the timeline rework that was her best work all quarter. Worse, generic boilerplate is exactly the kind of detached, one-size-fits-all language that treats people unfairly, because it never looks at the person. The rule holds with no exceptions: if the AI is inventing the evaluation, you have already lost. It must work from your specifics.\n\nThe second mistake is skipping the fairness and accuracy pass because the draft looks polished. Polish is seductive. A clean, confident paragraph feels finished, so you stop reading critically. But the model can quietly drift: it may add an example you never gave it (\"consistently mentored junior staff\" when you said nothing of the kind), or inflate \"hit the deadline\" into \"delivered flawless, industry-leading results.\" Both are now false statements in a document with career consequences. Read every sentence and ask: did I actually observe this? If you did not give it to the model, it does not belong in the review."}$lum$::jsonb, false),
  ($lum$98b4a1ca-50f5-504f-8933-76e136e58dc1$lum$::uuid, $lum$8af17bac-51a5-5c21-9b9d-35c48b75aa32$lum$::uuid, 7, $lum$multiple_choice$lum$, $lum${"stem":"A team lead drafts notes-to-language with AI, and the result says Priya 'consistently mentored junior staff this quarter.' The lead never observed or wrote anything about mentoring. What should happen?","options":[{"id":"a","label":"Keep it, since it is positive and a polished review should highlight as many strengths as possible.","is_correct":false,"explanation":"It is a fabricated example. Positive or not, a claim the manager never observed has no place in a document with career consequences, and including it makes the whole review less trustworthy."},{"id":"b","label":"Soften it to 'has shown some mentoring potential' so it is less of an overstatement.","is_correct":false,"explanation":"Softening an invented claim still leaves an invented claim. The issue is not the strength of the wording; it is that the behavior was never observed. It should be removed entirely."},{"id":"c","label":"Cut it, because the model added an example the manager never gave it, and the fairness pass exists to catch exactly this.","is_correct":true,"explanation":"Correct. AI works from your observations only. An example you did not supply is a fabrication, and reading every line to confirm it traces to something you actually saw is the whole point of the accuracy check."}]}$lum$::jsonb, false),
  ($lum$0b649d52-4ab3-58ab-8128-8f808bb1da17$lum$::uuid, $lum$8af17bac-51a5-5c21-9b9d-35c48b75aa32$lum$::uuid, 8, $lum$reading$lum$, $lum${"markdown":"The third mistake is letting the language slide from behavior toward personality. \"Raised the budget risk late\" is a behavior Priya can change. \"Is not a natural leader\" is a verdict on who she is, and it is neither fair nor useful. Models will sometimes reach for personality framing because it sounds evaluative. Catch it and pull it back to what the person did and what resulted.\n\nThe fourth mistake is inconsistent tone across the team. Because you write each review separately, sometimes on different days and in different moods, the model can phrase the same level of performance more warmly for one person and more coolly for another. Marcus, the HRBP, sees this constantly: two coordinators who performed the same get reviews that read very differently, and the gap usually tracks who the manager likes. After drafting, line your reviews up side by side and check that comparable performance gets comparable language. The fix is reading them as a set, not one at a time.\n\nThe last mistake is treating the polished draft as the finish line. It is the starting line. The model gives you a strong first phrasing; your judgment, your fairness check, and your edits are what make it ready to sign. The tool saved you the slow part. It did not take over the part that matters."}$lum$::jsonb, false),
  ($lum$cbe8db1d-7d8e-5d4b-bab2-239f6c7cca6a$lum$::uuid, $lum$8af17bac-51a5-5c21-9b9d-35c48b75aa32$lum$::uuid, 9, $lum$multiple_choice$lum$, $lum${"stem":"Marcus lines up two coordinators' reviews and notices the same level of performance reads much warmer for one than the other, and the gap tracks who the manager likes. Together with the 'not a natural leader' phrasing he also caught, which two mistakes is he seeing?","options":[{"id":"a","label":"Letting the AI generate the assessment, and skipping the accuracy pass.","is_correct":false,"explanation":"Neither fits. The notes were the manager's own, and the concern here is not a fabricated example but personality framing plus uneven tone across people."},{"id":"b","label":"Letting language slide from behavior toward personality, and inconsistent tone across the team that gives comparable performance different language.","is_correct":true,"explanation":"Correct. 'Not a natural leader' is a verdict on who she is rather than a changeable behavior, and warmer-versus-cooler phrasing for equal performance is the inconsistent-tone trap that reading reviews as a set is meant to catch."},{"id":"c","label":"Treating the polished draft as the finish line, and using the wrong tense throughout.","is_correct":false,"explanation":"Tense is never the issue in this lesson, and finishing too early is a separate mistake. What Marcus spotted is personality framing and uneven tone across people."}]}$lum$::jsonb, false),
  ($lum$1e214095-1548-5932-a435-0322c37d4b12$lum$::uuid, $lum$8af17bac-51a5-5c21-9b9d-35c48b75aa32$lum$::uuid, 10, $lum$before_after$lum$, $lum${"question":"You want AI's help writing Priya's quarterly review. Which prompt produces specific, fair feedback instead of vague boilerplate?","before_prompt":"Write a performance review for a marketing coordinator who is a good employee but could improve a bit.","after_prompt":"Turn my rough notes into specific, behavior-based review language. Keep my assessment intact: do not inflate it, do not soften it, and do not add any example I did not give you. For each point, name the specific example and its impact, and phrase the growth area as a constructive forward action. My notes: led the Q3 campaign launch and hit the deadline despite a vendor delay by reworking the timeline herself. Strong on execution. Growth area: tends to wait to be asked before raising concerns, so a budget risk surfaced late.","changes":["Supplies real observed examples instead of asking the AI to invent a review for a generic 'good employee.'","Bars the model from inflating, softening, or fabricating, so the manager's assessment stays intact.","Asks for example-plus-impact phrasing and frames the growth area as a forward action, which is what makes feedback specific, fair, and actionable."]}$lum$::jsonb, true),
  ($lum$21286860-a261-515c-aae8-64459260c3ff$lum$::uuid, $lum$8af17bac-51a5-5c21-9b9d-35c48b75aa32$lum$::uuid, 11, $lum$multiple_choice$lum$, $lum${"stem":"Marcus, an HRBP, is coaching a manager who keeps writing 'she's a strong communicator' in reviews. What is the most useful way to use AI here?","options":[{"id":"a","label":"Have the manager dump honest notes about specific things the person did, let the model phrase them into behavior-based language, then check the result for fairness and accuracy.","is_correct":true,"explanation":"Correct. The manager was vague because specificity is slow, not because they lacked an opinion. AI removes the time cost of careful phrasing while the manager keeps supplying the examples and doing the fairness check."},{"id":"b","label":"Have the manager ask the AI to 'make the review more specific and professional' without adding any examples.","is_correct":false,"explanation":"With no real examples to work from, the model can only invent specifics or repackage the same vagueness. Specificity has to come from the manager's observations, not from a polish request."},{"id":"c","label":"Tell the manager to stop using AI entirely and write every review by hand to stay authentic.","is_correct":false,"explanation":"That puts back the exact time cost that made the manager vague in the first place. Used correctly, AI handles the slow wording while the human keeps the judgment, which is what makes the manager actually adopt specificity."}]}$lum$::jsonb, false),
  ($lum$b915143b-749d-583d-90ff-e4371780666e$lum$::uuid, $lum$8af17bac-51a5-5c21-9b9d-35c48b75aa32$lum$::uuid, 12, $lum$mini_project$lum$, $lum${"brief":"Take a real review you need to write, or practice on one you wrote recently. Start by jotting your honest, rough notes about the person the way you would say them out loud: specific things they did, each with the example and its impact, including at least one genuine growth area. Hand the AI your notes and ask it to turn each point into specific, behavior-based language without inflating, softening, or inventing anything, framing any growth area as a constructive forward action. Then run the fairness pass before you trust a word of it, and notice how much sharper and more useful the result is than the vague version you would have written under deadline.","parts":[{"id":"1","prompt":"Confirm every statement traces to something you actually observed, and cut any example you did not supply."},{"id":"2","prompt":"Check that the feedback targets behavior and results rather than personality, rewriting any verdict-on-the-person back into a describable action."},{"id":"3","prompt":"Compare the tone against how you would phrase the same performance for a different team member, and even out any gap so comparable work gets comparable language."}]}$lum$::jsonb, false),
  ($lum$dc702f89-945c-5bdd-93bb-e9b51e1a37f4$lum$::uuid, $lum$8a622838-3935-540c-96d7-468f3b67b0da$lum$::uuid, 0, $lum$reading$lum$, $lum${"markdown":"There is a quiet risk in using AI well. The better it gets at drafting documentation and summarizing charts, the more tempting it becomes to let it creep into the part of your work that must stay yours: the clinical judgment. The danger is not that AI gives you a wrong answer you catch. The danger is that it gives you a fluent, confident answer that subtly shapes what you think before you have done your own thinking.\n\n**Form your own assessment first, then let AI help with the words.**\n\nThe order matters more than anything else in this lesson. If you read the patient, reach your own clinical impression, and then ask AI to help you write it up clearly, the tool is doing its job. If you ask AI what it thinks is going on and then build your impression around its answer, you have handed over the one thing you cannot delegate. Think first. Draft second.\n\nHere is what that looks like in practice. A 68-year-old woman with a documented heart failure history comes in reporting worsening shortness of breath over three days. Before you open any AI tool, you note the bibasilar crackles, the two-plus pitting edema at the ankles, the subtle weight gain since her last visit, and the fact that she mentions she ran out of furosemide four days ago. That cluster is your impression. It came from your training, your examination, and your read of the pattern. Now you can ask AI to help you write a structured note that documents those findings clearly. You are not asking it what is going on. You already know. You are asking it to help you say it precisely.\n\nIf you had opened with \"Here is her chart, what is most likely going on?\", the tool would have answered. It might even have said heart failure exacerbation, which in this case would be correct. But you would have confirmed your thinking against the AI's output rather than the other way around. Over time, that inversion is the problem."}$lum$::jsonb, false),
  ($lum$22933bd0-15ce-5ec2-b2e2-43582831df92$lum$::uuid, $lum$8a622838-3935-540c-96d7-468f3b67b0da$lum$::uuid, 1, $lum$multiple_choice$lum$, $lum${"stem":"According to this section, what is the correct order of operations when using AI on a patient you are evaluating?","options":[{"id":"a","label":"Ask AI what is most likely going on, then confirm your own thinking against its answer.","is_correct":false,"explanation":"This is the inversion the section warns against. Confirming your thinking against the AI's output hands over the one thing you cannot delegate, even when the AI happens to be right."},{"id":"b","label":"Reach your own clinical impression first, then ask AI to help you write it up clearly.","is_correct":true,"explanation":"Correct. Think first, draft second. You form the impression from your training and examination, and AI helps you say it precisely. The order matters more than anything else in this lesson."},{"id":"c","label":"Let AI and your own judgment run in parallel and pick whichever conclusion sounds more confident.","is_correct":false,"explanation":"A fluent, confident AI answer is exactly what subtly shapes your thinking before you have done your own. Confidence is not a tiebreaker. Your assessment comes first, on its own."},{"id":"d","label":"Skip your own impression for routine cases and reserve independent reasoning for complex ones.","is_correct":false,"explanation":"The section treats forming your own assessment first as the non-negotiable order every time, not a step you drop on cases that look routine. Routine-looking cases are where anchoring slips in unnoticed."}]}$lum$::jsonb, false),
  ($lum$8466240e-0626-5549-862e-302381ba2638$lum$::uuid, $lum$8a622838-3935-540c-96d7-468f3b67b0da$lum$::uuid, 2, $lum$reading$lum$, $lum${"markdown":"**Treat every AI suggestion as a question, not a conclusion.**\n\nWhen a summary says \"patient likely stable\" or an output hints toward a particular diagnosis, that is not a finding. It is a fluent guess from a tool that cannot examine anyone, cannot hear a lung, and cannot notice that the patient looks more tired than her chart suggests. Let it prompt you to check something, never to skip checking. The right internal response to any AI clinical claim is: \"Is that actually true?\" Then you go confirm it the way you always would.\n\nConsider a different scenario. A clinical coordinator is preparing for a post-discharge follow-up call with a 74-year-old man who was admitted for a COPD exacerbation. She asks an AI to summarize the discharge summary before the call. The output reads \"patient improved, discharged with updated medications, follow-up with pulmonology scheduled.\" That is all technically accurate. But when she reads the actual discharge notes, she notices the attending flagged uncertainty about whether the patient understood the new inhaler technique, and a social work note mentions the patient lives alone and his daughter, who typically helps with medications, has moved out of state. The AI summary was clean. The situation was not. The summary was a starting point. It was not a substitute for her read.\n\n**Watch for the summary that replaces your read.**\n\nA well-written AI summary of a 30-page chart is genuinely useful. It saves you time orienting to a new patient. But it flattens nuance by design. The offhand comment in a nurse's note, the trend you would have spotted across three visits, the detail that does not fit the otherwise tidy picture: these are exactly what a summary smooths over. Use the summary to find your way into the chart faster. Then look at the source for anything that will drive a care decision.\n\nHere is the specific pattern to watch for. You pull up a chart on a patient you have not seen in two months. The AI summary says \"no significant changes, chronic conditions managed, follow-up as needed.\" You are about to go into the room. But if you had scanned the actual visit notes, you would have seen that at the last two visits the patient mentioned fatigue and that her primary care provider had ordered labs that came back showing a mild but trending-down hemoglobin. Each visit note mentioned it briefly. The AI summary averaged those mentions into \"managed.\" The trend was real. The summary erased it. You cannot examine a summary. You examine a patient, and you need your full attention when you walk in."}$lum$::jsonb, false),
  ($lum$0b9ca7fb-6921-5ff3-8ab7-39f39908e2a8$lum$::uuid, $lum$8a622838-3935-540c-96d7-468f3b67b0da$lum$::uuid, 3, $lum$multiple_choice$lum$, $lum${"stem":"Before a visit, you ask an AI to summarize a long chart. The summary reads 'no significant concerns, patient stable.' What is the correct way to use this output?","options":[{"id":"a","label":"Use it as a fast orientation, then review the source notes yourself for anything that will drive a clinical decision.","is_correct":true,"explanation":"Correct. The summary speeds up your orientation, but you verify anything decision-relevant against the actual chart. Summaries flatten nuance, and 'stable' can erase a real trend or a detail that does not fit."},{"id":"b","label":"Trust it and proceed, since the AI read the entire chart more thoroughly than you have time to.","is_correct":false,"explanation":"A fluent summary is not a clinical finding. It can miss trends across visits, offhand notes from nursing staff, or details that only matter when you see them together. 'Stable' is exactly the kind of confident phrasing that can walk you past a real problem."},{"id":"c","label":"Ask the AI what it would recommend for this patient based on the summary.","is_correct":false,"explanation":"That step hands the clinical reasoning to a tool that cannot examine the patient. AI handles the words around care, not the care itself. Your assessment comes first."},{"id":"d","label":"Discard AI summaries entirely because they cannot be trusted in any healthcare context.","is_correct":false,"explanation":"That goes further than the evidence warrants. A summary is a useful way to orient yourself faster. The issue is treating it as a substitute for your own read, not using it at all."}]}$lum$::jsonb, false),
  ($lum$d5c3a8a3-38ef-58cf-8b96-d5f49227ee90$lum$::uuid, $lum$8a622838-3935-540c-96d7-468f3b67b0da$lum$::uuid, 4, $lum$reading$lum$, $lum${"markdown":"**The deskilling trap is real, and it is gradual.**\n\nSkills you stop using fade. This is not a character flaw. It is physiology and learning science. If you regularly hand your clinical reasoning to an AI tool, your own reasoning gets slower and rustier, precisely in the cases where it matters most: the patient who does not fit the pattern, the situation the AI has not been trained to flag, the subtle shift in presentation that only your trained eye would catch.\n\nThe way to avoid this is not to avoid AI. It is to keep reasoning first, every time, as a non-negotiable step before the tool is involved. Protect the practice the same way you protect any clinical skill: by using it. AI should carry the clerical load so you have more attention available for the thinking. The moment it starts replacing the thinking, the benefit has inverted.\n\nThe core principle of this entire healthcare track lands right here. AI handles the language around care. You handle the care. A tool that drafts your words, organizes your documentation, and saves you from repetitive tasks is a genuine asset. A tool you let reason for you is a liability with your name, your license, and your patient's safety attached."}$lum$::jsonb, false),
  ($lum$998cbf05-90d6-523f-881a-f40bffdfbcae$lum$::uuid, $lum$8a622838-3935-540c-96d7-468f3b67b0da$lum$::uuid, 5, $lum$multiple_choice$lum$, $lum${"stem":"This section calls deskilling 'real, and gradual.' Based on it, what is the recommended way to protect your clinical reasoning?","options":[{"id":"a","label":"Limit AI to your most complex cases, where rusty reasoning would be most dangerous.","is_correct":false,"explanation":"The complex, off-pattern cases are exactly where your reasoning must be sharpest, so leaning on AI there is the worst place to do it. The section keeps reasoning first across the board, not just on routine work."},{"id":"b","label":"Avoid AI tools altogether so your reasoning never has the chance to fade.","is_correct":false,"explanation":"The section is explicit that the way to avoid deskilling is not to avoid AI. The tool should carry the clerical load so you have more attention for the thinking."},{"id":"c","label":"Let AI handle the reasoning on busy days and reason unaided only when you have time.","is_correct":false,"explanation":"Handing the reasoning to AI on busy days is precisely the repeated delegation that makes the skill fade. Reasoning first is described as a non-negotiable step, not a time-permitting one."},{"id":"d","label":"Keep reasoning first every time as a non-negotiable step, letting AI carry the clerical load while you keep doing the thinking.","is_correct":true,"explanation":"Correct. You protect the practice by using it: reasoning stays first every time, and AI carries the clerical load so you have more attention for the thinking. The moment it replaces the thinking, the benefit has inverted."}]}$lum$::jsonb, false),
  ($lum$ff66e5cf-5190-5d33-9c23-0a59e0036d87$lum$::uuid, $lum$8a622838-3935-540c-96d7-468f3b67b0da$lum$::uuid, 6, $lum$reading$lum$, $lum${"markdown":"The principle sounds clear enough: form your own assessment first. But in practice, several specific patterns trip up even experienced clinicians. Knowing them by name helps you catch yourself.\n\n**Asking AI \"what is going on with this patient\" before forming your own impression.**\n\nThis is the most common version of the problem. You are busy. The chart is long. You paste in a summary and ask the tool to tell you what it sees. The AI answers in confident, fluent language. Now you have an anchor. Everything you read afterward gets filtered through that anchor, even if you intend to stay open. The fix is a strict personal rule: your working impression gets written down before you open the AI tool, even if it is just two lines in your own words. Once you have your impression committed, AI cannot overwrite it.\n\n**Trusting a clean summary and skipping the source notes.**\n\nMany clinicians report doing this on busy days, especially for patients they have seen before. The summary says \"chronic conditions stable, no acute issues,\" and they move on. The problem is that AI summaries do well with structured data and poorly with the informal, contextual notes where real clinical signal often lives. A nurse's notation that a patient \"seemed more confused than last time\" or a medication reconciliation flag that was never fully resolved: these rarely make it into a clean summary. Skipping the source is the specific behavior that converts a useful tool into a safety risk.\n\n**Letting AI framing anchor your assessment.**\n\nThis one is subtler. You read the AI summary first, and it uses a particular frame: maybe it emphasizes cardiac history in a way that primes you to think cardiac even when respiratory is the better fit. You do your own assessment, but the AI's framing has already shaped what you notice. The countermeasure is sequence: read the patient and form your impression before you read any AI output about that patient. The summary should follow your assessment, not precede it."}$lum$::jsonb, false),
  ($lum$3fea4401-4f7c-5c12-acd5-e6f54dc64dfc$lum$::uuid, $lum$8a622838-3935-540c-96d7-468f3b67b0da$lum$::uuid, 7, $lum$multiple_choice$lum$, $lum${"stem":"A clinician reads an AI summary that emphasizes a patient's cardiac history, and afterward finds herself leaning toward a cardiac explanation even though respiratory may fit better. Which named pattern is this, and what is the countermeasure?","options":[{"id":"a","label":"Confusing documentation quality with reasoning quality; the fix is to write a more structured note.","is_correct":false,"explanation":"That pattern is about mistaking a polished note for sound reasoning, which is not what is happening here. The issue here is that the AI's framing shaped what she noticed before she formed her own impression."},{"id":"b","label":"Letting AI framing anchor your assessment; the countermeasure is sequence, forming your own impression before you read any AI output.","is_correct":true,"explanation":"Correct. Reading the AI summary first lets its frame prime what you notice. The countermeasure named here is sequence: read the patient and form your impression first, so the summary follows your assessment rather than preceding it."},{"id":"c","label":"Gradual deskilling from never reasoning unaided; the fix is intentional unassisted practice.","is_correct":false,"explanation":"Deskilling is the slow erosion of skill over months from repeated delegation. Here the clinician did reason on her own, but the AI's framing had already anchored what she noticed. The relevant fix is sequence, not unassisted practice."},{"id":"d","label":"Trusting a clean summary and skipping the source notes; the fix is to always open the source chart.","is_correct":false,"explanation":"That pattern is about skipping verification of the source. Here she did her own assessment but was anchored by the AI's frame, so the precise countermeasure is the order in which she reads, not whether she opens the source."}]}$lum$::jsonb, false),
  ($lum$4a67da0d-9c2b-5958-8037-d682c656e8ca$lum$::uuid, $lum$8a622838-3935-540c-96d7-468f3b67b0da$lum$::uuid, 8, $lum$reading$lum$, $lum${"markdown":"**Gradual deskilling from never reasoning unaided.**\n\nThis mistake does not feel like a mistake in the moment. It accumulates over months. Clinicians who use AI heavily sometimes report that writing an unassisted note feels harder than it used to, or that starting from scratch on a clinical impression takes longer. That is deskilling. The intervention is intentional practice: on some percentage of routine notes and chart reviews, do the full reasoning and drafting yourself before checking any AI output. Keep the skill sharp the same way you would keep any procedural skill sharp: by doing it regularly, not just when it is hard.\n\n**Confusing documentation quality with reasoning quality.**\n\nAI makes your notes cleaner and more complete. This is real value. But a well-structured note is not the same as a well-reasoned assessment. It is easy to mistake a polished output for a thorough thought process, especially under time pressure. The note AI helps you write looks authoritative. That appearance is not evidence that the reasoning behind it was yours or that it was sound. Separate the two explicitly: reasoning is what you do before the tool; documentation is what the tool helps you do after."}$lum$::jsonb, false),
  ($lum$61249d71-790f-5f48-9bd3-cedf46983f96$lum$::uuid, $lum$8a622838-3935-540c-96d7-468f3b67b0da$lum$::uuid, 9, $lum$multiple_choice$lum$, $lum${"stem":"A nurse on a busy floor uses an AI tool to help with documentation every shift. Over time, she notices that writing a progress note without AI feels harder than it used to. What is the most accurate description of what is happening?","options":[{"id":"a","label":"She is experiencing normal fatigue from a demanding job. The difficulty is not related to AI use.","is_correct":false,"explanation":"Fatigue is real, but the specific pattern of finding unassisted work harder over time, especially when AI has been used consistently for that same task, is a signal of deskilling rather than general tiredness."},{"id":"b","label":"She is experiencing gradual deskilling: a skill used less frequently becomes harder to execute, and she should intentionally practice reasoning and drafting unaided on some portion of her notes to keep the skill sharp.","is_correct":true,"explanation":"Correct. Deskilling from over-reliance on AI is a documented risk. The intervention is deliberate practice: doing the full reasoning and drafting yourself on a regular subset of tasks so the skill stays accessible when you need it without assistance."},{"id":"c","label":"She should stop using AI for documentation since the deskilling risk outweighs any efficiency benefit.","is_correct":false,"explanation":"Removing the tool entirely is not the right response. The solution is keeping reasoning unaided while still using AI for drafting and organizing. The goal is to protect the thinking, not to stop using a tool that genuinely saves time."},{"id":"d","label":"This is a sign she has learned to use AI correctly. Difficulty without AI means she has integrated the tool well.","is_correct":false,"explanation":"That inverts the goal. The aim is to keep your clinical reasoning sharp and independent, then use AI for the words. If reasoning unaided is getting harder, the balance has shifted in the wrong direction."}]}$lum$::jsonb, false),
  ($lum$e7bc8b25-2435-5f16-a0a8-5bcb7d120e04$lum$::uuid, $lum$8a622838-3935-540c-96d7-468f3b67b0da$lum$::uuid, 10, $lum$before_after$lum$, $lum${"question":"Same patient, same chart, same tool. One prompt outsources the judgment. The other keeps the clinician's assessment in place and uses AI only for documentation and verification. Notice who does the thinking in each version.","before_prompt":"Here is a patient's chart: 68-year-old with shortness of breath and a history of heart failure, slightly elevated heart rate, and some lower extremity swelling. What is most likely going on and what should I do next?","after_prompt":"Here is a patient's chart: 68-year-old with shortness of breath and a history of heart failure, slightly elevated heart rate, and lower extremity swelling. I have completed my own assessment and have a working clinical impression. Do not offer a diagnosis or suggest next steps. Instead, help me write a clear, structured progress note that documents my findings, and list any specific items from this chart I should personally verify against the source notes before I finalize my plan.","changes":["The after prompt states that the clinician's own assessment is already formed, which removes the invitation for AI to supply a diagnosis and keeps clinical reasoning exactly where it belongs.","The after prompt redirects AI to the two things it is genuinely useful for: organizing the documentation precisely and surfacing items to double-check, rather than deciding what is happening with the patient.","The after prompt turns the AI into a verification prompt rather than an answer, which protects both the patient and the clinician's judgment and license."]}$lum$::jsonb, true),
  ($lum$02c00fae-72f7-56b6-ac6d-b87bb8af46bb$lum$::uuid, $lum$8a622838-3935-540c-96d7-468f3b67b0da$lum$::uuid, 11, $lum$multiple_choice$lum$, $lum${"stem":"A medical assistant is about to use AI to help document a visit for a patient with new-onset confusion. Which prompt best protects clinical judgment while still using AI effectively?","options":[{"id":"a","label":"\"This patient has new-onset confusion. What are the most likely causes and what workup should the provider order?\"","is_correct":false,"explanation":"This prompt asks AI to supply the clinical reasoning. It may produce a plausible-sounding differential, but that output belongs to the clinician, not the tool. The medical assistant would be anchoring the team's thinking to an AI guess before anyone has formed their own impression."},{"id":"b","label":"\"The provider has completed the assessment and has a working impression for this patient with new-onset confusion. Help me write a structured note documenting the findings shared, and flag any items in the chart that should be verified before finalizing the plan.\"","is_correct":true,"explanation":"Correct. This prompt positions AI as a documentation and verification tool, not a diagnostic one. The clinical reasoning belongs to the provider, and the AI is directed to tasks it can do reliably: organizing language and surfacing items to double-check."},{"id":"c","label":"\"Summarize this patient's chart and tell me if there is anything to worry about for a patient with new-onset confusion.\"","is_correct":false,"explanation":"Asking AI what to worry about delegates the clinical judgment. A summary is useful for orientation, but asking the tool to identify concerns hands it the assessment role. The clinician or provider needs to identify concerns based on their own evaluation."}]}$lum$::jsonb, false),
  ($lum$b2e6dc23-5068-5923-98c8-9c8cb7389a8c$lum$::uuid, $lum$8a622838-3935-540c-96d7-468f3b67b0da$lum$::uuid, 12, $lum$mini_project$lum$, $lum${"brief":"Design and write down your own three-step think-first, draft-second, verify workflow for a documentation task you actually do regularly, such as writing a progress note, completing a pre-visit chart review, or documenting a care coordination call. Be specific about what you assess on your own before the AI tool opens, exactly what instruction you give the tool (with an explicit directive not to diagnose or recommend), and which items you personally verify against source material before the note is final.","parts":[{"id":"1","prompt":"Step 1 (Think first): Write down what you will assess and conclude on your own before opening any AI tool. For a progress note, this means your clinical impression and key findings in your own words, even two or three lines. For a pre-visit chart review, this means the questions you want answered and the trends you are watching, identified before you see any AI summary."},{"id":"2","prompt":"Step 2 (Draft second): Write the exact instruction you will give the AI, including a specific scope: help structure and phrase what you have already assessed, list items to verify against the source, and do not suggest diagnoses or next steps. Keep this instruction short enough to use every time."},{"id":"3","prompt":"Step 3 (Verify and close): Name the specific source material you will check before finalizing, such as the last two visit notes, the medication list in the EHR, or the most recent lab values, so verification is a deliberate step and not skipped under time pressure. Add one sentence naming the deskilling risk for this specific task: the clinical judgment you must keep practicing yourself so it does not erode from repeated delegation."}]}$lum$::jsonb, false),
  ($lum$1f49342a-ea52-580d-a40f-36ad37cae901$lum$::uuid, $lum$b86804f9-8ac7-5427-8116-0a2ad1cf94e3$lum$::uuid, 0, $lum$reading$lum$, $lum${"markdown":"For most of your career, fraud defense quietly leaned on one comforting fact: attackers were sloppy. The phishing email had a typo in the company name. The fake invoice used the wrong font and a total that did not add up. The person calling to \"authorize\" a wire could not actually sound like your CFO, so a moment on the phone usually gave them away. You learned to trust your eye and your ear, and most of the time that worked. The fakes announced themselves.\n\nThat world is gone, and it is worth saying plainly so you can stop blaming yourself for feeling uneasy. AI did not invent fraud. It removed the friction and the flaws that used to make fraud easy to catch. A convincing email, a cloned voice on a voicemail, a forged document that matches your exact template down to the logo placement, all of it is now cheap, fast, and very good. The polish of a request is no longer evidence that the request is real. That single sentence is the whole lesson, and everything else is how you live by it."}$lum$::jsonb, false),
  ($lum$d7ab7a74-8933-5895-a774-7311ae0d7bfa$lum$::uuid, $lum$b86804f9-8ac7-5427-8116-0a2ad1cf94e3$lum$::uuid, 1, $lum$multiple_choice$lum$, $lum${"stem":"Across most of your career, what made fraud relatively easy to catch, and what changed?","options":[{"id":"a","label":"Fraud was caught because attackers used the wrong channels, and AI changed which channels they use.","is_correct":false,"explanation":"The old tell was not the channel, it was sloppiness: typos, wrong fonts, a voice that did not match. AI removed those flaws, which is the actual shift."},{"id":"b","label":"Fraud used to announce itself through sloppiness, and AI removed the flaws so polish is no longer evidence a request is real.","is_correct":true,"explanation":"Correct. Defense quietly leaned on attackers being sloppy. AI removed the friction and the flaws, so the polish of a request is no longer evidence that the request is real."},{"id":"c","label":"Fraud was rare before AI, and AI mainly increased how often fraud is attempted.","is_correct":false,"explanation":"The lesson is not about frequency. AI did not invent fraud, it removed the flaws that used to make fraud easy to catch, so convincing fakes are now cheap, fast, and very good."}]}$lum$::jsonb, false),
  ($lum$a2130719-41ac-5f70-b7f8-ebeadb3828bf$lum$::uuid, $lum$b86804f9-8ac7-5427-8116-0a2ad1cf94e3$lum$::uuid, 2, $lum$reading$lum$, $lum${"markdown":"Think about Mara, an accounts payable clerk at a mid-size distributor. One Thursday she gets a voicemail. It is her CFO's voice, the same slightly rushed cadence she hears in every quarterly meeting, saying a confidential acquisition is closing and she needs to push a wire to a new account today, keep it quiet, he will explain later. It sounds exactly like him because it was built from a few minutes of him talking on a public webinar. Nothing about the voice is wrong. The old defense, \"does this sound like him,\" fails completely, because it sounds perfectly like him. The voice was never the thing to verify.\n\nOr take Devin, a controller who opens an email from a long-standing vendor. The email is warm, correctly formatted, references a real recent invoice number, and politely notes the vendor has switched banks, so please update the payment details for the next run. There are no spelling errors, no clumsy phrasing, no broken English. It reads like every legitimate vendor email Devin has processed for years, because an AI model wrote it after studying exactly that kind of email. The request to change bank details is the single highest-value move a fraudster can make, and it arrived looking completely ordinary.\n\nOr Priya, a treasury analyst who receives wire instructions that are, if anything, too clean. Perfect reference numbers, correct beneficiary formatting, a tone of calm authority, an attached document on what looks like real letterhead. The very smoothness that used to reassure her is now neutral information. A flawless message proves nothing about who actually sent it."}$lum$::jsonb, false),
  ($lum$bc7fd164-f99f-5d61-b52f-229354f1866b$lum$::uuid, $lum$b86804f9-8ac7-5427-8116-0a2ad1cf94e3$lum$::uuid, 3, $lum$multiple_choice$lum$, $lum${"stem":"Mara, an AP clerk, receives a voicemail that perfectly matches her CFO's voice asking her to wire funds to a new account today and keep it quiet. AI makes this kind of voice clone easy to produce. What is the control that still works?","options":[{"id":"a","label":"Call the CFO back on a number she already had on file, not the number from the voicemail, and confirm before any funds move.","is_correct":true,"explanation":"Correct. Because the voice itself can be perfectly cloned, the defense cannot rely on judging whether it sounds real. Confirming through an independent, pre-known channel is the control that does not depend on spotting the fake."},{"id":"b","label":"Trust it, because the voice clearly matches how the CFO normally sounds and the request feels genuinely urgent.","is_correct":false,"explanation":"That is exactly the trap. AI makes a voice trivial to imitate, so sounding authentic is no longer evidence of being authentic. The matching voice is the bait, and the urgency is the pressure designed to switch off verification."},{"id":"c","label":"Call back the number left in the voicemail to confirm it is really the CFO, then proceed once someone says yes.","is_correct":false,"explanation":"That number is part of the channel the attacker controls. A callback only proves something if it goes to contact details you already trusted, not details supplied by the request itself."}]}$lum$::jsonb, false),
  ($lum$5b2ea4a3-2fa7-5dbe-a865-191df29649fd$lum$::uuid, $lum$b86804f9-8ac7-5427-8116-0a2ad1cf94e3$lum$::uuid, 4, $lum$reading$lum$, $lum${"markdown":"Here is the part that should lower your anxiety rather than raise it. The defense was never going to come from you getting better at spotting fakes, because the fakes are now better than your eye. The defense comes from controls that do not depend on judging authenticity at all. The center of it is out-of-band verification. Before any payment, any new account, any vendor bank-detail change, you confirm the instruction through a separate channel you already trusted, not the channel the request arrived on. You call back a number you already had on file, never the number in the email signature, never the number left on the voicemail, never the reply path of the message itself. If the request is real, a thirty-second callback costs nothing. If it is fake, that callback is the wall it cannot climb, because the fraudster does not control the phone on your known contact list.\n\nLayer two more disciplines on top. Dual authorization means funds above a threshold require two sets of eyes and two approvals, so no single faked request can move money alone. A hard rule on vendor bank changes means details only change through a verified, documented process with a callback, regardless of how routine the request looks. And the cultural piece matters as much as the procedural one: pausing to verify an urgent request has to be rewarded, never punished. Attackers weaponize urgency precisely because they know a finance professional who fears looking slow will skip the check. \"Before the deal closes today\" and \"keep this confidential\" are not details of a real emergency, they are pressure designed to switch off your verification reflex.\n\nAI is not only the attacker's tool, by the way. It can help you scan transaction patterns for anomalies, flag duplicate or oddly timed invoices, and even draft your verification procedures. Use it. But notice the asymmetry: AI helps you detect, it does not get to be the thing you trust. The principle underneath every tool is simpler than any tool. In a world where requests can be perfectly faked, you trust the channel, not the content. A perfect message is just a message. A callback to a number you already trusted is proof. Build your processes so that no amount of polish on a fake can move a dollar on its own, and the anxiety starts to fade, because you are no longer relying on catching the uncatchable. You are relying on a rule."}$lum$::jsonb, false),
  ($lum$f01208e8-5206-52d6-988c-ca4b3d8b338d$lum$::uuid, $lum$b86804f9-8ac7-5427-8116-0a2ad1cf94e3$lum$::uuid, 5, $lum$fill_blank$lum$, $lum${"template":"When a payment or bank-detail request arrives, the safe move is to verify it through an {{1}} channel using contact details you already held, never the reply path inside the request, because AI makes the {{2}} of a message worthless as proof of who sent it.","blanks":[{"id":"1","accept":["out-of-band","out of band","independent","separate","pre-known"],"ideal":"out-of-band"},{"id":"2","accept":["polish","quality","appearance","authenticity","look"],"ideal":"polish"}],"explanation":"Verification must travel through an out-of-band channel you already trusted, not one supplied by the request, since the polish of a message is now cheap to fake and tells you nothing about its true sender."}$lum$::jsonb, false),
  ($lum$a37bd58a-28fe-5ef1-9ce2-68df9c1af6b9$lum$::uuid, $lum$b86804f9-8ac7-5427-8116-0a2ad1cf94e3$lum$::uuid, 6, $lum$reading$lum$, $lum${"markdown":"The failures here rarely come from careless people. They come from good instincts being turned against you, so it helps to name exactly how it goes wrong.\n\nThe most common mistake is verifying through the channel the request arrived on. Devin, the controller, gets the vendor bank-change email and replies to it, or calls the phone number in the signature, and gets a friendly confirmation. But if the email is fraudulent, the reply path and that number belong to the fraudster. The \"confirmation\" is the same person who sent the lie, saying the lie again. Verification only counts when it travels through a separate channel you already held, never one handed to you inside the suspicious request.\n\nThe second mistake is treating polish as proof. Priya sees a too-perfect wire instruction and relaxes, because in the past, sloppiness was the warning sign and smoothness meant legitimate. AI inverted that. A flawless email, a correct reference number, real-looking letterhead, none of it tells you who actually sent the message. When you catch yourself thinking \"this looks completely legitimate, so it must be,\" that is the exact moment to slow down, because looking legitimate is now free to fake."}$lum$::jsonb, false),
  ($lum$c087270b-a5ef-593f-a1e7-aa41d28c1dc9$lum$::uuid, $lum$b86804f9-8ac7-5427-8116-0a2ad1cf94e3$lum$::uuid, 7, $lum$multiple_choice$lum$, $lum${"stem":"Devin replies directly to a vendor's bank-change email and calls the phone number in its signature, and gets a friendly confirmation. Why does this fail to verify the request?","options":[{"id":"a","label":"Because email confirmations are never valid, and only a confirmation in writing on official letterhead can count.","is_correct":false,"explanation":"Letterhead is exactly the kind of polish that is now free to fake. The problem is not the format of the reply, it is that the reply travels back through the channel the request itself supplied."},{"id":"b","label":"Because if the email is fraudulent, the reply path and that number belong to the fraudster, so it is the same person confirming their own lie.","is_correct":true,"explanation":"Correct. Verification only counts when it travels through a separate channel you already held, never one handed to you inside the suspicious request. Replying or calling the signature number reaches the fraudster again."},{"id":"c","label":"Because Devin should have trusted the polish of the email, since a flawless, error-free message proves it came from the real vendor.","is_correct":false,"explanation":"The opposite is true. Treating polish as proof is itself one of the named mistakes. A flawless email tells you nothing about who actually sent it."}]}$lum$::jsonb, false),
  ($lum$ad3aa765-0c75-5d55-ae16-7ea3d0980c64$lum$::uuid, $lum$b86804f9-8ac7-5427-8116-0a2ad1cf94e3$lum$::uuid, 8, $lum$reading$lum$, $lum${"markdown":"The third mistake is letting urgency and confidentiality override process. \"Before the deal closes today\" and \"keep this between us\" are not incidental, they are the attack. Urgency rushes you past the callback. Confidentiality isolates you so you cannot ask a colleague who might say \"wait, we always verify bank changes.\" A real executive will understand a verification step. A fraudster needs you to skip it, so any request that pressures you to skip it deserves more scrutiny, not less.\n\nThe fourth mistake is having no rule, only judgment. If verifying is something individuals choose to do when a request feels off, fraud wins on the day the fake feels perfectly on. Judgment is exactly what AI defeats. The fix is a standing rule that applies regardless of how the request looks: vendor bank details change only through a verified callback, wires above a threshold need dual approval, period. Rules do not get tired, flattered, or rushed.\n\nThe last mistake is cultural, and it is the one leaders cause. If your team treats a paused, double-checked payment as the clerk being difficult or slow, you have trained people to skip the very control that protects you. The clerk who calls back to verify an urgent CFO wire should be thanked, even when the request turns out to be real, because that callback is the system working. Punish the pause and you have quietly disabled your strongest defense."}$lum$::jsonb, false),
  ($lum$ee1c132e-c92e-58be-a19d-970966ed166a$lum$::uuid, $lum$b86804f9-8ac7-5427-8116-0a2ad1cf94e3$lum$::uuid, 9, $lum$multiple_choice$lum$, $lum${"stem":"Why is 'having no rule, only judgment' treated as a mistake, and what fixes it?","options":[{"id":"a","label":"Judgment is the very thing AI defeats, so the fix is a standing rule that applies regardless of how the request looks.","is_correct":true,"explanation":"Correct. If verifying is left to individual judgment, fraud wins on the day the fake feels perfectly on. A standing rule, such as verified callbacks for bank changes and dual approval over a threshold, does not get tired, flattered, or rushed."},{"id":"b","label":"Experienced staff have unreliable judgment, so they should defer to whoever is most senior on every payment.","is_correct":false,"explanation":"The point is not seniority. The problem is that any judgment, however experienced, can be beaten on the day a fake looks perfect, which is why a rule that applies regardless of appearance is needed."},{"id":"c","label":"Rules slow teams down, so the better fix is to train people to spot fakes more reliably by eye.","is_correct":false,"explanation":"Spotting fakes by eye is exactly what AI defeats. The lesson argues for a standing rule precisely because human judgment cannot be relied on to catch a perfect fake."}]}$lum$::jsonb, false),
  ($lum$dfb50d4d-2096-5600-8464-dfc24681532a$lum$::uuid, $lum$b86804f9-8ac7-5427-8116-0a2ad1cf94e3$lum$::uuid, 10, $lum$before_after$lum$, $lum${"question":"Devin, a controller, gets an urgent, perfectly written email from a known vendor asking to update their bank details before the next payment run. Which way of handling it actually protects the company?","before_prompt":"The email looks completely legitimate, references a real invoice number, and has no errors, and the vendor says it is urgent. Devin replies to the email and calls the phone number in the signature to confirm, gets a friendly yes, updates the bank details, and releases the next payment.","after_prompt":"Devin treats the polish as neutral and the urgency as a reason for more care, not less. He does not reply to the email or use any number it provides. He calls the vendor back on the phone number already on file from the original onboarding, confirms the bank change with a known contact, documents the verification, and routes the actual change through the standing dual-approval process before any payment is released.","changes":["Verifies through a separate channel already on file instead of the reply path and number the request itself supplied.","Treats the message's flawless polish and urgency as neutral or suspicious rather than as evidence the request is real.","Routes the change through a documented dual-approval rule so no single request can move the bank details or the money alone."]}$lum$::jsonb, true),
  ($lum$4e430b30-d46f-55cc-986d-9fc3ab7e09c5$lum$::uuid, $lum$b86804f9-8ac7-5427-8116-0a2ad1cf94e3$lum$::uuid, 11, $lum$multiple_choice$lum$, $lum${"stem":"An email pressuring you with 'before the deal closes today' and 'please keep this confidential' is most accurately understood as which of the following?","options":[{"id":"a","label":"A normal feature of high-pressure deals that you should respect by moving quickly and quietly.","is_correct":false,"explanation":"This is what the attacker wants you to believe. Real deals can absolutely be fast, but no legitimate request is harmed by a thirty-second verification callback, so urgency is never a reason to skip the control."},{"id":"b","label":"Pressure tactics engineered to rush you past verification and isolate you from a colleague who would say 'we always verify this.'","is_correct":true,"explanation":"Correct. Urgency rushes you past the callback and confidentiality isolates you from a second opinion. Both are designed to switch off your verification reflex, which is exactly why they signal more scrutiny, not less."},{"id":"c","label":"A sign the email is probably fake purely because it uses those phrases, so you can safely delete it without checking.","is_correct":false,"explanation":"Not quite. Those phrases are red flags worth heeding, but the disciplined response is to verify through a separate trusted channel, not to assume and act on a guess in either direction."}]}$lum$::jsonb, false),
  ($lum$3fb9430c-8ba4-56c0-8991-46229dbf4fac$lum$::uuid, $lum$b86804f9-8ac7-5427-8116-0a2ad1cf94e3$lum$::uuid, 12, $lum$mini_project$lum$, $lum${"brief":"Pick one money-movement process you personally touch, such as approving a payment, onboarding a vendor, or changing bank details. Walk through it step by step and mark every point where the process currently relies on a request looking or sounding legitimate, because under AI each of those points is now a soft spot. For each soft spot, design a specific out-of-band verification step using contact details you already hold on file, not anything supplied inside the request. Then use AI as a drafting aid to turn your fixes into a short, followable procedure and a plain-language note to your team. Aim for a process where no perfect-looking fake can move money on its own.","parts":[{"id":"1","prompt":"List each step in your chosen process and flag where it trusts the polish, voice, or appearance of a request."},{"id":"2","prompt":"Write the exact callback or out-of-band check for each flag, naming the trusted channel and where the contact detail comes from."},{"id":"3","prompt":"Draft the team note explaining why an urgent, flawless request is the one to slow down and verify, and why pausing will be thanked, not blamed."}]}$lum$::jsonb, false),
  ($lum$9d4af66e-99d8-5995-98a3-d24ed60c25c6$lum$::uuid, $lum$1cc6bbd0-64d2-5fdf-bfa1-96e8f107401d$lum$::uuid, 0, $lum$reading$lum$, $lum${"markdown":"Taking over a complex patient means absorbing a mountain of history fast: prior admissions, a long med list, consult notes, labs trending in three directions. Reading all of it is not realistic on a busy unit. Skimming it means you miss things. This is exactly the gap a good summary closes.\n\nThe trick is asking for the right summary. \"Summarize this chart\" gives you a flat recap. What you actually need is the clinical picture: what is active, what changed, what to watch.\n\n**The targeted prompt:**\n\n*\"This is a de-identified patient record. Give me: 1) Active problems and current treatment for each, 2) Anything that changed in the last 48 hours, 3) Current medications grouped by purpose, 4) Open or unresolved issues from the notes, 5) Three questions I should be able to answer before I see this patient. Use only what is in the record.\"*\n\nThis forces the tool to organize around clinical relevance instead of chronology.\n\n**The verification habit.** Summaries are where errors hide, because a confident summary feels complete. Before you act on anything that affects care, especially medications, doses, allergies, or code status, confirm it against the source document. Treat the summary as a map, not the territory.\n\n**Privacy first:** only use a tool approved for protected health information, or de-identify thoroughly before pasting. Charts are dense with identifiers.\n\nDone well, this gives you back the minutes you would have spent flipping pages, and you walk in knowing the three things that matter."}$lum$::jsonb, false),
  ($lum$f1d69c8f-d335-561f-ae51-c005616536fe$lum$::uuid, $lum$1cc6bbd0-64d2-5fdf-bfa1-96e8f107401d$lum$::uuid, 1, $lum$before_after$lum$, $lum${"question":"Same 40-page chart, two prompts. Notice which one gives you the clinical picture instead of a recap.","before_prompt":"Summarize this patient's chart.","after_prompt":"This is a de-identified patient record. Give me: 1) active problems and current treatment for each, 2) anything that changed in the last 48 hours, 3) current medications grouped by purpose, 4) open or unresolved issues from the notes, 5) three questions I should be able to answer before I see this patient. Use only what is in the record.","changes":["Asks for the clinical picture (active problems, recent changes, open issues) rather than a flat chronological recap.","Organizes meds by purpose and surfaces what changed recently, which is what you actually need in the four minutes before the door.","Forces the tool to work only from the record and to hand you the three questions to verify, instead of inventing a tidy story."]}$lum$::jsonb, true),
  ($lum$186874d2-253b-542c-9672-dca215db31c1$lum$::uuid, $lum$1cc6bbd0-64d2-5fdf-bfa1-96e8f107401d$lum$::uuid, 2, $lum$multiple_choice$lum$, $lum${"stem":"The AI chart summary lists the medications, an allergy, and code status. You have four minutes before you walk in. What is the safe move?","options":[{"id":"a","label":"Use the summary to orient, but confirm meds, doses, the allergy, and code status against the source chart before acting on any of them.","is_correct":true,"explanation":"Correct. A confident summary feels complete, which is exactly why errors hide there. Anything that affects care, especially meds, doses, allergies, and code status, gets verified against the source. The summary is the map, not the territory."},{"id":"b","label":"Act on the summary directly; it read the whole chart more thoroughly than you have time to.","is_correct":false,"explanation":"The summary can misread a dose or drop an allergy and still sound authoritative. For decision-critical facts, the source document is the only safe reference."},{"id":"c","label":"Skip the chart entirely and ask the AI to confirm the allergy is correct.","is_correct":false,"explanation":"The tool cannot verify its own summary against a source it has already compressed. Confirmation has to come from the actual chart."},{"id":"d","label":"Trust the medication list but re-check only the code status.","is_correct":false,"explanation":"Medication and dose errors are among the most dangerous a summary can introduce. The whole critical set (meds, doses, allergies, code status) gets verified, not a subset."}]}$lum$::jsonb, false),
  ($lum$f07d4692-d502-5734-baac-1dcc4fca5e78$lum$::uuid, $lum$1cc6bbd0-64d2-5fdf-bfa1-96e8f107401d$lum$::uuid, 3, $lum$mini_project$lum$, $lum${"brief":"Your 5-minute exercise: Take one complex case (de-identified) and run the targeted prompt. Then open the source chart and verify the medication list and any allergy or code-status detail line by line. Did the summary get the critical facts exactly right? Where would relying on it alone have been risky?","parts":[]}$lum$::jsonb, false),
  ($lum$3e50acfc-906c-5ddc-bd93-b1d72fe3e5c3$lum$::uuid, $lum$6bbe08e8-036f-51b6-9437-82f5c1103eb5$lum$::uuid, 0, $lum$reading$lum$, $lum${"markdown":"Every other healthcare lesson in this track ends with two warnings: verify the facts, and protect privacy. This lesson is the reason those warnings exist. If you take one thing from the entire healthcare track, take this.\n\n**What AI actually does, and why it fails in clinical settings**\n\nLarge language models do not look anything up. They do not have a live connection to a drug database, a formulary, or a clinical guideline repository. What they do is predict what text sounds like a reasonable answer, based on the enormous volume of text they were trained on. Most of the time, in most contexts, that works well enough. In clinical contexts, \"most of the time\" is not good enough, and \"sounds reasonable\" is genuinely dangerous.\n\nThe failure mode has a name: hallucination. A model produces a confident, fluent, specific, wrong answer. The problem is not that the model gives obviously garbled output. The problem is that it gives output that looks exactly like a correct answer. A nurse who asks an AI for the maximum daily dose of metformin for a patient with mild renal impairment may get a specific number stated with clinical authority. That number might be right. It might also be significantly higher than what current guidelines recommend for that patient's GFR range, presented with identical tone and formatting. Nothing in the output signals the error."}$lum$::jsonb, false),
  ($lum$968bc115-d3b8-50ee-810b-c882ce374e2f$lum$::uuid, $lum$6bbe08e8-036f-51b6-9437-82f5c1103eb5$lum$::uuid, 1, $lum$multiple_choice$lum$, $lum${"stem":"According to this segment, why is a hallucination especially dangerous in a clinical context, compared to obviously garbled output?","options":[{"id":"a","label":"Because the model refuses to answer clinical questions, leaving the clinician without any information.","is_correct":false,"explanation":"The danger described is the opposite. The model does answer, fluently and confidently. A refusal would at least signal that something is missing."},{"id":"b","label":"Because the output looks exactly like a correct answer, stated with clinical authority, so nothing in it signals the error.","is_correct":true,"explanation":"Correct. The segment stresses that the problem is not garbled output but fluent, specific, confident output that is wrong. A plausible metformin dose for the wrong GFR range looks identical to a correct one."},{"id":"c","label":"Because the model is querying a live drug database that is frequently out of date.","is_correct":false,"explanation":"The segment is explicit that the model has no live connection to a drug database or formulary. It predicts plausible text rather than looking anything up."},{"id":"d","label":"Because the output is always formatted differently from a real reference, which confuses the reader.","is_correct":false,"explanation":"The opposite is described: the wrong answer is presented with identical tone and formatting to a correct one, which is what makes it hard to catch."}]}$lum$::jsonb, false),
  ($lum$d93f4dbf-c3fb-5a77-aa96-8db6ae67b5d3$lum$::uuid, $lum$6bbe08e8-036f-51b6-9437-82f5c1103eb5$lum$::uuid, 2, $lum$reading$lum$, $lum${"markdown":"**Rule 1: AI is a drafting tool, never a clinical reference**\n\nThe line is not complicated, but it needs to be a firm habit. Use AI to organize your notes, rephrase complex language for a patient education handout, draft a shift summary, or structure a care coordination email. Do not use it as the source for any clinical fact, because it cannot reliably be that source.\n\nHere is what this looks like in practice.\n\nA clinical coordinator uses an AI tool to draft discharge instructions for a patient starting warfarin. The AI includes a sentence about avoiding high vitamin K foods and lists several specific examples. The list is plausible. It also omits grapefruit and several leafy greens that are clinically significant, and it slightly understates the monitoring frequency recommended in the facility's anticoagulation protocol. Nothing in the draft flags itself as incomplete. A coordinator who approves that draft without checking it against the anticoagulation protocol is relying on AI as a clinical reference. That is the error.\n\nA medical assistant working on prior authorization paperwork uses an AI tool to pull together clinical details from notes. The tool helpfully drafts a sentence describing the patient's indication and dosing history. Buried in that sentence is a drug name with a dose that is off by a factor of two, stated with perfect clinical confidence. The medication is opioid-based. The medical assistant submits the authorization request before checking the source chart. That is a real scenario, not a hypothetical.\n\nA nurse preparing for a patient education session asks an AI about a drug-drug interaction between two medications a patient is taking. The AI says there is no significant interaction and briefly explains the mechanisms. The nurse, pressed for time, moves on. The interaction is real, documented in UpToDate and the facility's clinical pharmacology database, and clinically significant. The AI was wrong and had no way to signal that it was wrong.\n\nIn all three cases, the problem is not that AI was used. The problem is that AI output was treated as a clinical reference. The rule is: any clinical fact in AI output, including a dose, an interaction, a guideline recommendation, a contraindication, or a monitoring parameter, is a question to verify, not an answer to trust. Verification means checking against your approved drug reference, your organization's clinical protocols, or consulting with pharmacy or a supervising clinician."}$lum$::jsonb, false),
  ($lum$ea27e369-299f-5e22-b6ac-76e2c35b32a3$lum$::uuid, $lum$6bbe08e8-036f-51b6-9437-82f5c1103eb5$lum$::uuid, 3, $lum$multiple_choice$lum$, $lum${"stem":"While drafting a warfarin patient's discharge instructions, the AI states a specific INR monitoring frequency. You recognize it as close to what you usually see. What does Rule 1 require?","options":[{"id":"a","label":"Treat the monitoring frequency as a question to verify, and confirm it against your facility's anticoagulation protocol before the instructions go to the patient.","is_correct":true,"explanation":"Correct. AI does not consult your facility's protocol. It predicts what sounds right. A monitoring frequency that is close to what you usually see is still unverified, and close is not correct when it involves anticoagulation management."},{"id":"b","label":"Use it, because it matches your general expectation and you are familiar with this medication.","is_correct":false,"explanation":"Familiarity with the answer is exactly what makes this dangerous. When the AI output matches what you expect, verification feels unnecessary. That is the moment hallucinations get through. Doses and monitoring parameters come from approved references, not from how plausible the output sounds."},{"id":"c","label":"Ask the AI to confirm its own recommendation before using it.","is_correct":false,"explanation":"A model asked to check its own clinical claim will often confirm it with equal confidence. The error is not corrected by re-querying the same source. Verification means going to your facility protocol, a drug reference, or pharmacy."},{"id":"d","label":"Use it but add a note that the frequency was suggested by AI.","is_correct":false,"explanation":"Labeling output as AI-generated does not make an unverified clinical recommendation safe to act on. The instruction would still carry an unconfirmed clinical fact. The rule is to verify first, then use."}]}$lum$::jsonb, false),
  ($lum$80a6eb15-7021-55c4-9944-fcd92dad9a19$lum$::uuid, $lum$6bbe08e8-036f-51b6-9437-82f5c1103eb5$lum$::uuid, 4, $lum$reading$lum$, $lum${"markdown":"**Rule 2: Patient identifiers never go into an unapproved tool**\n\nNames, dates of birth, medical record numbers, room numbers paired with diagnosis details, insurance IDs, dates of service, anything that identifies a specific patient is protected health information under HIPAA. Pasting a sentence that includes a patient name and diagnosis into a consumer AI chatbot is a potential HIPAA violation. Pasting a full chart excerpt into an app on your personal phone that has not been reviewed and approved by your organization's compliance or IT security team is a potential HIPAA violation, regardless of how helpful the app appears or how convenient it would be.\n\nThis matters because consumer AI tools, including the major chatbots most people have heard of, are not approved business associates under HIPAA unless your organization has a signed BAA with that vendor and has specifically authorized the tool for clinical use. The two safe paths are clear. First, de-identify thoroughly before using any AI tool: use \"a 68-year-old male patient\" instead of the patient's name and MRN, describe the clinical situation without identifiers, and ask your question in a way that would not allow anyone reading it to identify the specific patient. Second, use only tools your organization has formally approved for handling PHI, and follow your organization's specific guidance on how to use them.\n\nWhen in doubt, do not paste it. That is not overcaution. That is the rule.\n\n**A check before you hit enter**\n\nBefore you submit any prompt to any AI tool, ask yourself one question: would I be comfortable if this exact text appeared on a screen at the nurses' station, or in a compliance audit next quarter? If patient-identifiable information is in the prompt, the answer is no. If you are about to let an AI-generated clinical fact go to a patient without verifying it, the answer is no. Fix it first, then submit.\n\nThese two rules are not restrictions on what AI can do for you. They are the conditions that make everything else in this track safe to use. Every lesson in this track assumes you are applying both of them. Starting now, you are."}$lum$::jsonb, false),
  ($lum$84015084-2634-5e11-86a8-716ce2f051b4$lum$::uuid, $lum$6bbe08e8-036f-51b6-9437-82f5c1103eb5$lum$::uuid, 5, $lum$multiple_choice$lum$, $lum${"stem":"Under Rule 2, when is it acceptable to paste a sentence containing a patient's name and diagnosis into a major consumer AI chatbot?","options":[{"id":"a","label":"Whenever the chatbot is one of the well-known major tools, since those are generally considered trustworthy.","is_correct":false,"explanation":"The segment specifically names the major chatbots as tools that are not approved business associates by default. Being well-known does not make a tool HIPAA-compliant for PHI."},{"id":"b","label":"Whenever the task is convenient and the app appears helpful on your personal phone.","is_correct":false,"explanation":"The segment states a personal phone app that has not been reviewed and approved is a potential HIPAA violation regardless of how helpful or convenient it appears."},{"id":"c","label":"Only if your organization has a signed BAA with that vendor and has specifically authorized the tool for clinical use.","is_correct":true,"explanation":"Correct. The segment says consumer tools are not approved business associates unless your organization has a signed BAA and has specifically authorized the tool. Otherwise the safe path is to de-identify or use a formally approved tool."},{"id":"d","label":"Any time, as long as you delete the chat history immediately afterward.","is_correct":false,"explanation":"Deleting history does not change the fact that PHI was sent to an unapproved tool. The exposure has already occurred, and the rule is when in doubt, do not paste it."}]}$lum$::jsonb, false),
  ($lum$f7560cd8-4d17-51a0-ba4c-744affd5d580$lum$::uuid, $lum$6bbe08e8-036f-51b6-9437-82f5c1103eb5$lum$::uuid, 6, $lum$reading$lum$, $lum${"markdown":"**Common mistakes: what actually goes wrong**\n\nThe two rules are simple. The mistakes happen in predictable patterns, and knowing them in advance is the best way to avoid them.\n\n**Mistake 1: Trusting a fluent dose because it sounds right**\n\nMost clinicians who have worked through a pharmacy reference know what a reasonable dose range looks like for common medications. When an AI produces a number that falls inside that range and states it with clinical language, the brain registers it as plausible and moves on. The problem is that \"plausible\" and \"correct for this patient's specific situation\" are not the same thing. AI outputs a standard adult dose when your patient has renal impairment. It gives an initial titration dose when your patient is already at maintenance. It lists a dose from a non-formulary formulation. All of these are within a plausible range and all of them are wrong for the situation. The rule is not \"verify doses that seem off.\" The rule is \"verify all doses.\"\n\n**Mistake 2: Asking AI to double-check its own clinical claim**\n\nThis one feels logical in the moment: if the model gave you a dose, ask it whether that dose is correct. The problem is that language models are not verifying against an external database when they answer. They are predicting what a confident, correct-sounding response looks like. The same process that produced the original answer will produce a confirmation of that answer. You may get a response like \"yes, 25 mg twice daily is the standard dose for this indication\" when the answer was wrong to begin with. Verification has to happen outside the model, against your approved drug reference, your organization's protocol, or a clinical pharmacist."}$lum$::jsonb, false),
  ($lum$8b78c672-791d-55a9-b472-3cf5d7b17c2b$lum$::uuid, $lum$6bbe08e8-036f-51b6-9437-82f5c1103eb5$lum$::uuid, 7, $lum$multiple_choice$lum$, $lum${"stem":"Mistake 1 warns against trusting a fluent dose because it sounds right. Which situation best illustrates a dose that is within a plausible range but still wrong?","options":[{"id":"a","label":"The AI refuses to give a dose and tells you to consult pharmacy.","is_correct":false,"explanation":"That is not the mistake being described. A refusal sends you to a verified source. Mistake 1 is about confidently stated doses that look reasonable but do not fit the patient."},{"id":"b","label":"The AI returns a string of garbled numbers that obviously cannot be a real dose.","is_correct":false,"explanation":"Obviously garbled output is easy to catch. The danger in Mistake 1 is a number that falls inside the expected range and reads as plausible, so the brain moves on."},{"id":"c","label":"The AI asks you a clarifying question about the patient before answering.","is_correct":false,"explanation":"A clarifying question is not the failure mode here. Mistake 1 is about a plausible-looking dose stated with clinical language that does not match the patient's situation."},{"id":"d","label":"The AI gives a standard adult dose when your patient has renal impairment, so the number looks normal but is wrong for this patient.","is_correct":true,"explanation":"Correct. The segment lists exactly this: a standard adult dose for a patient with renal impairment is within a plausible range yet wrong for the situation. That is why the rule is to verify all doses, not only the ones that seem off."}]}$lum$::jsonb, false),
  ($lum$65da24f6-b411-5b8e-926d-ea2708e3554e$lum$::uuid, $lum$6bbe08e8-036f-51b6-9437-82f5c1103eb5$lum$::uuid, 8, $lum$reading$lum$, $lum${"markdown":"**Mistake 3: Assuming de-identification is done when it is not**\n\nA nurse removes a patient's name and date of birth from a note before pasting it into an AI tool. The note still contains the patient's MRN in the document header, a reference to a rare diagnosis that affects very few people in the facility, and the exact date of a procedure that happened the previous Tuesday. Any one of these details can re-identify a patient, particularly in a small facility or a specialized unit. De-identification means removing all 18 HIPAA-defined identifiers, not just the most obvious ones. When in doubt about whether a detail is identifying, remove it or use a tool your organization has approved for PHI.\n\n**Mistake 4: Treating an approved enterprise tool and a personal phone app as interchangeable**\n\nYour organization may have a Microsoft Copilot instance, an Epic-integrated AI feature, or another enterprise tool that has been reviewed, approved, and covered under a BAA. That approval applies to that specific tool, under those specific terms. It does not apply to ChatGPT on your personal phone, a productivity AI your colleague mentioned, or a browser extension that summarizes text. These are separate tools with separate data handling practices. Using an unapproved tool for a task because it seems similar to your approved tool is a common compliance gap. The right question is not \"does this seem like a safe tool\" but \"has my organization specifically approved this tool for this type of data.\"\n\n**What to do instead**\n\nThe habit that prevents all four mistakes is a two-second check before acting on AI output: what is the clinical claim, and have I verified it against a real reference? Is there any patient-identifiable information in what I am about to submit, and has my organization approved this tool for it? That check, applied consistently, is the whole skill."}$lum$::jsonb, false),
  ($lum$4e7dbe5f-1a2e-5621-b9f4-649c6f0e9317$lum$::uuid, $lum$6bbe08e8-036f-51b6-9437-82f5c1103eb5$lum$::uuid, 9, $lum$fill_blank$lum$, $lum${"template":"Rule 1: AI is a {{1}} tool, not a clinical reference, so any dose or guideline it produces must be confirmed against an approved source. Rule 2: patient {{2}} like names and medical record numbers never go into a tool your organization has not {{3}} for PHI.","blanks":[{"id":"1","accept":["drafting","writing","editing","organizational"],"ideal":"drafting"},{"id":"2","accept":["identifiers","identifier","data","information","PHI"],"ideal":"identifiers"},{"id":"3","accept":["approved","authorized","cleared","vetted"],"ideal":"approved"}],"explanation":"The two rules are the foundation for every lesson in this track. AI helps you draft and organize. You verify every clinical fact against a real reference. And identifiable patient data stays out of any tool your organization has not formally approved."}$lum$::jsonb, false),
  ($lum$220a17cc-5abb-53d9-8be2-4e4753b9cce3$lum$::uuid, $lum$6bbe08e8-036f-51b6-9437-82f5c1103eb5$lum$::uuid, 10, $lum$before_after$lum$, $lum${"question":"A nurse on a cardiac step-down unit needs to draft a patient education summary for Maria Gonzalez, MRN 4471823, who is being discharged after a heart failure exacerbation. The nurse wants to use AI to write the summary and also wants to double-check the appropriate fluid restriction recommendation for her ejection fraction. Which version of this prompt is safe to use?","before_prompt":"My patient is Maria Gonzalez, MRN 4471823, a 72-year-old female with HFrEF (EF 30%), admitted 5/28 for acute decompensated heart failure. Write a discharge education summary and tell me the appropriate daily fluid restriction for someone with her ejection fraction.","after_prompt":"Write a discharge education summary for a 72-year-old female patient being discharged after an acute decompensated heart failure exacerbation. Use plain language appropriate for a patient with a sixth-grade reading level. Do not include a specific fluid restriction volume in the summary. I will verify the fluid limit against our cardiology protocol and add it after.","changes":["Removed all patient identifiers: name, MRN, admission date, and specific EF value that could re-identify the patient in context.","Stopped asking AI for the clinical fact (fluid restriction) and moved that to a verified source, the facility's cardiology protocol.","Kept AI in the drafting role it can actually fill: plain-language patient education writing."]}$lum$::jsonb, true),
  ($lum$24287d81-a015-53bd-adf4-cd46624c9725$lum$::uuid, $lum$6bbe08e8-036f-51b6-9437-82f5c1103eb5$lum$::uuid, 11, $lum$multiple_choice$lum$, $lum${"stem":"A medical assistant needs to draft a prior authorization request and wants to use AI to help structure the clinical rationale. The patient's chart has a full name, MRN, date of birth, and diagnosis codes. What is the right approach?","options":[{"id":"a","label":"De-identify the clinical details before pasting anything into the AI tool, and verify any specific clinical claims the AI produces against the source chart before submitting.","is_correct":true,"explanation":"Correct. Drafting assistance does not require identifiers. Remove them first, use AI to structure the rationale, then verify that any clinical facts in the draft match the actual chart before the authorization request goes out."},{"id":"b","label":"Paste the full chart excerpt because it is faster and the prior auth form is not a clinical record.","is_correct":false,"explanation":"The prior authorization form is a business record, but the PHI in the prompt is still PHI. Pasting identifiable patient data into an unapproved tool is a potential HIPAA violation regardless of the downstream document type."},{"id":"c","label":"Use a personal phone AI app since it is quicker than the organization's approved tool.","is_correct":false,"explanation":"A personal phone app and an organization-approved tool are not interchangeable. Approval applies to the specific tool under a specific agreement. Using an unapproved tool for PHI is a compliance issue, regardless of convenience."},{"id":"d","label":"Ask a colleague to paste the information so the medical assistant is not personally responsible.","is_correct":false,"explanation":"The privacy obligation belongs to anyone who handles the data, not just the person who submits the prompt. Routing the task through a colleague does not change the compliance requirement."}]}$lum$::jsonb, false),
  ($lum$f1a85c18-e0d5-50de-9146-6fd5ead0982f$lum$::uuid, $lum$6bbe08e8-036f-51b6-9437-82f5c1103eb5$lum$::uuid, 12, $lum$mini_project$lum$, $lum${"brief":"Pick a clinical topic you know cold, something you would not need to look up in your own work: a standard medication dose you manage regularly, a common drug interaction you routinely screen for, or a monitoring parameter from a protocol you use every shift. Ask an AI tool a specific, concrete question about it. Then check the AI's answer against your approved reference, whether that is UpToDate, your facility's formulary, your organization's clinical protocol, or a package insert.","parts":[{"id":"1","prompt":"Write down the AI's answer word for word, including any specific numbers, timeframes, or qualifications it gave."},{"id":"2","prompt":"Look up the same question in your approved reference and note where the AI was right, where it was partly right, and where it was confidently wrong."},{"id":"3","prompt":"Identify one category of clinical question where you will now treat AI output as a starting question rather than a final answer, and keep that category in mind as you work through the rest of this track."}]}$lum$::jsonb, false),
  ($lum$25c6e41d-f1c5-5d21-bb83-7d635a345b0d$lum$::uuid, $lum$90c5ee5c-f9fb-5434-8084-e8569537c541$lum$::uuid, 0, $lum$reading$lum$, $lum${"markdown":"Here is something that should worry you a little, in a useful way. An AI model does not know your numbers. It has never seen your ledger, your bank feed, or last quarter's audited statement. So when you ask it \"what was our gross margin\" and it answers \"roughly 72 percent,\" it did not look anything up. It produced text that statistically resembles an answer. The frightening part is not that it guesses. It is that it guesses in the calm, precise, confident voice of something that checked. And in finance, a confident wrong number is far more dangerous than an obvious blank.\n\nPicture Dana, an FP&A analyst building the quarterly board deck on a Sunday night. She is tired, the meeting is at eight, and she asks the AI to \"summarize the revenue trend and give me the year-over-year growth figure.\" It hands her \"revenue grew 18.4 percent year over year, driven by strong enterprise expansion.\" That sentence is perfect. It is specific, it sounds like her business, and it slots cleanly into slide four. The only problem is that the model invented 18.4 percent. The real figure, sitting in her actual export, is 11 percent. Nobody at the table will know the difference until a board member who runs the numbers asks a follow-up question Dana cannot answer, and suddenly the whole deck feels untrustworthy."}$lum$::jsonb, false),
  ($lum$2ba6568c-4a52-5d25-a0ea-a2b762f50aa9$lum$::uuid, $lum$90c5ee5c-f9fb-5434-8084-e8569537c541$lum$::uuid, 1, $lum$multiple_choice$lum$, $lum${"stem":"Dana, an FP&A analyst, asks AI for the year-over-year revenue growth figure and pastes its answer of 18.4 percent straight into the board deck. Why does this lesson treat that as a serious mistake?","options":[{"id":"a","label":"The AI produced that figure from prediction, not from any source, so it is an unverified claim that must be traced to her real revenue export before it can be reported.","is_correct":true,"explanation":"Correct. The model never saw Dana's numbers. A figure that originates inside the AI is a hypothesis, not a value of record, and in finance every reported number must trace back to a real source first."},{"id":"b","label":"The figure is fine to use because modern AI tools connect to company financial systems automatically.","is_correct":false,"explanation":"A general AI tool has no live link to Dana's ledger or export. Assuming it knows her actual revenue is exactly the trap that puts an invented number in front of the board."},{"id":"c","label":"The only issue is that she should have asked the AI for more decimal places to make the growth rate more precise.","is_correct":false,"explanation":"Precision is not the problem. A confidently precise figure like 18.4 percent can be entirely fabricated. The fix is sourcing the number against her export, not formatting it more finely."},{"id":"d","label":"Board decks should never contain growth figures at all, so any number here would be wrong.","is_correct":false,"explanation":"Growth figures absolutely belong in a board deck. The lesson is not to remove numbers, it is to verify each one against a real source before it appears."}]}$lum$::jsonb, false),
  ($lum$84f62cfd-ca6e-5ac4-a91f-585f3930b5b1$lum$::uuid, $lum$90c5ee5c-f9fb-5434-8084-e8569537c541$lum$::uuid, 2, $lum$reading$lum$, $lum${"markdown":"This is the core idea of the lesson, and it is worth saying plainly. Every number an AI gives you is a claim, not a fact. A claim is something you check. A fact is something you have already checked. The verification rule is simply this: no figure leaves your hands until you have traced it back to a real source, the actual statement, the actual ledger, the actual filing, the actual export. The number the AI asserted is a hypothesis. The number in your source document is the truth. You report the second one.\n\nIt helps to understand exactly how the failure happens, because it is not random. AI fabricates in three predictable ways, and once you can name them, you can catch them. The first is the hallucinated figure: a revenue number, a cash balance, a headcount cost that the model simply made up because you asked and it wanted to answer. The second is the invented benchmark: \"a healthy current ratio for your industry is 1.8,\" stated as if it came from a study, when it came from nowhere in particular. The third is the quiet arithmetic error: you paste real numbers and ask the model to compute, and it transposes a digit, misapplies a formula, or sums a column wrong. That third one is the sneakiest, because the inputs were real, so the output feels real too."}$lum$::jsonb, false),
  ($lum$864cf242-4b6b-5021-99af-07142d465475$lum$::uuid, $lum$90c5ee5c-f9fb-5434-8084-e8569537c541$lum$::uuid, 3, $lum$fill_blank$lum$, $lum${"template":"Every number an AI produces should be treated as a {{1}} to verify against a real source, never as a {{2}} you can report without checking.","blanks":[{"id":"1","accept":["claim","hypothesis","draft","guess"],"ideal":"claim"},{"id":"2","accept":["fact","truth","value of record","source of truth"],"ideal":"fact"}],"explanation":"The heart of the verification rule is the distinction between a claim and a fact. A figure the AI generates is a claim you must trace to a primary source. Only after you confirm it against the actual ledger, statement, or export does it become a fact you can stand behind."}$lum$::jsonb, false),
  ($lum$623339a7-c46c-51d2-8619-a0b15564c915$lum$::uuid, $lum$90c5ee5c-f9fb-5434-8084-e8569537c541$lum$::uuid, 4, $lum$reading$lum$, $lum${"markdown":"Now, none of this means AI is useless with numbers. That would be the wrong lesson, and it would cost you a genuinely powerful tool. AI is excellent at the work around the numbers. It can explain why two figures might differ. It can draft the narrative that surrounds a table you already built. It can restructure data you pasted, walk you through a calculation method so you can apply it yourself, or help you write the commentary for a variance you have already verified. The line is clean once you see it. AI is wonderful at describing numbers and dangerous at being the place numbers come from.\n\nSo draw that line hard in your own workflow. Numbers that originate in a real source, your accounting system, a bank feed, an audited statement, a filing, are trustworthy, and AI can help you talk about them all day. Numbers the model produces from memory or estimation are drafts to verify, never values to report. And when you paste your own data and ask the AI to compute something, you still check the math by hand, because the model can transpose a digit as easily as it can write a clean sentence. The figure is yours to stand behind, which means it is yours to confirm.\n\nThink about Marcus, a controller closing the month. He asks the AI to help reconcile an account and it tells him \"the difference of 4,200 is explained by the timing of the vendor accrual.\" That might be true. It might also be a complete fabrication that happens to sound plausible. The disciplined move is the same every time: he opens the actual accrual entry, looks at the actual dollar amount, and confirms it himself. If it matches, great, the AI saved him time framing the explanation. If it does not, he just caught a number that would otherwise have gone into the close with a confident story attached to it.\n\nThe habit you are building is a reflex, and reflexes are simple by design. Every time a number appears in something AI wrote for you, a quiet alarm goes off, and you ask one question: where did this come from. If you can point to the source document, the number stays. If you cannot, the number is a draft, and a draft does not go into a board deck, a filing, a covenant calculation, or a client email. That single question, asked every time, is what separates the finance professionals who use AI safely from the ones who get burned by it."}$lum$::jsonb, false),
  ($lum$64608cdc-0ffe-514c-876d-6279e088726f$lum$::uuid, $lum$90c5ee5c-f9fb-5434-8084-e8569537c541$lum$::uuid, 5, $lum$multiple_choice$lum$, $lum${"stem":"According to this segment, what is the clean line that separates where AI is safe to use with numbers from where it is dangerous?","options":[{"id":"a","label":"AI is dangerous for any task involving numbers, so it should never touch financial work in any form.","is_correct":false,"explanation":"The lesson explicitly warns against this conclusion. Treating AI as useless with numbers would cost you a genuinely powerful tool that is excellent at the work around the numbers."},{"id":"b","label":"AI is trustworthy whenever it sounds confident, and the confidence of its tone tells you the number is sound.","is_correct":false,"explanation":"Confidence is exactly what makes a fabricated figure dangerous. A calm, precise tone is not evidence the number was checked, so tone is never the dividing line."},{"id":"c","label":"AI is wonderful at describing numbers and dangerous at being the place numbers come from, so it can talk about sourced figures but should never originate them.","is_correct":true,"explanation":"Correct. The segment draws the line cleanly: numbers that originate in a real source are trustworthy and AI can help you discuss them, while numbers the model produces from memory or estimation are drafts to verify, never values to report."},{"id":"d","label":"AI can be trusted to do arithmetic on data you paste, because real inputs guarantee a correct result.","is_correct":false,"explanation":"The segment says the opposite: even when you paste your own data, you still check the math by hand, because the model can transpose a digit as easily as it can write a clean sentence."}]}$lum$::jsonb, false),
  ($lum$3b61f5d6-696e-5b0b-9754-0666353546d0$lum$::uuid, $lum$90c5ee5c-f9fb-5434-8084-e8569537c541$lum$::uuid, 6, $lum$reading$lum$, $lum${"markdown":"The verification rule sounds obvious on a calm afternoon. It breaks down in the exact moments it matters most, so it helps to know where it usually goes wrong.\n\nThe first failure is the deadline override. When the meeting is in twenty minutes and the AI hands you a clean, specific number, the temptation to just use it is enormous. The figure looks right, it fits the slide, and checking it feels like a luxury you cannot afford. This is precisely when an unverified number slips through, because pressure is the enemy of the cite-and-check habit. The fix is to make verification non-negotiable rather than optional, the same way you would never skip tying out a control just because you were busy.\n\nThe second failure is trusting the math because the inputs were real. A bookkeeper named Priya pastes her actual receivables aging into the AI and asks it to total the over-90-day bucket. The inputs came from her real system, so when the model returns a sum, it feels sourced. It is not. The model could have added a column wrong or dropped a row. Real inputs do not make the output verified. You still re-add the bucket yourself, because the arithmetic is a separate claim from the data."}$lum$::jsonb, false),
  ($lum$cc439ccf-8663-5c42-bcbc-067ad97cbb52$lum$::uuid, $lum$90c5ee5c-f9fb-5434-8084-e8569537c541$lum$::uuid, 7, $lum$multiple_choice$lum$, $lum${"stem":"Why does this segment call the deadline override the first place the verification rule breaks down?","options":[{"id":"a","label":"Because AI produces worse numbers when it senses a deadline is approaching.","is_correct":false,"explanation":"The model has no awareness of your deadline and does not produce worse numbers under time pressure. The risk lives in the human decision to skip checking, not in the AI's behavior."},{"id":"b","label":"Because under time pressure a clean, specific number is tempting to use as-is, and pressure is the enemy of the cite-and-check habit, so the fix is to make verification non-negotiable.","is_correct":true,"explanation":"Correct. The segment explains that when the meeting is minutes away, an unverified number slips through precisely because checking feels like a luxury, which is why verification must be treated as non-negotiable rather than optional."},{"id":"c","label":"Because deadlines mean the source documents are usually unavailable, so verification is impossible.","is_correct":false,"explanation":"The segment does not claim sources become unavailable. The problem is the temptation to skip checking under pressure, not a genuine inability to access the source."},{"id":"d","label":"Because rushing makes you ask the AI for fewer decimal places, which reduces accuracy.","is_correct":false,"explanation":"Decimal places are not the issue here. The deadline override is about skipping verification entirely, not about how finely a figure is formatted."}]}$lum$::jsonb, false),
  ($lum$5a4082b6-1f25-5464-9583-16d3941cb814$lum$::uuid, $lum$90c5ee5c-f9fb-5434-8084-e8569537c541$lum$::uuid, 8, $lum$reading$lum$, $lum${"markdown":"The third failure is the invented benchmark dressed up as authority. The AI tells you \"a current ratio above 2.0 is considered healthy for your sector\" and it sounds researched, so you repeat it to a client as if it were established fact. The model did not consult a study. If a benchmark matters to a decision, it needs a real source you can name, not a confident sentence from a tool that cannot cite where the number came from.\n\nThe fourth failure is the silent edit. You give the AI your real figures and ask it to write the narrative, and it quietly adds a number you never provided, a percentage, a total, a comparison, woven so smoothly into the prose that you read right past it. The defense is to instruct the model never to introduce figures you did not supply, and then to scan its output specifically for any number you do not recognize.\n\nThe thread running through all four is the same. The danger is never that AI is obviously wrong. It is that AI is plausibly, confidently, specifically wrong, in your own language, at the worst possible moment. Verification is the one habit that holds up under all of it."}$lum$::jsonb, false),
  ($lum$aff27dc1-7f32-5425-b03e-13d90e488dd9$lum$::uuid, $lum$90c5ee5c-f9fb-5434-8084-e8569537c541$lum$::uuid, 9, $lum$multiple_choice$lum$, $lum${"stem":"The silent edit failure describes the AI quietly adding a number you never provided while writing your narrative. What is the defense this segment recommends?","options":[{"id":"a","label":"Stop asking AI to write any narrative around your figures, since it cannot be trusted with prose.","is_correct":false,"explanation":"The lesson values AI for drafting narrative around verified figures. The defense is not to abandon that help, it is to constrain and then scan the output."},{"id":"b","label":"Trust the prose as long as it reads smoothly, because a fluent narrative signals the numbers are accurate.","is_correct":false,"explanation":"Smooth prose is exactly how the silent edit hides. A number woven seamlessly into fluent text is easy to read past, so fluency is no guarantee of accuracy."},{"id":"c","label":"Instruct the model never to introduce figures you did not supply, then scan its output specifically for any number you do not recognize.","is_correct":true,"explanation":"Correct. The segment names exactly this two-part defense: constrain the model up front so it does not add figures, and then actively scan the output for any unfamiliar number that slipped in anyway."},{"id":"d","label":"Run the narrative through a second AI to confirm the numbers, and accept them if both agree.","is_correct":false,"explanation":"A second model can repeat or invent figures just as confidently. Agreement between AI runs is not verification, and it is not the defense this segment describes."}]}$lum$::jsonb, false),
  ($lum$6276bd5a-26ca-50df-a00c-14f8b55a6480$lum$::uuid, $lum$90c5ee5c-f9fb-5434-8084-e8569537c541$lum$::uuid, 10, $lum$try_it_live$lum$, $lum${"instructions":"Practice writing a prompt that keeps the numbers verifiable instead of invented. Imagine you want AI's help reporting last quarter's gross margin. The wrong move is to ask the AI to recall or estimate the figure. The right move is to supply your own real numbers from a source export and ask it only to compute and explain, with the formula shown so you can check it by hand. Try this sample: you have revenue of 2,480,000 and cost of revenue of 690,000 from your accounting export, and you want gross margin plus a short, clearly labeled note on how that margin reads for a SaaS business.","system_prompt":"You are a careful finance assistant helping a non-technical professional report a figure safely. Never recall, estimate, or invent any financial number. Use only the figures the user explicitly provides. When asked to calculate, show the full formula and the steps so the user can verify the math by hand. If you add any general commentary, clearly label it as general context and not a benchmark specific to the user's company. Never introduce a number the user did not supply. Be warm, plain, and brief. No em dashes.","ideal_output":"Here is your gross margin from the figures you provided. Formula: gross margin = (revenue minus cost of revenue) divided by revenue. Steps: revenue 2,480,000 minus cost of revenue 690,000 equals gross profit of 1,790,000. Then 1,790,000 divided by 2,480,000 equals 0.7218, or about 72.2 percent. You can re-run those two steps yourself to confirm them. General context, not a benchmark for your company: a gross margin in this range is often read as strong for a software business, where the cost to serve each customer tends to be low. Treat that as a rough frame only and check any real benchmark against a named source. I have not added any figures beyond the two you gave me.","input_placeholder":"Paste your real revenue and cost of revenue, then ask for the margin and the formula..."}$lum$::jsonb, true),
  ($lum$0a198ef4-5186-5920-aad9-e5cfe2ed9c39$lum$::uuid, $lum$90c5ee5c-f9fb-5434-8084-e8569537c541$lum$::uuid, 11, $lum$multiple_choice$lum$, $lum${"stem":"Priya, a bookkeeper, pastes her actual receivables aging from her real accounting system into the AI and asks it to total the over-90-day bucket. The inputs were real, so what should she do with the total the AI returns?","options":[{"id":"a","label":"Report it as final, since the data came straight from her real system and was not invented by the AI.","is_correct":false,"explanation":"Real inputs do not make the output verified. The arithmetic is a separate claim from the data, and the model can add a column wrong or drop a row even when the source numbers are genuine."},{"id":"b","label":"Re-add the over-90-day bucket herself, because the calculation is a separate claim that needs checking even though the input data was sourced.","is_correct":true,"explanation":"Correct. Sourcing the inputs is only half the job. The total is its own claim, and a model can transpose a digit or misadd a column as easily as it writes clean prose, so the math gets checked by hand."},{"id":"c","label":"Ask the AI a second time and trust the answer if both totals match.","is_correct":false,"explanation":"Two passes from the same model can repeat the same error confidently. Agreement between AI runs is not verification. The only reliable check is re-doing the arithmetic against the real data herself."},{"id":"d","label":"Trust it because totaling a column is too simple for an AI to get wrong.","is_correct":false,"explanation":"Simple arithmetic is exactly where quiet errors hide. A dropped row or transposed digit in a long aging report is easy to miss, which is why the bucket gets re-added by hand."}]}$lum$::jsonb, false),
  ($lum$b9f9c50a-0c91-50e8-92c8-4030f7f5f3e7$lum$::uuid, $lum$90c5ee5c-f9fb-5434-8084-e8569537c541$lum$::uuid, 12, $lum$mini_project$lum$, $lum${"brief":"Take one report or summary you produce regularly that contains figures, a board slide, a month-end memo, a client update, anything with numbers in it. Your job is to run the verification rule across it from top to bottom and feel the difference between a number you can stand behind and one that merely sounds right.","parts":[{"id":"1","prompt":"For every single number in the document, mark exactly where it came from: a system export, a statement, a feed, or honestly \"not sure,\" and treat every \"not sure\" as the real finding worth fixing."},{"id":"2","prompt":"For the numbers that do have a real source, try using AI to draft the surrounding narrative by pasting the figures in rather than asking it to recall them, and then scan its output for any number you did not provide."},{"id":"3","prompt":"Re-do by hand at least one calculation the AI performed for you, even a simple total, so you experience checking arithmetic as a separate step from sourcing the data."}]}$lum$::jsonb, false),
  ($lum$1d4476a7-03b0-565e-a52e-0363b4b4827f$lum$::uuid, $lum$f26e0181-bb69-5bc5-af9a-3c6d94a2fd7e$lum$::uuid, 0, $lum$reading$lum$, $lum${"markdown":"Documentation is the part of the job that follows you home. You did the care hours ago. Now you are reconstructing it from memory and half-finished jottings, and the longer you wait the more you lose. Most clinicians know same-day charting is better, but the friction of formatting it properly is what causes the delay. You have four more patients to see, a family asking questions at the nurses station, and a medication reconciliation to finish. By the time you sit down to chart that 10 a.m. encounter, it is 3 p.m. and the details are softer than they were.\n\nAI removes the friction of expansion, not the friction of observing. Your job is still to witness the patient, make the clinical judgment, and capture the raw facts quickly. The tool turns those facts into structured prose. That division of labor is the entire point.\n\n**The three-step workflow**\n\n**Step 1: Capture in shorthand, immediately after the encounter.** Do not attempt to format. Do not worry about complete sentences. Get the clinical facts down before the next task pulls your attention. The threshold for jotting is low: whatever you would have written on a scrap of paper before you had an EHR, write that.\n\nFor a post-surgical patient on a med-surg floor, the shorthand might read: \"61F, post-op day 2 R hip arthroplasty, pain 6/10 at rest rates 8/10 with movement, Toradol 15mg IV given 0945, ambulated hallway x1 with PT assist tolerated without SOB, refused second PT session states too tired, Foley removed 0800 voided 250mL clear yellow at 1100, incision site CDI no erythema no drainage, family at bedside, daughter asked re: discharge timeline, educated re: expected day 3-4 discharge pending OT eval.\"\n\nThat block of text took about 45 seconds to write. It contains everything you need for a compliant nursing progress note: the assessment, the intervention, the patient response, the refusal with stated reason, I and O, wound assessment, and family education with topic."}$lum$::jsonb, false),
  ($lum$522e1618-8a22-5d9e-98c4-7bbd878ee44e$lum$::uuid, $lum$f26e0181-bb69-5bc5-af9a-3c6d94a2fd7e$lum$::uuid, 1, $lum$multiple_choice$lum$, $lum${"stem":"According to Step 1 of the workflow, what is the right way to capture an encounter in shorthand immediately after you leave the room?","options":[{"id":"a","label":"Write the note in complete, polished sentences so it is ready to paste later.","is_correct":false,"explanation":"Step 1 explicitly says do not attempt to format and do not worry about complete sentences. Polishing is exactly the friction the tool is meant to remove later. Your only job at capture is getting the raw clinical facts down fast."},{"id":"b","label":"Jot the raw clinical facts quickly, the way you would scribble on a scrap of paper, without formatting.","is_correct":true,"explanation":"Correct. The reading sets the threshold low: whatever you would have written on a scrap of paper before you had an EHR, write that. A 45-second block of shorthand can still contain the assessment, intervention, response, refusal, I and O, and more."},{"id":"c","label":"Wait until you have a free moment later in the shift so you can write it carefully.","is_correct":false,"explanation":"The whole point of Step 1 is to capture immediately, before the next task pulls your attention. Waiting is what causes details to soften, which is the exact problem the workflow is designed to avoid."},{"id":"d","label":"Skip the shorthand and rely on the AI to reconstruct the encounter from a brief summary.","is_correct":false,"explanation":"The tool removes the friction of expansion, not the friction of observing. It cannot witness the patient, so without your captured facts it has nothing accurate to expand. Capture comes first."}]}$lum$::jsonb, false),
  ($lum$86794f9e-6194-53bc-8bcf-31b401ac9592$lum$::uuid, $lum$f26e0181-bb69-5bc5-af9a-3c6d94a2fd7e$lum$::uuid, 2, $lum$reading$lum$, $lum${"markdown":"**Step 2: Expand using a structured prompt.** Open whatever AI tool your organization has approved for clinical use. Paste the shorthand with a prompt like this one:\n\n\"Expand these shorthand notes into a structured nursing progress note following an Assessment, Intervention, Response, and Plan format. Use only the facts I provided. Where I did not state something, leave it out rather than guessing. Flag anything that looks incomplete for a clinical note.\"\n\nThe output you receive should read something like this: \"Patient is a 61-year-old female, post-operative day 2 following right hip arthroplasty. At rest, pain rated 6/10; with movement, 8/10. Toradol 15 mg IV administered at 0945 per orders. Patient ambulated hallway one time with physical therapy assist without shortness of breath or complaints of dizziness; tolerated activity. Declined second PT session, stating fatigue as reason. Foley catheter removed at 0800; patient voided 250 mL of clear yellow urine at 1100. Surgical incision site clean, dry, and intact; no erythema or drainage observed. Daughter present at bedside; patient and family educated regarding anticipated discharge on post-operative day 3 to 4, contingent on occupational therapy evaluation.\"\n\nThat is a publishable nursing progress note. The AI did the sentence construction. You did the clinical work."}$lum$::jsonb, false),
  ($lum$8ce92c65-fdfa-5ef8-b03d-b03e34ce5536$lum$::uuid, $lum$f26e0181-bb69-5bc5-af9a-3c6d94a2fd7e$lum$::uuid, 3, $lum$multiple_choice$lum$, $lum${"stem":"The Step 2 expansion prompt includes the instruction: 'Use only the facts I provided. Where I did not state something, leave it out rather than guessing.' Why is that line in the prompt?","options":[{"id":"a","label":"It makes the note shorter so it takes less time to read.","is_correct":false,"explanation":"Length is not the goal. The instruction is about accuracy, not brevity. A note can be long and still honest, or short and still fabricated. The line targets what the tool is allowed to assert, not how much it writes."},{"id":"b","label":"It forces the AI to use the Assessment, Intervention, Response, and Plan headings.","is_correct":false,"explanation":"The format structure comes from the separate instruction to follow an Assessment, Intervention, Response, and Plan format. The 'use only the facts I provided' line does something different: it constrains the content to what you actually documented."},{"id":"c","label":"It tells the tool to leave gaps empty rather than guess, so it does not invent details you never documented.","is_correct":true,"explanation":"Correct. By instructing the tool to use only your facts and leave gaps empty, the prompt prevents it from filling in plausible-sounding details that were never part of the encounter. The output then reflects your clinical work, not the model's pattern-matching."},{"id":"d","label":"It lets the AI pull missing values from the patient's chart automatically.","is_correct":false,"explanation":"The tool has no access to the patient's chart. The instruction does the opposite of pulling in outside data: it tells the model to leave anything you did not state out of the note entirely rather than sourcing or guessing it."}]}$lum$::jsonb, false),
  ($lum$0ed7f397-f34b-5b78-8965-0ae10185e0b3$lum$::uuid, $lum$f26e0181-bb69-5bc5-af9a-3c6d94a2fd7e$lum$::uuid, 4, $lum$reading$lum$, $lum${"markdown":"**Step 3: Read every line before you sign.** This step is not optional. Read the note as if you are a risk manager reviewing it for the first time. Check that every specific claim reflects something you actually observed or documented. The AI can phrase your notes clearly. It cannot witness the patient. Any detail in the note that you did not put in the shorthand is a detail the tool invented, and an invented clinical finding is a documentation error regardless of how fluent it sounds.\n\nThree things to check on every review:\n\nFirst, check for assessment statements you never made. If your shorthand said \"pain 6/10\" and the note says \"pain well controlled at 6/10 with prior analgesic,\" the word \"well controlled\" is an interpretation you did not document. Either you agree with it and add it consciously, or you remove it.\n\nSecond, check for negative findings you never elicited. \"Patient denied nausea, dizziness, and chest pain\" is a common filler phrase AI tools insert into clinical notes because it appears in training data constantly. If you did not ask about those symptoms, that sentence does not belong in your note.\n\nThird, check that refusals and consent discussions are documented with the exact stated reason. \"Patient declined second PT session\" is weaker than \"Patient declined second PT session, stating fatigue.\" The stated reason is yours to record. The AI will sometimes smooth it into a vague clinical phrase. Put your actual words back.\n\n**One more scenario worth naming**\n\nConsider a clinical coordinator building a prior authorization letter from a provider's dictated notes on a 54-year-old male with moderate persistent asthma who has failed two step-3 agents. The shorthand captures the trial history, the spirometry values, the symptom burden score, and the specific biologic being requested. The AI expands it into a formatted payer letter with medical necessity language, ICD-10 codes, and a summary of clinical rationale. The coordinator reviews, corrects the date of the second controller trial the AI got wrong, and submits. The entire draft took four minutes instead of twenty-five.\n\nSame workflow. Same three steps. The shorthand is the bottleneck the tool removes. The review is the step that keeps the documentation accurate and legally sound."}$lum$::jsonb, false),
  ($lum$0a3e9bcc-a799-52ca-9141-67a7de1cc25e$lum$::uuid, $lum$f26e0181-bb69-5bc5-af9a-3c6d94a2fd7e$lum$::uuid, 5, $lum$multiple_choice$lum$, $lum${"stem":"You jot shorthand after a patient encounter and run the expansion prompt. The AI-generated note reads: 'Patient denied nausea and reported adequate pain control following repositioning.' Your shorthand mentioned pain at 6/10 and ambulation. You never documented asking about nausea, and you never charted repositioning. What do you do?","options":[{"id":"a","label":"Delete both fabricated details. The note may only contain what you actually observed and documented.","is_correct":true,"explanation":"Correct. The AI can phrase your notes but it cannot witness the patient. Any detail you did not place in your shorthand was invented by the tool. Charting care that did not happen is a documentation error with real liability consequences. Remove it and, if nausea assessment was clinically indicated, go back and assess the patient."},{"id":"b","label":"Keep both lines because they sound clinically plausible and strengthen the note.","is_correct":false,"explanation":"Plausible is not the same as observed. A fluent invented detail is the most dangerous kind because it reads as real to anyone who reviews the record later. A note that says 'denied nausea' when you never asked is a false record, regardless of whether the patient actually had nausea."},{"id":"c","label":"Keep the lines but add a notation that the AI generated them.","is_correct":false,"explanation":"Labeling a fabricated clinical finding does not make it acceptable in the legal medical record. The chart documents care you actually provided. Remove the fabricated lines."},{"id":"d","label":"Ask the AI whether those clinical details are accurate before deciding.","is_correct":false,"explanation":"The tool cannot know. It generated those details from pattern-matching on training data, not from your patient encounter. Only you know what you observed. Delete anything not grounded in your shorthand."}]}$lum$::jsonb, false),
  ($lum$26084bf3-c858-5f6b-97d7-c4f72ab2f23b$lum$::uuid, $lum$f26e0181-bb69-5bc5-af9a-3c6d94a2fd7e$lum$::uuid, 6, $lum$reading$lum$, $lum${"markdown":"The workflow is straightforward, but there are a handful of specific errors that show up consistently when clinicians first start using AI for documentation. Knowing them in advance means you do not have to learn them by finding them in a signed note at 2 a.m.\n\n**Pasting real patient identifiers into a non-approved tool.** This is the most common and most serious error. Most freely available AI tools are not HIPAA-covered and do not have business associate agreements with your organization. Pasting a note that contains a patient name, date of birth, MRN, or even a rare enough combination of diagnosis and procedure date can constitute a reportable breach. De-identify your shorthand before it goes anywhere that is not your organization's approved system. Replace the patient name with a role label like \"61F, post-op day 2.\" Drop the MRN entirely. Use generic dates like \"admitted two days ago\" rather than the actual admission date. The clinical facts travel fine without the identifiers. The expansion is just as useful.\n\n**Accepting a note that contains a finding you never assessed.** This is the accuracy failure. AI tools trained on clinical notes learn to produce notes that look complete, which means they learn to include negative review-of-systems statements, denial phrases, and assessment interpretations that flesh out a real note. The phrase \"patient denied chest pain, shortness of breath, and palpitations\" appears in hundreds of thousands of training examples. The tool inserts it into your output because it fits the pattern, not because you asked those questions. If you did not ask, the note now claims you did. That is not a stylistic issue. That is a false record. Read every line and remove every assertion you cannot personally verify."}$lum$::jsonb, false),
  ($lum$ae05fc0e-69da-52a9-8aab-2b746487ee86$lum$::uuid, $lum$f26e0181-bb69-5bc5-af9a-3c6d94a2fd7e$lum$::uuid, 7, $lum$fill_blank$lum$, $lum${"template":"Before pasting shorthand into an AI tool for expansion, remove all {{1}} so that no patient-identifiable information leaves your organization's approved systems. After reviewing the expanded note, delete any negative findings or assessment statements that the AI added but that you {{2}} during the actual encounter.","blanks":[{"id":"1","accept":["patient identifiers","identifiers","PHI","protected health information","identifying information","personal identifiers"],"ideal":"patient identifiers"},{"id":"2","accept":["never assessed","did not assess","never documented","did not document","never observed","did not observe","never elicited","did not elicit"],"ideal":"never assessed"}],"explanation":"De-identification protects against unauthorized disclosure of protected health information when using tools that are not covered under your organization's BAA. Removing AI-added findings you never assessed protects against documenting care that did not happen, which is a documentation error regardless of clinical plausibility."}$lum$::jsonb, false),
  ($lum$f199c2f2-16da-5117-9772-698d92cae43b$lum$::uuid, $lum$f26e0181-bb69-5bc5-af9a-3c6d94a2fd7e$lum$::uuid, 8, $lum$reading$lum$, $lum${"markdown":"**Signing without reading because the note looks complete.** A well-formatted AI note is fluent and looks like it was written by a careful clinician. That fluency is a trap. The errors are not obvious typos. They are plausible additions, softened assessments, and synthesized details that read naturally. \"Pain well-controlled with current regimen\" sounds fine, but if your shorthand said \"pain 6/10 rates 8/10 with movement\" and you never wrote that it was controlled, the AI added an interpretation. Reading the note carefully takes two to three minutes. Not reading it carefully means you are signing a document you cannot verify.\n\n**Skipping same-day documentation and trying to reconstruct from memory.** The three-step workflow only works well when your shorthand is fresh. Clinicians who capture notes right after the encounter find the AI expansion accurate and complete because the shorthand is detailed. Clinicians who try to reconstruct six hours later find the shorthand thin, which means the AI has less to work with and is more likely to fill gaps with pattern-generated language. The shorthand step is not optional. It is what makes the rest of the workflow reliable. One sentence jotted immediately after an encounter is more useful than a full paragraph reconstructed from memory.\n\n**Letting the tool smooth over a documented refusal or a difficult conversation.** If a patient refused a medication, the note needs to say so in plain language, including the stated reason if one was given. If a family member asked pointed questions about prognosis, that conversation belongs in the record. AI tools tend to soften these entries because they are trained on notes where refusals are often abbreviated and family conversations are often omitted. Review those sections actively. A chart that documents refusal with stated reason protects both the patient and the clinician. A chart that omits it or softens it creates a gap."}$lum$::jsonb, false),
  ($lum$9b1f3520-8701-5fd4-b617-ca2cf05dc3ac$lum$::uuid, $lum$f26e0181-bb69-5bc5-af9a-3c6d94a2fd7e$lum$::uuid, 9, $lum$multiple_choice$lum$, $lum${"stem":"A note your AI tool produced reads 'pain well-controlled with current regimen,' and a documented refusal of a second PT session appears in the note simply as 'patient declined therapy.' Your shorthand said 'pain 6/10 rates 8/10 with movement, refused 2nd PT states tired.' Based on the common mistakes described, what should you do before signing?","options":[{"id":"a","label":"Sign it. The note is fluent and well-formatted, which means it was written carefully.","is_correct":false,"explanation":"Fluency is described as a trap, not a sign of accuracy. A polished note can carry softened assessments and synthesized details. Signing a document you have not verified line by line is exactly the mistake the reading warns against."},{"id":"b","label":"Keep 'well-controlled' since 6/10 is moderate, but rewrite the refusal in vaguer language to sound professional.","is_correct":false,"explanation":"Both edits go the wrong direction. 'Well-controlled' is an interpretation you never documented and should come out, and the refusal should be made more specific, not vaguer. The stated reason is yours to record and protects both patient and clinician."},{"id":"c","label":"Leave the softened refusal alone because refusals are routinely abbreviated in charts anyway.","is_correct":false,"explanation":"The fact that tools learned to abbreviate refusals from training data is precisely why you must review those sections actively. A chart that omits or softens a documented refusal creates a gap rather than protection."},{"id":"d","label":"Remove the unsupported 'well-controlled' interpretation and restore the refusal with its stated reason in plain language.","is_correct":true,"explanation":"Correct. 'Well-controlled' is an assessment you never wrote and must be removed or added consciously. The refusal should be documented in plain language with the stated reason ('declined second PT session, stating fatigue'), because that record protects both the patient and the clinician."}]}$lum$::jsonb, false),
  ($lum$45594ecd-b4f1-52ed-a536-2f3692474a81$lum$::uuid, $lum$f26e0181-bb69-5bc5-af9a-3c6d94a2fd7e$lum$::uuid, 10, $lum$before_after$lum$, $lum${"question":"Same patient encounter, two different prompts. Compare the outputs you would get and notice which prompt keeps the note honest and complete.","before_prompt":"Write a nursing progress note for a post-op hip replacement patient who ambulated today and is doing okay.","after_prompt":"Expand these shorthand notes into a structured nursing progress note following Assessment, Intervention, Response, and Plan format: '61F, post-op day 2 R hip arthroplasty, pain 6/10 rest 8/10 movement, Toradol 15mg IV 0945, ambulated hallway x1 PT assist tolerated, refused 2nd PT states tired, Foley out 0800 voided 250mL clear yellow 1100, incision CDI no erythema no drainage, family at bedside daughter asked re: discharge, educated re: day 3-4 discharge pending OT eval.' Use only the facts I provided. Where I did not state something, leave it out rather than guessing. Flag anything that looks incomplete for a clinical note.","changes":["Starts from the actual captured shorthand rather than a vague description, so every specific clinical detail from the encounter is preserved in the note.","Instructs the tool to leave gaps empty rather than invent details, which prevents it from inserting negative findings or assessment interpretations you never documented.","Asks the tool to flag incompleteness, turning it into a prompt for the nurse to add missing facts rather than a generator that fills gaps silently."]}$lum$::jsonb, true),
  ($lum$94960c57-a4ee-5a93-b46f-b49f4027fd2e$lum$::uuid, $lum$f26e0181-bb69-5bc5-af9a-3c6d94a2fd7e$lum$::uuid, 11, $lum$multiple_choice$lum$, $lum${"stem":"A medical assistant uses the shorthand-expansion workflow to draft a prior authorization letter for a patient's biologic asthma medication. After the AI expands the shorthand, the letter includes a spirometry value the MA does not recognize from the provider's notes. What is the correct next step?","options":[{"id":"a","label":"Remove the unrecognized value, then check the source notes for the correct value before submitting.","is_correct":true,"explanation":"Correct. A value you cannot verify from your source material is either a fabrication or a transcription error by the tool. Both carry the same risk: submitting incorrect clinical data to a payer. Remove it, locate the correct value in the provider's notes, and add it manually."},{"id":"b","label":"Leave it in. Spirometry values are technical and the AI likely pulled it from a database.","is_correct":false,"explanation":"AI tools do not have access to the patient's chart or clinical databases. Any specific value in the output came from your shorthand or was generated. An unrecognized value is almost certainly fabricated and must not appear in a payer submission."},{"id":"c","label":"Ask the provider to verify the value before the letter goes out.","is_correct":false,"explanation":"This adds unnecessary delay. The source notes are already available. Check the spirometry value in the dictated notes yourself, correct the letter, and submit. Reserve provider escalation for genuinely ambiguous clinical questions."},{"id":"d","label":"Add a footnote saying the value was AI-generated and may need verification.","is_correct":false,"explanation":"A payer authorization letter with a footnoted unverified clinical value is not a complete submission. Remove the fabricated value, find the correct one in the source notes, and submit a clean letter."}]}$lum$::jsonb, false),
  ($lum$f9fe77c2-2644-5acc-ac5e-0578309cc156$lum$::uuid, $lum$f26e0181-bb69-5bc5-af9a-3c6d94a2fd7e$lum$::uuid, 12, $lum$mini_project$lum$, $lum${"brief":"For your next scheduled patient encounter, capture everything in pure shorthand immediately after you leave the room, before you chart anything else. Run the expansion prompt using whatever AI tool your organization has approved. Time the review-and-correct step with a clock.","parts":[{"id":"1","prompt":"In the expanded note, circle or highlight every assertion that you cannot directly trace back to a specific word in your shorthand, including any negative findings, symptom denials, or assessment interpretations the tool inserted."},{"id":"2","prompt":"Correct the note by removing fabricated details and restoring any softened documentation to your original language, then note the total review time."},{"id":"3","prompt":"Identify one place where the shorthand itself was thin enough that the AI was forced to either leave a gap or fill it with a guess, and decide whether that gap reflects incomplete documentation or a next step you need to take with the patient."}]}$lum$::jsonb, false),
  ($lum$74b957a5-12b9-5aa1-840f-c95a8cb623ad$lum$::uuid, $lum$8fd501bb-da66-5983-96ac-1dfcc2a2a773$lum$::uuid, 0, $lum$reading$lum$, $lum${"markdown":"Most people get better at their work through feedback, and customer service agents get surprisingly little of it that is actually useful and timely. A quarterly QA score hands you a number, not a thing to do differently on your next shift. Your team lead is buried in tickets and only ever pulls the conversations that went badly enough to escalate. By the time anyone reviews a chat or email with you, it is weeks old and you barely remember the customer, let alone why you phrased things the way you did. So you keep repeating the same small habits, good and bad, with nobody to point them out while they are still fresh. AI changes the math on this. You can get specific, immediate, private feedback on your own interactions, on your own terms, before any formal review and without anyone watching you learn.\n\nThe core move is simple: bring AI your own work and ask it to coach you. Take a reply you sent, or one you are about to send, strip out anything that identifies the customer, and ask a focused question. The quality of what you get back depends almost entirely on the quality of what you ask. \"How was this?\" gets you a polite shrug and some flattery, because open praise is the path of least resistance for the tool. \"Where did I sound defensive?\" or \"Did I acknowledge the emotion before I jumped to the solution?\" gets you something you can act on tomorrow. The narrower the question, the more honest and usable the answer."}$lum$::jsonb, false),
  ($lum$bcc73240-ec18-5c0a-9586-526486dd0adf$lum$::uuid, $lum$8fd501bb-da66-5983-96ac-1dfcc2a2a773$lum$::uuid, 1, $lum$multiple_choice$lum$, $lum${"stem":"According to the core move described, why does a narrow question like 'Where did I sound defensive?' work better than 'How was this?'","options":[{"id":"a","label":"An open question like 'How was this?' pulls the tool toward flattery, while a narrow question forces a specific, usable answer you can act on.","is_correct":true,"explanation":"Correct. Open praise is the path of least resistance for the tool, so a vague question gets a polite shrug. The narrower the question, the more honest and usable the answer."},{"id":"b","label":"Narrow questions are faster for the tool to process, so the feedback arrives sooner.","is_correct":false,"explanation":"Speed is not the point. The reason narrow questions work is that they force the tool past flattery into something specific you can act on, not that they are quicker to compute."},{"id":"c","label":"A narrow question lets you skip removing the customer's identifying details first.","is_correct":false,"explanation":"The opposite is implied. You still strip anything that identifies the customer regardless of how you phrase the question. The narrowness only affects the quality of the feedback."}]}$lum$::jsonb, false),
  ($lum$3082f953-55d5-572a-b85b-708e195abbae$lum$::uuid, $lum$8fd501bb-da66-5983-96ac-1dfcc2a2a773$lum$::uuid, 2, $lum$reading$lum$, $lum${"markdown":"Here is what that looks like in practice. Say a customer wrote in furious that their order arrived broken for the second time. You replied, and now you want to check yourself. You paste a de-identified version into the AI: \"Here is how I responded to a frustrated customer whose order was damaged twice. Did I acknowledge how annoyed they were before I started explaining the replacement process? Be specific.\" The AI points out that your first sentence was \"I have gone ahead and processed a new order for you.\" Practical, yes, but it skipped right past the person's feelings. It suggests opening with one line that names the frustration first, then moving to the fix. That is a concrete habit you can carry into the next damaged-order ticket and the hundred after it.\n\nA second example. You are about to send a reply to a customer asking for a refund that falls outside your policy window. You are not sure if your wording lands as firm-but-kind or as cold. So you ask: \"Does any line in this read as dismissive or like I am hiding behind the rules?\" The AI flags your sentence \"Unfortunately, our policy states that refunds are only available within thirty days.\" It explains that \"unfortunately our policy states\" reads as defensive and puts the company between you and the customer. It suggests reframing around what you can do: \"Here is what I am able to offer you instead,\" followed by the option. Same outcome for the customer, very different temperature.\n\nA third use is rehearsal. The AI can role-play a difficult customer so you can practice live before a real one shows up. You tell it: \"Play an angry customer whose subscription auto-renewed without warning. Push back on me. I want to practice staying calm and acknowledging the frustration before I explain the cancellation steps.\" It pushes, you respond, it pushes again. That kind of low-stakes, judgment-free reps are nearly impossible to get on the floor, where every conversation is real and counts. You get to fumble the first attempt in private and arrive at the live ticket already warmed up."}$lum$::jsonb, false),
  ($lum$30365a08-c52d-568f-a44c-30a2af56e7fe$lum$::uuid, $lum$8fd501bb-da66-5983-96ac-1dfcc2a2a773$lum$::uuid, 3, $lum$fill_blank$lum$, $lum${"template":"In the refund example, the line 'unfortunately, our policy states' reads as {{1}} because it puts the company between you and the customer, so the suggested fix reframes around what you {{2}} for them instead.","blanks":[{"id":"1","accept":["defensive","dismissive","cold","hiding behind the rules"],"ideal":"defensive"},{"id":"2","accept":["can do","are able to do","can offer","are able to offer","can do for them"],"ideal":"can do"}],"explanation":"The AI flags 'unfortunately our policy states' as reading defensive and putting the company between you and the customer. It suggests reframing around what you can do, such as 'Here is what I am able to offer you instead,' for the same outcome at a very different temperature."}$lum$::jsonb, false),
  ($lum$ec49df64-95ee-5b5a-89d2-555c58074c71$lum$::uuid, $lum$8fd501bb-da66-5983-96ac-1dfcc2a2a773$lum$::uuid, 4, $lum$reading$lum$, $lum${"markdown":"A fourth use is spotting your own filler and softeners. Say you tend to over-apologize, opening three different lines with \"So sorry about that.\" You paste a recent reply and ask: \"Am I apologizing more than this situation needs, and does it weaken my message?\" The AI counts the apologies back to you and points out that the repeated \"so sorry\" starts to sound automatic instead of sincere. It suggests one clear apology up front, then confident, helpful language for the rest. You did not need a manager to catch that. You just needed to ask the right question of a tool that reads your text closely and does not get bored.\n\nThe thread running through all of these is that you are coaching the fundamentals on real material, in private, at the moment you actually care. The patterns you notice while reviewing one conversation do not stay in that conversation. They show up in your phrasing, your pacing, and your instincts on the next one.\n\nTwo things keep this safe and useful. First, keep customer identifiers and personal data out of the tool. You are reviewing your own language and approach, and you can do that perfectly well on a de-identified version. Strip the name, the account number, the order ID, the email. None of that changes whether your tone worked. Second, remember the AI is a practice aid, not the authority on a good interaction. It can be wrong. It can miss the context that made your unusual choice exactly right. It does not know your customer or your account the way you did in the moment. So use it to surface things worth thinking about and to drill the basics, then apply your own judgment about what feedback actually fits. Treated that way, it becomes the most available coach you have, and the one you can reach for before anyone is grading you."}$lum$::jsonb, false),
  ($lum$2c9d2e4b-306d-567e-b0de-1355b7a35a99$lum$::uuid, $lum$8fd501bb-da66-5983-96ac-1dfcc2a2a773$lum$::uuid, 5, $lum$multiple_choice$lum$, $lum${"stem":"You are using AI to review your own customer interactions. Which approach gets you feedback you can actually use, and keeps the tool in its right role?","options":[{"id":"a","label":"Paste the full conversation with the customer's name and account, and ask 'was this good?' for an overall verdict.","is_correct":false,"explanation":"This fails twice. It exposes customer data to the tool, and a vague 'was this good' invites flattery instead of usable feedback. Both the privacy and the framing are wrong."},{"id":"b","label":"Ask a specific, de-identified question like 'did I acknowledge the emotion before solving,' and treat the answer as input to your own judgment, not the final word.","is_correct":true,"explanation":"Correct. A specific question yields actionable critique, removing identifiers protects the customer, and remembering the AI can miss context keeps it as a practice aid rather than the authority on your work."},{"id":"c","label":"Treat the AI's critique as the definitive verdict on your performance and change your approach to match it exactly.","is_correct":false,"explanation":"The AI is a practice aid, not the authority. It can be wrong or miss the context that made your choice right. You use it to surface things worth considering, then apply your own judgment about what fits."}]}$lum$::jsonb, false),
  ($lum$6729a11c-96fd-5fa5-b792-9f6257c719f5$lum$::uuid, $lum$8fd501bb-da66-5983-96ac-1dfcc2a2a773$lum$::uuid, 6, $lum$reading$lum$, $lum${"markdown":"The tool only helps if you use it well, and there are a few mistakes that quietly cancel out the benefit. They are easy to make, so it is worth naming them plainly.\n\nThe first is a privacy mistake. In a hurry, agents paste the entire conversation straight from the ticket, the customer's full name, their account number, their email, the order ID, all of it. None of that information helps the AI coach your tone or your structure. You are reviewing how you wrote, not who you wrote to. Before anything goes into the tool, scrub the identifiers. Replace the name with \"the customer,\" strip the account and order numbers, remove the email and phone. If you would not want that data sitting in a third-party tool, do not put it there. The de-identified version teaches you exactly the same lesson."}$lum$::jsonb, false),
  ($lum$14731b9d-b29d-553e-8bd3-e32d131557a4$lum$::uuid, $lum$8fd501bb-da66-5983-96ac-1dfcc2a2a773$lum$::uuid, 7, $lum$multiple_choice$lum$, $lum${"stem":"When the privacy mistake says to scrub identifiers before pasting a conversation, what is the reason it gives that this costs you nothing?","options":[{"id":"a","label":"The tool refuses to process replies that still contain account numbers or emails.","is_correct":false,"explanation":"Nothing in the passage says the tool blocks identifiers. The point is that you choose to strip them because they do not help, not that the tool forces you to."},{"id":"b","label":"The identifying details do not help the AI coach your tone or structure, so the de-identified version teaches exactly the same lesson.","is_correct":true,"explanation":"Correct. You are reviewing how you wrote, not who you wrote to. None of the customer data helps coach your tone or structure, so the scrubbed version teaches the same lesson with no loss."},{"id":"c","label":"Removing identifiers makes the AI's feedback arrive faster and in more detail.","is_correct":false,"explanation":"Speed and detail are not the reason given. The reason is that the identifying data is irrelevant to coaching your writing, so removing it changes nothing about the lesson."}]}$lum$::jsonb, false),
  ($lum$5fc22214-ff16-5674-ab5b-f585d1662578$lum$::uuid, $lum$8fd501bb-da66-5983-96ac-1dfcc2a2a773$lum$::uuid, 8, $lum$reading$lum$, $lum${"markdown":"The second is asking the wrong question. \"Was this good?\" feels efficient, but it is the worst prompt you can give. Open-ended approval questions pull the AI toward reassurance, and you walk away with a warm feeling and nothing to change. The fix is to aim the question at a specific behavior you can hear in your own writing. \"Where did I sound defensive?\" \"Did I name the emotion before the solution?\" \"Was my next step clear, or did I leave the customer guessing?\" \"Did I over-apologize?\" Specific in, specific out. A pointed question forces the tool past flattery and into something you can actually drill.\n\nThe third mistake is the most subtle and the most important. It is treating the AI's critique as the final verdict on your performance. The AI is confident and fluent, so it is tempting to take its read as the truth and rewrite yourself around it. But it does not know your customer. It did not see the three earlier messages where that person told you they just wanted to be heard, not handed a process. It cannot tell that your slightly blunt line was the right call because this particular customer had explicitly asked you to skip the pleasantries. The AI works only from the words you paste, with none of the context that lived in your head during the real exchange. So when it flags something, treat that as \"worth a second look,\" not \"you got this wrong.\" Sometimes you will agree and adjust. Sometimes you will realize the AI is missing the very thing that made your choice correct, and you will keep your version. Both are wins, because in both cases you thought about it on purpose. The danger is handing over your judgment to a tool that has less information than you do. Use it to sharpen your instincts, not to replace them."}$lum$::jsonb, false),
  ($lum$309eb533-b35f-54a5-abe7-2e0fe355767e$lum$::uuid, $lum$8fd501bb-da66-5983-96ac-1dfcc2a2a773$lum$::uuid, 9, $lum$fill_blank$lum$, $lum${"template":"Before pasting a reply into the AI for coaching, remove all customer {{1}} so you are reviewing only your own language. And when the AI critiques your work, treat its feedback as input to your own {{2}}, not as the final verdict, because it cannot see the context you had in the real conversation.","blanks":[{"id":"1","accept":["identifiers","identifying details","identifying information","personal data","personal details","identifying data","identity details"],"ideal":"identifiers"},{"id":"2","accept":["judgment","judgement","judgment call","discretion","decision"],"ideal":"judgment"}],"explanation":"You strip customer identifiers because you are reviewing your own approach, not the customer's data, and a de-identified version teaches the same lesson safely. You treat the critique as input to your own judgment because the AI works only from the words you pasted and can miss the context that made your choice right."}$lum$::jsonb, false),
  ($lum$19417330-c45e-5242-bb15-ebadce3033f1$lum$::uuid, $lum$8fd501bb-da66-5983-96ac-1dfcc2a2a773$lum$::uuid, 10, $lum$try_it_live$lum$, $lum${"instructions":"Bring the AI one of your own replies, de-identified, and ask for specific coaching. Or use the sample: a reply you sent to a frustrated customer where you want to know if you acknowledged the emotion before jumping to the solution. Strip the name, account, and order details first.","system_prompt":"You are a supportive but honest customer-service coach reviewing an agent's own interaction. The agent shares a de-identified reply and a focused question. Give specific, actionable feedback: name one or two genuine strengths with the exact phrasing that worked, then one or two concrete improvements with a suggested rewrite of the relevant line. Focus on acknowledgment, tone, clarity, and whether the emotion was addressed before the solution. Be direct and useful rather than flattering. Remind the agent that you may be missing context they had, and that their own judgment about their own customer comes first. No jargon. No em dashes.","ideal_output":"Here is specific feedback on your reply. I am working only from what you shared, so trust your own read where you had context I do not.\n\nWhat worked: You opened with 'I can see how frustrating this must be,' which names the emotion before you get into logistics. That is the right order, and a lot of agents skip it. You also closed with a clear next step, so the customer knows what happens now.\n\nWhere to strengthen: The middle line, 'Unfortunately, our policy states,' is likely to read as defensive and pull the temperature back up right after you brought it down. Try owning the help instead: 'Here is what I am able to do for you,' then state the option. It keeps you on the customer's side rather than the policy's side.\n\nOne thing to drill: practice swapping any 'unfortunately our policy' opening for a 'here is what I can do' opening. Want to run a quick role-play where I play the upset customer so you can rehearse that switch?","input_placeholder":"Paste your de-identified reply and a specific question about it..."}$lum$::jsonb, true),
  ($lum$30f72f26-8a6f-58cc-bcc6-53478e29a85f$lum$::uuid, $lum$8fd501bb-da66-5983-96ac-1dfcc2a2a773$lum$::uuid, 11, $lum$multiple_choice$lum$, $lum${"stem":"You ran one of your own de-identified replies through the AI and it flagged a line as 'too blunt.' But you remember that this specific customer had asked you to skip the pleasantries and just give them the answer. What is the right move?","options":[{"id":"a","label":"Rewrite the line to be softer, since the AI flagged it and it knows tone better than you do.","is_correct":false,"explanation":"The AI does not know your customer or the earlier messages. It is working only from the words you pasted. Overriding your own context because the tool sounds confident is exactly the mistake to avoid."},{"id":"b","label":"Keep your version this time, since you had context the AI lacked, and note the flag as a reminder to check your bluntness on customers who did not ask for it.","is_correct":true,"explanation":"Correct. You treat the critique as input, not verdict. The AI missed the context that made your choice right, so you keep your call here while still using the flag to sharpen your instinct for next time."},{"id":"c","label":"Stop using the AI for coaching, since it clearly cannot understand your conversations.","is_correct":false,"explanation":"One miss does not make the tool useless. It is a practice aid that surfaces things worth a second look. The skill is applying your own judgment to its feedback, not abandoning the tool entirely."}]}$lum$::jsonb, false),
  ($lum$57699ea0-63a9-51f2-a5fe-dff25bcf0578$lum$::uuid, $lum$8fd501bb-da66-5983-96ac-1dfcc2a2a773$lum$::uuid, 12, $lum$mini_project$lum$, $lum${"brief":"Pick three of your own recent interactions, ideally a mix: one that went well, one that felt rocky, and one routine. De-identify each one by stripping the customer's name, account number, order details, and contact info. Bring each to the AI with a specific question rather than \"was this good,\" for example \"where did I sound defensive,\" \"did I acknowledge the emotion before the solution,\" or \"was my next step clear.\" Note which feedback genuinely lands and, just as important, any feedback that misses context you actually had. Then pick the single most useful recurring improvement across all three and drill it, optionally with an AI role-play of a tough customer, while keeping the final judgment yours.","parts":[{"id":"1","prompt":"De-identify three recent replies (one strong, one rocky, one routine) by removing every customer identifier before anything goes into the tool."},{"id":"2","prompt":"Ask each one a specific, behavior-focused question and write down both the feedback that fits and the feedback that misses your real context."},{"id":"3","prompt":"Choose the one recurring improvement that would help most, and drill it with an AI role-play until the new phrasing feels natural."}]}$lum$::jsonb, false),
  ($lum$52060ad0-a5bb-5cf0-af72-c95189d8f807$lum$::uuid, $lum$80375829-ef95-598c-8b3f-dc9da43e1617$lum$::uuid, 0, $lum$reading$lum$, $lum${"markdown":"AI quality monitoring is spreading fast in customer service, and there is a good chance it has already arrived on your team or soon will. The old way was a supervisor pulling a handful of calls or chats each month and scoring them by hand. The new way is an AI system that scores every single interaction against a rubric: did you acknowledge the issue, did you follow the process, was your tone appropriate, did you resolve the ticket. When you first hear about it, it can feel like surveillance. Understood properly, it is a tool with real strengths and real blind spots, and knowing both is what lets you work alongside it instead of under it.\n\nStart with the strengths, because they are genuine. A human supervisor can review maybe two percent of your conversations. An AI can review all of them. It can catch consistency problems you would never see from a sample, like a step you skip when you are tired at the end of a shift. It can surface coaching opportunities while they are still fresh instead of in a review three months later. For a new agent, that fast and steady signal can genuinely speed up learning. None of that is fake, and pretending the tool is worthless will not serve you."}$lum$::jsonb, false),
  ($lum$868ea791-c6aa-5784-8a33-38d2104fb60e$lum$::uuid, $lum$80375829-ef95-598c-8b3f-dc9da43e1617$lum$::uuid, 1, $lum$multiple_choice$lum$, $lum${"stem":"According to the reading, what is the core difference between the old way of quality review and AI quality monitoring?","options":[{"id":"a","label":"The old way scored every interaction while AI monitoring scores only a small sample.","is_correct":false,"explanation":"It is the reverse. The old way was a supervisor scoring a handful of calls or chats by hand, while the AI scores every single interaction."},{"id":"b","label":"A human supervisor could review only a small fraction of conversations, while the AI can review all of them, catching consistency problems a sample would miss.","is_correct":true,"explanation":"Correct. The reading notes a supervisor can review maybe two percent of conversations while an AI can review all of them, surfacing consistency issues you would never see from a sample."},{"id":"c","label":"AI monitoring removes the rubric entirely and judges interactions on overall feel.","is_correct":false,"explanation":"The AI still scores against a rubric, checking things like acknowledgment, process, tone, and resolution. It does not replace the rubric with a feel-based judgment."}]}$lum$::jsonb, false),
  ($lum$cc8a634b-e5f5-593f-b735-81b3ebeb130f$lum$::uuid, $lum$80375829-ef95-598c-8b3f-dc9da43e1617$lum$::uuid, 2, $lum$reading$lum$, $lum${"markdown":"Now the blind spots, because they are just as genuine and they are the part nobody warns you about. These systems score patterns, not meaning. They are very good at spotting whether your words match the shape of a \"good\" interaction and very bad at knowing whether you actually helped the human on the other end.\n\nPicture three real situations. First, a billing agent gets a customer whose mother just died and who is calling to close her account. The standard process is to walk through a retention offer before closing. The agent reads the moment, skips the retention script entirely, and closes the account gently and quickly. The rubric was looking for the retention step. It was not there, so the interaction gets dinged on \"process adherence.\" The agent did exactly the right thing and the score went down.\n\nSecond, think about what a rubric actually measures. A typical one scores four things: acknowledgment, process, tone, and resolution. An AI can check that you said \"I understand how frustrating this is,\" that you ran the troubleshooting steps in order, that no harsh words appeared, and that the ticket got marked solved. Each of those is a pattern it can detect. What it cannot detect is whether your \"I understand how frustrating this is\" landed as sincere or as a hollow line you paste into every chat. It can reward the agent who hits all four checkboxes while leaving the customer feeling like a number, and it can penalize the agent who threw out the script to actually fix the problem. Sincere warmth can read as off-pattern. Checkbox-hitting can read as excellent."}$lum$::jsonb, false),
  ($lum$cde2d5f7-71e2-532f-a9ec-0bbf29adbde1$lum$::uuid, $lum$80375829-ef95-598c-8b3f-dc9da43e1617$lum$::uuid, 3, $lum$fill_blank$lum$, $lum${"template":"These systems score {{1}}, not {{2}}. They are good at spotting whether your words match the shape of a good interaction, but bad at knowing whether you actually helped the person.","blanks":[{"id":"1","accept":["patterns","pattern","the pattern","patterns of words"],"ideal":"patterns"},{"id":"2","accept":["meaning","the meaning","context","intent"],"ideal":"meaning"}],"explanation":"The reading states these systems score patterns, not meaning. They detect whether words match the shape of a good interaction but cannot tell whether you genuinely helped the customer."}$lum$::jsonb, false),
  ($lum$0ab3672b-3fce-58de-8b6e-8ce84f34a58e$lum$::uuid, $lum$80375829-ef95-598c-8b3f-dc9da43e1617$lum$::uuid, 4, $lum$reading$lum$, $lum${"markdown":"Third, picture how scores get used in practice. An agent has a run of low scores over two weeks. On a smart team, that pattern is not a verdict. It is a trigger. It opens a human review where a supervisor pulls the actual conversations and reads them. Maybe the agent really is rushing customers and needs coaching. Or maybe this agent caught a string of unusual, high-stakes cases where breaking the template was the correct call, and the rubric simply had no way to see that. You only learn which by reading the real interactions. The score told you where to look. It did not tell you what you found.\n\nThat gap is the whole lesson. The scores are signals worth investigating, not verdicts to act on blindly. A pattern of low scores is a reason to look closer, not grounds on its own for a consequential decision about a person. Anything that affects someone's standing, coaching, a performance rating, a warning, needs a human who can read the context the model cannot. A high score is not proof of a good interaction, and a low score is not proof of a bad one. They are both clues.\n\nFor you as an agent, the practical move is to engage with it rather than fear it. Use the feedback that is genuinely useful, because plenty of it will be. Recognize when a low score reflects the system missing context rather than a real miss on your part. And be ready to make that case with the specific interaction in hand, calmly and with evidence. The goal is a partnership where the AI handles the scale and humans supply the judgment. It is not a regime where a score becomes a verdict that nobody is allowed to question. When you understand the tool this well, you stop being afraid of it and start using it."}$lum$::jsonb, false),
  ($lum$a035248f-c4fc-5553-8e91-73761f8f8365$lum$::uuid, $lum$80375829-ef95-598c-8b3f-dc9da43e1617$lum$::uuid, 5, $lum$multiple_choice$lum$, $lum${"stem":"An AI monitoring system flags one of your interactions with a low quality score, but you handled an unusual situation by sensibly departing from the standard script. How should that score be treated?","options":[{"id":"a","label":"As an accurate verdict, since the AI reviewed the interaction objectively against the rubric.","is_correct":false,"explanation":"The rubric scores observable patterns, not the context that can make an unusual response correct. Treating the score as an objective verdict is exactly the trap, because it can penalize good judgment that broke the template for a real reason."},{"id":"b","label":"As a signal worth investigating, not a verdict, since the system scores patterns and can miss the context that made an off-script response exactly right. A human should review the actual conversation.","is_correct":true,"explanation":"Correct. AI monitoring catches patterns at scale but misses meaning and context. A low score is a prompt to look closer, not proof of a bad interaction, and any consequential judgment needs a human reading the real conversation."},{"id":"c","label":"As irrelevant, since AI monitoring is never useful and should be ignored entirely.","is_correct":false,"explanation":"That overcorrects. The monitoring has real strengths: scale, consistency, fast coaching signals. The point is to treat scores as signals to investigate rather than verdicts, not to dismiss the tool wholesale."}]}$lum$::jsonb, false),
  ($lum$35bb91d1-8476-5f48-8ef1-3a974e5c98be$lum$::uuid, $lum$80375829-ef95-598c-8b3f-dc9da43e1617$lum$::uuid, 6, $lum$reading$lum$, $lum${"markdown":"A few predictable mistakes show up once a team starts using AI quality monitoring. Knowing them ahead of time keeps you from falling into any of them.\n\nThe first and most damaging mistake is treating an AI score as an objective verdict and making a real decision about a person on the score alone. A supervisor sees a low number, writes up the agent, and never reads the conversation. This is the same error people make with any AI output: mistaking a confident result for a true one. The AI did not watch the interaction. It measured whether the words matched a pattern. When you let a number stand in for reading the actual conversation, you can punish the agent who did the right thing and reward the one who gamed the format. No consequential decision about a person should ever rest on a score by itself. The score points you to the conversation. A human still has to go read it.\n\nThe second mistake comes from the agent's side: gaming the rubric instead of helping the customer. Once you know the AI is checking for \"I understand how frustrating this is\" and a resolution tag, it is tempting to paste that line into every chat and mark tickets solved to keep your numbers clean, even when the customer is not actually helped. You can hit every checkbox and leave someone worse off than you found them. The rubric was always a rough stand-in for the real goal, which is a customer who got what they needed. The moment you optimize for the stand-in instead of the goal, the score climbs while the actual work gets worse. Hit the rubric because you genuinely served the customer, not the other way around."}$lum$::jsonb, false),
  ($lum$b363ce02-3f95-5f5e-88be-ccec20d6ef1d$lum$::uuid, $lum$80375829-ef95-598c-8b3f-dc9da43e1617$lum$::uuid, 7, $lum$multiple_choice$lum$, $lum${"stem":"A supervisor sees a low AI score, writes up the agent, and never reads the conversation. The reading calls this the first and most damaging mistake. Why?","options":[{"id":"a","label":"Because the supervisor should have waited for several low scores to accumulate before acting on a single number.","is_correct":false,"explanation":"The problem is not the count of low scores. It is that no consequential decision about a person should rest on a score at all without a human reading the actual conversation."},{"id":"b","label":"Because the AI score is always wrong and supervisors should ignore the monitoring output completely.","is_correct":false,"explanation":"The reading does not say the score is always wrong. It says a confident result is not the same as a true one, so the score points you to the conversation that a human still has to read."},{"id":"c","label":"Because the AI only measured whether the words matched a pattern, so letting a number replace reading the conversation can punish the agent who did the right thing.","is_correct":true,"explanation":"Correct. The AI did not watch the interaction; it measured pattern-matching. Letting a number stand in for the real conversation can punish good work and reward the agent who gamed the format."}]}$lum$::jsonb, false),
  ($lum$759caf42-e14f-5636-a0c0-acca27abfa2c$lum$::uuid, $lum$80375829-ef95-598c-8b3f-dc9da43e1617$lum$::uuid, 8, $lum$reading$lum$, $lum${"markdown":"The third mistake is over-trusting the monitoring AI as an authority, treating it as if it knows something you do not. It does not have secret insight into your conversations. It is a pattern-matcher with a rubric, confident and consistent, and confidence is not the same as being right. This is the general lesson that runs through all of this work: an AI's output is a useful input, not a judgment from on high. The monitoring system is no more an authority than a chatbot or a search result. It gives you a signal. You and your supervisor supply the judgment about what the signal means.\n\nNotice that all three mistakes share one root. They all let the AI's output stand in for human judgment, just in different directions. The supervisor lets the score replace reading the conversation. The agent lets the rubric replace helping the customer. Everyone lets the tool's confidence replace their own thinking. The fix is the same every time. Treat the score as one input, go look at the real thing it points to, and keep a person in the loop wherever the decision actually matters. The tool is good at scale. It is not good at meaning, and meaning is the part that counts."}$lum$::jsonb, false),
  ($lum$490cb745-4a4f-5e5e-8e80-d9d002f34cd2$lum$::uuid, $lum$80375829-ef95-598c-8b3f-dc9da43e1617$lum$::uuid, 9, $lum$multiple_choice$lum$, $lum${"stem":"The reading says all three mistakes share one root. What is it?","options":[{"id":"a","label":"They all let the AI's output stand in for human judgment, just in different directions.","is_correct":true,"explanation":"Correct. The supervisor lets the score replace reading the conversation, the agent lets the rubric replace helping the customer, and everyone lets the tool's confidence replace their own thinking."},{"id":"b","label":"They all come from the rubric being too short and needing more scoring categories.","is_correct":false,"explanation":"The shared root is not the rubric's length. It is letting the AI's output substitute for human judgment, which a longer rubric would not fix."},{"id":"c","label":"They all happen because the monitoring AI is poorly trained and gives inaccurate scores.","is_correct":false,"explanation":"The reading frames the issue as a pattern-matcher being trusted too much, not as a poorly trained model. The fix is keeping a human in the loop, not retraining the AI."}]}$lum$::jsonb, false),
  ($lum$70bd1df6-d080-5ec9-af20-afe380bc5020$lum$::uuid, $lum$80375829-ef95-598c-8b3f-dc9da43e1617$lum$::uuid, 10, $lum$before_after$lum$, $lum${"question":"Your team is setting up how AI quality scores get used. Which framing prompt produces a fair, workable approach?","before_prompt":"Set up an AI system to score all our agent conversations and rank agents by their scores.","after_prompt":"Help me design how our team should use an AI quality-monitoring tool fairly. I want it to score interactions at scale to surface coaching opportunities and consistency issues, but I do not want scores treated as verdicts. Draft a short policy where: scores are signals that trigger a human review of the actual conversation, no consequential decision about an agent rests on a score alone, agents can flag when a low score missed the context of an unusual situation, and the emphasis is coaching over ranking. Also note where the AI is likely to misread context, like a sensible off-script departure or sincere warmth reading as off-pattern, so reviewers know to watch for it.","changes":["Reframes scores as signals that trigger a human review of the real conversation, not as verdicts or a ranking.","Puts a human in every consequential decision, where the model's context-blindness does the most damage, and gives agents a path to flag a score that missed the situation.","Names the model's specific blind spots, like off-script departures and sincere warmth, so reviewers compensate instead of trusting the number."]}$lum$::jsonb, true),
  ($lum$46140d2b-0e10-5b25-930d-7da957640b29$lum$::uuid, $lum$80375829-ef95-598c-8b3f-dc9da43e1617$lum$::uuid, 11, $lum$multiple_choice$lum$, $lum${"stem":"You are writing your team's policy for using AI quality scores. Which rule best protects against the tool's blind spots while keeping its benefits?","options":[{"id":"a","label":"Rank agents monthly by average AI score and base coaching priority on that ranking, since it covers every conversation objectively.","is_correct":false,"explanation":"Ranking treats the score as a verdict and ignores that the AI misses context. An agent who caught hard cases and broke templates correctly could rank low, so a ranking-first policy punishes good judgment."},{"id":"b","label":"Turn the monitoring off entirely and go back to a supervisor sampling a few conversations by hand each month.","is_correct":false,"explanation":"This throws away the real benefits of scale, consistency, and fast coaching signals. The goal is to use the tool well, with humans supplying judgment, not to abandon it."},{"id":"c","label":"Use scores to flag patterns worth a closer look, then have a human read the actual conversations before any decision about an agent, and let agents flag scores that missed context.","is_correct":true,"explanation":"Correct. This keeps the AI doing what it is good at, scanning everything for patterns, while a human supplies the meaning and context the model cannot. No consequential decision rests on a number alone, and agents have a path to contest a misread."}]}$lum$::jsonb, false),
  ($lum$58fc0c53-3b40-5fc7-8579-efdae75f64ea$lum$::uuid, $lum$80375829-ef95-598c-8b3f-dc9da43e1617$lum$::uuid, 12, $lum$mini_project$lum$, $lum${"brief":"Get hands-on with how quality monitoring actually scores your work. Take three of your own real interactions from the past week and score them yourself against the rubric your team uses, or the one it would use if monitoring arrived tomorrow. For each one, think hard about where an AI scorer would agree with you and where it would misread something, like penalizing a sensible departure from script, missing genuine warmth that reads as off-pattern, or rewarding a clean resolution tag on a ticket that was not really fixed. Then write up the specific blind spots a human reviewer should watch for in your kind of work, so your team's policy can account for them.","parts":[{"id":"1","prompt":"Pull three recent real interactions and score each one yourself against your team's rubric, writing the number next to each."},{"id":"2","prompt":"For every interaction, note one place the AI would likely misread the context and explain in a sentence why a human reading the conversation would score it differently."},{"id":"3","prompt":"Write a short list of two or three specific blind spots a human reviewer should watch for in your work, and draft a brief note making the case for one interaction where a low score would not reflect a bad conversation."}]}$lum$::jsonb, false),
  ($lum$ab2b9e75-4c5b-5026-abfd-0fb13e586030$lum$::uuid, $lum$6fdd9be2-1452-5d0a-834a-82115aeb9f66$lum$::uuid, 0, $lum$reading$lum$, $lum${"markdown":"Escalations fail at the handoff more than anywhere else. You have spent ten minutes with a customer, tried a few things, and now you need to pass the ticket up to a senior agent or sideways to a different team. You are mid-shift, three other chats are open, and the queue is climbing. So you type something fast: \"customer upset about refund, please advise.\" Then you move on.\n\nThe person who picks that up has two bad options. They can reread the entire thread to reconstruct what happened, which burns time and stalls the customer. Or they can ask the customer to explain it all over again. That second one is the fastest way to turn a frustrated person into a furious one, because it tells them nobody was listening and nobody is actually in charge of their problem. The handoff was supposed to carry the story forward. Instead it dropped it.\n\nA clean handoff fixes this, and its anatomy is simple. It has four parts. First, a one-line situation summary, so the receiver knows what they are walking into. Second, what you already tried and the result of each attempt, so they do not repeat your steps or contradict what you told the customer. Third, the customer's current state and what they expect to happen, so the receiver knows the emotional temperature and the goal. Fourth, a specific statement of what you need the receiver to do or decide. Not \"please advise.\" Something the next person can act on."}$lum$::jsonb, false),
  ($lum$e5f6066b-188f-5e11-a925-1d7a384c1f52$lum$::uuid, $lum$6fdd9be2-1452-5d0a-834a-82115aeb9f66$lum$::uuid, 1, $lum$multiple_choice$lum$, $lum${"stem":"What is a clean escalation handoff, and what does AI actually do for it?","options":[{"id":"a","label":"A full copy of the chat transcript pasted into a note, so the receiver has everything.","is_correct":false,"explanation":"The whole point of a handoff is that the receiver does NOT have to reread the transcript. Pasting the full thread recreates the exact problem a handoff solves: it forces the next person to reconstruct the story themselves."},{"id":"b","label":"A tight summary written for the receiver, the situation, what was tried, the customer's state, and what you need next, and AI structures your rough notes into it in seconds.","is_correct":true,"explanation":"Correct. A clean handoff is a short, scannable summary aimed at the person receiving it, covering the four parts. AI's job is to take your messy mid-shift notes and shape them into that structure fast, so you are not writing it from scratch under pressure."},{"id":"c","label":"A polished message written to the customer apologizing for the escalation.","is_correct":false,"explanation":"A handoff is written for the receiver, not the customer. A customer apology is a different task. Confusing the two means the senior agent or tier 2 still has no idea what you tried or what you need."},{"id":"d","label":"A one-line note like 'please advise' that lets the receiver decide how to proceed.","is_correct":false,"explanation":"'Please advise' is the failed handoff this lesson is built around. It carries no situation, no attempts, no customer state, and no specific ask, so the receiver has to reread or re-ask everything."}]}$lum$::jsonb, false),
  ($lum$f6213ce6-3c30-533b-b125-3861c6ce7c0e$lum$::uuid, $lum$6fdd9be2-1452-5d0a-834a-82115aeb9f66$lum$::uuid, 2, $lum$reading$lum$, $lum${"markdown":"The reason agents skip this is not laziness. It is time. Writing four tight, accurate parts under pressure is real work, and the queue does not pause while you do it. That is exactly the gap AI closes. You hand the model your rough notes, even half-formed ones, and ask it to structure them into a handoff. What comes back is the clean summary you would write if you had ten unhurried minutes, produced in seconds. You read it, fix anything off, and send it on.\n\nHere is what that looks like in three real situations.\n\nA refund outside the return window. A customer bought a coffee grinder forty days ago, and your return window is thirty. They say it started grinding unevenly after two weeks. You confirmed the purchase date, explained that it is past the window, and offered store credit as a goodwill gesture. They declined the credit and asked for a manager. Your rough note might be: \"grinder, 40 days, past window, offered credit, said no, wants mgr.\" Hand that to AI and the handoff comes back structured: situation is a refund request outside policy; what you tried is confirming the date, explaining the policy, and offering store credit, which was declined; customer state is frustrated but reasonable, feels the product failed early, wants a manager to reconsider; what you need is a decision on a one-time exception or a clear alternative to offer. The senior agent reads four lines and steps in fully briefed."}$lum$::jsonb, false),
  ($lum$97d91359-10a6-5a3e-b2af-587170eaf8e0$lum$::uuid, $lum$6fdd9be2-1452-5d0a-834a-82115aeb9f66$lum$::uuid, 3, $lum$fill_blank$lum$, $lum${"template":"Agents skip writing a clean handoff not out of laziness but because of {{1}}. The model's contribution to the handoff is the {{2}}, which it produces in seconds from your rough notes.","blanks":[{"id":"1","accept":["time","lack of time","the queue","time pressure","pressure"],"ideal":"time"},{"id":"2","accept":["structure","the structure","structuring","shape","the shape"],"ideal":"structure"}],"explanation":"Agents skip the four-part handoff because writing it accurately under pressure takes time the queue will not give them. AI closes that gap by taking rough notes and producing the clean structure fast, so the only work left for you is confirming accuracy."}$lum$::jsonb, false),
  ($lum$0f661e86-b8bc-59c4-8f39-7314119972c3$lum$::uuid, $lum$6fdd9be2-1452-5d0a-834a-82115aeb9f66$lum$::uuid, 4, $lum$reading$lum$, $lum${"markdown":"A billing dispute handed to a senior agent. A customer was charged twice for the same monthly subscription. You confirmed in the system that two charges posted on the same date, issued a refund for the duplicate, and told them it would land in three to five business days. They are still upset because this is the second month it has happened and they want to know why. This is past your tools, so you escalate. The rough note: \"double charged again, refunded the dupe, but recurring problem, wants root cause, angry.\" The structured handoff makes clear that the immediate money issue is already handled, the open question is why the duplicate keeps recurring, and the senior agent needs to investigate the billing record, not re-refund anything. That distinction saves the customer from a second refund and a longer wait.\n\nA technical issue passed to tier 2. A customer cannot log in to their account on the mobile app. You walked them through a password reset, confirmed they are using the right email, and had them reinstall the app. The reset email never arrived and the reinstall did not help. The login works fine on desktop for them, just not mobile. Your note: \"no login on mobile, reset email not arriving, reinstalled, desktop works fine, app version current.\" The handoff tells tier 2 the exact narrowed-down problem so they do not start from \"have you tried resetting your password,\" which the customer has already done twice and will not enjoy hearing a third time. It also flags the desktop-works detail, which points tier 2 toward the mobile app or the email delivery rather than the account itself, saving them the first round of guessing.\n\nIn all three, the structure is the easy win AI hands you. The accuracy is yours to confirm before it goes. The next block is the checkpoint on that core idea."}$lum$::jsonb, false),
  ($lum$362d17c5-97bf-57d6-99d8-2b1b0db9ed9d$lum$::uuid, $lum$6fdd9be2-1452-5d0a-834a-82115aeb9f66$lum$::uuid, 5, $lum$multiple_choice$lum$, $lum${"stem":"In the billing dispute example, the duplicate charge was already refunded before escalating. Why does the handoff spell that out for the senior agent?","options":[{"id":"a","label":"So the senior agent knows to issue a second refund as a goodwill gesture.","is_correct":false,"explanation":"The opposite. The handoff makes clear the refund is already done precisely so the senior agent does NOT re-refund. A second refund would be the error this detail prevents."},{"id":"b","label":"Because the customer's emotional state is the only thing that matters in a billing case.","is_correct":false,"explanation":"State matters, but it is not the point here. The handoff separates the handled money issue from the open question so the receiver works the right problem, not just reads the temperature."},{"id":"c","label":"So the senior agent re-reads the full thread to confirm the refund themselves.","is_correct":false,"explanation":"Making the receiver re-read the thread is exactly what a clean handoff avoids. The point of stating the refund is done is to spare that step, not trigger it."},{"id":"d","label":"So the senior agent knows the money issue is handled and focuses on why the duplicate keeps recurring, instead of re-refunding.","is_correct":true,"explanation":"Correct. The handoff separates what is already done from what is still open. That tells the senior agent to investigate the billing record for the root cause, and it saves the customer from a second refund and a longer wait."}]}$lum$::jsonb, false),
  ($lum$6c1a0b76-a08f-5ac6-817c-2448bf014110$lum$::uuid, $lum$6fdd9be2-1452-5d0a-834a-82115aeb9f66$lum$::uuid, 6, $lum$reading$lum$, $lum${"markdown":"The handoff is fast and clean now, which is exactly why the mistakes here are dangerous. They do not look like mistakes. They look like finished work. Here are the ones that bite people on the job.\n\nThe first is pasting customer identifiers and personal data into a public tool. Mid-shift, it is tempting to copy your note as-is, full name, email, order number, maybe a card detail, and drop it into whatever AI tool is open in your browser. Do not. A public tool is not your company's system, and customer personal data does not belong there. The fix is simple and costs you nothing: structure the handoff from a de-identified version. Replace names and numbers with placeholders like \"customer\" and \"the order,\" let AI shape the structure, then attach the real specifics inside your own ticketing system where they belong. The AI never needed the identity to organize the story. It only needed the shape of what happened.\n\nThe second mistake is the quiet one: sending a handoff that reads clean but is subtly wrong. This is the trap of good structure. When something is tidy and well-formatted, your brain reads it as correct and moves on. But AI works from your notes, and if your notes were rushed, or if the model filled a small gap on its own, the handoff can misstate things while looking perfect. Maybe it says you offered a refund when you actually offered store credit. Maybe it lists \"wants a replacement\" when the customer actually wants a refund. Maybe it drops the step where you already confirmed the purchase date, so the receiver redoes it. Each of those errors is small. Each one sends the next person down the wrong path, and they go confidently because the handoff looked authoritative. A clean wrong handoff is worse than a messy note, because nobody doubts it."}$lum$::jsonb, false),
  ($lum$0d5b480c-5def-5765-b33e-c38702d3abee$lum$::uuid, $lum$6fdd9be2-1452-5d0a-834a-82115aeb9f66$lum$::uuid, 7, $lum$multiple_choice$lum$, $lum${"stem":"Mid-shift, you want to paste your note into a public AI tool to structure the handoff. What does the lesson say to do about the customer's name, email, and order number?","options":[{"id":"a","label":"Paste them in as-is, because the AI needs the identity to organize the story correctly.","is_correct":false,"explanation":"The lesson says the opposite directly: the AI never needed the identity to organize the story, only the shape of what happened. Pasting real personal data into a public tool is the first mistake."},{"id":"b","label":"Replace them with placeholders like 'customer' and 'the order,' let AI structure the de-identified version, then attach the real specifics in your own system.","is_correct":true,"explanation":"Correct. A public tool is not your company's system, so personal data does not belong there. De-identify first, let AI shape the structure, and store the real details where they belong in your ticketing system. The fix costs you nothing."},{"id":"c","label":"Leave the identifiers out entirely and never reconnect them, since the receiver does not need them.","is_correct":false,"explanation":"Half right. You do keep them out of the public tool, but the receiver does need the real specifics. The lesson says to attach them inside your own ticketing system, not drop them altogether."},{"id":"d","label":"It is fine as long as you delete the note from the tool afterward.","is_correct":false,"explanation":"Deleting later does not undo exposing customer data to a tool outside your company's system. The rule is to de-identify before anything is pasted, not to clean up after."}]}$lum$::jsonb, false),
  ($lum$2f1afdbc-5a9a-5987-b759-470b18f19cee$lum$::uuid, $lum$6fdd9be2-1452-5d0a-834a-82115aeb9f66$lum$::uuid, 8, $lum$reading$lum$, $lum${"markdown":"That leads to the third mistake, which sits underneath the other two: treating the AI output as authority instead of confirming it yourself. The model is a fast assistant, not a witness to the conversation. It did not talk to the customer. You did. So the structure is its contribution, and the accuracy is yours. Before you send any handoff on, read it against what actually happened and ask three plain questions. Did I really try everything it lists, in that order? Did it state what the customer wants correctly, in their words, not a guess? Did it leave out a step I took or a detail that changes the decision? If anything is off, fix it in ten seconds. That ten seconds is the whole game.\n\nOne more, smaller and worth naming: padding the handoff to seem thorough. A handoff works because it is scannable. If you let it balloon with background and side notes, the receiver has to hunt for the one thing you actually need from them, and the speed advantage is gone. Tight and accurate beats long and complete every time.\n\nNone of this means AI is risky to use for handoffs. It means the same speed that helps you can hand a clean-looking error to the next person if you skip the read-through. Use it for the structure. Own the accuracy. The next checkpoint is on the single habit that protects you."}$lum$::jsonb, false),
  ($lum$decf6f7a-0282-5b4c-8f45-833a86795ede$lum$::uuid, $lum$6fdd9be2-1452-5d0a-834a-82115aeb9f66$lum$::uuid, 9, $lum$multiple_choice$lum$, $lum${"stem":"AI gives you a clean, well-structured escalation handoff from your notes. What is the one thing you must do before sending it on?","options":[{"id":"a","label":"Add as much background as you can so the receiver has the full picture.","is_correct":false,"explanation":"Padding works against a handoff. It is supposed to be tight and scannable. Burying the specific ask under background makes the receiver hunt for it and loses the speed advantage entirely."},{"id":"b","label":"Nothing, because if the structure is clean and well-formatted the content is reliable.","is_correct":false,"explanation":"Clean structure is not evidence of correct content. This is the exact trap: AI can misstate what you tried or what the customer wants while looking perfectly tidy, and the polish makes the error harder to catch, not easier."},{"id":"c","label":"Read it against what actually happened and confirm it is accurate and complete, because a clean but subtly wrong handoff sends the receiver down the wrong path with false confidence.","is_correct":true,"explanation":"Correct. AI supplies the structure; you supply the accuracy, because you are the one who talked to the customer. A quick line-by-line check, did I try all this, is the customer's want stated right, is any step missing, takes ten seconds and prevents a confident error."}]}$lum$::jsonb, false),
  ($lum$8f3d8912-975b-5f8e-ae19-4192ac5cd41e$lum$::uuid, $lum$6fdd9be2-1452-5d0a-834a-82115aeb9f66$lum$::uuid, 10, $lum$try_it_live$lum$, $lum${"instructions":"Hand the AI your rough mid-shift notes and ask for a structured escalation handoff. Or use the sample: a customer wants a refund outside the return window, you have confirmed the policy and offered store credit which they declined, and they are now asking for a manager.","system_prompt":"You are a customer-support operations partner who turns an agent's rough mid-shift notes into a clean escalation handoff written for the person receiving it. Produce a tight, scannable structure with four labeled parts: a one-line situation summary; what has already been tried and the result of each attempt; the customer's current state and what they expect; and a specific statement of what the agent is asking the receiver to do or decide. Keep it factual and brief. Do not invent steps, details, or customer wants that were not in the notes. Do not include customer identifiers or personal data; remind the agent to attach real specifics inside their own system. No jargon. No em dashes.","ideal_output":"Here is a clean handoff built only from your notes. I left out customer identifiers, so attach the real name, order, and account details from your own system.\n\nSituation: Customer is requesting a full refund for an order that falls outside our return window and is now asking to escalate to a manager.\n\nWhat I have tried: (1) Confirmed the purchase date and that it is past the return window. (2) Explained the policy clearly; the customer understood it but is not satisfied. (3) Offered store credit as a goodwill alternative, which the customer declined.\n\nCustomer state: Frustrated but reasonable, not abusive. Feels the product underperformed and wants a manager to reconsider a refund.\n\nWhat I need from you: A decision on whether we can make a one-time policy exception for a refund, or a clear alternative I can offer instead. The customer is waiting on chat now.\n\nI added nothing beyond your notes. Want me to also draft the message you would send the customer once the decision is made?","input_placeholder":"Paste your rough notes: the situation, what you tried and what happened, where things stand, what you need next..."}$lum$::jsonb, true),
  ($lum$5bcf3cd4-2529-5db9-9d26-4de9649e4b92$lum$::uuid, $lum$6fdd9be2-1452-5d0a-834a-82115aeb9f66$lum$::uuid, 11, $lum$multiple_choice$lum$, $lum${"stem":"You paste your rough notes into AI and get back a handoff. Which approach is safe and correct on the job?","options":[{"id":"a","label":"De-identify your notes first, let AI structure them, then read the handoff against what actually happened and attach the real customer specifics inside your own system.","is_correct":true,"explanation":"Correct. This covers all three safeguards: no personal data in a public tool, a verification pass against reality, and the real specifics stored where they belong. The AI gives you structure; you give it safety and accuracy."},{"id":"b","label":"Paste the full note with the customer's name, email, and order number so the handoff is complete, then send it as soon as it looks clean.","is_correct":false,"explanation":"Two mistakes at once. Customer personal data should not go into a public tool, and sending the moment it 'looks clean' skips the verification that catches subtle errors. Looking clean is not the same as being correct."},{"id":"c","label":"Trust the output as-is since the AI organized it better than you would have under pressure.","is_correct":false,"explanation":"Better structure does not mean accurate content. The AI did not talk to the customer, so it can misstate a step or a want while looking authoritative. Verification is yours to do every time."}]}$lum$::jsonb, false),
  ($lum$965f8e26-7d8e-5dbf-90eb-66f73031588f$lum$::uuid, $lum$6fdd9be2-1452-5d0a-834a-82115aeb9f66$lum$::uuid, 12, $lum$mini_project$lum$, $lum${"brief":"Next time you escalate a ticket, or pick a recent one you handled, write your rough notes the way you actually would mid-shift: messy, quick, just enough to remember. Strip out the customer's name, email, and order number, replacing them with simple placeholders, and hand that de-identified version to the AI asking for a structured handoff with the four parts: one-line situation, what you tried and the results, the customer's state and expectation, and exactly what you need from the receiver. Then verify it line by line against what really happened, confirming it added no steps you did not take and did not misstate what the customer wants. Attach the real specifics from your own system, and compare the result to the vague \"please advise\" version you might have sent. Imagine receiving each one cold.","parts":[{"id":"1","prompt":"Write quick mid-shift notes for a real escalation, then de-identify them by swapping the customer name, email, and order number for placeholders before anything goes into the AI tool."},{"id":"2","prompt":"Ask the AI to structure the de-identified notes into a handoff with all four parts, then check it line by line: every step you actually tried, the customer's real want stated correctly, and nothing important missing."},{"id":"3","prompt":"Attach the real customer and order specifics inside your own ticketing system, send the handoff, and compare it side by side with the \"please advise\" note you would have sent before."}]}$lum$::jsonb, false),
  ($lum$9875bc03-d6f5-5200-baea-1f1cf2ed2dbe$lum$::uuid, $lum$a8f1356b-bd00-521a-aa75-8fb8f53cc00e$lum$::uuid, 0, $lum$reading$lum$, $lum${"markdown":"Job descriptions tend to get written backwards. Someone opens the last version for a similar role, swaps a couple of lines, changes the title, and posts it. Nobody sits down and asks what this specific job actually needs from a person. The result is a list of demands aimed at the company's convenience: twenty bullet points, a decade of required experience for a job a sharp two-year candidate could do, an unnecessary degree, and jargon only an insider would parse. The strong, qualified candidate reads it, counts that they meet eight of the twenty bullets, decides they are not what you are looking for, and quietly closes the tab. The posting did its job too well. It filtered out exactly the people you were hoping to reach.\n\nThis is the trap most postings fall into, and it is worth seeing clearly before you try to fix it. A job description is not a contract or a legal screen. It is the first message a candidate ever receives from you, and like any first message, it can either invite someone in or push them away. When a description is a wishlist written for the company, it reads as a list of reasons to feel unqualified. The capable people, the ones with options, are the first to self-select out, because they have other roles to consider and no reason to apply for one that seems to want someone else. The people who stay are often the ones who apply to everything regardless. So the wishlist does not raise your quality. It lowers it, while shrinking the pile."}$lum$::jsonb, false),
  ($lum$c46722ab-517a-5c3f-be1e-b34ef4f16b9b$lum$::uuid, $lum$a8f1356b-bd00-521a-aa75-8fb8f53cc00e$lum$::uuid, 1, $lum$multiple_choice$lum$, $lum${"stem":"A strong, qualified candidate reads a posting, sees they meet only eight of twenty bullets, and closes the tab. According to this lesson, what has the posting actually done?","options":[{"id":"a","label":"It successfully raised the quality of the applicant pool by setting a high bar.","is_correct":false,"explanation":"The lesson says the opposite. The wishlist does not raise your quality; it lowers it while shrinking the pile, because the capable people leave first."},{"id":"b","label":"It correctly screened out someone who was genuinely unqualified for the role.","is_correct":false,"explanation":"The candidate was strong and qualified. The bullets were a wishlist, not a real measure of fitness, so the posting filtered out someone it should have wanted."},{"id":"c","label":"It filtered out exactly the kind of capable person it was hoping to reach, because the wishlist read as a list of reasons to feel unqualified.","is_correct":true,"explanation":"Correct. The capable people with options self-select out first, so a wishlist written for the company pushes away the very candidates you wanted while shrinking the pile."}]}$lum$::jsonb, false),
  ($lum$774ef4a1-fe4b-5c83-a9e1-f7f98dc6cadd$lum$::uuid, $lum$a8f1356b-bd00-521a-aa75-8fb8f53cc00e$lum$::uuid, 2, $lum$reading$lum$, $lum${"markdown":"Here is the good news, and the reason this is a perfect job for AI. Rewriting a job description is a clarity, framing, and tone problem, not a facts problem. The model does not need to know your company secrets or invent anything. You supply the substance: what the role really does day to day, which requirements are genuine must-haves versus nice-to-haves, and what makes your team worth joining. The model takes that raw material and turns it into a posting written for the reader instead of for the filing cabinet. It is the same task you would do yourself if you had a quiet afternoon and a talent for plain writing, and it is exactly the kind of rewrite a model does fast and well.\n\nPicture a recruiter named Dani who is filling a mid-level operations analyst role. The inherited posting asks for a bachelor's degree, seven or more years of experience, and proficiency in four named tools. Dani knows the job is really about pulling weekly performance data, building a few simple dashboards, and flagging process bottlenecks to the ops team. A capable person with one or two solid years could do it. So Dani writes a prompt that gives the model the real picture: \"Draft a job description for a mid-level operations analyst. Day to day, the role pulls weekly performance data, builds simple dashboards, and flags process bottlenecks to the ops team. The genuine must-haves are comfort with spreadsheets, clear written communication, and one to two years in an analytical role. Everything else is a nice-to-have. Write it in plain language to attract a capable candidate who may not tick every box, keep the requirements list short and honest, and avoid jargon or inflated experience asks.\" The model returns a posting that sounds like a real human describing a real job, and the wishlist is gone."}$lum$::jsonb, false),
  ($lum$4e00808b-1f1a-57f8-abe4-41d2f53f64f7$lum$::uuid, $lum$a8f1356b-bd00-521a-aa75-8fb8f53cc00e$lum$::uuid, 3, $lum$multiple_choice$lum$, $lum${"stem":"A hiring manager keeps getting too few applicants for an open role and asks why AI is well suited to rewriting the job description. What is the most accurate reason from this lesson?","options":[{"id":"a","label":"Rewriting a job description is mostly a clarity, framing, and tone problem, and the HR pro supplies the real facts while the model handles the phrasing.","is_correct":true,"explanation":"Correct. The model does not need to invent anything. You supply the real role, the genuine must-haves, and what makes the team worth joining, and it turns that into a posting written for the reader."},{"id":"b","label":"AI knows the current job market better than any recruiter, so it can decide on its own which requirements to keep.","is_correct":false,"explanation":"The model does not know what your role truly requires or what is true about your team. You decide the requirements; the model only helps phrase them."},{"id":"c","label":"AI can pull salary and benefits data from your company systems automatically to fill in the posting.","is_correct":false,"explanation":"This is not what the lesson describes, and it is not why AI fits this task. The strength is reframing the substance you provide, not retrieving internal facts on its own."}]}$lum$::jsonb, false),
  ($lum$b59ae899-e4ad-5ef9-81a6-dd81f9138001$lum$::uuid, $lum$a8f1356b-bd00-521a-aa75-8fb8f53cc00e$lum$::uuid, 4, $lum$reading$lum$, $lum${"markdown":"Notice what made that prompt work. Dani named the audience, the capable candidate who may not meet every line, and the goal, to attract rather than to screen. Dani separated must-haves from nice-to-haves out loud, so the model knew which requirements were load-bearing and which were just noise carried over from the old version. And Dani described what the role actually does, which gives the model something true to write about instead of a generic template. Those three moves, real day-to-day, honest must-haves, and a named audience, are the whole technique. Everything else is refinement.\n\nThink about what the role offers, too, not just what it demands. A strong description spends as much energy on why someone would want this job as on what they need to bring. What will the new hire learn, who will they work with, what does the team actually feel like on a good week? AI is happy to lead with that if you tell it to. The shift from \"here is our list of requirements\" to \"here is interesting work and the kind of person who would enjoy it\" is small to write and large in effect. It is the difference between a posting that sorts people out and one that draws them in.\n\nNone of this hands the judgment to the machine. You are still the person who decides what the role genuinely requires, who knows your team, and who can tell an honest description from a flattering one. The model is fast at phrasing and bad at knowing what is true about your workplace. Used well, it gives you a clean first draft in minutes so you can spend your time on the part that matters: deciding what to ask for, and saying it in a way the right person actually wants to answer."}$lum$::jsonb, false),
  ($lum$cfe11ab7-29e5-574d-b7cd-7ff5734a3aa2$lum$::uuid, $lum$a8f1356b-bd00-521a-aa75-8fb8f53cc00e$lum$::uuid, 5, $lum$multiple_choice$lum$, $lum${"stem":"Based on this segment, what are the three moves that make up 'the whole technique' for prompting a job description, with everything else being refinement?","options":[{"id":"a","label":"A long requirements list, a formal tone, and a company-first framing.","is_correct":false,"explanation":"These are the habits the lesson warns against. A long list and company-first framing are what push capable candidates away."},{"id":"b","label":"Asking the model to invent perks, guessing at salary, and copying a competitor's posting.","is_correct":false,"explanation":"None of these appear in the lesson. The model should not invent facts, and the technique is built on supplying the truth about your role."},{"id":"c","label":"Letting the model decide the must-haves, hiding the audience, and keeping the role vague.","is_correct":false,"explanation":"This is the reverse of the technique. You must decide the must-haves, name the audience, and describe what the role actually does."},{"id":"d","label":"The real day-to-day, honest must-haves, and a named audience.","is_correct":true,"explanation":"Correct. The lesson states these three moves, real day-to-day, honest must-haves, and a named audience, are the whole technique, and everything else is refinement."}]}$lum$::jsonb, false),
  ($lum$6d0a7770-5964-5c6c-83b5-83c7d61a0b8c$lum$::uuid, $lum$a8f1356b-bd00-521a-aa75-8fb8f53cc00e$lum$::uuid, 6, $lum$reading$lum$, $lum${"markdown":"The most common way this goes wrong is trusting the first draft too much. A model trained on the open internet has read thousands of bloated job descriptions, so when you ask it for one, its instinct is to reach for the same inflated requirements everyone else uses. Ask for an operations analyst posting with no guidance and you will often get \"bachelor's degree required\" and \"five or more years of experience\" without ever telling it to. Those lines did not come from you. They came from the template average baked into the model. If you paste the draft straight into your posting, you have just reimported the exact wishlist you were trying to escape, now with a fresh coat of paint.\n\nConsider an HR generalist named Marcus who inherited a JD for a customer support lead. He asks AI to \"make it sound more appealing\" and gets back a smoother version that still demands a degree and five years of experience. The writing is better. The barrier is identical. Marcus did not tell the model which requirements were real, so it kept all of them and simply polished the prose. The lesson is that better phrasing does not fix an exclusionary list. You have to do the thinking about must-haves first, then let the model write, not the other way around."}$lum$::jsonb, false),
  ($lum$87df90bd-bd18-55a1-85a1-c093bbfba93f$lum$::uuid, $lum$a8f1356b-bd00-521a-aa75-8fb8f53cc00e$lum$::uuid, 7, $lum$fill_blank$lum$, $lum${"template":"When a model drafts a job description, watch for inflated or {{1}} requirements it imports from generic templates, because those quietly shrink and skew your {{2}} pool.","blanks":[{"id":"1","accept":["exclusionary","excluding","unnecessary"],"ideal":"exclusionary"},{"id":"2","accept":["applicant","candidate"],"ideal":"applicant"}],"explanation":"Generic templates push the model toward inflated, exclusionary requirements like an unneeded degree or too many years of experience. Left in, they narrow and distort the applicant pool by pushing strong candidates to self-select out."}$lum$::jsonb, false),
  ($lum$6e06d037-f20a-5011-b326-9971bc45c0fe$lum$::uuid, $lum$a8f1356b-bd00-521a-aa75-8fb8f53cc00e$lum$::uuid, 8, $lum$reading$lum$, $lum${"markdown":"The second failure is skipping the review for inclusive and accurate language. A model can produce coded phrasing that quietly narrows your pool, things like \"recent graduate,\" \"digital native,\" or a wall of aggressive, competitive language that reads as a signal about who belongs. None of that is usually intentional, but it does real damage, because it tells whole groups of qualified people that the role was not written for them. Your job after the draft is to read it the way a candidate would and ask: does this honestly describe the work, and does it invite the broadest qualified pool, or does it subtly screen people out?\n\nThere is also the honesty trap. AI is good at making things sound appealing, sometimes more appealing than they are. If the model writes that the team is \"fast-paced and collaborative\" but the real job is heads-down and high-pressure, you will attract people who leave in three months. A description that oversells is not kindness; it is a slow, expensive mismatch. Keep the model honest by feeding it the real texture of the role, the good and the demanding, and by cutting any line that sounds true only because it sounds nice.\n\nThe fix for all three is the same simple discipline. Decide the real must-haves before you prompt. Read the draft as a critic, not a customer. And remember that the model is a fast writer with no knowledge of your workplace, so the substance and the final judgment stay with you."}$lum$::jsonb, false),
  ($lum$d1eb8ec6-2153-58b6-92f6-cbe16befc238$lum$::uuid, $lum$a8f1356b-bd00-521a-aa75-8fb8f53cc00e$lum$::uuid, 9, $lum$multiple_choice$lum$, $lum${"stem":"The model drafts a posting that calls your team 'fast-paced and collaborative,' but the real job is heads-down and high-pressure. According to this segment, why is leaving that line in a problem?","options":[{"id":"a","label":"An oversold description is a slow, expensive mismatch, because it attracts people who leave in three months.","is_correct":true,"explanation":"Correct. The honesty trap means a description that oversells is not kindness; it draws in people who leave quickly once the real texture of the role does not match what was promised."},{"id":"b","label":"It is fine, because making the role sound appealing is the whole point of a posting.","is_correct":false,"explanation":"Appeal that is not true is the honesty trap. The lesson says to cut any line that sounds true only because it sounds nice."},{"id":"c","label":"The only risk is that competitors might copy your appealing phrasing.","is_correct":false,"explanation":"The lesson never raises this concern. The real cost is a mismatch that leads good hires to leave, not imitation by competitors."},{"id":"d","label":"It matters only for legal reasons, since job postings must be factually accurate by law.","is_correct":false,"explanation":"The lesson frames this as a fit and retention problem, not a legal one. The damage is people leaving in three months, not a compliance issue."}]}$lum$::jsonb, false),
  ($lum$5326e232-b02d-5865-bbad-fd1114962e05$lum$::uuid, $lum$a8f1356b-bd00-521a-aa75-8fb8f53cc00e$lum$::uuid, 10, $lum$before_after$lum$, $lum${"question":"You need a posting for a mid-level operations analyst, and you keep getting too few applicants. Which prompt produces a description that attracts strong candidates instead of filtering them out?","before_prompt":"Write a job description for an operations analyst.","after_prompt":"Draft a job description for a mid-level operations analyst. Day to day, the role pulls weekly performance data, builds simple dashboards, and flags process bottlenecks to the ops team. The genuine must-haves are comfort with spreadsheets, clear written communication, and one to two years in an analytical role. Everything else, including SQL, a specific tool, and a degree, is a nice-to-have, not a requirement. Write it in plain language to attract a capable candidate who may not tick every box, keep the requirements list short and honest, avoid jargon or inflated experience asks, and lead with what makes the work interesting. Then flag any line that could wrongly exclude a qualified person.","changes":["Describes what the role actually does, so the posting reflects the real job instead of a generic template.","Separates true must-haves from nice-to-haves, which stops the requirement list from filtering out strong applicants.","Names the audience and goal and asks the model to flag exclusionary lines, so jargon and inflated asks do not quietly shrink the pool."]}$lum$::jsonb, true),
  ($lum$c0f77faf-ffc1-5e6b-9db8-3438840acad6$lum$::uuid, $lum$a8f1356b-bd00-521a-aa75-8fb8f53cc00e$lum$::uuid, 11, $lum$multiple_choice$lum$, $lum${"stem":"The AI-drafted posting lists 'bachelor's degree required' and '7+ years experience' for a role you know a strong two-year candidate could do, even though you never asked for those. What should you conclude?","options":[{"id":"a","label":"It is fine, because higher requirements always produce higher-quality applicants.","is_correct":false,"explanation":"Higher bars do not mean better hires. They mean fewer and narrower applicants. An inflated requirement screens out capable people the job never needed to exclude."},{"id":"b","label":"The model imported inflated requirements from generic templates, so you should cut them down to the genuine must-haves before posting.","is_correct":true,"explanation":"Correct. Those lines came from the template average baked into the model, not from you. Trimming them to real must-haves widens the pool and stops strong candidates from self-selecting out."},{"id":"c","label":"The posting should list even more requirements to be thorough and look serious.","is_correct":false,"explanation":"More requirements make the problem worse. The goal is an honest, short list of genuine must-haves, not an exhaustive wishlist that deters the right candidates."}]}$lum$::jsonb, false),
  ($lum$51a5188a-805c-54cb-bdce-b0d829b05123$lum$::uuid, $lum$a8f1356b-bd00-521a-aa75-8fb8f53cc00e$lum$::uuid, 12, $lum$mini_project$lum$, $lum${"brief":"Take a real job description you use, ideally one for a role you struggle to fill, and rewrite it to the standard in this lesson. Before you open the AI, decide what the job actually requires so the model has true material to work with and you have a clear standard to judge the draft against.","parts":[{"id":"1","prompt":"Mark every requirement in your current JD as a genuine must-have or a nice-to-have, and be honest about which inflated lines crept in from old templates, then write a prompt that gives the model the real day-to-day, your honest must-have list, and what makes the team worth joining."},{"id":"2","prompt":"Ask for a plain-language posting aimed at a capable candidate who may not tick every box, leading with what makes the work interesting rather than the list of demands."},{"id":"3","prompt":"Review the draft for any requirement that would wrongly exclude someone and any coded or exclusionary language, fix it, then compare it to your original and note how many strong applicants the old version was quietly turning away."}]}$lum$::jsonb, false),
  ($lum$4c3ac624-9f55-51bd-ae2c-29f352a8840b$lum$::uuid, $lum$b308eab3-6296-50eb-987a-05f8508d7a40$lum$::uuid, 0, $lum$reading$lum$, $lum${"markdown":"Parent communication carries a weight that classroom writing does not. A note about a behavior incident, a missing-work pattern, or a hard conversation coming at conferences can land wrong in a dozen ways. Too blunt and you have a defensive parent on your hands by lunch. Too soft and the real message never gets through, so nothing changes. These are the messages that get written, deleted, rewritten, and put off until the end of the day, and the delay itself becomes part of the problem. A note that should have gone home Tuesday goes home Friday, and now the parent wonders why you waited.\n\nThis is a place AI genuinely earns its keep, because the difficulty here is tone and framing, not facts. You already know what happened. You were there. What is hard is saying it in a way that keeps the family on your side, treats the child fairly, and still gets the real point across. That is a writing problem, and writing problems are exactly what these tools help with.\n\nThe method is simple. You give the model four things: the situation, the facts you want to convey, the tone you are aiming for, and what you know about the family in general terms. Then you ask for a draft, read it the way the parent will read it, and shape it until it sounds like you. The AI does the first hard 80 percent, finding a warm and direct way in. You do the last 20 percent, the part that depends on knowing this family and this child."}$lum$::jsonb, false),
  ($lum$307e01ec-161d-57b8-9fa5-84b5ad5c71d6$lum$::uuid, $lum$b308eab3-6296-50eb-987a-05f8508d7a40$lum$::uuid, 1, $lum$multiple_choice$lum$, $lum${"stem":"According to this opening, why is parent communication a place where AI genuinely earns its keep?","options":[{"id":"a","label":"Because the hard part is tone and framing, not facts, and finding the right words is exactly the kind of writing problem these tools help with.","is_correct":true,"explanation":"Correct. You already know what happened; the difficulty is saying it in a way that keeps the family on your side, and that is a writing problem AI is built for."},{"id":"b","label":"Because AI knows the facts of the incident better than the teacher who was present.","is_correct":false,"explanation":"The teacher already has the facts and was there. The text is explicit that the difficulty is tone and framing, not facts."},{"id":"c","label":"Because parent messages do not really matter, so a rough AI draft is good enough.","is_correct":false,"explanation":"The opening stresses the opposite: these messages carry real weight and can land wrong in a dozen ways, which is why getting the tone right matters."},{"id":"d","label":"Because AI removes the need for the teacher to decide what to say at all.","is_correct":false,"explanation":"The method keeps you deciding what to say. The model does the first pass on tone and structure; you do the last 20 percent that depends on knowing the family."}]}$lum$::jsonb, false),
  ($lum$0bbc0b01-f1c1-5afd-a4d0-cb913580c96e$lum$::uuid, $lum$b308eab3-6296-50eb-987a-05f8508d7a40$lum$::uuid, 2, $lum$reading$lum$, $lum${"markdown":"Here is what that looks like in practice. Say it is Thursday and an 8th grader has missed three homework assignments this week. The student is sharp and engaged in class, which makes the pattern more worth flagging early, not less. You might prompt: \"Draft a warm but direct email to a parent of a middle school student. The facts: three homework assignments missed this week, the student is capable and engaged in class, and I want us to partner on a plan rather than place blame. Open by noting something genuine and specific about the student, state the pattern plainly, propose one small shared next step, and invite a quick call. Keep it under 150 words and easy to read on a phone.\" What comes back is a calm, structured starting point. You add the student's name and the specific assignments by hand, soften one line that reads a little stiff, and send it before your prep period ends.\n\nTake a second example, a playground conflict. Two second graders had a shoving match over a four square ball at recess, no injuries, but one child went home upset and you want to reach that family before the story arrives secondhand at dinner. The tone you need is different here. You want to reassure, not alarm, and you want to signal that you handled it in the moment. So you tell the model: \"Draft a brief, calm note to a parent about a minor recess conflict. Tone: reassuring, not alarming, makes clear the situation was handled at school and the children are fine. The facts: a disagreement over playground equipment, both children talked it through with me, no one was hurt. Let the parent know in case it comes up at home, and invite them to reach out with questions.\" That draft will not catastrophize, which is exactly the trap a tired teacher writing at 4 p.m. can fall into."}$lum$::jsonb, false),
  ($lum$796f6899-cc91-54ad-8b76-f6c32b67421f$lum$::uuid, $lum$b308eab3-6296-50eb-987a-05f8508d7a40$lum$::uuid, 3, $lum$multiple_choice$lum$, $lum${"stem":"In the playground-conflict example, what makes the prompt's requested tone different from the missing-homework one?","options":[{"id":"a","label":"It asks the model to be blunt so the parent grasps how serious the incident was.","is_correct":false,"explanation":"The goal here is the opposite of blunt. A blunt note risks catastrophizing a minor incident, which is the trap the text warns against."},{"id":"b","label":"It asks for a reassuring, not-alarming tone that makes clear the situation was already handled at school and the children are fine.","is_correct":true,"explanation":"Correct. The recess note aims to reassure and signal you handled it in the moment, so the family is not alarmed when the story reaches home."},{"id":"c","label":"It asks the model to leave out what happened so the parent stays calm.","is_correct":false,"explanation":"The prompt still states the facts plainly: a disagreement over equipment, both children talked it through, no one was hurt. It reassures without hiding what happened."},{"id":"d","label":"It asks for a long, formal message so the parent takes the incident seriously.","is_correct":false,"explanation":"The note is meant to be brief and calm, not long and formal. The point is to avoid alarming a family over a minor conflict."}]}$lum$::jsonb, false),
  ($lum$1f26626f-c435-579c-81da-bbddb10917ed$lum$::uuid, $lum$b308eab3-6296-50eb-987a-05f8508d7a40$lum$::uuid, 4, $lum$reading$lum$, $lum${"markdown":"Third, a conference follow-up about a reading struggle. You met the family at conferences, you sensed the parent was worried but did not want to say so, and you promised to send a plan. The facts are sensitive and the stakes feel high to this family. You might write: \"Draft a follow-up email after a parent conference about a 3rd grader who is reading below grade level. Tone: warm, hopeful, concrete, honest about the gap without alarming the family. Acknowledge our conversation, name one or two specific things we will try in class, suggest one simple thing they can do at home, and set a check-in date.\" The model gives you a frame that names a hard thing gently and ends on a plan, which is the hardest tone to hit when you are writing it cold.\n\nThree guardrails matter here more than anywhere, and the next section walks through what goes wrong when teachers skip them. For now, hold onto the shape: situation, facts, tone, family context. Give the model those four, and the dread of the hard email mostly disappears. You still decide what to say. You just stop spending thirty minutes hunting for the words, and you stop letting a hard note sit in your drafts folder for three days because you could not face writing it."}$lum$::jsonb, false),
  ($lum$ccc69529-b88c-511e-824b-cea77fb3732c$lum$::uuid, $lum$b308eab3-6296-50eb-987a-05f8508d7a40$lum$::uuid, 5, $lum$multiple_choice$lum$, $lum${"stem":"A colleague asks how you use AI to write tough parent emails so fast. Which description matches the method that actually works?","options":[{"id":"a","label":"I give the AI the situation, the facts to convey, the tone I want, and general family context, let it draft the structure and tone, then make the words mine and add the personal specifics.","is_correct":true,"explanation":"Correct. The AI handles the hard first pass on tone and structure from a de-identified description. The relationship, the final wording, and the specifics stay yours."},{"id":"b","label":"I describe the situation and let the AI send whatever it produces, since it writes more diplomatically than I do under pressure.","is_correct":false,"explanation":"The draft is a starting point, not the final word. The model can read colder than you mean, and the relationship with the family is yours to protect, so you always read and shape it before sending."},{"id":"c","label":"I ask the AI to invent the facts and the family background so the message sounds detailed and personal.","is_correct":false,"explanation":"You already have the facts, and you should never let the model invent details about a real child or family. The AI's job is tone and framing, not making things up."},{"id":"d","label":"I only use AI for cheerful messages and write all the hard ones myself, since AI cannot handle sensitive topics.","is_correct":false,"explanation":"The hard messages are exactly where this helps most, because the difficulty is wording and tone, not facts. You stay in control of the substance while the model finds a warm, clear way in."}]}$lum$::jsonb, false),
  ($lum$f64c2284-658c-5861-81e2-606e86682074$lum$::uuid, $lum$b308eab3-6296-50eb-987a-05f8508d7a40$lum$::uuid, 6, $lum$reading$lum$, $lum${"markdown":"The mistakes here are not really about the AI. They are about forgetting that a real family is on the other end of the message. Three come up again and again on the job, and each one is easy to avoid once you have seen it.\n\nThe first is pasting private information into a public tool. It is tempting, in the name of a more accurate draft, to paste in a student's full name, their grade history, a behavior log, or sensitive family details like a recent divorce or a custody arrangement. Do not. A public AI tool is not a place you control, and student records carry real privacy obligations. The fix is simple and costs you nothing: describe the situation generically. Write \"a middle school student who has missed three assignments this week,\" not the name and the gradebook. Write \"a family going through a hard transition at home,\" not the details. The model only needs the shape of the situation to draft good tone and structure. You add the real specifics by hand, after the draft comes back, in a document you control."}$lum$::jsonb, false),
  ($lum$98857805-3938-5fb9-a35c-4f0605ef24bd$lum$::uuid, $lum$b308eab3-6296-50eb-987a-05f8508d7a40$lum$::uuid, 7, $lum$multiple_choice$lum$, $lum${"stem":"You want AI's help drafting a sensitive email about a student going through a hard time at home. What is the safest way to give it the context it needs?","options":[{"id":"a","label":"Paste the student's full name, the counselor's notes, and the family's situation so the AI can personalize the message accurately.","is_correct":false,"explanation":"That puts private student and family information into a tool you do not control. Personalizing is your job at the editing stage, not the model's."},{"id":"b","label":"Describe the situation generically, with no name, records, or identifying family details, then add the real specifics yourself after the draft comes back.","is_correct":true,"explanation":"Correct. The model only needs the shape of the situation to draft good tone and structure. Keeping names, records, and private details out of a public tool protects the family while still getting you a usable draft."},{"id":"c","label":"Skip AI entirely for anything sensitive, since there is no safe way to use it.","is_correct":false,"explanation":"Sensitive messages are where this helps most. You can use it safely by describing the situation generically and keeping all identifying details out of the prompt."},{"id":"d","label":"Use a fake name and fake details so the message feels specific without exposing the real student.","is_correct":false,"explanation":"Inventing details risks them surviving into a real message and confusing the family. Describe the situation generically and add the true specifics by hand instead."}]}$lum$::jsonb, false),
  ($lum$64a98e8b-364b-5fec-810c-88e012ecc2ae$lum$::uuid, $lum$b308eab3-6296-50eb-987a-05f8508d7a40$lum$::uuid, 8, $lum$reading$lum$, $lum${"markdown":"The second mistake is sending the draft without reading it the way the parent will read it. You wrote the prompt, so you read the reply through the lens of what you meant. The parent has none of that context. They have a phone screen, a busy evening, and a flash of worry about their child. The model can strike a tone that is a notch colder and more clinical than you intended. A line like \"Please ensure the student completes all assignments going forward\" reads fine to you and reads like a scolding to a tired parent. So read every draft out loud, slowly, as if you are the parent opening it. The cold lines jump out immediately when you hear them. Soften them, and the whole message lands the way you meant.\n\nThe third mistake is treating the AI draft as an authority instead of a first pass. The model is good at structure and at finding a diplomatic opening. It does not know this child, this family, or the three years of history you have with them. If the draft says something that is not quite true, or skips the genuine detail that would actually reassure this particular parent, you fix it. The words have to sound like you, because the parent knows your voice from every other note you have sent. A message that suddenly sounds like a corporate form letter does not build trust, it spends it. Keep your phrasing, your warmth, the small specific thing only you would notice about their kid.\n\nThere is a quieter fourth trap worth naming: letting the speed make you careless. Because the draft comes back in seconds, it is tempting to fire off a hard message faster than you would have written it by hand. Some messages deserve a pause. A behavior incident or a hard conference follow-up may still warrant a night to sit, or a quick read by a colleague. The AI removes the labor of writing. It does not remove your judgment about timing and whether email is even the right channel. Sometimes the AI helps you realize the message should be a phone call instead, and that is a win too."}$lum$::jsonb, false),
  ($lum$610e5502-dfdc-502c-89cc-288989033fee$lum$::uuid, $lum$b308eab3-6296-50eb-987a-05f8508d7a40$lum$::uuid, 9, $lum$multiple_choice$lum$, $lum${"stem":"Why does this section say you should read every AI draft out loud as if you were the parent opening it?","options":[{"id":"a","label":"Because reading aloud makes the message longer and more formal.","is_correct":false,"explanation":"Reading aloud is a tone check, not a way to add length or formality. The aim is to catch lines that land wrong, not to bulk the message up."},{"id":"b","label":"Because you read the draft through what you meant, while the parent has none of that context and the model can sound a notch colder than you intended, so cold lines jump out when you hear them.","is_correct":true,"explanation":"Correct. The parent has a phone screen, a busy evening, and worry, not your context. Reading aloud surfaces the clinical lines so you can soften them before sending."},{"id":"c","label":"Because the speed of the draft means it is always safe to send immediately once you have skimmed it.","is_correct":false,"explanation":"The section warns that speed can make you careless. Some messages deserve a pause, and you still read carefully rather than skim and send."},{"id":"d","label":"Because the parent expects the message to sound like a corporate form letter.","is_correct":false,"explanation":"A form-letter voice spends trust rather than building it. The point of reading aloud is to keep the message sounding warm and like you."}]}$lum$::jsonb, false),
  ($lum$5d350af4-3b4b-5e19-8135-dbf7385c6135$lum$::uuid, $lum$b308eab3-6296-50eb-987a-05f8508d7a40$lum$::uuid, 10, $lum$before_after$lum$, $lum${"question":"You need to email a parent about a pattern of missing homework. Which prompt gets you a message that informs without putting the family on the defensive?","before_prompt":"Write an email to a parent about their kid not doing homework.","after_prompt":"Draft a warm but direct email to a parent of a middle school student. The facts: three homework assignments missed this week, the student is engaged and capable in class, and I want us to partner on a plan rather than place blame. Tone: respectful, solution-focused, assumes good intent from the family. Open by noting something genuine about the student, state the pattern plainly, propose one small shared next step, and invite a quick call. Keep it under 150 words and easy to read on a phone. Do not include the student's name or any grades; I will add those.","changes":["Gives the facts and the goal, so the message partners with the family instead of accusing the child.","Names the tone explicitly and asks for a genuine opening, a plain statement of the pattern, and one concrete next step.","Keeps the name and grades out of the prompt and sets a phone-friendly length, so it is both private and easy to read."]}$lum$::jsonb, true),
  ($lum$058eae6d-c9ca-521e-a61e-bae1026e4fc3$lum$::uuid, $lum$b308eab3-6296-50eb-987a-05f8508d7a40$lum$::uuid, 11, $lum$multiple_choice$lum$, $lum${"stem":"You ran the strong missing-homework prompt and got a solid draft. What is the right last step before you hit send?","options":[{"id":"a","label":"Send it as written, since the prompt already specified the tone you wanted.","is_correct":false,"explanation":"Clear instructions help, but the draft can still read colder than you meant. The relationship is yours, so you read and shape it first."},{"id":"b","label":"Add the student's name and the specific assignments, read it aloud as the parent will hear it, and soften any line that sounds stiff so it sounds like you.","is_correct":true,"explanation":"Correct. You supply the private specifics by hand, check the tone the way the parent will receive it, and make the words yours before it goes out."},{"id":"c","label":"Ask the AI to make it longer and more formal so the parent takes it seriously.","is_correct":false,"explanation":"Longer and more formal usually reads colder and harder to skim on a phone. The goal is warm, plain, and short, not formal."},{"id":"d","label":"Forward the draft straight to a colleague to send for you so you do not have to.","is_correct":false,"explanation":"The message is from you, and the family knows your voice. The point of the draft is to help you send a note that sounds like you, quickly."}]}$lum$::jsonb, false),
  ($lum$e5fd802e-3730-5cb6-a540-1b72f490d60a$lum$::uuid, $lum$b308eab3-6296-50eb-987a-05f8508d7a40$lum$::uuid, 12, $lum$mini_project$lum$, $lum${"brief":"Think of a real parent message you have been putting off, or one you send often, like a missing-work note, a behavior-incident note, or a conference follow-up. Write the prompt without any identifying details: the situation in general terms, the facts you need to convey, the tone you want, and what you know about the family in general terms. Get the draft, then read it out loud the way the parent will hear it, not the way you wrote it. Adjust anything that sounds cold, clinical, or not like you, and add the personal specifics by hand.","parts":[{"id":"1","prompt":"Write a de-identified prompt that names the situation, the facts, your target tone, and general family context, with no student name, grades, or private records in it."},{"id":"2","prompt":"Generate the draft, then read it aloud slowly as the parent receiving it, and mark every line that sounds stiff, scolding, or unlike your voice."},{"id":"3","prompt":"Revise those lines so the message sounds like you, add the real specifics by hand in a document you control, and send it or save it as a reusable template."}]}$lum$::jsonb, false),
  ($lum$68208a7c-f8ad-59cf-b898-fdb8c374961e$lum$::uuid, $lum$9fd48222-5d86-5bfc-a8bd-9281206b8e54$lum$::uuid, 0, $lum$reading$lum$, $lum${"markdown":"A genuinely confusing question in the AI age: when do you have to tell people you used it? Disclose everything and you sound absurd, nobody announces they used a calculator. Disclose nothing and you risk a real breach of trust, like a personal letter that turns out to be machine-written. There is no universal rule, but there is a reliable way to reason about it.\n\nThe guiding question is: **would this person feel misled if they found out?** Their reasonable expectation, not a fixed policy, is what determines whether disclosure matters.\n\n**Routine assistance: no disclosure needed.** Using AI to draft a standard work email, clean up grammar, summarize a document for yourself, or brainstorm privately is like using any other tool. Nobody expects those to be done by hand, so there is nothing to disclose.\n\n**Authorship and effort matter: disclose, or do not delegate.** When the value is partly in the fact that a human did it, a heartfelt thank-you, a personal recommendation, a creative work credited to you, condolences, the AI's involvement changes what the thing means. Here, either keep it genuinely yours or be transparent. Quietly passing off machine sentiment as your own is the case that burns trust.\n\n**Stakes, accountability, or rules: disclose.** In academic work, regulated fields, journalism, legal filings, or anywhere a policy or professional standard applies, disclosure is often required, and the safe default is transparency. When being wrong has consequences, people deserve to know a tool was involved.\n\n**When unsure, lean toward honesty, lightly.** You do not need a formal disclaimer. \"I drafted this with some AI help and reviewed it\" is often enough, and it costs you nothing while protecting the relationship.\n\nThe underlying principle is simple respect: people are entitled to an accurate sense of how something was made when that would matter to them. Get that right and disclosure stops being awkward. It becomes just another way of being trustworthy."}$lum$::jsonb, false),
  ($lum$60adb4fa-7389-5e80-b535-8e356c72fc13$lum$::uuid, $lum$9fd48222-5d86-5bfc-a8bd-9281206b8e54$lum$::uuid, 1, $lum$multiple_choice$lum$, $lum${"stem":"In which situation is it most important to disclose that you used AI?","options":[{"id":"a","label":"You used AI to fix the grammar and tighten a routine internal status update to your team.","is_correct":false,"explanation":"This is routine assistance, like using spell-check. Nobody expects a status update to be handwritten, so there's nothing meaningful to disclose."},{"id":"b","label":"You used AI to write a personal letter of recommendation that a former employee believes you wrote yourself from the heart.","is_correct":true,"explanation":"Correct. The value here is partly that a human who knows them vouched for them personally. If they'd feel misled to learn it was machine-written, that's exactly when authorship matters and you should either keep it genuinely yours or be transparent."},{"id":"c","label":"You used AI to summarize a long report for your own private reading.","is_correct":false,"explanation":"It's just for you, so there's no other party with an expectation to honor. Disclosure isn't relevant when you're the only audience."}]}$lum$::jsonb, false),
  ($lum$befed93a-42ea-53b3-b8e2-9fb85a7c751a$lum$::uuid, $lum$9fd48222-5d86-5bfc-a8bd-9281206b8e54$lum$::uuid, 2, $lum$mini_project$lum$, $lum${"brief":"Build your own disclosure rule of thumb using the one test that decides it: would this person feel misled if they found out? First, list six things you actually use AI for, mixing routine work with anything personal or high-stakes (for example: cleaning up internal emails, summarizing reports for yourself, drafting a personal recommendation, a condolence message, an academic submission, a client deliverable). Second, run each through the misled test and sort it into one of three buckets: no disclosure needed (routine assistance nobody expects to be handwritten), disclose or keep it genuinely yours (authorship and effort are part of the value), and disclosure likely required (a policy, professional standard, or real stakes apply). Third, for anything in the middle bucket, write the one light line you would actually use, such as \"I drafted this with some AI help and reviewed it.\" The deliverable is your sorted list plus that reusable disclosure line, so the call is already made before you are in the moment.","parts":[]}$lum$::jsonb, false),
  ($lum$ed3bc005-64d0-5529-9770-8bd806e3cc82$lum$::uuid, $lum$397ef739-dceb-509b-88e2-79705000275e$lum$::uuid, 0, $lum$reading$lum$, $lum${"markdown":"Here is a cost of AI that does not show up immediately. If you let it do all your thinking, your own ability to think gets weaker, the same way a muscle you stop using atrophies. People who outsource every draft slowly lose their writing voice. People who never plan a project themselves lose the instinct for it. The tool that made you faster this month can make you worse over a year, if you let it replace the thinking instead of sharpening it.\n\nThis is not an argument against AI. It is an argument for using it deliberately, so you keep the capabilities that make you valuable.\n\n**Form your own take first.** Before you ask AI, spend two minutes on your own answer, even a rough one. Then bring AI in to challenge, extend, or polish it. This one habit keeps you as the thinker and the AI as the assistant, instead of the reverse. The thinking stays yours.\n\n**Protect the skills you cannot afford to lose.** Decide which abilities are core to who you are professionally, the ones you would not want to rust, and keep doing those by hand often enough to stay sharp. Use AI freely on everything else. A writer should still write sometimes; an analyst should still reason through numbers sometimes.\n\n**Use it to learn, not just to answer.** When AI solves something, do not just take the result. Ask it to explain why, so you come away understanding more than you did. Used this way, AI builds your judgment instead of substituting for it.\n\n**Notice the dependency creep.** If you find you can no longer start a task without AI, or you cannot judge whether its output is any good, that is the warning sign. The fix is to do a few unassisted reps to rebuild the underlying skill.\n\nThe goal is a partnership where you stay the more capable one over time. AI should leave you sharper, with more range and better judgment, not hollowed out and unable to work without it. Which outcome you get is a choice you make every time you reach for it."}$lum$::jsonb, false),
  ($lum$a00e2506-5c85-5df5-ae06-9e2872a54aa6$lum$::uuid, $lum$397ef739-dceb-509b-88e2-79705000275e$lum$::uuid, 1, $lum$before_after$lum$, $lum${"question":"Two ways to use AI on a strategy memo you have to write. One erodes your thinking, the other builds it. Notice where your own judgment lives.","before_prompt":"Write a one-page strategy memo on whether we should expand into the Denver market.","after_prompt":"I've drafted my own rough position on expanding into Denver: I think yes, because we already have two clients there and low competition, but I'm worried about hiring and logistics costs. Here are my rough notes: [paste notes]. Push on my reasoning, point out what I'm missing or assuming, and suggest two angles I haven't considered. I'll write the final memo myself.","changes":["Starts from your own position and reasoning, so you stay the thinker and keep the judgment muscle in use.","Uses AI to challenge and extend your view rather than to generate it from scratch, which sharpens your analysis instead of replacing it.","Keeps you as the author of the final memo, so the skill of structuring an argument stays yours and does not quietly atrophy."]}$lum$::jsonb, true),
  ($lum$2338e927-c1d1-5e9b-b22e-8073ed569673$lum$::uuid, $lum$397ef739-dceb-509b-88e2-79705000275e$lum$::uuid, 2, $lum$multiple_choice$lum$, $lum${"stem":"You notice you can no longer start writing a report without asking AI for the first draft, and you're not sure you could tell whether its output is any good. What does this signal, and what's the fix this lesson recommends?","options":[{"id":"a","label":"Dependency creep, and the fix is to do a few unassisted reps to rebuild the underlying skill.","is_correct":true,"explanation":"Correct. Losing the ability to start a task, or to judge the output, is the warning sign the lesson names. The remedy is unassisted practice to bring the skill back."},{"id":"b","label":"Efficiency working as intended, so lean in and hand the whole task to AI from now on.","is_correct":false,"explanation":"That is the atrophy the lesson warns against. A tool that makes you faster this month can make you worse over a year if it replaces the thinking instead of sharpening it."},{"id":"c","label":"A prompting problem, fixable with a better template so the first draft needs less editing.","is_correct":false,"explanation":"A slicker prompt does not rebuild a skill you've stopped using. The issue is that you've stopped doing the thinking yourself, which only unassisted reps restore."}]}$lum$::jsonb, false),
  ($lum$6a915227-80d1-5665-8870-7e5f9597c6cb$lum$::uuid, $lum$0b836e2a-c5c5-58b4-bec0-37583db519f7$lum$::uuid, 0, $lum$reading$lum$, $lum${"markdown":"Here is a principle that will save your reputation: when work goes out under your name, you are accountable for it, no matter what helped you make it. \"The AI got it wrong\" is true and completely irrelevant. You chose the tool, you reviewed the output, and you sent it. The accountability stays with the human, exactly as it would if an intern drafted something and you signed off without reading it.\n\nThis sounds harsh, but it is actually freeing, because it puts the one thing you control front and center: your final check before the work leaves your hands.\n\n**The check is the job.** Using AI does not remove your responsibility, it relocates it. Your value moves from writing every word to verifying and deciding. The minute you treat the review as optional, you have accepted the AI's mistakes as your own without even seeing them. Skipping the check is the actual error; the hallucination is just what reveals it.\n\n**If something slips through, own it cleanly.** Despite good habits, an AI-assisted mistake will eventually reach someone. When it does, the move that protects you is not blaming the tool. It is the same as any professional error: acknowledge it, fix it, say what you will do differently. \"I missed that in my review, here's the correction\" rebuilds trust. \"The AI made it up\" sounds like you do not understand that you were supposed to catch it.\n\n**Never let the tool be the scapegoat.** Reaching for \"the AI did it\" signals that you will do it again, because you have not accepted the part that was yours. People forgive a caught-and-owned mistake quickly. They do not forgive someone who blames their tools.\n\n**Adjust the system, not just the apology.** A real error owns up to the gap that let it through and closes it: a tighter check on numbers, a second read on client work, a rule about what never goes out unverified. That is what turns a mistake into a stronger process.\n\nThe freeing part is this: you cannot control whether AI occasionally invents something, but you fully control whether you check before you send and how you respond if something gets through. Own both, and AI makes you faster without ever making you less trustworthy."}$lum$::jsonb, false),
  ($lum$8addcd05-5c50-579d-addf-6c6694ca44eb$lum$::uuid, $lum$0b836e2a-c5c5-58b4-bec0-37583db519f7$lum$::uuid, 1, $lum$before_after$lum$, $lum${"question":"An AI-drafted report you sent included a wrong figure, and your manager caught it. Two ways to respond. Notice which one protects your credibility.","before_prompt":"Sorry about that, the AI tool I used must have generated the wrong number. These tools aren't always reliable, so it pulled a figure that wasn't accurate. I'll be more careful with it next time.","after_prompt":"You're right, that figure is wrong, and that's on me. I used AI to help draft the report and didn't verify that number against the source before sending. I've corrected it (the actual figure is 14 percent, not 22) and resent the report. Going forward I'm going to check every number against the source before anything goes out. Sorry for the confusion.","changes":["Takes ownership directly instead of blaming the tool, which is what rebuilds trust after an error.","Names the real gap, skipping verification, rather than pinning it on the AI's reliability, showing you understand the check was your job.","Commits to a concrete process fix, verifying every number, so the apology closes the gap instead of just expressing regret."]}$lum$::jsonb, true),
  ($lum$aa6738f4-5f16-5b5a-8df4-f2cc43b48e1b$lum$::uuid, $lum$0b836e2a-c5c5-58b4-bec0-37583db519f7$lum$::uuid, 2, $lum$multiple_choice$lum$, $lum${"stem":"An AI-assisted error reached a client under your name despite your usual habits. Which response best protects your credibility, according to this lesson?","options":[{"id":"a","label":"Acknowledge it, correct it, name the real gap (you skipped verifying that detail), and commit to a concrete process fix.","is_correct":true,"explanation":"Correct. People forgive a caught-and-owned mistake quickly. Owning the gap and closing it with a process change rebuilds trust and turns the error into a stronger system."},{"id":"b","label":"Explain that the AI tool generated the wrong information and these tools aren't always reliable.","is_correct":false,"explanation":"Blaming the tool signals you don't accept that catching it was your job, which reads as 'I'll do this again.' Accountability does not transfer to the AI."},{"id":"c","label":"Quietly fix it and hope the client didn't notice the original.","is_correct":false,"explanation":"Hiding the error risks a much larger trust breach if it surfaces. A clean, owned correction is what protects credibility, not concealment."}]}$lum$::jsonb, false),
  ($lum$390d6e61-9c0d-5dd6-9939-9f2c8a2a1abb$lum$::uuid, $lum$616a76c2-1770-55c0-a4fa-dfbfeb0873d4$lum$::uuid, 0, $lum$reading$lum$, $lum${"markdown":"Most of this course has been about using AI well. This lesson is about the other half of judgment: deciding where you will not use it, and noticing when its answers are quietly skewed. The strongest AI users are not the ones who automate everything. They are the ones who chose their limits deliberately, instead of drifting into using the tool everywhere by default.\n\n**Set your own lines, before you are in the moment.** There are places where, on reflection, you may not want AI: the genuinely personal message that should cost you something to write, the decision you believe you should sit with yourself, the skill you are deliberately keeping sharp, the situation where speed is not actually the point. These are personal calls, not rules anyone can hand you. But deciding them in advance means you act from values rather than convenience when the shortcut is tempting.\n\n**Know that AI carries bias.** AI learned from an enormous pile of human text, and it absorbed the patterns in it, including the skews. It can lean toward majority viewpoints, reflect stereotypes about who does what job, default to a Western or English-speaking frame, and present a contested opinion as settled fact. None of this is malicious; it is a mirror of its training data. But if you take its output as neutral truth, you inherit those biases without knowing it.\n\n**Watch for the tells.** Be alert when AI presents one perspective as the obvious answer, makes assumptions about people based on roles or names, flattens a complex debate into a tidy consensus, or describes \"normal\" in a way that quietly excludes most of the world. Asking \"whose viewpoint is this, and who is missing\" surfaces what the smooth answer left out.\n\n**Counter it actively.** When a balanced view matters, ask for it: \"What are the strongest opposing perspectives? Whose experience might contradict this? What assumptions are you making about the people involved?\" You can steer around bias once you remember to look for it.\n\nThe throughline of responsible AI use is staying in charge: of where the tool belongs in your life, and of whether you accept its framing or question it. Use it with intention, hold onto the parts that should stay human, and never mistake a fluent answer for an unbiased one."}$lum$::jsonb, false),
  ($lum$33bb9bfd-a50c-5bff-a5b3-98c1b404e2ea$lum$::uuid, $lum$616a76c2-1770-55c0-a4fa-dfbfeb0873d4$lum$::uuid, 1, $lum$multiple_choice$lum$, $lum${"stem":"You ask AI to describe 'a typical successful entrepreneur' and it returns a confident, smooth profile. What is the most responsible way to read that output?","options":[{"id":"a","label":"Treat it as a neutral, data-backed summary, since AI has read far more than any person could.","is_correct":false,"explanation":"Reading volume doesn't make output neutral. AI reflects the skews in its training data, so a confident profile can quietly encode stereotypes about who counts as a 'typical' entrepreneur."},{"id":"b","label":"Recognize it likely reflects the dominant patterns in its training data, and ask what perspectives or kinds of people that profile leaves out.","is_correct":true,"explanation":"Correct. A fluent answer is not an unbiased one. Noticing that it mirrors majority patterns, and actively asking who is missing, is exactly how you use AI without inheriting its bias."},{"id":"c","label":"Discard it entirely, since anything from AI is too biased to be useful.","is_correct":false,"explanation":"Overcorrecting into total rejection isn't judgment either. The skill is to use the output while questioning its framing and steering for balance, not to throw it out wholesale."}]}$lum$::jsonb, false),
  ($lum$2c7636d5-c0e0-59f2-aa21-2efcadfb3e49$lum$::uuid, $lum$616a76c2-1770-55c0-a4fa-dfbfeb0873d4$lum$::uuid, 2, $lum$before_after$lum$, $lum${"question":"Same research question, two prompts. One inherits the AI's bias as neutral fact, the other forces it into the open. Notice what the second one asks for.","before_prompt":"Describe the qualities and typical background of a successful startup founder.","after_prompt":"Describe the qualities of a successful startup founder. Then tell me: whose viewpoint does this profile reflect, what assumptions about background, gender, age, or geography are baked into it, and whose paths to success it leaves out. Finish with the strongest counterexamples to the 'typical' profile.","changes":["Stops treating the first fluent answer as neutral truth, which is how you would otherwise inherit the skews in the training data without noticing.","Asks directly whose viewpoint the profile reflects and what it assumes, surfacing the stereotypes a smooth answer quietly encodes.","Requests counterexamples to the 'typical' founder, steering the model off the majority pattern toward a more balanced picture."]}$lum$::jsonb, true),
  ($lum$a394e4e6-3b0a-51b6-9931-87732125b970$lum$::uuid, $lum$b2973f7d-5cbf-5c2c-9f1e-7765e91fb253$lum$::uuid, 0, $lum$reading$lum$, $lum${"markdown":"It is tempting, when a hard decision lands on your desk, to ask AI what to do and follow its answer. That feels efficient, and it is a quiet abdication. AI can be an excellent advisor: fast, tireless, able to lay out options and trade-offs you would have missed. But it is a poor decision-maker, because it does not carry your context, your values, or the consequences. The decision, and the accountability for it, has to stay with you.\n\nThe useful frame is to give AI the analyst's job, not the executive's. Let it do the work that informs a decision, and keep the deciding for yourself.\n\n**Have it map the option space.** \"Lay out the realistic options here, with the main pros and cons of each.\" This is where AI shines, expanding your view beyond the two choices you were stuck between.\n\n**Make it surface trade-offs and risks.** \"What am I trading off with each option? What could go wrong that I'm not seeing?\" A good decision is rarely about the obvious upside; it is about the trade-offs, and AI is good at naming them.\n\n**Stress-test your leaning.** Once you have a tentative call, have AI argue against it. \"I'm leaning toward option B. Make the strongest case that I'm wrong.\" If your choice survives the attack, you decide with more confidence. If it does not, you just dodged a mistake.\n\n**Then decide, with your context.** Here is the part AI cannot do: weigh the options against what you know that it does not. The relationship history, the team's morale, the thing your gut is telling you, the values you will not compromise. You fold that in, and you make the call.\n\nThe line to hold: AI helps you decide better; it does not decide for you. When the outcome lands, \"the AI told me to\" is not a defense anyone accepts, nor should it be. You used a good tool to think more clearly, and then you chose. That is what owning a decision looks like."}$lum$::jsonb, false),
  ($lum$80d26de4-c1fc-57bd-8ead-abdcfa748535$lum$::uuid, $lum$b2973f7d-5cbf-5c2c-9f1e-7765e91fb253$lum$::uuid, 1, $lum$multiple_choice$lum$, $lum${"stem":"A hard hiring decision lands on your desk and you want to use AI well. Which use keeps both the decision and the accountability yours?","options":[{"id":"a","label":"Have it lay out the options, name the trade-offs and risks, and argue against your leaning, then you make the call weighing context only you have.","is_correct":true,"explanation":"Correct. That is the analyst's job, not the executive's. AI informs the decision; you fold in the relationships, values, and consequences it cannot know, and you choose."},{"id":"b","label":"Describe both candidates, ask AI who to hire, and follow its pick to save time.","is_correct":false,"explanation":"That hands the executive's job to a tool with none of your context. AI is a poor decision-maker precisely because it does not carry your values or bear the consequences."},{"id":"c","label":"Ask AI to make the call so that if it goes wrong, the decision wasn't really on you.","is_correct":false,"explanation":"Accountability does not transfer. 'The AI told me to' is not a defense anyone accepts, so dodging the decision this way protects nothing."}]}$lum$::jsonb, false),
  ($lum$1ba25104-525a-5858-931c-61d1743e67bd$lum$::uuid, $lum$b2973f7d-5cbf-5c2c-9f1e-7765e91fb253$lum$::uuid, 2, $lum$mini_project$lum$, $lum${"brief":"Take a real decision you are currently weighing and run it through an advisor-not-decider process, keeping the call firmly yours. First, write down your own initial leaning and the one or two things you are unsure about, before consulting AI at all. Second, use AI as an analyst: ask it to lay out the realistic options with pros and cons, then ask it to name the trade-offs and risks you might be missing, and finally ask it to make the strongest case against your current leaning. Third, set the AI output aside and write the decision yourself in a few sentences, explicitly noting the context only you have, the relationships, values, or constraints that AI never knew, and how they shaped your final call. The deliverable is your decision, on the record, informed by AI but owned by you. Notice how much clearer the reasoning is than if you had just asked it what to do.","parts":[]}$lum$::jsonb, false),
  ($lum$63d38b81-2d4c-535d-93cc-a96507a1a2c1$lum$::uuid, $lum$22f9642c-1580-58b1-9297-6a2884ea6dff$lum$::uuid, 0, $lum$reading$lum$, $lum${"markdown":"There is a quiet flaw in how AI talks to you, and it is dangerous precisely because it feels good. AI is trained to be helpful and agreeable, so it leans toward telling you what you want to hear. Float a weak idea and it often finds reasons to praise it. Push back on a correct answer and it frequently caves and agrees with your error. This tendency has a name: sycophancy, which just means flattering agreeableness.\n\nThe risk is obvious once you see it. If you use AI as a sounding board and it mostly nods along, you walk away feeling validated when you should have been corrected. It is a yes-man with a huge vocabulary, and a yes-man is worst exactly when you most need an honest second opinion.\n\nYou cannot retrain the model, but you can prompt around it.\n\n**Ask for the case against, not the case for.** Instead of \"what do you think of this plan,\" say \"give me the three strongest reasons this plan fails.\" You will get sharper, more useful feedback because you have pointed it at criticism instead of praise.\n\n**Do not reveal your preference.** If you say \"I think we should do X, what do you think,\" you have told it the answer you want. Ask neutrally: \"Compare X and Y on cost, risk, and speed, and tell me which is stronger and why.\" Hide your hand and you get an honest read.\n\n**Test its spine.** When it gives an answer, sometimes push back even when it was right, and watch. If it instantly folds and reverses, that is sycophancy, not new reasoning. Treat a too-quick reversal as a signal to verify, not as a correction.\n\n**Assign it the skeptic role.** \"Act as a tough critic who wants to find every flaw in this.\" Roleframing gives it permission to disagree, which counteracts the built-in urge to please.\n\nThe takeaway is not that AI lies. It is that its agreeableness is a feature you must actively switch off when you need truth. Real validation comes from a tool you have forced to push back, not one you let flatter you."}$lum$::jsonb, false),
  ($lum$25d06aa5-519e-5e9c-8fb0-2b33b7dbf358$lum$::uuid, $lum$22f9642c-1580-58b1-9297-6a2884ea6dff$lum$::uuid, 1, $lum$before_after$lum$, $lum${"question":"You want AI to pressure-test a business idea. One prompt invites flattery, the other forces honesty. Notice the difference.","before_prompt":"I'm thinking of launching a subscription box for artisanal coffee. I really think this could be huge. What do you think of the idea?","after_prompt":"Evaluate a business idea critically. The idea: a subscription box for artisanal coffee. Act as a skeptical investor who has seen many of these fail. Give me the three biggest reasons it could fail, the hardest question you'd ask the founder, and one comparable business that struggled and why. Do not reassure me, find the weak points.","changes":["Removes the giveaway 'I think this could be huge,' which would otherwise prompt the AI to agree with the preference you revealed.","Assigns a skeptical-investor role, giving the AI explicit permission to disagree and counteracting its built-in urge to please.","Asks specifically for failure modes and a hard question instead of an open 'what do you think,' so you get a pressure test rather than flattery."]}$lum$::jsonb, true),
  ($lum$a68c30ae-ee6d-53f3-b53e-89f84bd82003$lum$::uuid, $lum$22f9642c-1580-58b1-9297-6a2884ea6dff$lum$::uuid, 2, $lum$multiple_choice$lum$, $lum${"stem":"You give AI a correct answer, then push back as if it were wrong. It instantly reverses and agrees with your objection. How should you read that?","options":[{"id":"a","label":"As sycophancy, not new reasoning. Treat the too-quick reversal as a signal to verify, not as a correction.","is_correct":true,"explanation":"Correct. Testing its spine is exactly this move. An instant fold under mild pushback is the agreeableness flaw showing, so it's a cue to check the facts, not to trust the new answer."},{"id":"b","label":"As proof your objection was right, since the AI reconsidered and changed its mind.","is_correct":false,"explanation":"A caving response is not reconsideration. The model often abandons a correct answer just because you pushed, which is the trap, not evidence you were right."},{"id":"c","label":"As a sign the AI is useless and should never be trusted for anything.","is_correct":false,"explanation":"Overcorrection. The point isn't that AI lies, it's that you must switch off its agreeableness when you need truth, by prompting for criticism and verifying reversals."}]}$lum$::jsonb, false),
  ($lum$25635abd-6d50-5cf0-8175-a9468c7841fd$lum$::uuid, $lum$831e2277-4995-5fb1-a69d-51368c045f21$lum$::uuid, 0, $lum$reading$lum$, $lum${"markdown":"AI tools are useful because you can paste real work into them. That is also exactly where people get into trouble. So let's set a clear line you can actually follow.\n\nWhen you type into a free, public AI tool, your text may be saved on the company's servers and, in some cases, reviewed by people or used to train future versions. That is fine for a generic question. It is a real problem for a patient record, a client contract, an unreleased product plan, or a colleague's salary.\n\nThe safest mental model is simple. **Treat a public AI tool like a postcard, not a sealed letter.** Do not write anything on it that would cause harm if a stranger read it.\n\nHere is how to stay safe without slowing down.\n\n**Strip the identifiers.** You can still get great help by removing the sensitive parts. Replace \"patient Maria Lopez, room 4\" with \"the patient.\" Replace \"Acme Corp's Q3 layoffs\" with \"a client's confidential plan.\" The AI can summarize and rewrite just as well with the names removed.\n\n**Know your tools.** Many workplaces offer an approved, private version of an AI tool that does not store your data the same way. If yours does, use it for anything sensitive. If you are not sure what is approved, ask before you paste.\n\n**When in doubt, leave it out.** If you are unsure whether something is safe to share, that hesitation is your answer. Genericize it or keep it offline.\n\nPrivacy is not about avoiding AI. It is about being deliberate with what you feed it."}$lum$::jsonb, false),
  ($lum$c3bc5375-db49-5d4e-a9cd-e78f84c2b3fa$lum$::uuid, $lum$831e2277-4995-5fb1-a69d-51368c045f21$lum$::uuid, 1, $lum$multiple_choice$lum$, $lum${"stem":"You want AI to help summarize a confidential client contract, but you only have access to a free public AI tool. What is the safest way to proceed?","options":[{"id":"a","label":"Paste the full contract in, since you will delete the chat afterward.","is_correct":false,"explanation":"Deleting the chat does not undo the fact that the confidential text was already sent to and possibly stored on an outside server. The risk happens at the moment you paste."},{"id":"b","label":"Remove the client name and any identifying details first, then ask for a summary of the generic terms.","is_correct":true,"explanation":"Correct. Stripping the identifiers lets you get real help while keeping the confidential parts off a public tool. The AI summarizes the terms just as well without the names."},{"id":"c","label":"Paste it in but add a line telling the AI to keep it private.","is_correct":false,"explanation":"An instruction in the chat does not control how the company stores or reviews your text. The tool's data policy, not your request, decides what happens to it."}]}$lum$::jsonb, false),
  ($lum$b7e47ccb-babc-559d-80e3-4b3e06b9cf90$lum$::uuid, $lum$831e2277-4995-5fb1-a69d-51368c045f21$lum$::uuid, 2, $lum$before_after$lum$, $lum${"question":"Same goal, summarizing a sensitive document, two prompts for a free public tool. Notice which one keeps the confidential parts off the server.","before_prompt":"Summarize this performance review for me: 'Maria Lopez, Senior Analyst, has missed three deadlines this quarter and her manager David Chen is recommending a performance improvement plan before her March 15 review.'","after_prompt":"Help me summarize a performance review. Genericized: an employee has missed several deadlines this quarter and their manager is recommending a performance improvement plan before an upcoming review. Give me a clear, neutral summary and suggest how to phrase the concerns constructively. I'll add the real names and dates myself, offline.","changes":["Strips the employee name, the manager name, and the specific date before anything reaches a public tool, so no identifiable personnel record leaves your control.","Replaces the specifics with a generic description the AI can summarize and improve just as well.","Reserves the confidential details for offline work, treating the public tool like a postcard a stranger could read rather than a sealed letter."]}$lum$::jsonb, true),
  ($lum$87953298-910c-5b3a-9ae5-31cb8706477a$lum$::uuid, $lum$f4f68c66-2f07-5f57-a5cd-d155c7e8e9ac$lum$::uuid, 0, $lum$reading$lum$, $lum${"markdown":"A fair worry sits under a lot of AI use: am I being smart, or am I being lazy? Is this still my work? The honest answer is that it depends entirely on how you use the tool, and the difference is worth naming clearly so you can stay on the right side of it without guilt.\n\nThe line is this: **AI with integrity amplifies your thinking. Lazy AI replaces it.**\n\nWhen you bring the substance, the judgment, and the decisions, and use AI to draft faster, organize better, or get unstuck, you are the author and the tool is a tool. That is no more cheating than using a calculator or a spell-checker. When you hand over the thinking entirely, paste the output unread, and present it as considered work you never actually considered, you have crossed into something else, and people can usually tell.\n\nHere is what staying authentic looks like in practice.\n\n**You direct, it drafts.** The ideas, angle, and key points come from you. The AI helps you express them. A first draft you shaped is yours. A generic answer you requested and rubber-stamped is not.\n\n**You edit it into your voice.** Raw AI output has a recognizable flatness. When you revise it so it sounds like you and says what you actually mean, you are reclaiming authorship. The editing is where the work becomes yours again.\n\n**You can stand behind every word.** The real test: could you defend this if asked? Do you understand it, agree with it, and know it is true? If you would be caught out the moment someone questioned a line, you outsourced too much.\n\n**You are honest when it matters.** In contexts where original or personal work is expected, you are transparent about the tool's role rather than hiding it.\n\nUsing AI is not the lazy choice. Using it to avoid thinking is. The same tool can make you sharper or hollow you out, and which one happens is decided entirely by whether you stay in the author's chair."}$lum$::jsonb, false),
  ($lum$af85ab54-aa5e-568a-a2b7-29c5b1be4ed8$lum$::uuid, $lum$f4f68c66-2f07-5f57-a5cd-d155c7e8e9ac$lum$::uuid, 1, $lum$before_after$lum$, $lum${"question":"Same goal, a thank-you note to a mentor, two ways of using AI. One produces something hollow, the other something real. Notice where the thinking lives.","before_prompt":"Write a heartfelt thank-you note to my mentor for everything they've done for me over the years.","after_prompt":"Help me write a thank-you note to my mentor, Dr. Reyes. Here's what I actually want to say: she took a chance on me when I had no experience, she pushed me to apply for the lead role I was scared of, and her advice to 'slow down to get it right' changed how I work. I want it warm and specific, in my own plain voice, not flowery. Draft it from these points and I'll edit.","changes":["Brings the real substance, the specific memories and the actual message, so the note reflects a real relationship instead of a generic template anyone could have received.","Keeps the author in the driver's seat: the AI expresses points you supplied rather than inventing sentiment you never felt.","Sets up a draft you will edit into your own voice, which is what turns AI assistance into authentic work you can stand behind."]}$lum$::jsonb, true),
  ($lum$45115e63-d27b-55d0-ab5e-6d4bdf813d0a$lum$::uuid, $lum$f4f68c66-2f07-5f57-a5cd-d155c7e8e9ac$lum$::uuid, 2, $lum$multiple_choice$lum$, $lum${"stem":"Which of these uses of AI crosses the line from authentic into lazy, as this lesson draws it?","options":[{"id":"a","label":"Asking AI a question, pasting its unread answer into a report as your considered analysis, and being unable to defend a single line if questioned.","is_correct":true,"explanation":"Correct. Handing over the thinking, rubber-stamping output you never examined, and being unable to stand behind it is exactly the lazy side of the line."},{"id":"b","label":"Supplying your own points and angle, having AI draft from them, then editing it into your voice.","is_correct":false,"explanation":"This is authentic use. You brought the substance and judgment and reclaimed authorship through editing, which is no more cheating than a calculator."},{"id":"c","label":"Using AI to reorganize your own messy notes into a clearer structure you then refine.","is_correct":false,"explanation":"Organizing your own material and refining the result keeps you in the author's chair. The substance is yours; the tool just helped you express it."}]}$lum$::jsonb, false),
  ($lum$38d35c90-e7f3-52b9-8e7e-162aeb324fe8$lum$::uuid, $lum$7a53116d-422d-5bf5-8f0d-9f0386d02907$lum$::uuid, 0, $lum$reading$lum$, $lum${"markdown":"The errors that hurt you are not the wild ones. A glaringly wrong answer gets caught instantly. The damage comes from the subtle error: a date that is off by a year, a statistic that sounds right, a \"summary\" that quietly adds a claim your document never made. It reads smoothly, it fits your expectations, and it sails straight into your final draft.\n\nThese slip through because we read AI output for tone, not for truth. The text is fluent, so our guard drops. The fix is to stop relying on your own re-reading alone and instead make the AI surface its own uncertainty.\n\n**Ask it to mark confidence.** After any answer with facts in it, say: \"Mark each claim as confident, uncertain, or guess, and list anything I should independently verify.\" The model is often surprisingly honest about which parts are shaky once you ask it to separate them out.\n\n**Force fact apart from inference.** When you ask for a summary or analysis, add: \"Only state what is explicitly in the source. Put anything you inferred in a separate list labeled inference.\" This catches the most common subtle error, where AI helpfully fills a gap your document never filled.\n\n**Demand the source, then check it.** \"For each factual claim, tell me where it comes from.\" A real claim has a checkable origin. A hallucinated one often comes back with a vague \"general knowledge\" or a citation that does not exist when you look.\n\nThe point is not to distrust every word. It is to convert a smooth, undifferentiated wall of text into a labeled one, where the risky 10 percent is pulled out and waiting for your eyes instead of hiding in the other 90 percent."}$lum$::jsonb, false),
  ($lum$56f71d79-80ce-5c75-a977-6d721c898278$lum$::uuid, $lum$7a53116d-422d-5bf5-8f0d-9f0386d02907$lum$::uuid, 1, $lum$before_after$lum$, $lum${"question":"Both prompts ask for a summary of the same report. The second one forces the subtle errors into the open. Notice what you gain.","before_prompt":"Summarize the attached quarterly report in five bullet points.","after_prompt":"Summarize the attached quarterly report in five bullet points. Only include what is explicitly stated in the report. After the summary, add two short lists: (1) Verify these: any numbers, dates, or named figures I should confirm against the source. (2) Inference, not stated: anything you concluded that the report does not directly say. If a bullet relies on a figure, quote the figure exactly as written.","changes":["Pins the summary to what the document actually says, which stops the AI from quietly inventing a tidy conclusion the report never reached.","Pulls every checkable number and name into a Verify list, so the risky claims are gathered in one place instead of buried in fluent prose.","Separates inference from fact, exposing the single most common subtle error: a helpful-sounding claim that was added, not found."]}$lum$::jsonb, true),
  ($lum$b5b889bd-36c3-57c0-abd9-a92c96a6b52c$lum$::uuid, $lum$7a53116d-422d-5bf5-8f0d-9f0386d02907$lum$::uuid, 2, $lum$multiple_choice$lum$, $lum${"stem":"You asked AI to summarize a report whose only relevant line says 'revenue grew in Q3.' The summary reads: 'Revenue grew 12% in Q3, driven by strong international sales.' What is the subtle error to catch?","options":[{"id":"a","label":"The summary added a specific figure (12%) and a cause (international sales) the source never stated, which is invented detail dressed as fact.","is_correct":true,"explanation":"Correct. This is the classic subtle error: the AI filled a gap the document left open, turning a vague 'grew' into a precise number and a reason. Forcing fact apart from inference would have caught it."},{"id":"b","label":"Nothing, since the summary is more detailed and therefore more useful than the original.","is_correct":false,"explanation":"Extra detail the source does not support is not useful, it is fabricated. A summary should never contain claims the original did not make."},{"id":"c","label":"The summary is too short to be trustworthy.","is_correct":false,"explanation":"Length is not the issue. The problem is that specific, plausible-sounding claims were added, which is exactly the kind of smooth error that sails into a final draft."}]}$lum$::jsonb, false),
  ($lum$fb1a762a-4101-52e2-91c6-abf8179d5317$lum$::uuid, $lum$7f51ef0c-7de2-5e87-87b5-a9bc9b764372$lum$::uuid, 0, $lum$reading$lum$, $lum${"markdown":"Ask AI a question and you get a competent, reasonable, deeply average answer. That is not a flaw, it is how the tool works: it produces the most statistically likely response, which is by definition the most common one. The first answer is the consensus view, the thing everyone already knows. If you stop there, you get writing and thinking that sounds like everyone else's.\n\nThe people who get genuinely useful output have learned to treat the first answer as a warm-up, not a result. Here is how to push past the surface.\n\n**Ask for what's non-obvious.** After the first answer, say: \"That's the obvious take. What's the angle most people miss? What would an expert say that a beginner wouldn't?\" This forces the model off the well-worn path toward something with more edge.\n\n**Demand specifics over generalities.** Generic answers hide in abstraction. \"Improve communication\" means nothing. Push: \"Give me the exact sentence I'd say, the specific number, the concrete example.\" Specificity is where surface-level advice either becomes useful or falls apart.\n\n**Make it argue with itself.** \"Now give me the strongest case against what you just said.\" A single answer is a sales pitch. Forcing the counterargument surfaces the trade-offs and assumptions the first response quietly skipped, and you end up with a real picture instead of a tidy one.\n\n**Ask why, repeatedly.** Like a curious child, keep asking the model to go one level deeper. \"Why is that true? And why is that?\" Three rounds in, you reach the actual mechanism instead of the slogan.\n\nThe mindset shift is to stop treating the conversation as one question and one answer. The first reply is the cost of entry. The depth comes from the follow-ups, where you refuse the generic and keep pressing until the answer earns its place."}$lum$::jsonb, false),
  ($lum$b97d8b05-f61b-578c-a888-c5452e6f6ea1$lum$::uuid, $lum$7f51ef0c-7de2-5e87-87b5-a9bc9b764372$lum$::uuid, 1, $lum$try_it_live$lum$, $lum${"instructions":"Practice pushing past the surface. Take any first answer from an AI, or use the sample below, and write the follow-up prompts that force it deeper. Sample first answer: 'To improve employee retention, focus on competitive pay, good management, clear growth paths, and a positive culture.' Your job is to make it non-obvious and specific.","system_prompt":"You are a coach who teaches people to extract depth from AI. Given a generic, surface-level AI answer, write three sharp follow-up prompts the user could send to push past it: one that asks for the non-obvious angle, one that demands a concrete specific, and one that forces a counterargument. Make each follow-up directly about the sample content, not generic. No jargon, no em dashes.","ideal_output":"Three follow-ups to push that retention answer deeper: (1) Non-obvious angle: 'Those are the standard four everyone lists. What's the retention lever that companies consistently underestimate, and why does it get missed?' (2) Force a specific: 'Pick the single highest-impact one for a 30-person team with a tight budget, and give me the exact first action I'd take next week, including what I'd say.' (3) Counterargument: 'Now make the strongest case that focusing on pay and perks actually hurts retention compared to something else, and tell me what that something is.' Run these in order and the answer goes from a generic list to a specific, defensible plan.","input_placeholder":"Paste a generic AI answer and I'll write the prompts that dig past it..."}$lum$::jsonb, true),
  ($lum$d3ac84e0-eec7-54bc-aa69-048af69e6817$lum$::uuid, $lum$7f51ef0c-7de2-5e87-87b5-a9bc9b764372$lum$::uuid, 2, $lum$multiple_choice$lum$, $lum${"stem":"AI gives you a safe, generic first answer to a strategy question. Which follow-up best pushes it past the surface, as this lesson teaches?","options":[{"id":"a","label":"'That's the obvious take. What's the angle most people miss, and now give me the strongest case against what you just said.'","is_correct":true,"explanation":"Correct. Asking for the non-obvious angle and forcing a counterargument are exactly the moves that drive past the consensus answer to the trade-offs and edge the first reply skipped."},{"id":"b","label":"'Thanks, that's helpful.' and then using the first answer as-is.","is_correct":false,"explanation":"Stopping at the first answer is the whole problem. It is the consensus view everyone already knows, the cost of entry, not the result."},{"id":"c","label":"'Can you say that again but shorter?'","is_correct":false,"explanation":"Shortening a generic answer just gives you a shorter generic answer. Depth comes from non-obvious angles, specifics, and counterarguments, not concision."}]}$lum$::jsonb, false),
  ($lum$1087054a-78d8-5ca2-8bf9-34fd73dc520d$lum$::uuid, $lum$8ffd3c5f-2e70-5524-9fee-aa386b344c1d$lum$::uuid, 0, $lum$reading$lum$, $lum${"markdown":"Almost every AI embarrassment, the invented fact in a report, the email that sounds like a robot, the proposal with a placeholder nobody removed, traces back to one habit: someone pasted raw AI output straight into the real world without reading it properly. The fix is not a better prompt. It is a five-minute editing pass that you never skip.\n\nThink of AI output as a strong first draft from a fast but careless assistant. It got you 80 percent of the way in seconds, which is the whole point. But the last 20 percent, the part that makes it correct, appropriate, and yours, is your job. That last stretch is where the value and the safety live.\n\nHere is the editing pass, and it takes minutes.\n\n**Cut what does not earn its place.** AI over-writes. It pads with filler intros, restates the obvious, and inflates simple points. Read once with a delete key in hand. Almost everything reads better shorter.\n\n**Check the facts and the fit.** Confirm any specific claim, number, or name. Then ask the question only you can answer: is this appropriate for this person, this moment, this relationship? The AI does not know the history; you do.\n\n**Make it sound like you.** Remove the generic AI tells and adjust the wording so it matches how you actually communicate. A few sentence changes reclaim authorship and kill the robotic flatness.\n\n**Scan for the obvious slip.** Placeholders left in, a wrong name, a tone that does not fit, a promise you cannot keep. Thirty seconds of scanning catches the mistake that would have been mortifying.\n\nThis is not about distrusting AI. It is about understanding the deal: AI does the heavy lifting fast, you do the finishing. People who honor that deal look sharp and move quickly. People who skip the edit eventually paste something they regret. Be the first kind."}$lum$::jsonb, false),
  ($lum$b5073b3a-e641-581c-98ae-137219e25b42$lum$::uuid, $lum$8ffd3c5f-2e70-5524-9fee-aa386b344c1d$lum$::uuid, 1, $lum$before_after$lum$, $lum${"question":"A raw AI draft of a customer reply versus the same draft after a two-minute edit. Notice what the editing pass removes and fixes.","before_prompt":"Dear Valued Customer, Thank you so much for reaching out to us regarding your recent inquiry. We sincerely appreciate your patience and understanding. I am writing to inform you that we have received your request and are diligently working to address it. Please rest assured that your satisfaction is our utmost priority. We will endeavor to provide a resolution in a timely manner. [Insert resolution details here]. Should you have any further questions, please do not hesitate to reach out.","after_prompt":"Hi Dana, thanks for flagging this. I looked into the double charge on your March invoice, and you're right, it was billed twice. I've refunded the duplicate today, so you'll see it back on your card within three business days. Really sorry for the hassle, and thanks for catching it. If anything still looks off, just reply here and I'll sort it out.","changes":["Cuts the wall of filler ('valued customer,' 'rest assured,' 'utmost priority') down to a direct, warm reply a person would actually send.","Catches and fills the leftover placeholder, the unaddressed '[insert resolution details here],' which is exactly the slip that escapes when you paste raw.","Adds the specific facts only the human knew, the double charge, the refund, the timeline, turning a hollow template into a real answer to a real problem."]}$lum$::jsonb, true),
  ($lum$2fb1e679-6ba0-52e3-96f6-efd2322c4408$lum$::uuid, $lum$8ffd3c5f-2e70-5524-9fee-aa386b344c1d$lum$::uuid, 2, $lum$multiple_choice$lum$, $lum${"stem":"In the editing pass this lesson describes, which check is the one that catches the '[insert resolution details here]' placeholder before it embarrasses you?","options":[{"id":"a","label":"The thirty-second scan for the obvious slip: leftover placeholders, a wrong name, a promise you can't keep.","is_correct":true,"explanation":"Correct. The final scan exists precisely to catch the mortifying obvious mistakes, like a placeholder nobody removed, that escape when you paste raw."},{"id":"b","label":"Cutting filler, since shorter writing automatically removes placeholders.","is_correct":false,"explanation":"Trimming filler tightens the prose but won't reliably surface a leftover placeholder. The dedicated scan for obvious slips is what catches it."},{"id":"c","label":"None, because a good enough prompt means the draft never has placeholders.","is_correct":false,"explanation":"The lesson is explicit that the fix is not a better prompt but an editing pass you never skip. Raw drafts routinely contain placeholders and slips."}]}$lum$::jsonb, false),
  ($lum$6dd68013-1566-5e75-bb52-7ed447063fd5$lum$::uuid, $lum$a1ad841a-5ac6-526b-b70c-5b48555e505b$lum$::uuid, 0, $lum$reading$lum$, $lum${"markdown":"AI gives you confident answers. Confidence is not the same as correct. The skill that separates people who use AI well from people who get embarrassed by it is a simple checking habit.\n\nYou do not need to verify every word. You need to verify the parts that can actually be wrong and that matter if they are. Those are almost always the specifics: names, numbers, dates, quotes, and direct claims about how something works.\n\nHere is a method you can run in under a minute.\n\n**1. Highlight the specifics.** Read the answer and mentally flag anything concrete: a statistic, a person's name, a law, a date, a price, a step in a process that has real consequences.\n\n**2. Ask where it came from.** For anything flagged, ask yourself: could the AI actually know this, or is it likely guessing? Current events, internal policies, and exact figures are guess-prone.\n\n**3. Verify against one real source.** Check the flagged item against something you trust: the actual document, a quick search, the official site, or a colleague who knows. One good source beats the AI's confidence every time.\n\n**4. Watch for the too-clean answer.** When an answer is suspiciously tidy, with a perfect quote or a round statistic, slow down. Invented details, called hallucinations, often look more polished than real ones.\n\nThe goal is not to distrust everything. It is to know exactly which 10 percent to check so you can trust the other 90 percent and move fast."}$lum$::jsonb, false),
  ($lum$ba6ac2e5-27eb-5f0e-af56-0a9c13c8886a$lum$::uuid, $lum$a1ad841a-5ac6-526b-b70c-5b48555e505b$lum$::uuid, 1, $lum$try_it_live$lum$, $lum${"instructions":"Paste an AI answer you recently received, or the one below, and turn it into a checking plan. List every specific claim that needs verifying and name the single best source to check each one against. Sample: \"The new overtime rule took effect in January and applies to anyone earning under 55,000 a year.\"","system_prompt":"You are a careful fact-checking coach for non-technical professionals. Given an AI answer, extract every verifiable specific (names, numbers, dates, legal or policy claims) and, for each one, name a concrete real-world source the person should check it against. Be brief and practical. Do not invent facts.","ideal_output":"Claims to verify before you use this: (1) The date the rule took effect, January, check the official labor department page for the rule's effective date. (2) The salary threshold of 55,000, check the same official page, since this number changes and is often misquoted. (3) Who it applies to, confirm the exact category of workers in the official text, not a summary. Do not send or act on any of these numbers until the official source confirms them.","input_placeholder":"Paste an AI answer and I'll list what to check and where..."}$lum$::jsonb, true),
  ($lum$20685fb2-4c0c-55ca-afc3-e89c239dccf8$lum$::uuid, $lum$a1ad841a-5ac6-526b-b70c-5b48555e505b$lum$::uuid, 2, $lum$multiple_choice$lum$, $lum${"stem":"An AI answer includes a perfectly round statistic ('exactly 50% of small businesses fail in year one') alongside a crisp, quotable source name. Under this lesson's method, what should that tidy detail trigger?","options":[{"id":"a","label":"Extra caution and a check against the real source, because suspiciously clean numbers and flawless quotes are often the invented ones.","is_correct":true,"explanation":"Correct. Step 4: a too-clean answer, like a round statistic or a perfect quote, is a flag to slow down, since hallucinated details often look more polished than real ones."},{"id":"b","label":"Confidence that it is accurate, since a specific source name means the AI looked it up.","is_correct":false,"explanation":"A named source in an AI answer is not proof it exists or says that. Citations are exactly the kind of specific that gets invented, so this needs checking, not trust."},{"id":"c","label":"Nothing, because a statistic is the kind of general knowledge AI is reliable on.","is_correct":false,"explanation":"A specific figure is the opposite of safe general knowledge. Numbers are guess-prone and consequential, which is precisely what the method tells you to verify."}]}$lum$::jsonb, false),
  ($lum$05d83222-0f97-5630-984b-c3ec5068b16b$lum$::uuid, $lum$2c4315ba-aff6-5e90-85c2-fa6bb19f65dd$lum$::uuid, 0, $lum$reading$lum$, $lum${"markdown":"A lot of people use AI at work in a nervous gray zone, half-hiding it, unsure if they are being resourceful or breaking a rule they have not read. Let's replace the anxiety with a clear picture of what actually gets people in trouble, because it is rarely the thing they worry about.\n\nWhat almost never gets you fired: using AI to draft an email, clean up your notes, or think through a problem. That is using a tool, the same as using a spreadsheet or a search engine.\n\nWhat genuinely can: two things. **Data leaks and dishonesty.**\n\n**Data.** Pasting confidential, regulated, or personal information into a public AI tool is the real risk. Customer records, patient data, unreleased financials, someone's salary, source code. The tool may store or review what you paste, so this can breach a contract, a privacy law, or your company's security rules in one click. This is the line that matters most.\n\n**Disclosure and honesty.** Passing off AI work as something it is not, when honesty was expected, is the other risk. Submitting AI-written content where original work was required, or hiding AI use from a client or manager who would care, is a trust problem, not a tooling problem.\n\nHere is how to stay safe:\n\n**Find the policy.** Many employers now have an AI policy or an approved, private tool. Search the intranet, or just ask your manager or IT. Asking is not admitting guilt, it is being professional.\n\n**When there is no policy, assume a strict one.** Absence of a rule is not permission. Default to: no confidential or personal data in public tools, and be transparent about AI use when it would matter to someone.\n\n**Ask before, not after.** A two-minute question to your manager beats explaining a mistake later. \"I'd like to use AI to help draft these, with no client data pasted in. Any concerns?\" is a sentence that protects you.\n\nThe honest summary: the tool is almost never the problem. What you feed it and whether you are straight about using it are the things that carry real consequences."}$lum$::jsonb, false),
  ($lum$ddc7574c-4998-5e5d-97bd-5cf90f95b85d$lum$::uuid, $lum$2c4315ba-aff6-5e90-85c2-fa6bb19f65dd$lum$::uuid, 1, $lum$multiple_choice$lum$, $lum${"stem":"Your workplace has no written AI policy. You want to use a free public chatbot to help with your work. Which approach keeps you safest?","options":[{"id":"a","label":"Since there's no rule against it, paste in whatever you need, including client details, to get the best help.","is_correct":false,"explanation":"No policy is not permission. Pasting client details into a public tool is the exact action that can breach privacy rules or a client contract, regardless of whether an internal memo exists."},{"id":"b","label":"Use it for general drafting with no confidential or personal data pasted in, and ask your manager whether an approved tool or any limits exist.","is_correct":true,"explanation":"Correct. You get the benefit while avoiding the two real risks: you keep sensitive data out, and you surface the question to your manager, which is professional, not incriminating."},{"id":"c","label":"Avoid AI entirely until someone writes an official policy.","is_correct":false,"explanation":"Overcautious and unnecessary. Generic, non-confidential drafting is low-risk and a normal use of the tool. You can be safe without opting out completely."}]}$lum$::jsonb, false),
  ($lum$c193a7ea-04b9-561d-ae9d-2f5568ff43c5$lum$::uuid, $lum$2c4315ba-aff6-5e90-85c2-fa6bb19f65dd$lum$::uuid, 2, $lum$fill_blank$lum$, $lum${"template":"Using AI at work almost never gets you in trouble for the tool itself. The two real risks are leaking {{1}} or personal data into a public tool, and being dishonest by hiding your AI {{2}} when it would matter to someone. When no policy exists, assume a {{3}} one.","blanks":[{"id":"1","accept":["confidential","sensitive"],"ideal":"confidential"},{"id":"2","accept":["use","usage"],"ideal":"use"},{"id":"3","accept":["strict"],"ideal":"strict"}],"explanation":"The lesson's core: trouble comes from data leaks and dishonesty, not the tool. With no policy, default to strict, no confidential or personal data in public tools, and be transparent about AI use when it matters."}$lum$::jsonb, false),
  ($lum$ba4aca73-be70-546e-9b5b-357fceec9208$lum$::uuid, $lum$d9790939-c93b-5ffc-91a8-5e6f76cd6ff2$lum$::uuid, 0, $lum$reading$lum$, $lum${"markdown":"Once a team adopts AI, a new problem appears. One person's AI emails sound warm, another's sound robotic. One person fact-checks everything, another pastes raw output into client decks. The tool amplified everyone, but in ten different directions. Consistency, which used to come from a shared house style, quietly broke.\n\nThe skill here is moving AI from a personal tool to a team asset, so the good prompts and the guardrails are shared rather than locked in one person's head.\n\n**Build a shared prompt library.** When someone on the team finds a prompt that nails a recurring task, it should not die in their chat history. Put it in a shared doc or your tool's team workspace, labeled by job. Now the whole team starts from the proven version instead of a blank box, and the output converges.\n\n**Write a one-page voice and standards guide.** Capture how your team's writing should sound and what it should never do, in plain rules: \"Warm but concise. No buzzwords. Always sign off with the team name. Never invent a statistic.\" People paste this into the AI, or it goes in shared custom instructions, and ten voices become one.\n\n**Set a shared verification rule.** Decide as a team what must be checked before it goes out, especially anything client-facing or factual. A simple agreed standard (\"no AI-generated number leaves the team unverified\") prevents the weakest habit from becoming the team's risk.\n\n**Make the assets easy to find and easy to update.** A library nobody can locate is no library. Keep it in one obvious place, and let anyone add a winning prompt. Treat it as living: review it occasionally and prune what stopped working.\n\nThe payoff is leverage that compounds. Instead of each person slowly learning the same lessons alone, the team's best discoveries become everyone's starting point, and the work that ships looks like it came from one capable group rather than ten strangers."}$lum$::jsonb, false),
  ($lum$8e30412a-c278-525c-95d6-056a7301fea3$lum$::uuid, $lum$d9790939-c93b-5ffc-91a8-5e6f76cd6ff2$lum$::uuid, 1, $lum$multiple_choice$lum$, $lum${"stem":"Your team's AI output is all over the place: warm from one person, robotic from another, some of it unchecked. Which single shared asset most directly fixes the inconsistent voice?","options":[{"id":"a","label":"A one-page voice and standards guide that everyone pastes in or loads as shared custom instructions.","is_correct":true,"explanation":"Correct. Capturing how the team's writing should sound and what it must never do, then sharing it, is what turns ten voices into one. It targets the voice problem directly."},{"id":"b","label":"Telling each person to prompt more carefully on their own.","is_correct":false,"explanation":"Leaving it to individual effort is exactly how the inconsistency arose. The fix is moving standards out of one person's head into a shared asset."},{"id":"c","label":"A rule that only the manager is allowed to use AI for team writing.","is_correct":false,"explanation":"Bottlenecking through one person kills the leverage. The goal is shared assets so everyone produces consistent work, not restricting access."}]}$lum$::jsonb, false),
  ($lum$f76c5cdb-e4d2-5c8b-b73e-73332d39e9ff$lum$::uuid, $lum$d9790939-c93b-5ffc-91a8-5e6f76cd6ff2$lum$::uuid, 2, $lum$mini_project$lum$, $lum${"brief":"Draft the first version of a shared AI kit for your team, even if your \"team\" is just you and two colleagues. First, collect three prompts that have worked well for recurring team tasks, clean them up, and put them in one shared document labeled by job (writing, summarizing, client replies). Second, write a one-page voice and standards guide: five to eight plain rules covering how your team's writing should sound and the hard \"never do this\" lines, including at least one verification rule. Third, write one shared custom-instructions block the team can paste in so every chat starts tuned to your standards. Put all three in a single shared location and tell the team where it lives. Ask one colleague to use it for a real task this week and tell you what was missing, then update it. The first version does not need to be complete, it needs to exist and be findable.","parts":[]}$lum$::jsonb, false),
  ($lum$30cf00da-2580-5baa-b498-fcb034d7f687$lum$::uuid, $lum$a47e35f8-d763-5560-805c-0f71db4a749b$lum$::uuid, 0, $lum$reading$lum$, $lum${"markdown":"There is a sound that AI writing makes, and more people can hear it every month. The polished but empty opening. The phrase \"in today's fast-paced world.\" The relentless symmetry of three neat bullet points. The word \"delve.\" When a reader catches that sound in your message, two things happen: they trust it less, and they feel a little less respected, because you clearly did not write it to them.\n\nGood news: the AI sound is easy to remove once you know what produces it. Most of it comes from a few habits.\n\n**Cut the throat-clearing.** AI loves to warm up before saying anything. \"I hope this email finds you well. In an increasingly complex landscape, it is more important than ever to...\" Delete it. Start with the actual point. Real people get to it.\n\n**Swap inflated words for plain ones.** AI reaches for \"utilize,\" \"leverage,\" \"facilitate,\" \"delve into,\" \"robust.\" Change them to \"use,\" \"use,\" \"help,\" \"look at,\" \"strong.\" If you would not say the word out loud to the person, do not write it.\n\n**Break the perfect symmetry.** AI output is suspiciously balanced: every list has three items, every paragraph is the same length. Human writing is lumpy. Vary your sentence lengths, let one point be longer than the others, and do not force everything into a list.\n\n**Add one specific, human detail.** The fastest way to sound human is to include something only you would know: a reference to last week's conversation, a small aside, an actual name. Generic text has no fingerprints. One real detail puts yours on it.\n\nThe fix is not to write everything from scratch. It is to let AI draft, then spend sixty seconds removing the tells and adding yourself back in. That small edit is the difference between a message that sounds like a person and one that sounds like a machine wearing a tie."}$lum$::jsonb, false),
  ($lum$ce4bfb16-de0e-545b-bbd9-d021a9b017e5$lum$::uuid, $lum$a47e35f8-d763-5560-805c-0f71db4a749b$lum$::uuid, 1, $lum$before_after$lum$, $lum${"question":"The same message before and after a sixty-second human pass. Notice exactly which AI tells get removed.","before_prompt":"Hi team, I hope this message finds you well. In today's rapidly evolving business landscape, it is more important than ever to leverage our collective strengths. I wanted to take a moment to delve into three key priorities for the upcoming quarter: first, enhancing operational efficiency; second, fostering cross-functional collaboration; and third, optimizing our customer engagement strategies. I am confident that by working together, we can achieve robust results.","after_prompt":"Hi team, quick note on where we're focused next quarter. The big one is getting our turnaround time down, since that's what customers keep raising. I also want us talking across teams more, the marketing and support handoff has been rough lately. Beyond that, let's keep doing what's working. Thanks for the strong push this last stretch, the Henderson launch especially. Tom","changes":["Deletes the empty opening and the 'today's evolving landscape' filler, so the message starts with the actual point.","Replaces inflated words like leverage, delve, foster, and robust with plain language a person would actually say.","Breaks the rigid three-part symmetry and adds a specific human detail, the Henderson launch, that gives the message a real fingerprint."]}$lum$::jsonb, true),
  ($lum$0ce15407-13bd-56ef-893e-f9ce158d8f58$lum$::uuid, $lum$a47e35f8-d763-5560-805c-0f71db4a749b$lum$::uuid, 2, $lum$fill_blank$lum$, $lum${"template":"To strip the AI sound, delete the throat-clearing {{1}} so you start with the actual point, swap inflated words like 'utilize' and 'leverage' for {{2}} ones, and add one specific human {{3}} that only you would know.","blanks":[{"id":"1","accept":["opening","intro","introduction"],"ideal":"opening"},{"id":"2","accept":["plain","simple","plainer"],"ideal":"plain"},{"id":"3","accept":["detail","fact"],"ideal":"detail"}],"explanation":"The three biggest AI tells: a warm-up opening, inflated vocabulary, and a total absence of specific human detail. Cut the first two and add the third to sound like a person."}$lum$::jsonb, false),
  ($lum$8990bab1-17f7-577b-80c5-06b8292e9cbf$lum$::uuid, $lum$d5018f9e-63d8-511f-a528-d3266861a2ce$lum$::uuid, 0, $lum$reading$lum$, $lum${"markdown":"Here is the pattern almost everyone goes through. They learn AI can help, they get excited, they use it for a week, and then they drift back to doing everything the old way. Not because the tool let them down, but because reaching for it never became automatic. The hard part of AI is not the prompting. It is the remembering.\n\nThe skill in this lesson is workflow fit: getting AI to live inside the work you already do, instead of being a separate thing you have to remember to go visit.\n\n**Attach it to an existing task, not a new one.** Do not resolve to \"use AI more.\" Pick one task you already do on a schedule and bolt AI onto it. \"Every Monday when I write the team update, I draft it with AI first.\" The existing habit carries the new one.\n\n**Create a trigger.** A habit needs a cue. Keep the tool pinned in your browser, leave a saved prompt at the top of your weekly doc, or put a sticky note where the task happens. The goal is that the task itself reminds you, so you do not rely on willpower.\n\n**Start with one or two, not ten.** People who try to use AI for everything at once use it for nothing within a month. Pick the one or two tasks where it clearly helps, let those become automatic, then add a third. Slow adoption is the kind that lasts.\n\n**Lower the friction.** If using AI means opening a new tab, logging in, and retyping context every time, you will quit. Save your common prompts, set up custom instructions once, and keep the tool one click away. Every bit of friction you remove is a future day you actually use it.\n\nThe test of whether AI has stuck is simple: a month from now, are you still reaching for it without thinking? That only happens when it is wired into a real, recurring task, not floating as a good intention."}$lum$::jsonb, false),
  ($lum$3cbbc7cc-fb30-5680-abdd-627ecb0866d8$lum$::uuid, $lum$d5018f9e-63d8-511f-a528-d3266861a2ce$lum$::uuid, 1, $lum$multiple_choice$lum$, $lum${"stem":"You learned AI could help, used it enthusiastically for a week, then drifted back to the old way. According to this lesson, what is the most likely reason?","options":[{"id":"a","label":"Reaching for AI never became automatic, because it wasn't attached to a recurring task with a trigger to cue you.","is_correct":true,"explanation":"Correct. The hard part is remembering, not prompting. Without bolting AI onto an existing habit and creating a cue, willpower fades and you drift back to the old way."},{"id":"b","label":"The AI kept giving you bad answers, so the tool let you down.","is_correct":false,"explanation":"The lesson is explicit that people usually stop not because the tool failed, but because reaching for it never became a habit."},{"id":"c","label":"You needed to learn more advanced prompting techniques first.","is_correct":false,"explanation":"Better prompting is not the issue. Workflow fit and a reliable trigger are what make AI stick, not more technique."}]}$lum$::jsonb, false),
  ($lum$067f4dc5-00b7-5ba9-9779-e95884ab3b12$lum$::uuid, $lum$d5018f9e-63d8-511f-a528-d3266861a2ce$lum$::uuid, 2, $lum$mini_project$lum$, $lum${"brief":"Wire AI into one real, recurring task this week so it becomes a habit instead of a novelty. First, pick a single task you already do on a predictable schedule (a weekly report, a recurring type of email, a standing meeting prep) and write down exactly when it happens. Second, design the trigger: decide where the reminder will live (a pinned tab, a saved prompt at the top of the relevant doc, a calendar note) so the task itself cues you to use AI. Third, write and save the specific prompt you will reuse for that task, with your context already baked in, so there is no friction next time. Run it through one full cycle of the task this week, note what felt clunky, and fix that one piece of friction. Do not add a second task until this one runs on autopilot.","parts":[]}$lum$::jsonb, false),
  ($lum$093bda7d-11e7-58fe-b883-5f510f0364a1$lum$::uuid, $lum$7c564a90-4ab6-51de-a61e-e02339f7c2b5$lum$::uuid, 0, $lum$reading$lum$, $lum${"markdown":"If you have started using AI well, you have probably hit the next wall: the colleague who rolls their eyes, the manager who is wary, the teammate who tried it once, got a bad answer, and wrote it off. You cannot move a workflow forward alone, so bringing skeptics along is a real skill, and it is mostly about people, not technology.\n\nThe mistake is leading with enthusiasm and features. \"It's amazing, it can do anything\" lands as hype and deepens the resistance. Skeptics are not won by excitement. They are won by a relevant result and by having their actual concern taken seriously.\n\n**Name the real fear.** Most resistance is one of three worries: \"it will replace me,\" \"it will produce garbage I have to fix,\" or \"I'll look like I'm cheating.\" Surface it honestly. \"I'm not trying to replace your judgment, I'm trying to skip the blank-page part\" disarms far more than a feature list.\n\n**Show, on their task.** Do not demo a generic trick. Take a task they personally find tedious and show AI doing the boring 80 percent while they keep the judgment. A skeptic who watches AI turn their own messy notes into a clean draft in thirty seconds learns more than any pitch.\n\n**Be honest about the limits.** Skeptics trust people who admit the downsides. Show where it gets things wrong and how you check it. Counterintuitively, acknowledging the flaws makes them trust the tool more, because you are clearly not selling them.\n\n**Start them with one safe win.** Give them a single, low-stakes, high-annoyance task to try, with a prompt that already works. One real win they experienced themselves beats ten you described.\n\nThe goal is not to convert a believer overnight. It is to move someone from \"this is nonsense\" to \"huh, that actually saved me time,\" on a task they care about, with their concern respected. That shift is what spreads through a team."}$lum$::jsonb, false),
  ($lum$21c82e7c-3176-5bc9-9527-5956024df42e$lum$::uuid, $lum$7c564a90-4ab6-51de-a61e-e02339f7c2b5$lum$::uuid, 1, $lum$before_after$lum$, $lum${"question":"Two ways to pitch AI to a skeptical colleague. The second one is built to actually land. Notice the shift.","before_prompt":"You should really start using AI, it's incredible, it can write your emails, summarize anything, even build whole workflows. You're going to get left behind if you don't get on board soon.","after_prompt":"I know you've been burned by the hype, and I'm not saying hand over your judgment. But you mentioned you hate writing the monthly compliance summary. Can I show you something? Give me your rough notes and watch it produce a first draft in thirty seconds, then you edit it like you always would. If it's not actually useful on this one task, drop it.","changes":["Acknowledges the skeptic's real concern up front instead of steamrolling it with enthusiasm, which lowers their defenses.","Anchors to a specific task the colleague already finds tedious, so the value is concrete and personal rather than abstract hype.","Keeps them in control as the editor and offers an easy exit, which makes trying it feel safe instead of like a commitment or a threat."]}$lum$::jsonb, true),
  ($lum$1fb695a3-f6ae-51f5-a853-7d93607bd28e$lum$::uuid, $lum$7c564a90-4ab6-51de-a61e-e02339f7c2b5$lum$::uuid, 2, $lum$multiple_choice$lum$, $lum${"stem":"A colleague tried AI once, got a bad answer, and wrote it off. Based on this lesson, what is most likely to move them?","options":[{"id":"a","label":"Showing AI do the tedious 80 percent of a task they personally hate, while they keep the judgment and an easy exit.","is_correct":true,"explanation":"Correct. Skeptics are won by a relevant, concrete result on a task they care about, with their concern respected, not by enthusiasm or feature lists."},{"id":"b","label":"Listing everything AI can do and warning they'll be left behind if they don't adopt it.","is_correct":false,"explanation":"Leading with hype and feature lists lands as pressure and deepens resistance. It is the exact mistake the lesson warns against."},{"id":"c","label":"Hiding the tool's flaws so they don't get discouraged before they're hooked.","is_correct":false,"explanation":"Backwards. Being honest about the limits and showing how you check it is what makes skeptics trust you, because you are clearly not selling them."}]}$lum$::jsonb, false),
  ($lum$853eff81-f759-507c-b6a9-aafe2226315f$lum$::uuid, $lum$4a73e2b9-e2fd-5255-b460-71f82cdfe8b3$lum$::uuid, 0, $lum$reading$lum$, $lum${"markdown":"Most people use AI with one of two broken settings: trust everything, or trust nothing. Both waste the tool. The skill that sits in the middle is trust calibration, which just means deciding how much to believe a given answer based on what kind of answer it is.\n\nHere is the useful truth: AI is not uniformly reliable. It is excellent at some things and shaky at others, and the line between them is fairly predictable. Once you can see the line, you stop double-checking the safe stuff and you stop getting burned by the risky stuff.\n\n**The high-trust zone: shaping and explaining.** When AI rewrites your paragraph, organizes your messy notes, suggests a structure, brainstorms options, or explains a well-established general concept, it is on solid ground. You provided the substance, or the substance is common knowledge. Skim for tone and sense, then move on.\n\n**The low-trust zone: specific, checkable claims.** Names, numbers, dates, statistics, quotes, citations, legal or medical specifics, anything about recent events, and anything about your own company's internal details. These are exactly where AI invents confident, clean-looking answers. The more specific and the more recent, the more you verify.\n\n**The hard rule: stakes raise the bar.** A wrong word in a brainstorm costs nothing. A wrong dosage, a wrong contract figure, or a wrong number in a board deck costs a lot. When being wrong is expensive, verify even claims that feel safe.\n\nA simple way to hold this: ask \"could the AI actually know this, and what happens if it's wrong?\" High knowability and low stakes means trust it. Low knowability or high stakes means check it. You are not being paranoid, you are aiming your attention where it pays off."}$lum$::jsonb, false),
  ($lum$56bfde1c-6673-58dd-a4b2-e237a68b1406$lum$::uuid, $lum$4a73e2b9-e2fd-5255-b460-71f82cdfe8b3$lum$::uuid, 1, $lum$multiple_choice$lum$, $lum${"stem":"An AI tool gives you four things in one reply. Which one deserves the most verification before you rely on it?","options":[{"id":"a","label":"A cleaner rewrite of a clunky paragraph you wrote.","is_correct":false,"explanation":"Rewriting text you supplied is the high-trust zone. The substance is yours, so a quick read for tone is enough."},{"id":"b","label":"The exact percentage a tax credit changed by this year, stated to the decimal.","is_correct":true,"explanation":"Correct. A specific, recent, checkable number is the classic low-trust claim, and a tax figure is high-stakes. Confirm it against the official source before using it."},{"id":"c","label":"A plain-language explanation of what a mortgage is.","is_correct":false,"explanation":"Well-established general concepts are reliable. This is common knowledge the model has seen countless times."},{"id":"d","label":"Three possible titles for your presentation.","is_correct":false,"explanation":"Brainstorming is low-stakes and a strong use of AI. A weak title costs you nothing and you pick the one you like."}]}$lum$::jsonb, false),
  ($lum$0d5863e4-f235-590b-aa49-7419e78c5b12$lum$::uuid, $lum$4a73e2b9-e2fd-5255-b460-71f82cdfe8b3$lum$::uuid, 2, $lum$mini_project$lum$, $lum${"brief":"Build a trust map for the AI work you actually do, so calibration becomes automatic instead of a fresh judgment each time. First, list six real things you have recently asked AI to do (for example: reword an email, summarize a report, look up a statistic, explain a concept, draft a contract clause, brainstorm names). Second, place each one on two axes: could the AI actually know this reliably, and what happens if it is wrong? Mark each as high-trust (skim and move on) or low-trust (verify before relying on it). Third, for every item you marked low-trust, write the one source you would check it against. Finally, circle any item where the stakes alone push it into verify-even-if-it-feels-safe territory, like a number headed for a board deck or a client. Keep the map nearby for a week and notice where your instinct was miscalibrated, then adjust it.","parts":[]}$lum$::jsonb, false),
  ($lum$c946d9ca-b89d-540e-a774-f4c9098d06ca$lum$::uuid, $lum$aa6943e7-fdd2-587a-a4fe-4a3e7151625f$lum$::uuid, 0, $lum$reading$lum$, $lum${"markdown":"There is a quiet trap in using AI a lot: verification fatigue. At first you check everything carefully. Then it gets tiring, so you check less, then you check nothing, and one day an invented figure ends up in front of your boss. The problem was never your diligence. It was trying to check everything at the same intensity, which nobody can sustain.\n\nThe fix is to stop treating verification as one big chore and turn it into tiers, so your effort lands where the risk actually is.\n\n**Tier 1, the glance.** For low-stakes, easily-judged output, such as a reworded email or a brainstorm, one read for sense and tone is enough. No sourcing, no cross-checking. Most daily AI use lives here, and trying to forensically verify it is the main cause of burnout.\n\n**Tier 2, the targeted check.** For output that matters but is not dangerous, such as a report summary or a draft going to a client, do not re-verify everything. Pull out only the specific claims (numbers, names, dates) and check those against the source. The structure and wording you can trust.\n\n**Tier 3, the full verify.** For high-stakes output, such as anything legal, medical, financial, or public, every factual claim gets confirmed against a primary source, and a second person reviews where possible. This is slow on purpose, and you only pay that cost for the small slice of work that warrants it.\n\nThe skill is sorting incoming AI work into the right tier in two seconds, so you spend your limited checking energy on the 10 percent that can actually hurt you. Done consistently, this is what lets you use AI heavily and still sleep at night."}$lum$::jsonb, false),
  ($lum$3b7aa780-3a48-58cc-969c-295423b0bb54$lum$::uuid, $lum$aa6943e7-fdd2-587a-a4fe-4a3e7151625f$lum$::uuid, 1, $lum$multiple_choice$lum$, $lum${"stem":"You used AI to reword a short, casual email you had already drafted to a colleague. No new facts or figures were added. Which verification tier does this belong in?","options":[{"id":"a","label":"Tier 1, the glance: one read for sense and tone, then send.","is_correct":true,"explanation":"Correct. Low-stakes output with no AI-introduced facts to source is exactly Tier 1. Forensically checking it is the wasted effort that causes verification burnout."},{"id":"b","label":"Tier 3, the full verify: confirm every claim against a primary source and get a second reviewer.","is_correct":false,"explanation":"Full verification is reserved for high-stakes legal, medical, financial, or public work. Spending it on a reworded internal email is the over-checking the tiers exist to prevent."},{"id":"c","label":"Tier 2, the targeted check: pull every claim and check it against the source.","is_correct":false,"explanation":"Tier 2 is for output that matters and carries checkable specifics, like a client draft or a report summary. A casual reword you already wrote does not clear that bar."}]}$lum$::jsonb, false),
  ($lum$d1bddf02-fc83-5ca5-b4f6-a76f19ead953$lum$::uuid, $lum$aa6943e7-fdd2-587a-a4fe-4a3e7151625f$lum$::uuid, 2, $lum$mini_project$lum$, $lum${"brief":"Build your own three-tier verification routine and write it down so it becomes a habit instead of a daily decision. First, list the five most common types of AI output you produce in a typical week (for example: internal emails, meeting summaries, client-facing drafts, data lookups, social posts). Second, assign each one to a tier: glance, targeted check, or full verify, and write one sentence on what \"done checking\" means for that tier. Third, for your Tier 2 work, write a reusable instruction you can paste into the AI to make its claims easy to check, such as asking it to list every number and name separately. Keep the finished routine somewhere visible for two weeks and adjust any item that turns out to be in the wrong tier. The goal is a system you actually follow, not a perfect one you abandon.","parts":[]}$lum$::jsonb, false),
  ($lum$429bc7b6-9dc4-5ed2-8125-978d97137002$lum$::uuid, $lum$008aaca3-dc6d-5151-9c6f-da1c07911371$lum$::uuid, 0, $lum$reading$lum$, $lum${"markdown":"Here is an unfair situation that is becoming common: you write something yourself, run it through nobody, submit it, and get told a detector flagged it as AI-generated. A teacher, an editor, or a client is now questioning your honesty over a tool that, frankly, does not work very well.\n\nUnderstand the core fact first: **AI detectors are not reliable.** They do not detect AI in any real sense. They guess, based on how \"predictable\" the writing looks, and clear, competent, well-structured human writing often looks predictable. Non-native English speakers, people who write plainly, and anyone who edits carefully get falsely flagged regularly. A detector result is an opinion, not evidence.\n\nThat said, being right does not automatically protect you. Here is how to handle it.\n\n**Keep your process, not just your product.** The single best protection is evidence that you did the work. Draft in a tool that saves version history, keep your notes and outlines, and do not delete the messy early versions. A visible trail of drafts is almost impossible to fake and settles the question fast.\n\n**If you are accused, stay calm and lead with proof.** Defensiveness reads as guilt. Instead: \"I understand the detector flagged this, and I know those tools have high error rates. Here's my draft history and my research notes so you can see how it came together. I'm happy to walk you through my thinking.\" Calm plus evidence beats outrage every time.\n\n**Educate, gently.** Many people do not know detectors are unreliable. Sharing that these tools routinely flag human writing, ideally with a link to a reputable source, reframes the conversation from \"did you cheat\" to \"is this tool trustworthy,\" which is the real question.\n\n**Push for a better standard.** Where you can, encourage relying on process and conversation over detector scores. \"Ask me to explain any part of it\" is a fairer test than a number from a tool that admits its own error rate.\n\nYou cannot control a flawed detector. You can control whether you have a paper trail and whether you respond like someone with nothing to hide, because you do not."}$lum$::jsonb, false),
  ($lum$ad412a37-fabe-54e4-857e-953ce1a3e6b5$lum$::uuid, $lum$008aaca3-dc6d-5151-9c6f-da1c07911371$lum$::uuid, 1, $lum$before_after$lum$, $lum${"question":"You wrote the report yourself and a detector flagged it as AI. Two ways to respond to your manager. Notice which one actually resolves it.","before_prompt":"That's completely wrong, I wrote every word myself! Those detectors are garbage and I can't believe you'd accuse me of cheating. This is insulting after everything I've done here.","after_prompt":"I understand the detector flagged it, and I get why that's a concern. For what it's worth, those tools have well-documented false-positive rates and regularly flag human writing, especially clear, structured text. I wrote this myself and I can show you the draft history and my source notes so you can see how it developed. Happy to walk you through any section you'd like.","changes":["Replaces outrage with calm acknowledgment, since defensiveness reads as guilt while composure reads as confidence.","Names the real issue, that detectors have high false-positive rates, reframing it from 'did you cheat' to 'is this tool reliable.'","Offers concrete proof, the draft history and notes, which is the evidence that actually settles the question instead of just asserting innocence."]}$lum$::jsonb, true),
  ($lum$128c2a6a-b4ff-5032-bb09-4180b9024944$lum$::uuid, $lum$008aaca3-dc6d-5151-9c6f-da1c07911371$lum$::uuid, 2, $lum$multiple_choice$lum$, $lum${"stem":"You want to protect yourself in advance against being wrongly flagged as AI. What is the single best protection this lesson recommends?","options":[{"id":"a","label":"Keep evidence of your process: draft in a tool with version history, and save your notes and messy early versions.","is_correct":true,"explanation":"Correct. A visible trail of drafts is almost impossible to fake and settles the question fast. Protecting your process, not just the final product, is the best defense."},{"id":"b","label":"Run your writing through a detector yourself first and rewrite until it passes.","is_correct":false,"explanation":"Detectors guess and frequently flag genuine human writing, so chasing a passing score is a losing game. Evidence of your process is what actually protects you."},{"id":"c","label":"Make your writing deliberately messy so it looks less 'predictable' to a detector.","is_correct":false,"explanation":"Sabotaging your own clarity to fool an unreliable tool is the wrong fix. Keep writing well and keep a draft trail instead."}]}$lum$::jsonb, false)
